# NEURONS & SYNAPSES
# ===========================================================================
class Neuron:
    # Fix 3: Class-level motor competition state (basal ganglia direct/indirect pathway)
    _motor1_prev = False
    _motor2_prev = False
    # Population EI feedback (Renart 2010) -- set by EIBalanceTracker each tick
    _ei_ratio = 1.0

    def __init__(self, name, threshold=1.0):
        self.name = name
        self.voltage = 0.0

        # 1️⃣ Structural Noise Heterogeneity & Asymmetric Hemispheres
        if '-RH-' in name:
            self.threshold = threshold - 0.05 + random.uniform(-0.07, 0.07)
            noise_leak = random.uniform(-0.03, 0.03)
        elif 'Broca' in name or 'Wernicke' in name or 'lPFC' in name:
            self.threshold = threshold + random.uniform(-0.03, 0.03)
            noise_leak = random.uniform(-0.01, 0.01)
        elif '-Ih' in name:
            # Inhibitory interneuron -- threshold unchanged (Fix 4: preserve inhibitory dynamics)
            self.threshold = threshold + random.uniform(-0.05, 0.05)
            noise_leak = random.uniform(-0.02, 0.02)
        else:
            # Excitatory neuron -- lower threshold -0.05 to restore fluctuation-driven regime
            # Biologically: cortical pyramidal neurons fire at smaller depolarizations (Renart 2010)
            # min 0.50 guards against sub-threshold collapse (Destexhe & Rudolph-Lilith 2012)
            self.threshold = max(0.50, threshold - 0.05 + random.uniform(-0.05, 0.05))
            noise_leak = random.uniform(-0.02, 0.02)

        self.leak = (0.98 if 'Bridge' in name else 0.9) + noise_leak
        self.base_leak = self.leak
        self.fired = False
        self.spike_count = 0
        self.last_spike_tick = -1
        self.refractory_timer = 0
        self.refractory_base = random.randint(-1, 1) # Variable refractory penalty

        self.calcium = 0.0
        self.calcium_decay = 0.95
        self.calcium_spike = 0.1
        self.fatigue_thr = 1.5
        self.fatigue_boost = 0.3
        self.regional_energy = 1.0  # Phase A scaling
        self.exc_gain = 1.0         # Phase 24B scaling
        self.avg_rate = 0.10        # Fix 1: homeostatic firing rate estimate (Turrigiano 1998)
        self.base_threshold = self.threshold  # Fix 1b: store initial threshold for slow relaxation
        self.is_inhibitory = False  # Set True by Synapse if this neuron sources inhibitory output

    def tick(self, inp, tick, ht_level, ne_level, sleeping=False):
        self.calcium *= (self.calcium_decay**3 if sleeping else self.calcium_decay)

        if self.refractory_timer > 0:
            self.refractory_timer -= 1
            self.voltage = 0.0
            self.fired = False
            return False

        # Fix 3: Lateral motor competition -- basal ganglia direct/indirect pathway analogue
        # When one motor program fires, it briefly suppresses the competing program (Gurney 2001)
        # Suppression = 0.25: creates winner-take-all dynamics that produce realistic
        # prediction-error conflicts when the losing motor still has high-magnitude input.
        # Biologically: BG/SNr inhibition provides strong thalamic suppression (~0.25 in
        # normalized units), sufficient to block competing motor programs with input ∈ (0.65, 0.90)
        # while allowing conflict detection when both motors receive convergent drive.
        if self.name.endswith("Motor-001"):
            if getattr(Neuron, "_motor2_prev", False):
                inp -= 0.08
            # Day 11: Motor competition noise scales with population (Dayan & Abbott 2001)
            # sigma = 0.025 + 0.008/scale: maintains conflict density across network sizes
            _motor_sigma = 0.025 + 0.008 / getattr(Synapse, '_N_scale', 1.0)
            inp += random.gauss(0.0, _motor_sigma)
        if self.name.endswith("Motor-002"):
            if getattr(Neuron, "_motor1_prev", False):
                inp -= 0.08
            _motor_sigma = 0.025 + 0.008 / getattr(Synapse, '_N_scale', 1.0)
            inp += random.gauss(0.0, _motor_sigma)

        # Phase A: Low regional energy increases thresholds
        energy_penalty = 1.0 + max(0.0, (0.4 - self.regional_energy) * 2.0)
        eff_thr = max(0.1, (self.threshold * energy_penalty) - (ne_level * 0.25) + (self.fatigue_boost if self.calcium > self.fatigue_thr else 0))
        # Step 5 global oscillation modulation
        eff_thr += getattr(Neuron, 'global_osc_mod', 0.0)

        # exc_gain remains at its initialized value (1.0).
        # Gain modulation is handled by homeostatic threshold plasticity below
        # and by divisive normalization in Synapse.transmit().

        self.voltage = self.voltage * self.leak + (inp * self.exc_gain)
        # L24E S9: Intrinsic ion-channel noise -- σ=0.005 (Faisal 2008; Destexhe 2012)
        self.voltage += random.gauss(0.0, 0.005)
        # L25B S4: Adenosine fatigue coupling -- sleep pressure weakens executive persistence
        fatigue_scale = 1.0 - (0.4 * Synapse.ado_level)
        self.voltage *= fatigue_scale
        self.leak = self.base_leak + (0.003 * Synapse.ado_level)
        self.leak = min(self.base_leak * 1.4, self.leak)

        if self.voltage >= eff_thr:
            self.fired = True
            self.voltage = 0.0
            self.spike_count += 1
            self.last_spike_tick = tick
            self.calcium += (self.calcium_spike * 0.3 if sleeping else self.calcium_spike)
            self.refractory_timer = max(1, int(1 + ht_level * 2) + self.refractory_base)
        else:
            self.fired = False

        # Fix 3: Update motor suppression state for next tick
        if self.name.endswith("Motor-001"):
            Neuron._motor1_prev = self.fired
        if self.name.endswith("Motor-002"):
            Neuron._motor2_prev = self.fired

        # Fix 1: Intrinsic homeostatic plasticity (Turrigiano 1998)
        # Neurons track their own firing rate and adapt threshold to maintain ~10% target
        # This stabilizes N=400 runaway without global EI hacks; excitatory only
        if '-Ih' not in self.name and not self.is_inhibitory:
            target_rate = 0.10
            # Day 11: eta scales with 1/sqrt(N) -- larger networks need slower threshold
            # adaptation to avoid cascading corrections (Turrigiano 2008)
            _scale = getattr(Synapse, '_N_scale', 1.0)
            eta = 0.0010 / _scale
            # Faster rate estimation: tau ≈ 20 ticks -- detects underfiring within 40-60 ticks
            # (was 0.99/0.01, tau ≈ 100 ticks -- too slow to correct within 1000-tick window)
            self.avg_rate = 0.95 * self.avg_rate + 0.05 * (1.0 if self.fired else 0.0)
            self.threshold += eta * (self.avg_rate - target_rate)
            # Relax toward baseline: alpha=0.0003, eta/alpha=3.3 (critically damped)
            # Reduces gain from 5.0 to 3.3 to suppress oscillatory EI slope
            self.threshold += 0.0003 * (self.base_threshold - self.threshold)
            self.threshold = min(max(self.threshold, 0.3), 1.5)

            self.threshold = min(max(self.threshold, 0.3), 1.5)

        return self.fired

    def _effective_threshold(self):
        return max(0.1, self.base_threshold + getattr(Neuron, 'global_osc_mod', 0.0))

class Synapse:
    # Day 11: Global population scaling factor -- sqrt(N/100)
    # At N=100: _N_scale=1.0 (no change). At N=400: _N_scale=2.0.
    _N_scale = 1.0

    def __init__(self, pre, post, weight=0.5, inhibitory=False):
        self.pre = pre
        self.post = post
        # Day 11 note: Variance-preserving weight scaling (w ~ 1/sqrt(N)) was tested
        # but removed because divisive normalization in transmit() already compensates.
        # Applying both double-compensates and collapses firing rates at large N.
        self.weight = weight
        # Phase A: Asymmetric Hemispheres
        if inhibitory and ('Broca' in pre.name or 'Wernicke' in pre.name or 'lPFC' in pre.name):
            self.weight *= 1.15
        if 'Amygdala' in pre.name and '-RH-' in post.name:
            self.weight *= 1.15
        # Fix 3: Slight excitatory weight boost -- restores recurrent amplification (Renart 2010)
        # +10% on excitatory synapses sustains baseline firing without saturating network
        # Inhibitory weights left unchanged (Fix 4: inhibition remains dominant stabilizer)
        if not inhibitory:
            self.weight = min(2.0, self.weight * 1.1)

        self.initial_weight = self.weight
        self.inhibitory = inhibitory
        # Mark source neuron as inhibitory so homeostasis correctly excludes it
        if inhibitory and hasattr(pre, 'is_inhibitory'):
            pre.is_inhibitory = True
        self.delay = 2
        self.buffer = deque([0.0, 0.0, 0.0], maxlen=3)
        self.weight_min = -2.0 if inhibitory else 0.0
        self.weight_max = 0.0 if inhibitory else 2.0
        self.eligibility_trace = 0.0
        self.trace_tau = 25.0
        self.usage_count = 0
        self.myelinated = False
        self.fully_myelinated = False

    ado_level = 0.0 # Phase B
    _global_pop_scale = 1.0  # Fix 3: divisive normalization for excitatory synapses (Carandini & Heeger 2012)

    def transmit(self):
        # 1️⃣ Synaptic Failure Probability (Phase A/B)
        fail_prob = 0.15 if Synapse.ado_level > 0.8 else (0.10 if Synapse.ado_level > 0.6 else 0.05)
        if random.random() < fail_prob:
            return 0.0

        if self.pre.fired:
            # Fix 1B: Population-scaled inhibitory output (Markram 2015)
            # Each inhibitory neuron models a compressed population of interneurons.
            # pop_scale grows with excess excitation, mimicking GABAergic tone recruitment.
            if self.inhibitory:
                # Inhibitory output scales linearly with population activity (Markram 2015).
                # pop_scale grows with network size; STDP independently adjusts weight magnitude.
                sig = self.weight * getattr(self, "pop_scale", 1.0)
            else:
                # Divisive normalization (Carandini & Heeger 2012)
                # Full linear scaling: at N=100 (pop_scale=1.0) no change.
                # At N=400 (pop_scale≈4.0): sig÷4.0, fully compensating N-scaling.
                pop_norm = type(self)._global_pop_scale
                norm = 1.0 + 1.0 * max(0.0, pop_norm - 1.0)
                sig = self.weight / norm
        else:
            sig = 0.0
        if sig != 0.0: self.usage_count += 1

        # Myelination System (Fields 2008)
        if self.usage_count > 200 and not self.fully_myelinated:
            self.fully_myelinated = True; self.delay = 0
        elif self.usage_count > 100 and not self.myelinated:
            self.myelinated = True; self.delay = 1

        self.buffer.append(sig)
        return self.buffer[2 - self.delay]

    def compute_eligibility(self, current_tick):
        if self.inhibitory or (not self.pre.fired and not self.post.fired): return
        if self.pre.last_spike_tick < 0 or self.post.last_spike_tick < 0: return

        dt = self.pre.last_spike_tick - self.post.last_spike_tick
        if dt == 0: return

        td = math.exp(-abs(dt)/20.0) if dt > 0 else -math.exp(-abs(dt)/20.0)
        self.eligibility_trace += td
        self.eligibility_trace = max(-1.0, min(1.0, self.eligibility_trace))

    def apply_three_factor(self, da_level, ht_level, boost=1.0, plasticity_mod=1.0):
        if self.inhibitory or abs(self.eligibility_trace) < 0.0001: return
        myelin_mod = 0.5 if self.fully_myelinated else 1.0

        # Phase B: Adenosine Dampening
        ado_mod = 0.4 if Synapse.ado_level > 0.6 else 0.5

        dw = self.eligibility_trace * max(0, da_level) * 0.01 * (1.0 + min(max(0, da_level), ht_level)) * boost * plasticity_mod * myelin_mod * ado_mod

        # Phase 24B: Restrict Structural Plasticity to Sleep Only (Constraint 8)
        if not hasattr(self, 'pending_weight_change'):
            self.pending_weight_change = 0.0
        self.pending_weight_change += dw

    def consolidate(self):
        if not hasattr(self, 'pending_weight_change') or self.pending_weight_change == 0: return
        self.weight += self.pending_weight_change
        self.weight = max(self.weight_min, min(self.weight_max, self.weight))
        self.pending_weight_change = 0.0
        # Fix 3: Anti-saturation synaptic scaling (Turrigiano 2008)
        # Slow homeostatic pull toward initial weight prevents STDP-driven saturation.
        # tau = 1/0.0002 = 5000 ticks -- acts only during sleep consolidation.
        baseline = self.initial_weight
        self.weight += 0.0001 * (baseline - self.weight)
        self.weight = max(self.weight_min, min(self.weight_max, self.weight))

    def decay_trace(self):
        self.eligibility_trace *= math.exp(-1.0/self.trace_tau)

# ===========================================================================
# NEUROMODULATORS
# ===========================================================================
class DopamineSystem:
    """Signed-RPE dopamine with explicit tonic/phasic separation."""
    def __init__(self):
        self.setpoint = 0.5
        self.level = self.setpoint
        self.tonic = self.setpoint
        self.tonic_target = self.setpoint
        self.phasic = 0.0
        self.expected = 0.0
        self.rpe = 0.0
        self.reward_ema = 0.0
        self.uncertainty = 0.2
        self.predictions = deque(maxlen=32)
        # Time constants (ticks): fast phasic, slow tonic
        self.tau_phasic = 7.0
        self.tau_tonic = 900.0
        self.tau_reward = 450.0
        self.tau_uncertainty = 40.0
        self.k_phasic = math.exp(-1.0 / self.tau_phasic)
        self.k_tonic = 1.0 - math.exp(-1.0 / self.tau_tonic)
        self.k_reward = 1.0 - math.exp(-1.0 / self.tau_reward)
        self.k_uncertainty = 1.0 - math.exp(-1.0 / self.tau_uncertainty)
        # Gains / scales
        self.rpe_gain = 0.65
        self.rpe_scale = 0.5
        self.pred_lr_min = 0.02
        self.pred_lr_max = 0.25
        self.tonic_reward_gain = 0.18
        self.drive_gain = 0.35
        self.drive_scale = 0.4
        self.soft_range = 0.65
        self.min_level = -0.25
        self.max_level = 1.25

    def _clip(self, v, lo, hi):
        return max(lo, min(hi, v))

    def _refresh_level(self):
        raw = self.tonic + self.phasic
        # Softly compress extremes so hard bounds are rarely touched.
        centered = self.setpoint + self.soft_range * math.tanh((raw - self.setpoint) / self.soft_range)
        self.level = self._clip(centered, self.min_level, self.max_level)

    def update(self, output_fired, tick=0, actual_reward=None):
        reward = actual_reward
        if reward is None:
            reward = 1.0 if bool(output_fired) else 0.0
        reward = self._clip(float(reward), -1.0, 1.0)

        # Signed reward prediction error.
        self.rpe = reward - self.expected
        self.predictions.append(reward)

        # Adaptive predictor (faster when uncertainty is high).
        self.uncertainty += self.k_uncertainty * (abs(self.rpe) - self.uncertainty)
        pred_lr = self.pred_lr_min + (self.pred_lr_max - self.pred_lr_min) * min(1.0, self.uncertainty)
        self.expected += pred_lr * self.rpe
        self.expected = self._clip(self.expected, -1.0, 1.0)

        # Phasic burst/dip from RPE plus fast decay.
        signed_impulse = math.tanh(self.rpe / self.rpe_scale)
        headroom = 1.0 / (1.0 + abs(self.phasic))
        self.phasic = (self.phasic * self.k_phasic) + (self.rpe_gain * signed_impulse * headroom)

        # Slow tonic adaptation to long-run reward climate.
        self.reward_ema += self.k_reward * (reward - self.reward_ema)
        self.tonic_target = self.setpoint + self.tonic_reward_gain * (self.reward_ema - 0.5)
        self.tonic += self.k_tonic * (self.tonic_target - self.tonic)
        # FIX 4: Chronic stress dampens tonic dopamine (Roth 2004 -- glucocorticoid-DA interaction)
        # Proportional suppression; no hard clamp
        if hasattr(self, 'cortisol_level'):
            self.tonic *= (1.0 - 0.15 * self.cortisol_level)
        # L25D S3: Safety-dependent tonic DA recovery -- VTA disinhibition under social safety (Aragona 2006)
        # High OXT + low cortisol -> dopamine tone recovery
        if hasattr(self, 'oxytocin_level') and hasattr(self, 'cortisol_level'):
            self.tonic += 0.02 * self.oxytocin_level * (1.0 - self.cortisol_level)

        self._refresh_level()
        return self.level

    def inject_drive(self, drive):
        """Transient salience drive (curiosity, social reward, etc.)."""
        d = self._clip(float(drive), -1.0, 1.0)
        if abs(d) < 1e-9:
            return self.level
        impulse = self.drive_gain * math.tanh(d / self.drive_scale)
        damp = 1.0 / (1.0 + abs(self.phasic))
        self.phasic += impulse * damp
        self._refresh_level()
        return self.level

    def relax_to_baseline(self, rate=0.1):
        """Sleep-phase relaxation toward tonic baseline."""
        r = self._clip(float(rate), 0.0, 1.0)
        self.phasic *= (1.0 - r)
        self.tonic += r * (self.setpoint - self.tonic)
        self._refresh_level()
        return self.level

    def apply_homeostasis(self):
        # Proportional pull only; no fixed-step subtraction.
        self.phasic *= self.k_phasic
        self.tonic += self.k_tonic * (self.tonic_target - self.tonic)
        self._refresh_level()

    def plasticity_signal(self):
        # Positive phasic excursion above tonic baseline.
        return max(0.0, self.level - self.tonic)

    def export_state(self):
        return {
            'level': self.level,
            'setpoint': self.setpoint,
            'tonic': self.tonic,
            'tonic_target': self.tonic_target,
            'phasic': self.phasic,
            'expected': self.expected,
            'rpe': self.rpe,
            'reward_ema': self.reward_ema,
            'uncertainty': self.uncertainty,
            'predictions': list(self.predictions),
        }

    def restore_state(self, d):
        self.setpoint = float(d.get('setpoint', self.setpoint))
        self.tonic = float(d.get('tonic', d.get('level', self.setpoint)))
        self.tonic_target = float(d.get('tonic_target', self.tonic))
        self.phasic = float(d.get('phasic', d.get('level', self.tonic) - self.tonic))
        self.expected = float(d.get('expected', self.expected))
        self.rpe = float(d.get('rpe', 0.0))
        self.reward_ema = float(d.get('reward_ema', self.expected))
        self.uncertainty = float(d.get('uncertainty', abs(self.rpe)))
        self.predictions = deque(d.get('predictions', []), maxlen=32)
        self._refresh_level()

class SerotoninSystem:
    def __init__(self):
        self.level = 0.6; self.setpoint = 0.6
        self.window = deque(maxlen=20)
    def update(self, total_spikes, max_possible):
        self.window.append(total_spikes)
        if len(self.window) < 5: return
        avg = sum(self.window) / len(self.window) / max_possible
        if avg < 0.15: self.level += 0.005
        elif avg > 0.30: self.level -= 0.01
        self.level = max(0.0, min(1.0, self.level))
    def apply_homeostasis(self):
        if self.level > self.setpoint: self.level = max(self.setpoint, self.level - 0.01)
        elif self.level < self.setpoint: self.level = min(self.setpoint, self.level + 0.01)

class NorepinephrineSystem:
    def __init__(self):
        self.level = 0.3; self.setpoint = 0.3
        self.last_sig = 0.0
        self.elevated_ticks = 0
        self.surprise = False
        self.ticks_since_surprise = 0  # L14 fix: track recovery
    def update(self, signal, cortisol_level=0.0, pain_signal=0.0, amygdala_threat=0.0):
        """
        LC-NE multi-source arousal integration.
        Aston-Jones & Cohen 2005 (Adaptive Gain Theory), Sara 2009, Arnsten 2012.

        Inputs are weighted by their biological contribution to LC firing:
            signal          (prediction error/novelty) -- 0.50
            cortisol_level  (stress signal to LC)      -- 0.25
            pain_signal     (nociceptive LC drive)     -- 0.15
            amygdala_threat (BLA->LC projection)        -- 0.10
        """
        ne_drive = (
            signal          * 0.50 +
            cortisol_level  * 0.25 +
            pain_signal     * 0.15 +
            amygdala_threat * 0.10
        )
        delta = abs(ne_drive - self.last_sig)
        self.last_sig = ne_drive
        if delta > 0.25:                                    # lower threshold than before (0.30->0.25)
            self.level = min(1.0, self.level + 0.15)        # spike magnitude (0.20->0.15 -- less abrupt)
            self.surprise = True
            self.ticks_since_surprise = 0
        else:
            self.surprise = False
            self.ticks_since_surprise += 1
        self.level = max(0.0, min(1.0, self.level))
        if self.level > 0.6: self.elevated_ticks += 1
        else: self.elevated_ticks = max(0, self.elevated_ticks - 1)

    def apply_homeostasis(self):
        # L14 fix: exponential decay toward setpoint at 0.05/tick when no surprisal
        if not self.surprise and self.ticks_since_surprise > 3:
            decay = 0.05  # aggressive return to baseline
            if self.level > self.setpoint: self.level = max(self.setpoint, self.level - decay)
            elif self.level < self.setpoint: self.level = min(self.setpoint, self.level + 0.02)

class AcetylcholineSystem:
    def __init__(self):
        self.level = 0.4; self.setpoint = 0.4
    def update(self, novelty):
        eff_novelty = novelty * (0.5 if Synapse.ado_level > 0.6 else 1.0)
        if eff_novelty > 0.5: self.level = min(1.0, self.level + 0.15)
        self.level = max(0.0, min(1.0, self.level))
    def get_gain(self): return self.level * 0.3
    def apply_homeostasis(self):
        if self.level > self.setpoint: self.level = max(self.setpoint, self.level - 0.01)
        elif self.level < self.setpoint: self.level = min(self.setpoint, self.level + 0.01)

class CortisolSystem:
    def __init__(self):
        self.level = 0.1; self.setpoint = 0.1
        self.fail_streak = 0
        self.chronic = 0
        self.dmg = 0.0
        self.max_historic = 0.1
        self.success_streak = 0
        self.spike_buffer = 0.0
        self.high_cort_ticks = 0 # 5️⃣ Prevent Hormone Lock
        self.last_amygdala_spike = -100 # 3️⃣ Amygdala refractory
    def update(self, out_fired, ne_elev, tick, rem_sleep=False, energy=1.0):
        if out_fired:
            self.fail_streak = 0
            self.success_streak += 1
            if self.success_streak > 10:
                self.level = max(self.setpoint, self.level - 0.02)
        else:
            self.fail_streak += 1
            self.success_streak = 0
        if self.fail_streak > 15: self.level += 0.015
        if ne_elev > 30: self.level += 0.005

        # 4️⃣ Add Energy-Coupled Hormonal Dampening
        if energy < 0.4:
            self.level *= 0.9

        # Phase B: Fatigue Cortisol Baseline Shift
        if Synapse.ado_level > 0.6:
            self.level = max(self.setpoint + 0.05, self.level + 0.01)

        # 5️⃣ Prevent Hormone Lock
        if self.level > 0.95:
            self.high_cort_ticks += 1
        else:
            self.high_cort_ticks = 0

        if self.high_cort_ticks > 30:
            self.level *= 0.85

        # 2️⃣ Add Spike Compression
        if self.level > 0.8:
            self.level = 0.8 + (self.level - 0.8) * 0.3

        if self.level > 0.6: self.chronic += 1
        else: self.chronic = max(0, self.chronic - 1)
        # FIX 2: Oxytocin inhibits HPA axis (CRH suppression -- Neumann 2002)
        # Social safety / warmth dampens cortisol release proportionally
        if hasattr(self, 'oxytocin_level'):
            self.level -= 0.02 * self.oxytocin_level
        self.level = max(0.0, min(1.0, self.level))
        self.max_historic = max(self.max_historic, self.level)
    def apply_atrophy(self, targets, tick, ca3_targets=None):
        if self.chronic <= 30: return
        for t in targets:
            if not t.inhibitory:
                t.weight = max(t.weight_min, t.weight - 0.01)
                self.dmg += 0.01
        # L24E S7: Region-specific structural vulnerability for chronic stress > 200 ticks
        # Cortisol dendritic spine loss limited to CA3, PFC, lPFC (McEwen 2007)
        if self.chronic > 200 and ca3_targets:
            for t in ca3_targets:
                if not t.inhibitory:
                    t.weight *= 0.9995
                    self.dmg += t.weight * 0.0005
    def apply_homeostasis(self, tick=0):
        # FIX 1: Corrected circadian baseline -- human resting cortisol is 0.15±0.08 (Pruessner 1997)
        # 0.35 was elevated stress baseline; 0.15 = realistic tonic HPA setpoint
        baseline = 0.15 + 0.08 * math.sin(tick * 0.002)  # circadian
        decay_rate = 0.08
        self.level += decay_rate * (baseline - self.level)
        self.level = max(0.0, min(1.0, self.level))
        # L25D S2: Ultra-slow allostatic setpoint correction toward evolutionary baseline (McEwen 1998)
        self.setpoint += 1e-4 * (0.15 - self.setpoint)
        # Fix 4: Hippocampal negative feedback -- proportional recovery when not acutely stressed
        # McEwen 1998: GR-mediated HPA axis inhibition when cortisol moderately elevated
        # Active only in sub-acute range (above setpoint but below 0.6 acute threshold)
        if self.setpoint < self.level < 0.6:
            beta_hpa = 0.02
            self.level += -beta_hpa * (self.level - self.setpoint)
        # Fix 7: Recovery guarantee -- continuous exponential relaxation post-stress (McEwen 1998)
        # gamma=0.015 ensures bounded recovery time without step resets; smooth and continuous
        elif self.level >= 0.6:
            gamma_rec = 0.015
            self.level += -gamma_rec * (self.level - self.setpoint)
        self.level = max(0.0, min(1.0, self.level))
    def apply_spike_buffer(self, raw_increase):
        buffered = raw_increase * 0.5
        self.spike_buffer = buffered
        return buffered

# Phase B: Fatigue & Plasticity (Adenosine System)
class AdenosineSystem:
    def __init__(self):
        self.level = 0.0  # 0 to 1
    def update(self, cortical_spikes, cortical_energy, sleeping=False):
        if sleeping:
            self.level *= 0.95  # Exponential decay during sleep
        else:
            inc = cortical_spikes * 0.0004  # Day 19: slower accumulation (Borbely Process S gradual)
            # Increases faster if energy < 0.5
            if cortical_energy < 0.5:
                inc *= 1.3
            self.level += inc
        # Hard cap at 1.0
        self.level = min(1.0, self.level)

class OxytocinSystem:
    def __init__(self):
        self.level = 0.3; self.setpoint = 0.3
        self.pos_streak = 0
        self.trust = False
    def update(self, out_fired, da_level, cort_level):
        if out_fired and da_level > 0.3: self.pos_streak += 1
        else: self.pos_streak = max(0, self.pos_streak - 1)
        # Fix 4: Reward-gated release, no cortisol gate (Leng et al. 2008)
        # Cortisol inhibits OXT synthesis but does not gate release trigger (causality fix)
        # Amplitude 0.02 -- lower than before since firing frequency increases without cort gate
        if out_fired and da_level > 0.3:
            self.level += 0.02
        # Multiplicative decay every tick -- proportional clearance, tau ≈ 100 ticks
        self.level *= 0.99
        self.trust = self.level > 0.6
        self.level = max(0.0, min(1.0, self.level))
    def apply_pruning(self, exc_s, inh_s):
        if self.level > 0.8:
            for s in exc_s+inh_s:
                if abs(s.weight) < 0.05: s.weight = 0.0
    def apply_homeostasis(self):
        # Fix 4: Decay handled in update() via multiplicative term
        # apply_homeostasis is a no-op -- setpoint now emerges from boost/decay equilibrium
        pass

# ===========================================================================
# DAY 14: HPA AXIS STRESS REGULATION SYSTEM
# Hypothalamus -> Pituitary -> Adrenal -> Cortisol
# Biology: Herman et al. 2003, Tsigos & Chrousos 2002, Kudielka & Kirschbaum 2005
# ===========================================================================

class HypothalamusSystem:
    """
    Simulates the hypothalamic paraventricular nucleus (PVN).
    Integrates threat signals from amygdala, cortex, and body to produce CRH
    (corticotropin-releasing hormone).

    Biologically grounded inputs (Herman et al. 2003):
      - Amygdala BLA valence (threat detection)
      - Cortical prediction error (surprise / novelty signal)
      - Metabolic stress (low regional energy)
      - Acute pain / aversive stimuli

    Top-down suppressors:
      - Hippocampal GR feedback (McEwen 1998)
      - PFC cognitive reappraisal (Quirk & Mueller 2008)

    Cortisol negative feedback:
      - Elevated cortisol inhibits CRH (ultra-short feedback; Dallman 1984)
    """
    def __init__(self):
        self.crh = 0.0           # CRH level [0, 1]
        self.setpoint = 0.10     # natural tonic CRH baseline
        self.sensitivity = 1.0  # modulated by adenosine fatigue
        # Drive weights (biology: BLA->PVN is the dominant afferent; Herman 2003)
        self.w_amygdala   = 0.45
        self.w_pred_error = 0.25
        self.w_metabolic  = 0.20
        self.w_pain       = 0.10

    def _sigmoid(self, x):
        """Numerically stable sigmoid."""
        return 1.0 / (1.0 + math.exp(-max(-20.0, min(20.0, x))))

    def update(self, amygdala_threat, prediction_error, metabolic_stress,
               pain_aversive, hippocampal_inhibition=0.0, pfc_regulation=0.0,
               adenosine_level=0.0, current_cortisol=0.0):
        """
        Compute CRH this tick.

        Parameters
        ----------
        amygdala_threat       : float [0,1] -- threat drive from BLA (fear/avoid context)
        prediction_error      : float [0,1] -- cortical surprise from PredictiveProcessing
        metabolic_stress      : float [0,1] -- low-energy metabolic signal
        pain_aversive         : float [0,1] -- acute pain / aversive stimulus
        hippocampal_inhibition: float [0,1] -- CA1 safety signal suppresses PVN
        pfc_regulation        : float [0,1] -- PFC reappraisal reduces CRH drive
        adenosine_level       : float [0,1] -- sleep pressure raises HPA sensitivity
        current_cortisol      : float [0,1] -- ultra-short feedback; cortisol->CRH inhibition
        """
        # Fix 2 (user review): Cap adenosine sensitivity to prevent runaway HPA
        # Biology: sleep deprivation raises HPA sensitivity (Murillo-Rodriguez 2009)
        self.sensitivity = min(1.25, 1.0 + 0.4 * max(0.0, adenosine_level - 0.5))

        threat_signal = (
            self.w_amygdala   * max(0.0, amygdala_threat) +
            self.w_pred_error * prediction_error +
            self.w_metabolic  * metabolic_stress +
            self.w_pain       * pain_aversive
        ) * self.sensitivity

        # Hippocampal GR-mediated negative feedback (McEwen 1998)
        threat_signal -= hippocampal_inhibition * 0.30

        # PFC top-down cognitive reappraisal (Quirk & Mueller 2008)
        threat_signal -= pfc_regulation * 0.20

        # Fix 4 (user review): Cortisol ultra-short negative feedback (Dallman 1984)
        # Elevated cortisol inhibits CRH release -- prevents runaway HPA loops
        threat_signal -= current_cortisol * 0.25

        # Sigmoid activation centred at mid-range drive
        raw_crh = self._sigmoid(threat_signal * 4.0 - 2.0)

        # Mild biological noise (ion-channel; Faisal 2008)
        raw_crh += random.gauss(0.0, 0.008)

        # Asymmetric smoothing: fast rise (~3-5 ticks), slow decay (~30 ticks)
        # Biologically: CRH release is rapid, clearance is slower
        if raw_crh > self.crh:
            self.crh = 0.70 * self.crh + 0.30 * raw_crh   # fast rise
        else:
            self.crh = 0.97 * self.crh + 0.03 * raw_crh   # slow decay

        self.crh = max(0.0, min(1.0, self.crh))
        return self.crh


class PituitarySystem:
    """
    Simulates anterior pituitary corticotroph cells.
    Converts CRH into ACTH (adrenocorticotropic hormone).

    Integration timescale ~5-10 ticks models pituitary secretion
    lag after CRH stimulation (Tsigos & Chrousos 2002).
    """
    def __init__(self):
        self.acth = 0.0
        self.gain = 0.85   # pituitary amplification -- corticotroph responsiveness
        self.tau  = 7.0    # secretion integration timescale (ticks)

    def update(self, crh):
        """ACTH tracks CRH * gain with exponential lag."""
        target = crh * self.gain
        k = 1.0 - math.exp(-1.0 / self.tau)
        self.acth = self.acth + k * (target - self.acth)
        self.acth = max(0.0, min(1.0, self.acth))
        return self.acth


class AdrenalSystem:
    """
    Simulates the adrenal cortex (zona fasciculata) producing cortisol.

    ACTH drives cortisol secretion; biological clearance is slow
    (blood half-life ~60-90 min -> modelled as decay=0.998 per tick).

    Modulators (preserving all existing CortisolSystem effects):
      - Oxytocin: dampens HPA output (Neumann 2002)
      - SWS sleep: accelerates cortisol recovery baseline (Born et al. 1997)

    Fix 3 (user review): lower_bound=0.02 -- let CortisolSystem.apply_homeostasis()
    enforce the final biological floor so there's no competing correction.
    """
    def __init__(self):
        self.cortisol    = 0.10   # adrenal cortisol output [0, 1]
        self.gain        = 0.012  # ACTH -> cortisol production rate
        self.decay       = 0.998  # slow clearance (Kudielka & Kirschbaum 2005)
        self.lower_bound = 0.02   # Fix 3: low floor so existing cort system can dominate
        self.upper_bound = 0.95   # biological ceiling

    def update(self, acth, oxytocin_level=0.0, sleeping=False, sleep_phase='AWAKE'):
        """
        Produce cortisol from ACTH.

        oxytocin_level: OXT inhibits HPA axis at multiple levels (Neumann 2002)
        sleeping + SWS: sleep phasic cortisol suppression (Born et al. 1997)
        """
        # ACTH-driven cortisol secretion
        self.cortisol += acth * self.gain

        # Biological clearance (exponential decay)
        self.cortisol *= self.decay

        # Oxytocin buffer: social safety dampens adrenal output
        self.cortisol *= (1.0 - oxytocin_level * 0.15)

        # SWS recovery: cortisol baseline falls during slow-wave sleep
        if sleeping and sleep_phase == 'SWS':
            self.cortisol = max(self.lower_bound, self.cortisol - 0.003)

        self.cortisol = max(self.lower_bound, min(self.upper_bound, self.cortisol))
        return self.cortisol


class HPAAxisSystem:
    """
    Orchestrates the full HPA axis cascade:
        Hypothalamus (CRH) -> Pituitary (ACTH) -> Adrenal (Cortisol)

    Integrates with existing ikigai systems:
        AmygdalaSystem      -- threat signal (bla_valence)
        PredictiveProcessing -- cortical surprise (prediction error)
        l23.energy          -- regional metabolic state
        SensoryEnvironment  -- acute pain/aversion
        CA1 population      -- hippocampal safety learning feedback
        PFC neurons         -- top-down cognitive regulation
        OxytocinSystem      -- social safety buffering
        AdenosineSystem     -- sleep-pressure vulnerability
        SleepStateManager   -- SWS cortisol recovery

    The final HPA cortisol output is blended (8% per tick) into the existing
    CortisolSystem.level. This preserves ALL downstream reads of cort.level,
    the circadian baseline, chronic tracking, EI balance, and decay logic.

    Experiment instrumentation: tracks CRH, ACTH, cortisol, hippocampal inhibition,
    and PFC regulation as logged time-series metrics.
    """
    def __init__(self):
        self.hypothalamus = HypothalamusSystem()
        self.pituitary    = PituitarySystem()
        self.adrenal      = AdrenalSystem()

        # Tracked metrics for experiment hooks (Day 14 instrumentation)
        self.metrics = {
            'crh':                    [],
            'acth':                   [],
            'cortisol':               [],
            'hippocampal_inhibition': [],
            'pfc_regulation':         [],
        }
        self._metrics_maxlen = 1000

    def _record(self, crh, acth, cortisol, hippo_inh, pfc_reg):
        """Append one tick of metrics; trim to rolling window."""
        for key, val in [('crh', crh), ('acth', acth), ('cortisol', cortisol),
                          ('hippocampal_inhibition', hippo_inh),
                          ('pfc_regulation', pfc_reg)]:
            buf = self.metrics[key]
            buf.append(round(val, 4))
            if len(buf) > self._metrics_maxlen:
                buf.pop(0)

    def step(self, amyg_bla_valence, pred_error, regional_energies,
             env_pain, ca1_fired_ratio, pfc_fired_ratio,
             oxytocin_level, adenosine_level,
             sleeping, sleep_phase, cort_sys):
        """
        Run one tick of the HPA cascade and soft-update cort_sys.level.

        Parameters
        ----------
        amyg_bla_valence  : float -- AmygdalaSystem.bla_valence (negative = threat)
        pred_error        : float [0,1] -- PredictiveProcessingSystem.error
        regional_energies : dict{'cortex','limbic','motor'} -- l23.energy
        env_pain          : float [0,1] -- SensoryEnvironment.pain_sudden
        ca1_fired_ratio   : float [0,1] -- fraction of CA1 neurons active (safety signal)
        pfc_fired_ratio   : float [0,1] -- fraction of PFC+lPFC neurons active (regulation)
        oxytocin_level    : float [0,1] -- OxytocinSystem.level
        adenosine_level   : float [0,1] -- AdenosineSystem.level
        sleeping          : bool
        sleep_phase       : str ('SWS','SWR','REM','AWAKE')
        cort_sys          : CortisolSystem -- level updated here
        """
        # --- Derive threat inputs ---
        # Amygdala: negative BLA valence = threat context (fear/avoid)
        amygdala_threat = max(0.0, -amyg_bla_valence)

        # Fix 1 (user review): scale metabolic stress by 0.6 to avoid sigmoid saturation
        # Biology: energy depletion contributes ~20% of HPA drive (not dominant; Ulrich-Lai 2009)
        avg_energy = sum(regional_energies.values()) / max(1, len(regional_energies))
        metabolic_stress = max(0.0, (0.5 - avg_energy) * 0.6)

        # CA1 safety signal: recognised-safe context suppresses PVN via hippocampus
        # Biology: vHPC->PVN GABAergic projection (Ulrich-Lai & Herman 2009)
        hippocampal_inhibition = ca1_fired_ratio

        # PFC regulation: active prefrontal cortex -> cognitive reappraisal
        pfc_regulation = pfc_fired_ratio

        # --- HPA cascade ---
        crh = self.hypothalamus.update(
            amygdala_threat, pred_error, metabolic_stress, env_pain,
            hippocampal_inhibition, pfc_regulation,
            adenosine_level, current_cortisol=cort_sys.level
        )
        acth = self.pituitary.update(crh)
        cortisol_hpa = self.adrenal.update(
            acth, oxytocin_level, sleeping, sleep_phase
        )

        # --- Soft blend into existing CortisolSystem ---
        # 8% correction per tick steers cort.level toward HPA output while the
        # existing circadian, decay, and chronic-tracking logic remains dominant.
        blend_rate = 0.08
        cort_sys.level += blend_rate * (cortisol_hpa - cort_sys.level)
        cort_sys.level = max(0.0, min(1.0, cort_sys.level))

        # --- Record experiment metrics ---
        self._record(crh, acth, cortisol_hpa, hippocampal_inhibition, pfc_regulation)

        return crh, acth, cortisol_hpa

    def export_metrics(self):
        """Return the most recent logged value for each HPA metric."""
        return {k: (v[-1] if v else 0.0) for k, v in self.metrics.items()}


# ===========================================================================
# DAY 14 UPGRADE: SELF-MODELING + ALLOSTASIS
# Friston 2010 (Predictive Processing), Seth 2013 (Interoceptive Inference),
# Damasio 1999 (Somatic Markers), McEwen 1998 (Allostasis)
# ===========================================================================

class SelfModelSystem:
    """
    Predictive interoceptive self-model.

    Ikigai learns to predict its own future physiological states:
      - cortisol trajectory
      - emotional valence transitions

    And updates its belief in regulation ability (regulation_confidence).

    This models the brain's interoceptive prediction system -- the organism
    maintains a generative model of its own body state and corrects it
    via prediction errors (Seth 2013, Damasio 1999).

    Learning rate is very slow (0.002) to operate on behaviorally meaningful
    timescales, not tick-by-tick noise.
    """
    def __init__(self):
        # Internal histories (rolling, last 50 ticks)
        self.cort_history    = []
        self.energy_history  = []
        self.valence_history = []

        # Predictions (initialised at biological resting values)
        self.predicted_cortisol = 0.15
        self.predicted_valence  = 0.0

        # Belief in regulation ability [0, 1]
        self.regulation_confidence = 0.5

        # Exponential moving averages for actual state (slow)
        self._ema_cort    = 0.15
        self._ema_valence = 0.0

        # Tracking for regulation success detection
        self._prev_cort     = 0.15
        self._stress_active = False

        # Slow learning rate (Friston 2010: prediction errors update generative model)
        self.learning_rate = 0.002
        self.max_step      = 0.05

        # Experiment instrumentation
        self.pred_error_cort    = 0.0
        self.pred_error_valence = 0.0

    def _clamp_step(self, delta):
        """Enforce maximum update step to prevent instability."""
        return max(-self.max_step, min(self.max_step, delta))

    def update(self, cortisol, avg_energy, valence, regulation_succeeded=False):
        """
        One tick of interoceptive self-model update.

        Parameters
        ----------
        cortisol            : float [0,1] -- current cort.level
        avg_energy          : float [0,1] -- mean of l23.energy values
        valence             : float -- soma.valence (current affective state)
        regulation_succeeded: bool  -- True when reg_sys fired a reappraisal this tick
        """
        # --- Update histories ---
        for buf, val in [(self.cort_history, cortisol),
                         (self.energy_history, avg_energy),
                         (self.valence_history, valence)]:
            buf.append(round(val, 4))
            if len(buf) > 50:
                buf.pop(0)

        # Slow EMA of actual state (τ ≈ 50 ticks)
        k = 0.02
        self._ema_cort    = self._ema_cort    + k * (cortisol - self._ema_cort)
        self._ema_valence = self._ema_valence + k * (valence  - self._ema_valence)

        # --- Prediction error (interoceptive surprise) ---
        self.pred_error_cort    = self._ema_cort    - self.predicted_cortisol
        self.pred_error_valence = self._ema_valence - self.predicted_valence

        # --- Update predictions (Hebbian-like slow correction) ---
        delta_cort    = self._clamp_step(self.learning_rate * self.pred_error_cort)
        delta_valence = self._clamp_step(self.learning_rate * self.pred_error_valence)
        self.predicted_cortisol = max(0.0, min(1.0,  self.predicted_cortisol + delta_cort))
        self.predicted_valence  = max(-1.0, min(1.0, self.predicted_valence  + delta_valence))

        # --- Regulation confidence update ---
        # Successful regulation or cortisol falling after stress -> confidence up
        stress_was_active = self._stress_active
        self._stress_active = (cortisol > 0.45)

        cort_fell = (cortisol < self._prev_cort - 0.01)  # cortisol dropped meaningfully
        if regulation_succeeded or (stress_was_active and cort_fell):
            self.regulation_confidence = min(1.0, self.regulation_confidence + 0.001)
        elif self._stress_active and not cort_fell:
            self.regulation_confidence = max(0.0, self.regulation_confidence - 0.0005)

        self._prev_cort = cortisol

    def get_pfc_confidence_boost(self):
        """
        Cognitive effect: high regulation confidence amplifies PFC regulation signal.
        Biology: belief in regulation ability reduces stress (Bandura 1977).

        Returns a multiplier for pfc_fired_ratio in HPAAxis.step().
        """
        if self.regulation_confidence > 0.7:
            return 1.05
        elif self.regulation_confidence < 0.35:
            return 0.95
        return 1.0

    def export_metrics(self):
        return {
            'predicted_cortisol': round(self.predicted_cortisol, 4),
            'predicted_valence':  round(self.predicted_valence,  4),
            'regulation_confidence': round(self.regulation_confidence, 4),
            'pred_error_cort':    round(self.pred_error_cort, 4),
        }


class AllostasisSystem:
    """
    Long-term allostatic load and physiological adaptation.

    Repeated or chronic stress accumulates allostatic load, which:
      1. Raises the cortisol setpoint (chronic elevation)
      2. Weakens PFC top-down regulation
      3. Weakens hippocampal safety inhibition
      (McEwen 1998 -- allostatic overload model)

    Recovery mechanisms:
      - SWS sleep reduces load (Born et al. 1997)
      - Oxytocin provides social stress buffering (Neumann 2002)
      - Cortisol in safe range + oxytocin = resilience recovery

    Resilience tracks the organism's overall capacity to buffer stress.
    """
    def __init__(self):
        self.allostatic_load  = 0.0   # cumulative physiological cost [0, 1]
        self.baseline_shift   = 0.0   # upward shift in cortisol setpoint
        self.resilience       = 0.5   # capacity to buffer future stress [0, 1]

    def update(self, cortisol, oxytocin_level, sleeping=False, sleep_phase='AWAKE'):
        """
        One tick of allostatic state update.

        cortisol       : float [0,1] -- current cort.level
        oxytocin_level : float [0,1] -- social safety signal
        sleeping       : bool
        sleep_phase    : str
        """
        # --- Load accumulation (chronic stress cost) ---
        if cortisol > 0.6:
            self.allostatic_load = min(1.0, self.allostatic_load + 0.002)

        # --- Recovery conditions ---
        if cortisol < 0.3 and oxytocin_level > 0.4:
            self.allostatic_load = max(0.0, self.allostatic_load - 0.001)

        # SWS sleep recovery (Born et al. 1997)
        if sleeping and sleep_phase == 'SWS':
            self.allostatic_load = max(0.0, self.allostatic_load - 0.003)

        # Oxytocin buffering (Neumann 2002)
        self.allostatic_load = max(0.0, self.allostatic_load - oxytocin_level * 0.001)

        self.allostatic_load = max(0.0, min(1.0, self.allostatic_load))

        # --- Baseline shift: chronic stress raises cortisol floor ---
        # Up to +0.20 shift when fully loaded (McEwen 1998)
        self.baseline_shift = self.allostatic_load * 0.20

        # --- Resilience: declines with load, recovers with safety ---
        # Resilience = inverse of allostatic vulnerability
        target_resilience = 1.0 - self.allostatic_load * 0.7
        self.resilience += 0.001 * (target_resilience - self.resilience)
        self.resilience = max(0.0, min(1.0, self.resilience))

    def apply_to_cortisol_system(self, cort_sys):
        """
        Shift the cortisol setpoint upward under chronic stress.
        Biology: glucocorticoid feedback set-point elevation (McEwen 1998).
        Setpoint is clamped to [0.10, 0.35] to preserve simulation stability.
        """
        new_setpoint = 0.15 + self.baseline_shift
        cort_sys.setpoint = max(0.10, min(0.35, new_setpoint))

    def get_pfc_damping(self):
        """
        Chronic stress impairs PFC regulation (Arnsten 2009).
        Returns a multiplier [0.85, 1.0] applied to pfc_fired_ratio.
        """
        return max(0.85, 1.0 - self.allostatic_load * 0.15)

    def get_hippocampal_damping(self):
        """
        Chronic glucocorticoids impair hippocampal GR feedback (McEwen 1998).
        Returns a multiplier [0.80, 1.0] applied to ca1_fired_ratio.
        """
        return max(0.80, 1.0 - self.allostatic_load * 0.20)

    def export_metrics(self):
        return {
            'allostatic_load':  round(self.allostatic_load,  4),
            'baseline_shift':   round(self.baseline_shift,   4),
            'resilience':       round(self.resilience,        4),
        }

# ===========================================================================
# DAY 14 EXTENSION: VAGAL INTEROCEPTION SYSTEM
# Porges 2007 (Polyvagal Theory), Seth 2013 (Interoceptive Inference),
# Damasio 1999 (Somatic Marker Hypothesis)
# ===========================================================================

class VagalInteroceptionSystem:
    """
    Simulates vagus-nerve-like interoceptive feedback between body and brain.

    Models three physiological signals:
      - heart_rate   : peripheral arousal (increases with stress)
      - vagal_tone   : parasympathetic calming (increases with safety/sleep/OXT)
      - body_stress  : integrated somatic burden = 0.6*cortisol + 0.4*heart_rate

    Brain feedback effects (applied in main loop):
      1. High vagal_tone suppresses HPA activation (applied post-step to cort.level)
         Porges 2007: vagal cardiac brake buffers amygdala -> HPA pathway
      2. High body_stress amplifies amygdala threat signal (applied to bla_valence)
         Damasio 1999: somatic markers bias threat evaluation

    All state variables bounded in [0, 1].
    Low-frequency dynamics (≤0.01/tick) preserve simulation stability.
    """
    def __init__(self):
        self.heart_rate  = 0.5   # peripheral cardiac arousal [0, 1]
        self.vagal_tone  = 0.5   # parasympathetic tone [0, 1]
        self.body_stress = 0.2   # integrated somatic burden [0, 1]

    def update(self, cortisol, oxytocin, sleep_phase='AWAKE'):
        """
        Update interoceptive body signals for this tick.

        cortisol    : float [0,1] -- current cort.level
        oxytocin    : float [0,1] -- current oxt.level
        sleep_phase : str  -- 'SWS', 'REM', 'SWR', or 'AWAKE'
        """
        # --- Heart rate dynamics ---
        # Stress raises HR (sympathetic activation; Berntson 1997)
        if cortisol > 0.6:
            self.heart_rate = min(1.0, self.heart_rate + 0.01)
        # High vagal tone applies cardiac brake (Porges 2007)
        if self.vagal_tone > 0.6:
            self.heart_rate = max(0.0, self.heart_rate - 0.01)
        # SWS sleep: HR slows (Born et al. 1997)
        if sleep_phase == 'SWS':
            self.heart_rate = max(0.0, self.heart_rate - 0.01)
        # Passive recovery toward resting rate (0.5) at very slow pace
        self.heart_rate += 0.0005 * (0.5 - self.heart_rate)
        self.heart_rate = max(0.0, min(1.0, self.heart_rate))

        # --- Vagal tone dynamics ---
        # SWS sleep boosts parasympathetic tone (Porges 2007)
        if sleep_phase == 'SWS':
            self.vagal_tone = min(1.0, self.vagal_tone + 0.01)
        # Oxytocin: social safety increases vagal tone (Uvnäs-Moberg 2003)
        self.vagal_tone = min(1.0, self.vagal_tone + oxytocin * 0.002)
        # Cortisol: chronic stress suppresses vagal tone (McEwen 1998)
        self.vagal_tone = max(0.0, self.vagal_tone - cortisol * 0.002)
        # Slow recovery toward baseline when unstressed
        self.vagal_tone += 0.0003 * (0.5 - self.vagal_tone)
        self.vagal_tone = max(0.0, min(1.0, self.vagal_tone))

        # --- Body stress: integrated somatic burden ---
        # Damasio 1999: somatic marker = weighted sum of stress signals
        self.body_stress = min(1.0, 0.6 * cortisol + 0.4 * self.heart_rate)

        return self.heart_rate, self.vagal_tone, self.body_stress

    def export_metrics(self):
        return {
            'heart_rate':  round(self.heart_rate,  4),
            'vagal_tone':  round(self.vagal_tone,  4),
            'body_stress': round(self.body_stress, 4),
        }


# ===========================================================================
# DAY 15: GLOBAL HOMEOSTATIC REGULATION SYSTEM
# Cannon 1932 (Homeostasis), Sterling & Eyer 1988 (Allostasis),
# Friston 2010 (Active Inference), Damasio 1999 (Somatic Marker Hypothesis)
# ===========================================================================

class HomeostasisSystem:
    """
    Central homeostatic regulation layer.

    Continuously monitors key physiological state variables and computes
    motivational drives representing the organism's internal imbalance.
    Drives guide action selection and physiological regulation.

    Mathematical foundation (Cannon 1932 / Sterling & Eyer 1988):
        Deviation:         D_i  = x_i - x*_i
        Drive strength:    d_i  = |D_i|  (clipped to [0,1])
        Global imbalance:  E    = Σ w_i * |x_i - x*_i|

    Five primary drives:
        hunger    -- energy below setpoint        (explore/forage)
        safety    -- cortisol above setpoint       (withdraw/regulate)
        social    -- oxytocin below setpoint       (approach agent)
        sleep     -- adenosine above setpoint      (rest/consolidate)
        curiosity -- prediction error / novelty    (explore/learn)

    Sleep regulation:
        sleep onset: sleep_drive > SLEEP_ONSET_THRESHOLD  (0.70)
        sleep end:   sleep_drive < SLEEP_OFFSET_THRESHOLD (0.30)
        Replaces hard tick-counter (SLEEP_START/SLEEP_END) with
        physiological sleep pressure, matching the Borbély two-process
        model (Borbély 1982): sleep pressure rises with adenosine
        accumulation (Process S) and falls during sleep (clearance).

    All outputs bounded in [0, 1].
    Setpoints updated ONLY through AllostasisSystem -- never directly here.
    """

    # --- Sleep pressure thresholds (Borbély 1982 Process S) ---
    SLEEP_ONSET_THRESHOLD  = 0.30   # Process S threshold (gate is Process C -- see should_sleep_onset)
    SLEEP_OFFSET_THRESHOLD = 0.30   # sleep_drive below this -> sleep ends
    # Minimum waking ticks before sleep is allowed (prevents rapid oscillations)
    MIN_WAKE_TICKS = 200   # Day 19: longer wake enforcement (Borbely two-process gating)

    def __init__(self):
        # --- Homeostatic setpoints (target physiological values) ---
        self.setpoints = {
            "energy":    0.70,   # preferred regional cortical energy
            "cortisol":  0.15,   # preferred cortisol (resting baseline)
            "oxytocin":  0.40,   # preferred oxytocin (social bond)
            "adenosine": 0.20,   # preferred adenosine (rested state)
        }

        # --- Regulatory importance weights (Σ w_i = 1.0) ---
        self.weights = {
            "energy":    0.30,
            "cortisol":  0.30,
            "oxytocin":  0.20,
            "adenosine": 0.20,
        }

        # --- Current motivational drives [0, 1] ---
        self.drives = {
            "hunger":    0.0,
            "safety":    0.0,
            "social":    0.0,
            "sleep":     0.0,
            "curiosity": 0.0,
        }

        # --- Global imbalance score E ---
        self.global_imbalance = 0.0

        # --- Internal state tracking ---
        self._wake_ticks    = 0     # consecutive waking ticks since last sleep
        self._sleep_active  = False # homeostatic sleep currently active
        self._last_cortisol = 0.0   # Law 3: stored for sleep gate (Buckley & Schatzberg 2005)

    def update(self, avg_energy, cortisol, oxytocin, adenosine, prediction_error):
        """
        Compute all motivational drives for the current tick.

        avg_energy       : float [0,1] -- mean cortical regional energy
        cortisol         : float [0,1] -- cort.level
        oxytocin         : float [0,1] -- oxt.level
        adenosine        : float [0,1] -- ado.level
        prediction_error : float ≥0   -- pp.error (prediction error magnitude)
        """
        sp = self.setpoints

        # --- Per-variable deviation and drive computation ---
        # hunger: energy below setpoint drives foraging/exploring
        self.drives["hunger"] = max(0.0, min(1.0, sp["energy"] - avg_energy))

        # safety: cortisol above setpoint drives withdrawal/regulation
        self.drives["safety"] = max(0.0, min(1.0, cortisol - sp["cortisol"]))

        # social: oxytocin below setpoint drives social approach
        self.drives["social"] = max(0.0, min(1.0, sp["oxytocin"] - oxytocin))

        # sleep: adenosine above setpoint drives rest (Borbely 1982 two-process model)
        sleep_pressure = max(0.0, adenosine - sp["adenosine"])
        sleep_pressure *= 0.6
        # curiosity opposes sleep (Friston 2010 active inference)
        sleep_pressure *= (1.0 - min(0.5, prediction_error * 0.5))
        self.drives["sleep"] = min(1.0, sleep_pressure)

        # curiosity: proportional to prediction error (Friston 2010 free energy)
        self.drives["curiosity"] = max(0.0, min(1.0, prediction_error))

        # --- Global imbalance E = Σ w_i * |x_i - x*_i| ---
        weighted = (
            self.weights["energy"]    * abs(avg_energy - sp["energy"])
            + self.weights["cortisol"]  * abs(cortisol  - sp["cortisol"])
            + self.weights["oxytocin"]  * abs(oxytocin  - sp["oxytocin"])
            + self.weights["adenosine"] * abs(adenosine - sp["adenosine"])
        )
        self.global_imbalance = min(1.0, weighted)

        # --- Wake tick counter (used by homeostatic sleep onset logic) ---
        if not self._sleep_active:
            self._wake_ticks += 1
        else:
            self._wake_ticks = 0

        # Law 3 support: store cortisol so should_sleep_onset() can gate on it
        self._last_cortisol = cortisol

    def should_sleep_onset(self, circadian=None):
        """
        Returns True when homeostatic sleep pressure is sufficient for sleep AND
        circadian rhythm permits sleep onset (Borbely 1982 Two-Process Model).

        Process C (circadian) gates when sleep is allowed.
        Process S (adenosine) determines drive strength within that window.
        Law 3: Elevated cortisol suppresses sleep onset (Buckley & Schatzberg 2005).
        """
        # Day 19: Circadian gate (Process C) -- sleep only allowed in circadian sleep phase
        if circadian is not None and not circadian.is_sleep_phase():
            return False
        # Law 3 (upgraded Day 17): Probabilistic cortisol sleep gate (Buckley & Schatzberg 2005)
        # Replaces hard threshold with continuous probability -- biologically realistic
        # At cort=0: 100% sleep allowed; at cort=0.83+: fully blocked
        _sleep_prob = max(0.0, 1.0 - self._last_cortisol * 1.2)
        if random.random() > _sleep_prob:
            return False
        # Day 18 Threat/Arousal: arousal override blocks sleep onset (Aston-Jones & Cohen 2005)
        # High arousal enforces wakefulness -- threat detected organisms cannot sleep
        if getattr(self, '_arousal_override', False):
            return False
        return (
            self.drives["sleep"] > self.SLEEP_ONSET_THRESHOLD
            and self._wake_ticks >= self.MIN_WAKE_TICKS
            and not self._sleep_active
        )

    def should_sleep_end(self):
        """Returns True when sleep pressure has been relieved sufficiently."""
        return self._sleep_active and self.drives["sleep"] < self.SLEEP_OFFSET_THRESHOLD

    def mark_sleep_start(self):
        self._sleep_active = True
        self._wake_ticks   = 0

    def mark_sleep_end(self):
        self._sleep_active = False

    def get_bg_drive_biases(self):
        """
        Return action channel biases for the BasalGangliaSystem.
        Higher bias -> higher channel drive, increasing probability of that action.

        Maps:
            hunger  -> explore  (forage for novel inputs)
            safety  -> withdraw (threat avoidance)
            social  -> approach (reconnect with agent)
            curiosity -> explore (epistemic motivation)

        Biases are small additive offsets to L5 drive signals.
        Bounded returns prevent drive biases from dominating neural signals.
        """
        return {
            "approach": min(0.30, self.drives["social"]   * 0.50),
            "withdraw": min(0.30, self.drives["safety"]   * 0.60),
            "explore":  min(0.30, (self.drives["hunger"]  * 0.40
                                    + self.drives["curiosity"] * 0.40)),
        }

    def export_metrics(self):
        return {
            "hunger":           round(self.drives["hunger"],    3),
            "safety":           round(self.drives["safety"],    3),
            "social":           round(self.drives["social"],    3),
            "sleep":            round(self.drives["sleep"],     3),
            "curiosity":        round(self.drives["curiosity"], 3),
            "global_imbalance": round(self.global_imbalance,   3),
        }


# ===========================================================================
# LATENT STATE VECTOR (LSV) -- 64-dim compressed cognitive-context substrate
# Friston 2010 (predictive processing); Damasio 1994 (somatic marker);
# Dayan & Abbott 2001 (neural representations)
#
# Provides a single continuously-updated vector summarising Ikigai's lived
# context.  Shared substrate for ConceptGraph, ReplayBuffer, ActionExplanation,
# language grounding, and long-horizon planning.
#
# Layout:
#   dims  0-15  body / interoception   (all [0,1])
#   dims 16-31  neural summary          (all [0,1])
#   dims 32-47  world context           (all [0,1])
#   dims 48-63  temporal traces         (all [0,1])
#
# Rules:
#   - Read-only observer: never modifies any biological variable.
#   - Updated every WAKING tick after homeostasis.update().
#   - decay(0.001) called every SLEEPING tick (biological forgetting).
#   - Serialised via to_dict() / from_dict() for cross-session persistence.
# ===========================================================================

class LatentStateVector:
    """64-dim continuous float vector representing Ikigai's compressed lived context."""

    DIM   = 64
    ALPHA = 0.92   # EMA weight on previous tick (tau ~ 12 ticks)

    # Action embedding: explore=0.0, approach=0.5, withdraw=1.0
    _ACTION_ENC = {'explore': 0.0, 'approach': 0.5, 'withdraw': 1.0}

    # Canonical dim names (used by snapshot())
    _NAMES = [
        # body (0-15)
        'energy',               'energy_slope',         'cortisol',
        'cortisol_slope',       'adenosine',            'oxytocin',
        'vagal_tone',           'body_stress',          'dopamine_tonic',
        'dopamine_phasic',      'uncertainty',          'global_imbalance',
        'hunger_drive',         'safety_drive',         'sleep_drive',
        'curiosity_drive',
        # neural (16-31)
        'total_spike_rate',     'ei_ratio',             'dominant_assembly_strength',
        'assembly_entropy',     'wm_load',              'prediction_error',
        'memory_confidence',    'action_streak',        'habit_strength',
        'conflict_density',     'oscillation_phase',    'dmn_gain',
        'task_gain',            'narrative_coherence',  'replay_readiness',
        'regulation_confidence',
        # world (32-47)
        'x',                    'y',                    'velocity',
        'last_reward_x',        'last_reward_y',        'last_threat_x',
        'last_threat_y',        'novelty_density',      'spatial_uncertainty',
        'local_valence',        'resource_probability', 'danger_probability',
        'safe_zone_confidence', 'last_external_event',  'current_object_type',
        'context_id',
        # temporal traces (48-63)
        'prev_action_embedding', 'prev_concept_embedding', 'prev_latent_delta',
        'trace_body',           'trace_neural',         'trace_world',
        'trace_3',              'trace_4',              'trace_5',
        'trace_6',              'trace_7',              'trace_8',
        'trace_9',              'trace_10',             'trace_11',
        'trace_12',
    ]

    def __init__(self):
        self.v               = [0.0] * self.DIM
        self._prev_snapshot  = [0.0] * self.DIM
        self._trace_slots    = [0.0] * 13
        self._prev_energy    = 0.5
        self._prev_cort      = 0.15
        self._prev_concept   = 0.0
        self._tick           = 0

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    @staticmethod
    def _clamp(x, lo=0.0, hi=1.0):
        return lo if x < lo else (hi if x > hi else x)

    def _ema(self, old, new):
        return self.ALPHA * old + (1.0 - self.ALPHA) * new

    def _norm_pos(self, val, bound=100.0):
        """Spatial position [-bound, bound] -> [0, 1]."""
        return self._clamp((val + bound) / (2.0 * bound))

    def _norm_gain(self, val, lo=0.8, hi=1.2):
        """DMN/task network gain [0.8, 1.2] -> [0, 1]."""
        return self._clamp((val - lo) / (hi - lo))

    # ------------------------------------------------------------------
    # Core API
    # ------------------------------------------------------------------

    def update(self, body, neural, world, action='withdraw', concept_val=0.0):
        """
        Compute new raw feature vector, apply EMA, store result.

        Parameters
        ----------
        body        : dict of interoceptive / neuromodulator readings
        neural      : dict of neural population summary statistics
        world       : dict of spatial and environmental context
        action      : current selected action string
        concept_val : current dominant assembly activation [0, 1]
        """
        self._tick += 1
        c = self._clamp

        # Slope features: compare against previous raw value (not EMA)
        energy_raw   = c(body.get('energy',   0.5))
        cort_raw     = c(body.get('cortisol', 0.15))
        energy_slope = c((energy_raw - self._prev_energy) + 0.5)  # centred at 0.5
        cort_slope   = c((cort_raw   - self._prev_cort)   + 0.5)
        self._prev_energy = energy_raw
        self._prev_cort   = cort_raw

        # --- raw feature vector construction (must yield exactly DIM values) ---
        raw = [
            # dims 0-15: body
            energy_raw,
            energy_slope,
            cort_raw,
            cort_slope,
            c(body.get('adenosine',        0.0)),
            c(body.get('oxytocin',         0.3)),
            c(body.get('vagal_tone',       0.5)),
            c(body.get('body_stress',      0.2)),
            c(body.get('dopamine_tonic',   0.3)),
            c(body.get('dopamine_phasic',  0.0)),
            c(body.get('uncertainty',      0.0)),
            c(body.get('global_imbalance', 0.0)),
            c(body.get('hunger_drive',     0.0)),
            c(body.get('safety_drive',     0.0)),
            c(body.get('sleep_drive',      0.0)),
            c(body.get('curiosity_drive',  0.0)),
            # dims 16-31: neural
            c(neural.get('total_spike_rate',             0.0)),
            c(neural.get('ei_ratio',                     0.5)),
            c(neural.get('dominant_assembly_strength',   0.0)),
            c(neural.get('assembly_entropy',             0.0)),
            c(neural.get('wm_load',                      0.0)),
            c(neural.get('prediction_error',             0.0)),
            c(neural.get('memory_confidence',            0.5)),
            c(neural.get('action_streak',                0.0) / 50.0),
            c(neural.get('habit_strength',               0.0)),
            c(neural.get('conflict_density',             0.0)),
            c((neural.get('oscillation_phase', 0.0) + 1.0) / 2.0),
            self._norm_gain(neural.get('dmn_gain',  1.0)),
            self._norm_gain(neural.get('task_gain', 1.0)),
            c(neural.get('narrative_coherence',          0.0)),
            c(neural.get('replay_readiness',             0.0)),
            c(neural.get('regulation_confidence',        0.0)),
            # dims 32-47: world
            self._norm_pos(world.get('x',           0.0)),
            self._norm_pos(world.get('y',           0.0)),
            c(world.get('velocity',                  0.0)),
            self._norm_pos(world.get('last_reward_x', 0.0)),
            self._norm_pos(world.get('last_reward_y', 0.0)),
            self._norm_pos(world.get('last_threat_x', 0.0)),
            self._norm_pos(world.get('last_threat_y', 0.0)),
            c(world.get('novelty_density',           0.0)),
            c(world.get('spatial_uncertainty',       0.5)),
            c((world.get('local_valence', 0.0) + 1.0) / 2.0),
            c(world.get('resource_probability',      0.5)),
            c(world.get('danger_probability',        0.0)),
            c(world.get('safe_zone_confidence',      0.5)),
            c(world.get('last_external_event',       0.0)),
            c(world.get('current_object_type',       0.0)),
            c(world.get('context_id',                0.0) / 10.0),
        ]

        # dims 48-50: temporal anchor
        action_emb = self._ACTION_ENC.get(action, 0.0)
        prev_delta = c(sum(abs(self.v[i] - self._prev_snapshot[i])
                          for i in range(self.DIM)) / self.DIM)
        raw += [action_emb, c(self._prev_concept), prev_delta]

        # dims 51-63: rolling learned trace slots (per-region delta EMAs)
        trace_body   = sum(abs(self.v[i]    - raw[i])    for i in range(16)) / 16.0
        trace_neural = sum(abs(self.v[i+16] - raw[i+16]) for i in range(16)) / 16.0
        trace_world  = sum(abs(self.v[i+32] - raw[i+32]) for i in range(16)) / 16.0
        self._trace_slots[0] = self._ema(self._trace_slots[0], trace_body)
        self._trace_slots[1] = self._ema(self._trace_slots[1], trace_neural)
        self._trace_slots[2] = self._ema(self._trace_slots[2], trace_world)
        # slots 3-12 reserved for future learned traces, held at 0.0
        raw += [c(self._trace_slots[i]) for i in range(13)]

        # Apply EMA to all dims
        self._prev_snapshot = self.v[:]
        for i in range(self.DIM):
            self.v[i] = self._ema(self.v[i], raw[i])

        self._prev_concept = concept_val

    def snapshot(self):
        """Return current vector as a named dict (64 keys)."""
        return dict(zip(self._NAMES, self.v))

    def snapshot_vector(self):
        """Return current vector as a plain list[64] (for ARL latent_pre/post capture)."""
        return self.v[:]

    def similarity(self, other):
        """Cosine similarity [0, 1] (both vectors non-negative)."""
        dot   = sum(self.v[i] * other.v[i] for i in range(self.DIM))
        mag_a = math.sqrt(sum(x * x for x in self.v))  + 1e-9
        mag_b = math.sqrt(sum(x * x for x in other.v)) + 1e-9
        return dot / (mag_a * mag_b)

    def decay(self, rate=0.001):
        """
        Gentle pull toward 0.5 during sleep (biological forgetting / NREM diffusion).
        rate=0.001/tick: 500 sleep ticks moves a dim ~40% toward neutral from any extreme.
        """
        for i in range(self.DIM):
            self.v[i] += rate * (0.5 - self.v[i])

    # ------------------------------------------------------------------
    # Serialisation (for PersistenceSystem integration)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'v':               self.v[:],
            '_prev_snapshot':  self._prev_snapshot[:],
            '_trace_slots':    self._trace_slots[:],
            '_prev_energy':    self._prev_energy,
            '_prev_cort':      self._prev_cort,
            '_prev_concept':   self._prev_concept,
            '_tick':           self._tick,
        }

    @classmethod
    def from_dict(cls, d):
        lsv = cls()
        lsv.v              = list(d.get('v',              [0.0] * cls.DIM))
        lsv._prev_snapshot = list(d.get('_prev_snapshot', [0.0] * cls.DIM))
        lsv._trace_slots   = list(d.get('_trace_slots',   [0.0] * 13))
        lsv._prev_energy   = float(d.get('_prev_energy',  0.5))
        lsv._prev_cort     = float(d.get('_prev_cort',    0.15))
        lsv._prev_concept  = float(d.get('_prev_concept', 0.0))
        lsv._tick          = int(d.get('_tick',           0))
        return lsv


# ===========================================================================
# ACTION REASONING LOG  (Rank 5 cognition substrate -- Prince Siddhpara 2026)
# Records per-tick causal decision trace: which stage won, latent pre/post,
# survival scores, explore prob, and energy/cortisol deltas.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class ActionReasoningLog:
    """
    Causal rationale trace for every decision tick.

    Stores records in a memory-safe collections.deque(maxlen=1000).
    Each record is a flat dict -- serialisable, inspectable, and replayable.

    Record schema
    -------------
    tick            : int   -- absolute simulation tick
    latent_pre      : list  -- LSV snapshot BEFORE action selection (len 64)
    wm_scores       : dict  -- world-model survival values {action: float}
    explore_prob    : float -- computed exploration probability this tick
    floor_triggered : bool  -- True when 0.02 random floor fired
    selected_action : str   -- final action string
    reason_stage    : str   -- 'wm' | 'explore' | 'floor'
    energy_delta    : float -- energy change this tick (post - pre)
    cortisol_delta  : float -- cortisol change this tick (post - pre)
    latent_post     : list  -- LSV snapshot AFTER update (len 64)

    Future consumers (read-only)
    ----------------------------
    narrative.action_log   -- grounded sentence generation
    planning_sys.action_log -- replay supervision / counterfactual
    semantic.action_log    -- concept supervision
    """

    def __init__(self, maxlen=1000):
        self._log     = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        self.total_recorded = 0          # monotonic counter, never resets

    # ------------------------------------------------------------------
    # Write path (called once per waking tick from main loop)
    # ------------------------------------------------------------------

    def record(
        self,
        tick,
        latent_pre,
        wm_scores,
        explore_prob,
        floor_triggered,
        selected_action,
        reason_stage,
        energy_delta,
        cortisol_delta,
        latent_post,
    ):
        """
        Append one tick record.  All list arguments are shallow-copied
        so the ring-buffer owns its own data and cannot alias live state.
        """
        self._log.append({
            'tick':            int(tick),
            'latent_pre':      list(latent_pre),
            'wm_scores':       dict(wm_scores),
            'explore_prob':    float(explore_prob),
            'floor_triggered': bool(floor_triggered),
            'selected_action': str(selected_action),
            'reason_stage':    str(reason_stage),
            'energy_delta':    float(energy_delta),
            'cortisol_delta':  float(cortisol_delta),
            'latent_post':     list(latent_post),
        })
        self.total_recorded += 1

    # ------------------------------------------------------------------
    # Read path (zero side-effects)
    # ------------------------------------------------------------------

    def recent(self, n=10):
        """Return the last n records (oldest first) as a list."""
        buf = list(self._log)
        return buf[-n:] if n < len(buf) else buf

    def last(self):
        """Return the most recent record, or None if empty."""
        return self._log[-1] if self._log else None

    def __len__(self):
        return len(self._log)

    # ------------------------------------------------------------------
    # Serialisation (for PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':         self._maxlen,
            'total_recorded': self.total_recorded,
            'log':            list(self._log),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 1000)))
        obj.total_recorded = int(d.get('total_recorded', 0))
        for rec in d.get('log', []):
            obj._log.append(rec)
        return obj


# ===========================================================================
# REPLAY BUFFER  (Rank 6 cognition substrate -- Prince Siddhpara 2026)
# Stores decision transition episodes for replay-driven learning.
# Distinct from EpisodicReplaySystem (spatial trajectories) and
# ActionReasoningLog (full trace).  This stores compact (s,a,r,s') tuples
# suitable for credit assignment and policy gradient estimation during sleep.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class ReplayBuffer:
    """
    Salience-biased experience replay buffer for decision transitions.

    Stores compact (latent_pre, action, reason_stage, deltas, latent_post)
    episodes in a bounded deque(maxlen=2000).  Sampling prioritises
    high-salience transitions (large |energy_delta| + |cortisol_delta|)
    to bias replay toward consequential events.

    Episode schema
    --------------
    tick            : int    -- absolute simulation tick
    latent_pre      : list   -- LSV snapshot BEFORE action (len 64)
    action          : str    -- selected action string
    reason_stage    : str    -- 'wm' | 'explore' | 'floor'
    energy_delta    : float  -- energy change this tick
    cortisol_delta  : float  -- cortisol change this tick
    latent_post     : list   -- LSV snapshot AFTER update (len 64)

    Future consumers (read-only)
    ----------------------------
    sleep consolidation  -- sample_for_replay(k=16) during SWS
    semantic             -- concept supervision from salient transitions
    planning_sys         -- counterfactual planning from stored transitions
    episodic_replay      -- cross-system trajectory alignment
    """

    def __init__(self, maxlen=2000):
        self._buf    = deque(maxlen=maxlen)
        self._maxlen = maxlen
        self.total_pushed = 0         # monotonic counter, survives overflow

    # ------------------------------------------------------------------
    # Write path  (called once per waking tick, after ARL.record())
    # ------------------------------------------------------------------

    def push(
        self,
        tick,
        latent_pre,
        action,
        reason_stage,
        energy_delta,
        cortisol_delta,
        latent_post,
    ):
        """
        Append one transition.  Lists are shallow-copied so the buffer
        owns its data and cannot alias live latent state.
        """
        self._buf.append({
            'tick':           int(tick),
            'latent_pre':     list(latent_pre),
            'action':         str(action),
            'reason_stage':   str(reason_stage),
            'energy_delta':   float(energy_delta),
            'cortisol_delta': float(cortisol_delta),
            'latent_post':    list(latent_post),
        })
        self.total_pushed += 1

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def _salience(self, ep):
        """Salience score for an episode (higher = more consequential)."""
        return abs(ep['energy_delta']) + abs(ep['cortisol_delta'])

    def sample(self, k=16, seed=None):
        """
        Return up to k episodes sampled with salience bias.

        Algorithm (O(n log n), n = buffer size):
          1. Sort all episodes by salience descending.
          2. Consider top 25% (at least k) as the candidate pool.
          3. Randomly sample k from the pool (without replacement).
          4. Fall back to full random sample when buffer is tiny.

        seed : int or None  -- pass an int for deterministic tests.
        """
        buf = list(self._buf)
        if not buf:
            return []
        if len(buf) <= k:
            return list(buf)          # return everything when small

        rng = random.Random(seed) if seed is not None else random

        # Sort by salience descending; stable sort preserves FIFO for ties
        sorted_buf = sorted(buf, key=self._salience, reverse=True)

        # Top 25% pool, but at least k candidates
        pool_size = max(k, len(sorted_buf) // 4)
        pool      = sorted_buf[:pool_size]

        return rng.sample(pool, k)

    def sample_for_replay(self, k=16):
        """
        Convenience alias used by sleep consolidation.
        Returns a salience-biased sample of up to k transition episodes.
        The caller must not modify the returned dicts.
        """
        return self.sample(k=k)

    def recent(self, n=10):
        """Return the last n pushed episodes (oldest-first)."""
        buf = list(self._buf)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._buf)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':       self._maxlen,
            'total_pushed': self.total_pushed,
            'buf':          list(self._buf),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 2000)))
        obj.total_pushed = int(d.get('total_pushed', 0))
        for ep in d.get('buf', []):
            obj._buf.append(ep)
        return obj


# ===========================================================================
# EVENT COMPRESSOR  (Rank 2 cognition substrate -- Prince Siddhpara 2026)
# Converts streams of replay transitions into compressed meaningful episodes.
# Episode = contiguous run of transitions sharing action family, reason stage,
# high latent similarity, and rising cumulative salience.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class EventCompressor:
    """
    Temporal event segmentation over replay transitions.

    Reads from ReplayBuffer transitions (via ingest_transition), groups
    temporally contiguous, contextually similar transitions into compressed
    events, and stores them in a bounded deque(maxlen=500).

    Segmentation law (ALL must hold to stay in same event):
      1. ticks are contiguous (gap <= 1)
      2. cosine_similarity(latent_post_prev, latent_pre_next) > 0.90
      3. same action family OR same reason_stage
      4. cumulative salience still rising (not dropped sharply)

    Compressed event schema
    -----------------------
    start_tick             : int   - first tick of the episode
    end_tick               : int   - last tick of the episode
    length                 : int   - number of transitions merged
    dominant_action        : str   - most frequent action in run
    dominant_reason_stage  : str   - most frequent reason_stage in run
    mean_energy_delta      : float - mean energy_delta across run
    mean_cortisol_delta    : float - mean cortisol_delta across run
    peak_salience          : float - max |e_delta|+|c_delta| in run
    latent_start           : list  - latent_pre of first transition (len 64)
    latent_end             : list  - latent_post of last transition (len 64)

    Future consumers (read-only)
    ----------------------------
    semantic.event_compressor   - concept chunking / grounded sentences
    narrative.event_compressor  - narrative episode construction
    planning_sys.event_compressor - hierarchical planning motifs
    """

    # Segmentation thresholds (class-level constants for easy tuning)
    _SIM_THRESHOLD  = 0.90   # cosine similarity gate
    _SAL_DROP_RATIO = 0.30   # flush if cumulative salience drops by >30%

    def __init__(self, maxlen=500, min_event_len=3):
        self._events       = deque(maxlen=maxlen)
        self._maxlen       = maxlen
        self._min_len      = min_event_len
        self.current_event = []          # accumulator for current open event
        self._cum_salience = 0.0         # running cumulative salience
        self._peak_sal     = 0.0         # peak salience so far in current event
        self.total_flushed = 0           # monotonic compressed-event counter

    # ------------------------------------------------------------------
    # Cosine similarity  (internal, no imports)
    # ------------------------------------------------------------------

    @staticmethod
    def _cos_sim(a, b):
        """Cosine similarity between two equal-length float lists."""
        dot  = sum(x * y for x, y in zip(a, b))
        ma   = math.sqrt(sum(x * x for x in a)) + 1e-9
        mb   = math.sqrt(sum(x * x for x in b)) + 1e-9
        return dot / (ma * mb)

    @staticmethod
    def _salience(ep):
        return abs(ep['energy_delta']) + abs(ep['cortisol_delta'])

    @staticmethod
    def _action_family(action):
        """Map action string to coarse family bucket."""
        return action.lower().strip()   # identity for now; extend for aliases

    # ------------------------------------------------------------------
    # Write path
    # ------------------------------------------------------------------

    def ingest_transition(self, ep):
        """
        Ingest one replay transition dict.  Decides whether to continue
        the current event or flush and start a new one.

        ep  : dict with keys tick, latent_pre, latent_post, action,
              reason_stage, energy_delta, cortisol_delta
        """
        sal = self._salience(ep)

        if not self.current_event:
            # Start fresh event
            self.current_event.append(ep)
            self._cum_salience = sal
            self._peak_sal     = sal
            return

        prev = self.current_event[-1]

        # --- Segmentation checks ---
        tick_gap   = ep['tick'] - prev['tick']
        sim        = self._cos_sim(prev['latent_post'], ep['latent_pre'])
        same_fam   = (self._action_family(ep['action']) ==
                      self._action_family(prev['action']))
        same_stage = ep['reason_stage'] == prev['reason_stage']
        new_sal    = self._cum_salience + sal
        sal_ok     = (self._peak_sal < 1e-9 or
                      new_sal >= self._cum_salience * (1.0 - self._SAL_DROP_RATIO))

        # Merge law:
        #   1. ticks contiguous (gap <= 1)
        #   2. latent continuity (cosine sim > threshold)
        #   3. same action family  [hard primary gate -- action switch always splits]
        #   4. within same family: same reason_stage OR very high sim (>0.95) keeps merged
        #   5. cumulative salience still rising
        context_ok = same_fam and (same_stage or sim > 0.95)

        if (tick_gap <= 1 and
                sim > self._SIM_THRESHOLD and
                context_ok and
                sal_ok):
            # Continue current event
            self.current_event.append(ep)
            self._cum_salience = new_sal
            self._peak_sal     = max(self._peak_sal, sal)
        else:
            # Boundary detected: flush, then start new event
            self.flush_current_event()
            self.current_event = [ep]
            self._cum_salience = sal
            self._peak_sal     = sal

    def flush_current_event(self, reason='boundary'):
        """
        Compress and store self.current_event if it meets min_event_len.
        Clears the accumulator.  reason is informational only.
        """
        evs = self.current_event
        if not evs or len(evs) < self._min_len:
            self.current_event = []
            self._cum_salience = 0.0
            self._peak_sal     = 0.0
            return

        # --- Compute compressed fields ---
        n   = len(evs)
        actions = [e['action'] for e in evs]
        stages  = [e['reason_stage'] for e in evs]
        dom_action = max(set(actions), key=actions.count)
        dom_stage  = max(set(stages),  key=stages.count)
        mean_e_delta = sum(e['energy_delta']   for e in evs) / n
        mean_c_delta = sum(e['cortisol_delta'] for e in evs) / n
        peak_sal     = max(self._salience(e) for e in evs)

        compressed = {
            'start_tick':            evs[0]['tick'],
            'end_tick':              evs[-1]['tick'],
            'length':                n,
            'dominant_action':       dom_action,
            'dominant_reason_stage': dom_stage,
            'mean_energy_delta':     mean_e_delta,
            'mean_cortisol_delta':   mean_c_delta,
            'peak_salience':         peak_sal,
            'latent_start':          list(evs[0]['latent_pre']),
            'latent_end':            list(evs[-1]['latent_post']),
        }
        self._events.append(compressed)
        self.total_flushed += 1

        # Reset accumulator
        self.current_event = []
        self._cum_salience = 0.0
        self._peak_sal     = 0.0

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def recent(self, n=10):
        """Return the last n compressed events (oldest-first)."""
        buf = list(self._events)
        return buf[-n:] if n < len(buf) else buf

    def last(self):
        """Return most recent compressed event, or None."""
        return self._events[-1] if self._events else None

    def __len__(self):
        return len(self._events)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':        self._maxlen,
            'min_event_len': self._min_len,
            'total_flushed': self.total_flushed,
            'events':        list(self._events),
            'current_event': list(self.current_event),
            '_cum_salience': self._cum_salience,
            '_peak_sal':     self._peak_sal,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(
            maxlen       = int(d.get('maxlen', 500)),
            min_event_len= int(d.get('min_event_len', 3)),
        )
        obj.total_flushed  = int(d.get('total_flushed', 0))
        obj._cum_salience  = float(d.get('_cum_salience', 0.0))
        obj._peak_sal      = float(d.get('_peak_sal', 0.0))
        for ev in d.get('events', []):
            obj._events.append(ev)
        obj.current_event  = list(d.get('current_event', []))
        return obj



# ===========================================================================
# CONCEPT GRAPH  (Rank 3 cognition substrate -- Prince Siddhpara 2026)
# Converts repeated compressed events into stable reusable latent concepts.
# Concepts are latent centroids + transition motifs, not string tokens.
# Edge reinforcement encodes sequential concept transitions for reasoning.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class ConceptGraph:
    """
    Learnable concept graph over compressed episode space.

    Each node is a latent concept centroid formed by EMA-merging recurring
    compressed events that share action family, reason stage, and high cosine
    similarity.  Directed edges record sequential concept activations.

    Node format
    -----------
    id                   : int
    centroid             : list[64]  -- EMA latent prototype
    dominant_action      : str
    dominant_reason_stage: str
    support              : int       -- number of events merged
    mean_salience        : float     -- EMA of peak_salience
    last_tick            : int
    debug_label          : str|None  -- optional human-readable tag

    Edge format
    -----------
    edges[(src_id, dst_id)] : int  -- activation count, capped at 255

    Concept formation law
    ---------------------
    Merge into existing node if ALL hold:
      1. cosine_similarity(event.latent_end, centroid) > similarity_threshold
      2. dominant_action matches
      3. dominant_reason_stage matches OR similarity > 0.97
    Otherwise create new node.
    Overflow (>max_nodes): evict node with lowest support * recency score.

    Edge law
    --------
    Consecutive concept activations within 10 ticks reinforce the directed
    edge (src -> dst).  Weight capped at 255.
    """

    # EMA weight for centroid update (tau ~ 20 events)
    _CENTROID_ALPHA = 0.95

    def __init__(self, max_nodes=128, similarity_threshold=0.93):
        self.nodes        = {}   # id -> node dict
        self.edges        = {}   # (src_id, dst_id) -> int count
        self.node_counter = 0    # monotonic, never decrements
        self._max_nodes   = max_nodes
        self._sim_thresh  = similarity_threshold
        self._last_node_id   = None   # for edge reinforcement
        self._last_node_tick = -999   # tick of last activation
        self.total_ingested  = 0      # monotonic event counter

    # ------------------------------------------------------------------
    # Cosine similarity (internal, no imports needed)
    # ------------------------------------------------------------------

    @staticmethod
    def _cos_sim(a, b):
        dot = sum(x * y for x, y in zip(a, b))
        ma  = math.sqrt(sum(x * x for x in a)) + 1e-9
        mb  = math.sqrt(sum(x * x for x in b)) + 1e-9
        return dot / (ma * mb)

    @staticmethod
    def _ema(old, new, alpha):
        return alpha * old + (1.0 - alpha) * new

    # ------------------------------------------------------------------
    # Write path
    # ------------------------------------------------------------------

    def ingest_event(self, event):
        """
        Ingest one compressed event dict from EventCompressor.
        Merges into an existing concept node or creates a new one.
        Reinforces sequential edge from last activated concept.

        event keys: start_tick, end_tick, length, dominant_action,
                    dominant_reason_stage, mean_energy_delta,
                    mean_cortisol_delta, peak_salience,
                    latent_start, latent_end
        """
        if event is None:
            return

        vec     = event['latent_end']
        action  = event['dominant_action']
        stage   = event['dominant_reason_stage']
        sal     = event['peak_salience']
        tick    = event['end_tick']
        self.total_ingested += 1

        # --- Find best matching node ---
        best_id  = None
        best_sim = -1.0
        for nid, node in self.nodes.items():
            if node['dominant_action'] != action:
                continue
            sim = self._cos_sim(vec, node['centroid'])
            if sim <= self._sim_thresh:
                continue
            stage_ok = (node['dominant_reason_stage'] == stage or sim > 0.97)
            if not stage_ok:
                continue
            if sim > best_sim:
                best_sim = sim
                best_id  = nid

        if best_id is not None:
            # --- Merge into existing node ---
            node = self.nodes[best_id]
            # EMA centroid update
            node['centroid'] = [
                self._ema(node['centroid'][i], vec[i], self._CENTROID_ALPHA)
                for i in range(64)
            ]
            node['support']      += 1
            node['mean_salience'] = self._ema(node['mean_salience'], sal, 0.9)
            node['last_tick']     = tick
            matched_id = best_id
        else:
            # --- Create new node ---
            if len(self.nodes) >= self._max_nodes:
                self._evict_one(tick)
            new_id = self.node_counter
            self.node_counter += 1
            self.nodes[new_id] = {
                'id':                    new_id,
                'centroid':              list(vec),
                'dominant_action':       action,
                'dominant_reason_stage': stage,
                'support':               1,
                'mean_salience':         sal,
                'last_tick':             tick,
                'debug_label':           None,
            }
            matched_id = new_id

        # --- Edge reinforcement ---
        if (self._last_node_id is not None and
                self._last_node_id != matched_id and
                (tick - self._last_node_tick) <= 10):
            key = (self._last_node_id, matched_id)
            self.edges[key] = min(255, self.edges.get(key, 0) + 1)

        self._last_node_id   = matched_id
        self._last_node_tick = tick

    def _evict_one(self, current_tick):
        """
        Evict the node with the lowest priority score.
        Priority = support * recency_factor
        recency_factor = 1 / (1 + age_ticks / 1000)
        Lowest score = oldest + least-supported node.
        Also removes all edges involving the evicted node.
        """
        if not self.nodes:
            return
        def _score(node):
            age    = max(0, current_tick - node['last_tick'])
            recency = 1.0 / (1.0 + age / 1000.0)
            return node['support'] * recency

        evict_id = min(self.nodes.keys(), key=lambda nid: _score(self.nodes[nid]))
        del self.nodes[evict_id]
        # Clean up edges
        dead = [k for k in self.edges if evict_id in k]
        for k in dead:
            del self.edges[k]

    def reinforce_transition(self, src_id, dst_id):
        """
        Manually reinforce a directed edge (src_id -> dst_id).
        Provides external hook for future reward-weighted credit assignment.
        Weight capped at 255.
        """
        if src_id not in self.nodes or dst_id not in self.nodes:
            return
        key = (src_id, dst_id)
        self.edges[key] = min(255, self.edges.get(key, 0) + 1)

    # ------------------------------------------------------------------
    # Read path (zero side-effects)
    # ------------------------------------------------------------------

    def query_similar(self, latent_vec, k=5):
        """
        Return up to k node dicts most similar to latent_vec.
        Sorted by cosine similarity descending.
        """
        if not self.nodes:
            return []
        scored = []
        for nid, node in self.nodes.items():
            sim = self._cos_sim(latent_vec, node['centroid'])
            scored.append((sim, nid))
        scored.sort(reverse=True)
        return [self.nodes[nid] for _, nid in scored[:k]]

    def top_active(self, n=5):
        """Return the n highest-support nodes (most reinforced concepts)."""
        sorted_nodes = sorted(
            self.nodes.values(),
            key=lambda nd: nd['support'],
            reverse=True
        )
        return sorted_nodes[:n]

    def recent(self, n=10):
        """Return the n most recently activated nodes."""
        sorted_nodes = sorted(
            self.nodes.values(),
            key=lambda nd: nd['last_tick'],
            reverse=True
        )
        return sorted_nodes[:n]

    def __len__(self):
        return len(self.nodes)

    # ------------------------------------------------------------------
    # Serialisation (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'max_nodes':      self._max_nodes,
            'sim_thresh':     self._sim_thresh,
            'node_counter':   self.node_counter,
            'total_ingested': self.total_ingested,
            'last_node_id':   self._last_node_id,
            'last_node_tick': self._last_node_tick,
            # Nodes indexed by string key (JSON requirement)
            'nodes': {str(k): v for k, v in self.nodes.items()},
            # Edges serialised as list of [src, dst, weight] triples
            'edges': [[k[0], k[1], w] for k, w in self.edges.items()],
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(
            max_nodes          = int(d.get('max_nodes', 128)),
            similarity_threshold = float(d.get('sim_thresh', 0.93)),
        )
        obj.node_counter    = int(d.get('node_counter', 0))
        obj.total_ingested  = int(d.get('total_ingested', 0))
        obj._last_node_id   = d.get('last_node_id', None)
        obj._last_node_tick = int(d.get('last_node_tick', -999))
        for k_str, node in d.get('nodes', {}).items():
            obj.nodes[int(k_str)] = node
        for triple in d.get('edges', []):
            obj.edges[(triple[0], triple[1])] = int(triple[2])
        return obj


# ===========================================================================
# REPORT BUS  (Rank 4 cognition substrate -- Prince Siddhpara 2026)
# Shared active cognitive workspace: synthesises a compact semantic scene
# snapshot each tick from LSV, ConceptGraph, and ActionReasoningLog.
# Downstream consumers (narrative, semantic, planning) read via .latest().
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class ReportBus:
    """
    Shared cognitive workspace: publishes a compact scene snapshot each tick.

    Each report is a fixed-schema semantic snapshot derived from:
      - LatentStateVector   : current interoceptive + neural state
      - ConceptGraph        : active concept IDs and their salience
      - ActionReasoningLog  : last action and decision stage

    Report schema
    -------------
    tick                : int   - absolute simulation tick
    latent_focus        : list  - top-8 most informative LSV dims (by abs dev from 0.5)
    top_concepts        : list  - up to 3 concept node IDs by similarity to current LSV
    last_action         : str   - most recent selected action
    last_reason_stage   : str   - most recent reason_stage ('wm'|'explore'|'floor')
    mean_salience       : float - mean of top-concept mean_salience values [0,1]
    workspace_confidence: float - blended confidence score [0,1]

    Consumers (read-only)
    ---------------------
    semantic.report_bus    - grounded sentence generation
    narrative.report_bus   - narrative self-model
    planning_sys.report_bus - hierarchical planning context
    """

    def __init__(self, maxlen=64):
        self._bus    = deque(maxlen=maxlen)
        self._maxlen = maxlen

    # ------------------------------------------------------------------
    # Internal synthesis helpers  (pure functions, no side effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _latent_focus(lsv_vec):
        """
        Extract the 8 most informative dims from a 64D LSV vector.
        Ranked by abs deviation from 0.5 baseline (highest first).
        Returns a list of 8 floats.
        """
        scored = sorted(enumerate(lsv_vec),
                        key=lambda iv: abs(iv[1] - 0.5),
                        reverse=True)
        return [lsv_vec[i] for i, _ in scored[:8]]

    @staticmethod
    def _workspace_confidence(top_nodes, lsv_vec, action_log):
        """
        Blended workspace confidence [0, 1].

        Components:
          C1 : top-concept support -- saturates at 50 merges
          C2 : latent variance magnitude  -- mean abs-dev from 0.5
          C3 : rationale consistency  -- fraction of last-5 records sharing same stage

        Final = 0.4*C1 + 0.35*C2 + 0.25*C3
        """
        # C1: support saturation
        if top_nodes:
            avg_support = sum(n['support'] for n in top_nodes) / len(top_nodes)
            c1 = min(1.0, avg_support / 50.0)
        else:
            c1 = 0.0

        # C2: latent variance magnitude
        c2 = min(1.0, sum(abs(v - 0.5) for v in lsv_vec) / (64 * 0.5))

        # C3: rationale consistency (last 5 records)
        recent_recs = action_log.recent(n=5) if action_log else []
        if len(recent_recs) >= 2:
            stage0 = recent_recs[-1]['reason_stage']
            matches = sum(1 for r in recent_recs if r['reason_stage'] == stage0)
            c3 = matches / len(recent_recs)
        else:
            c3 = 0.5   # neutral when insufficient history

        conf = 0.40 * c1 + 0.35 * c2 + 0.25 * c3
        return max(0.0, min(1.0, conf))

    # ------------------------------------------------------------------
    # Write path  (called once per waking tick from main loop)
    # ------------------------------------------------------------------

    def publish(self, tick, latent_state, concept_graph, action_log,
                sleep_onset=False):
        """
        Synthesise and store one cognitive scene report.

        Parameters
        ----------
        tick          : int   - current simulation tick
        latent_state  : list  - 64D LSV snapshot_vector()
        concept_graph : ConceptGraph instance (read-only)
        action_log    : ActionReasoningLog instance (read-only)
        sleep_onset   : bool  - True -> apply 0.85 confidence penalty
        """
        lsv = latent_state

        # latent_focus: 8 highest-deviation dims
        focus = self._latent_focus(lsv)

        # top_concepts: query concept_graph for 3 closest nodes by cosine sim
        similar_nodes = concept_graph.query_similar(lsv, k=3)
        top_concept_ids = [n['id'] for n in similar_nodes]

        # last action + reason stage
        last_rec = action_log.last() if action_log else None
        last_action = last_rec['selected_action'] if last_rec else 'unknown'
        last_stage  = last_rec['reason_stage']    if last_rec else 'unknown'

        # mean salience of top concepts
        if similar_nodes:
            mean_sal = sum(n['mean_salience'] for n in similar_nodes) / len(similar_nodes)
        else:
            mean_sal = 0.0

        # workspace confidence
        conf = self._workspace_confidence(similar_nodes, lsv, action_log)
        if sleep_onset:
            conf *= 0.85

        report = {
            'tick':                 int(tick),
            'latent_focus':         list(focus),
            'top_concepts':         list(top_concept_ids),
            'last_action':          str(last_action),
            'last_reason_stage':    str(last_stage),
            'mean_salience':        float(max(0.0, min(1.0, mean_sal))),
            'workspace_confidence': float(max(0.0, min(1.0, conf))),
        }
        self._bus.append(report)

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return the most recent report, or None if empty."""
        return self._bus[-1] if self._bus else None

    def recent(self, n=10):
        """Return last n reports (oldest-first)."""
        buf = list(self._bus)
        return buf[-n:] if n < len(buf) else buf

    def current_scene(self):
        """
        Return the latest report as a flat readable dict.
        Alias for latest(); named for downstream readability.
        """
        return self.latest()

    def __len__(self):
        return len(self._bus)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'bus':    list(self._bus),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rep in d.get('bus', []):
            obj._bus.append(rep)
        return obj


# ===========================================================================
# LANGUAGE READOUT  (Rank 5 cognition substrate -- Prince Siddhpara 2026)
# Converts the active ReportBus scene snapshot into a grounded semantic
# proposition.  Output is MEANING SPACE, not polished English.
# Substrate for future SentenceGenerator and self-narration.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class LanguageReadout:
    """
    Semantic proposition generator over ReportBus scene snapshots.

    Each call to read_scene() produces one structured proposition dict
    representing the organism's current cognitive state in meaning space.
    Propositions are stored in a bounded deque(maxlen=64).

    Proposition schema
    ------------------
    tick           : int         -- simulation tick of source scene
    focus_concept  : int | None  -- first concept ID in scene top_concepts
    state_polarity : str         -- 'neutral'|'stress'|'recovery'|'explore'
    action_intent  : str         -- scene last_action
    causal_basis   : str         -- scene last_reason_stage
    confidence     : float       -- scene workspace_confidence [0,1]

    State polarity inference (latent_focus dims)
    --------------------------------------------
    The latent_focus is a list of the 8 highest-deviation dims from LSV.
    Polarity is inferred from the statistical signature of those dims:

      'stress'   : mean > 0.60  (cortisol/threat dims elevated)
      'recovery' : mean < 0.40  AND dim spread < 0.15 (depleted, converging)
      'explore'  : spread > 0.25 AND NOT stress (high variance, exploratory)
      'neutral'  : otherwise

    Polarity is purely statistical over latent_focus values -- no hardcoded
    indices, no hardcoded dim semantics.

    Future consumers (read-only)
    ----------------------------
    semantic.language_readout   - grounded sentence seed
    narrative.language_readout  - self-narration substrate
    planning_sys.language_readout - planning context
    """

    def __init__(self, maxlen=64):
        self._props  = deque(maxlen=maxlen)
        self._maxlen = maxlen

    # ------------------------------------------------------------------
    # State polarity inference  (pure function, no external state)
    # ------------------------------------------------------------------

    @staticmethod
    def _infer_polarity(latent_focus):
        """
        Infer state polarity from the 8-dim latent_focus list.

        Returns one of: 'stress' | 'recovery' | 'explore' | 'neutral'
        """
        if not latent_focus:
            return 'neutral'
        n    = len(latent_focus)
        mean = sum(latent_focus) / n
        spread = max(latent_focus) - min(latent_focus)

        if mean > 0.60:
            return 'stress'
        if mean < 0.40 and spread < 0.15:
            return 'recovery'
        if spread > 0.25:
            return 'explore'
        return 'neutral'

    # ------------------------------------------------------------------
    # Write path  (called once per waking tick from main loop)
    # ------------------------------------------------------------------

    def read_scene(self, scene):
        """
        Derive and store one semantic proposition from a ReportBus snapshot.

        scene : dict from report_bus.current_scene() -- must not be None.

        Returns the proposition dict (also stored in self._props).
        """
        if scene is None:
            return None

        # focus_concept: first concept ID from scene, or None
        top = scene.get('top_concepts', [])
        focus_concept = top[0] if top else None

        # state_polarity: inferred from latent_focus values
        polarity = self._infer_polarity(scene.get('latent_focus', []))

        # action_intent and causal_basis: direct reads from scene
        action_intent = scene.get('last_action',       'unknown')
        causal_basis  = scene.get('last_reason_stage', 'unknown')

        # confidence: clamped scene workspace_confidence
        confidence = float(max(0.0, min(1.0,
                        scene.get('workspace_confidence', 0.0))))

        prop = {
            'tick':          scene.get('tick', -1),
            'focus_concept': focus_concept,
            'state_polarity': polarity,
            'action_intent':  action_intent,
            'causal_basis':   causal_basis,
            'confidence':     confidence,
        }
        self._props.append(prop)
        return prop

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return most recent proposition, or None."""
        return self._props[-1] if self._props else None

    def recent(self, n=10):
        """Return last n propositions (oldest-first)."""
        buf = list(self._props)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._props)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'props':  list(self._props),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for prop in d.get('props', []):
            obj._props.append(prop)
        return obj


# ===========================================================================
# SENTENCE GENERATOR  (Rank 6 language surface -- Prince Siddhpara 2026)
# Converts LanguageReadout semantic propositions into grounded natural English.
# Output is compositional -- clauses selected by polarity + confidence tier.
# NOT template theater: clauses are individually varied and composed.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class SentenceGenerator:
    """
    Compositional natural-language surface over LanguageReadout propositions.

    Converts the 6-field semantic proposition into a grounded English sentence
    by selecting and combining three independent clause banks:

      Clause A (state)   -- from state_polarity
      Clause B (action)  -- from action_intent
      Clause C (causal)  -- from causal_basis

    Three structural templates vary by confidence tier:
      High (>= 0.65) : "{A}, {B} {C}."
      Mid  (>= 0.35) : "{A}. {B} {C}."
      Low  (<  0.35) : "{C_cap}, {B_low} while {A_low}."

    Within each clause bank multiple phrases are defined; selection rotates
    by (tick % n_variants) so consecutive identical polarities still differ.

    Utterance schema
    ----------------
    tick           : int
    sentence       : str   -- grounded English sentence (not template artifact)
    confidence     : float -- from proposition.confidence [0,1]
    focus_concept  : int|None -- from proposition.focus_concept
    """

    # ------------------------------------------------------------------
    # Clause banks  (3+ variants per key, index chosen by tick mod)
    # ------------------------------------------------------------------

    _STATE_CLAUSES = {
        'stress': [
            "I am under rising internal pressure",
            "I am experiencing elevated stress load",
            "my internal state signals mounting pressure",
        ],
        'recovery': [
            "I am stabilizing after a demanding state",
            "I am recovering toward a more balanced state",
            "my internal state is returning to equilibrium",
        ],
        'explore': [
            "I am in an exploratory state",
            "I am actively sampling uncertain territory",
            "I am exploring the available action space",
        ],
        'neutral': [
            "I am in a balanced state",
            "my internal state is currently stable",
            "I am operating within normal boundaries",
        ],
    }

    _ACTION_CLAUSES = {
        'withdraw': [
            "and moving toward safety",
            "and retreating to a safer zone",
            "and pulling back from the current position",
        ],
        'approach': [
            "and moving toward the most promising option",
            "and approaching the highest-value target",
            "and advancing toward my current goal",
        ],
        'explore': [
            "and testing a new path",
            "and probing an unfamiliar direction",
            "and sampling an unexplored region",
        ],
    }
    _ACTION_DEFAULT = [
        "and maintaining current behavior",
        "and holding my current course",
        "and continuing the present action",
    ]

    _CAUSAL_CLAUSES = {
        'wm': [
            "because my predictive model favored it",
            "because my world model predicted the best outcome here",
            "because prediction error was lowest for this choice",
        ],
        'explore': [
            "because uncertainty encouraged exploration",
            "because novelty drive pushed me toward new options",
            "because the value of information outweighed exploitation",
        ],
        'floor': [
            "because a fallback action was required",
            "because no stronger signal overrode the default",
            "because the floor behavior activated in the absence of a clear cue",
        ],
    }
    _CAUSAL_DEFAULT = [
        "because current evidence supported it",
        "because the available signals pointed this way",
        "because the organism's state made this the best option",
    ]

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    @classmethod
    def _pick(cls, bank, key, tick):
        """Pick phrase variant by tick modulo, with fallback."""
        variants = bank.get(key, None)
        if not variants:
            variants = bank.get('_default', [""])
        return variants[tick % len(variants)]

    @classmethod
    def _pick_list(cls, variants, tick):
        return variants[tick % len(variants)]

    @classmethod
    def _compose(cls, prop):
        """
        Compose a sentence from proposition fields.
        Returns (sentence_str, confidence_float).
        """
        tick    = prop.get('tick', 0)
        polarity= prop.get('state_polarity', 'neutral')
        action  = prop.get('action_intent',  'unknown')
        basis   = prop.get('causal_basis',   'unknown')
        conf    = float(max(0.0, min(1.0, prop.get('confidence', 0.0))))

        # Select clauses
        a_vars = cls._STATE_CLAUSES.get(polarity, cls._STATE_CLAUSES['neutral'])
        clause_a = a_vars[tick % len(a_vars)]

        b_vars = cls._ACTION_CLAUSES.get(action, cls._ACTION_DEFAULT)
        clause_b = b_vars[tick % len(b_vars)]

        c_vars = cls._CAUSAL_CLAUSES.get(basis, cls._CAUSAL_DEFAULT)
        clause_c = c_vars[tick % len(c_vars)]

        # Template selection by confidence tier
        if conf >= 0.65:
            # High confidence: flowing single sentence
            sentence = f"{clause_a}, {clause_b} {clause_c}."
        elif conf >= 0.35:
            # Mid confidence: two-clause with pause
            sentence = f"{clause_a}. {clause_b} {clause_c}."
        else:
            # Low confidence: causal-first, hedged form
            c_cap = clause_c[0].upper() + clause_c[1:]
            b_low = clause_b.lower()
            a_low = clause_a.lower()
            sentence = f"{c_cap}, {b_low} while {a_low}."

        return sentence, conf

    # ------------------------------------------------------------------
    # Public interface
    # ------------------------------------------------------------------

    def __init__(self, maxlen=64):
        self._utterances = deque(maxlen=maxlen)
        self._maxlen     = maxlen

    def generate(self, prop):
        """
        Generate a grounded English sentence from a LanguageReadout proposition.
        Stores the utterance record and returns it.

        prop : dict from language_readout.latest() -- must not be None.
        """
        if prop is None:
            return None

        sentence, conf = self._compose(prop)
        utterance = {
            'tick':          prop.get('tick', -1),
            'sentence':      sentence,
            'confidence':    conf,
            'focus_concept': prop.get('focus_concept', None),
        }
        self._utterances.append(utterance)
        return utterance

    def latest(self):
        """Return most recent utterance, or None."""
        return self._utterances[-1] if self._utterances else None

    def recent(self, n=10):
        """Return last n utterances (oldest-first)."""
        buf = list(self._utterances)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._utterances)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':     self._maxlen,
            'utterances': list(self._utterances),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for utt in d.get('utterances', []):
            obj._utterances.append(utt)
        return obj


# ===========================================================================
# SLEEP CONSOLIDATOR  (Rank 7 cognition substrate -- Prince Siddhpara 2026)
# Offline semantic consolidation during sleep.
# Reads ReplayBuffer, EventCompressor, ConceptGraph, SentenceGenerator.
# Strengthens concept motifs, reinforces edges, calibrates confidence.
# ONLY acts during sleep branch. ZERO writes during waking ticks.
# Pure observer -- all writes are to ConceptGraph internals (read-hooks only)
# and its own deque.  Never touches action path, WM, BG, or neuromodulators.
# ===========================================================================

class SleepConsolidator:
    """
    Offline semantic memory consolidation during sleep.

    Consolidation steps (per sleep tick, call from 'if sleeping:' branch):

    1. Concept reinforcement
       Sample replay buffer (salience-biased, k=16).
       For each transition, query nearest ConceptGraph node.
       Apply soft EMA tightening to centroid (alpha=0.98, very gentle).
       Increment support by 1, capped at +4 per sleep cycle per node.
       Records which concept IDs were reinforced.

    2. Edge reinforcement
       Read recent compressed events (last 5 from EventCompressor).
       For consecutive event pairs, reinforce their concept-edge.
       Weight capped at 255 (same as ConceptGraph law).

    3. Confidence calibration
       Read last 10 SentenceGenerator utterances.
       Compute variance of confidence values.
       High variance (> 0.04) -> reduce support of lowest-support nodes by 1.
       Low variance (< 0.01)  -> increase support of top-3 nodes by 1.
       Returns confidence_shift (net change, float).

    4. Dominant sentence focus
       Most frequent focus_concept from recent utterances.

    Consolidation record schema
    ---------------------------
    tick                    : int
    reinforced_concepts     : list[int]  -- concept IDs whose support changed
    reinforced_edges        : list[tuple] -- (src_id, dst_id) pairs reinforced
    confidence_shift        : float      -- net support calibration effect
    dominant_sentence_focus : int|None   -- most frequent focus_concept

    Sleep gate
    ----------
    Call ONLY from 'if sleeping:' branch.  Waking path does not call consolidate().
    """

    # Maximum support increment per sleep cycle per concept node
    _MAX_SUPPORT_BUMP_PER_CYCLE = 4

    def __init__(self, maxlen=256):
        self._records  = deque(maxlen=maxlen)
        self._maxlen   = maxlen
        # Track per-cycle support bumps to enforce cap
        self._cycle_bumps = {}   # node_id -> int  (cleared each consolidate call)

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    @staticmethod
    def _cos_sim(a, b):
        dot = sum(x * y for x, y in zip(a, b))
        ma  = math.sqrt(sum(x * x for x in a)) + 1e-9
        mb  = math.sqrt(sum(x * x for x in b)) + 1e-9
        return dot / (ma * mb)

    def _find_nearest_node(self, vec, concept_graph):
        """Return (node_id, sim) for the closest concept node, or (None, -1)."""
        best_id, best_sim = None, -1.0
        for nid, node in concept_graph.nodes.items():
            sim = self._cos_sim(vec, node['centroid'])
            if sim > best_sim:
                best_sim, best_id = sim, nid
        return best_id, best_sim

    # ------------------------------------------------------------------
    # Consolidation steps
    # ------------------------------------------------------------------

    def _step1_concept_reinforcement(self, tick, replay_buffer, concept_graph):
        """Sample replay buffer; tighten centroids; bump support."""
        reinforced = []
        self._cycle_bumps = {}

        transitions = replay_buffer.sample_for_replay(k=16)
        for tr in transitions:
            vec = tr.get('latent_post', [])
            if not vec:
                continue
            nid, sim = self._find_nearest_node(vec, concept_graph)
            if nid is None or sim < 0.80:
                continue       # too dissimilar -- don't reinforce

            node = concept_graph.nodes[nid]
            # Soft EMA tightening (alpha=0.98 -- very gentle pull toward replay sample)
            node['centroid'] = [
                0.98 * node['centroid'][i] + 0.02 * vec[i]
                for i in range(min(64, len(vec)))
            ]
            # Support increment capped per cycle
            bumps_so_far = self._cycle_bumps.get(nid, 0)
            if bumps_so_far < self._MAX_SUPPORT_BUMP_PER_CYCLE:
                node['support'] += 1
                self._cycle_bumps[nid] = bumps_so_far + 1
                if nid not in reinforced:
                    reinforced.append(nid)
            node['last_tick'] = tick

        return reinforced

    def _step2_edge_reinforcement(self, event_compressor, concept_graph):
        """Reinforce concept edges for repeated sequential event chains."""
        reinforced_edges = []
        events = event_compressor.recent(5)
        if len(events) < 2:
            return reinforced_edges

        # Map each event to its nearest concept node
        node_ids = []
        for ev in events:
            vec = ev.get('latent_end', [])
            if not vec:
                node_ids.append(None)
                continue
            nid, sim = self._find_nearest_node(vec, concept_graph)
            node_ids.append(nid if sim >= 0.80 else None)

        # Reinforce edges for consecutive (non-None, distinct) pairs
        for idx in range(len(node_ids) - 1):
            src = node_ids[idx]
            dst = node_ids[idx + 1]
            if src is None or dst is None or src == dst:
                continue
            key = (src, dst)
            concept_graph.edges[key] = min(255, concept_graph.edges.get(key, 0) + 1)
            if key not in reinforced_edges:
                reinforced_edges.append(key)

        return reinforced_edges

    def _step3_confidence_calibration(self, concept_graph, sentence_generator):
        """
        Calibrate concept supports based on recent sentence confidence variance.
        Returns confidence_shift (float).
        """
        utts = sentence_generator.recent(n=10)
        if len(utts) < 2:
            return 0.0

        confs = [u['confidence'] for u in utts]
        mean_conf  = sum(confs) / len(confs)
        variance   = sum((c - mean_conf) ** 2 for c in confs) / len(confs)

        shift = 0.0
        if variance > 0.04:
            # High instability: soften the weakest concept
            if concept_graph.nodes:
                weakest_id = min(concept_graph.nodes.keys(),
                                 key=lambda k: concept_graph.nodes[k]['support'])
                if concept_graph.nodes[weakest_id]['support'] > 1:
                    concept_graph.nodes[weakest_id]['support'] -= 1
                    shift = -1.0
        elif variance < 0.01:
            # High stability: strengthen top-3 concepts by 1
            sorted_ids = sorted(concept_graph.nodes.keys(),
                                key=lambda k: concept_graph.nodes[k]['support'],
                                reverse=True)
            for nid in sorted_ids[:3]:
                concept_graph.nodes[nid]['support'] += 1
            shift = float(min(3, len(sorted_ids)))

        return shift

    def _step4_dominant_focus(self, sentence_generator):
        """Return most frequent focus_concept from recent utterances."""
        utts = sentence_generator.recent(n=10)
        freq = {}
        for u in utts:
            fc = u.get('focus_concept')
            if fc is not None:
                freq[fc] = freq.get(fc, 0) + 1
        if not freq:
            return None
        return max(freq, key=lambda k: freq[k])

    # ------------------------------------------------------------------
    # Main consolidation call  (sleep-branch only)
    # ------------------------------------------------------------------

    def consolidate(self, tick, replay_buffer, event_compressor,
                    concept_graph, sentence_generator):
        """
        Perform one sleep-tick consolidation pass.

        MUST be called only from 'if sleeping:' branch.
        Pure observer during waking ticks.
        """
        reinforced_concepts = self._step1_concept_reinforcement(
            tick, replay_buffer, concept_graph)

        reinforced_edges    = self._step2_edge_reinforcement(
            event_compressor, concept_graph)

        confidence_shift    = self._step3_confidence_calibration(
            concept_graph, sentence_generator)

        dominant_focus      = self._step4_dominant_focus(sentence_generator)

        record = {
            'tick':                     int(tick),
            'reinforced_concepts':      list(reinforced_concepts),
            'reinforced_edges':         [list(e) for e in reinforced_edges],
            'confidence_shift':         float(confidence_shift),
            'dominant_sentence_focus':  dominant_focus,
        }
        self._records.append(record)
        return record

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def last(self):
        """Return the most recent consolidation record, or None."""
        return self._records[-1] if self._records else None

    def recent(self, n=10):
        """Return last n consolidation records (oldest-first)."""
        buf = list(self._records)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._records)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'records': list(self._records),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('records', []):
            obj._records.append(rec)
        return obj


# ===========================================================================
# NARRATIVE MEMORY  (Rank 8 cognition substrate -- Prince Siddhpara 2026)
# Segments the waking sentence stream + sleep consolidation motifs into
# autobiographical arc chunks.  Each arc = one coherent episode of experience.
# Pure observer -- ZERO writes to any behavior path.
# ===========================================================================

class NarrativeMemory:
    """
    Session-level autobiographical memory over the language substrate.

    Accumulates waking sentences from SentenceGenerator into a 'current_arc'
    buffer.  When the arc ends (focus shift, confidence jump, sleep boundary),
    it is flushed as a single compact autobiographical record and stored in a
    bounded deque(maxlen=128).

    Arc continuity criteria  (all must hold to extend arc)
    -------------------------------------------------------
    1. focus_concept unchanged  (same or both None)
    2. confidence delta from previous sentence < 0.20
    3. top ConceptGraph node unchanged  (query_similar with k=1)
    4. no sleep boundary signal

    Arc schema
    ----------
    start_tick        : int
    end_tick          : int
    dominant_focus    : int | None   -- mode focus_concept across arc sentences
    dominant_theme    : str          -- 'challenge'|'stabilization'|'discovery'|'transition'
    arc_summary       : str          -- 2-3 sentence autobiographical paragraph
    mean_confidence   : float        -- mean sentence confidence across the arc

    Arc summary composition  (not a fixed template)
    ------------------------------------------------
    Built from:
      - opening clause from first sentence
      - pattern theme clause (counts of polarity seen)
      - closing clause from final sentence
      - optional sleep motif suffix if sleep_consolidator provides a focus
    Composed as a 2-3 sentence paragraph.  No raw transcript dump.

    Sleep gate
    ----------
    flush_arc(reason="sleep_boundary") commits the arc at every sleep onset.
    ingest_tick() must NOT be called during sleeping==True ticks;
    the main loop ensures this by placing it inside the 'if not sleeping:' branch.
    """

    # Minimum arc length before we bother summarising (avoids 1-sentence micro-arcs)
    _MIN_ARC_LEN = 2

    def __init__(self, maxlen=128):
        self._arcs    = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        self.current_arc = []           # list of utterance dicts in progress

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    @staticmethod
    def _top_concept(concept_graph):
        """Return the concept node ID with highest support, or None."""
        if not concept_graph.nodes:
            return None
        return max(concept_graph.nodes.keys(),
                   key=lambda k: concept_graph.nodes[k]['support'])

    @staticmethod
    def _dominant_focus(arc_sentences):
        """Mode focus_concept across an arc; None if all are None."""
        freq = {}
        for s in arc_sentences:
            fc = s.get('focus_concept')
            if fc is not None:
                freq[fc] = freq.get(fc, 0) + 1
        if not freq:
            return None
        return max(freq, key=lambda k: freq[k])

    @staticmethod
    def _dominant_theme(arc_sentences):
        """
        Infer theme from sentence polarities embedded in sentence text.
        Maps to: 'challenge' | 'stabilization' | 'discovery' | 'transition'
        """
        counts = {'stress': 0, 'recovery': 0, 'explore': 0, 'neutral': 0}
        for s in arc_sentences:
            text = s.get('sentence', '').lower()
            if 'pressure' in text or 'stress' in text:
                counts['stress'] += 1
            elif 'stabiliz' in text or 'equilibrium' in text or 'recovering' in text:
                counts['recovery'] += 1
            elif 'explor' in text or 'sampling' in text or 'probing' in text:
                counts['explore'] += 1
            else:
                counts['neutral'] += 1

        # Majority rule
        total = len(arc_sentences)
        threshold = total * 0.50
        if counts['stress']   >= threshold: return 'challenge'
        if counts['recovery'] >= threshold: return 'stabilization'
        if counts['explore']  >= threshold: return 'discovery'
        return 'transition'

    @staticmethod
    def _mean_confidence(arc_sentences):
        if not arc_sentences:
            return 0.0
        return sum(s.get('confidence', 0.0) for s in arc_sentences) / len(arc_sentences)

    @classmethod
    def _compose_summary(cls, arc_sentences, theme, sleep_focus=None):
        """
        Compose a 2-3 sentence autobiographical paragraph from arc content.
        Not a fixed template -- built compositionally from first/last/theme.
        """
        if not arc_sentences:
            return ""

        first_sent = arc_sentences[0].get('sentence', '').rstrip('.')
        last_sent  = arc_sentences[-1].get('sentence', '').rstrip('.')
        n          = len(arc_sentences)

        # Theme clause
        theme_clauses = {
            'challenge':      f"This episode was marked by internal challenge across {n} moments.",
            'stabilization':  f"This episode reflected a period of stabilization over {n} ticks.",
            'discovery':      f"This episode traced an exploratory arc through {n} successive states.",
            'transition':     f"This episode moved through mixed states across {n} ticks.",
        }
        theme_clause = theme_clauses.get(theme, theme_clauses['transition'])

        # Build 2 or 3 sentence paragraph
        if sleep_focus is not None:
            summary = (f"{first_sent}, leading into a period of {theme.lower()}. "
                       f"{theme_clause} "
                       f"Sleep consolidation anchored on concept {sleep_focus}: "
                       f"{last_sent}.")
        else:
            summary = (f"{first_sent}, which opened a period of {theme.lower()}. "
                       f"{theme_clause} "
                       f"It concluded with: {last_sent}.")

        return summary

    # ------------------------------------------------------------------
    # Arc continuation check
    # ------------------------------------------------------------------

    def _should_continue_arc(self, utterance, concept_graph):
        """
        Return True if utterance belongs to the same arc as current_arc.
        Returns False (triggering a flush) on any continuity break.
        """
        if not self.current_arc:
            return True

        prev = self.current_arc[-1]

        # 1. Focus concept unchanged
        if utterance.get('focus_concept') != prev.get('focus_concept'):
            return False

        # 2. Confidence delta < 0.20
        conf_delta = abs(utterance.get('confidence', 0.0) -
                         prev.get('confidence', 0.0))
        if conf_delta >= 0.20:
            return False

        # 3. Top ConceptGraph node unchanged (if graph is non-empty)
        if concept_graph.nodes:
            top_now = self._top_concept(concept_graph)
            # Store top concept in the arc metadata on first tick
            if '_top_concept' not in self.current_arc[0]:
                self.current_arc[0]['_top_concept'] = top_now
            if top_now != self.current_arc[0].get('_top_concept'):
                return False

        return True

    # ------------------------------------------------------------------
    # Main ingest call  (waking ticks only)
    # ------------------------------------------------------------------

    def ingest_tick(self, tick, sentence, concept_graph, sleeping=False):
        """
        Ingest one SentenceGenerator utterance into the current arc.
        Must be called ONLY when sleeping==False.

        sentence : dict from sentence_generator.latest()
        """
        if sleeping or sentence is None:
            return

        if not self._should_continue_arc(sentence, concept_graph):
            self.flush_arc(reason='focus_shift')

        self.current_arc.append(sentence)

    # ------------------------------------------------------------------
    # Arc flush  (sleep boundary or focus shift)
    # ------------------------------------------------------------------

    def flush_arc(self, reason='sleep_boundary', sleep_focus=None):
        """
        Commit current_arc as a finished autobiographical record.
        Resets current_arc to [].

        reason      : str        -- 'sleep_boundary' | 'focus_shift'
        sleep_focus : int|None   -- dominant_sentence_focus from SleepConsolidator
        """
        if len(self.current_arc) < self._MIN_ARC_LEN:
            self.current_arc = []
            return None

        arc  = self.current_arc
        t0   = arc[0].get('tick', -1)
        t1   = arc[-1].get('tick', -1)
        dom  = self._dominant_focus(arc)
        them = self._dominant_theme(arc)
        mconf= self._mean_confidence(arc)
        summ = self._compose_summary(arc, them, sleep_focus=sleep_focus)

        record = {
            'start_tick':       int(t0),
            'end_tick':         int(t1),
            'dominant_focus':   dom,
            'dominant_theme':   them,
            'arc_summary':      summ,
            'mean_confidence':  float(round(mconf, 4)),
        }
        self._arcs.append(record)
        self.current_arc = []
        return record

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return the most recently committed arc, or None."""
        return self._arcs[-1] if self._arcs else None

    def recent(self, n=10):
        """Return last n committed arcs (oldest-first)."""
        buf = list(self._arcs)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._arcs)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':      self._maxlen,
            'arcs':        list(self._arcs),
            'current_arc': list(self.current_arc),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for arc in d.get('arcs', []):
            obj._arcs.append(arc)
        obj.current_arc = list(d.get('current_arc', []))
        return obj


# ===========================================================================
# REFLECTIVE REASONER  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Post-sleep metacognitive self-assessment over autobiographical arcs.
# Reads:  NarrativeMemory.recent(5)   -- read-only arc history
#         SleepConsolidator.last()    -- read-only dominant consolidation focus
#         ConceptGraph.nodes          -- read-only for concept support context
#
# Runs:   ONLY inside 'if sleeping:' branch, after sleep_consolidator.consolidate()
# Writes: ONLY to its own internal deque
#
# Zero behavior drift -- never touches selected_action, BG, WM, drives,
# neuromodulators, or sleep physiology.
# Memory-safe -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class ReflectiveReasoner:
    """
    Post-sleep metacognitive self-assessment over autobiographical arcs.

    Reads the last 5 committed NarrativeMemory arcs and produces a structured
    reflection record covering:

      - reflection_type    : motif detected across arcs
      - confidence_trend   : direction of mean confidence across arcs
      - loop_risk          : recurrence rate of dominant arc focus [0, 1]
      - reflection_summary : 2-sentence metacognitive note

    Reflection types
    ----------------
    'stress_loop'           -- repeated 'challenge' arcs (≥ 3 of 5)
    'successful_regulation' -- repeated 'stabilization' arcs (≥ 3 of 5)
    'productive_exploration'-- repeated 'discovery' arcs (≥ 3 of 5)
    'transition_instability'-- alternating or mixed themes without majority

    Confidence trends
    -----------------
    Compare mean confidence of first-half vs second-half of arc window:
      rising (diff > +0.05)  -> 'improving'
      falling (diff < -0.05) -> 'destabilizing'
      else                   -> 'flat'

    Loop risk
    ---------
    count_of_most_frequent_dominant_focus / len(arcs_sampled)
    Clamped [0.0, 1.0].

    Sleep gate
    ----------
    reflect() MUST be called only from the 'if sleeping:' branch, after
    sleep_consolidator.consolidate() has run.  Zero waking writes.

    Reflection record schema
    ------------------------
    tick                : int
    dominant_arc_focus  : int | None  -- mode focus across sampled arcs
    reflection_type     : str
    confidence_trend    : str
    loop_risk           : float
    reflection_summary  : str         -- always exactly 2 sentences
    """

    # Minimum arcs needed to produce a meaningful reflection
    _MIN_ARCS = 2

    # Threshold for majority theme detection (≥ this fraction of arcs)
    _MAJORITY_THRESH = 0.60   # 3 of 5 -> 0.60

    # Confidence trend sensitivity (absolute difference between halves)
    _TREND_EPSILON = 0.05

    def __init__(self, maxlen=128):
        self._records = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    # ------------------------------------------------------------------
    # Internal analysis helpers  (all read-only, no side-effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _dominant_focus(arcs):
        """Mode dominant_focus across arcs; None if all None."""
        freq = {}
        for arc in arcs:
            df = arc.get('dominant_focus')
            if df is not None:
                freq[df] = freq.get(df, 0) + 1
        if not freq:
            return None
        return max(freq, key=lambda k: freq[k])

    @staticmethod
    def _compute_reflection_type(arcs):
        """
        Determine reflection_type from arc themes.

        Majority rule (>= 60% of arcs share a theme):
          'challenge'      -> 'stress_loop'
          'stabilization'  -> 'successful_regulation'
          'discovery'      -> 'productive_exploration'
        Otherwise:
          'transition_instability'
        """
        counts = {'challenge': 0, 'stabilization': 0,
                  'discovery': 0, 'transition': 0}
        for arc in arcs:
            theme = arc.get('dominant_theme', 'transition')
            counts[theme] = counts.get(theme, 0) + 1

        n = len(arcs)
        if n == 0:
            return 'transition_instability'

        majorities = {
            'challenge':     'stress_loop',
            'stabilization': 'successful_regulation',
            'discovery':     'productive_exploration',
        }
        # sorted to make deterministic when counts are equal
        for theme in ('challenge', 'stabilization', 'discovery'):
            if counts[theme] / n >= ReflectiveReasoner._MAJORITY_THRESH:
                return majorities[theme]
        return 'transition_instability'

    @staticmethod
    def _compute_confidence_trend(arcs):
        """
        Compare mean confidence of first vs second half of arc window.
        Returns 'improving' | 'destabilizing' | 'flat'.
        """
        if len(arcs) < 2:
            return 'flat'

        mid   = len(arcs) // 2
        first = arcs[:mid]
        second = arcs[mid:]

        def _mean(subset):
            confs = [a.get('mean_confidence', 0.0) for a in subset]
            return sum(confs) / len(confs) if confs else 0.0

        first_mean  = _mean(first)
        second_mean = _mean(second)
        diff = second_mean - first_mean

        if diff > ReflectiveReasoner._TREND_EPSILON:
            return 'improving'
        if diff < -ReflectiveReasoner._TREND_EPSILON:
            return 'destabilizing'
        return 'flat'

    @staticmethod
    def _compute_loop_risk(arcs, dominant_focus):
        """
        Fraction of arcs whose dominant_focus matches the modal focus.
        Returns float clamped [0.0, 1.0].
        """
        if not arcs or dominant_focus is None:
            return 0.0
        matches = sum(1 for a in arcs if a.get('dominant_focus') == dominant_focus)
        return max(0.0, min(1.0, matches / len(arcs)))

    @staticmethod
    def _compose_reflection_summary(reflection_type, confidence_trend, loop_risk):
        """
        Compose a 2-sentence metacognitive reflection note.

        Sentence 1: describes the detected pattern.
        Sentence 2: states the implication for future stability.
        """
        # --- Sentence 1: pattern description ---
        pattern_clauses = {
            'stress_loop': (
                "Recent autobiographical arcs reveal a recurring challenge motif, "
                "suggesting the organism has been under sustained internal pressure."
            ),
            'successful_regulation': (
                "Recent autobiographical arcs show a dominant stabilization theme, "
                "indicating the organism successfully regulated its internal state."
            ),
            'productive_exploration': (
                "Recent autobiographical arcs trace a sustained exploratory arc, "
                "reflecting an episode of active environmental sampling."
            ),
            'transition_instability': (
                "Recent autobiographical arcs exhibit mixed thematic content without "
                "a stable dominant motif, indicating a period of thematic transition."
            ),
        }
        s1 = pattern_clauses.get(reflection_type, pattern_clauses['transition_instability'])

        # --- Sentence 2: implication based on trend + loop_risk ---
        if confidence_trend == 'improving':
            trend_note = "rising confidence across arc history"
        elif confidence_trend == 'destabilizing':
            trend_note = "declining confidence across arc history"
        else:
            trend_note = "stable confidence across arc history"

        if loop_risk >= 0.80:
            risk_note = (f"High focus recurrence (risk={loop_risk:.2f}) suggests "
                         f"a potential behavioral loop requiring future variation.")
        elif loop_risk >= 0.50:
            risk_note = (f"Moderate focus recurrence (risk={loop_risk:.2f}) warrants "
                         f"monitoring for emerging repetitive motifs.")
        else:
            risk_note = (f"Low focus recurrence (risk={loop_risk:.2f}) indicates "
                         f"healthy thematic diversity across arcs.")

        s2 = f"With {trend_note}, {risk_note}"

        return f"{s1} {s2}"

    # ------------------------------------------------------------------
    # Main reflection call  (sleep-branch only)
    # ------------------------------------------------------------------

    def reflect(self, tick, narrative_memory, sleep_consolidator, concept_graph):
        """
        Perform one post-sleep metacognitive reflection pass.

        MUST be called only from 'if sleeping:' branch, after
        sleep_consolidator.consolidate() has run.
        Pure observer during waking ticks.

        Parameters
        ----------
        tick               : int          -- current simulation tick
        narrative_memory   : NarrativeMemory  -- read-only arc source
        sleep_consolidator : SleepConsolidator -- read-only for last() record
        concept_graph      : ConceptGraph -- read-only for node context
        """
        arcs = narrative_memory.recent(5)
        if len(arcs) < self._MIN_ARCS:
            return None   # not enough arc history yet

        dom_focus    = self._dominant_focus(arcs)
        ref_type     = self._compute_reflection_type(arcs)
        conf_trend   = self._compute_confidence_trend(arcs)
        loop_risk    = self._compute_loop_risk(arcs, dom_focus)
        summary      = self._compose_reflection_summary(ref_type, conf_trend, loop_risk)

        record = {
            'tick':               int(tick),
            'dominant_arc_focus': dom_focus,
            'reflection_type':    ref_type,
            'confidence_trend':   conf_trend,
            'loop_risk':          float(round(loop_risk, 4)),
            'reflection_summary': summary,
        }
        self._records.append(record)
        return record

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return the most recent reflection record, or None."""
        return self._records[-1] if self._records else None

    def recent(self, n=10):
        """Return last n reflection records (oldest-first)."""
        buf = list(self._records)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._records)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'records': list(self._records),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('records', []):
            obj._records.append(rec)
        return obj


# ===========================================================================
# COGNITIVE PLANNER  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts autobiographical reflections into future-directed cognitive goals.
# Reads:  ReflectiveReasoner.latest()   -- read-only reflection record
#         NarrativeMemory.recent(5)     -- read-only arc context
#         ConceptGraph.nodes            -- read-only concept support ranking
#
# Runs:   ONLY inside 'if sleeping:' branch, after reflective_reasoner.reflect()
# Writes: ONLY to its own internal deque
#
# Zero survival drift -- never touches selected_action, BG, WM, drives,
# homeostasis, or neuromodulators.
# Memory-safe  -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class CognitivePlanner:
    """
    Future-directed cognitive goal generation from reflective arc assessment.

    Reads ReflectiveReasoner.latest() to derive the dominant cognitive pattern,
    then maps it to an explicit goal type with urgency scoring and a 2-sentence
    planning summary.

    Goal types
    ----------
    'stabilize'            -- stress loop detected with high recurrence risk
    'reinforce_success'    -- successful regulation with improving confidence
    'expand_exploration'   -- productive exploration with healthy diversity
    'reduce_variance'      -- thematic instability with no majority pattern
    'maintain_continuity'  -- default when reflection is unavailable or neutral

    Urgency blend (clamped [0, 1])
    ------------------------------
    base  = loop_risk * 0.50
    +0.25 if confidence_trend == 'destabilizing'
    -0.10 if confidence_trend == 'improving'
    clamp to [0.0, 1.0]

    Plan schema
    -----------
    tick             : int
    goal_type        : str
    target_focus     : int | None   -- dominant_arc_focus from reflection
    urgency          : float [0, 1]
    planning_summary : str          -- always exactly 2 sentences

    Sleep gate
    ----------
    plan() MUST be called only from 'if sleeping:' branch, after
    reflective_reasoner.reflect() has run.  Zero waking writes.
    """

    # Goal type precedence map: reflection_type -> goal_type
    _GOAL_MAP = {
        'stress_loop':           'stabilize',
        'successful_regulation': 'reinforce_success',
        'productive_exploration':'expand_exploration',
        'transition_instability':'reduce_variance',
    }

    # Urgency coefficients
    _LOOP_RISK_WEIGHT      = 0.50
    _DESTABILIZING_BONUS   = 0.25
    _IMPROVING_DISCOUNT    = 0.10

    def __init__(self, maxlen=128):
        self._plans  = deque(maxlen=maxlen)
        self._maxlen = maxlen

    # ------------------------------------------------------------------
    # Internal helpers  (all read-only, no side-effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _resolve_goal_type(reflection):
        """Map reflection_type + urgency signals to concrete goal_type."""
        if reflection is None:
            return 'maintain_continuity'
        ref_type   = reflection.get('reflection_type',  'transition_instability')
        conf_trend = reflection.get('confidence_trend', 'flat')
        loop_risk  = reflection.get('loop_risk',        0.0)

        base_goal = CognitivePlanner._GOAL_MAP.get(ref_type, 'maintain_continuity')

        # Override: stress_loop but confidence is improving and low risk
        # -> organism managing well; soften to maintain_continuity
        if (ref_type == 'stress_loop'
                and conf_trend == 'improving'
                and loop_risk < 0.50):
            return 'maintain_continuity'

        # Override: successful_regulation but falling confidence
        # -> regression starting; escalate to stabilize
        if (ref_type == 'successful_regulation'
                and conf_trend == 'destabilizing'
                and loop_risk >= 0.60):
            return 'stabilize'

        return base_goal

    @staticmethod
    def _compute_urgency(reflection):
        """
        Blend loop_risk, confidence_trend, and goal_type into urgency [0, 1].
        """
        if reflection is None:
            return 0.0
        loop_risk  = reflection.get('loop_risk',        0.0)
        conf_trend = reflection.get('confidence_trend', 'flat')

        urgency = loop_risk * CognitivePlanner._LOOP_RISK_WEIGHT
        if conf_trend == 'destabilizing':
            urgency += CognitivePlanner._DESTABILIZING_BONUS
        elif conf_trend == 'improving':
            urgency -= CognitivePlanner._IMPROVING_DISCOUNT

        return max(0.0, min(1.0, urgency))

    @staticmethod
    def _compose_planning_summary(goal_type, reflection, concept_graph):
        """
        Compose a 2-sentence future-directed plan note.

        Sentence 1: what future cognitive trajectory should be favored.
        Sentence 2: why, grounded in reflection evidence.
        """
        loop_risk  = 0.0 if reflection is None else reflection.get('loop_risk', 0.0)
        conf_trend = 'flat' if reflection is None else reflection.get('confidence_trend', 'flat')
        ref_type   = 'transition_instability' if reflection is None else reflection.get('reflection_type', 'transition_instability')

        # --- Sentence 1: trajectory prescription ---
        trajectory_clauses = {
            'stabilize': (
                "Future cognition should prioritize internal stabilization, "
                "reducing activation of high-stress concept motifs."
            ),
            'reinforce_success': (
                "Future cognition should reinforce the currently successful "
                "regulation motif to consolidate the improving confidence trajectory."
            ),
            'expand_exploration': (
                "Future cognition should expand exploratory scope, "
                "diversifying concept engagement beyond the current dominant focus."
            ),
            'reduce_variance': (
                "Future cognition should seek thematic coherence, "
                "establishing a stable dominant arc focus to reduce transition noise."
            ),
            'maintain_continuity': (
                "Future cognition should maintain its current operational trajectory, "
                "sustaining the present balance of arousal and regulation."
            ),
        }
        s1 = trajectory_clauses.get(goal_type, trajectory_clauses['maintain_continuity'])

        # --- Sentence 2: evidence grounding ---
        if conf_trend == 'improving':
            trend_note = "confidence is on a rising trajectory"
        elif conf_trend == 'destabilizing':
            trend_note = "confidence has been declining across recent arcs"
        else:
            trend_note = "confidence has held stable across recent arcs"

        if loop_risk >= 0.80:
            risk_note = f"with focus recurrence at {loop_risk:.2f}, signaling a high-risk behavioral loop"
        elif loop_risk >= 0.50:
            risk_note = f"with moderate focus recurrence at {loop_risk:.2f}"
        else:
            risk_note = f"and healthy thematic diversity (recurrence={loop_risk:.2f})"

        ref_label = {
            'stress_loop':           "repeated challenge arcs",
            'successful_regulation': "sustained stabilization arcs",
            'productive_exploration':"consistent exploration arcs",
            'transition_instability':"mixed thematic arcs without majority motif",
        }.get(ref_type, "recent autobiographical evidence")

        s2 = (f"Reflective evidence of {ref_label} shows {trend_note}, "
              f"{risk_note}.")

        return f"{s1} {s2}"

    # ------------------------------------------------------------------
    # Main planning call  (sleep-branch only)
    # ------------------------------------------------------------------

    def update(self, state):
        """Unified interface (Day 32)."""
        return self._plan(
            tick                = state.tick,
            reflective_reasoner = state.reflective_reasoner,
            narrative_memory    = state.narrative_memory,
            concept_graph       = state.concept_graph,
        )

    def _plan(self, tick, reflective_reasoner, narrative_memory, concept_graph):
        """
        Derive one future-directed cognitive goal from the latest reflection.

        MUST be called only from 'if sleeping:' branch, after
        reflective_reasoner.reflect() has run.
        Pure observer during waking ticks.

        Parameters
        ----------
        tick                : int
        reflective_reasoner : ReflectiveReasoner  -- read-only via .latest()
        narrative_memory    : NarrativeMemory     -- read-only via .recent()
        concept_graph       : ConceptGraph        -- read-only via .nodes
        """
        reflection = reflective_reasoner.latest()

        # Need at least 1 reflection to plan (guards against cold-start)
        if reflection is None:
            return None

        goal_type    = self._resolve_goal_type(reflection)
        target_focus = reflection.get('dominant_arc_focus')
        urgency      = self._compute_urgency(reflection)
        summary      = self._compose_planning_summary(goal_type, reflection, concept_graph)

        record = {
            'tick':             int(tick),
            'goal_type':        goal_type,
            'target_focus':     target_focus,
            'urgency':          float(round(urgency, 4)),
            'planning_summary': summary,
        }
        self._plans.append(record)
        return record

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return the most recent plan record, or None."""
        return self._plans[-1] if self._plans else None

    def recent(self, n=10):
        """Return last n plan records (oldest-first)."""
        buf = list(self._plans)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._plans)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'plans':  list(self._plans),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('plans', []):
            obj._plans.append(rec)
        return obj


# ===========================================================================
# GOAL EXECUTION BRIDGE  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts sleep-derived cognitive plans into waking semantic attention bias.
# Reads:  CognitivePlanner.latest()  -- read-only plan record
#         ConceptGraph.nodes         -- read-only concept support for bias blend
#         ReportBus                  -- read-only (future scene context)
#
# Runs:   ONLY inside 'if not sleeping:' branch, immediately before report_bus.publish()
# Writes: ONLY to its own internal deque + two safe read hooks on planning_sys
#         (planning_sys.semantic_bias, planning_sys.goal_focus)
#
# Zero survival contamination -- never touches selected_action, BG, WM, drives,
# homeostasis, or neuromodulators.
# Memory-safe  -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class GoalExecutionBridge:
    """
    Waking semantic attention bias derived from the active cognitive plan.

    Each waking tick, reads CognitivePlanner.latest() and computes a
    semantic_bias score that downstream semantic systems (ReportBus,
    LanguageReadout, SentenceGenerator, NarrativeMemory) may optionally
    consult to weight their outputs toward the active goal focus.

    Bias is exposed ONLY via two safe read hooks on planning_sys:
      planning_sys.semantic_bias  -- float [0, 1]: current salience preference
      planning_sys.goal_focus     -- int | None:   dominant concept node to weight

    No direct writes to any behavioral or survival path.

    Semantic bias blend
    -------------------
    bias = plan.urgency × 0.70  +  concept_support_norm × 0.30
    where concept_support_norm = support(target_focus) / max_support
    (falls back to 0.0 if target_focus is None or graph is empty)
    Result clamped to [0.0, 1.0].

    Bridge schema
    -------------
    tick            : int
    active_goal     : str
    target_focus    : int | None
    semantic_bias   : float [0, 1]
    bridge_summary  : str   -- always exactly 2 sentences
    """

    # Urgency weight in the bias blend
    _URGENCY_WEIGHT  = 0.70
    # Concept support weight in the bias blend
    _SUPPORT_WEIGHT  = 0.30

    def __init__(self, maxlen=128):
        self._records = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    # ------------------------------------------------------------------
    # Internal helpers  (all read-only, no side-effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _concept_support_norm(target_focus, concept_graph):
        """
        Normalised support of target_focus concept node in [0, 1].
        Returns 0.0 if target_focus is None, node not found, or graph empty.
        """
        if target_focus is None or not concept_graph.nodes:
            return 0.0
        node = concept_graph.nodes.get(target_focus)
        if node is None:
            return 0.0
        max_sup = max(n['support'] for n in concept_graph.nodes.values())
        if max_sup <= 0:
            return 0.0
        return max(0.0, min(1.0, node['support'] / max_sup))

    @staticmethod
    def _compute_semantic_bias(plan, concept_graph):
        """
        Blend plan urgency and concept support into a salience bias [0, 1].
        """
        urgency      = plan.get('urgency', 0.0)
        target_focus = plan.get('target_focus')
        csn          = GoalExecutionBridge._concept_support_norm(
            target_focus, concept_graph)
        raw = (urgency * GoalExecutionBridge._URGENCY_WEIGHT
               + csn    * GoalExecutionBridge._SUPPORT_WEIGHT)
        return max(0.0, min(1.0, raw))

    @staticmethod
    def _compose_bridge_summary(active_goal, target_focus, semantic_bias):
        """
        Compose a 2-sentence waking intention note.

        Sentence 1: which semantic motif should receive extra attention.
        Sentence 2: why based on the planner trajectory.
        """
        # --- Sentence 1: directed attention prescription ---
        goal_attention = {
            'stabilize': (
                "Waking cognition should increase attention toward stabilization "
                "motifs, suppressing high-stress concept recurrence."
            ),
            'reinforce_success': (
                "Waking cognition should sustain attention toward the successful "
                "regulation motif to consolidate the improving confidence arc."
            ),
            'expand_exploration': (
                "Waking cognition should broaden attentional scope, sampling "
                "underactivated concept regions beyond the current dominant focus."
            ),
            'reduce_variance': (
                "Waking cognition should anchor attention toward thematically "
                "stable motifs to reduce arc-level transition noise."
            ),
            'maintain_continuity': (
                "Waking cognition should maintain its current attentional "
                "allocation, sustaining the present balance of semantic activation."
            ),
        }
        s1 = goal_attention.get(active_goal,
                                goal_attention['maintain_continuity'])

        # --- Sentence 2: evidence grounding from bias + focus ---
        if semantic_bias >= 0.70:
            bias_note = f"elevated semantic salience (bias={semantic_bias:.2f})"
        elif semantic_bias >= 0.40:
            bias_note = f"moderate semantic salience (bias={semantic_bias:.2f})"
        else:
            bias_note = f"low semantic salience (bias={semantic_bias:.2f})"

        if target_focus is not None:
            focus_note = f"anchored to concept node {target_focus}"
        else:
            focus_note = "with no specific concept anchor yet"

        s2 = (f"The current CognitivePlanner goal carries {bias_note}, "
              f"{focus_note}.")

        return f"{s1} {s2}"

    # ------------------------------------------------------------------
    # Main bias call  (waking-branch only)
    # ------------------------------------------------------------------

    def bias(self, tick, cognitive_planner, report_bus, concept_graph):
        """
        Compute waking semantic attention bias from the active cognitive plan.

        MUST be called only from 'if not sleeping:' branch, immediately
        before report_bus.publish().  Pure observer during sleeping ticks.

        After computing, exposes two safe read hooks via planning_sys:
          planning_sys.semantic_bias  (float [0, 1])
          planning_sys.goal_focus     (int | None)

        These hooks are set on the planning_sys object passed at class level
        via the safe-hook assignment in the init block.
        The hooks are NOT set here -- they are set by the waking loop after
        reading this record's values, to avoid coupling planning_sys into
        this class signature.

        Parameters
        ----------
        tick              : int
        cognitive_planner : CognitivePlanner -- read via .latest()
        report_bus        : ReportBus        -- available for future scene reads
        concept_graph     : ConceptGraph     -- read via .nodes (read-only)
        """
        plan = cognitive_planner.latest()
        if plan is None:
            return None   # no plan yet (cold-start)

        active_goal   = plan.get('goal_type',     'maintain_continuity')
        target_focus  = plan.get('target_focus')
        sem_bias      = self._compute_semantic_bias(plan, concept_graph)
        summary       = self._compose_bridge_summary(active_goal,
                                                     target_focus, sem_bias)

        record = {
            'tick':           int(tick),
            'active_goal':    active_goal,
            'target_focus':   target_focus,
            'semantic_bias':  float(round(sem_bias, 4)),
            'bridge_summary': summary,
        }
        self._records.append(record)
        return record

    # ------------------------------------------------------------------
    # Read path  (zero side-effects)
    # ------------------------------------------------------------------

    def latest(self):
        """Return the most recent bridge record, or None."""
        return self._records[-1] if self._records else None

    def recent(self, n=10):
        """Return last n bridge records (oldest-first)."""
        buf = list(self._records)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._records)

    # ------------------------------------------------------------------
    # Serialisation  (PersistenceSystem round-trip)
    # ------------------------------------------------------------------

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'records': list(self._records),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('records', []):
            obj._records.append(rec)
        return obj


# ===========================================================================
# TASK FRAMEWORK  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts active semantic goal bias into explicit bounded internal task objects.
# Reads:  planning_sys.semantic_bias
#         planning_sys.goal_focus
#         NarrativeMemory.recent()
#         GoalExecutionBridge
# Runs:   ONLY inside 'if not sleeping:' branch, right after bridge bias exposure
# Writes: ONLY to its own internal deque
#
# Zero survival contamination -- no writes to selected_action, BG, WM, etc.
# Memory-safe -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class TaskFramework:
    """
    Semantic-task layer: derives explicit cognitive tasks from waking bias.

    Reads the active semantic_bias and goal_focus from planning_sys, along
    with NarrativeMemory context, to spawn discrete internal task objects.
    These tasks represent what the organism's cognitive attention should
    "work on" during the current waking cycle (e.g., stabilizing, exploring).

    Task types
    ----------
    'high_priority_stabilization'  (bias >= 0.80)
    'focused_continuation'         (bias >= 0.60)
    'exploratory_probe'            (bias >= 0.35)
    'background_monitoring'        (bias < 0.35)
    Override: 'research_expansion' (recent dominant_theme == 'discovery' AND bias >= 0.50)

    Priority Blend
    --------------
    priority = (semantic_bias * 0.75) + (recent narrative confidence * 0.25)
    Clamped to [0.0, 1.0].

    Task schema
    -----------
    tick         : int
    task_type    : str
    task_focus   : int | None
    priority     : float [0, 1]
    task_summary : str         -- always exactly 2 sentences
    """

    def __init__(self, maxlen=128):
        self._tasks  = deque(maxlen=maxlen)
        self._maxlen = maxlen

    # ------------------------------------------------------------------
    # Internal helpers  (read-only)
    # ------------------------------------------------------------------

    @staticmethod
    def _resolve_task_type(bias, narrative_memory):
        """Map bias thresholds to task types, with narrative override."""
        # 1. Check override
        # recent(1) gives the latest completed arc, though the current arc might
        # be active but not flushed. We'll use latest flushed arc for stability.
        arcs = narrative_memory.recent(1)
        if arcs:
            recent_theme = arcs[0].get('dominant_theme', '')
            if recent_theme == 'discovery' and bias >= 0.50:
                return 'research_expansion'

        # 2. Thresholds
        if bias >= 0.80:
            return 'high_priority_stabilization'
        if bias >= 0.60:
            return 'focused_continuation'
        if bias >= 0.35:
            return 'exploratory_probe'
        return 'background_monitoring'

    @staticmethod
    def _compute_priority(bias, narrative_memory):
        """Blend semantic_bias (0.75) with recent narrative confidence (0.25)."""
        arcs = narrative_memory.recent(1)
        recent_conf = arcs[0].get('mean_confidence', 0.50) if arcs else 0.50
        raw = (bias * 0.75) + (recent_conf * 0.25)
        return max(0.0, min(1.0, raw))

    @staticmethod
    def _compose_task_summary(task_type, bias):
        """Compose a 2-sentence explicit task note."""
        # Sentence 1
        s1_map = {
            'high_priority_stabilization': "The next waking cycle should continue stabilizing the dominant recovery motif.",
            'focused_continuation':        "The next waking cycle should focus on the continued integration of the primary semantic motif.",
            'exploratory_probe':           "The next waking cycle should actively probe novel associations via exploratory logic.",
            'background_monitoring':       "The next waking cycle requires only background monitoring of the current conceptual state.",
            'research_expansion':          "The next waking cycle should actively expand on recent thematic discoveries.",
        }
        s1 = s1_map.get(task_type, s1_map['background_monitoring'])

        # Sentence 2
        if bias >= 0.80:
            s2 = "Elevated semantic bias and repeated reflective recurrence indicate this thread remains the highest-priority cognitive task."
        elif bias >= 0.60:
            s2 = "Consistent semantic bias sustains this task as a primary cognitive objective."
        elif bias >= 0.35:
            s2 = "Moderate semantic pressure supports this mild attentional divergence."
        else:
            s2 = "Low semantic bias permits generalized rather than directed cognitive effort."

        return f"{s1} {s2}"

    # ------------------------------------------------------------------
    # Main spawn call  (waking-branch only)
    # ------------------------------------------------------------------

    def spawn(self, tick, planning_sys, goal_execution_bridge, narrative_memory):
        """
        Derive an explicit internal task object from the current active bias.

        MUST be called only from 'if not sleeping:' branch, after bias is exposed
        and before report_bus synthesis. Pure observer.
        """
        bias  = getattr(planning_sys, 'semantic_bias', 0.0)
        focus = getattr(planning_sys, 'goal_focus', None)

        task_type = self._resolve_task_type(bias, narrative_memory)
        priority  = self._compute_priority(bias, narrative_memory)
        summary   = self._compose_task_summary(task_type, bias)

        record = {
            'tick':         int(tick),
            'task_type':    task_type,
            'task_focus':   focus,
            'priority':     float(round(priority, 4)),
            'task_summary': summary,
        }
        self._tasks.append(record)
        return record

    def latest(self):
        return self._tasks[-1] if self._tasks else None

    def recent(self, n=10):
        buf = list(self._tasks)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._tasks)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'tasks':  list(self._tasks),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('tasks', []):
            obj._tasks.append(rec)
        return obj


# ToolRouter extracted -- import from package (sys.path already patched above)
from ikigai.cognition.routers import ToolRouter



# ===========================================================================
# EXECUTION SANDBOX  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts internal operation intents into safe local simulated execution traces.
# Reads:  ToolRouter.latest()
#         NarrativeMemory.recent()
# Runs:   ONLY inside 'if not sleeping:' branch, right after tool_router.route()
# Writes: ONLY to its own internal deque
#
# Zero survival contamination -- no writes to selected_action, BG, WM, etc.
# Memory-safe -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class ExecutionSandbox:
    """
    Simulated execution layer: converts intents into mock outcome traces.

    Reads the active routed operation from ToolRouter and mocks its execution.
    This provides a closed-loop framework for the organism to 'simulate'
    operations and estimate their success without requiring an external engine,
    supporting expected-vs-observed reasoning protocols.

    Outcome mapping
    ---------------
    'inspect_and_adjust'    -> 'state_refined'
    'continue_thread'       -> 'continuity_preserved'
    'compare_paths'         -> 'branch_difference_observed'
    'observe_only'          -> 'state_monitored'
    'hypothesis_expand'     -> 'novel_relation_detected'

    Success Score Blend
    -------------------
    success_score = (route_confidence * 0.70) + (narrative continuity * 0.30)
    Clamped to [0.0, 1.0].

    Execution schema
    ----------------
    tick              : int
    operation_type    : str
    simulated_outcome : str
    success_score     : float [0, 1]
    execution_summary : str         -- always exactly 2 sentences
    """

    def __init__(self, maxlen=128):
        self._traces = deque(maxlen=maxlen)
        self._maxlen = maxlen

    # ------------------------------------------------------------------
    # Internal helpers  (read-only)
    # ------------------------------------------------------------------

    @staticmethod
    def _resolve_outcome(operation_type):
        """Map operation_type to simulated_outcome."""
        mapping = {
            'inspect_and_adjust': 'state_refined',
            'continue_thread':    'continuity_preserved',
            'compare_paths':      'branch_difference_observed',
            'observe_only':       'state_monitored',
            'hypothesis_expand':  'novel_relation_detected',
        }
        return mapping.get(operation_type, 'state_monitored')

    @staticmethod
    def _compute_success_score(route_confidence, narrative_memory):
        """
        Blend route confidence (0.70) with recency continuity (0.30).
        Using recent mean_confidence as the continuity proxy.
        """
        arcs = narrative_memory.recent(1)
        continuity = arcs[0].get('mean_confidence', 0.50) if arcs else 0.50
        raw = (route_confidence * 0.70) + (continuity * 0.30)
        return max(0.0, min(1.0, raw))

    @staticmethod
    def _compose_execution_summary(outcome_type):
        """Compose a 2-sentence simulated outcome note."""
        s1_map = {
            'state_refined':              "The routed inspection operation successfully refined the targeted conceptual state.",
            'continuity_preserved':       "The routed operation preserved continuity across the active cognitive thread.",
            'branch_difference_observed': "The routed comparison operation observed meaningful divergence across the parallel branches.",
            'state_monitored':            "The routed observational pass effectively monitored the existing semantic baseline.",
            'novel_relation_detected':    "The routed generative operation detected a novel relation within the expanded semantic field.",
        }
        s1 = s1_map.get(outcome_type, s1_map['state_monitored'])

        s2 = "Simulated confidence and narrative consistency suggest the expected outcome remains stable."
        return f"{s1} {s2}"

    # ------------------------------------------------------------------
    # Main execute call  (waking-branch only)
    # ------------------------------------------------------------------

    def execute(self, tick, tool_router, narrative_memory):
        """
        Simulate an operation execution from the active routing intent.

        MUST be called only from 'if not sleeping:' branch, right after
        tool_router.route().
        """
        route = tool_router.latest()
        if route is None:
             return None

        operation  = route.get('operation_type', 'observe_only')
        confidence = route.get('route_confidence', 0.0)

        outcome = self._resolve_outcome(operation)
        score   = self._compute_success_score(confidence, narrative_memory)
        summary = self._compose_execution_summary(outcome)

        record = {
            'tick':              int(tick),
            'operation_type':    operation,
            'simulated_outcome': outcome,
            'success_score':     float(round(score, 4)),
            'execution_summary': summary,
        }
        self._traces.append(record)
        return record

    def latest(self):
        return self._traces[-1] if self._traces else None

    def recent(self, n=10):
        buf = list(self._traces)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._traces)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'traces': list(self._traces),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('traces', []):
            obj._traces.append(rec)
        return obj


# ===========================================================================
# ERROR REFLECTOR  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts simulated execution outcomes into simulated internal mismatch pressure.
# Reads:  TaskFramework.latest()
#         ExecutionSandbox.latest()
# Runs:   ONLY inside 'if not sleeping:' branch, right after ExecutionSandbox
# Writes: ONLY to its own internal deque
#
# Zero survival contamination -- no writes to selected_action, BG, WM, etc.
# Memory-safe -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class ErrorReflector:
    """
    Error reflection layer: detects expectation mismatches from simulated traces.

    Reads the active simulated execution and compares it against the origin
    task trajectory. Identifies logical discrepancies (e.g., trying to innovate
    when explicitly told to stabilize) and generates internal self-repair pressure.
    Produces purely reflective notes; requires a later executor loop for true correction.

    Mismatch mapping
    ----------------
    'continuity_preserved' + non-'focused_continuation' task -> 'trajectory_mismatch'
    'state_refined'        + low priority (< 0.50 task priority) -> 'overcorrection'
    'novel_relation_detected' + 'high_priority_stabilization' task -> 'goal_divergence'
    otherwise -> 'aligned'

    Repair Pressure
    ---------------
    pressure = ((1 - success_score) * 0.70) + (task_priority * 0.30)
    If mismatch == 'aligned': pressure *= 0.25
    Clamped [0.0, 1.0]

    Reflection schema
    -----------------
    tick               : int
    expected_outcome   : str
    mismatch_type      : str
    repair_pressure    : float [0, 1]
    reflection_summary : str         -- always exactly 2 sentences
    """

    def __init__(self, maxlen=128):
        self._reflections = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _resolve_mismatch(outcome, task_type, priority):
        """Map simulation/task pairings to internal mismatch categories."""
        if outcome == 'continuity_preserved' and task_type != 'focused_continuation':
            return 'trajectory_mismatch'
        if outcome == 'state_refined' and priority < 0.50:
            return 'overcorrection'
        if outcome == 'novel_relation_detected' and task_type == 'high_priority_stabilization':
            return 'goal_divergence'
        return 'aligned'

    @staticmethod
    def _compute_repair_pressure(mismatch, success_score, task_priority):
        """Quantify how much correction the current simulation demands."""
        p = ((1.0 - success_score) * 0.70) + (task_priority * 0.30)
        if mismatch == 'aligned':
            p *= 0.25
        return max(0.0, min(1.0, p))

    @staticmethod
    def _compose_summary(mismatch, expected_outcome):
        """Compose a 2-sentence mismatch reflection note."""
        if mismatch == 'trajectory_mismatch':
            s1 = f"The simulated {expected_outcome} outcome diverged from the active task trajectory by preserving continuity during a non-continuation phase."
            s2 = "Elevated repair pressure suggests the next route should bias toward properly aligned structural operations."
        elif mismatch == 'overcorrection':
            s1 = f"The simulated {expected_outcome} outcome over-optimised structural refinement during a low-priority task phase."
            s2 = "Moderate repair pressure suggests relaxing constraint enforcement in the subsequent execution loop."
        elif mismatch == 'goal_divergence':
            s1 = f"The simulated {expected_outcome} outcome diverged from the active task trajectory by introducing a novelty expansion during a stabilization phase."
            s2 = "Elevated repair pressure suggests the next route should bias toward continuity-preserving operations."
        else:
            s1 = f"The simulated {expected_outcome} outcome aligned with the structural demands of the active cognitive trajectory."
            s2 = "Minimal repair pressure permits forward progression without explicit retroactive correction."

        return f"{s1} {s2}"

    def reflect_error(self, tick, execution_sandbox, task_framework):
        """
        Detect logical mismatch from the most recent simulated outcome.

        MUST be called only from 'if not sleeping:' branch, right after
        execution_sandbox.execute().
        """
        trace = execution_sandbox.latest()
        task  = task_framework.latest()

        if not trace or not task:
            return None

        outcome       = trace.get('simulated_outcome', 'state_monitored')
        success_score = trace.get('success_score', 0.5)
        task_type     = task.get('task_type', 'background_monitoring')
        priority      = task.get('priority', 0.0)

        mismatch = self._resolve_mismatch(outcome, task_type, priority)
        pressure = self._compute_repair_pressure(mismatch, success_score, priority)
        summary  = self._compose_summary(mismatch, outcome)

        record = {
            'tick':               int(tick),
            'expected_outcome':   outcome,
            'mismatch_type':      mismatch,
            'repair_pressure':    float(round(pressure, 4)),
            'reflection_summary': summary,
        }
        self._reflections.append(record)
        return record

    def latest(self):
        return self._reflections[-1] if self._reflections else None

    def recent(self, n=10):
        buf = list(self._reflections)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._reflections)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'reflections': list(self._reflections),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('reflections', []):
            obj._reflections.append(rec)
        return obj


# ===========================================================================
# RETRY PLANNER  (Day 23 cognition substrate -- Prince Siddhpara 2026)
# Converts mismatch pressure into revised safe route intents.
# Reads:  ErrorReflector.latest()
#         ToolRouter.latest()
# Runs:   ONLY inside 'if not sleeping:' branch, right after error_reflector
# Writes: ONLY to its own internal deque
#
# Zero survival contamination -- no writes to selected_action, BG, WM, etc.
# Memory-safe -- deque(maxlen=128)
# Fully serializable -- to_dict() / from_dict()
# ===========================================================================

class RetryPlanner:
    """
    Retry planning layer: consumes mismatch reflection to formulate safe intent reiterations.

    Acts as the final node in the mock-execution loop. Interprets trajectory errors
    derived from expected-vs-observed mismatches and generates revised structural plans.
    Strictly observer-only; produces proto-self-repair intents that could later be acted
    upon by the waking baseline engine.

    Strategy mapping
    ----------------
    'trajectory_mismatch' -> 'force_continuity'
    'overcorrection'      -> 'lower_intensity'
    'goal_divergence'     -> 'fallback_to_stable_route'
    'aligned'             -> 'preserve_route'

    Retry Confidence Blend
    ----------------------
    confidence = (repair_pressure * 0.70) + ((1.0 - route_confidence) * 0.30)
    If mismatch == 'aligned': confidence *= 0.20
    Clamped [0.0, 1.0]

    Retry schema
    ------------
    tick             : int
    retry_strategy   : str
    retry_confidence : float [0, 1]
    retry_summary    : str         -- always exactly 2 sentences
    """

    def __init__(self, maxlen=128):
        self._plans = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _resolve_strategy(mismatch_type):
        """Map mismatch category to tactical retry intent."""
        mapping = {
            'trajectory_mismatch': 'force_continuity',
            'overcorrection':      'lower_intensity',
            'goal_divergence':     'fallback_to_stable_route',
            'aligned':             'preserve_route',
        }
        return mapping.get(mismatch_type, 'preserve_route')

    @staticmethod
    def _compute_confidence(mismatch_type, repair_pressure, route_confidence):
        """Quantify how securely the strategy should overwrite the prior route."""
        c = (repair_pressure * 0.70) + ((1.0 - route_confidence) * 0.30)
        if mismatch_type == 'aligned':
            c *= 0.20
        return max(0.0, min(1.0, c))

    @staticmethod
    def _compose_summary(strategy_type):
        """Compose a 2-sentence revised-route note based on strategy."""
        s1_map = {
            'force_continuity':         "The next simulated route should force continuation operations to repair the broken trajectory.",
            'lower_intensity':          "The next simulated route should lower structural variation intensity to mitigate the detected overcorrection.",
            'fallback_to_stable_route': "The next simulated route should fallback toward continuity-preserving operations around the prior stable thread.",
            'preserve_route':           "The next simulated route should preserve the active cognitive thread parameters identically.",
        }
        s1 = s1_map.get(strategy_type, s1_map['preserve_route'])

        s2_map = {
            'force_continuity':         "High repair pressure indicates the previous route drifted into an unstructured state.",
            'lower_intensity':          "Moderate repair pressure suggests the current cognitive phase requires less active intervention.",
            'fallback_to_stable_route': "High repair pressure and detected goal divergence indicate the previous route expanded beyond task-safe bounds.",
            'preserve_route':           "Minimal repair pressure and established alignment confirm the previous route profile is optimally bounded.",
        }
        s2 = s2_map.get(strategy_type, s2_map['preserve_route'])

        return f"{s1} {s2}"

    def update(self, state):
        """Unified interface (Day 32)."""
        return self._plan_retry(
            tick            = state.tick,
            error_reflector = state.error_reflector,
            tool_router     = state.tool_router,
        )

    def _plan_retry(self, tick, error_reflector, tool_router):
        """
        Formulate a route-revision strategy based on reflection mismatch.

        MUST be called only from 'if not sleeping:' branch, right after
        error_reflector.reflect_error().
        """
        err   = error_reflector.latest()
        route = tool_router.latest()

        if not err or not route:
            return None

        mismatch   = err.get('mismatch_type', 'aligned')
        pressure   = err.get('repair_pressure', 0.0)
        route_conf = route.get('route_confidence', 0.5)

        strategy   = self._resolve_strategy(mismatch)
        confidence = self._compute_confidence(mismatch, pressure, route_conf)
        summary    = self._compose_summary(strategy)

        record = {
            'tick':             int(tick),
            'retry_strategy':   strategy,
            'retry_confidence': float(round(confidence, 4)),
            'retry_summary':    summary,
        }
        self._plans.append(record)
        return record

    def latest(self):
        return self._plans[-1] if self._plans else None

    def recent(self, n=10):
        buf = list(self._plans)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._plans)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'plans':  list(self._plans),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('plans', []):
            obj._plans.append(rec)
        return obj


