class RouteMutator:
    """
    Mutator layer: converts retry strategy into a next-route operation bias override.
    """
    def __init__(self, maxlen=128):
        self._mutations = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _resolve_mutation(strategy, current_route):
        mapping = {
            'force_continuity':         'continue_thread',
            'lower_intensity':          'observe_only',
            'fallback_to_stable_route': 'continue_thread',
            'preserve_route':           current_route,
        }
        return mapping.get(strategy, current_route)

    @staticmethod
    def _compute_strength(retry_confidence, route_confidence):
        s = (retry_confidence * 0.80) + ((1.0 - route_confidence) * 0.20)
        return max(0.0, min(1.0, s))

    def mutate(self, tick, retry_planner, tool_router):
        retry = retry_planner.latest()
        route = tool_router.latest()

        if not retry or not route:
            return None

        strategy         = retry.get('retry_strategy', 'preserve_route')
        retry_conf       = retry.get('retry_confidence', 0.0)
        current_route    = route.get('operation_type', 'observe_only')
        route_conf       = route.get('route_confidence', 0.5)

        mutated  = self._resolve_mutation(strategy, current_route)
        strength = self._compute_strength(retry_conf, route_conf)

        if strategy == 'preserve_route':
            summary = "The active route was preserved without structural modification. Mutation strength minimized to maintain trajectory alignment."
        else:
            summary = "The active route was explicitly mutated following strict strategy constraints. Mutation strength overrides previous directional errors."

        record = {
            'tick':              int(tick),
            'mutated_route':     mutated,
            'mutation_strength': float(round(strength, 4)),
            'mutation_summary':  summary,
        }
        self._mutations.append(record)
        return record

    def latest(self): return self._mutations[-1] if self._mutations else None
    def recent(self, n=10): buf = list(self._mutations); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._mutations)
    def to_dict(self): return {'maxlen': self._maxlen, 'mutations': list(self._mutations)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('mutations', []): obj._mutations.append(rec)
        return obj


class MutationGuard:
    """
    Guard layer: prevents retry oscillation and loop lock.
    """
    def __init__(self, maxlen=128):
        self._guards = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def _evaluate(self, recent_mutations):
        if len(recent_mutations) < 3:
            return 'stable'
        last_3 = recent_mutations[-3:]
        routes = [r.get('mutated_route') for r in last_3]

        if len(set(routes)) == 3:
            return 'oscillation_risk'
        if len(set(routes)) == 1:
            return 'loop_lock'
        return 'stable'

    def validate(self, tick, route_mutator):
        history = route_mutator.recent(3)
        state = self._evaluate(history)

        pressure = 0.85 if state != 'stable' else 0.15

        s1 = f"Mutation guard evaluated recent route modifications as {state}."
        s2 = "The route modification trajectory remains within safe non-oscillatory bounds." if state == 'stable' else "The route modification trajectory breached structural limits indicating corrective lockup."

        record = {
            'tick':           int(tick),
            'guard_state':    state,
            'guard_pressure': float(round(pressure, 4)),
            'guard_summary':  f"{s1} {s2}",
        }
        self._guards.append(record)
        return record

    def latest(self): return self._guards[-1] if self._guards else None
    def recent(self, n=10): buf = list(self._guards); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._guards)
    def to_dict(self): return {'maxlen': self._maxlen, 'guards': list(self._guards)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('guards', []): obj._guards.append(rec)
        return obj


class RetryOutcomeTracker:
    """
    Outcome layer: measures whether the simulated trace improved after mutation.
    """
    def __init__(self, maxlen=128):
        self._trackers = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def _resolve_status(self, prev_strat, curr_strat):
        if curr_strat == 'preserve_route' and prev_strat != 'preserve_route':
            return 'improved'
        if curr_strat == prev_strat:
            return 'unchanged'
        return 'regressed'

    def track(self, tick, route_mutator, execution_sandbox, retry_planner):
        mutation = route_mutator.latest()
        sandbox  = execution_sandbox.latest()
        previous = retry_planner.recent(2)

        if not mutation or not sandbox or not previous:
            return None

        curr_strat = previous[-1].get('retry_strategy')
        prev_strat = previous[0].get('retry_strategy') if len(previous) > 1 else 'preserve_route'

        status = self._resolve_status(prev_strat, curr_strat)

        mut_strength = mutation.get('mutation_strength', 0.0)
        succ_score   = sandbox.get('success_score', 0.5)

        score = (mut_strength * 0.60) + (succ_score * 0.40)
        score = max(0.0, min(1.0, score))

        s1 = f"Simulation validation rated the current route modification cycle as {status}."
        if status == 'improved': s2 = "Outcome alignment successfully resolved the prior mismatch penalty."
        else: s2 = "Outcome alignment failed to fully resolve the structural inconsistency."

        record = {
            'tick':              int(tick),
            'outcome_status':    status,
            'improvement_score': float(round(score, 4)),
            'tracker_summary':   f"{s1} {s2}",
        }
        self._trackers.append(record)
        return record

    def latest(self): return self._trackers[-1] if self._trackers else None
    def recent(self, n=10): buf = list(self._trackers); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._trackers)
    def to_dict(self): return {'maxlen': self._maxlen, 'trackers': list(self._trackers)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('trackers', []): obj._trackers.append(rec)
        return obj


