class StrategyLearner:
    """Learns which retry strategies effectively improve coherence."""
    def __init__(self, maxlen=128):
        self._learned = deque(maxlen=maxlen)
        self._maxlen = maxlen
        self._preferences = {}

    def learn(self, tick, retry_outcome_tracker, retry_planner):
        tracker = retry_outcome_tracker.latest()
        retry   = retry_planner.latest()

        if not tracker or not retry:
            return None

        status   = tracker.get('outcome_status', 'unchanged')
        strategy = retry.get('retry_strategy', 'preserve_route')

        if status == 'improved': delta = 0.10
        elif status == 'unchanged': delta = 0.00
        else: delta = -0.08

        old_score = self._preferences.get(strategy, 0.5)
        new_score = max(0.0, min(1.0, old_score * 0.92 + delta))
        self._preferences[strategy] = new_score

        s1 = f"Strategy '{strategy}' demonstrated a {status} outcome."
        if delta > 0: s2 = "Preference strength increased to bias future route applications."
        elif delta < 0: s2 = "Preference strength decayed to marginalize this path."
        else: s2 = "Preference strength maintained stable equilibrium."

        record = {
            'tick':             int(tick),
            'strategy_key':     strategy,
            'preference_score': float(round(new_score, 4)),
            'learning_summary': f"{s1} {s2}",
        }
        self._learned.append(record)
        return record

    def latest(self): return self._learned[-1] if self._learned else None
    def recent(self, n=10): buf = list(self._learned); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._learned)
    def to_dict(self): return {'maxlen': self._maxlen, 'learned': list(self._learned), 'preferences': self._preferences.copy()}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        obj._preferences = d.get('preferences', {})
        for rec in d.get('learned', []): obj._learned.append(rec)
        return obj


class PolicyShaper:
    """Turns learned preferences into future route priors and mutation dampening."""
    def __init__(self, maxlen=128):
        self._policies = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def shape(self, tick, strategy_learner, mutation_guard):
        learner = strategy_learner.latest()
        guard   = mutation_guard.latest()

        if not learner or not guard:
            return None

        score = learner.get('preference_score', 0.5)
        state = guard.get('guard_state', 'stable')
        pressure = guard.get('guard_pressure', 0.15)

        if state == 'oscillation_risk':
            bias = 'dampen_mutation'
        elif state == 'loop_lock':
            bias = 'inject_exploration_escape'
        elif state == 'stable' and score > 0.65:
            bias = 'reinforce_strategy'
        else:
            bias = 'neutral'

        strength = (score * 0.70) + ((1.0 - pressure) * 0.30)
        strength = max(0.0, min(1.0, strength))

        s1 = f"Policy shaper applied structural {bias} prioritizing outcome stabilization."
        if bias in ['dampen_mutation', 'inject_exploration_escape']:
            s2 = "Current learning bias maps explicitly block active oscillatory locks."
        else:
            s2 = "Current learning bias reinforces observed success trajectories."

        record = {
            'tick':           int(tick),
            'policy_bias':    bias,
            'bias_strength':  float(round(strength, 4)),
            'policy_summary': f"{s1} {s2}",
        }
        self._policies.append(record)
        return record

    def latest(self): return self._policies[-1] if self._policies else None
    def recent(self, n=10): buf = list(self._policies); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._policies)
    def to_dict(self): return {'maxlen': self._maxlen, 'policies': list(self._policies)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('policies', []): obj._policies.append(rec)
        return obj


class FailureAtlas:
    """Stores recurring mismatch to successful-recovery pairings as knowledge maps."""
    def __init__(self, maxlen=128):
        self._atlas = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def record(self, tick, error_reflector, retry_planner, retry_outcome_tracker, strategy_learner):
        error   = error_reflector.latest()
        retry   = retry_planner.latest()
        tracker = retry_outcome_tracker.latest()
        learner = strategy_learner.latest()

        if not error or not retry or not tracker or not learner:
            return None

        mismatch = error.get('mismatch_type', 'aligned')
        strategy = retry.get('retry_strategy', 'preserve_route')
        imp_score = tracker.get('improvement_score', 0.5)
        pref_score = learner.get('preference_score', 0.5)

        sig = f"{mismatch}->{strategy}"
        conf = (imp_score * 0.80) + (pref_score * 0.20)
        conf = max(0.0, min(1.0, conf))

        s1 = f"Failure atlas encoded recovery mapping {sig}."
        if conf > 0.5: s2 = "High structural confidence secures this signature for future automatic resolution."
        else: s2 = "Low structural confidence flags this signature for continued monitoring."

        record = {
            'tick':              int(tick),
            'failure_signature': sig,
            'best_recovery':     strategy,
            'atlas_confidence':  float(round(conf, 4)),
            'atlas_summary':     f"{s1} {s2}",
        }

        # Deduplicate: if signature exists, remove old one so the new confidence record sits at the head
        existing = [r for r in self._atlas if r['failure_signature'] != sig]
        self._atlas.clear()
        for r in existing:
            self._atlas.append(r)

        self._atlas.append(record)
        return record

    def latest(self): return self._atlas[-1] if self._atlas else None
    def recent(self, n=10): buf = list(self._atlas); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._atlas)
    def to_dict(self): return {'maxlen': self._maxlen, 'atlas': list(self._atlas)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('atlas', []): obj._atlas.append(rec)
        return obj



