class AbstractTaskEngine:
    def __init__(self, maxlen=128):
        self._plans = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def build(self, tick, task_framework, policy_shaper, failure_atlas):
        task   = task_framework.latest()
        policy = policy_shaper.latest()
        atlas  = failure_atlas.latest()

        if not task or not policy or not atlas:
            return None

        task_type = task.get('task_type', 'background_monitoring')
        priority  = task.get('priority', 0.0)
        atlas_conf = atlas.get('atlas_confidence', 0.5)

        mapping = {
            'high_priority_stabilization': ["inspect", "refine", "verify"],
            'focused_continuation': ["continue", "integrate", "validate"],
            'research_expansion': ["expand", "compare", "synthesize"]
        }
        subgoals = mapping.get(task_type, ["monitor", "evaluate", "log"])

        conf = (priority * 0.60) + (atlas_conf * 0.40)
        conf = max(0.0, min(1.0, conf))

        plan_id = f"plan_{tick}"
        s1 = f"Abstract task engine decomposed {task_type} into sequential subgoals."
        if conf > 0.6: s2 = "High structural confidence guides execution."
        else: s2 = "Moderate structural confidence guides execution."

        record = {
            'tick':            int(tick),
            'plan_id':         plan_id,
            'subgoals':        subgoals,
            'active_subgoal':  subgoals[0] if subgoals else "none",
            'plan_confidence': float(round(conf, 4)),
            'plan_summary':    f"{s1} {s2}"
        }
        self._plans.append(record)
        return record

    def latest(self): return self._plans[-1] if self._plans else None
    def recent(self, n=10): buf = list(self._plans); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._plans)
    def to_dict(self): return {'maxlen': self._maxlen, 'plans': list(self._plans)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('plans', []): obj._plans.append(rec)
        return obj

class PlanGraphMemory:
    def __init__(self, maxlen=128):
        self._graphs = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def store(self, tick, abstract_task_engine, retry_outcome_tracker):
        plan = abstract_task_engine.latest()
        tracker = retry_outcome_tracker.latest()

        if not plan or not tracker:
            return None

        status = tracker.get('outcome_status', 'unchanged')
        sig = "->".join(plan.get('subgoals', []))

        if status == 'improved': delta = 0.08
        elif status == 'unchanged': delta = 0.00
        else: delta = -0.05

        old_score = 0.5
        existing = [g for g in self._graphs if g['plan_signature'] == sig]
        if existing:
            old_score = existing[-1]['success_bias']

        new_score = old_score * 0.94 + delta
        new_score = max(0.0, min(1.0, new_score))

        # deduplicate logic internally
        purged = [g for g in self._graphs if g['plan_signature'] != sig]
        self._graphs.clear()
        for g in purged: self._graphs.append(g)

        s1 = f"Graph memory integrated routing structure {sig}."
        if delta > 0: s2 = "Success bias positively strengthened."
        elif delta < 0: s2 = "Success bias penalized due to regression."
        else: s2 = "Success bias maintained."

        record = {
            'tick':           int(tick),
            'plan_signature': sig,
            'success_bias':   float(round(new_score, 4)),
            'graph_summary':  f"{s1} {s2}"
        }
        self._graphs.append(record)
        return record

    def latest(self): return self._graphs[-1] if self._graphs else None
    def recent(self, n=10): buf = list(self._graphs); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._graphs)
    def to_dict(self): return {'maxlen': self._maxlen, 'graphs': list(self._graphs)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('graphs', []): obj._graphs.append(rec)
        return obj

class SubgoalEvaluator:
    def __init__(self, maxlen=128):
        self._evals = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def evaluate(self, tick, abstract_task_engine, retry_outcome_tracker, mutation_guard):
        plan = abstract_task_engine.latest()
        tracker = retry_outcome_tracker.latest()
        guard = mutation_guard.latest()

        if not plan or not tracker or not guard:
            return None

        status = tracker.get('outcome_status', 'unchanged')
        gstate = guard.get('guard_state', 'stable')
        conf = plan.get('plan_confidence', 0.5)
        imp = tracker.get('improvement_score', 0.5)

        if status == 'improved' and gstate == 'stable':
            state = 'progressing'
        elif status == 'unchanged' and gstate == 'loop_lock':
            state = 'stalled'
        elif status == 'regressed' and gstate == 'oscillation_risk':
            state = 'destabilized'
        else:
            state = 'uncertain'

        score = (conf * 0.70) + (imp * 0.30)
        score = max(0.0, min(1.0, score))

        s1 = f"Subgoal evaluation established status as {state}."
        if state == 'progressing': s2 = "Chain execution verified to be proceeding nominally."
        else: s2 = "Chain execution flagged with progressive instabilities."

        record = {
            'tick':               int(tick),
            'subgoal_state':      state,
            'progress_score':     float(round(score, 4)),
            'evaluation_summary': f"{s1} {s2}"
        }
        self._evals.append(record)
        return record

    def latest(self): return self._evals[-1] if self._evals else None
    def recent(self, n=10): buf = list(self._evals); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._evals)
    def to_dict(self): return {'maxlen': self._maxlen, 'evals': list(self._evals)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('evals', []): obj._evals.append(rec)
        return obj

