# ProjectWorkspace + ArtifactStateMemory + ConsistencyVerifier
# Friston 2010 (active inference, object permanence);
# Baddeley 2000 (working memory buffer); Tulving 1983 (episodic continuity).
#
# Rules:
#   - Waking-only: runs after subgoal_evaluator.evaluate(), before report_bus.publish()
#   - Zero survival contamination: never touches selected_action, BG, WM, drives,
#     neuromodulators, or any motor-loop variable
#   - Bounded: each class uses deque(maxlen=128), fully serializable, leak-free
#   - No filesystem writes: internal artifact cognition only (simulated continuity)
# ===========================================================================

class ProjectWorkspace:
    """
    Maintains the organism's current active work-product context.

    Schema:
        tick                 : int
        workspace_id         : str
        artifact_type        : str  -- 'code_block' | 'document' | 'research_note'
        active_section       : str  -- mirrors current active_subgoal
        workspace_confidence : float [0, 1]
        workspace_summary    : str

    Confidence = plan_confidence * 0.65 + progress_score * 0.35, clamped [0, 1].
    """

    _ARTIFACT_MAP = {
        'inspect':    'code_block',
        'refine':     'code_block',
        'verify':     'code_block',
        'continue':   'document',
        'integrate':  'document',
        'validate':   'document',
        'expand':     'research_note',
        'compare':    'research_note',
        'synthesize': 'research_note',
    }

    def __init__(self, maxlen=128):
        self._workspaces = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def update(self, tick, abstract_task_engine, subgoal_evaluator, plan_graph_memory):
        plan  = abstract_task_engine.latest()
        evalu = subgoal_evaluator.latest()
        # plan_graph_memory is available for future enrichment; not required
        if not plan or not evalu:
            return None

        active_subgoal = plan.get('active_subgoal', 'monitor')
        artifact_type  = self._ARTIFACT_MAP.get(active_subgoal, 'research_note')
        plan_conf      = plan.get('plan_confidence', 0.5)
        progress_score = evalu.get('progress_score', 0.5)
        confidence     = plan_conf * 0.65 + progress_score * 0.35
        confidence     = max(0.0, min(1.0, confidence))

        s1 = (f"The active workspace currently holds a {artifact_type} "
              f"centered on the {active_subgoal} subgoal.")
        if confidence >= 0.65:
            s2 = ("Confidence remains high because hierarchical progression "
                  "and workflow priors are aligned.")
        elif confidence >= 0.35:
            s2 = "Confidence is moderate; subgoal progression is partially constrained."
        else:
            s2 = "Confidence is low; structural instability detected in the active work context."

        record = {
            'tick':                 int(tick),
            'workspace_id':         f"ws_{tick}",
            'artifact_type':        artifact_type,
            'active_section':       active_subgoal,
            'workspace_confidence': float(round(confidence, 4)),
            'workspace_summary':    f"{s1} {s2}",
        }
        self._workspaces.append(record)
        return record

    def latest(self): return self._workspaces[-1] if self._workspaces else None
    def recent(self, n=10): buf = list(self._workspaces); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._workspaces)
    def to_dict(self): return {'maxlen': self._maxlen, 'workspaces': list(self._workspaces)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('workspaces', []): obj._workspaces.append(rec)
        return obj


class ArtifactStateMemory:
    """
    Preserves versioned internal artifact evolution (object permanence memory).

    Schema:
        tick               : int
        artifact_signature : str   -- '{artifact_type}:{active_section}'
        version_index      : int   -- increments on each consecutive identical signature
        state_stability    : float [0, 1]
        artifact_summary   : str

    DEDUP LAW: consecutive identical signatures do NOT produce a new record.
    Instead, stability is reinforced (EMA toward 1.0) and version_index increments.
    New signature resets version to 1 and appends a fresh record.

    Stability = workspace_confidence * 0.70 + improvement_score * 0.30, clamped [0, 1].
    """

    def __init__(self, maxlen=128):
        self._states = deque(maxlen=maxlen)
        self._maxlen = maxlen
        self._last_signature = None

    def remember(self, tick, project_workspace, retry_outcome_tracker):
        workspace = project_workspace.latest()
        tracker   = retry_outcome_tracker.latest() if retry_outcome_tracker else None
        if not workspace:
            return None

        artifact_type  = workspace.get('artifact_type', 'research_note')
        active_section = workspace.get('active_section', 'monitor')
        ws_conf        = workspace.get('workspace_confidence', 0.5)
        imp_score      = tracker.get('improvement_score', 0.5) if tracker else 0.5

        signature = f"{artifact_type}:{active_section}"
        stability = max(0.0, min(1.0, ws_conf * 0.70 + imp_score * 0.30))

        # DEDUP: same consecutive signature -> strengthen stability, increment version
        if self._states and self._last_signature == signature:
            last = self._states[-1]
            new_stability = min(1.0, last['state_stability'] * 0.90 + stability * 0.10 + 0.02)
            new_version   = last['version_index'] + 1
            updated = {
                'tick':               int(tick),
                'artifact_signature': signature,
                'version_index':      new_version,
                'state_stability':    float(round(new_stability, 4)),
                'artifact_summary': (
                    f"Artifact '{signature}' sustained at version {new_version}. "
                    f"Stability reinforced to {new_stability:.3f} through continued coherence."
                ),
            }
            self._states[-1] = updated
            return updated

        # New signature: start fresh
        self._last_signature = signature
        record = {
            'tick':               int(tick),
            'artifact_signature': signature,
            'version_index':      1,
            'state_stability':    float(round(stability, 4)),
            'artifact_summary': (
                f"New artifact state established: '{signature}' at version 1. "
                f"Initial stability anchored at {stability:.3f}."
            ),
        }
        self._states.append(record)
        return record

    def latest(self): return self._states[-1] if self._states else None
    def recent(self, n=10): buf = list(self._states); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._states)
    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'states': list(self._states),
            'last_signature': self._last_signature,
        }
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('states', []): obj._states.append(rec)
        obj._last_signature = d.get('last_signature', None)
        return obj


class ConsistencyVerifier:
    """
    Verifies that the evolving artifact still matches current subgoal + workflow graph.
    Prevents silent continuity drift.

    Schema:
        tick                : int
        consistency_state   : str  -- 'consistent' | 'stale' | 'drifted' | 'uncertain'
        consistency_score   : float [0, 1]
        consistency_summary : str

    State rules:
        consistent : matching active_section + subgoal_state == 'progressing'
        stale      : same artifact section + subgoal_state == 'stalled'
        drifted    : subgoal_state == 'destabilized' + section mismatch (signature jump)
        uncertain  : all other cases

    Score = workspace_confidence * 0.60 + state_stability * 0.40, clamped [0, 1].
    """

    def __init__(self, maxlen=128):
        self._records = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    def verify(self, tick, project_workspace, artifact_state_memory, subgoal_evaluator):
        workspace = project_workspace.latest()
        artifact  = artifact_state_memory.latest()
        evalu     = subgoal_evaluator.latest()
        if not workspace or not artifact or not evalu:
            return None

        ws_section    = workspace.get('active_section', '')
        art_sig       = artifact.get('artifact_signature', '')
        # signature is '{artifact_type}:{active_section}' -- extract section
        art_section   = art_sig.split(':', 1)[-1] if ':' in art_sig else art_sig
        ws_conf       = workspace.get('workspace_confidence', 0.5)
        stability     = artifact.get('state_stability', 0.5)
        subgoal_state = evalu.get('subgoal_state', 'uncertain')

        section_match = (ws_section == art_section)

        if section_match and subgoal_state == 'progressing':
            consistency_state = 'consistent'
        elif subgoal_state == 'destabilized' and not section_match:
            consistency_state = 'drifted'
        elif subgoal_state == 'stalled' and section_match:
            consistency_state = 'stale'
        else:
            consistency_state = 'uncertain'

        score = max(0.0, min(1.0, ws_conf * 0.60 + stability * 0.40))

        if consistency_state == 'consistent':
            summary = (
                f"The artifact remains consistent with the active {ws_section} subgoal "
                f"and current workflow memory. No evidence of stale carryover or "
                f"continuity drift is present."
            )
        elif consistency_state == 'stale':
            version = artifact.get('version_index', 1)
            summary = (
                f"Artifact '{art_sig}' at version {version} shows no forward progression. "
                f"Subgoal state is stalled; continuity has become static."
            )
        elif consistency_state == 'drifted':
            summary = (
                f"Artifact signature jump detected: workspace section '{ws_section}' "
                f"does not match artifact section '{art_section}'. "
                f"Continuity drift present; workspace and artifact are misaligned."
            )
        else:
            summary = (
                f"Consistency state undetermined for artifact '{art_sig}'. "
                f"Insufficient progression signal to confirm alignment."
            )

        record = {
            'tick':                int(tick),
            'consistency_state':   consistency_state,
            'consistency_score':   float(round(score, 4)),
            'consistency_summary': summary,
        }
        self._records.append(record)
        return record

    def latest(self): return self._records[-1] if self._records else None
    def recent(self, n=10): buf = list(self._records); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._records)
    def to_dict(self): return {'maxlen': self._maxlen, 'records': list(self._records)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('records', []): obj._records.append(rec)
        return obj

