# EditIntentGenerator + PatchPreviewMemory + IntegrityScorer
# Friston 2010 (active inference, predictive coding);
# Hofstadter 1979 (symbolic self-modification loops).
#
# Rules:
#   - Waking-only: after consistency_verifier.verify(), before report_bus.publish()
#   - Zero survival contamination: no selected_action / BG / WM / drive writes
#   - No real file mutation: symbolic predicted edits only
#   - Bounded: deque(maxlen=128), fully serializable, leak-free
# ===========================================================================

class EditIntentGenerator:
    """
    Determines the next symbolic edit operation from the active artifact state.

    Schema:
        tick             : int
        edit_operation   : str   -- symbolic op (analyze_segment, modify_segment, ...)
        target_region    : str   -- mirrors active_section
        edit_confidence  : float [0, 1]
        intent_summary   : str

    Operation mapping (active_section -> edit_operation):
        inspect   -> analyze_segment
        refine    -> modify_segment
        verify    -> validate_segment
        integrate -> merge_segment
        synthesize-> synthesize_segment
        default   -> modify_segment

    Confidence = workspace_confidence * 0.70 + consistency_score * 0.30, clamped [0, 1].
    """

    _OP_MAP = {
        'inspect':    'analyze_segment',
        'refine':     'modify_segment',
        'verify':     'validate_segment',
        'integrate':  'merge_segment',
        'synthesize': 'synthesize_segment',
    }

    def __init__(self, maxlen=128):
        self._intents = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    def generate(self, tick, project_workspace, consistency_verifier, subgoal_evaluator):
        workspace = project_workspace.latest()
        cons      = consistency_verifier.latest()
        # subgoal_evaluator available for future enrichment; not required
        if not workspace or not cons:
            return None

        active_section  = workspace.get('active_section', 'refine')
        ws_conf         = workspace.get('workspace_confidence', 0.5)
        cons_score      = cons.get('consistency_score', 0.5)

        edit_operation  = self._OP_MAP.get(active_section, 'modify_segment')
        target_region   = active_section
        confidence      = max(0.0, min(1.0, ws_conf * 0.70 + cons_score * 0.30))

        s1 = f"Edit intent selected '{edit_operation}' targeting region '{target_region}'."
        if confidence >= 0.70:
            s2 = "High confidence: intent is well-supported by workspace and consistency signals."
        elif confidence >= 0.40:
            s2 = "Moderate confidence: intent derivable but some uncertainty remains."
        else:
            s2 = "Low confidence: artifact state insufficient to anchor a strong edit intent."

        record = {
            'tick':           int(tick),
            'edit_operation': edit_operation,
            'target_region':  target_region,
            'edit_confidence': float(round(confidence, 4)),
            'intent_summary': f"{s1} {s2}",
        }
        self._intents.append(record)
        return record

    def latest(self): return self._intents[-1] if self._intents else None
    def recent(self, n=10): buf = list(self._intents); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._intents)
    def to_dict(self): return {'maxlen': self._maxlen, 'intents': list(self._intents)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('intents', []): obj._intents.append(rec)
        return obj


class PatchPreviewMemory:
    """
    Stores symbolic before/after patch previews (proto internal diff memory).

    Schema:
        tick              : int
        before_signature  : str   -- current artifact signature
        after_signature   : str   -- '{before_signature}->{edit_operation}'
        preview_strength  : float [0, 1]
        repeat_count      : int   -- how many consecutive identical after_signature calls
        patch_summary     : str

    DEDUP LAW: repeated identical after_signature -> update in place.
        preview_strength = old * 0.92 + new * 0.08 + 0.01
        repeat_count    += 1
        No duplicate record appended.

    Preview strength = state_stability * 0.60 + edit_confidence * 0.40, clamped [0, 1].
    """

    def __init__(self, maxlen=128):
        self._previews      = deque(maxlen=maxlen)
        self._maxlen        = maxlen
        self._last_after_sig = None

    def preview(self, tick, edit_intent_generator, artifact_state_memory):
        intent   = edit_intent_generator.latest()
        artifact = artifact_state_memory.latest()
        if not intent or not artifact:
            return None

        edit_op         = intent.get('edit_operation', 'modify_segment')
        edit_conf       = intent.get('edit_confidence', 0.5)
        before_sig      = artifact.get('artifact_signature', 'unknown:unknown')
        stability       = artifact.get('state_stability', 0.5)

        after_sig       = f"{before_sig}->{edit_op}"
        strength        = max(0.0, min(1.0, stability * 0.60 + edit_conf * 0.40))

        # DEDUP: same after_signature -> strengthen in place, no new record
        if self._previews and self._last_after_sig == after_sig:
            last = self._previews[-1]
            new_strength  = min(1.0, last['preview_strength'] * 0.92 + strength * 0.08 + 0.01)
            new_repeat    = last['repeat_count'] + 1
            updated = {
                'tick':             int(tick),
                'before_signature': before_sig,
                'after_signature':  after_sig,
                'preview_strength': float(round(new_strength, 4)),
                'repeat_count':     new_repeat,
                'patch_summary': (
                    f"Patch preview '{after_sig}' reinforced at repeat {new_repeat}. "
                    f"Preview strength consolidated to {new_strength:.3f}."
                ),
            }
            self._previews[-1] = updated
            return updated

        # New after_signature: fresh record
        self._last_after_sig = after_sig
        record = {
            'tick':             int(tick),
            'before_signature': before_sig,
            'after_signature':  after_sig,
            'preview_strength': float(round(strength, 4)),
            'repeat_count':     1,
            'patch_summary': (
                f"New patch preview established: '{after_sig}'. "
                f"Initial preview strength anchored at {strength:.3f}."
            ),
        }
        self._previews.append(record)
        return record

    def latest(self): return self._previews[-1] if self._previews else None
    def recent(self, n=10): buf = list(self._previews); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._previews)
    def to_dict(self):
        return {
            'maxlen':          self._maxlen,
            'previews':        list(self._previews),
            'last_after_sig':  self._last_after_sig,
        }
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('previews', []): obj._previews.append(rec)
        obj._last_after_sig = d.get('last_after_sig', None)
        return obj


class IntegrityScorer:
    """
    Validates whether the predicted patch still preserves artifact continuity
    and subgoal alignment. First symbolic edit safety gate.

    Schema:
        tick               : int
        integrity_state    : str   -- 'safe_patch' | 'redundant_patch' | 'unsafe_patch' | 'uncertain'
        integrity_score    : float [0, 1]
        integrity_summary  : str

    State rules (priority order):
        safe_patch     : consistency_state == 'consistent' AND preview_strength > 0.70
        redundant_patch: consistency_state == 'stale'      AND repeat_count > 1
        unsafe_patch   : consistency_state == 'drifted'
        uncertain      : all other cases

    Score = preview_strength * 0.65 + consistency_score * 0.35, clamped [0, 1].
    """

    def __init__(self, maxlen=128):
        self._scores = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def score(self, tick, patch_preview_memory, consistency_verifier):
        preview = patch_preview_memory.latest()
        cons    = consistency_verifier.latest()
        if not preview or not cons:
            return None

        preview_strength = preview.get('preview_strength', 0.5)
        repeat_count     = preview.get('repeat_count', 1)
        cons_state       = cons.get('consistency_state', 'uncertain')
        cons_score       = cons.get('consistency_score', 0.5)
        after_sig        = preview.get('after_signature', '')

        if cons_state == 'consistent' and preview_strength > 0.70:
            integrity_state = 'safe_patch'
        elif cons_state == 'stale' and repeat_count > 1:
            integrity_state = 'redundant_patch'
        elif cons_state == 'drifted':
            integrity_state = 'unsafe_patch'
        else:
            integrity_state = 'uncertain'

        iscore = max(0.0, min(1.0, preview_strength * 0.65 + cons_score * 0.35))

        if integrity_state == 'safe_patch':
            summary = (
                f"Patch '{after_sig}' is safe to apply. "
                f"Artifact is consistent with active subgoal and preview strength is strong."
            )
        elif integrity_state == 'redundant_patch':
            summary = (
                f"Patch '{after_sig}' is redundant (repeat {repeat_count}). "
                f"Artifact is stalled; applying this patch would not advance the subgoal."
            )
        elif integrity_state == 'unsafe_patch':
            summary = (
                f"Patch '{after_sig}' flagged unsafe. "
                f"Artifact has drifted from the current workspace context."
            )
        else:
            summary = (
                f"Integrity undetermined for patch '{after_sig}'. "
                f"Insufficient alignment signal to classify edit safety."
            )

        record = {
            'tick':              int(tick),
            'integrity_state':   integrity_state,
            'integrity_score':   float(round(iscore, 4)),
            'integrity_summary': summary,
        }
        self._scores.append(record)
        return record

    def latest(self): return self._scores[-1] if self._scores else None
    def recent(self, n=10): buf = list(self._scores); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._scores)
    def to_dict(self): return {'maxlen': self._maxlen, 'scores': list(self._scores)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('scores', []): obj._scores.append(rec)
        return obj

