# DAY 24 PATCH EXECUTION PACK
# PatchExecutor + VersionDiffTracker + RollbackController
# Hofstadter 1979 (self-modifying symbolic loops);
# Dijkstra 1968 (structured program evolution);
# Parnas 1972 (information hiding, controlled state transitions).
#
# Rules:
#   - Waking-only: after integrity_scorer.score(), before report_bus.publish()
#   - Zero survival contamination: no selected_action / BG / WM / drive writes
#   - No real file mutation: symbolic state transitions only
#   - Bounded: deque(maxlen=128), fully serializable, leak-free
# ===========================================================================

class PatchExecutor:
    """
    Simulates applying a safe symbolic patch preview.
    First internal artifact state transition.

    Schema:
        tick               : int
        applied_signature  : str   -- always preview.after_signature
        execution_state    : str   -- 'applied' | 'skipped' | 'blocked' | 'tentative'
        execution_score    : float [0, 1]
        execution_summary  : str

    Execution mapping (integrity_state -> execution_state):
        safe_patch      -> applied
        redundant_patch -> skipped
        unsafe_patch    -> blocked
        uncertain       -> tentative

    Score = preview_strength * 0.70 + integrity_score * 0.30, clamped [0, 1].
    """

    _EXEC_MAP = {
        'safe_patch':      'applied',
        'redundant_patch': 'skipped',
        'unsafe_patch':    'blocked',
    }

    def __init__(self, maxlen=128):
        self._executions = deque(maxlen=maxlen)
        self._maxlen     = maxlen

    def execute(self, tick, patch_preview_memory, integrity_scorer, artifact_state_memory):
        preview   = patch_preview_memory.latest()
        integrity = integrity_scorer.latest()
        # artifact_state_memory available for future enrichment; not required
        if not preview or not integrity:
            return None

        integrity_state  = integrity.get('integrity_state', 'uncertain')
        integrity_score  = integrity.get('integrity_score', 0.5)
        preview_strength = preview.get('preview_strength', 0.5)
        applied_sig      = preview.get('after_signature', 'unknown->unknown')

        execution_state = self._EXEC_MAP.get(integrity_state, 'tentative')
        escore = max(0.0, min(1.0, preview_strength * 0.70 + integrity_score * 0.30))

        if execution_state == 'applied':
            summary = (
                f"Patch '{applied_sig}' symbolically applied. "
                f"Artifact advanced to new state with score {escore:.3f}."
            )
        elif execution_state == 'skipped':
            summary = (
                f"Patch '{applied_sig}' skipped: redundant operation detected. "
                f"No artifact state change produced."
            )
        elif execution_state == 'blocked':
            summary = (
                f"Patch '{applied_sig}' blocked: unsafe integrity state. "
                f"Artifact preserved at prior stable version."
            )
        else:
            summary = (
                f"Patch '{applied_sig}' applied tentatively under uncertain integrity. "
                f"Outcome requires verification."
            )

        record = {
            'tick':              int(tick),
            'applied_signature': applied_sig,
            'execution_state':   execution_state,
            'execution_score':   float(round(escore, 4)),
            'execution_summary': summary,
        }
        self._executions.append(record)
        return record

    def latest(self): return self._executions[-1] if self._executions else None
    def recent(self, n=10): buf = list(self._executions); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._executions)
    def to_dict(self): return {'maxlen': self._maxlen, 'executions': list(self._executions)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('executions', []): obj._executions.append(rec)
        return obj


class VersionDiffTracker:
    """
    Tracks symbolic pre/post artifact transitions (version trajectory memory).

    Schema:
        tick              : int
        from_version      : int   -- artifact.version_index at time of call
        to_signature      : str   -- executor.applied_signature
        diff_state        : str   -- 'advanced' | 'unchanged' | 'protected' | 'uncertain'
        diff_score        : float [0, 1]
        stagnation_count  : int   -- consecutive unchanged diffs (dedup counter)
        diff_summary      : str

    Diff mapping (execution_state -> diff_state):
        applied   -> advanced
        skipped   -> unchanged
        blocked   -> protected
        tentative -> uncertain

    Score = execution_score * 0.65 + state_stability * 0.35, clamped [0, 1].

    DEDUP LAW: consecutive 'unchanged' diffs -> update in place.
        diff_score      = old * 0.90 + new * 0.10 + 0.01
        stagnation_count += 1
        No duplicate record appended.
    """

    _DIFF_MAP = {
        'applied':   'advanced',
        'skipped':   'unchanged',
        'blocked':   'protected',
        'tentative': 'uncertain',
    }

    def __init__(self, maxlen=128):
        self._diffs  = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def track(self, tick, patch_executor, artifact_state_memory):
        executor = patch_executor.latest()
        artifact = artifact_state_memory.latest()
        if not executor or not artifact:
            return None

        exec_state  = executor.get('execution_state', 'tentative')
        exec_score  = executor.get('execution_score', 0.5)
        stability   = artifact.get('state_stability', 0.5)
        from_ver    = artifact.get('version_index', 1)
        to_sig      = executor.get('applied_signature', 'unknown')

        diff_state = self._DIFF_MAP.get(exec_state, 'uncertain')
        dscore     = max(0.0, min(1.0, exec_score * 0.65 + stability * 0.35))

        # DEDUP: consecutive unchanged diffs -> update in place
        if (diff_state == 'unchanged'
                and self._diffs
                and self._diffs[-1].get('diff_state') == 'unchanged'):
            last = self._diffs[-1]
            new_score      = min(1.0, last['diff_score'] * 0.90 + dscore * 0.10 + 0.01)
            new_stagnation = last['stagnation_count'] + 1
            updated = {
                'tick':              int(tick),
                'from_version':      from_ver,
                'to_signature':      to_sig,
                'diff_state':        'unchanged',
                'diff_score':        float(round(new_score, 4)),
                'stagnation_count':  new_stagnation,
                'diff_summary': (
                    f"Diff remains unchanged at stagnation count {new_stagnation}. "
                    f"Score consolidated to {new_score:.3f}."
                ),
            }
            self._diffs[-1] = updated
            return updated

        # New diff state (or first record): append fresh
        if diff_state == 'advanced':
            summary = (
                f"Version advanced from v{from_ver} to '{to_sig}'. "
                f"Trajectory progressing with score {dscore:.3f}."
            )
        elif diff_state == 'unchanged':
            summary = (
                f"Version unchanged at v{from_ver}. "
                f"Patch skipped; stagnation begins."
            )
        elif diff_state == 'protected':
            summary = (
                f"Version protected at v{from_ver}. "
                f"Blocked patch preserved artifact stability."
            )
        else:
            summary = (
                f"Version diff uncertain at v{from_ver} -> '{to_sig}'. "
                f"Tentative execution requires monitoring."
            )

        record = {
            'tick':             int(tick),
            'from_version':     from_ver,
            'to_signature':     to_sig,
            'diff_state':       diff_state,
            'diff_score':       float(round(dscore, 4)),
            'stagnation_count': 1 if diff_state == 'unchanged' else 0,
            'diff_summary':     summary,
        }
        self._diffs.append(record)
        return record

    def latest(self): return self._diffs[-1] if self._diffs else None
    def recent(self, n=10): buf = list(self._diffs); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._diffs)
    def to_dict(self): return {'maxlen': self._maxlen, 'diffs': list(self._diffs)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('diffs', []): obj._diffs.append(rec)
        return obj


class RollbackController:
    """
    Restores last stable symbolic version when patch evolution degrades.
    First symbolic recovery controller.

    Schema:
        tick                : int
        rollback_state      : str        -- 'rollback_to_last_stable' | 'hold_previous' |
                                            'commit_forward' | 'monitor'
        restored_signature  : str | None -- target signature for the rollback action
        rollback_score      : float [0, 1]
        rollback_summary    : str

    State rules (priority order):
        rollback_to_last_stable: diff_state == 'protected' AND integrity_state == 'unsafe_patch'
        hold_previous          : diff_state == 'protected' AND integrity_state != 'unsafe_patch'
        commit_forward         : diff_state == 'advanced'  AND integrity_state == 'safe_patch'
        monitor                : all other cases

    restored_signature:
        rollback_to_last_stable -> preview.before_signature
        hold_previous           -> preview.before_signature
        commit_forward          -> preview.after_signature
        monitor                 -> None

    Score = diff_score * 0.60 + integrity_score * 0.40, clamped [0, 1].
    """

    def __init__(self, maxlen=128):
        self._controls = deque(maxlen=maxlen)
        self._maxlen   = maxlen

    def control(self, tick, version_diff_tracker, integrity_scorer, patch_preview_memory):
        diff      = version_diff_tracker.latest()
        integrity = integrity_scorer.latest()
        preview   = patch_preview_memory.latest()
        if not diff or not integrity or not preview:
            return None

        diff_state      = diff.get('diff_state', 'uncertain')
        diff_score      = diff.get('diff_score', 0.5)
        integrity_state = integrity.get('integrity_state', 'uncertain')
        integrity_score = integrity.get('integrity_score', 0.5)
        before_sig      = preview.get('before_signature', '')
        after_sig       = preview.get('after_signature', '')

        if diff_state == 'protected' and integrity_state == 'unsafe_patch':
            rollback_state     = 'rollback_to_last_stable'
            restored_signature = before_sig
        elif diff_state == 'protected':
            rollback_state     = 'hold_previous'
            restored_signature = before_sig
        elif diff_state == 'advanced' and integrity_state == 'safe_patch':
            rollback_state     = 'commit_forward'
            restored_signature = after_sig
        else:
            rollback_state     = 'monitor'
            restored_signature = None

        rscore = max(0.0, min(1.0, diff_score * 0.60 + integrity_score * 0.40))

        if rollback_state == 'rollback_to_last_stable':
            summary = (
                f"Rollback triggered: restoring to '{restored_signature}'. "
                f"Blocked unsafe patch reversed to last stable artifact state."
            )
        elif rollback_state == 'hold_previous':
            summary = (
                f"Hold applied: retaining '{restored_signature}'. "
                f"Protected diff without unsafe flag; conservative hold enacted."
            )
        elif rollback_state == 'commit_forward':
            summary = (
                f"Commit confirmed: advancing to '{restored_signature}'. "
                f"Safe patch successfully integrated into artifact trajectory."
            )
        else:
            summary = (
                f"Monitor mode: no rollback action required at tick {tick}. "
                f"Patch evolution within acceptable bounds."
            )

        record = {
            'tick':               int(tick),
            'rollback_state':     rollback_state,
            'restored_signature': restored_signature,
            'rollback_score':     float(round(rscore, 4)),
            'rollback_summary':   summary,
        }
        self._controls.append(record)
        return record

    def latest(self): return self._controls[-1] if self._controls else None
    def recent(self, n=10): buf = list(self._controls); return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._controls)
    def to_dict(self): return {'maxlen': self._maxlen, 'controls': list(self._controls)}
    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('controls', []): obj._controls.append(rec)
        return obj

# ===========================================================================
# DAY 25: STRUCTURE-AWARE INTERNAL REASONING  --  PACK 1
# StructureMapBuilder + DependencyLinkMemory + SemanticRegionGuard
# Hofstadter 1985 (metamagical themas: reflective self-models);
# Parnas 1972 (information hiding, module interfaces);
# Dijkstra 1968 (structured program evolution);
# Brooks 1995 (software as living system); Gamma et al. 1994 (design patterns).
#
# Purpose:
#   Upgrade organism cognition from flat symbolic signatures to persistent
#   semantic territories.  The organism can now reason over:
#     - epoch banners (DAY X strata)
#     - subsystem clusters (HPA, homeostasis, cognition chain, patch evolution)
#     - class territories (Neuron, Synapse, HPAAxisSystem, ...)
#     - micro-regions (init blocks, scoring laws, serialization zones, citations)
#   and predict the blast radius of edits across dependency chains.
#
# Rules:
#   - Waking-only: after project_workspace.update(), before edit_intent_generator
#   - Zero survival contamination: no selected_action / BG / WM / drive writes
#   - Bounded: deque(maxlen=128) throughout
#   - Region identity persists unless semantic role changes or anchor overlap < 70%
#   - Protected biology zones: Neuron, Synapse, HomeostasisSystem, HPAAxisSystem,
#     CortisolSystem, AdenosineSystem
# ===========================================================================


