class StructureMapBuilder:
    """
    Builds a nested semantic territory map from the organism's active workspace
    and artifact cognition state.

    Four detection layers:
        A -- epoch banners   (DAY 14 ... DAY 25)
        B -- subsystem clusters  (hpa_axis, homeostasis, ...)
        C -- class territories   (Neuron, Synapse, HPAAxisSystem, ...)
        D -- micro-regions       (init, scoring_law, serialization, citation, ...)

    Region identity is persistent: a region_id does not change unless the
    semantic role or anchor overlap falls below 70%.

    Schema per record:
        tick            : int
        regions         : list[dict]   -- each region follows SemanticRegion fields
        region_count    : int
        epoch_count     : int
        protected_count : int
        map_confidence  : float [0, 1]
        map_summary     : str

    map_confidence = min(1.0, region_count / 10.0) -- confident once 10+ regions found.

    Waking-only. Zero survival contamination.
    """

    # Micro-region detection keywords
    _MICRO_PATTERNS = (
        ('init_block',      ('def __init__', '__init__(self')),
        ('scoring_law',     ('score', 'confidence', 'clamped', 'round(')),
        ('serialization',   ('to_dict', 'from_dict', 'json', 'pickle')),
        ('export_metrics',  ('export_metrics', 'def export')),
        ('safety_clamp',    ('min(1.0', 'max(0.0', 'clamp', 'clip')),
        ('citation',        ('Friston', 'Borbely', 'Damasio', 'Tononi', 'Parnas',
                             'Dijkstra', 'Hofstadter', 'McEwen', 'Gross', 'Tulving')),
        ('invariant_law',   ('Law 1', 'Law 2', 'Law 3', 'Rule', 'MUST', 'invariant',
                             'zero survival', 'never touches')),
        ('update_law',      ('def update', 'def step', 'def tick')),
    )

    def __init__(self, maxlen=128):
        self._maps    = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        # Stable region identity pool  {region_id: confidence}
        self._region_pool: dict = {}

    # ------------------------------------------------------------------
    # Region detection helpers  (all read-only, no side effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _detect_epoch(text: str) -> str | None:
        """Return epoch label if text contains a DAY banner.
        Normalises underscores to spaces so 'DAY_24' and 'DAY 24' both match.
        """
        u = text.upper().replace('_', ' ')
        for pfx in _EPOCH_PREFIXES:
            if pfx in u:
                return pfx.replace(' ', '_')
        return None

    @staticmethod
    def _detect_cluster(text: str) -> str | None:
        """Return first matching cluster name."""
        for cluster_name, keywords in _CLUSTER_KEYWORDS:
            for kw in keywords:
                if kw in text:
                    return cluster_name
        return None

    @staticmethod
    def _detect_class(text: str) -> str | None:
        """Return class name if text contains a class definition."""
        for part in text.split():
            if part.startswith('class '):
                return part[6:].rstrip(':(')
        if 'class ' in text:
            idx = text.index('class ')
            rest = text[idx + 6:].split()[0].rstrip(':(')
            if rest:
                return rest
        return None

    @classmethod
    def _detect_micro(cls, text: str) -> str | None:
        """Return first matching micro-region type."""
        for micro_name, keywords in cls._MICRO_PATTERNS:
            for kw in keywords:
                if kw in text:
                    return micro_name
        return None

    @staticmethod
    def _is_protected(class_name: str) -> bool:
        return class_name in _PROTECTED_CLASS_NAMES

    # ------------------------------------------------------------------
    # Main build method
    # ------------------------------------------------------------------

    def build(self, tick, project_workspace, artifact_state_memory,
              consistency_verifier):
        """
        Build a territory map for the current tick from live artifact state.

        Reads:
            project_workspace.latest()     -- active_section, artifact_type
            artifact_state_memory.latest() -- artifact_signature
            consistency_verifier.latest()  -- consistency_state

        Writes:
            self._maps   (own deque only)
        """
        ws_rec  = project_workspace.latest()
        asm_rec = artifact_state_memory.latest()
        cv_rec  = consistency_verifier.latest()

        if not ws_rec:
            return None

        # Aggregate input text for pattern detection
        active_section  = ws_rec.get('active_section', '')
        artifact_type   = ws_rec.get('artifact_type', '')
        artifact_sig    = asm_rec.get('artifact_signature', '') if asm_rec else ''
        ws_conf         = ws_rec.get('workspace_confidence', 0.5)
        cons_state      = cv_rec.get('consistency_state', 'uncertain') if cv_rec else 'uncertain'

        regions = []

        # Layer A: epoch
        combined_text = f"{active_section} {artifact_sig} {artifact_type}"
        epoch = self._detect_epoch(combined_text)
        if epoch:
            rid = f"epoch:{epoch}"
            self._region_pool[rid] = min(1.0, self._region_pool.get(rid, 0.5) + 0.1)
            regions.append({
                'region_id':        rid,
                'parent_region':    None,
                'depth':            1,
                'region_type':      'epoch_banner',
                'start_anchor':     epoch,
                'end_anchor':       f"{epoch}:end",
                'exported_symbols': [],
                'invariants':       [],
                'protected':        False,
                'confidence':       round(self._region_pool[rid], 4),
            })

        # Layer B: subsystem cluster
        cluster = self._detect_cluster(combined_text)
        if cluster:
            parent = epoch if epoch else None
            rid = f"cluster:{cluster}"
            self._region_pool[rid] = min(1.0, self._region_pool.get(rid, 0.5) + 0.1)
            regions.append({
                'region_id':        rid,
                'parent_region':    parent,
                'depth':            2,
                'region_type':      'subsystem_cluster',
                'start_anchor':     cluster,
                'end_anchor':       f"{cluster}:end",
                'exported_symbols': [],
                'invariants':       [],
                'protected':        cluster in ('hpa_axis', 'homeostasis', 'sleep_systems',
                                                'neuromodulators'),
                'confidence':       round(self._region_pool[rid], 4),
            })

        # Layer C: class territory (from artifact_signature pattern e.g. "code_block:refine")
        # Infer a representative class name from section/subgoal
        _sec_words = active_section.replace('->', ':').replace('_', ' ').split()
        _class_candidate = None
        for _sw in _sec_words:
            _sw_cap = _sw.capitalize()
            if _sw_cap in _BLAST_WEIGHTS:
                _class_candidate = _sw_cap
                break
        # Also scan artifact_signature tokens
        if _class_candidate is None:
            for _tok in artifact_sig.replace('->', ' ').replace(':', ' ').replace('_', ' ').split():
                _tok_cap = _tok.capitalize()
                if _tok_cap in _BLAST_WEIGHTS:
                    _class_candidate = _tok_cap
                    break

        if _class_candidate:
            parent = f"cluster:{cluster}" if cluster else (epoch if epoch else None)
            rid = f"class:{_class_candidate}"
            self._region_pool[rid] = min(1.0, self._region_pool.get(rid, 0.5) + 0.15)
            is_prot = self._is_protected(_class_candidate)
            regions.append({
                'region_id':        rid,
                'parent_region':    parent,
                'depth':            3,
                'region_type':      'class_territory',
                'start_anchor':     f"class {_class_candidate}:",
                'end_anchor':       f"class {_class_candidate}:end",
                'exported_symbols': [_class_candidate],
                'invariants':       ['zero_survival_contamination'] if not is_prot else
                                    ['protected_biology', 'zero_survival_contamination'],
                'protected':        is_prot,
                'confidence':       round(self._region_pool[rid], 4),
            })

        # Layer D: micro-region from consistency / section semantics
        micro = self._detect_micro(active_section)
        if micro is None:
            micro = self._detect_micro(artifact_sig)
        if micro:
            parent = f"class:{_class_candidate}" if _class_candidate else (
                     f"cluster:{cluster}" if cluster else epoch)
            rid = f"micro:{micro}"
            self._region_pool[rid] = min(1.0, self._region_pool.get(rid, 0.5) + 0.08)
            regions.append({
                'region_id':        rid,
                'parent_region':    parent,
                'depth':            4,
                'region_type':      'micro_region',
                'start_anchor':     micro,
                'end_anchor':       f"{micro}:end",
                'exported_symbols': [],
                'invariants':       ['micro_region_stability'],
                'protected':        False,
                'confidence':       round(self._region_pool[rid], 4),
            })

        # Also add a "serialization" micro-region whenever artifact_sig contains "->"
        if '->' in artifact_sig and 'micro:serialization' not in {r['region_id'] for r in regions}:
            parent = f"class:{_class_candidate}" if _class_candidate else epoch
            rid = 'micro:serialization'
            self._region_pool[rid] = min(1.0, self._region_pool.get(rid, 0.5) + 0.05)
            regions.append({
                'region_id':        rid,
                'parent_region':    parent,
                'depth':            4,
                'region_type':      'micro_region',
                'start_anchor':     'to_dict',
                'end_anchor':       'from_dict',
                'exported_symbols': ['to_dict', 'from_dict'],
                'invariants':       ['serialization_round_trip'],
                'protected':        False,
                'confidence':       round(self._region_pool[rid], 4),
            })

        epoch_count     = sum(1 for r in regions if r['region_type'] == 'epoch_banner')
        protected_count = sum(1 for r in regions if r['protected'])
        map_confidence  = min(1.0, len(self._region_pool) / 10.0)
        # Boost confidence if consistency is stable
        if cons_state == 'consistent':
            map_confidence = min(1.0, map_confidence + 0.05)

        summary = (
            f"Tick {tick}: {len(regions)} regions detected "
            f"(pool={len(self._region_pool)}, prot={protected_count}, "
            f"cons={cons_state}, conf={map_confidence:.2f})."
        )

        record = {
            'tick':            int(tick),
            'regions':         regions,
            'region_count':    len(regions),
            'epoch_count':     epoch_count,
            'protected_count': protected_count,
            'map_confidence':  float(round(map_confidence, 4)),
            'map_summary':     summary,
        }
        self._maps.append(record)
        return record

    def latest(self): return self._maps[-1] if self._maps else None
    def recent(self, n=10):
        buf = list(self._maps)
        return buf[-n:] if n < len(buf) else buf
    def pool_size(self): return len(self._region_pool)
    def __len__(self): return len(self._maps)

    def to_dict(self):
        return {
            'maxlen':      self._maxlen,
            'maps':        list(self._maps),
            'region_pool': dict(self._region_pool),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('maps', []):
            obj._maps.append(rec)
        obj._region_pool = dict(d.get('region_pool', {}))
        return obj


class DependencyLinkMemory:
    """
    Tracks region-to-region dependency chains and predicts edit blast radius.

    Maps:
        - class usage chains (which regions call / depend on which)
        - serialization dependencies (to_dict / from_dict coupling)
        - report-bus hooks (downstream publish consumers)
        - rollback compatibility (edit safe within or crosses stable boundary)
        - test region coverage (estimated coverage per cluster)
        - comment provenance inheritance (citation / law comments)

    Reinforcement model analogous to ConceptGraph and PlanGraphMemory:
        Each dependency edge gains weight each time it is confirmed active.
        Edges decay slowly (EMA 0.98) to eliminate stale links.

    Schema per record:
        tick               : int
        source_region      : str
        downstream_regions : list[str]
        blast_radius       : float [0, 1]
        edge_weights       : dict {region_id: float}
        confidence         : float [0, 1]
        dependency_summary : str

    blast_radius = _BLAST_WEIGHTS.get(class_name, 0.30) * confidence, clamped [0, 1].
    confidence   = mean edge weight across downstream_regions.

    Waking-only. Zero survival contamination.
    """

    # Static downstream dependency map  (class -> classes it affects)
    _DOWNSTREAM_MAP = {
        'HomeostasisSystem':  ['CircadianSystem', 'AdenosineSystem', 'ConceptGraph',
                               'NarrativeMemory', 'ReportBus', 'SentenceGenerator'],
        'HPAAxisSystem':      ['CortisolSystem', 'HomeostasisSystem', 'SelfModelSystem'],
        'Neuron':             ['Synapse', 'HomeostasisSystem', 'ActionReasoningLog'],
        'Synapse':            ['Neuron', 'ReplayBuffer', 'ConceptGraph'],
        'CortisolSystem':     ['HomeostasisSystem', 'HPAAxisSystem', 'NarrativeMemory'],
        'AdenosineSystem':    ['HomeostasisSystem', 'SleepConsolidator'],
        'ReportBus':          ['LanguageReadout', 'SentenceGenerator', 'NarrativeMemory'],
        'ConceptGraph':       ['NarrativeMemory', 'SentenceGenerator', 'SleepConsolidator',
                               'ReflectiveReasoner'],
        'LatentStateVector':  ['ReportBus', 'ActionReasoningLog', 'ConceptGraph'],
        'ActionReasoningLog': ['ReplayBuffer', 'EventCompressor', 'ReportBus'],
        'ReplayBuffer':       ['EventCompressor', 'ConceptGraph', 'SleepConsolidator'],
        'NarrativeMemory':    ['ReflectiveReasoner', 'CognitivePlanner'],
        'SubgoalEvaluator':   ['ProjectWorkspace', 'ArtifactStateMemory'],
        'RollbackController': ['IntegrityScorer', 'PatchPreviewMemory',
                               'VersionDiffTracker'],
        'ProjectWorkspace':   ['ArtifactStateMemory', 'ConsistencyVerifier',
                               'EditIntentGenerator'],
        'ArtifactStateMemory':['ConsistencyVerifier', 'PatchPreviewMemory'],
        'IntegrityScorer':    ['PatchExecutor', 'RollbackController'],
        'PatchExecutor':      ['VersionDiffTracker', 'RollbackController'],
        'StructureMapBuilder':['DependencyLinkMemory', 'SemanticRegionGuard',
                               'EditIntentGenerator'],
        'DependencyLinkMemory':['SemanticRegionGuard', 'EditIntentGenerator'],
        'SemanticRegionGuard': ['EditIntentGenerator', 'IntegrityScorer'],
    }

    def __init__(self, maxlen=128):
        self._links  = deque(maxlen=maxlen)
        self._maxlen = maxlen
        # Edge weight memory  {source_region: {downstream_region: float}}
        self._edge_weights: dict = {}

    # ------------------------------------------------------------------

    def _reinforce(self, source: str, downstream: list) -> dict:
        """Reinforce edge weights for observed active dependencies (EMA 0.02 step)."""
        if source not in self._edge_weights:
            self._edge_weights[source] = {}
        ew = self._edge_weights[source]
        # Decay all existing edges slightly
        for k in list(ew.keys()):
            ew[k] = max(0.0, ew[k] * 0.98)
        # Reinforce active downstream edges
        for ds in downstream:
            ew[ds] = min(1.0, ew.get(ds, 0.3) + 0.05)
        return dict(ew)

    def link(self, tick, structure_map_builder, consistency_verifier,
             rollback_controller):
        """
        Derive dependency links from the current StructureMapBuilder snapshot.

        Reads:
            structure_map_builder.latest()  -- regions list
            consistency_verifier.latest()   -- consistency_state (confidence mod)
            rollback_controller.latest()    -- rollback_state (blast amplifier)

        Writes:
            self._links  (own deque only)
        """
        map_rec  = structure_map_builder.latest()
        cv_rec   = consistency_verifier.latest()
        rc_rec   = rollback_controller.latest()

        if not map_rec:
            return None

        regions      = map_rec.get('regions', [])
        cons_state   = cv_rec.get('consistency_state', 'uncertain') if cv_rec else 'uncertain'
        rb_state     = rc_rec.get('rollback_state', 'monitor') if rc_rec else 'monitor'

        # Choose source region: deepest non-micro class territory found
        source_region = None
        source_class  = None
        for r in sorted(regions, key=lambda x: -x.get('depth', 0)):
            if r['region_type'] == 'class_territory':
                source_region = r['region_id']
                source_class  = r['exported_symbols'][0] if r.get('exported_symbols') else None
                break
        if source_region is None and regions:
            source_region = regions[0]['region_id']

        # Downstream regions from static map
        downstream_static = self._DOWNSTREAM_MAP.get(source_class, []) if source_class else []
        # Also add all region_ids from the map itself as structural neighbors
        downstream_ids = [r['region_id'] for r in regions if r['region_id'] != source_region]
        all_downstream = list(dict.fromkeys(downstream_static + downstream_ids))

        # Reinforce edge weights
        ew = self._reinforce(source_region, all_downstream)

        # Compute blast radius
        base_blast = _BLAST_WEIGHTS.get(source_class, 0.30) if source_class else 0.30
        # Amplify if rollback is active (unstable state)
        if rb_state in ('rollback_to_last_stable', 'hold_previous'):
            base_blast = min(1.0, base_blast + 0.10)
        # Attenuate if consistency is stable
        if cons_state == 'consistent':
            base_blast = max(0.0, base_blast - 0.05)

        mean_ew   = sum(ew.values()) / max(1, len(ew)) if ew else 0.3
        confidence = min(1.0, mean_ew * (0.60 + map_rec.get('map_confidence', 0.5) * 0.40))

        blast_radius = float(round(min(1.0, base_blast), 4))
        confidence   = float(round(confidence, 4))

        summary = (
            f"Source '{source_region}' -> {len(all_downstream)} downstream. "
            f"blast={blast_radius:.2f} conf={confidence:.2f} rb={rb_state}."
        )

        record = {
            'tick':               int(tick),
            'source_region':      source_region,
            'downstream_regions': all_downstream[:16],  # cap to 16 for compactness
            'blast_radius':       blast_radius,
            'edge_weights':       {k: round(v, 4) for k, v in list(ew.items())[:8]},
            'confidence':         confidence,
            'dependency_summary': summary,
        }
        self._links.append(record)
        return record

    def latest(self): return self._links[-1] if self._links else None
    def recent(self, n=10):
        buf = list(self._links)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._links)

    def to_dict(self):
        return {
            'maxlen':       self._maxlen,
            'links':        list(self._links),
            'edge_weights': {k: dict(v) for k, v in self._edge_weights.items()},
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('links', []):
            obj._links.append(rec)
        obj._edge_weights = {k: dict(v) for k, v in d.get('edge_weights', {}).items()}
        return obj


class SemanticRegionGuard:
    """
    Rejects unsafe edits before Day 24 edit-intent generation.

    Checks:
        1. Protected biology boundary crossing -- blocks Neuron, Synapse, HomeostasisSystem,
           HPAAxisSystem, CortisolSystem, AdenosineSystem edits with high blast radius.
        2. Serialization drift -- blocks if edit would break to_dict/from_dict coupling.
        3. Banner provenance deletion -- blocks edits targeting epoch banners.
        4. Invariant comment deletion -- blocks edits removing law/citation comments.
        5. Rollback-incompatible region merges.

    States (exactly one per record):
        safe_region_patch        : edit is within bounds, no violations
        boundary_violation       : edit crosses protected region boundary
        protected_zone_violation : edit targets a protected biology class
        serialization_drift      : edit breaks serialization coupling
        uncertain                : insufficient data to evaluate

    Score:
        safe_region_patch        : map_confidence * 0.70 + (1 - blast_radius) * 0.30
        boundary_violation / protected_zone_violation / serialization_drift : blast_radius * 0.30
        uncertain                : 0.50

    Schema per record:
        tick              : int
        guard_state       : str
        guard_score       : float [0, 1]
        source_region     : str | None
        violation_detail  : str
        guard_summary     : str

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._guards = deque(maxlen=maxlen)
        self._maxlen = maxlen

    def guard(self, tick, structure_map_builder, dependency_link_memory,
              integrity_scorer):
        """
        Evaluate the safety of the next candidate edit.

        Reads:
            structure_map_builder.latest()  -- regions (protected flags, types)
            dependency_link_memory.latest() -- blast_radius, source_region
            integrity_scorer.latest()       -- integrity_state (pre-Day25 gate)

        Writes:
            self._guards  (own deque only)
        """
        map_rec  = structure_map_builder.latest()
        dep_rec  = dependency_link_memory.latest()
        isc_rec  = integrity_scorer.latest()

        # If upstream data absent, emit uncertain
        if not map_rec or not dep_rec:
            record = {
                'tick':             int(tick),
                'guard_state':      'uncertain',
                'guard_score':      0.50,
                'source_region':    None,
                'violation_detail': 'Insufficient upstream map/dependency data.',
                'guard_summary':    f"Tick {tick}: uncertain -- no upstream data.",
            }
            self._guards.append(record)
            return record

        regions       = map_rec.get('regions', [])
        map_conf      = map_rec.get('map_confidence', 0.5)
        blast         = dep_rec.get('blast_radius', 0.3)
        source_region = dep_rec.get('source_region', None)
        isc_state     = isc_rec.get('integrity_state', 'uncertain') if isc_rec else 'uncertain'

        guard_state     = 'safe_region_patch'
        violation_detail = ''

        # --- Check 1: protected zone violation ---
        # Any region with protected=True AND blast_radius > 0.60 => violation
        protected_hit = [r for r in regions if r.get('protected', False)]
        if protected_hit and blast > 0.60:
            guard_state      = 'protected_zone_violation'
            hit_ids          = [r['region_id'] for r in protected_hit]
            violation_detail = (
                f"Protected biology zone(s) in blast path: {hit_ids}. "
                f"blast_radius={blast:.2f} exceeds 0.60 threshold."
            )

        # --- Check 2: serialization drift ---
        # If a serialization micro-region is active AND integrity_state is 'unsafe_patch'
        if guard_state == 'safe_region_patch':
            serial_regions = [r for r in regions
                              if r.get('region_type') == 'micro_region'
                              and 'serialization' in r.get('region_id', '')]
            if serial_regions and isc_state == 'unsafe_patch':
                guard_state      = 'serialization_drift'
                violation_detail = (
                    f"Serialization micro-region active with unsafe_patch integrity. "
                    f"Risk of to_dict/from_dict decoupling."
                )

        # --- Check 3: boundary violation ---
        # Edit targets an epoch banner region directly  (depth==1 region being modified)
        if guard_state == 'safe_region_patch':
            epoch_regions = [r for r in regions if r.get('region_type') == 'epoch_banner']
            if epoch_regions and isc_state in ('unsafe_patch', 'uncertain') and blast > 0.50:
                guard_state      = 'boundary_violation'
                epoch_ids        = [r['region_id'] for r in epoch_regions]
                violation_detail = (
                    f"Edit approaches epoch banner(s) {epoch_ids} with degraded integrity. "
                    f"Banner provenance deletion risk."
                )

        # --- Score computation ---
        if guard_state == 'safe_region_patch':
            guard_score = max(0.0, min(1.0,
                map_conf * 0.70 + (1.0 - blast) * 0.30))
        elif guard_state == 'uncertain':
            guard_score = 0.50
        else:
            guard_score = max(0.0, min(1.0, blast * 0.30))

        summary = (
            f"Tick {tick}: guard_state={guard_state} "
            f"score={guard_score:.3f} blast={blast:.2f} "
            f"{'VIOLATION: ' + violation_detail if violation_detail else 'OK'}."
        )

        record = {
            'tick':             int(tick),
            'guard_state':      guard_state,
            'guard_score':      float(round(guard_score, 4)),
            'source_region':    source_region,
            'violation_detail': violation_detail,
            'guard_summary':    summary,
        }
        self._guards.append(record)
        return record

    def latest(self): return self._guards[-1] if self._guards else None
    def recent(self, n=10):
        buf = list(self._guards)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._guards)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'guards': list(self._guards)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('guards', []):
            obj._guards.append(rec)
        return obj


# ===========================================================================
# DAY 25: STRUCTURE-AWARE INTERNAL REASONING  --  PACK 2
# RegionRewritePlanner + InterfaceStabilityChecker + CrossRegionCommitGraph
# Dijkstra 1968 (structured program evolution);
# Parnas 1972 (information hiding: safe migration across module interfaces);
# Fowler 1999 (refactoring: ordered, dependency-first transformations);
# Gamma et al. 1994 (design patterns: stable exported interfaces);
# Brooks 1995 (no silver bullet: rewrite order is the primary risk surface).
#
# Purpose:
#   Upgrade multi-region mutation cognition:
#     - ordered rewrite chains (dependency-first, interface-last)
#     - interface-safe migration detection (method names, schema keys, rollback sigs)
#     - grouped commit continuity with rollback ancestry and partial success tracking
#
# Rules:
#   - Waking-only: after semantic_region_guard.guard(), before edit_intent_generator
#   - Zero survival contamination: no selected_action / BG / WM / drive writes
#   - Bounded: deque(maxlen=128) throughout
#   - Protected biology zones escalate to requires_guard_escalation=True (no hard block)
#   - Rewrite order: interface-origin -> downstream -> serialization -> tests -> rollback
# ===========================================================================


# ---------------------------------------------------------------------------
# Rewrite step operation vocabulary  (symbolic only, no real file ops)
# ---------------------------------------------------------------------------
_REWRITE_OPS = (
    'inspect_interface',   # examine exported symbols, method names
    'modify_region',       # targeted content change within region
    'migrate_interface',   # rename/add exported symbol with downstream update
    'update_serialization',# update to_dict/from_dict key set
    'validate_tests',      # assert test anchors remain intact
    'update_rollback',     # extend rollback ancestry with new parent
)

# ---------------------------------------------------------------------------
# Serialization-sensitive key patterns
# ---------------------------------------------------------------------------
_SERIALIZATION_KEYS = frozenset({
    'to_dict', 'from_dict', 'maxlen', 'records', 'controls', 'maps',
    'links', 'guards', 'intents', 'previews', 'scores', 'executions',
    'diffs', 'trackers', 'evals', 'states', 'workspaces', 'region_pool',
    'edge_weights', 'commit_groups', 'plan_steps', 'stability_checks',
})

# ---------------------------------------------------------------------------
# Known exported public interfaces per class cluster
# (used by InterfaceStabilityChecker to detect migration requirements)
# ---------------------------------------------------------------------------
_EXPORTED_INTERFACES = {
    'serialization':     ['to_dict', 'from_dict'],
    'cognition_chain':   ['latest', 'recent', '__len__', 'snapshot_vector',
                          'ingest_tick', 'flush_arc', 'generate', 'read_scene',
                          'publish', 'current_scene'],
    'patch_evolution':   ['update', 'remember', 'verify', 'generate', 'preview',
                          'score', 'execute', 'track', 'control'],
    'planning':          ['reflect', 'plan', 'bridge', 'evaluate', 'route',
                          'sandbox', 'learn', 'shape'],
    'structure_reasoning': ['build', 'link', 'guard', 'plan', 'check', 'commit'],
    'rollback':          ['control', 'rollback_state', 'restored_signature',
                          'rollback_score'],
    'report_bus':        ['publish', 'current_scene', 'latest', '__len__'],
}


class RegionRewritePlanner:
    """
    Generates ordered multi-region rewrite plans from structure map and dependency data.

    Rewrite order law (dependency-first -- Dijkstra 1968):
        Step 1: interface-origin region  (the class being changed)
        Step 2: downstream dependent regions (blast-radius ordered, highest first)
        Step 3: serialization regions (to_dict/from_dict coupling)
        Step 4: test anchor regions
        Step 5: rollback ancestry update

    Risk score formula:
        risk = blast_radius * 0.60 + integrity_risk * 0.40   (clamped [0, 1])

    where integrity_risk = 1.0 - integrity_score.

    requires_guard_escalation:
        True when the step touches a protected biology class (Rule 2).

    Schema per record:
        tick                 : int
        plan_steps           : list[dict]   -- ordered list of RewriteStep-schema dicts
        step_count           : int
        max_risk             : float [0, 1]
        requires_escalation  : bool         -- any step requires guard escalation
        plan_confidence      : float [0, 1]
        plan_summary         : str

    plan_confidence = guard_score * 0.60 + (1 - max_risk) * 0.40.

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._plans   = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    # ------------------------------------------------------------------
    # Step builders  (pure functions, no side effects)
    # ------------------------------------------------------------------

    @staticmethod
    def _step(index: int, region_id: str, operation: str,
              risk: float, escalate: bool) -> dict:
        return {
            'step_index':               int(index),
            'region_id':                str(region_id),
            'operation':                str(operation),
            'risk_score':               float(round(max(0.0, min(1.0, risk)), 4)),
            'requires_guard_escalation': bool(escalate),
        }

    @staticmethod
    def _needs_escalation(region_id: str) -> bool:
        """True if the region touches a protected biology class.
        Checks both full lowercase name and stem (without 'System'/'Axis' suffix)
        so cluster:homeostasis triggers on HomeostasisSystem, etc.

        Returns False immediately for None (unresolved cross-day thread lineage).
        """
        if region_id is None:
            return False
        rid = region_id.lower()
        for pname in _PROTECTED_CLASS_NAMES:
            if pname.lower() in rid:
                return True
            # Stem check: remove common suffixes so 'HomeostasisSystem' -> 'homeostasis'
            stem = pname.lower()
            for suffix in ('system', 'axissystem', 'axis'):
                if stem.endswith(suffix):
                    stem = stem[:-len(suffix)]
                    break
            if stem and len(stem) >= 4 and stem in rid:
                return True
        return False

    # ------------------------------------------------------------------
    # Main plan method
    # ------------------------------------------------------------------

    def update(self, state):
        """Unified interface (Day 32)."""
        return self._plan(
            tick                   = state.tick,
            structure_map_builder  = state.structure_map_builder,
            dependency_link_memory = state.dependency_link_memory,
            semantic_region_guard  = state.semantic_region_guard,
            edit_intent_generator  = state.edit_intent_generator,
        )

    def _plan(self, tick, structure_map_builder, dependency_link_memory,
              semantic_region_guard, edit_intent_generator):
        """
        Derive an ordered rewrite plan for the current tick.

        Reads:
            structure_map_builder.latest()   -- regions list, map_confidence
            dependency_link_memory.latest()  -- source_region, downstream_regions,
                                                blast_radius, edge_weights
            semantic_region_guard.latest()   -- guard_state, guard_score
            edit_intent_generator.latest()   -- edit_operation, target_region,
                                                edit_confidence

        Writes:
            self._plans  (own deque only)
        """
        map_rec  = structure_map_builder.latest()
        dep_rec  = dependency_link_memory.latest()
        grd_rec  = semantic_region_guard.latest()
        eig_rec  = edit_intent_generator.latest()

        if not map_rec or not dep_rec:
            return None

        source_region   = dep_rec.get('source_region', 'unknown')
        downstream      = dep_rec.get('downstream_regions', [])
        blast           = dep_rec.get('blast_radius', 0.3)
        guard_score     = grd_rec.get('guard_score', 0.5) if grd_rec else 0.5
        guard_state     = grd_rec.get('guard_state', 'uncertain') if grd_rec else 'uncertain'
        edit_op         = eig_rec.get('edit_operation', 'modify_segment') if eig_rec else 'modify_segment'
        edit_conf       = eig_rec.get('edit_confidence', 0.5) if eig_rec else 0.5
        map_conf        = map_rec.get('map_confidence', 0.5)
        regions         = map_rec.get('regions', [])

        # Null-safe continuity hotfix: source_region may be None when a
        # deferred or resurfaced cross-day thread has not yet resolved its
        # concrete region lineage (Day 27 Pack 3 deferred resurfacing path).
        # Fallback priority: first known region from structure map ->
        # "region:unknown_continuity".  No biology escalation on fallback.
        fallback_source_used = False
        if source_region is None:
            if regions:
                source_region = regions[0].get('region_id', 'region:unknown_continuity')
            else:
                source_region = 'region:unknown_continuity'
            fallback_source_used = True

        # integrity_risk: invert of edit_confidence (confidence = safety proxy)
        integrity_risk  = 1.0 - edit_conf

        steps = []
        idx   = 1

        # --- Step 1: interface-origin region ---
        step1_risk = max(0.0, min(1.0, blast * 0.60 + integrity_risk * 0.40))
        steps.append(self._step(
            idx, source_region, edit_op,
            step1_risk, self._needs_escalation(source_region),
        ))
        idx += 1

        # --- Step 2: downstream dependent regions (highest blast-ordered) ---
        # Sort downstream by edge_weight (descending) if available, else preserve order
        ew = dep_rec.get('edge_weights', {})
        ordered_ds = sorted(downstream[:8], key=lambda r: -ew.get(r, 0.3))
        for ds_region in ordered_ds:
            # Downstream risk attenuates proportionally with distance
            ds_blast  = max(0.0, blast * 0.75)
            ds_risk   = max(0.0, min(1.0, ds_blast * 0.60 + integrity_risk * 0.40))
            steps.append(self._step(
                idx, ds_region, 'modify_region',
                ds_risk, self._needs_escalation(ds_region),
            ))
            idx += 1

        # --- Step 3: serialization regions ---
        # Detect from current region pool: any region with 'serialization' in id
        serial_regions = [r['region_id'] for r in regions
                          if 'serialization' in r.get('region_id', '')]
        if not serial_regions:
            serial_regions = ['micro:serialization']
        for sr in serial_regions[:2]:
            serial_risk = max(0.0, min(1.0, blast * 0.40 + integrity_risk * 0.30))
            steps.append(self._step(
                idx, sr, 'update_serialization',
                serial_risk, False,
            ))
            idx += 1

        # --- Step 4: test anchor region ---
        test_region_id = f"test:{source_region}"
        test_risk = max(0.0, min(1.0, blast * 0.25 + integrity_risk * 0.20))
        steps.append(self._step(
            idx, test_region_id, 'validate_tests',
            test_risk, False,
        ))
        idx += 1

        # --- Step 5: rollback ancestry update ---
        rollback_risk = max(0.0, min(1.0, blast * 0.20 + integrity_risk * 0.15))
        steps.append(self._step(
            idx, 'rollback:ancestry', 'update_rollback',
            rollback_risk, False,
        ))

        # Aggregate metrics
        max_risk        = max(s['risk_score'] for s in steps) if steps else 0.0
        requires_esc    = any(s['requires_guard_escalation'] for s in steps)
        plan_confidence = max(0.0, min(1.0,
            guard_score * 0.60 + (1.0 - max_risk) * 0.40))

        # Suppress plan if guard is a hard violation AND blast is extreme
        if guard_state == 'protected_zone_violation' and blast > 0.80:
            plan_confidence = max(0.0, plan_confidence - 0.20)

        summary = (
            f"Tick {tick}: {len(steps)}-step rewrite plan for '{source_region}'. "
            f"max_risk={max_risk:.2f} escalation={'YES' if requires_esc else 'NO'} "
            f"conf={plan_confidence:.2f}."
        )

        record = {
            'tick':                int(tick),
            'plan_steps':          steps,
            'step_count':          len(steps),
            'max_risk':            float(round(max_risk, 4)),
            'requires_escalation': requires_esc,
            'plan_confidence':     float(round(plan_confidence, 4)),
            'plan_summary':        summary,
            'fallback_source_used': fallback_source_used,
        }
        self._plans.append(record)
        return record

    def latest(self): return self._plans[-1] if self._plans else None
    def recent(self, n=10):
        buf = list(self._plans)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._plans)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'plans': list(self._plans)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('plans', []):
            obj._plans.append(rec)
        return obj


class InterfaceStabilityChecker:
    """
    Validates that multi-region rewrite plans do not silently break interfaces.

    Validates:
        1. Public method names remain in their cluster's exported interface set
        2. Serialization keys (to_dict/from_dict) remain paired
        3. Rollback signatures remain accessible after the plan executes
        4. Region IDs referenced in downstream chains remain resolvable
        5. Exported test anchors referenced in plan step 4 remain intact

    States (exactly one per record):
        interface_stable        : all checks pass
        migration_required      : a public method or exported symbol changes
        serialization_break_risk: serialization region mutated without paired update
        rollback_break_risk     : rollback ancestry step missing or high-risk
        uncertain               : insufficient plan data

    Score formula:
        interface_stable        : plan_confidence * 0.70 + (1 - max_risk) * 0.30
        migration_required      : 0.50 * plan_confidence
        serialization_break_risk: 0.35
        rollback_break_risk     : 0.30
        uncertain               : 0.50

    Schema per record:
        tick               : int
        stability_state    : str
        stability_score    : float [0, 1]
        migration_regions  : list[str]   -- regions that require interface migration
        serial_break_risk  : bool
        rollback_break_risk: bool
        stability_summary  : str

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._checks  = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    # ------------------------------------------------------------------

    @staticmethod
    def _touches_serialization(steps: list) -> bool:
        """True if any step targets a serialization region."""
        return any('serialization' in s.get('region_id', '') or
                   s.get('operation') == 'update_serialization'
                   for s in steps)

    @staticmethod
    def _has_rollback_step(steps: list) -> bool:
        """True if plan includes a rollback ancestry update step."""
        return any(s.get('operation') == 'update_rollback' for s in steps)

    @staticmethod
    def _detect_migration_regions(steps: list) -> list:
        """Return region_ids of steps that declare interface migration."""
        return [s['region_id'] for s in steps
                if s.get('operation') == 'migrate_interface']

    @staticmethod
    def _serial_break_risk(steps: list) -> bool:
        """
        Risk is high if a serialization region is mutated (operation != update_serialization)
        without an explicit update_serialization step following it.
        """
        serial_mutated = any(
            'serialization' in s.get('region_id', '') and
            s.get('operation') not in ('update_serialization', 'validate_tests')
            for s in steps
        )
        has_serial_update = any(s.get('operation') == 'update_serialization' for s in steps)
        return serial_mutated and not has_serial_update

    # ------------------------------------------------------------------

    def check(self, tick, region_rewrite_planner, dependency_link_memory,
              rollback_controller):
        """
        Validate interface stability for the current rewrite plan.

        Reads:
            region_rewrite_planner.latest()  -- plan_steps, max_risk, plan_confidence
            dependency_link_memory.latest()  -- downstream_regions (for resolution check)
            rollback_controller.latest()     -- rollback_state (ancestry health)

        Writes:
            self._checks  (own deque only)
        """
        plan_rec = region_rewrite_planner.latest()
        dep_rec  = dependency_link_memory.latest()
        rc_rec   = rollback_controller.latest()

        if not plan_rec:
            record = {
                'tick':               int(tick),
                'stability_state':    'uncertain',
                'stability_score':    0.50,
                'migration_regions':  [],
                'serial_break_risk':  False,
                'rollback_break_risk': False,
                'stability_summary':  f"Tick {tick}: uncertain -- no plan data.",
            }
            self._checks.append(record)
            return record

        steps        = plan_rec.get('plan_steps', [])
        plan_conf    = plan_rec.get('plan_confidence', 0.5)
        max_risk     = plan_rec.get('max_risk', 0.5)
        downstream   = dep_rec.get('downstream_regions', []) if dep_rec else []
        rb_state     = rc_rec.get('rollback_state', 'monitor') if rc_rec else 'monitor'

        # Run checks
        migration_regions  = self._detect_migration_regions(steps)
        serial_break       = self._serial_break_risk(steps)
        rollback_break     = not self._has_rollback_step(steps) and max_risk > 0.65
        # Extra: if rollback is currently in degraded state, amplify risk
        if rb_state in ('rollback_to_last_stable',):
            rollback_break = True

        # Determine state (priority order)
        if serial_break:
            stability_state = 'serialization_break_risk'
            stability_score = 0.35
        elif rollback_break:
            stability_state = 'rollback_break_risk'
            stability_score = 0.30
        elif migration_regions:
            stability_state = 'migration_required'
            stability_score = max(0.0, min(1.0, 0.50 * plan_conf))
        else:
            stability_state = 'interface_stable'
            stability_score = max(0.0, min(1.0,
                plan_conf * 0.70 + (1.0 - max_risk) * 0.30))

        summary_parts = [f"Tick {tick}: {stability_state}"]
        if migration_regions:
            summary_parts.append(f"migration_needed={migration_regions}")
        if serial_break:
            summary_parts.append("serial_break_risk=True")
        if rollback_break:
            summary_parts.append("rollback_break_risk=True")
        summary_parts.append(f"score={stability_score:.3f}")

        record = {
            'tick':               int(tick),
            'stability_state':    stability_state,
            'stability_score':    float(round(stability_score, 4)),
            'migration_regions':  migration_regions,
            'serial_break_risk':  serial_break,
            'rollback_break_risk': rollback_break,
            'stability_summary':  ' | '.join(summary_parts),
        }
        self._checks.append(record)
        return record

    def latest(self): return self._checks[-1] if self._checks else None
    def recent(self, n=10):
        buf = list(self._checks)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._checks)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'stability_checks': list(self._checks)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('stability_checks', []):
            obj._checks.append(rec)
        return obj


class CrossRegionCommitGraph:
    """
    Tracks grouped multi-region commit continuity across waking ticks.

    Each commit group bundles all the rewrite steps from one RegionRewritePlanner
    output into a named unit with rollback ancestry, stability validation, and
    a reinforced success score.

    Commit ID generation:
        f"commit_{tick}_{source_region_slug}"
        where source_region_slug = source_region[:20].replace(':', '_').replace(' ', '_')

    Rollback parent:
        The most recent previous commit_id where success_score >= 0.60.
        None if no such ancestor exists.

    Reinforcement law (Fowler 1999 refactoring principle -- preserve history):
        If stability_state == 'interface_stable':
            new_score = old_score * 0.92 + raw_score * 0.08 + 0.02   (success)
        else:
            new_score = old_score * 0.95 - 0.03                       (failure)
        Clamped [0, 1].

    raw_score = stability_score * 0.60 + (1 - max_risk) * 0.40.

    Schema per record:
        tick                 : int
        commit_id            : str
        region_chain         : list[str]   -- ordered region_ids from plan
        stable_interfaces    : bool
        rollback_parent      : str | None
        success_score        : float [0, 1]
        partial_success      : bool        -- True if some steps succeeded, some failed
        failed_regions       : list[str]   -- steps with risk_score > 0.70
        commit_summary       : str

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._commits = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        # Stable ancestor pool: {commit_id: success_score}
        self._ancestry: dict = {}
        # Running EMA score per region_chain signature
        self._chain_scores: dict = {}   # {chain_sig: float}

    # ------------------------------------------------------------------

    @staticmethod
    def _chain_sig(region_chain: list) -> str:
        """Stable signature for a region chain (first 4 IDs joined)."""
        return '|'.join(region_chain[:4])

    def _best_rollback_parent(self) -> str | None:
        """Return commit_id of best ancestor with success_score >= 0.60."""
        best = None
        best_score = 0.0
        for cid, sc in self._ancestry.items():
            if sc >= 0.60 and sc > best_score:
                best_score = sc
                best = cid
        return best

    # ------------------------------------------------------------------

    def commit(self, tick, region_rewrite_planner,
               interface_stability_checker):
        """
        Record a grouped commit for the current rewrite plan.

        Reads:
            region_rewrite_planner.latest()       -- plan_steps, max_risk, step_count
            interface_stability_checker.latest()  -- stability_state, stability_score

        Writes:
            self._commits    (own deque only)
            self._ancestry   (own dict only)
            self._chain_scores (own dict only)
        """
        plan_rec  = region_rewrite_planner.latest()
        stab_rec  = interface_stability_checker.latest()

        if not plan_rec:
            return None

        steps           = plan_rec.get('plan_steps', [])
        max_risk        = plan_rec.get('max_risk', 0.5)
        source_region   = steps[0]['region_id'] if steps else 'unknown'
        region_chain    = [s['region_id'] for s in steps]

        stability_state = stab_rec.get('stability_state', 'uncertain') if stab_rec else 'uncertain'
        stability_score = stab_rec.get('stability_score', 0.5) if stab_rec else 0.5
        stable          = stability_state == 'interface_stable'

        # Failed regions: any step with risk_score > 0.70
        failed_regions  = [s['region_id'] for s in steps if s.get('risk_score', 0) > 0.70]
        partial_success = bool(failed_regions) and len(failed_regions) < len(steps)

        # Commit ID
        slug = source_region[:20].replace(':', '_').replace(' ', '_')
        commit_id = f"commit_{tick}_{slug}"

        # Rollback parent
        rollback_parent = self._best_rollback_parent()

        # Raw score for this commit
        raw_score = max(0.0, min(1.0,
            stability_score * 0.60 + (1.0 - max_risk) * 0.40))

        # Reinforced success score (EMA over chain history)
        chain_sig  = self._chain_sig(region_chain)
        old_score  = self._chain_scores.get(chain_sig, raw_score)
        if stable:
            new_score = max(0.0, min(1.0, old_score * 0.92 + raw_score * 0.08 + 0.02))
        else:
            new_score = max(0.0, min(1.0, old_score * 0.95 - 0.03))
        self._chain_scores[chain_sig] = new_score

        # Update ancestry
        self._ancestry[commit_id] = new_score

        # Trim ancestry to avoid unbounded growth (keep last 128 entries)
        if len(self._ancestry) > 128:
            oldest = next(iter(self._ancestry))
            del self._ancestry[oldest]

        summary = (
            f"Commit '{commit_id}': {len(region_chain)}-region chain. "
            f"stable={stable} score={new_score:.3f} "
            f"parent={rollback_parent} failed={len(failed_regions)}."
        )

        record = {
            'tick':            int(tick),
            'commit_id':       commit_id,
            'region_chain':    region_chain,
            'stable_interfaces': stable,
            'rollback_parent': rollback_parent,
            'success_score':   float(round(new_score, 4)),
            'partial_success': partial_success,
            'failed_regions':  failed_regions,
            'commit_summary':  summary,
        }
        self._commits.append(record)
        return record

    def latest(self): return self._commits[-1] if self._commits else None
    def recent(self, n=10):
        buf = list(self._commits)
        return buf[-n:] if n < len(buf) else buf
    def ancestry_size(self): return len(self._ancestry)
    def __len__(self): return len(self._commits)

    def to_dict(self):
        return {
            'maxlen':       self._maxlen,
            'commit_groups': list(self._commits),
            'ancestry':      dict(self._ancestry),
            'chain_scores':  dict(self._chain_scores),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('commit_groups', []):
            obj._commits.append(rec)
        obj._ancestry    = dict(d.get('ancestry', {}))
        obj._chain_scores = dict(d.get('chain_scores', {}))
        return obj


# ===========================================================================
# DAY 25: STRUCTURE-AWARE INTERNAL REASONING  --  PACK 3
# RewriteTrajectorySimulator + InvariantDriftEstimator + PreCommitOutcomeMemory
# Friston 2010 (predictive processing: prediction before execution);
# Clark 2013 (prospective coding: future-state simulation before action);
# Sutton & Barto 1998 (temporal difference: outcome vs prediction);
# Kahneman 2011 (pre-mortem: simulate failure modes before committing).
#
# Purpose:
#   First prospective rewrite cognition layer -- sparse counterfactual simulation
#   before patch execution.  The organism simulates 5 future trajectory nodes,
#   estimates invariant drift, and learns from prediction error over sessions.
#
# EEIL sparse compute law (mandatory):
#   Expand at most: source + top-4-downstream + serialization + rollback + test
#   = deque(maxlen=16) per trajectory.  Never simulate all regions.
#
# Rules:
#   - Waking-only: after cross_region_commit_graph.commit(),
#                  before edit_intent_generator.generate()
#   - Zero survival contamination: no selected_action / BG / WM / drive writes
#   - Bounded: deque(maxlen=128) for records; deque(maxlen=16) for trajectory nodes
#   - Biology escalation: any trajectory node touching protected class =>
#     requires_biology_escalation = True
#   - Prediction-error learning: actual outcome updates future_bias EMA each tick
# ===========================================================================


class RewriteTrajectorySimulator:
    """
    Generates sparse future rewrite trajectories BEFORE patch execution.

    Expands exactly (up to) 8 trajectory nodes (EEIL sparse compute law):
        1. source region
        2-5. top-4 downstream regions by edge weight
        6. serialization region
        7. test anchor
        8. rollback ancestry

    Prediction formulas:
        predicted_integrity     = current_integrity * (1.0 - risk_score * 0.35)
        rollback_survivability  = 1.0 - max(0.0, risk_score - 0.4)
        invariant_risk          = risk_score * blast_radius * 0.5
                                  (amplified if region is protected)

    requires_biology_escalation:
        True if any protected class name or stem appears in region_id.

    Schema per record:
        tick                  : int
        trajectory            : list[dict]   -- TrajectoryState-schema dicts (maxlen=16)
        node_count            : int
        max_invariant_risk    : float [0, 1]
        any_biology_escalation: bool
        current_integrity     : float [0, 1]  -- integrity_score at simulation time
        trajectory_confidence : float [0, 1]
        trajectory_summary    : str

    trajectory_confidence = (1 - max_invariant_risk) * 0.70 + current_integrity * 0.30

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._trajectories = deque(maxlen=maxlen)
        self._maxlen       = maxlen

    # ------------------------------------------------------------------

    @staticmethod
    def _needs_bio_escalation(region_id: str) -> bool:
        """True if region touches a protected biology class (same logic as Pack 1/2)."""
        rid = region_id.lower()
        for pname in _PROTECTED_CLASS_NAMES:
            if pname.lower() in rid:
                return True
            stem = pname.lower()
            for suffix in ('system', 'axissystem', 'axis'):
                if stem.endswith(suffix):
                    stem = stem[:-len(suffix)]
                    break
            if stem and len(stem) >= 4 and stem in rid:
                return True
        return False

    @staticmethod
    def _trajectory_node(idx: int, region_id: str, risk: float,
                         blast: float, current_integrity: float) -> dict:
        pred_int  = max(0.0, min(1.0, current_integrity * (1.0 - risk * 0.35)))
        rollback  = max(0.0, min(1.0, 1.0 - max(0.0, risk - 0.4)))
        inv_risk  = max(0.0, min(1.0, risk * blast * 0.5))
        bio_esc   = RewriteTrajectorySimulator._needs_bio_escalation(region_id)
        if bio_esc:
            inv_risk = min(1.0, inv_risk + 0.15)   # amplify for protected zones
        return {
            'step_index':                int(idx),
            'region_id':                 str(region_id),
            'predicted_integrity':       float(round(pred_int, 4)),
            'rollback_survivability':    float(round(rollback, 4)),
            'invariant_risk':            float(round(inv_risk, 4)),
            'requires_biology_escalation': bio_esc,
        }

    # ------------------------------------------------------------------

    def simulate(self, tick, region_rewrite_planner, dependency_link_memory,
                 cross_region_commit_graph, integrity_scorer):
        """
        Simulate future trajectory states for the current rewrite plan.

        Reads:
            region_rewrite_planner.latest()    -- plan_steps, max_risk
            dependency_link_memory.latest()    -- blast_radius, edge_weights,
                                                  downstream_regions
            cross_region_commit_graph.latest() -- success_score (ancestor confidence)
            integrity_scorer.latest()          -- integrity_score (current state)

        Writes:
            self._trajectories  (own deque only)
        """
        plan_rec  = region_rewrite_planner.latest()
        dep_rec   = dependency_link_memory.latest()
        crcg_rec  = cross_region_commit_graph.latest()
        isc_rec   = integrity_scorer.latest()

        if not plan_rec or not dep_rec:
            return None

        steps           = plan_rec.get('plan_steps', [])
        blast           = dep_rec.get('blast_radius', 0.30)
        ew              = dep_rec.get('edge_weights', {})
        downstream      = dep_rec.get('downstream_regions', [])
        ancestor_score  = crcg_rec.get('success_score', 0.5) if crcg_rec else 0.5
        current_integrity = (isc_rec.get('integrity_score', 0.5)
                             if isc_rec else 0.5)

        trajectory: list = []
        idx = 1

        # Node 1: source region (step 1 of plan)
        if steps:
            s1 = steps[0]
            trajectory.append(self._trajectory_node(
                idx, s1['region_id'], s1['risk_score'], blast, current_integrity))
            idx += 1

        # Nodes 2-5: top-4 downstream by edge weight (EEIL sparse law)
        top_ds = sorted(downstream[:8], key=lambda r: -ew.get(r, 0.3))[:4]
        for ds in top_ds:
            ds_risk = max(0.0, min(1.0, blast * 0.65))
            trajectory.append(self._trajectory_node(
                idx, ds, ds_risk, blast * 0.75, current_integrity))
            idx += 1

        # Node: serialization region
        serial_step = next(
            (s for s in steps if s.get('operation') == 'update_serialization'), None)
        serial_id = serial_step['region_id'] if serial_step else 'micro:serialization'
        serial_risk = max(0.0, min(1.0, blast * 0.30))
        trajectory.append(self._trajectory_node(
            idx, serial_id, serial_risk, blast * 0.50, current_integrity))
        idx += 1

        # Node: test anchor
        test_step = next(
            (s for s in steps if s.get('operation') == 'validate_tests'), None)
        test_id   = test_step['region_id'] if test_step else 'test:anchor'
        test_risk = max(0.0, min(1.0, blast * 0.20))
        trajectory.append(self._trajectory_node(
            idx, test_id, test_risk, blast * 0.40, current_integrity))
        idx += 1

        # Node: rollback ancestry
        rb_risk = max(0.0, min(1.0, blast * 0.15 * (1.0 - ancestor_score)))
        trajectory.append(self._trajectory_node(
            idx, 'rollback:ancestry', rb_risk, blast * 0.30, current_integrity))

        # Enforce EEIL maxlen=16
        trajectory = trajectory[:16]

        max_inv_risk = max(n['invariant_risk'] for n in trajectory) if trajectory else 0.0
        any_bio_esc  = any(n['requires_biology_escalation'] for n in trajectory)
        traj_conf    = max(0.0, min(1.0,
            (1.0 - max_inv_risk) * 0.70 + current_integrity * 0.30))

        summary = (
            f"Tick {tick}: {len(trajectory)}-node trajectory. "
            f"max_inv_risk={max_inv_risk:.3f} bio_esc={'YES' if any_bio_esc else 'NO'} "
            f"conf={traj_conf:.3f}."
        )

        record = {
            'tick':                   int(tick),
            'trajectory':             trajectory,
            'node_count':             len(trajectory),
            'max_invariant_risk':     float(round(max_inv_risk, 4)),
            'any_biology_escalation': any_bio_esc,
            'current_integrity':      float(round(current_integrity, 4)),
            'trajectory_confidence':  float(round(traj_conf, 4)),
            'trajectory_summary':     summary,
        }
        self._trajectories.append(record)
        return record

    def latest(self): return self._trajectories[-1] if self._trajectories else None
    def recent(self, n=10):
        buf = list(self._trajectories)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._trajectories)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'trajectories': list(self._trajectories)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('trajectories', []):
            obj._trajectories.append(rec)
        return obj


class InvariantDriftEstimator:
    """
    Estimates semantic invariant degradation across the simulated trajectory
    BEFORE patch execution.

    Drift formula:
        drift = mean(1.0 - predicted_integrity  across all trajectory nodes)

    States (exactly one):
        stable_projection          : drift < 0.20 and no biology escalation
        localized_drift            : 0.20 <= drift < 0.45 and no biology escalation
        serialization_projection_risk: serialization node has high invariant_risk (>0.35)
                                       AND no rollback ancestry node is low-risk
        biology_projection_risk    : any trajectory node has requires_biology_escalation
        uncertain                  : trajectory empty or data absent

    Priority:
        biology_projection_risk > serialization_projection_risk > localized_drift
        > stable_projection

    Score:
        stable_projection             : 1.0 - drift
        localized_drift               : max(0.0, 0.60 - drift)
        serialization_projection_risk : 0.35
        biology_projection_risk       : 0.20
        uncertain                     : 0.50

    Schema per record:
        tick                  : int
        drift_state           : str
        drift_score           : float [0, 1]
        mean_drift            : float [0, 1]
        serial_node_risk      : float        -- invariant_risk of serialization node
        rollback_protected    : bool         -- rollback survivability >= 0.60
        drift_summary         : str

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._estimates = deque(maxlen=maxlen)
        self._maxlen    = maxlen

    # ------------------------------------------------------------------

    def estimate(self, tick, rewrite_trajectory_simulator,
                 cross_region_commit_graph):
        """
        Estimate invariant drift from the current trajectory.

        Reads:
            rewrite_trajectory_simulator.latest() -- trajectory, max_invariant_risk,
                                                     any_biology_escalation
            cross_region_commit_graph.latest()    -- success_score (rollback health)

        Writes:
            self._estimates  (own deque only)
        """
        traj_rec  = rewrite_trajectory_simulator.latest()
        crcg_rec  = cross_region_commit_graph.latest()

        if not traj_rec or not traj_rec.get('trajectory'):
            record = {
                'tick':             int(tick),
                'drift_state':      'uncertain',
                'drift_score':      0.50,
                'mean_drift':       0.0,
                'serial_node_risk': 0.0,
                'rollback_protected': False,
                'drift_summary':    f"Tick {tick}: uncertain -- no trajectory data.",
            }
            self._estimates.append(record)
            return record

        trajectory    = traj_rec.get('trajectory', [])
        bio_esc       = traj_rec.get('any_biology_escalation', False)
        ancestor_score = crcg_rec.get('success_score', 0.5) if crcg_rec else 0.5

        # Drift = mean(1 - predicted_integrity)
        mean_drift = 1.0 - (
            sum(n['predicted_integrity'] for n in trajectory) / max(1, len(trajectory)))
        mean_drift = max(0.0, min(1.0, mean_drift))

        # Serialization node risk
        serial_node = next(
            (n for n in trajectory if 'serialization' in n.get('region_id', '')), None)
        serial_risk = serial_node['invariant_risk'] if serial_node else 0.0

        # Rollback ancestry survivability
        rb_node = next(
            (n for n in trajectory if 'rollback' in n.get('region_id', '')), None)
        rollback_protected = (rb_node['rollback_survivability'] >= 0.60
                              if rb_node else ancestor_score >= 0.60)

        # State determination (priority order)
        if bio_esc:
            drift_state = 'biology_projection_risk'
            drift_score = 0.20
        elif serial_risk > 0.35 and not rollback_protected:
            drift_state = 'serialization_projection_risk'
            drift_score = 0.35
        elif mean_drift >= 0.20:
            drift_state = 'localized_drift'
            drift_score = max(0.0, 0.60 - mean_drift)
        else:
            drift_state = 'stable_projection'
            drift_score = max(0.0, min(1.0, 1.0 - mean_drift))

        drift_score = float(round(drift_score, 4))

        summary = (
            f"Tick {tick}: {drift_state} drift={mean_drift:.3f} "
            f"serial_risk={serial_risk:.3f} rb_protected={rollback_protected} "
            f"score={drift_score:.3f}."
        )

        record = {
            'tick':               int(tick),
            'drift_state':        drift_state,
            'drift_score':        drift_score,
            'mean_drift':         float(round(mean_drift, 4)),
            'serial_node_risk':   float(round(serial_risk, 4)),
            'rollback_protected': rollback_protected,
            'drift_summary':      summary,
        }
        self._estimates.append(record)
        return record

    def latest(self): return self._estimates[-1] if self._estimates else None
    def recent(self, n=10):
        buf = list(self._estimates)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._estimates)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'estimates': list(self._estimates)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('estimates', []):
            obj._estimates.append(rec)
        return obj


class PreCommitOutcomeMemory:
    """
    Stores prediction-vs-actual outcome traces and learns future bias corrections.

    Prediction error:
        prediction_error = abs(actual_score - predicted_score)

    Future bias update (EMA prediction-error learning):
        if prediction_error <= 0.10:  (accurate prediction)
            future_bias = old_bias * 0.90 + prediction_error * 0.10 + 0.02
        else:  (inaccurate prediction / overshoot)
            future_bias = old_bias * 0.90 + prediction_error * 0.10 - 0.03
        Clamped [-1, 1].

    actual_score is derived from:
        cross_region_commit_graph.latest().success_score

    predicted_score is derived from:
        invariant_drift_estimator.latest().drift_score

    Schema per record:
        tick               : int
        chain_signature    : str
        predicted_score    : float [0, 1]
        actual_score       : float [0, 1]
        prediction_error   : float [0, 1]
        future_bias        : float [-1, 1]
        rollback_succeeded : bool    -- commit ancestry non-None
        interface_stable   : bool    -- from cross_region_commit_graph
        trace_summary      : str

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._traces  = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        # Per-chain future bias  {chain_sig: float}
        self._biases: dict = {}

    # ------------------------------------------------------------------

    def trace(self, tick, rewrite_trajectory_simulator,
              invariant_drift_estimator, cross_region_commit_graph):
        """
        Record prediction vs actual and update future bias.

        Reads:
            rewrite_trajectory_simulator.latest()  -- trajectory (chain_sig source),
                                                       trajectory_confidence (predicted)
            invariant_drift_estimator.latest()     -- drift_score (predicted quality)
            cross_region_commit_graph.latest()     -- success_score (actual outcome),
                                                      rollback_parent, stable_interfaces

        Writes:
            self._traces   (own deque only)
            self._biases   (own dict only)
        """
        traj_rec  = rewrite_trajectory_simulator.latest()
        drift_rec = invariant_drift_estimator.latest()
        crcg_rec  = cross_region_commit_graph.latest()

        if not traj_rec or not crcg_rec:
            return None

        # Chain signature from trajectory (first 4 node region_ids)
        nodes     = traj_rec.get('trajectory', [])
        chain_sig = '|'.join(n['region_id'] for n in nodes[:4]) if nodes else 'empty'

        # Predicted score = trajectory_confidence blended with drift_score
        traj_conf    = traj_rec.get('trajectory_confidence', 0.5)
        drift_score  = drift_rec.get('drift_score', 0.5) if drift_rec else 0.5
        predicted    = max(0.0, min(1.0, traj_conf * 0.60 + drift_score * 0.40))

        # Actual score = commit success_score
        actual       = float(crcg_rec.get('success_score', 0.5))
        pred_error   = abs(actual - predicted)

        # Future bias EMA
        old_bias = self._biases.get(chain_sig, 0.0)
        if pred_error <= 0.10:
            new_bias = max(-1.0, min(1.0,
                old_bias * 0.90 + pred_error * 0.10 + 0.02))
        else:
            new_bias = max(-1.0, min(1.0,
                old_bias * 0.90 + pred_error * 0.10 - 0.03))
        self._biases[chain_sig] = new_bias

        rollback_succeeded = crcg_rec.get('rollback_parent') is not None
        interface_stable   = crcg_rec.get('stable_interfaces', False)

        summary = (
            f"Tick {tick}: pred={predicted:.3f} actual={actual:.3f} "
            f"err={pred_error:.3f} bias={new_bias:.3f} "
            f"rb={'OK' if rollback_succeeded else 'NONE'} "
            f"stable={interface_stable}."
        )

        record = {
            'tick':               int(tick),
            'chain_signature':    chain_sig,
            'predicted_score':    float(round(predicted, 4)),
            'actual_score':       float(round(actual, 4)),
            'prediction_error':   float(round(pred_error, 4)),
            'future_bias':        float(round(new_bias, 4)),
            'rollback_succeeded': rollback_succeeded,
            'interface_stable':   interface_stable,
            'trace_summary':      summary,
        }
        self._traces.append(record)
        return record

    def latest(self): return self._traces[-1] if self._traces else None
    def recent(self, n=10):
        buf = list(self._traces)
        return buf[-n:] if n < len(buf) else buf
    def bias_for(self, chain_sig: str) -> float:
        """Return current future_bias for a chain signature (0.0 if unseen)."""
        return self._biases.get(chain_sig, 0.0)
    def __len__(self): return len(self._traces)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'traces': list(self._traces),
            'biases': dict(self._biases),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('traces', []):
            obj._traces.append(rec)
        obj._biases = dict(d.get('biases', {}))
        return obj

# ===========================================================================
# DAY 25: STRUCTURE-AWARE INTERNAL REASONING  --  PACK 4
# TrajectoryBranchGenerator + FutureValueSelector + BranchOutcomeArchive
# Janis 1972 (prospective comparison of plausible failure paths);
# March 1994 (bounded rational choice under sparse alternatives);
# Sutton & Barto 1998 (value comparison under uncertain return).
#
# Purpose:
#   Multi-branch future deliberation. The organism no longer accepts only one
#   projected rewrite future; it now generates 2-4 sparse branch families,
#   compares explicit future value, and archives strategic branch memory.
# ===========================================================================


class TrajectoryBranchGenerator:
    """
    Generates 2-4 sparse rewrite branch futures from the current Pack 2/3 state.

    Default branch families:
        1. direct_patch
        2. serialization_first
        3. test_first
        4. rollback_first (only when rollback / drift / ancestry pressure is high)

    Each branch is capped at 5 projected nodes and remains sparse by law.
    Waking-only. Zero survival contamination.
    """

    _BASE_STRATEGIES = ('direct_patch', 'serialization_first', 'test_first')

    def __init__(self, maxlen=128):
        self._generations = deque(maxlen=maxlen)
        self._maxlen      = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _infer_operation(region_id: str, step_lookup: dict) -> str:
        step = step_lookup.get(region_id)
        if step:
            return step.get('operation', 'modify_region')
        if 'serialization' in region_id:
            return 'update_serialization'
        if region_id.startswith('test:'):
            return 'validate_tests'
        if 'rollback' in region_id:
            return 'update_rollback'
        return 'modify_region'

    @classmethod
    def _fallback_node(cls, idx: int, region_id: str, operation: str,
                       risk: float, blast: float, current_integrity: float) -> dict:
        risk     = cls._clamp(risk)
        pred_int = cls._clamp(current_integrity * (1.0 - risk * 0.35))
        rollback = cls._clamp(1.0 - max(0.0, risk - 0.4))
        drift    = cls._clamp(risk * blast * 0.5)
        bio_esc  = RewriteTrajectorySimulator._needs_bio_escalation(region_id)
        if bio_esc:
            drift = cls._clamp(drift + 0.15)
        return {
            'step_index':                 int(idx),
            'region_id':                  str(region_id),
            'operation':                  str(operation),
            'predicted_integrity':        float(round(pred_int, 4)),
            'rollback_survivability':     float(round(rollback, 4)),
            'predicted_drift':            float(round(drift, 4)),
            'requires_biology_escalation': bio_esc,
        }

    @staticmethod
    def _branch_order(strategy: str, source_region: str, downstream_region: str | None,
                      serial_id: str, test_id: str, rollback_id: str) -> list:
        if strategy == 'serialization_first':
            order = [serial_id, source_region, downstream_region, test_id, rollback_id]
        elif strategy == 'test_first':
            order = [test_id, source_region, downstream_region, serial_id, rollback_id]
        elif strategy == 'rollback_first':
            order = [rollback_id, source_region, serial_id, downstream_region, test_id]
        else:
            order = [source_region, downstream_region, serial_id, test_id, rollback_id]
        return [rid for rid in order if rid]

    @classmethod
    def _materialize_branch(cls, strategy: str, source_region: str,
                            downstream_region: str | None, serial_id: str,
                            test_id: str, rollback_id: str, node_lookup: dict,
                            step_lookup: dict, blast: float,
                            current_integrity: float) -> list:
        ordered = cls._branch_order(
            strategy=strategy,
            source_region=source_region,
            downstream_region=downstream_region,
            serial_id=serial_id,
            test_id=test_id,
            rollback_id=rollback_id,
        )
        nodes = []
        seen  = set()
        idx   = 1
        for rid in ordered:
            if rid in seen:
                continue
            seen.add(rid)
            base_node = node_lookup.get(rid)
            operation = cls._infer_operation(rid, step_lookup)
            if base_node:
                node = {
                    'step_index':                 int(idx),
                    'region_id':                  str(rid),
                    'operation':                  operation,
                    'predicted_integrity':        float(round(base_node.get('predicted_integrity', current_integrity), 4)),
                    'rollback_survivability':     float(round(base_node.get('rollback_survivability', 0.5), 4)),
                    'predicted_drift':            float(round(base_node.get('invariant_risk', 0.5), 4)),
                    'requires_biology_escalation': bool(
                        base_node.get(
                            'requires_biology_escalation',
                            RewriteTrajectorySimulator._needs_bio_escalation(rid),
                        )
                    ),
                }
            else:
                step = step_lookup.get(rid, {})
                risk = step.get('risk_score', blast * 0.35)
                node = cls._fallback_node(
                    idx=idx,
                    region_id=rid,
                    operation=operation,
                    risk=risk,
                    blast=blast,
                    current_integrity=current_integrity,
                )
            nodes.append(node)
            idx += 1
            if len(nodes) >= 5:
                break
        return nodes

    @classmethod
    def _branch_metrics(cls, strategy: str, nodes: list, plan_max_risk: float,
                        drift_rec: dict, ancestor_score: float,
                        rollback_parent: str | None) -> dict:
        if not nodes:
            return {
                'projected_integrity':        0.50,
                'rollback_survivability':     0.50,
                'predicted_drift':            0.50,
                'compute_cost':               0.50,
                'eeil_sparse_efficiency':     0.50,
                'ancestry_success_prior':     0.50,
                'requires_biology_escalation': False,
            }

        node_count = len(nodes)
        base_int   = sum(n['predicted_integrity'] for n in nodes) / node_count
        base_rb    = sum(n['rollback_survivability'] for n in nodes) / node_count
        base_drift = sum(n['predicted_drift'] for n in nodes) / node_count
        any_bio    = any(n['requires_biology_escalation'] for n in nodes)

        serial_pressure = drift_rec.get('serial_node_risk', 0.0) if drift_rec else 0.0
        if drift_rec and drift_rec.get('drift_state') == 'serialization_projection_risk':
            serial_pressure = max(serial_pressure, 1.0)
        serial_pressure = cls._clamp(serial_pressure)
        stability_pressure = cls._clamp(max(
            plan_max_risk,
            drift_rec.get('mean_drift', 0.0) if drift_rec else 0.0,
        ))
        rollback_pressure = max(0.0, 0.65 - ancestor_score)
        if not rollback_parent:
            rollback_pressure += 0.15
        if drift_rec and not drift_rec.get('rollback_protected', True):
            rollback_pressure += 0.10
        rollback_pressure = cls._clamp(rollback_pressure)
        bio_pressure = 1.0 if any_bio else 0.0

        if strategy == 'serialization_first':
            serial_bonus = 0.07 if serial_pressure > 0.35 else -0.01
            projected_integrity = cls._clamp(
                base_int + serial_bonus - 0.02 * stability_pressure - 0.03 * bio_pressure)
            rollback_survivability = cls._clamp(base_rb + 0.02 + 0.01 * rollback_pressure)
            predicted_drift = cls._clamp(
                base_drift - (0.08 if serial_pressure > 0.35 else 0.01) + 0.06 * bio_pressure)
            compute_cost = cls._clamp(0.22 + node_count * 0.08)
            ancestry_success_prior = cls._clamp(ancestor_score * 0.98 + 0.01)
        elif strategy == 'test_first':
            test_bonus = 0.06 if stability_pressure > 0.40 else -0.01
            projected_integrity = cls._clamp(
                base_int + test_bonus - 0.01 * serial_pressure - 0.03 * bio_pressure)
            rollback_survivability = cls._clamp(base_rb + 0.04 + 0.03 * stability_pressure)
            predicted_drift = cls._clamp(
                base_drift - (0.06 if stability_pressure > 0.40 else 0.015) + 0.05 * bio_pressure)
            compute_cost = cls._clamp(0.24 + node_count * 0.08)
            ancestry_success_prior = cls._clamp(ancestor_score * 0.97 + 0.02)
        elif strategy == 'rollback_first':
            rollback_bonus = 0.10 if rollback_pressure > 0.35 else 0.03
            projected_integrity = cls._clamp(
                base_int + (0.03 if rollback_pressure > 0.35 else -0.02) - 0.02 * bio_pressure)
            rollback_survivability = cls._clamp(base_rb + rollback_bonus)
            predicted_drift = cls._clamp(
                base_drift - (0.04 if rollback_pressure > 0.35 else 0.01) + 0.05 * bio_pressure)
            compute_cost = cls._clamp(0.20 + node_count * 0.08)
            ancestry_success_prior = cls._clamp(
                ancestor_score + (0.08 if rollback_pressure > 0.35 else 0.02) +
                (0.04 if rollback_parent else 0.0))
        else:
            projected_integrity = cls._clamp(
                base_int - 0.03 * serial_pressure - 0.03 * stability_pressure -
                0.04 * bio_pressure + 0.02 * (
                    1.0 - max(serial_pressure, stability_pressure, rollback_pressure)))
            rollback_survivability = cls._clamp(
                base_rb - 0.03 * rollback_pressure + 0.02 * (1.0 - rollback_pressure))
            predicted_drift = cls._clamp(
                base_drift + 0.05 * serial_pressure + 0.04 * stability_pressure +
                0.08 * bio_pressure - 0.02 * (1.0 - max(serial_pressure, stability_pressure)))
            compute_cost = cls._clamp(0.16 + node_count * 0.07)
            ancestry_success_prior = cls._clamp(
                ancestor_score * 0.96 + (0.03 if rollback_parent else 0.0))

        return {
            'projected_integrity':        float(round(projected_integrity, 4)),
            'rollback_survivability':     float(round(rollback_survivability, 4)),
            'predicted_drift':            float(round(predicted_drift, 4)),
            'compute_cost':               float(round(compute_cost, 4)),
            'eeil_sparse_efficiency':     float(round(cls._clamp(1.0 - compute_cost), 4)),
            'ancestry_success_prior':     float(round(ancestry_success_prior, 4)),
            'requires_biology_escalation': any_bio,
        }

    def generate(self, tick, region_rewrite_planner, dependency_link_memory,
                 rewrite_trajectory_simulator, invariant_drift_estimator,
                 cross_region_commit_graph):
        plan_rec   = region_rewrite_planner.latest()
        dep_rec    = dependency_link_memory.latest()
        traj_rec   = rewrite_trajectory_simulator.latest()
        drift_rec  = invariant_drift_estimator.latest()
        commit_rec = cross_region_commit_graph.latest()

        if not plan_rec or not dep_rec or not traj_rec:
            record = {
                'tick':                   int(tick),
                'source_region':          None,
                'branches':               [],
                'branch_count':           0,
                'max_branch_nodes':       0,
                'any_biology_escalation': False,
                'generation_summary':     f"Tick {tick}: uncertain -- no branch generation inputs.",
            }
            self._generations.append(record)
            return record

        steps             = plan_rec.get('plan_steps', [])
        edge_weights      = dep_rec.get('edge_weights', {})
        blast             = dep_rec.get('blast_radius', 0.30)
        plan_max_risk     = plan_rec.get('max_risk', 0.5)
        current_integrity = traj_rec.get('current_integrity', 0.5)
        trajectory        = traj_rec.get('trajectory', [])
        ancestor_score    = commit_rec.get('success_score', 0.5) if commit_rec else 0.5
        rollback_parent   = commit_rec.get('rollback_parent') if commit_rec else None
        source_region     = (steps[0]['region_id']
                             if steps else dep_rec.get('source_region', 'unknown'))

        modify_steps = [s for s in steps if s.get('operation') == 'modify_region']
        if modify_steps:
            top_modify = sorted(
                modify_steps,
                key=lambda s: (-edge_weights.get(s['region_id'], 0.0), s.get('risk_score', 0.0)),
            )[0]
            downstream_region = top_modify['region_id']
        else:
            downstream_candidates = [
                rid for rid in dep_rec.get('downstream_regions', [])
                if rid != source_region
            ]
            downstream_region = downstream_candidates[0] if downstream_candidates else None

        serial_step   = next((s for s in steps if s.get('operation') == 'update_serialization'), None)
        test_step     = next((s for s in steps if s.get('operation') == 'validate_tests'), None)
        rollback_step = next((s for s in steps if s.get('operation') == 'update_rollback'), None)
        serial_id     = serial_step['region_id'] if serial_step else 'micro:serialization'
        test_id       = test_step['region_id'] if test_step else f"test:{source_region}"
        rollback_id   = rollback_step['region_id'] if rollback_step else 'rollback:ancestry'

        strategies = list(self._BASE_STRATEGIES)
        if (plan_max_risk >= 0.45 or
                (drift_rec and drift_rec.get('drift_state') != 'stable_projection') or
                ancestor_score < 0.62 or
                not rollback_parent):
            strategies.append('rollback_first')
        strategies = strategies[:4]

        node_lookup = {n['region_id']: n for n in trajectory}
        step_lookup = {s['region_id']: s for s in steps}
        branches    = []
        source_slug = source_region[:24].replace(':', '_').replace(' ', '_')

        for strategy in strategies:
            branch_nodes = self._materialize_branch(
                strategy=strategy,
                source_region=source_region,
                downstream_region=downstream_region,
                serial_id=serial_id,
                test_id=test_id,
                rollback_id=rollback_id,
                node_lookup=node_lookup,
                step_lookup=step_lookup,
                blast=blast,
                current_integrity=current_integrity,
            )
            metrics = self._branch_metrics(
                strategy=strategy,
                nodes=branch_nodes,
                plan_max_risk=plan_max_risk,
                drift_rec=drift_rec or {},
                ancestor_score=ancestor_score,
                rollback_parent=rollback_parent,
            )
            region_chain = [n['region_id'] for n in branch_nodes]
            chain_sig    = '|'.join(region_chain[:4]) if region_chain else 'empty'
            family_sig   = f"{source_region}|{strategy}"
            branches.append({
                'branch_id':                   f"branch_{tick}_{strategy}_{source_slug}",
                'strategy':                    strategy,
                'family_signature':            family_sig,
                'chain_signature':             chain_sig,
                'branch_nodes':                branch_nodes[:5],
                'node_count':                  min(5, len(branch_nodes)),
                'projected_integrity':         metrics['projected_integrity'],
                'rollback_survivability':      metrics['rollback_survivability'],
                'predicted_drift':             metrics['predicted_drift'],
                'compute_cost':                metrics['compute_cost'],
                'eeil_sparse_efficiency':      metrics['eeil_sparse_efficiency'],
                'ancestry_success_prior':      metrics['ancestry_success_prior'],
                'requires_biology_escalation': metrics['requires_biology_escalation'],
                'branch_summary':              (
                    f"{strategy}: int={metrics['projected_integrity']:.3f} "
                    f"rb={metrics['rollback_survivability']:.3f} "
                    f"drift={metrics['predicted_drift']:.3f} "
                    f"cost={metrics['compute_cost']:.3f}."
                ),
            })

        max_nodes = max((b['node_count'] for b in branches), default=0)
        any_bio   = any(b['requires_biology_escalation'] for b in branches)
        record = {
            'tick':                   int(tick),
            'source_region':          source_region,
            'branches':               branches,
            'branch_count':           len(branches),
            'max_branch_nodes':       max_nodes,
            'any_biology_escalation': any_bio,
            'generation_summary':     (
                f"Tick {tick}: generated {len(branches)} sparse branches for '{source_region}'. "
                f"max_nodes={max_nodes} bio_esc={'YES' if any_bio else 'NO'}."
            ),
        }
        self._generations.append(record)
        return record

    def latest(self): return self._generations[-1] if self._generations else None
    def recent(self, n=10):
        buf = list(self._generations)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._generations)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'generations': list(self._generations)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('generations', []):
            obj._generations.append(rec)
        return obj


class FutureValueSelector:
    """
    Compares sparse branch futures and selects the best projected rewrite path.

    Frozen scoring law:
        future_value = (
            projected_integrity * 0.35
            + rollback_survivability * 0.25
            + (1.0 - predicted_drift) * 0.20
            + ancestry_success_prior * 0.15
            + eeil_sparse_efficiency * 0.05
        )

    Value is clamped to [0, 1].

    Selection then applies:
        - biology escalation penalty (separate from the frozen value law)
        - drift minimization tie-break
        - branch sparsity tie-break

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._selections = deque(maxlen=maxlen)
        self._maxlen     = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def select(self, tick, trajectory_branch_generator, pre_commit_outcome_memory,
               branch_outcome_archive):
        gen_rec  = trajectory_branch_generator.latest()
        branches = gen_rec.get('branches', []) if gen_rec else []

        if not branches:
            record = {
                'tick':                       int(tick),
                'selection_state':            'uncertain',
                'selected_branch_id':         None,
                'selected_strategy':          None,
                'selected_family_signature':  None,
                'selected_chain_signature':   None,
                'predicted_score':            0.50,
                'decision_score':             0.50,
                'comparisons':                [],
                'selection_summary':          f"Tick {tick}: uncertain -- no branch futures to compare.",
            }
            self._selections.append(record)
            return record

        comparisons = []
        for branch in branches:
            chain_sig    = branch.get('chain_signature', 'empty')
            family_sig   = branch.get('family_signature')
            future_bias  = (pre_commit_outcome_memory.bias_for(chain_sig)
                            if pre_commit_outcome_memory else 0.0)
            family_prior = (branch_outcome_archive.family_prior_for(family_sig)
                            if branch_outcome_archive else 0.5)

            future_value = self._clamp(
                branch.get('projected_integrity', 0.5) * 0.35 +
                branch.get('rollback_survivability', 0.5) * 0.25 +
                (1.0 - branch.get('predicted_drift', 0.5)) * 0.20 +
                branch.get('ancestry_success_prior', 0.5) * 0.15 +
                branch.get('eeil_sparse_efficiency', 0.5) * 0.05
            )

            biology_penalty = 0.12 if branch.get('requires_biology_escalation', False) else 0.0
            decision_score = self._clamp(
                future_value - biology_penalty + future_bias * 0.03 +
                (family_prior - 0.5) * 0.04
            )

            comparisons.append({
                'branch_id':                   branch.get('branch_id'),
                'strategy':                    branch.get('strategy'),
                'family_signature':            family_sig,
                'chain_signature':             chain_sig,
                'predicted_score':             float(round(future_value, 4)),
                'decision_score':              float(round(decision_score, 4)),
                'projected_integrity':         branch.get('projected_integrity', 0.5),
                'rollback_survivability':      branch.get('rollback_survivability', 0.5),
                'predicted_drift':             branch.get('predicted_drift', 0.5),
                'compute_cost':                branch.get('compute_cost', 0.5),
                'eeil_sparse_efficiency':      branch.get('eeil_sparse_efficiency', 0.5),
                'ancestry_success_prior':      branch.get('ancestry_success_prior', 0.5),
                'future_bias':                 float(round(future_bias, 4)),
                'family_prior':                float(round(family_prior, 4)),
                'requires_biology_escalation': branch.get('requires_biology_escalation', False),
            })

        ranked = sorted(
            comparisons,
            key=lambda c: (
                -c['decision_score'],
                c['predicted_drift'],
                -c['eeil_sparse_efficiency'],
                -c['ancestry_success_prior'],
            ),
        )
        for idx, comp in enumerate(ranked, start=1):
            comp['rank'] = idx

        best = ranked[0]
        selection_state = ('biology_escalation_required'
                           if best.get('requires_biology_escalation', False)
                           else 'best_future_selected')
        record = {
            'tick':                       int(tick),
            'selection_state':            selection_state,
            'selected_branch_id':         best['branch_id'],
            'selected_strategy':          best['strategy'],
            'selected_family_signature':  best['family_signature'],
            'selected_chain_signature':   best['chain_signature'],
            'predicted_score':            best['predicted_score'],
            'decision_score':             best['decision_score'],
            'comparisons':                ranked,
            'selection_summary':          (
                f"Tick {tick}: selected {best['strategy']} "
                f"(pred={best['predicted_score']:.3f}, decision={best['decision_score']:.3f}, "
                f"rank=1/{len(ranked)})."
            ),
        }
        self._selections.append(record)
        return record

    def latest(self): return self._selections[-1] if self._selections else None
    def recent(self, n=10):
        buf = list(self._selections)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._selections)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'selections': list(self._selections)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('selections', []):
            obj._selections.append(rec)
        return obj


# ===========================================================================
# DAY 26 OBSERVATION: Branch Deliberation Confidence
# Observer-only metric quantifying confidence of selected Pack 4 branch future.
# Zero drift: does not alter Pack 1-4 cognition, execution routing, or rollback.
# ===========================================================================

class BranchDeliberationConfidence:
    """
    Quantifies the confidence of the currently selected Pack 4 branch future.

    Metric Law:
        confidence = selected_branch_score * lineage_stability
        clamped to [0, 1]

    Observer-only:
        - reads from FutureValueSelector and BranchOutcomeArchive
        - writes only to internal bounded deque(maxlen=32)
        - does NOT alter branch selection, scoring, or any Pack 1-4 state

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=32):
        self._history   = deque(maxlen=maxlen)
        self._maxlen    = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def _lineage_stability(self, branch_outcome_archive, selected_branch_id: str | None):
        if not selected_branch_id or not branch_outcome_archive:
            return 0.85
        lineage = branch_outcome_archive.lineage_for(selected_branch_id)
        if not lineage:
            return 0.85
        family_sig = lineage.get('family_signature')
        if not family_sig:
            return 0.85
        recent = branch_outcome_archive.recent(n=16)
        if not recent:
            return 0.85
        family_selections = 0
        for rec in recent:
            archived = rec.get('archived_families', [])
            for arch in archived:
                if arch.get('family_signature') == family_sig and arch.get('selected'):
                    family_selections += 1
        stability = self._clamp(0.5 + (family_selections / max(1, len(recent))) * 0.5)
        return stability

    def update(self, tick, future_value_selector, branch_outcome_archive):
        sel_rec = future_value_selector.latest() if future_value_selector else None
        if not sel_rec:
            record = {
                'tick':            int(tick),
                'selected_score': 0.0,
                'lineage_stability': 0.85,
                'confidence':      0.0,
                'state':           'no_selection',
            }
            self._history.append(record)
            return record
        selected_branch_id = sel_rec.get('selected_branch_id')
        selected_score = float(sel_rec.get('decision_score', 0.5))
        stability = self._lineage_stability(branch_outcome_archive, selected_branch_id)
        confidence = self._clamp(selected_score * stability)
        record = {
            'tick':               int(tick),
            'selected_branch_id': selected_branch_id,
            'selected_score':     float(round(selected_score, 4)),
            'lineage_stability':  float(round(stability, 4)),
            'confidence':         float(round(confidence, 4)),
            'state':              sel_rec.get('selection_state', 'unknown'),
            'selection_summary':  sel_rec.get('selection_summary', ''),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 32)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj

    def summary(self):
        if not self._history:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._history[-1]
        stability = latest.get('confidence', 0.5)
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'latest_state': latest.get('state', 'unknown'),
            'stability_score': float(round(self._clamp(stability), 4)),
        }


class BranchReasoningTrace:
    """
    Provides a short bounded trace of why Pack 4 selected a branch future.

    Captures top 3 reasoning factors:
        1. projected integrity contribution
        2. rollback survivability contribution
        3. drift minimization contribution

    Optional fourth:
        - ancestry prior contribution

    Observer-only:
        - reads from FutureValueSelector comparisons
        - writes only to internal bounded deque(maxlen=48)
        - does NOT alter branch selection, scoring, or any Pack 1-4 state

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=48):
        self._history   = deque(maxlen=maxlen)
        self._maxlen    = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def _compute_factor_contributions(self, future_value_selector, selected_branch_id):
        if not future_value_selector:
            return None
        sel_rec = future_value_selector.latest()
        if not sel_rec:
            return None
        comparisons = sel_rec.get('comparisons', [])
        selected_comp = None
        for comp in comparisons:
            if comp.get('branch_id') == selected_branch_id:
                selected_comp = comp
                break
        if not selected_comp:
            return None
        integrity = float(selected_comp.get('projected_integrity', 0.5))
        rollback = float(selected_comp.get('rollback_survivability', 0.5))
        drift = float(selected_comp.get('predicted_drift', 0.5))
        ancestry = float(selected_comp.get('ancestry_success_prior', 0.5))
        integrity_contrib = integrity * 0.35
        rollback_contrib = rollback * 0.25
        drift_contrib = (1.0 - drift) * 0.20
        ancestry_contrib = ancestry * 0.15
        total = integrity_contrib + rollback_contrib + drift_contrib + ancestry_contrib
        if total > 0:
            norm_integrity = integrity_contrib / total
            norm_rollback = rollback_contrib / total
            norm_drift = drift_contrib / total
            norm_ancestry = ancestry_contrib / total
        else:
            norm_integrity = norm_rollback = norm_drift = norm_ancestry = 0.25
        return {
            'integrity_contribution': float(round(integrity_contrib, 4)),
            'rollback_contribution': float(round(rollback_contrib, 4)),
            'drift_contribution': float(round(drift_contrib, 4)),
            'ancestry_contribution': float(round(ancestry_contrib, 4)),
            'norm_integrity': float(round(self._clamp(norm_integrity), 4)),
            'norm_rollback': float(round(self._clamp(norm_rollback), 4)),
            'norm_drift': float(round(self._clamp(norm_drift), 4)),
            'norm_ancestry': float(round(self._clamp(norm_ancestry), 4)),
            'factor_sum': float(round(total, 4)),
        }

    def update(self, tick, future_value_selector, branch_deliberation_confidence):
        sel_rec = future_value_selector.latest() if future_value_selector else None
        if not sel_rec:
            record = {
                'tick':            int(tick),
                'selected_branch_id': None,
                'factors':         None,
                'final_score':    0.0,
                'lineage_confidence': 0.0,
                'state':           'no_selection',
            }
            self._history.append(record)
            return record
        selected_branch_id = sel_rec.get('selected_branch_id')
        final_score = float(sel_rec.get('decision_score', 0.5))
        factors = self._compute_factor_contributions(future_value_selector, selected_branch_id)
        conf_rec = branch_deliberation_confidence.latest() if branch_deliberation_confidence else None
        lineage_confidence = conf_rec.get('confidence', 0.0) if conf_rec else 0.0
        record = {
            'tick':               int(tick),
            'selected_branch_id': selected_branch_id,
            'factors':            factors,
            'final_score':        float(round(final_score, 4)),
            'lineage_confidence': float(round(lineage_confidence, 4)),
            'state':              sel_rec.get('selection_state', 'unknown'),
            'selection_summary':  sel_rec.get('selection_summary', ''),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._history[-1]
        factors = latest.get('factors')
        stability = 0.5
        if factors:
            coherence = (
                factors.get('norm_integrity', 0.0) +
                factors.get('norm_rollback', 0.0) +
                factors.get('norm_drift', 0.0) +
                factors.get('norm_ancestry', 0.0)
            )
            stability = self._clamp(coherence / 4.0)
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'latest_state': latest.get('state', 'unknown'),
            'stability_score': float(round(stability, 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 48)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class BranchOutcomeArchive:
    """
    Archives branch families, selected futures, and ancestry priors over time.

    Maintains:
        - branch family
        - chosen branch
        - predicted score
        - actual score
        - long-term selection bias
        - branch lineage signature

    family_prior_for(family_signature) returns:
        0.70 * ema_predicted_score + 0.30 * win_rate

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=128):
        self._archives     = deque(maxlen=maxlen)
        self._maxlen       = maxlen
        self._family_stats = {}
        self._lineages     = {}

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _clamp_signed(v: float) -> float:
        return max(-1.0, min(1.0, float(v)))

    def family_prior_for(self, family_signature: str | None) -> float:
        if not family_signature or family_signature not in self._family_stats:
            return 0.50
        stats    = self._family_stats[family_signature]
        win_rate = stats['wins'] / max(1, stats['observations'])
        return self._clamp(stats['ema_predicted_score'] * 0.70 + win_rate * 0.30)

    def lineage_for(self, branch_id: str):
        return self._lineages.get(branch_id)

    def archive(self, tick, trajectory_branch_generator, future_value_selector,
                cross_region_commit_graph, pre_commit_outcome_memory):
        gen_rec    = trajectory_branch_generator.latest()
        sel_rec    = future_value_selector.latest()
        commit_rec = cross_region_commit_graph.latest()

        branches = gen_rec.get('branches', []) if gen_rec else []
        selected_branch_id = sel_rec.get('selected_branch_id') if sel_rec else None
        selected_family    = sel_rec.get('selected_family_signature') if sel_rec else None
        comparisons = {
            c['branch_id']: c for c in (sel_rec.get('comparisons', []) if sel_rec else [])
        }

        commit_id       = commit_rec.get('commit_id') if commit_rec else None
        rollback_parent = commit_rec.get('rollback_parent') if commit_rec else None
        actual_score    = float(commit_rec.get('success_score', 0.5)) if commit_rec else 0.5

        archived_families = []
        for branch in branches:
            branch_id   = branch.get('branch_id')
            family_sig  = branch.get('family_signature')
            chain_sig   = branch.get('chain_signature', 'empty')
            comp_rec    = comparisons.get(branch_id, {})
            predicted   = float(comp_rec.get('predicted_score', 0.50))
            decision    = float(comp_rec.get('decision_score', predicted))
            selected    = branch_id == selected_branch_id
            future_bias = (pre_commit_outcome_memory.bias_for(chain_sig)
                           if pre_commit_outcome_memory else 0.0)

            stats = self._family_stats.get(family_sig, {
                'ema_predicted_score': 0.50,
                'ema_actual_score':    0.50,
                'selection_bias':      0.0,
                'observations':        0,
                'wins':                0,
            })
            stats['ema_predicted_score'] = self._clamp(
                stats['ema_predicted_score'] * 0.85 + predicted * 0.15)
            stats['ema_actual_score'] = self._clamp(
                stats['ema_actual_score'] * 0.85 + actual_score * 0.15)
            stats['selection_bias'] = self._clamp_signed(
                stats['selection_bias'] * 0.90 + (actual_score - predicted) * 0.10)
            stats['observations'] += 1
            if selected:
                stats['wins'] += 1
                stats['last_selected_branch_id'] = branch_id
            stats['last_tick'] = int(tick)
            stats['last_chain_signature'] = chain_sig
            stats['source_commit_id'] = commit_id
            stats['rollback_parent'] = rollback_parent
            self._family_stats[family_sig] = stats

            self._lineages[branch_id] = {
                'tick':                       int(tick),
                'family_signature':           family_sig,
                'chain_signature':            chain_sig,
                'source_commit_id':           commit_id,
                'rollback_parent':            rollback_parent,
                'selected':                   selected,
                'requires_biology_escalation': branch.get('requires_biology_escalation', False),
            }
            if len(self._lineages) > 256:
                oldest = next(iter(self._lineages))
                del self._lineages[oldest]

            archived_families.append({
                'branch_id':         branch_id,
                'family_signature':  family_sig,
                'predicted_score':   float(round(predicted, 4)),
                'decision_score':    float(round(decision, 4)),
                'actual_score':      float(round(actual_score, 4)),
                'selected':          selected,
                'future_bias':       float(round(future_bias, 4)),
                'selection_bias':    float(round(stats['selection_bias'], 4)),
                'family_prior':      float(round(self.family_prior_for(family_sig), 4)),
                'lineage_signature': chain_sig,
                'source_commit_id':  commit_id,
                'rollback_parent':   rollback_parent,
            })

        record = {
            'tick':                       int(tick),
            'selected_branch_id':         selected_branch_id,
            'selected_family_signature':  selected_family,
            'family_count':               len(archived_families),
            'source_commit_id':           commit_id,
            'rollback_parent':            rollback_parent,
            'actual_score':               float(round(actual_score, 4)),
            'archived_families':          archived_families,
            'archive_summary':            (
                f"Tick {tick}: archived {len(archived_families)} branch families. "
                f"selected={selected_branch_id} actual={actual_score:.3f} "
                f"parent={rollback_parent}."
            ),
        }
        self._archives.append(record)
        return record

    def latest(self): return self._archives[-1] if self._archives else None
    def recent(self, n=10):
        buf = list(self._archives)
        return buf[-n:] if n < len(buf) else buf
    def __len__(self): return len(self._archives)

    def summary(self):
        if not self._archives:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._archives[-1]
        selected_branch_id = latest.get('selected_branch_id')
        lineage = self._lineages.get(selected_branch_id) if selected_branch_id else None
        family_sig = lineage.get('family_signature') if lineage else None
        stability = 0.5
        if family_sig and family_sig in self._family_stats:
            stats = self._family_stats[family_sig]
            stability = self._clamp(stats.get('ema_actual_score', 0.5))
        return {
            'history_len': len(self._archives),
            'latest_tick': latest.get('tick'),
            'latest_state': latest.get('selection_state', 'unknown'),
            'stability_score': float(round(stability, 4)),
        }

    def to_dict(self):
        return {
            'maxlen':       self._maxlen,
            'archives':     list(self._archives),
            'family_stats': dict(self._family_stats),
            'lineages':     dict(self._lineages),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 128)))
        for rec in d.get('archives', []):
            obj._archives.append(rec)
        obj._family_stats = dict(d.get('family_stats', {}))
        obj._lineages = dict(d.get('lineages', {}))
        return obj


# ===========================================================================
# DAY 26 PHASE 2B: Selected Branch Intent Bridge
# Shadow decision-to-intent coupling - observer mode only
# ===========================================================================

class SelectedBranchIntentBridge:
    """
    Converts selected Pack 4 future branch into shadow edit-intent recommendation.

    Bridge scoring law:
        bridge_confidence = selected_branch_score * branch_deliberation_confidence * intent_schema_match

    Observer-shadow mode:
        - generates shadow_edit_intent
        - does NOT mutate edit_intent_generator
        - no execution routing changes

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def _compute_schema_match(self, edit_intent_generator, selected_branch_id, selected_strategy):
        if not edit_intent_generator:
            return 0.80
        intent_rec = edit_intent_generator.latest()
        if not intent_rec:
            return 0.80
        real_intent = intent_rec.get('intent_summary', '')
        if not real_intent:
            return 0.80
        branch_keywords = []
        if selected_strategy:
            branch_keywords = [selected_strategy.lower()]
        if selected_branch_id:
            branch_keywords.append(selected_branch_id.lower())
        match_count = sum(1 for kw in branch_keywords if kw and kw in real_intent.lower())
        return self._clamp(0.5 + (match_count / max(1, len(branch_keywords))) * 0.5) if branch_keywords else 0.80

    def update(self, tick, future_value_selector, branch_deliberation_confidence,
               branch_reasoning_trace, edit_intent_generator):
        sel_rec = future_value_selector.latest() if future_value_selector else None
        if not sel_rec:
            record = {
                'tick': int(tick),
                'selected_branch_id': None,
                'shadow_edit_intent': None,
                'bridge_confidence': 0.0,
                'selection_reason': 'no_selection',
                'intent_schema_match': 0.80,
            }
            self._history.append(record)
            return record
        selected_branch_id = sel_rec.get('selected_branch_id')
        selected_strategy = sel_rec.get('selected_strategy')
        selected_score = float(sel_rec.get('decision_score', 0.5))
        conf_rec = branch_deliberation_confidence.latest() if branch_deliberation_confidence else None
        branch_confidence = conf_rec.get('confidence', 0.5) if conf_rec else 0.5
        trace_rec = branch_reasoning_trace.latest() if branch_reasoning_trace else None
        selection_reason = ''
        if trace_rec and trace_rec.get('factors'):
            factors = trace_rec['factors']
            top_factor = max(factors.keys(), key=lambda k: factors.get(k, 0) if 'norm' in k else 0)
            selection_reason = f"top_factor={top_factor}"
        schema_match = self._compute_schema_match(edit_intent_generator, selected_branch_id, selected_strategy)
        bridge_confidence = self._clamp(selected_score * branch_confidence * schema_match)
        shadow_intent = f"shadow_intent_{selected_strategy}_{selected_branch_id}" if selected_branch_id else None
        record = {
            'tick': int(tick),
            'selected_branch_id': selected_branch_id,
            'selected_strategy': selected_strategy,
            'shadow_edit_intent': shadow_intent,
            'bridge_confidence': float(round(bridge_confidence, 4)),
            'selection_reason': selection_reason,
            'intent_schema_match': float(round(schema_match, 4)),
            'selection_summary': sel_rec.get('selection_summary', ''),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._history[-1]
        stability = latest.get('bridge_confidence', 0.5)
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'latest_state': 'bridge_active' if latest.get('selected_branch_id') else 'no_selection',
            'stability_score': float(round(self._clamp(stability), 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class IntentConsistencyAuditor:
    """
    Audits whether shadow intent matches real downstream intent schema.

    States:
        - aligned: shadow matches real intent
        - schema_partial: partial overlap
        - schema_mismatch: no meaningful overlap
        - no_real_intent: no real intent to compare

    Pre-steering safety layer. Observer-only.
    """

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def audit(self, tick, selected_branch_intent_bridge, edit_intent_generator):
        bridge_rec = selected_branch_intent_bridge.latest() if selected_branch_intent_bridge else None
        if not bridge_rec or not bridge_rec.get('selected_branch_id'):
            record = {
                'tick': int(tick),
                'audit_state': 'no_real_intent',
                'overlap_score': 0.0,
                'shadow_intent': None,
                'real_intent_summary': None,
            }
            self._history.append(record)
            return record
        shadow_intent = bridge_rec.get('shadow_edit_intent')
        intent_rec = edit_intent_generator.latest() if edit_intent_generator else None
        if not intent_rec:
            state = 'no_real_intent'
            overlap = 0.0
            real_summary = None
        else:
            real_summary = intent_rec.get('intent_summary', '')
            if not real_summary:
                state = 'no_real_intent'
                overlap = 0.0
            else:
                shadow_str = str(shadow_intent) if shadow_intent else ''
                shadow_words = set(shadow_str.lower().split('_'))
                real_words = set(real_summary.lower().split())
                overlap = len(shadow_words & real_words) / max(1, len(shadow_words | real_words))
                if overlap >= 0.5:
                    state = 'aligned'
                elif overlap >= 0.2:
                    state = 'schema_partial'
                else:
                    state = 'schema_mismatch'
        record = {
            'tick': int(tick),
            'audit_state': state,
            'overlap_score': float(round(self._clamp(overlap), 4)),
            'shadow_intent': shadow_intent,
            'real_intent_summary': real_summary,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._history[-1]
        stability = latest.get('overlap_score', 0.5)
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'latest_state': latest.get('audit_state', 'unknown'),
            'stability_score': float(round(self._clamp(stability), 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class BridgeOutcomeMemory:
    """
    Persists bridge outcomes for learning whether branch-selected futures
    produce coherent intent recommendations.

    Stores:
        - selected branch id
        - shadow intent hash
        - bridge confidence
        - audit state
        - actual downstream intent summary
        - bridge error signal

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def _hash_intent(self, intent_str):
        if not intent_str:
            return 'none'
        return str(abs(hash(intent_str)))

    def trace(self, tick, selected_branch_intent_bridge, intent_consistency_auditor,
              edit_intent_generator, branch_deliberation_confidence):
        bridge_rec = selected_branch_intent_bridge.latest() if selected_branch_intent_bridge else None
        audit_rec = intent_consistency_auditor.latest() if intent_consistency_auditor else None
        conf_rec = branch_deliberation_confidence.latest() if branch_deliberation_confidence else None
        if not bridge_rec:
            record = {
                'tick': int(tick),
                'selected_branch_id': None,
                'shadow_intent_hash': 'none',
                'bridge_confidence': 0.0,
                'audit_state': 'no_bridge',
                'actual_intent_summary': None,
                'bridge_error': 1.0,
            }
            self._history.append(record)
            return record
        selected_branch_id = bridge_rec.get('selected_branch_id')
        shadow_intent = bridge_rec.get('shadow_edit_intent')
        shadow_hash = self._hash_intent(shadow_intent) if shadow_intent else 'none'
        bridge_confidence = bridge_rec.get('bridge_confidence', 0.5)
        audit_state = audit_rec.get('audit_state', 'unknown') if audit_rec else 'unknown'
        intent_rec = edit_intent_generator.latest() if edit_intent_generator else None
        actual_summary = intent_rec.get('intent_summary', '') if intent_rec else ''
        error_signal = 0.0
        if audit_state == 'aligned':
            error_signal = 0.0
        elif audit_state == 'schema_partial':
            error_signal = 0.3
        elif audit_state == 'schema_mismatch':
            error_signal = 0.7
        else:
            error_signal = 0.5
        record = {
            'tick': int(tick),
            'selected_branch_id': selected_branch_id,
            'shadow_intent_hash': shadow_hash,
            'bridge_confidence': float(round(bridge_confidence, 4)),
            'audit_state': audit_state,
            'actual_intent_summary': actual_summary[:200] if actual_summary else None,
            'bridge_error': float(round(error_signal, 4)),
            'lineage_confidence': conf_rec.get('confidence', 0.5) if conf_rec else 0.5,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {
                'history_len': 0,
                'latest_tick': None,
                'latest_state': 'empty',
                'stability_score': 0.5,
            }
        latest = self._history[-1]
        stability = 1.0 - latest.get('bridge_error', 0.5)
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'latest_state': latest.get('audit_state', 'unknown'),
            'stability_score': float(round(self._clamp(stability), 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


