class SelectedBranchExecutionBridge:
    """
    Converts shadow bridge confidence into a bounded live steering bias
    for downstream edit intent generation.

    Gating law (ALL conditions must hold):
        bridge_confidence  >= 0.70
        audit_state        == 'aligned'
        bridge_error       <= 0.30
        rollback_survivability >= 0.65

    Biology rule (no exceptions):
        If selected branch carries biology escalation -> steering_bias = 0.0

    Steering bias formula (when gating passes and no biology):
        steering_bias = clamp(bridge_confidence * 0.35, 0.0, 0.35)

    Outputs:
        steering_bias        -- float [0.0, 0.35]
        steering_enabled     -- bool
        bias_reason          -- str
        steered_intent_hint  -- str or None

    Waking-only. Zero survival contamination.
    """

    BIAS_MAX          = 0.35
    GATE_CONFIDENCE   = 0.70
    GATE_ERROR        = 0.30
    GATE_SURVIVABILITY = 0.65

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v: float, lo: float = 0.0, hi: float = 1.0) -> float:
        return max(lo, min(hi, float(v)))

    def _selected_rollback_survivability(self, future_value_selector):
        if not future_value_selector:
            return 1.0
        sel_rec = future_value_selector.latest()
        if not sel_rec:
            return 1.0
        selected_id = sel_rec.get('selected_branch_id')
        for comp in sel_rec.get('comparisons', []):
            if comp.get('branch_id') == selected_id:
                return float(comp.get('rollback_survivability', 1.0))
        return 1.0

    def _selected_biology_escalation(self, future_value_selector):
        if not future_value_selector:
            return False
        sel_rec = future_value_selector.latest()
        if not sel_rec:
            return False
        selected_id = sel_rec.get('selected_branch_id')
        for comp in sel_rec.get('comparisons', []):
            if comp.get('branch_id') == selected_id:
                return bool(comp.get('requires_biology_escalation', False))
        return False

    def update(self, tick, bridge_outcome_memory, future_value_selector,
               branch_outcome_archive):
        outcome_rec = bridge_outcome_memory.latest() if bridge_outcome_memory else None
        if not outcome_rec:
            record = {
                'tick':                int(tick),
                'steering_enabled':    False,
                'steering_bias':       0.0,
                'bias_reason':         'no_bridge_data',
                'steered_intent_hint': None,
                'gate_confidence':     0.0,
                'gate_error':          1.0,
                'gate_survivability':  0.0,
                'biology_suppressed':  False,
            }
            self._history.append(record)
            return record

        bridge_confidence      = float(outcome_rec.get('bridge_confidence', 0.0))
        audit_state            = outcome_rec.get('audit_state', 'unknown')
        bridge_error           = float(outcome_rec.get('bridge_error', 1.0))
        selected_branch_id     = outcome_rec.get('selected_branch_id')
        rollback_survivability = self._selected_rollback_survivability(future_value_selector)
        biology_escalation     = self._selected_biology_escalation(future_value_selector)

        if biology_escalation:
            record = {
                'tick':                int(tick),
                'steering_enabled':    False,
                'steering_bias':       0.0,
                'bias_reason':         'biology_suppressed',
                'steered_intent_hint': None,
                'gate_confidence':     float(round(bridge_confidence, 4)),
                'gate_error':          float(round(bridge_error, 4)),
                'gate_survivability':  float(round(rollback_survivability, 4)),
                'biology_suppressed':  True,
            }
            self._history.append(record)
            return record

        gate_pass = (
            bridge_confidence      >= self.GATE_CONFIDENCE      and
            audit_state            == 'aligned'                 and
            bridge_error           <= self.GATE_ERROR           and
            rollback_survivability >= self.GATE_SURVIVABILITY
        )

        if not gate_pass:
            reasons = []
            if bridge_confidence < self.GATE_CONFIDENCE:
                reasons.append(f'conf_low({bridge_confidence:.3f})')
            if audit_state != 'aligned':
                reasons.append(f'audit_{audit_state}')
            if bridge_error > self.GATE_ERROR:
                reasons.append(f'err_high({bridge_error:.3f})')
            if rollback_survivability < self.GATE_SURVIVABILITY:
                reasons.append(f'surv_low({rollback_survivability:.3f})')
            record = {
                'tick':                int(tick),
                'steering_enabled':    False,
                'steering_bias':       0.0,
                'bias_reason':         'steering_disabled:' + ','.join(reasons),
                'steered_intent_hint': None,
                'gate_confidence':     float(round(bridge_confidence, 4)),
                'gate_error':          float(round(bridge_error, 4)),
                'gate_survivability':  float(round(rollback_survivability, 4)),
                'biology_suppressed':  False,
            }
            self._history.append(record)
            return record

        steering_bias = self._clamp(
            bridge_confidence * self.BIAS_MAX,
            lo=0.0, hi=self.BIAS_MAX
        )
        sel_rec           = future_value_selector.latest() if future_value_selector else None
        selected_strategy = sel_rec.get('selected_strategy', '') if sel_rec else ''
        steered_hint      = (
            f"steer:{selected_strategy}:{selected_branch_id}"
            if selected_branch_id else None
        )
        record = {
            'tick':                int(tick),
            'steering_enabled':    True,
            'steering_bias':       float(round(steering_bias, 4)),
            'bias_reason':         f'gated_pass:conf={bridge_confidence:.3f}',
            'steered_intent_hint': steered_hint,
            'gate_confidence':     float(round(bridge_confidence, 4)),
            'gate_error':          float(round(bridge_error, 4)),
            'gate_survivability':  float(round(rollback_survivability, 4)),
            'biology_suppressed':  False,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'latest_state': 'empty', 'stability_score': 0.5}
        latest = self._history[-1]
        bias_norm = latest.get('steering_bias', 0.0) / self.BIAS_MAX
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'latest_state':   'steering_enabled' if latest.get('steering_enabled') else 'steering_disabled',
            'stability_score': float(round(self._clamp(bias_norm), 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ExecutionOutcomeComparator:
    """
    Compares predicted branch-steered edit intent against actual intent output.

    Captures action-reality mismatch for strategic policy shaper.

    execution_alignment_score  [0, 1] -- match between steered hint and actual intent
    steering_error             [0, 1] -- divergence combining alignment, integrity, rollback
    policy_delta               [-1,1] -- signed direction signal (+1 success, -1 failure)

    Uses latest() values from upstream systems (one-tick feedback lag -- biologically
    plausible and rollback-safe).

    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _clamp_signed(v: float) -> float:
        return max(-1.0, min(1.0, float(v)))

    def _intent_alignment(self, steered_hint, actual_summary):
        if not steered_hint or not actual_summary:
            return 0.5
        hint_words   = {w for w in str(steered_hint).lower().replace(':', '_').split('_') if len(w) > 2}
        actual_words = set(str(actual_summary).lower().split())
        if not hint_words or not actual_words:
            return 0.5
        overlap = len(hint_words & actual_words)
        union   = len(hint_words | actual_words)
        raw = overlap / max(1, union)
        return self._clamp(raw + 0.30)

    def compare(self, tick, selected_branch_execution_bridge, edit_intent_generator,
                rollback_controller, integrity_scorer, invariant_drift_estimator):
        bridge_rec = selected_branch_execution_bridge.latest() if selected_branch_execution_bridge else None

        if not bridge_rec or not bridge_rec.get('steering_enabled'):
            record = {
                'tick':                       int(tick),
                'steering_active':            False,
                'execution_alignment_score':  0.5,
                'steering_error':             0.0,
                'policy_delta':               0.0,
                'comparator_state':           'no_steering',
                'rollback_active':            False,
                'patch_integrity':            0.5,
                'invariant_drift':            'stable_projection',
            }
            self._history.append(record)
            return record

        steered_hint   = bridge_rec.get('steered_intent_hint')
        intent_rec     = edit_intent_generator.latest() if edit_intent_generator else None
        actual_summary = intent_rec.get('intent_summary', '') if intent_rec else ''

        alignment = self._intent_alignment(steered_hint, actual_summary)

        rollback_rec   = rollback_controller.latest() if rollback_controller else None
        rollback_state = rollback_rec.get('rollback_state', 'monitor') if rollback_rec else 'monitor'
        rollback_active = rollback_state in ('rollback_to_last_stable', 'hold_previous')

        integrity_rec  = integrity_scorer.latest() if integrity_scorer else None
        patch_integrity = float(integrity_rec.get('integrity_score', 0.5)) if integrity_rec else 0.5

        drift_rec      = invariant_drift_estimator.latest() if invariant_drift_estimator else None
        invariant_drift = drift_rec.get('drift_state', 'stable_projection') if drift_rec else 'stable_projection'

        drift_penalty    = 0.20 if invariant_drift in ('biology_projection_risk', 'serialization_projection_risk') else 0.0
        rollback_penalty = 0.30 if rollback_active else 0.0
        steering_error   = self._clamp(
            (1.0 - alignment) * 0.50 +
            (1.0 - patch_integrity) * 0.30 +
            rollback_penalty + drift_penalty
        )

        if alignment >= 0.60 and not rollback_active and patch_integrity >= 0.60:
            policy_delta = self._clamp_signed(alignment - 0.50)
        else:
            policy_delta = self._clamp_signed(-steering_error)

        record = {
            'tick':                       int(tick),
            'steering_active':            True,
            'execution_alignment_score':  float(round(alignment, 4)),
            'steering_error':             float(round(steering_error, 4)),
            'policy_delta':               float(round(policy_delta, 4)),
            'comparator_state':           'aligned' if alignment >= 0.60 else 'diverged',
            'rollback_active':            rollback_active,
            'patch_integrity':            float(round(patch_integrity, 4)),
            'invariant_drift':            invariant_drift,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'latest_state': 'empty', 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'latest_state':   latest.get('comparator_state', 'unknown'),
            'stability_score': float(round(self._clamp(latest.get('execution_alignment_score', 0.5)), 4)),
        }

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class StrategicPolicyShaper:
    """
    Converts repeated successful steering events into long-horizon execution policies.

    Per branch-family statistics (keyed by strategy name):
        ema_success_rate    -- EMA of positive policy_delta events
        policy_confidence   -- 0.7 * ema_success_rate + 0.3 * (1 - failure_suppression)
        safe_bias_prior     -- EMA of steering_bias values on success ticks [0, 0.35]
        failure_suppression -- EMA of steering_error (high = suppress future bias)

    Policy update law (EMA_ALPHA = 0.10):
        ema = old * 0.90 + new * 0.10

    safe_bias_for(family_sig) -> float [0.0, 0.35]
        Returns accumulated safe bias prior for use by downstream steering.
        Returns 0.0 if family has no history.

    Policy states:
        policy_mature   -- confidence >= 0.70
        policy_forming  -- ema_success_rate >= 0.60
        policy_learning -- steering active, no threshold reached yet
        steering_disabled -- no active steering this tick

    Waking-only. Zero survival contamination.
    """

    EMA_ALPHA = 0.10
    BIAS_MAX  = 0.35

    def __init__(self, maxlen=64):
        self._history  = deque(maxlen=maxlen)
        self._maxlen   = maxlen
        self._policies = {}

    @staticmethod
    def _clamp(v: float) -> float:
        return max(0.0, min(1.0, float(v)))

    def _ema(self, old: float, new: float) -> float:
        return self._clamp(old * (1.0 - self.EMA_ALPHA) + new * self.EMA_ALPHA)

    def _update_policy(self, family_sig, steering_bias, policy_delta, steering_error,
                       steering_enabled):
        if family_sig not in self._policies:
            self._policies[family_sig] = {
                'ema_success_rate':    0.50,
                'policy_confidence':   0.50,
                'safe_bias_prior':     0.00,
                'failure_suppression': 0.50,
                'observations':        0,
            }
        pol = self._policies[family_sig]
        pol['observations'] = int(pol['observations']) + 1
        if not steering_enabled:
            return
        success_signal = 1.0 if policy_delta > 0.0 else 0.0
        pol['ema_success_rate']    = self._ema(pol['ema_success_rate'],    success_signal)
        pol['failure_suppression'] = self._ema(pol['failure_suppression'], steering_error)
        pol['safe_bias_prior']     = max(0.0, min(self.BIAS_MAX,
            pol['safe_bias_prior'] * (1.0 - self.EMA_ALPHA) +
            min(steering_bias, self.BIAS_MAX) * self.EMA_ALPHA
        ))
        pol['policy_confidence']   = self._clamp(
            pol['ema_success_rate'] * 0.70 +
            (1.0 - pol['failure_suppression']) * 0.30
        )

    def update(self, tick, selected_branch_execution_bridge, execution_outcome_comparator):
        bridge_rec     = selected_branch_execution_bridge.latest() if selected_branch_execution_bridge else None
        comparator_rec = execution_outcome_comparator.latest()     if execution_outcome_comparator     else None

        if not bridge_rec:
            record = {
                'tick':               int(tick),
                'family_sig':         'unknown',
                'policy_state':       'no_data',
                'policy_confidence':  0.50,
                'safe_bias_prior':    0.00,
                'ema_success_rate':   0.50,
                'failure_suppression': 0.50,
                'policy_count':       0,
            }
            self._history.append(record)
            return record

        steering_enabled = bool(bridge_rec.get('steering_enabled', False))
        steering_bias    = float(bridge_rec.get('steering_bias', 0.0))
        hint             = bridge_rec.get('steered_intent_hint') or ''
        parts            = hint.split(':')
        family_sig       = parts[1] if len(parts) >= 2 else 'unknown'

        policy_delta   = float(comparator_rec.get('policy_delta',   0.0)) if comparator_rec else 0.0
        steering_error = float(comparator_rec.get('steering_error', 0.5)) if comparator_rec else 0.5

        self._update_policy(family_sig, steering_bias, policy_delta, steering_error, steering_enabled)
        pol = self._policies.get(family_sig, {})

        if steering_enabled:
            conf = pol.get('policy_confidence', 0.5)
            if conf >= 0.70:
                policy_state = 'policy_mature'
            elif pol.get('ema_success_rate', 0.5) >= 0.60:
                policy_state = 'policy_forming'
            else:
                policy_state = 'policy_learning'
        else:
            policy_state = 'steering_disabled'

        record = {
            'tick':               int(tick),
            'family_sig':         family_sig,
            'policy_state':       policy_state,
            'policy_confidence':  float(round(pol.get('policy_confidence',  0.5), 4)),
            'safe_bias_prior':    float(round(pol.get('safe_bias_prior',    0.0), 4)),
            'ema_success_rate':   float(round(pol.get('ema_success_rate',   0.5), 4)),
            'failure_suppression': float(round(pol.get('failure_suppression', 0.5), 4)),
            'policy_count':       int(len(self._policies)),
        }
        self._history.append(record)
        return record

    def safe_bias_for(self, family_sig: str) -> float:
        pol = self._policies.get(family_sig)
        if not pol:
            return 0.0
        return max(0.0, min(self.BIAS_MAX, float(pol.get('safe_bias_prior', 0.0))))

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'latest_state': 'empty', 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'latest_state':   latest.get('policy_state', 'unknown'),
            'stability_score': float(round(self._clamp(latest.get('policy_confidence', 0.5)), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':   self._maxlen,
            'history':  list(self._history),
            'policies': dict(self._policies),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._policies = d.get('policies', {})
        return obj


