class PolicyConditionedSubgoalRouter:
    """
    Routes action habits into bounded subgoal arcs conditioned on policy priors.

    Policy priors from StrategicPolicyShaper are the primary routing signal.
    Rollback events compress the active horizon by 2 (min 2). Protected
    biology families receive zero routing (active_horizon=0, empty chain).

    active_horizon in [2, 6]
    route_confidence in [0.0, 1.0]

    Rollback penalty law:
        if rollback_active: active_horizon -= 2, clamped to [2, 6]
        else: slow recovery +1 per tick toward HORIZON_MAX

    Biology families (zero routing):
        neuron, synapse, homeostasis, hpa, cortisol, adenosine

    Waking-only. Zero survival contamination.
    """

    HORIZON_MAX      = 6
    HORIZON_MIN      = 2
    ROLLBACK_PENALTY = 2
    BIOLOGY_TOKENS   = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa', 'cortisol',
        'adenosine', 'homeostatic', 'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=64):
        self._history        = deque(maxlen=maxlen)
        self._maxlen         = maxlen
        self._active_horizon = 4

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _clamp_horizon(v):
        return max(2, min(6, int(v)))

    def _is_biology_family(self, family_sig):
        if not family_sig:
            return False
        key = str(family_sig).lower().replace('_', '').replace('-', '')
        for token in self.BIOLOGY_TOKENS:
            if token in key:
                return True
        return False

    def update(self, state):
        """Unified interface (Day 32)."""
        return self._route(
            tick                             = state.tick,
            strategic_policy_shaper          = state.strategic_policy_shaper,
            selected_branch_execution_bridge = state.selected_branch_execution_bridge,
            execution_outcome_comparator     = state.execution_outcome_comparator,
        )

    def _route(self, tick, strategic_policy_shaper, selected_branch_execution_bridge,
               execution_outcome_comparator):
        bridge_rec     = selected_branch_execution_bridge.latest() if selected_branch_execution_bridge else None
        comparator_rec = execution_outcome_comparator.latest()     if execution_outcome_comparator     else None
        shaper_rec     = strategic_policy_shaper.latest()          if strategic_policy_shaper         else None

        # Extract family_sig from bridge hint (steer:family:branch_id format)
        family_sig = 'unknown'
        if bridge_rec:
            hint  = bridge_rec.get('steered_intent_hint') or ''
            parts = hint.split(':')
            family_sig = parts[1] if len(parts) >= 2 else 'unknown'
        elif shaper_rec:
            family_sig = shaper_rec.get('family_sig', 'unknown')

        # Biology exclusion: zero routing, no subgoal chain
        if self._is_biology_family(family_sig):
            record = {
                'tick':               int(tick),
                'family_sig':         family_sig,
                'active_horizon':     0,
                'route_confidence':   0.0,
                'subgoal_chain':      [],
                'biology_excluded':   True,
                'rollback_compressed': False,
            }
            self._history.append(record)
            return record

        # Rollback penalty: compress active horizon
        rollback_active = False
        if comparator_rec:
            rollback_active = bool(comparator_rec.get('rollback_active', False))
        if rollback_active:
            self._active_horizon = self._clamp_horizon(
                self._active_horizon - self.ROLLBACK_PENALTY
            )
        elif self._active_horizon < self.HORIZON_MAX:
            self._active_horizon = self._clamp_horizon(self._active_horizon + 1)

        # Policy priors: primary routing signal
        policy_confidence = 0.5
        safe_bias_prior   = 0.0
        if shaper_rec:
            policy_confidence = float(shaper_rec.get('policy_confidence', 0.5))
        if strategic_policy_shaper and family_sig != 'unknown':
            safe_bias_prior = float(strategic_policy_shaper.safe_bias_for(family_sig))

        # Route confidence: weighted by policy confidence and normalized safe bias
        bias_norm        = min(1.0, safe_bias_prior / max(0.001, StrategicPolicyShaper.BIAS_MAX))
        route_confidence = self._clamp(policy_confidence * 0.60 + bias_norm * 0.40)

        # Divergence modulation: dampen confidence when comparator diverged
        if comparator_rec and comparator_rec.get('comparator_state') == 'diverged':
            route_confidence = self._clamp(route_confidence * 0.70)

        # Build subgoal chain (bounded by active_horizon)
        steering_enabled = bool(bridge_rec.get('steering_enabled', False)) if bridge_rec else False
        subgoal_chain = []
        if steering_enabled and route_confidence >= 0.40:
            for i in range(self._active_horizon):
                priority = self._clamp(route_confidence * (1.0 - i * 0.12))
                subgoal_chain.append({
                    'step':           i + 1,
                    'target_family':  family_sig,
                    'priority_score': float(round(priority, 4)),
                })

        record = {
            'tick':               int(tick),
            'family_sig':         family_sig,
            'active_horizon':     int(self._active_horizon),
            'route_confidence':   float(round(route_confidence, 4)),
            'subgoal_chain':      subgoal_chain,
            'biology_excluded':   False,
            'rollback_compressed': rollback_active,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'latest_horizon': 0, 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'latest_horizon': latest.get('active_horizon', 0),
            'stability_score': float(round(latest.get('route_confidence', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':          self._maxlen,
            'history':         list(self._history),
            'active_horizon':  self._active_horizon,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._active_horizon = int(d.get('active_horizon', 4))
        return obj


class ExecutionHorizonPlanner:
    """
    Converts routed subgoal chains into horizon-aware execution arcs.

    Outputs per record:
        execution_steps    -- ordered step dicts (region, action_hint, risk, priority)
        expected_regions   -- unique regions expected to be touched
        risk_decay_curve   -- per-step risk [0, 1], grows with step index
        checkpoint_ticks   -- estimated absolute tick offsets for checks
        horizon_len        -- number of planned steps (max 6)
        arc_confidence     -- [0, 1] weighted from route and policy confidence

    Empty arc produced for biology-excluded families or absent routing data.
    Max horizon = 6 enforced unconditionally (EEIL sparse compute law).
    Waking-only. Zero survival contamination.
    """

    HORIZON_MAX    = 6
    TICKS_PER_STEP = 50

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, state):
        """Unified interface (Day 32)."""
        return self._plan(
            tick                              = state.tick,
            policy_conditioned_subgoal_router = state.policy_conditioned_subgoal_router,
            strategic_policy_shaper           = state.strategic_policy_shaper,
            integrity_scorer                  = state.integrity_scorer,
        )

    def _plan(self, tick, policy_conditioned_subgoal_router, strategic_policy_shaper,
              integrity_scorer):
        router_rec = policy_conditioned_subgoal_router.latest() if policy_conditioned_subgoal_router else None
        shaper_rec = strategic_policy_shaper.latest()           if strategic_policy_shaper           else None

        # Empty arc: no routing data or biology-excluded family
        if not router_rec or router_rec.get('biology_excluded') or not router_rec.get('subgoal_chain'):
            record = {
                'tick':             int(tick),
                'execution_steps':  [],
                'expected_regions': [],
                'risk_decay_curve': [],
                'checkpoint_ticks': [],
                'horizon_len':      0,
                'arc_confidence':   0.0,
            }
            self._history.append(record)
            return record

        subgoal_chain    = router_rec.get('subgoal_chain', [])
        horizon          = min(len(subgoal_chain), self.HORIZON_MAX)
        route_confidence = float(router_rec.get('route_confidence', 0.5))
        family_sig       = router_rec.get('family_sig', 'unknown')

        policy_confidence = 0.5
        if shaper_rec:
            policy_confidence = float(shaper_rec.get('policy_confidence', 0.5))

        arc_confidence = self._clamp(route_confidence * 0.55 + policy_confidence * 0.45)

        execution_steps  = []
        risk_decay_curve = []
        checkpoint_ticks = []
        expected_regions = []
        seen_regions     = set()

        for i, sg in enumerate(subgoal_chain[:horizon]):
            step_risk   = self._clamp((1.0 - arc_confidence) * (1.0 + i * 0.08))
            step_region = f"{family_sig}_region_{i + 1}"
            step_hint   = f"execute:{family_sig}:step{i + 1}"

            execution_steps.append({
                'step':        i + 1,
                'region':      step_region,
                'action_hint': step_hint,
                'risk':        float(round(step_risk, 4)),
                'priority':    float(round(sg.get('priority_score', 0.5), 4)),
            })
            risk_decay_curve.append(float(round(step_risk, 4)))
            checkpoint_ticks.append(int(tick) + (i + 1) * self.TICKS_PER_STEP)
            if step_region not in seen_regions:
                expected_regions.append(step_region)
                seen_regions.add(step_region)

        record = {
            'tick':             int(tick),
            'execution_steps':  execution_steps,
            'expected_regions': expected_regions,
            'risk_decay_curve': risk_decay_curve,
            'checkpoint_ticks': checkpoint_ticks,
            'horizon_len':      int(horizon),
            'arc_confidence':   float(round(arc_confidence, 4)),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'horizon_len': 0, 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'horizon_len':    latest.get('horizon_len', 0),
            'stability_score': float(round(latest.get('arc_confidence', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class _LegacyOutcomeCreditAssigner:
    """
    Day 26 credit assigner -- horizon-chain credit assignment.
    Renamed Day 32 Pack 2: shadowed by Day 29 OutcomeCreditAssigner.
    Kept for reference; no longer instantiated.

    Per-tick outputs:
        per_step_credit    -- list of per-step success contributions
        rollback_penalty   -- 0.30 if rollback active, else 0.0
        drift_penalty      -- 0.20 if biology/serial risk; 0.10 if localized_drift
        integrity_reward   -- patch integrity contribution [0.0, 0.50]
        family_reward      -- EMA long-horizon reward per family [0, 1]
        horizon_suggestion -- 'compress' | 'hold' | 'expand'
        net_credit         -- clamped [0, 1]

    Family-level EMA statistics (alpha=0.10):
        long_horizon_reward  -- EMA net credit
        rollback_exposure    -- EMA rollback penalty
        drift_exposure       -- EMA drift penalty

    Horizon suggestion rules:
        compress : rollback_penalty > 0 or drift_penalty >= 0.20
        expand   : family_reward >= 0.65 and net_credit >= 0.50
        hold     : all other cases

    Waking-only. Zero survival contamination.
    """

    EMA_ALPHA = 0.10

    def __init__(self, maxlen=64):
        self._history        = deque(maxlen=maxlen)
        self._maxlen         = maxlen
        self._family_rewards = {}

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _ema(self, old, new):
        return self._clamp(old * (1.0 - self.EMA_ALPHA) + new * self.EMA_ALPHA)

    def _update_family(self, family_sig, step_credit, rollback_penalty, drift_penalty):
        if family_sig not in self._family_rewards:
            self._family_rewards[family_sig] = {
                'long_horizon_reward': 0.50,
                'rollback_exposure':   0.00,
                'drift_exposure':      0.00,
                'credit_observations': 0,
            }
        fr = self._family_rewards[family_sig]
        fr['credit_observations'] = int(fr['credit_observations']) + 1
        net = self._clamp(step_credit - rollback_penalty - drift_penalty)
        fr['long_horizon_reward'] = self._ema(fr['long_horizon_reward'], net)
        fr['rollback_exposure']   = self._ema(fr['rollback_exposure'],   rollback_penalty)
        fr['drift_exposure']      = self._ema(fr['drift_exposure'],      drift_penalty)

    def assign(self, tick, execution_horizon_planner, execution_outcome_comparator,
               invariant_drift_estimator, integrity_scorer):
        planner_rec    = execution_horizon_planner.latest()    if execution_horizon_planner    else None
        comparator_rec = execution_outcome_comparator.latest() if execution_outcome_comparator else None

        # No plan or empty arc: zero credit
        if not planner_rec or not planner_rec.get('execution_steps'):
            record = {
                'tick':               int(tick),
                'family_sig':         'unknown',
                'per_step_credit':    [],
                'rollback_penalty':   0.0,
                'drift_penalty':      0.0,
                'integrity_reward':   0.0,
                'family_reward':      0.5,
                'horizon_suggestion': 'hold',
                'net_credit':         0.0,
            }
            self._history.append(record)
            return record

        execution_steps = planner_rec.get('execution_steps', [])
        arc_confidence  = float(planner_rec.get('arc_confidence', 0.5))

        # Extract family_sig from first step action_hint (execute:family:step1)
        family_sig = 'unknown'
        if execution_steps:
            hint  = execution_steps[0].get('action_hint', '')
            parts = hint.split(':')
            family_sig = parts[1] if len(parts) >= 2 else 'unknown'

        # Rollback penalty
        rollback_penalty = 0.0
        if comparator_rec and comparator_rec.get('rollback_active', False):
            rollback_penalty = 0.30

        # Drift penalty (reads invariant_drift from comparator -- one-tick lag)
        drift_penalty = 0.0
        if comparator_rec:
            inv_drift = comparator_rec.get('invariant_drift', 'stable_projection')
            if inv_drift in ('biology_projection_risk', 'serialization_projection_risk'):
                drift_penalty = 0.20
            elif inv_drift == 'localized_drift':
                drift_penalty = 0.10

        # Alignment and policy delta from comparator
        alignment    = 0.5
        policy_delta = 0.0
        if comparator_rec:
            alignment    = float(comparator_rec.get('execution_alignment_score', 0.5))
            policy_delta = float(comparator_rec.get('policy_delta', 0.0))

        # Per-step credit: alignment + arc confidence + policy delta, decayed by step
        per_step_credit = []
        for i in range(len(execution_steps)):
            decay   = max(0.0, 1.0 - i * 0.10)
            step_cr = self._clamp(
                alignment       * 0.40 * decay +
                arc_confidence  * 0.30 * decay +
                max(0.0, policy_delta) * 0.30
            )
            per_step_credit.append(float(round(step_cr, 4)))

        mean_step_credit = (
            sum(per_step_credit) / len(per_step_credit)
        ) if per_step_credit else 0.0

        # Integrity reward from scorer
        integrity_reward = 0.0
        if integrity_scorer:
            sc = integrity_scorer.latest()
            if sc:
                integrity_reward = self._clamp(
                    float(sc.get('integrity_score', 0.5)) * 0.50
                )

        # Net credit
        net_credit = self._clamp(
            mean_step_credit + integrity_reward - rollback_penalty - drift_penalty
        )

        # Family EMA update
        self._update_family(family_sig, mean_step_credit, rollback_penalty, drift_penalty)
        fr = self._family_rewards.get(family_sig, {})
        family_reward = float(fr.get('long_horizon_reward', 0.5))

        # Horizon suggestion
        if rollback_penalty > 0.0 or drift_penalty >= 0.20:
            horizon_suggestion = 'compress'
        elif family_reward >= 0.65 and net_credit >= 0.50:
            horizon_suggestion = 'expand'
        else:
            horizon_suggestion = 'hold'

        record = {
            'tick':               int(tick),
            'family_sig':         family_sig,
            'per_step_credit':    per_step_credit,
            'rollback_penalty':   float(round(rollback_penalty, 4)),
            'drift_penalty':      float(round(drift_penalty, 4)),
            'integrity_reward':   float(round(integrity_reward, 4)),
            'family_reward':      float(round(family_reward, 4)),
            'horizon_suggestion': horizon_suggestion,
            'net_credit':         float(round(net_credit, 4)),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'net_credit': 0.0, 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'net_credit':     latest.get('net_credit', 0.0),
            'stability_score': float(round(latest.get('family_reward', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':         self._maxlen,
            'history':        list(self._history),
            'family_rewards': dict(self._family_rewards),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._family_rewards = d.get('family_rewards', {})
        return obj


# ===========================================================================
# DAY 26 PRE-PHASE 2C CONSOLIDATION: Temporal Stability + Sequence Compression
# Post-learning sequence consolidation before systems-level continuity transfer.
# Observer + advisory only. Zero direct mutation of routing or steering state.
# Waking-only. Zero survival contamination.
# ===========================================================================

class TemporalSequenceStabilityMonitor:
    """
    Monitors temporal stability of execution sequences across Pack 2/3 outputs.

    Integrates arc confidence, execution alignment, net credit, and route
    confidence into a smoothed stability_score via EMA (alpha=0.10).

    stability_state:
        'stable'    : stability_score >= 0.70
        'uncertain' : 0.50 <= stability_score < 0.70
        'unstable'  : 0.30 <= stability_score < 0.50
        'degraded'  : stability_score < 0.30

    trend (computed over last 8 records):
        'improving' : mean(last 4) > mean(first 4) + 0.05
        'degrading' : mean(first 4) > mean(last 4) + 0.05
        'stable'    : within 0.05 threshold

    Observer only. Zero direct mutation.
    Waking-only. Zero survival contamination.
    """

    EMA_ALPHA = 0.10

    def __init__(self, maxlen=64):
        self._history       = deque(maxlen=maxlen)
        self._maxlen        = maxlen
        self._stability_ema = 0.60

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _ema(self, old, new):
        return self._clamp(old * (1.0 - self.EMA_ALPHA) + new * self.EMA_ALPHA)

    def _compute_trend(self, current_score):
        # Include current tick's score in the window so trend is accurate on tick 7
        prior  = [r['stability_score'] for r in self._history]
        scores = (prior + [current_score])[-8:]
        if len(scores) < 8:
            return 'stable'
        mean_first = sum(scores[:4]) / 4.0
        mean_last  = sum(scores[4:]) / 4.0
        if mean_last > mean_first + 0.05:
            return 'improving'
        if mean_first > mean_last + 0.05:
            return 'degrading'
        return 'stable'

    def update(self, tick, execution_horizon_planner, execution_outcome_comparator,
               outcome_credit_assigner, policy_conditioned_subgoal_router):
        planner_rec = execution_horizon_planner.latest()    if execution_horizon_planner    else None
        comp_rec    = execution_outcome_comparator.latest() if execution_outcome_comparator else None
        credit_rec  = outcome_credit_assigner.latest()      if outcome_credit_assigner      else None
        router_rec  = policy_conditioned_subgoal_router.latest() if policy_conditioned_subgoal_router else None

        arc_confidence  = float(planner_rec.get('arc_confidence', 0.5))            if planner_rec else 0.5
        alignment       = float(comp_rec.get('execution_alignment_score', 0.5))    if comp_rec    else 0.5
        rollback_active = bool(comp_rec.get('rollback_active', False))             if comp_rec    else False
        net_credit      = float(credit_rec.get('net_credit', 0.5))                if credit_rec  else 0.5
        route_conf      = float(router_rec.get('route_confidence', 0.5))           if router_rec  else 0.5
        rb_compressed   = bool(router_rec.get('rollback_compressed', False))       if router_rec  else False

        # Per-tick stability signal: penalize rollback and compressed events
        rollback_hit    = 1.0 if (rollback_active or rb_compressed) else 0.0
        per_tick_signal = self._clamp(
            arc_confidence * 0.30 +
            alignment      * 0.25 +
            net_credit     * 0.25 +
            route_conf     * 0.20 -
            rollback_hit   * 0.20
        )

        self._stability_ema = self._ema(self._stability_ema, per_tick_signal)
        stability_score     = float(round(self._stability_ema, 4))

        if stability_score >= 0.70:
            stability_state = 'stable'
        elif stability_score >= 0.50:
            stability_state = 'uncertain'
        elif stability_score >= 0.30:
            stability_state = 'unstable'
        else:
            stability_state = 'degraded'

        trend = self._compute_trend(stability_score)

        record = {
            'tick':            int(tick),
            'stability_score': stability_score,
            'stability_state': stability_state,
            'trend':           trend,
            'arc_confidence':  float(round(arc_confidence, 4)),
            'alignment':       float(round(alignment, 4)),
            'net_credit':      float(round(net_credit, 4)),
            'rollback_active': rollback_active,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'stability_state': 'unknown', 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'stability_state': latest.get('stability_state', 'unknown'),
            'stability_score': float(round(latest.get('stability_score', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':        self._maxlen,
            'history':       list(self._history),
            'stability_ema': self._stability_ema,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._stability_ema = float(d.get('stability_ema', 0.60))
        return obj


class HorizonCompressionAdvisor:
    """
    Generates advisory horizon compression recommendations.

    Advisory only. Does NOT directly mutate active_horizon, subgoal chains,
    steering bias, or any planning system state.

    Compression conditions (each independently sufficient):
        1. rollback_penalty > 0.0      -- rollback penalties dominate
        2. net_credit < 0.45           -- delayed credit below threshold
        3. route_divergence > 0.35     -- route confidence below 0.65

    recommended_horizon_delta:
        -2 : two or more conditions active
        -1 : exactly one condition active
         0 : no compression needed

    safe_relaunch_tick = current_tick + 8 * max(1, |delta|)

    Advisory only. Zero direct mutation.
    Waking-only. Zero survival contamination.
    """

    def __init__(self, maxlen=64):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick, temporal_sequence_stability_monitor,
               outcome_credit_assigner, policy_conditioned_subgoal_router):
        monitor_rec = temporal_sequence_stability_monitor.latest() if temporal_sequence_stability_monitor else None
        credit_rec  = outcome_credit_assigner.latest()             if outcome_credit_assigner              else None
        router_rec  = policy_conditioned_subgoal_router.latest()   if policy_conditioned_subgoal_router    else None

        rollback_penalty = float(credit_rec.get('rollback_penalty', 0.0)) if credit_rec else 0.0
        net_credit       = float(credit_rec.get('net_credit', 0.5))       if credit_rec else 0.5
        route_confidence = float(router_rec.get('route_confidence', 0.5)) if router_rec else 0.5
        stability_score  = float(monitor_rec.get('stability_score', 0.5)) if monitor_rec else 0.5

        route_divergence = 1.0 - route_confidence

        # Evaluate compression conditions
        cond_rollback   = rollback_penalty > 0.0
        cond_credit     = net_credit < 0.45
        cond_divergence = route_divergence > 0.35

        active_conditions = sum([cond_rollback, cond_credit, cond_divergence])

        # Recommended delta bounded to [-2, -1, 0]
        if active_conditions >= 2:
            delta = -2
            compression_reason = 'multi_condition_degradation'
        elif active_conditions == 1:
            delta = -1
            if cond_rollback:
                compression_reason = 'rollback_pressure'
            elif cond_credit:
                compression_reason = 'low_delayed_credit'
            else:
                compression_reason = 'route_divergence'
        else:
            delta = 0
            compression_reason = 'no_compression_needed'

        safe_relaunch_tick    = int(tick) + 8 * max(1, abs(delta))
        compression_confidence = self._clamp(
            (active_conditions / 3.0) * 0.60 +
            (1.0 - stability_score)   * 0.40
        )

        record = {
            'tick':                      int(tick),
            'recommended_horizon_delta': int(delta),
            'compression_reason':        compression_reason,
            'safe_relaunch_tick':        safe_relaunch_tick,
            'compression_confidence':    float(round(compression_confidence, 4)),
            'conditions_active':         int(active_conditions),
            'cond_rollback':             cond_rollback,
            'cond_credit':               cond_credit,
            'cond_divergence':           cond_divergence,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'recommended_delta': 0, 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':       len(self._history),
            'latest_tick':       latest.get('tick'),
            'recommended_delta': latest.get('recommended_horizon_delta', 0),
            'stability_score':   float(round(latest.get('compression_confidence', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class FailurePatternShield:
    """
    Persists recurring failure motifs as global suppression priors.

    A family becomes shielded when the same failure motif occurs >= 3 times
    within a 16-tick sliding window (SHIELD_THRESHOLD=3, WINDOW=16).

    Failure motifs:
        'rollback_heavy'   : rollback_active == True
        'divergence_heavy' : comparator_state == 'diverged'
        'low_credit'       : net_credit < 0.30
        'horizon_loop'     : rollback_compressed and route_confidence < 0.40

    Output:
        shielded_family_patterns -- {family: {motif, suppression_confidence, ...}}
        suppression_confidence   -- mean suppression confidence across shielded families
        shield_reason            -- most frequent shield motif, or 'no_shield_active'

    Advisory only. Does NOT mutate routing, steering bias, or policy priors.
    is_shielded(family_sig) -> bool for downstream advisory queries.
    Waking-only. Zero survival contamination.
    """

    SHIELD_THRESHOLD    = 3
    SHIELD_WINDOW_TICKS = 16
    LOW_CREDIT_THRESH   = 0.30

    def __init__(self, maxlen=64):
        self._history   = deque(maxlen=maxlen)
        self._maxlen    = maxlen
        self._event_log = deque(maxlen=256)
        self._shielded  = {}

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _detect_motifs(self, rollback_active, comparator_state,
                       net_credit, rb_compressed, route_confidence):
        motifs = []
        if rollback_active:
            motifs.append('rollback_heavy')
        if comparator_state == 'diverged':
            motifs.append('divergence_heavy')
        if net_credit < self.LOW_CREDIT_THRESH:
            motifs.append('low_credit')
        if rb_compressed and route_confidence < 0.40:
            motifs.append('horizon_loop')
        return motifs

    def _count_in_window(self, family, motif, current_tick):
        cutoff = current_tick - self.SHIELD_WINDOW_TICKS
        return sum(
            1 for (t, f, m) in self._event_log
            if t >= cutoff and f == family and m == motif
        )

    def update(self, tick, execution_outcome_comparator, outcome_credit_assigner,
               policy_conditioned_subgoal_router):
        comp_rec   = execution_outcome_comparator.latest() if execution_outcome_comparator else None
        credit_rec = outcome_credit_assigner.latest()      if outcome_credit_assigner      else None
        router_rec = policy_conditioned_subgoal_router.latest() if policy_conditioned_subgoal_router else None

        rollback_active  = bool(comp_rec.get('rollback_active', False))     if comp_rec   else False
        comparator_state = comp_rec.get('comparator_state', 'no_steering')  if comp_rec   else 'no_steering'
        net_credit       = float(credit_rec.get('net_credit', 0.5))         if credit_rec else 0.5
        family_sig       = credit_rec.get('family_sig', 'unknown')          if credit_rec else 'unknown'
        route_confidence = float(router_rec.get('route_confidence', 0.5))   if router_rec else 0.5
        rb_compressed    = bool(router_rec.get('rollback_compressed', False)) if router_rec else False

        active_motifs = self._detect_motifs(
            rollback_active, comparator_state,
            net_credit, rb_compressed, route_confidence
        )

        # Log failure events
        for motif in active_motifs:
            self._event_log.append((int(tick), family_sig, motif))

        # Check shield thresholds: scan motifs seen for this family
        seen_motifs = set(m for (_, f, m) in self._event_log if f == family_sig)
        for motif in seen_motifs:
            if family_sig not in self._shielded:
                count = self._count_in_window(family_sig, motif, int(tick))
                if count >= self.SHIELD_THRESHOLD:
                    self._shielded[family_sig] = {
                        'motif':                  motif,
                        'suppression_confidence': self._clamp(count / (self.SHIELD_THRESHOLD * 2.0)),
                        'first_shield_tick':      int(tick),
                        'trigger_count':          int(count),
                    }

        # Refresh suppression_confidence for already-shielded family
        if family_sig in self._shielded:
            sh = self._shielded[family_sig]
            count = self._count_in_window(family_sig, sh['motif'], int(tick))
            sh['suppression_confidence'] = self._clamp(count / (self.SHIELD_THRESHOLD * 2.0))
            sh['trigger_count'] = int(count)

        # Aggregate
        if self._shielded:
            suppression_confidence = float(round(
                sum(s['suppression_confidence'] for s in self._shielded.values()) /
                len(self._shielded), 4
            ))
            motif_counts = {}
            for s in self._shielded.values():
                m = s['motif']
                motif_counts[m] = motif_counts.get(m, 0) + 1
            shield_reason = max(motif_counts, key=motif_counts.get)
        else:
            suppression_confidence = 0.0
            shield_reason = 'no_shield_active'

        record = {
            'tick':                     int(tick),
            'family_sig':               family_sig,
            'active_motifs':            active_motifs,
            'shielded_family_patterns': dict(self._shielded),
            'shielded_family_count':    int(len(self._shielded)),
            'suppression_confidence':   suppression_confidence,
            'shield_reason':            shield_reason,
        }
        self._history.append(record)
        return record

    def is_shielded(self, family_sig: str) -> bool:
        return family_sig in self._shielded

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'shielded_count': 0, 'stability_score': 0.5}
        latest = self._history[-1]
        return {
            'history_len':    len(self._history),
            'latest_tick':    latest.get('tick'),
            'shielded_count': latest.get('shielded_family_count', 0),
            'stability_score': float(round(latest.get('suppression_confidence', 0.5), 4)),
        }

    def to_dict(self):
        return {
            'maxlen':    self._maxlen,
            'history':   list(self._history),
            'shielded':  dict(self._shielded),
            'event_log': list(self._event_log),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._shielded = d.get('shielded', {})
        for evt in d.get('event_log', []):
            obj._event_log.append(tuple(evt) if isinstance(evt, list) else evt)
        return obj


# =============================================================================
# DAY 27 -- Phase 2C: Cross-Day Project Continuity
# Pack 1 -- Cross-Session Plan Identity
# CrossSessionPlanMemory / GoalThreadPersistence / NarrativeProjectState
# =============================================================================

class CrossSessionPlanMemory:
    """
    Persists unfinished plan state across session boundaries.

    Reads the current execution state from Day 26 Pack 2/3 systems and
    marks which subgoal chains are incomplete, unresolved, or shielded so
    that the organism can resume them in a future session.

    Unfinished priority law (any condition -> 'high'):
        rollback_compressed              : horizon was forcibly compressed
        net_credit < 0.50               : reward unresolved this session
        shielded_family_count > 0       : active failure shield present
        route_confidence < 0.60 and
          non-empty execution_steps     : partial route completion

    Continuity score formula (clamped [0, 1]):
        goal_completion_prior * 0.40
        + unfinished_priority_score   * 0.30
        + stability_score             * 0.20
        + failure_shield_safety       * 0.10

    Where:
        goal_completion_prior     = net_credit  (OutcomeCreditAssigner)
        unfinished_priority_score = 1.0 if high, 0.50 if normal
        stability_score           = TemporalSequenceStabilityMonitor EMA score
        failure_shield_safety     = 1.0 - suppression_confidence (inverse shield)

    Safe resumption anchor: {tick, family, horizon, route_confidence}
    Updated every tick when continuity_score >= 0.60.

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96) -- Day 27 cross-session continuity window.
    """

    def __init__(self, maxlen=96):
        self._history            = deque(maxlen=maxlen)
        self._maxlen             = maxlen
        self._last_stable_anchor = None

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _priority_score(priority):
        return 1.0 if priority == 'high' else 0.50

    def update(self, tick,
               outcome_credit_assigner,
               execution_horizon_planner,
               policy_conditioned_subgoal_router,
               failure_pattern_shield,
               horizon_compression_advisor,
               temporal_sequence_stability_monitor):

        credit_rec  = outcome_credit_assigner.latest()             if outcome_credit_assigner             else None
        planner_rec = execution_horizon_planner.latest()           if execution_horizon_planner           else None
        router_rec  = policy_conditioned_subgoal_router.latest()   if policy_conditioned_subgoal_router   else None
        shield_rec  = failure_pattern_shield.latest()              if failure_pattern_shield              else None
        advisor_rec = horizon_compression_advisor.latest()         if horizon_compression_advisor         else None
        stab_rec    = temporal_sequence_stability_monitor.latest() if temporal_sequence_stability_monitor else None

        # --- source fields ---
        net_credit       = float(credit_rec.get('net_credit',  0.0))          if credit_rec  else 0.0
        plan_family      = credit_rec.get('family_sig', 'unknown')             if credit_rec  else 'unknown'
        execution_steps  = list(planner_rec.get('execution_steps', []))        if planner_rec else []
        horizon_len      = int(planner_rec.get('horizon_len', 0))              if planner_rec else 0
        route_confidence = float(router_rec.get('route_confidence', 0.5))     if router_rec  else 0.5
        rb_compressed    = bool(router_rec.get('rollback_compressed', False))  if router_rec  else False
        shielded_count   = int(shield_rec.get('shielded_family_count', 0))    if shield_rec  else 0
        shield_reason    = shield_rec.get('shield_reason', 'no_shield_active') if shield_rec  else 'no_shield_active'
        suppression_conf = float(shield_rec.get('suppression_confidence', 0.0)) if shield_rec else 0.0
        compression_delta = int(advisor_rec.get('compression_delta', 0))      if advisor_rec else 0
        stability_score  = float(stab_rec.get('stability_score', 0.5))        if stab_rec    else 0.5

        # --- unfinished priority ---
        partial_route = (route_confidence < 0.60 and len(execution_steps) > 0)
        if rb_compressed or net_credit < 0.50 or shielded_count > 0 or partial_route:
            unfinished_priority = 'high'
        else:
            unfinished_priority = 'normal'

        # --- continuity score ---
        failure_shield_safety = self._clamp(1.0 - suppression_conf)
        priority_score        = self._priority_score(unfinished_priority)
        continuity_score      = self._clamp(
            net_credit            * 0.40 +
            priority_score        * 0.30 +
            stability_score       * 0.20 +
            failure_shield_safety * 0.10
        )

        # --- safe resumption anchor (update when score is high enough) ---
        if continuity_score >= 0.60:
            self._last_stable_anchor = {
                'tick':             int(tick),
                'family':           plan_family,
                'horizon':          horizon_len,
                'route_confidence': float(round(route_confidence, 4)),
            }

        last_stable_horizon = horizon_len if continuity_score >= 0.60 else (
            self._last_stable_anchor['horizon'] if self._last_stable_anchor else 0
        )

        record = {
            'tick':                  int(tick),
            'plan_family':           plan_family,
            'unfinished_chain':      execution_steps,
            'last_stable_horizon':   last_stable_horizon,
            'compression_advisory':  compression_delta,
            'shield_context': {
                'shield_reason':         shield_reason,
                'shielded_family_count': shielded_count,
            },
            'unfinished_priority':   unfinished_priority,
            'continuity_score':      float(round(continuity_score, 4)),
            'safe_resumption_anchor': dict(self._last_stable_anchor) if self._last_stable_anchor else None,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'continuity_score': 0.0, 'unfinished_priority': 'normal'}
        latest = self._history[-1]
        return {
            'history_len':         len(self._history),
            'latest_tick':         latest.get('tick'),
            'continuity_score':    float(round(latest.get('continuity_score', 0.0), 4)),
            'unfinished_priority': latest.get('unfinished_priority', 'normal'),
        }

    def to_dict(self):
        return {
            'maxlen':             self._maxlen,
            'history':            list(self._history),
            'last_stable_anchor': self._last_stable_anchor,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._last_stable_anchor = d.get('last_stable_anchor', None)
        return obj


class GoalThreadPersistence:
    """
    Maintains durable goal thread ownership across session boundaries.

    Per-family thread tracking (keyed by family_sig):
        thread_state       : 'active' | 'unfinished' | 'complete' | 'shielded'
        thread_priority    : float [0, 1]
        resume_confidence  : EMA float [0, 1]  (alpha=0.10)
        inherited_credit   : EMA accumulated delayed reward
        continuation_prior : EMA from policy confidence

    Thread state classification:
        'shielded'   : family is shielded by FailurePatternShield
        'unfinished' : unfinished_priority == 'high' (from CrossSessionPlanMemory)
        'complete'   : net_credit >= 0.70 and continuity_score >= 0.60
        'active'     : all other cases

    thread_priority formula (clamped [0, 1]):
        0.50 * continuity_score
        + 0.30 * route_confidence
        + 0.20 * policy_confidence

    resume_confidence: EMA(old, thread_priority, alpha=0.10)

    Outputs per record:
        family_sig         : active family
        thread_state       : current state
        thread_priority    : float [0, 1]
        resume_confidence  : float [0, 1]
        inherited_credit   : float [0, 1]
        continuation_prior : float [0, 1]
        thread_count       : total tracked families

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96) -- Day 27 cross-session continuity window.
    """

    EMA_ALPHA = 0.10

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        self._threads = {}   # family_sig -> per-family state dict

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _ema(self, old, new):
        return self._clamp(old * (1.0 - self.EMA_ALPHA) + new * self.EMA_ALPHA)

    def _ensure_thread(self, family_sig):
        if family_sig not in self._threads:
            self._threads[family_sig] = {
                'thread_state':       'active',
                'thread_priority':    0.5,
                'resume_confidence':  0.5,
                'inherited_credit':   0.5,
                'continuation_prior': 0.5,
                'observations':       0,
            }

    def update(self, tick,
               cross_session_plan_memory,
               outcome_credit_assigner,
               policy_conditioned_subgoal_router,
               strategic_policy_shaper,
               failure_pattern_shield):

        plan_rec   = cross_session_plan_memory.latest()           if cross_session_plan_memory   else None
        credit_rec = outcome_credit_assigner.latest()             if outcome_credit_assigner     else None
        router_rec = policy_conditioned_subgoal_router.latest()   if policy_conditioned_subgoal_router else None
        shaper_rec = strategic_policy_shaper.latest()             if strategic_policy_shaper     else None
        shield_rec = failure_pattern_shield.latest()              if failure_pattern_shield      else None

        # --- source fields ---
        family_sig        = credit_rec.get('family_sig', 'unknown')          if credit_rec  else 'unknown'
        net_credit        = float(credit_rec.get('net_credit', 0.0))         if credit_rec  else 0.0
        route_confidence  = float(router_rec.get('route_confidence', 0.5))   if router_rec  else 0.5
        policy_confidence = float(shaper_rec.get('policy_confidence', 0.5))  if shaper_rec  else 0.5
        continuity_score  = float(plan_rec.get('continuity_score', 0.0))     if plan_rec    else 0.0
        unfinished_prior  = plan_rec.get('unfinished_priority', 'normal')     if plan_rec    else 'normal'
        shielded_count    = int(shield_rec.get('shielded_family_count', 0))  if shield_rec  else 0

        # --- determine thread state ---
        is_shielded = (
            shielded_count > 0 and
            failure_pattern_shield is not None and
            failure_pattern_shield.is_shielded(family_sig)
        )

        if is_shielded:
            thread_state = 'shielded'
        elif unfinished_prior == 'high':
            thread_state = 'unfinished'
        elif net_credit >= 0.70 and continuity_score >= 0.60:
            thread_state = 'complete'
        else:
            thread_state = 'active'

        # --- thread priority ---
        thread_priority = self._clamp(
            0.50 * continuity_score +
            0.30 * route_confidence +
            0.20 * policy_confidence
        )

        # --- update per-family EMA state ---
        self._ensure_thread(family_sig)
        th = self._threads[family_sig]
        th['thread_state']       = thread_state
        th['thread_priority']    = float(round(thread_priority, 4))
        th['resume_confidence']  = float(round(self._ema(th['resume_confidence'],  thread_priority), 4))
        th['inherited_credit']   = float(round(self._ema(th['inherited_credit'],   net_credit), 4))
        th['continuation_prior'] = float(round(self._ema(th['continuation_prior'], policy_confidence), 4))
        th['observations']       = int(th['observations']) + 1

        record = {
            'tick':               int(tick),
            'family_sig':         family_sig,
            'thread_state':       thread_state,
            'thread_priority':    float(round(thread_priority, 4)),
            'resume_confidence':  th['resume_confidence'],
            'inherited_credit':   th['inherited_credit'],
            'continuation_prior': th['continuation_prior'],
            'thread_count':       int(len(self._threads)),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'thread_count': 0, 'thread_state': 'empty'}
        latest = self._history[-1]
        return {
            'history_len':  len(self._history),
            'latest_tick':  latest.get('tick'),
            'thread_count': latest.get('thread_count', 0),
            'thread_state': latest.get('thread_state', 'unknown'),
        }

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
            'threads': dict(self._threads),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._threads = d.get('threads', {})
        return obj


class NarrativeProjectState:
    """
    Constructs the organism's first autobiographical project narrative.

    Builds a persistent project self from active goal threads, unfinished arcs,
    artifact continuity, and patch execution state. Analogous to autobiographical
    goal continuity and narrative self-ownership in biological episodic memory
    (Tulving, 1983; Conway, 2005).

    Biology family exclusion law:
        Protected substrate families (neuron, synapse, homeostasis, hpa,
        cortisol, adenosine) are NEVER written into identity_threads.
        The organism does not claim narrative ownership of its own substrate.

    identity_threads:
        Up to 8 non-biology project arcs with highest thread_priority.
        Each entry: {family, state, priority, resume_confidence}

    narrative_state classification:
        'blocked'      : shielded_thread_count > 1
        'resuming'     : unfinished_thread_count > 0  (not blocked)
        'consolidating': complete_thread_count > 0    (not blocked or resuming)
        'advancing'    : default -- active forward progress

    self_owned_project_arc:
        Plain-text summary of the primary owned arc (ASCII only).
        Format: "Arc: {family} | State: {state} | Priority: {p:.2f}"

    Outputs per record:
        tick                   : int
        identity_threads       : list[dict]  (biology excluded, max 8)
        narrative_state        : str
        self_owned_project_arc : str
        active_arc_count       : int
        unfinished_arc_count   : int
        shielded_arc_count     : int
        complete_arc_count     : int
        artifact_continuity    : int   (artifact state memory len)
        patch_applied_count    : int   (patch executor latest applied_count)

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96) -- Day 27 cross-session continuity window.
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa', 'cortisol',
        'adenosine', 'homeostatic', 'cortisolsys', 'adenosinesys',
    })
    MAX_IDENTITY_THREADS = 8

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, family_sig):
        if not family_sig:
            return False
        key = str(family_sig).lower().replace('_', '').replace('-', '')
        for token in self.BIOLOGY_TOKENS:
            if token in key:
                return True
        return False

    def update(self, tick,
               goal_thread_persistence,
               cross_session_plan_memory,
               artifact_state_memory,
               patch_executor):

        plan_rec = cross_session_plan_memory.latest() if cross_session_plan_memory else None

        # --- collect all tracked threads (biology excluded) ---
        all_threads = []
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            for fam, th in goal_thread_persistence._threads.items():
                if self._is_biology(fam):
                    continue
                all_threads.append({
                    'family':            fam,
                    'state':             th.get('thread_state', 'active'),
                    'priority':          float(round(th.get('thread_priority', 0.5), 4)),
                    'resume_confidence': float(round(th.get('resume_confidence', 0.5), 4)),
                })

        # Sort by priority descending; cap at MAX_IDENTITY_THREADS
        all_threads.sort(key=lambda x: -x['priority'])
        identity_threads = all_threads[:self.MAX_IDENTITY_THREADS]

        # --- state counts ---
        active_arc_count     = sum(1 for t in all_threads if t['state'] == 'active')
        unfinished_arc_count = sum(1 for t in all_threads if t['state'] == 'unfinished')
        shielded_arc_count   = sum(1 for t in all_threads if t['state'] == 'shielded')
        complete_arc_count   = sum(1 for t in all_threads if t['state'] == 'complete')

        # --- narrative state ---
        if shielded_arc_count > 1:
            narrative_state = 'blocked'
        elif unfinished_arc_count > 0:
            narrative_state = 'resuming'
        elif complete_arc_count > 0:
            narrative_state = 'consolidating'
        else:
            narrative_state = 'advancing'

        # --- primary self-owned arc (ASCII only) ---
        if identity_threads:
            top = identity_threads[0]
            self_owned_project_arc = (
                "Arc: " + str(top['family']) +
                " | State: " + str(top['state']) +
                " | Priority: " + "{:.2f}".format(top['priority'])
            )
        elif plan_rec and plan_rec.get('plan_family', 'unknown') != 'unknown':
            fam = plan_rec.get('plan_family', 'unknown')
            if not self._is_biology(fam):
                self_owned_project_arc = (
                    "Arc: " + str(fam) +
                    " | State: unresolved" +
                    " | Priority: " + "{:.2f}".format(plan_rec.get('continuity_score', 0.0))
                )
            else:
                self_owned_project_arc = 'no_owned_arc'
        else:
            self_owned_project_arc = 'no_owned_arc'

        # --- artifact continuity + patch count ---
        artifact_continuity = len(artifact_state_memory) if artifact_state_memory else 0
        patch_applied_count = 0
        if patch_executor and hasattr(patch_executor, 'latest'):
            latest_patch = patch_executor.latest()
            if latest_patch:
                patch_applied_count = int(latest_patch.get('applied_count', 0))

        record = {
            'tick':                   int(tick),
            'identity_threads':       identity_threads,
            'narrative_state':        narrative_state,
            'self_owned_project_arc': self_owned_project_arc,
            'active_arc_count':       active_arc_count,
            'unfinished_arc_count':   unfinished_arc_count,
            'shielded_arc_count':     shielded_arc_count,
            'complete_arc_count':     complete_arc_count,
            'artifact_continuity':    artifact_continuity,
            'patch_applied_count':    patch_applied_count,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'narrative_state': 'empty', 'arc_count': 0}
        latest = self._history[-1]
        return {
            'history_len':     len(self._history),
            'latest_tick':     latest.get('tick'),
            'narrative_state': latest.get('narrative_state', 'unknown'),
            'arc_count':       (latest.get('active_arc_count', 0) +
                                latest.get('unfinished_arc_count', 0)),
        }

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


