class ContinuityDriftMonitor:
    """
    Tracks continuity score slope and detects drift warnings.

    Drift warning triggers when:
        continuity score drops >= 0.20 within 8 ticks

    Observes (reads only):
        - CrossSessionPlanMemory.continuity_score
        - CrossSessionPlanMemory.unfinished_priority
        - GoalThreadPersistence thread states
        - FailurePatternShield reactivation events

    Outputs (advisory):
        - drift_state      : 'stable' | 'degrading' | 'drifting'
        - drift_score     : float [0, 1] -- magnitude of recent decline
        - drift_warning    : bool        -- True if drift threshold exceeded
        - slope_history   : list[float] -- recent slopes

    Strict observer. Zero mutation of any Pack 1 law.
    deque(maxlen=64) -- bounded memory.
    """

    DRIFT_WINDOW = 8
    DRIFT_THRESHOLD = 0.20
    _HISTORY_MAXLEN = 64

    def __init__(self, maxlen=64):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        self._slope_buffer = deque(maxlen=self.DRIFT_WINDOW)

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               cross_session_plan_memory,
               goal_thread_persistence,
               failure_pattern_shield):

        plan_rec = cross_session_plan_memory.latest() if cross_session_plan_memory else None
        continuity_score = float(plan_rec.get('continuity_score', 0.5)) if plan_rec else 0.5
        unfinished_priority = plan_rec.get('unfinished_priority', 'normal') if plan_rec else 'normal'

        thread_data = {}
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            for fam, th in goal_thread_persistence._threads.items():
                thread_data[fam] = {
                    'state': th.get('thread_state', 'active'),
                    'priority': float(th.get('thread_priority', 0.5)),
                }

        shielded_count = 0
        if failure_pattern_shield and hasattr(failure_pattern_shield, 'latest'):
            shield_rec = failure_pattern_shield.latest()
            if shield_rec:
                shielded_count = int(shield_rec.get('shielded_family_count', 0))

        prev_score = None
        if len(self._history) > 0:
            prev_rec = self._history[-1]
            prev_score = prev_rec.get('continuity_score', continuity_score)

        if prev_score is not None:
            slope = continuity_score - prev_score
            self._slope_buffer.append(slope)
        else:
            slope = 0.0

        window_scores = [rec.get('continuity_score', 0.5) for rec in list(self._history)[-self.DRIFT_WINDOW:]]
        window_scores.append(continuity_score)

        drift_score = 0.0
        if len(window_scores) >= 2:
            first_score = window_scores[0]
            current_score = window_scores[-1]
            decline = first_score - current_score
            if decline > 0:
                drift_score = self._clamp(decline)

        if len(self._slope_buffer) >= self.DRIFT_WINDOW:
            recent_slopes = list(self._slope_buffer)[-self.DRIFT_WINDOW:]
            total_decline = sum(s for s in recent_slopes if s < 0)
            drift_score = self._clamp(abs(total_decline))

        if drift_score >= self.DRIFT_THRESHOLD:
            drift_state = 'drifting'
            drift_warning = True
        elif drift_score >= 0.10:
            drift_state = 'degrading'
            drift_warning = False
        else:
            drift_state = 'stable'
            drift_warning = False

        record = {
            'tick': int(tick),
            'continuity_score': float(round(continuity_score, 4)),
            'unfinished_priority': unfinished_priority,
            'thread_count': int(len(thread_data)),
            'shielded_count': int(shielded_count),
            'slope': float(round(slope, 4)),
            'drift_score': float(round(drift_score, 4)),
            'drift_state': drift_state,
            'drift_warning': drift_warning,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'drift_state': 'empty', 'drift_warning': False}
        latest = self._history[-1]
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'drift_state': latest.get('drift_state', 'stable'),
            'drift_warning': latest.get('drift_warning', False),
        }

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ResumeConfidenceAdvisor:
    """
    Estimates confidence in safe resumption of unfinished project arcs.

    Resume confidence formula (frozen):
        continuity_score * 0.50
        + thread_priority * 0.30
        + narrative_coherence * 0.20

    Clamped to [0, 1].

    Observes (reads only):
        - CrossSessionPlanMemory.continuity_score
        - CrossSessionPlanMemory.safe_resumption_anchor
        - GoalThreadPersistence thread_priority
        - NarrativeProjectState narrative_state

    Outputs (advisory):
        - resume_confidence  : float [0, 1]
        - resume_rank        : int   -- rank among all threads (1 = best)
        - recommended_thread : str   -- family_sig of highest-confidence arc
        - resume_reason     : str   -- human-readable rationale

    Strict observer. Zero mutation of any Pack 1 law.
    deque(maxlen=64) -- bounded memory.
    """

    _HISTORY_MAXLEN = 64

    def __init__(self, maxlen=64):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _narrative_coherence_score(self, narrative_state):
        if narrative_state == 'advancing':
            return 1.0
        elif narrative_state == 'consolidating':
            return 0.75
        elif narrative_state == 'resuming':
            return 0.50
        elif narrative_state == 'blocked':
            return 0.25
        return 0.5

    def update(self, tick,
               cross_session_plan_memory,
               goal_thread_persistence,
               narrative_project_state):

        plan_rec = cross_session_plan_memory.latest() if cross_session_plan_memory else None
        continuity_score = float(plan_rec.get('continuity_score', 0.5)) if plan_rec else 0.5

        narrative_state = 'advancing'
        if narrative_project_state and hasattr(narrative_project_state, 'latest'):
            nps_rec = narrative_project_state.latest()
            if nps_rec:
                narrative_state = nps_rec.get('narrative_state', 'advancing')

        narrative_coherence = self._narrative_coherence_score(narrative_state)

        thread_scores = []
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            for fam, th in goal_thread_persistence._threads.items():
                thread_priority = float(th.get('thread_priority', 0.5))
                resume_conf = self._clamp(
                    continuity_score * 0.50 +
                    thread_priority * 0.30 +
                    narrative_coherence * 0.20
                )
                thread_scores.append({
                    'family': fam,
                    'thread_priority': thread_priority,
                    'resume_confidence': resume_conf,
                })

        thread_scores.sort(key=lambda x: -x['resume_confidence'])

        if thread_scores:
            best = thread_scores[0]
            recommended_thread = best['family']
            resume_confidence = best['resume_confidence']
            resume_rank = 1
            resume_reason = (
                f"continuity={continuity_score:.2f}, priority={best['thread_priority']:.2f}, "
                f"narrative={narrative_coherence:.2f}"
            )
        else:
            recommended_thread = 'none'
            resume_confidence = 0.5
            resume_rank = 0
            resume_reason = 'no_active_threads'

        record = {
            'tick': int(tick),
            'continuity_score': float(round(continuity_score, 4)),
            'narrative_coherence': float(round(narrative_coherence, 4)),
            'resume_confidence': float(round(resume_confidence, 4)),
            'resume_rank': resume_rank,
            'recommended_thread': recommended_thread,
            'resume_reason': resume_reason,
            'thread_count': len(thread_scores),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'resume_confidence': 0.0, 'recommended_thread': 'none'}
        latest = self._history[-1]
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'resume_confidence': latest.get('resume_confidence', 0.0),
            'recommended_thread': latest.get('recommended_thread', 'none'),
        }

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class NarrativeCoherenceProbe:
    """
    Monitors narrative thread continuity, arc fragmentation, and coherence drift.

    Coherence scoring:
        - High if narrative_state == 'advancing' and few state transitions
        - Medium for 'consolidating' or 'resuming'
        - Low for 'blocked' or frequent thread churn

    Fragmentation warning triggers when:
        - 3+ different thread states in last 8 ticks
        - OR repeated 'blocked' states (3+ in window)

    Observes (reads only):
        - NarrativeProjectState narrative_state
        - NarrativeProjectState identity_threads
        - GoalThreadPersistence thread states

    Outputs (advisory):
        - coherence_score    : float [0, 1]
        - coherence_state    : 'coherent' | 'fragmented' | 'degraded'
        - fragmentation_warning : bool
        - state_transition_count : int

    Strict observer. Zero mutation of any Pack 1 law.
    deque(maxlen=64) -- bounded memory.
    """

    FRAGMENTATION_WINDOW = 8
    FRAGMENTATION_THRESHOLD = 3

    def __init__(self, maxlen=64):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        self._state_history = deque(maxlen=self.FRAGMENTATION_WINDOW)

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               narrative_project_state,
               goal_thread_persistence):

        narrative_state = 'advancing'
        identity_threads = []
        if narrative_project_state and hasattr(narrative_project_state, 'latest'):
            nps_rec = narrative_project_state.latest()
            if nps_rec:
                narrative_state = nps_rec.get('narrative_state', 'advancing')
                identity_threads = nps_rec.get('identity_threads', [])

        self._state_history.append(narrative_state)

        state_counts = {}
        for s in self._state_history:
            state_counts[s] = state_counts.get(s, 0) + 1

        state_transition_count = 0
        prev_state = None
        for s in self._state_history:
            if prev_state is not None and s != prev_state:
                state_transition_count += 1
            prev_state = s

        unique_states = len(state_counts)
        blocked_count = state_counts.get('blocked', 0)

        fragmentation_warning = (
            unique_states >= self.FRAGMENTATION_THRESHOLD or
            blocked_count >= self.FRAGMENTATION_THRESHOLD
        )

        if narrative_state == 'advancing' and unique_states <= 1:
            coherence_score = 1.0
            coherence_state = 'coherent'
        elif narrative_state in ('consolidating', 'resuming'):
            coherence_score = 0.65
            coherence_state = 'coherent'
        elif fragmentation_warning:
            coherence_score = 0.30
            coherence_state = 'fragmented'
        else:
            coherence_score = 0.50
            coherence_state = 'degraded'

        thread_count = len(identity_threads)
        active_threads = sum(1 for t in identity_threads if t.get('state') == 'active')

        record = {
            'tick': int(tick),
            'narrative_state': narrative_state,
            'coherence_score': float(round(coherence_score, 4)),
            'coherence_state': coherence_state,
            'fragmentation_warning': fragmentation_warning,
            'state_transition_count': state_transition_count,
            'unique_states': unique_states,
            'thread_count': thread_count,
            'active_threads': active_threads,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else None

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def summary(self):
        if not self._history:
            return {'history_len': 0, 'latest_tick': None,
                    'coherence_state': 'empty', 'fragmentation_warning': False}
        latest = self._history[-1]
        return {
            'history_len': len(self._history),
            'latest_tick': latest.get('tick'),
            'coherence_state': latest.get('coherence_state', 'unknown'),
            'fragmentation_warning': latest.get('fragmentation_warning', False),
        }

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


