class GoalArbitrationEngine:
    """
    Arbitrate surviving non-biology threads using continuity score, unfinished
    bonus (+0.20), shield penalty (-0.25), resume confidence, narrative
    coherence, and dormant resurfacing bonus (+0.10 after >= 3 suppression
    cycles).  Produces a single selected_goal_thread per tick with suppressed
    lineage for archive ingestion.
    """

    BIOLOGY_TOKENS   = frozenset({'neuron', 'synapse', 'homeostasis', 'hpa',
                                   'cortisol', 'adenosine', 'homeostatic',
                                   'cortisolsys', 'adenosinesys'})
    UNFINISHED_BONUS = 0.20
    SHIELD_PENALTY   = 0.25
    DORMANT_BONUS    = 0.10
    DORMANT_CYCLES   = 3

    def __init__(self, maxlen=96):
        self._history           = deque(maxlen=maxlen)
        self._maxlen            = maxlen
        self._suppression_counts = {}   # family_sig -> int (reset on win)

    def update(self, tick, goal_thread_persistence, cross_session_plan_memory,
               resume_confidence_advisor, narrative_coherence_probe,
               suppressed_thread_archive):
        threads = {}
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            threads = goal_thread_persistence._threads

        ncp_latest = {}
        if narrative_coherence_probe and hasattr(narrative_coherence_probe, 'latest'):
            ncp_latest = narrative_coherence_probe.latest() or {}

        coherence_score = ncp_latest.get('coherence_score', 0.5)

        candidates = []
        for fam, td in threads.items():
            fam_lower = fam.lower()
            if any(t in fam_lower for t in self.BIOLOGY_TOKENS):
                continue

            base  = td.get('thread_priority', 0.5)
            bonus = 0.0
            parts = []

            ts = td.get('thread_state', 'active')
            if ts in ('unfinished', 'shielded'):
                bonus += self.UNFINISHED_BONUS
                parts.append('unfinished_bonus')
            if ts == 'shielded':
                bonus -= self.SHIELD_PENALTY
                parts.append('shield_penalty')

            sup_n = self._suppression_counts.get(fam, 0)
            if sup_n >= self.DORMANT_CYCLES:
                bonus += self.DORMANT_BONUS
                parts.append('dormant_bonus')

            arb = max(0.0, min(1.0, base + bonus))
            candidates.append({
                'family_sig':        fam,
                'arbitration_score': arb,
                'thread_state':      ts,
                'resume_confidence': td.get('resume_confidence', 0.5),
                'sup_count':         sup_n,
                'reason':            ','.join(parts) if parts else 'standard',
            })

        candidates.sort(key=lambda x: x['arbitration_score'], reverse=True)

        selected   = candidates[0] if candidates else None
        suppressed = candidates[1:] if len(candidates) > 1 else []

        # Update suppression tracking
        for c in suppressed:
            fam = c['family_sig']
            self._suppression_counts[fam] = self._suppression_counts.get(fam, 0) + 1
        if selected:
            self._suppression_counts[selected['family_sig']] = 0

        record = {
            'tick':               tick,
            'selected_goal_thread': selected['family_sig'] if selected else None,
            'arbitration_score':  selected['arbitration_score'] if selected else 0.0,
            'suppressed_threads': [c['family_sig'] for c in suppressed],
            'arbitration_reason': selected['reason'] if selected else 'no_candidates',
            'candidate_count':    len(candidates),
            'coherence_score':    coherence_score,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {
            'maxlen':             self._maxlen,
            'history':            list(self._history),
            'suppression_counts': dict(self._suppression_counts),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._suppression_counts = dict(d.get('suppression_counts', {}))
        return obj


class NarrativeConflictResolver:
    """
    Detect and resolve autobiographical conflicts: duplicate unfinished arcs,
    blocked-vs-advancing contradictions, safe-anchor contention, repeated
    ownership loops (>= 4 consecutive wins), and narrative provenance
    collisions.  Biology families unconditionally excluded.
    """

    BIOLOGY_TOKENS   = frozenset({'neuron', 'synapse', 'homeostasis', 'hpa',
                                   'cortisol', 'adenosine', 'homeostatic',
                                   'cortisolsys', 'adenosinesys'})
    LOOP_THRESHOLD   = 4

    def __init__(self, maxlen=96):
        self._history       = deque(maxlen=maxlen)
        self._maxlen        = maxlen
        self._ownership_log = {}   # family_sig -> consecutive ownership count

    def update(self, tick, goal_arbitration_engine, narrative_project_state,
               cross_session_plan_memory, goal_thread_persistence):
        gae_latest  = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_latest = goal_arbitration_engine.latest() or {}

        nps_latest  = {}
        if narrative_project_state and hasattr(narrative_project_state, 'latest'):
            nps_latest = narrative_project_state.latest() or {}

        cspm_latest = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_latest = cross_session_plan_memory.latest() or {}

        threads = {}
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            threads = goal_thread_persistence._threads

        selected        = gae_latest.get('selected_goal_thread')
        narrative_state = nps_latest.get('narrative_state', 'advancing')

        conflict_flags     = []
        conflict_provenance = []

        # Duplicate unfinished arcs
        unfinished = [f for f, td in threads.items()
                      if td.get('thread_state') == 'unfinished'
                      and not any(t in f.lower() for t in self.BIOLOGY_TOKENS)]
        if len(unfinished) > 1:
            conflict_flags.append('duplicate_unfinished')
            conflict_provenance.append({'type': 'duplicate_unfinished',
                                        'families': unfinished[:4]})

        # Blocked vs advancing contradiction
        if selected and narrative_state == 'blocked':
            sel_state = threads.get(selected, {}).get('thread_state', 'active')
            if sel_state == 'active':
                conflict_flags.append('blocked_advancing_contradiction')
                conflict_provenance.append({'type': 'blocked_vs_advancing',
                                            'family': selected})

        # Safe-anchor contention
        anchor = cspm_latest.get('safe_resumption_anchor')
        if isinstance(anchor, dict):
            anchor_fam = anchor.get('family')
            if anchor_fam and anchor_fam != selected:
                conflict_flags.append('anchor_contention')
                conflict_provenance.append({'type': 'anchor_contention',
                                            'anchor_fam': anchor_fam,
                                            'selected': selected})

        # Repeated ownership loop
        if selected:
            self._ownership_log[selected] = self._ownership_log.get(selected, 0) + 1
            if self._ownership_log[selected] >= self.LOOP_THRESHOLD:
                conflict_flags.append('ownership_loop')
                conflict_provenance.append({'type': 'ownership_loop',
                                            'family': selected,
                                            'count': self._ownership_log[selected]})
        for fam in list(self._ownership_log):
            if fam != selected:
                self._ownership_log[fam] = max(0, self._ownership_log[fam] - 1)

        # Conflict state
        if not conflict_flags:
            conflict_state = 'clean'
        elif 'ownership_loop' in conflict_flags or 'duplicate_unfinished' in conflict_flags:
            conflict_state = 'contested'
        else:
            conflict_state = 'marginal'

        # Resolved threads (biology excluded, deduped, cap 4)
        seen             = set()
        resolved_threads = []
        for fam, td in threads.items():
            if any(t in fam.lower() for t in self.BIOLOGY_TOKENS):
                continue
            if fam in seen:
                continue
            seen.add(fam)
            resolved_threads.append({
                'family_sig':     fam,
                'thread_state':   td.get('thread_state', 'active'),
                'thread_priority': td.get('thread_priority', 0.5),
            })
            if len(resolved_threads) >= 4:
                break

        dominant = (max(resolved_threads, key=lambda x: x['thread_priority'])
                    if resolved_threads else None)

        if conflict_state == 'clean':
            resolution_reason = 'no_conflict'
        elif 'ownership_loop' in conflict_flags:
            resolution_reason = 'loop_broken_by_priority'
        elif 'duplicate_unfinished' in conflict_flags:
            resolution_reason = 'unfinished_deduplication'
        else:
            resolution_reason = 'marginal_resolution'

        record = {
            'tick':              tick,
            'resolved_threads':  resolved_threads,
            'conflict_state':    conflict_state,
            'dominant_story_arc': dominant['family_sig'] if dominant else None,
            'conflict_provenance': conflict_provenance[:4],
            'resolution_reason': resolution_reason,
            'conflict_count':    len(conflict_flags),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {
            'maxlen':        self._maxlen,
            'history':       list(self._history),
            'ownership_log': dict(self._ownership_log),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._ownership_log = dict(d.get('ownership_log', {}))
        return obj


class PersistentIntentScheduler:
    """
    Convert the winning arbitration thread into a bounded future agenda.
    Schedules <= 4 intents with relaunch ticks and safe anchors.
    Overflow threads go to a deferred candidates list.
    Biology families unconditionally excluded.
    """

    BIOLOGY_TOKENS = frozenset({'neuron', 'synapse', 'homeostasis', 'hpa',
                                 'cortisol', 'adenosine', 'homeostatic',
                                 'cortisolsys', 'adenosinesys'})
    MAX_INTENTS    = 4

    def __init__(self, maxlen=96):
        self._history  = deque(maxlen=maxlen)
        self._maxlen   = maxlen
        self._schedule = []   # bounded list of intent dicts (max MAX_INTENTS)
        self._deferred = []   # overflow deferred candidates

    def update(self, tick, goal_arbitration_engine, narrative_conflict_resolver,
               cross_session_plan_memory, goal_thread_persistence):
        gae_latest  = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_latest = goal_arbitration_engine.latest() or {}

        ncr_latest  = {}
        if narrative_conflict_resolver and hasattr(narrative_conflict_resolver, 'latest'):
            ncr_latest = narrative_conflict_resolver.latest() or {}

        cspm_latest = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_latest = cross_session_plan_memory.latest() or {}

        selected       = gae_latest.get('selected_goal_thread')
        resolved       = ncr_latest.get('resolved_threads', [])
        conflict_state = ncr_latest.get('conflict_state', 'clean')
        anchor         = cspm_latest.get('safe_resumption_anchor')

        new_intents  = []
        new_deferred = []

        # Primary intent from arbitration winner
        if selected and not any(t in selected.lower() for t in self.BIOLOGY_TOKENS):
            safe_anchor = None
            if isinstance(anchor, dict) and anchor.get('family') == selected:
                safe_anchor = anchor
            new_intents.append({
                'family_sig':     selected,
                'rank':           0,
                'relaunch_tick':  tick + 8,
                'safe_anchor':    safe_anchor,
                'conflict_clean': (conflict_state == 'clean'),
                'intent_type':    'primary',
            })

        # Secondary intents from conflict-resolved threads
        for rt in resolved:
            fam = rt.get('family_sig', '')
            if fam == selected:
                continue
            if any(t in fam.lower() for t in self.BIOLOGY_TOKENS):
                continue
            if len(new_intents) >= self.MAX_INTENTS:
                new_deferred.append({
                    'family_sig':     fam,
                    'thread_priority': rt.get('thread_priority', 0.5),
                })
                continue
            new_intents.append({
                'family_sig':     fam,
                'rank':           len(new_intents),
                'relaunch_tick':  tick + 8 * (len(new_intents) + 1),
                'safe_anchor':    None,
                'conflict_clean': (conflict_state == 'clean'),
                'intent_type':    'secondary',
            })

        self._schedule = new_intents[:self.MAX_INTENTS]
        self._deferred = new_deferred[:self.MAX_INTENTS]

        if new_intents and conflict_state == 'clean':
            has_anchor   = new_intents[0].get('safe_anchor') is not None
            agenda_conf  = 0.80 + 0.20 * (1 if has_anchor else 0)
        elif new_intents:
            agenda_conf  = 0.50
        else:
            agenda_conf  = 0.10

        record = {
            'tick':               tick,
            'scheduled_intents':  list(self._schedule),
            'deferred_candidates': list(self._deferred),
            'agenda_confidence':  agenda_conf,
            'intent_count':       len(self._schedule),
            'deferred_count':     len(self._deferred),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {
            'maxlen':    self._maxlen,
            'history':   list(self._history),
            'schedule':  list(self._schedule),
            'deferred':  list(self._deferred),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._schedule = list(d.get('schedule', []))
        obj._deferred = list(d.get('deferred', []))
        return obj


class SuppressedThreadArchive:
    """
    Dormant autobiographical memory.  Persists suppressed thread lineage:
    suppression count, last arbitration loss tick, starvation duration, and
    resurfacing eligibility (>= 3 suppression cycles).
    Biology families unconditionally excluded.
    """

    BIOLOGY_TOKENS     = frozenset({'neuron', 'synapse', 'homeostasis', 'hpa',
                                     'cortisol', 'adenosine', 'homeostatic',
                                     'cortisolsys', 'adenosinesys'})
    RESURFACE_THRESHOLD = 3

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen
        self._archive = {}   # family_sig -> archive entry dict

    def update(self, tick, goal_arbitration_engine, goal_thread_persistence):
        gae_latest = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_latest = goal_arbitration_engine.latest() or {}

        threads = {}
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            threads = goal_thread_persistence._threads

        suppressed_list = gae_latest.get('suppressed_threads', [])
        selected        = gae_latest.get('selected_goal_thread')

        for fam in suppressed_list:
            if any(t in fam.lower() for t in self.BIOLOGY_TOKENS):
                continue
            if fam not in self._archive:
                td = threads.get(fam, {})
                self._archive[fam] = {
                    'family_sig':           fam,
                    'suppression_count':    0,
                    'last_arbitration_loss': tick,
                    'starvation_duration':  0,
                    'initial_priority':     td.get('thread_priority', 0.5),
                    'thread_state':         td.get('thread_state', 'active'),
                }
            entry = self._archive[fam]
            entry['suppression_count']    += 1
            entry['last_arbitration_loss'] = tick
            entry['starvation_duration']  += 1
            td = threads.get(fam, {})
            if 'thread_state' in td:
                entry['thread_state'] = td['thread_state']

        # Clear archive when thread wins arbitration
        if selected and selected in self._archive:
            del self._archive[selected]

        resurface_ready = [
            fam for fam, entry in self._archive.items()
            if entry['suppression_count'] >= self.RESURFACE_THRESHOLD
        ]

        if not self._archive:
            archive_state = 'empty'
        elif resurface_ready:
            archive_state = 'resurface_pending'
        else:
            archive_state = 'suppressed'

        max_starv = max(
            (e['starvation_duration'] for e in self._archive.values()), default=0
        )

        record = {
            'tick':                   tick,
            'archive_state':          archive_state,
            'resurface_ready_threads': resurface_ready,
            'archive_size':           len(self._archive),
            'max_starvation':         max_starv,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
            'archive': dict(self._archive),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._archive = dict(d.get('archive', {}))
        return obj


class DeferredResumptionGovernor:
    """
    Dormant future governance.  Absorbs deferred candidates from
    PersistentIntentScheduler, ages them, applies dormant fairness bonuses
    from SuppressedThreadArchive, purges stale entries (>= 16 ticks), and
    returns bounded resumption candidates.
    Biology families unconditionally excluded.
    """

    BIOLOGY_TOKENS  = frozenset({'neuron', 'synapse', 'homeostasis', 'hpa',
                                  'cortisol', 'adenosine', 'homeostatic',
                                  'cortisolsys', 'adenosinesys'})
    STALE_THRESHOLD = 16

    def __init__(self, maxlen=96):
        self._history        = deque(maxlen=maxlen)
        self._maxlen         = maxlen
        self._deferred_queue = []   # list of deferred intent dicts with age

    def update(self, tick, persistent_intent_scheduler, suppressed_thread_archive,
               goal_arbitration_engine):
        pis_latest = {}
        if persistent_intent_scheduler and hasattr(persistent_intent_scheduler, 'latest'):
            pis_latest = persistent_intent_scheduler.latest() or {}

        sta_latest = {}
        if suppressed_thread_archive and hasattr(suppressed_thread_archive, 'latest'):
            sta_latest = suppressed_thread_archive.latest() or {}

        # Absorb new deferred candidates
        for cand in pis_latest.get('deferred_candidates', []):
            fam = cand.get('family_sig', '')
            if any(t in fam.lower() for t in self.BIOLOGY_TOKENS):
                continue
            if not any(d['family_sig'] == fam for d in self._deferred_queue):
                self._deferred_queue.append({
                    'family_sig':   fam,
                    'entered_tick': tick,
                    'age':          0,
                    'priority':     cand.get('thread_priority', 0.5),
                    'dormant_bonus': 0.0,
                })

        resurface_ready = set(sta_latest.get('resurface_ready_threads', []))

        # Age entries, apply dormant bonus, collect stale
        to_purge = []
        for entry in self._deferred_queue:
            entry['age'] = tick - entry['entered_tick']
            if entry['family_sig'] in resurface_ready:
                entry['dormant_bonus'] = 0.10
            if entry['age'] >= self.STALE_THRESHOLD:
                to_purge.append(entry['family_sig'])

        self._deferred_queue = [
            d for d in self._deferred_queue
            if d['family_sig'] not in to_purge
        ]

        sorted_q = sorted(
            self._deferred_queue,
            key=lambda x: x['priority'] + x['dormant_bonus'],
            reverse=True,
        )

        resumption_candidates = [
            {
                'family_sig':   d['family_sig'],
                'priority':     d['priority'] + d['dormant_bonus'],
                'age':          d['age'],
                'dormant_bonus': d['dormant_bonus'],
            }
            for d in sorted_q[:4]
        ]

        if not self._deferred_queue:
            governor_state = 'idle'
        elif any(d['dormant_bonus'] > 0 for d in self._deferred_queue):
            governor_state = 'resurface_active'
        else:
            governor_state = 'managing'

        if not resumption_candidates:
            resumption_reason = 'queue_empty'
        elif any(c['dormant_bonus'] > 0 for c in resumption_candidates):
            resumption_reason = 'dormant_fairness'
        else:
            resumption_reason = 'priority_order'

        record = {
            'tick':                  tick,
            'resumption_candidates': resumption_candidates,
            'governor_state':        governor_state,
            'resumption_reason':     resumption_reason,
            'queue_size':            len(self._deferred_queue),
            'purged_count':          len(to_purge),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {
            'maxlen':         self._maxlen,
            'history':        list(self._history),
            'deferred_queue': list(self._deferred_queue),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._deferred_queue = list(d.get('deferred_queue', []))
        return obj


# ===========================================================================
# DAY 28 PHASE A -- Cross-Day Narrative Synthesis + Milestone Memory Suite
# Autobiographical milestone abstraction, arc merger, identity continuity
# index, dormant revival, dependency graph, and break resumption anchoring.
# Conway 2005 (autobiographical milestones); Tulving 1983 (episodic narrative);
# Fuster 2008 (prefrontal goal persistence); Damasio 1999 (somatic self-model)
# ===========================================================================

class MilestoneMemorySynthesizer:
    """
    Compress dominant narrative arcs, successful executive recoveries,
    conflict resolutions, deferred resurfacing wins, continuity fallback
    recoveries, and project identity transitions into milestone-grade
    persistent memories that survive long dormancy periods.

    Milestone cap: 6 (MILESTONE_CAP).
    Biology family exclusion enforced at every entry point.

    Salience formula per thread:
        thread_priority   * 0.40
        + continuity_score * 0.30
        + resume_confidence* 0.20
        + state_bonus      * 0.10   (0.10 if unfinished, 0.05 if complete)

    synthesis_class values:
        'dominant_arc'        : highest-arbitration selected thread
        'conflict_resolved'   : thread surviving clean conflict state
        'deferred_resurfaced' : thread appearing in deferred governor
        'continuity_survivor' : all other qualified threads

    Outputs per record:
        tick               : int
        milestone_memories : list[dict] -- max 6, each:
                               {family_sig, salience, synthesis_class,
                                thread_state, continuity_score}
        milestone_salience : float -- mean salience across memories
        synthesis_reason   : str
        synthesized_count  : int

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    MILESTONE_CAP  = 6
    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, family_sig):
        if not family_sig:
            return True
        key = str(family_sig).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               narrative_project_state,
               goal_arbitration_engine,
               cross_session_plan_memory,
               goal_thread_persistence,
               narrative_conflict_resolver,
               deferred_resumption_governor):

        nps_rec = {}
        if narrative_project_state and hasattr(narrative_project_state, 'latest'):
            nps_rec = narrative_project_state.latest() or {}
        identity_threads = nps_rec.get('identity_threads', [])

        gae_rec = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_rec = goal_arbitration_engine.latest() or {}
        selected_thread = gae_rec.get('selected_goal_thread')

        ncr_rec = {}
        if narrative_conflict_resolver and hasattr(narrative_conflict_resolver, 'latest'):
            ncr_rec = narrative_conflict_resolver.latest() or {}
        conflict_state = ncr_rec.get('conflict_state', 'clean')

        drg_rec = {}
        if deferred_resumption_governor and hasattr(deferred_resumption_governor, 'latest'):
            drg_rec = deferred_resumption_governor.latest() or {}
        deferred_families = {
            c.get('family_sig', '')
            for c in drg_rec.get('resumption_candidates', [])
        }

        cspm_rec = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_rec = cross_session_plan_memory.latest() or {}
        continuity_score = float(cspm_rec.get('continuity_score', 0.5))

        threads_map = {}
        if goal_thread_persistence and hasattr(goal_thread_persistence, '_threads'):
            threads_map = goal_thread_persistence._threads

        candidates = []
        for th in identity_threads:
            fam = th.get('family', '') or th.get('family_sig', '')
            if self._is_biology(fam):
                continue
            td               = threads_map.get(fam, {})
            thread_priority  = float(th.get('priority', td.get('thread_priority', 0.5)))
            resume_conf      = float(th.get('resume_confidence',
                                             td.get('resume_confidence', 0.5)))
            thread_state     = th.get('state', td.get('thread_state', 'active'))

            if thread_state == 'unfinished':
                state_bonus = 0.10
            elif thread_state == 'complete':
                state_bonus = 0.05
            else:
                state_bonus = 0.0

            salience = self._clamp(
                thread_priority  * 0.40
                + continuity_score * 0.30
                + resume_conf      * 0.20
                + state_bonus      * 0.10
            )

            if fam == selected_thread:
                synth_cls = 'dominant_arc'
            elif conflict_state == 'clean':
                synth_cls = 'conflict_resolved'
            elif fam in deferred_families:
                synth_cls = 'deferred_resurfaced'
            else:
                synth_cls = 'continuity_survivor'

            candidates.append({
                'family_sig':       fam,
                'salience':         salience,
                'synthesis_class':  synth_cls,
                'thread_state':     thread_state,
                'continuity_score': continuity_score,
            })

        candidates.sort(key=lambda x: x['salience'], reverse=True)
        milestone_memories = candidates[:self.MILESTONE_CAP]

        if milestone_memories:
            milestone_salience = self._clamp(
                sum(m['salience'] for m in milestone_memories) / len(milestone_memories)
            )
        else:
            milestone_salience = 0.0

        n = len(milestone_memories)
        if n == 0:
            synthesis_reason = 'no_threads_available'
        elif n == self.MILESTONE_CAP:
            synthesis_reason = 'cap_reached_top6_selected'
        else:
            synthesis_reason = 'partial_synthesis_{}'.format(n)

        record = {
            'tick':               tick,
            'milestone_memories': milestone_memories,
            'milestone_salience': milestone_salience,
            'synthesis_reason':   synthesis_reason,
            'synthesized_count':  n,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class NarrativeArcMerger:
    """
    Merge convergent dormant arcs when identity overlap >= MERGE_THRESHOLD.

    Identity overlap uses token-level Jaccard similarity of family_sig strings.
    Suppressed lineage bonus (+0.10) applied when both families share
    archive history in SuppressedThreadArchive.

    MERGE_THRESHOLD: 0.65  (Rule 2 -- prevents false milestone fusion)

    Outputs per record:
        tick                   : int
        merged_arcs            : list[dict] -- each: {primary_family,
                                     secondary_family, overlap_score,
                                     merged_label}
        merge_confidence       : float -- mean overlap of all merged pairs
        identity_overlap_score : float -- max overlap seen this tick
        merge_count            : int

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    MERGE_THRESHOLD = 0.65
    BIOLOGY_TOKENS  = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    @staticmethod
    def _jaccard(a, b):
        import re as _re
        toks_a = set(_re.split(r'[_\-\s]+', a.lower())) - {''}
        toks_b = set(_re.split(r'[_\-\s]+', b.lower())) - {''}
        if not toks_a and not toks_b:
            return 1.0
        if not toks_a or not toks_b:
            return 0.0
        return len(toks_a & toks_b) / len(toks_a | toks_b)

    def update(self, tick,
               milestone_memory_synthesizer,
               suppressed_thread_archive,
               goal_arbitration_engine):

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestones = mms_rec.get('milestone_memories', [])

        archived_families = set()
        if suppressed_thread_archive and hasattr(suppressed_thread_archive, '_archive'):
            archived_families = set(suppressed_thread_archive._archive.keys())

        merged_arcs   = []
        checked_pairs = set()
        max_overlap   = 0.0

        for i, m1 in enumerate(milestones):
            fam1 = m1.get('family_sig', '')
            if self._is_biology(fam1):
                continue
            for j, m2 in enumerate(milestones):
                if j <= i:
                    continue
                fam2 = m2.get('family_sig', '')
                if self._is_biology(fam2):
                    continue
                pair_key = (min(fam1, fam2), max(fam1, fam2))
                if pair_key in checked_pairs:
                    continue
                checked_pairs.add(pair_key)

                overlap = self._jaccard(fam1, fam2)
                if fam1 in archived_families and fam2 in archived_families:
                    overlap = self._clamp(overlap + 0.10)
                if overlap > max_overlap:
                    max_overlap = overlap

                if overlap >= self.MERGE_THRESHOLD:
                    sal1 = m1.get('salience', 0.0)
                    sal2 = m2.get('salience', 0.0)
                    primary   = fam1 if sal1 >= sal2 else fam2
                    secondary = fam2 if primary == fam1 else fam1
                    merged_arcs.append({
                        'primary_family':   primary,
                        'secondary_family': secondary,
                        'overlap_score':    self._clamp(overlap),
                        'merged_label':     '{}_x_{}'.format(
                            primary[:20], secondary[:20]
                        ),
                    })

        merge_confidence = self._clamp(
            sum(a['overlap_score'] for a in merged_arcs) / len(merged_arcs)
        ) if merged_arcs else 0.0

        record = {
            'tick':                    tick,
            'merged_arcs':             merged_arcs,
            'merge_confidence':        merge_confidence,
            'identity_overlap_score':  self._clamp(max_overlap),
            'merge_count':             len(merged_arcs),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ProjectIdentityContinuityIndex:
    """
    Frozen long-gap identity coherence score integrating four orthogonal
    autobiographical signals into a single bounded index.

    Formula (frozen):
        identity_index =
              milestone_salience    * 0.35
            + continuity_strength   * 0.25
            + arbitration_stability * 0.20
            + recovery_resilience   * 0.20
        Clamped to [0, 1].

    Sources:
        milestone_salience    <- MilestoneMemorySynthesizer.milestone_salience
        continuity_strength   <- CrossSessionPlanMemory.continuity_score
        arbitration_stability <- GoalArbitrationEngine.arbitration_score
        recovery_resilience   <- ResumeConfidenceAdvisor.resume_confidence

    index_state classification:
        'strong'   : identity_index >= 0.70
        'moderate' : identity_index >= 0.40
        'fragile'  : identity_index <  0.40

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               milestone_memory_synthesizer,
               cross_session_plan_memory,
               goal_arbitration_engine,
               resume_confidence_advisor):

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestone_salience = float(mms_rec.get('milestone_salience', 0.0))

        cspm_rec = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_rec = cross_session_plan_memory.latest() or {}
        continuity_strength = float(cspm_rec.get('continuity_score', 0.5))

        gae_rec = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_rec = goal_arbitration_engine.latest() or {}
        arbitration_stability = float(gae_rec.get('arbitration_score', 0.5))

        rca_rec = {}
        if resume_confidence_advisor and hasattr(resume_confidence_advisor, 'latest'):
            rca_rec = resume_confidence_advisor.latest() or {}
        recovery_resilience = float(rca_rec.get('resume_confidence', 0.5))

        identity_index = self._clamp(
            milestone_salience    * 0.35
            + continuity_strength  * 0.25
            + arbitration_stability * 0.20
            + recovery_resilience  * 0.20
        )

        if identity_index >= 0.70:
            index_state = 'strong'
        elif identity_index >= 0.40:
            index_state = 'moderate'
        else:
            index_state = 'fragile'

        record = {
            'tick':                   tick,
            'identity_index':         identity_index,
            'milestone_salience':     milestone_salience,
            'continuity_strength':    continuity_strength,
            'arbitration_stability':  arbitration_stability,
            'recovery_resilience':    recovery_resilience,
            'index_state':            index_state,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class DormantMilestoneReviver:
    """
    Detect and revive dormant milestone-worthy arcs before purge.

    Revival criteria (Rule 3 -- all three must hold):
        suppression_count >= SUPPRESSION_THRESHOLD (3)
        initial_priority  >= PRIORITY_FLOOR (0.40)
        Biology exclusion applies unconditionally.

    Deferred eligibility: flagged when family appears in
    DeferredResumptionGovernor.resumption_candidates.

    revival_priority formula:
        initial_priority * 0.60 + clamp(suppression_count / 10.0) * 0.40

    Outputs per record:
        tick               : int
        revived_milestones : list[dict] -- each: {family_sig,
                                revival_priority, suppression_count,
                                initial_priority, deferred_eligible}
        revival_reason     : str
        revival_priority   : float -- max across revived milestones
        revival_count      : int

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    BIOLOGY_TOKENS        = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })
    SUPPRESSION_THRESHOLD = 3
    PRIORITY_FLOOR        = 0.40

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               suppressed_thread_archive,
               cross_session_plan_memory,
               deferred_resumption_governor):

        archive = {}
        if suppressed_thread_archive and hasattr(suppressed_thread_archive, '_archive'):
            archive = suppressed_thread_archive._archive

        drg_rec = {}
        if deferred_resumption_governor and hasattr(deferred_resumption_governor, 'latest'):
            drg_rec = deferred_resumption_governor.latest() or {}
        deferred_families = {
            c.get('family_sig', '')
            for c in drg_rec.get('resumption_candidates', [])
        }

        revived_milestones = []
        for fam, entry in archive.items():
            if self._is_biology(fam):
                continue
            sup_count     = int(entry.get('suppression_count', 0))
            init_priority = float(entry.get('initial_priority', 0.5))
            if sup_count < self.SUPPRESSION_THRESHOLD:
                continue
            if init_priority < self.PRIORITY_FLOOR:
                continue
            revival_priority = self._clamp(
                init_priority * 0.60
                + min(1.0, sup_count / 10.0) * 0.40
            )
            revived_milestones.append({
                'family_sig':        fam,
                'revival_priority':  revival_priority,
                'suppression_count': sup_count,
                'initial_priority':  init_priority,
                'deferred_eligible': fam in deferred_families,
            })

        revived_milestones.sort(key=lambda x: x['revival_priority'], reverse=True)

        if revived_milestones:
            max_priority   = revived_milestones[0]['revival_priority']
            revival_reason = 'dormant_arcs_revived_{}'.format(len(revived_milestones))
        else:
            max_priority   = 0.0
            revival_reason = 'no_eligible_dormant_arcs'

        record = {
            'tick':               tick,
            'revived_milestones': revived_milestones,
            'revival_reason':     revival_reason,
            'revival_priority':   max_priority,
            'revival_count':      len(revived_milestones),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MilestoneDependencyGraph:
    """
    Track milestone prerequisites, unresolved blockers, dormant dependencies,
    and deferred critical chains as a post-break scientific path memory.

    critical_milestone_path: milestones ordered by salience, revived dormant
                             milestones appended after.
    blocked_milestones: path entries intersecting suppressed_threads or
                        named in narrative conflict provenance.
    dependency_pressure: blocked_count / max(1, total_path_length).

    graph_state classification:
        'clear'     : dependency_pressure == 0.0
        'pressured' : dependency_pressure <= 0.50
        'blocked'   : dependency_pressure >  0.50

    Biology family exclusion enforced at all entry points.

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               milestone_memory_synthesizer,
               dormant_milestone_reviver,
               goal_arbitration_engine,
               narrative_conflict_resolver):

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestones = mms_rec.get('milestone_memories', [])

        dmr_rec = {}
        if dormant_milestone_reviver and hasattr(dormant_milestone_reviver, 'latest'):
            dmr_rec = dormant_milestone_reviver.latest() or {}
        revived = dmr_rec.get('revived_milestones', [])

        gae_rec = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_rec = goal_arbitration_engine.latest() or {}
        suppressed_threads = set(gae_rec.get('suppressed_threads', []))

        ncr_rec = {}
        if narrative_conflict_resolver and hasattr(narrative_conflict_resolver, 'latest'):
            ncr_rec = narrative_conflict_resolver.latest() or {}
        conflict_families = set()
        for prov in ncr_rec.get('conflict_provenance', []):
            if not isinstance(prov, dict):
                continue
            for f in prov.get('families', []):
                conflict_families.add(f)
            if 'family' in prov:
                conflict_families.add(prov['family'])

        critical_path = []
        for m in milestones:
            fam = m.get('family_sig', '')
            if self._is_biology(fam):
                continue
            critical_path.append(fam)
        for r in revived:
            fam = r.get('family_sig', '')
            if self._is_biology(fam) or fam in critical_path:
                continue
            critical_path.append(fam)

        blocked_milestones = [
            fam for fam in critical_path
            if fam in suppressed_threads or fam in conflict_families
        ]

        dep_pressure = self._clamp(len(blocked_milestones) / max(1, len(critical_path)))

        if dep_pressure == 0.0:
            graph_state = 'clear'
        elif dep_pressure <= 0.50:
            graph_state = 'pressured'
        else:
            graph_state = 'blocked'

        record = {
            'tick':                    tick,
            'critical_milestone_path': critical_path,
            'blocked_milestones':      blocked_milestones,
            'dependency_pressure':     dep_pressure,
            'path_length':             len(critical_path),
            'graph_state':             graph_state,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class BreakResumptionAnchor:
    """
    Single post-break restart anchor representing the organism's most
    meaningful week-gap self-return story.

    Uniqueness law (Rule 4): exactly one primary break anchor per record.
    anchor_unique is always True -- enforced structurally, not conditionally.
    Biology family exclusion enforced at all entry points.

    break_anchor schema:
        primary_milestone       : str or None
        critical_path           : list[str] -- bounded to 6 entries
        first_resumption_thread : str or None
        stable_safe_anchor      : dict or None
        unresolved_question     : str -- ASCII
        re_entry_rationale      : str -- ASCII

    restart_priority formula:
        identity_index * 0.50 + milestone_salience * 0.50
    Clamped to [0, 1].

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               project_identity_continuity_index,
               milestone_dependency_graph,
               milestone_memory_synthesizer,
               goal_arbitration_engine,
               deferred_resumption_governor,
               cross_session_plan_memory):

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))
        index_state    = pici_rec.get('index_state', 'moderate')

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        critical_path = mdg_rec.get('critical_milestone_path', [])
        graph_state   = mdg_rec.get('graph_state', 'clear')

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestones         = mms_rec.get('milestone_memories', [])
        milestone_salience = float(mms_rec.get('milestone_salience', 0.0))

        gae_rec = {}
        if goal_arbitration_engine and hasattr(goal_arbitration_engine, 'latest'):
            gae_rec = goal_arbitration_engine.latest() or {}
        selected_thread = gae_rec.get('selected_goal_thread')

        drg_rec = {}
        if deferred_resumption_governor and hasattr(deferred_resumption_governor, 'latest'):
            drg_rec = deferred_resumption_governor.latest() or {}
        deferred_candidates = drg_rec.get('resumption_candidates', [])

        cspm_rec = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_rec = cross_session_plan_memory.latest() or {}
        stable_safe_anchor = cspm_rec.get('safe_resumption_anchor')

        # Primary milestone (top salience, non-biology) -- uniqueness law
        primary_milestone = None
        for m in milestones:
            fam = m.get('family_sig', '')
            if not self._is_biology(fam):
                primary_milestone = fam
                break
        if primary_milestone is None:
            for fam in critical_path:
                if not self._is_biology(fam):
                    primary_milestone = fam
                    break

        # First resumption thread
        first_resumption_thread = None
        for cand in deferred_candidates:
            fam = cand.get('family_sig', '')
            if not self._is_biology(fam):
                first_resumption_thread = fam
                break
        if first_resumption_thread is None and selected_thread:
            if not self._is_biology(selected_thread):
                first_resumption_thread = selected_thread

        # ASCII unresolved question summary
        if primary_milestone:
            unresolved = (
                'Primary arc [{}] requires resumption. '
                'Path depth: {}. Graph: {}.'.format(
                    primary_milestone, len(critical_path), graph_state
                )
            )
        else:
            unresolved = 'No primary milestone identified. Rebuild narrative from scratch.'

        # ASCII re-entry rationale
        if index_state == 'strong':
            rationale = (
                'Identity strong (index={:.2f}). '
                'Resume [{}] first.'.format(
                    identity_index,
                    first_resumption_thread or 'unknown'
                )
            )
        elif index_state == 'moderate':
            rationale = (
                'Identity moderate (index={:.2f}). '
                'Rebuild via [{}].'.format(
                    identity_index,
                    first_resumption_thread or 'unknown'
                )
            )
        else:
            rationale = (
                'Identity fragile (index={:.2f}). '
                'Diagnostic recovery before action.'.format(identity_index)
            )

        break_anchor = {
            'primary_milestone':        primary_milestone,
            'critical_path':            critical_path[:6],
            'first_resumption_thread':  first_resumption_thread,
            'stable_safe_anchor':       stable_safe_anchor,
            'unresolved_question':      unresolved,
            're_entry_rationale':       rationale,
        }

        restart_priority = self._clamp(
            identity_index * 0.50 + milestone_salience * 0.50
        )

        if primary_milestone:
            anchor_reason = 'anchor_set_primary={}_priority={:.2f}'.format(
                primary_milestone, restart_priority
            )
        else:
            anchor_reason = 'anchor_fallback_no_milestone'

        record = {
            'tick':             tick,
            'break_anchor':     break_anchor,
            'restart_priority': restart_priority,
            'anchor_reason':    anchor_reason,
            'anchor_unique':    True,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


