# DAY 28 PHASE B -- Break-Aware Resumption Intelligence Suite
# Long-gap restart cognition: priority ordering, blocker-first override,
# momentum recovery, dormant final revival, stale pruning, restart script.
# Tulving 1985 (task resumption after episodic gaps);
# Anderson & Bjork 1994 (retrieval-induced forgetting / pruning);
# Fuster 2008 (prefrontal momentum restoration)
# ===========================================================================

class ResumptionPriorityEngine:
    """
    Convert break anchor, milestone salience, dependency pressure,
    arbitration stability, and continuity strength into ordered restart
    priorities for the post-break first tick.

    Blocker-first override (Rule 2):
        If dependency_pressure >= 0.70, blocked milestones are promoted
        to the front of restart_priorities unconditionally.

    RESTART_CAP: 5 -- no post-break overwhelm.

    resume_confidence formula:
        identity_index * 0.50
        + continuity_score * 0.30
        + milestone_salience * 0.20
    Clamped to [0, 1].

    Outputs per record:
        tick              : int
        restart_priorities: list[dict] -- max 5, ordered, each:
                              {family_sig, priority_score, priority_rank,
                               reason, is_blocker}
        priority_reason   : str
        resume_confidence : float

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    RESTART_CAP             = 5
    BLOCKER_PRESSURE_THRESH = 0.70
    BIOLOGY_TOKENS          = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               break_resumption_anchor,
               milestone_memory_synthesizer,
               milestone_dependency_graph,
               project_identity_continuity_index,
               cross_session_plan_memory):

        bra_rec = {}
        if break_resumption_anchor and hasattr(break_resumption_anchor, 'latest'):
            bra_rec = break_resumption_anchor.latest() or {}
        break_anchor    = bra_rec.get('break_anchor', {}) or {}
        restart_priority = float(bra_rec.get('restart_priority', 0.5))

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestones         = mms_rec.get('milestone_memories', [])
        milestone_salience = float(mms_rec.get('milestone_salience', 0.0))

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        blocked_milestones = mdg_rec.get('blocked_milestones', [])
        dep_pressure       = float(mdg_rec.get('dependency_pressure', 0.0))

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))

        cspm_rec = {}
        if cross_session_plan_memory and hasattr(cross_session_plan_memory, 'latest'):
            cspm_rec = cross_session_plan_memory.latest() or {}
        continuity_score = float(cspm_rec.get('continuity_score', 0.5))

        resume_confidence = self._clamp(
            identity_index     * 0.50
            + continuity_score  * 0.30
            + milestone_salience * 0.20
        )

        # Build candidate list
        first_thread = break_anchor.get('first_resumption_thread')
        seen         = set()
        candidates   = []

        # Blocker-first override (Rule 2)
        blocker_override = dep_pressure >= self.BLOCKER_PRESSURE_THRESH
        if blocker_override:
            for fam in blocked_milestones:
                if self._is_biology(fam) or fam in seen:
                    continue
                seen.add(fam)
                candidates.append({
                    'family_sig':     fam,
                    'priority_score': self._clamp(dep_pressure),
                    'reason':         'blocker_override',
                    'is_blocker':     True,
                })

        # First resumption thread (from break anchor)
        if first_thread and not self._is_biology(first_thread) and first_thread not in seen:
            seen.add(first_thread)
            candidates.append({
                'family_sig':     first_thread,
                'priority_score': restart_priority,
                'reason':         'break_anchor_primary',
                'is_blocker':     False,
            })

        # Remaining milestone families by salience
        for m in milestones:
            fam = m.get('family_sig', '')
            if self._is_biology(fam) or fam in seen:
                continue
            seen.add(fam)
            candidates.append({
                'family_sig':     fam,
                'priority_score': float(m.get('salience', 0.5)),
                'reason':         'milestone_salience',
                'is_blocker':     fam in blocked_milestones,
            })

        candidates = candidates[:self.RESTART_CAP]
        for i, c in enumerate(candidates):
            c['priority_rank'] = i + 1

        if not candidates:
            priority_reason = 'no_restart_targets'
        elif blocker_override:
            priority_reason = 'blocker_first_override_pressure={:.2f}'.format(dep_pressure)
        else:
            priority_reason = 'salience_ordered_{}_targets'.format(len(candidates))

        record = {
            'tick':               tick,
            'restart_priorities': candidates,
            'priority_reason':    priority_reason,
            'resume_confidence':  resume_confidence,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MilestoneBlockerResolver:
    """
    Detect and order critical blocked milestones, deferred unresolved
    chains, and dormant dependency failures for blocker-first resolution.

    primary_blocker: first item in blocked_milestones (highest-pressure).
    blocker_resolution_path: [primary_blocker] + up to 3 non-biology
        deferred candidates from DeferredResumptionGovernor.
    dependency_unwind_order: critical_milestone_path[:5].

    resolver_state classification:
        'critical'   : dependency_pressure >= 0.70
        'resolving'  : dependency_pressure > 0.0 and < 0.70
        'unblocked'  : dependency_pressure == 0.0

    Biology family exclusion enforced at all entry points.

    Outputs per record:
        tick                    : int
        primary_blocker         : str or None
        blocker_resolution_path : list[str]
        dependency_unwind_order : list[str]
        blocker_pressure        : float
        resolver_state          : str

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    CRITICAL_PRESSURE = 0.70
    BIOLOGY_TOKENS    = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               milestone_dependency_graph,
               deferred_resumption_governor,
               goal_arbitration_engine,
               cross_session_plan_memory):

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        blocked_milestones = [
            f for f in mdg_rec.get('blocked_milestones', [])
            if not self._is_biology(f)
        ]
        critical_path = [
            f for f in mdg_rec.get('critical_milestone_path', [])
            if not self._is_biology(f)
        ]
        dep_pressure = float(mdg_rec.get('dependency_pressure', 0.0))

        drg_rec = {}
        if deferred_resumption_governor and hasattr(deferred_resumption_governor, 'latest'):
            drg_rec = deferred_resumption_governor.latest() or {}
        deferred_candidates = [
            c.get('family_sig', '') for c in drg_rec.get('resumption_candidates', [])
            if not self._is_biology(c.get('family_sig', ''))
        ]

        primary_blocker = blocked_milestones[0] if blocked_milestones else None

        # Resolution path: primary blocker + up to 3 deferred candidates
        resolution_path = []
        if primary_blocker:
            resolution_path.append(primary_blocker)
        for fam in deferred_candidates:
            if fam not in resolution_path:
                resolution_path.append(fam)
            if len(resolution_path) >= 4:
                break

        dependency_unwind_order = critical_path[:5]

        if dep_pressure >= self.CRITICAL_PRESSURE:
            resolver_state = 'critical'
        elif dep_pressure > 0.0:
            resolver_state = 'resolving'
        else:
            resolver_state = 'unblocked'

        record = {
            'tick':                    tick,
            'primary_blocker':         primary_blocker,
            'blocker_resolution_path': resolution_path,
            'dependency_unwind_order': dependency_unwind_order,
            'blocker_pressure':        dep_pressure,
            'resolver_state':          resolver_state,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MomentumRecoveryPlanner:
    """
    Design the first 5-step momentum restoration arc for post-break
    re-entry, analogous to warm-start cognitive sequencing observed in
    episodic memory reinstatement (Tulving, 1985).

    RESTART_CAP: 5 -- no overwhelm.

    Step assembly order:
        Step 1: primary_blocker resolution (if any blocker present)
        Steps 2-3: top restart priorities (milestone reconnections)
        Step 4: confidence rebuild via safe anchor
        Step 5: executive handoff to first resumption thread

    recovery_confidence formula:
        resume_confidence * 0.60 + milestone_salience * 0.40
    Clamped to [0, 1].

    action_type values:
        'blocker_resolution', 'milestone_reconnect',
        'confidence_rebuild', 'executive_handoff', 'low_friction_win'

    Biology family exclusion enforced at all entry points.

    Outputs per record:
        tick               : int
        momentum_sequence  : list[dict] -- max 5, each:
                               {step, action_type, target_family,
                                description, confidence}
        recovery_confidence: float
        warm_start_reason  : str

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    RESTART_CAP    = 5
    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               resumption_priority_engine,
               milestone_blocker_resolver,
               break_resumption_anchor,
               milestone_memory_synthesizer):

        rpe_rec = {}
        if resumption_priority_engine and hasattr(resumption_priority_engine, 'latest'):
            rpe_rec = resumption_priority_engine.latest() or {}
        restart_priorities = rpe_rec.get('restart_priorities', [])
        resume_confidence  = float(rpe_rec.get('resume_confidence', 0.5))

        mbr_rec = {}
        if milestone_blocker_resolver and hasattr(milestone_blocker_resolver, 'latest'):
            mbr_rec = milestone_blocker_resolver.latest() or {}
        primary_blocker  = mbr_rec.get('primary_blocker')
        resolver_state   = mbr_rec.get('resolver_state', 'unblocked')

        bra_rec = {}
        if break_resumption_anchor and hasattr(break_resumption_anchor, 'latest'):
            bra_rec = break_resumption_anchor.latest() or {}
        break_anchor         = bra_rec.get('break_anchor', {}) or {}
        first_resume_thread  = break_anchor.get('first_resumption_thread')
        stable_safe_anchor   = break_anchor.get('stable_safe_anchor')

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestone_salience = float(mms_rec.get('milestone_salience', 0.0))

        recovery_confidence = self._clamp(
            resume_confidence * 0.60 + milestone_salience * 0.40
        )

        sequence = []
        used_fams = set()

        # Step 1 -- blocker resolution (if any)
        if primary_blocker and not self._is_biology(primary_blocker):
            used_fams.add(primary_blocker)
            sequence.append({
                'step':          1,
                'action_type':   'blocker_resolution',
                'target_family': primary_blocker,
                'description':   'Resolve blocker [{}] before advancing.'.format(
                    primary_blocker),
                'confidence':    self._clamp(recovery_confidence * 0.90),
            })

        # Steps 2-3 -- milestone reconnections from priority engine
        step_n = len(sequence) + 1
        for p in restart_priorities:
            if step_n > 3 or len(sequence) >= self.RESTART_CAP - 2:
                break
            fam = p.get('family_sig', '')
            if self._is_biology(fam) or fam in used_fams:
                continue
            used_fams.add(fam)
            sequence.append({
                'step':          step_n,
                'action_type':   'milestone_reconnect',
                'target_family': fam,
                'description':   'Reconnect milestone arc [{}].'.format(fam),
                'confidence':    self._clamp(float(p.get('priority_score', 0.5))),
            })
            step_n += 1

        # Step (next) -- confidence rebuild
        if len(sequence) < self.RESTART_CAP:
            anchor_fam = None
            if isinstance(stable_safe_anchor, dict):
                anchor_fam = stable_safe_anchor.get('family')
            sequence.append({
                'step':          len(sequence) + 1,
                'action_type':   'confidence_rebuild',
                'target_family': anchor_fam,
                'description':   'Rebuild confidence via safe anchor{}.'.format(
                    ' [{}]'.format(anchor_fam) if anchor_fam else ''
                ),
                'confidence':    self._clamp(recovery_confidence * 0.80),
            })

        # Final step -- executive handoff
        if len(sequence) < self.RESTART_CAP and first_resume_thread:
            if not self._is_biology(first_resume_thread):
                sequence.append({
                    'step':          len(sequence) + 1,
                    'action_type':   'executive_handoff',
                    'target_family': first_resume_thread,
                    'description':   'Hand off execution to [{}].'.format(
                        first_resume_thread),
                    'confidence':    recovery_confidence,
                })

        # Pad with low_friction_win if under cap and no thread for handoff
        if len(sequence) < self.RESTART_CAP:
            sequence.append({
                'step':          len(sequence) + 1,
                'action_type':   'low_friction_win',
                'target_family': None,
                'description':   'Execute lowest-risk available action.',
                'confidence':    self._clamp(recovery_confidence * 0.70),
            })

        sequence = sequence[:self.RESTART_CAP]

        if not sequence:
            warm_start_reason = 'no_momentum_targets'
        elif resolver_state == 'critical':
            warm_start_reason = 'blocker_first_sequence'
        else:
            warm_start_reason = 'salience_warm_start_{}_steps'.format(len(sequence))

        record = {
            'tick':                tick,
            'momentum_sequence':   sequence,
            'recovery_confidence': recovery_confidence,
            'warm_start_reason':   warm_start_reason,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class DormantFinalRevivalGate:
    """
    Allow exactly one final milestone resurrection attempt before purge
    (Rule 3: one revival attempt per break cycle).

    Target: highest revival_priority dormant milestone from
    DormantMilestoneReviver.revived_milestones.

    revival_viability formula:
        revival_priority * 0.70 + (1.0 - dependency_pressure) * 0.30
    Clamped to [0, 1].

    gate_state classification:
        'viable'        : revival_viability >= 0.50
        'low_viability' : revival_viability >= 0.20 and < 0.50
        'no_candidates' : no revived milestones available

    Biology family exclusion enforced unconditionally.

    Outputs per record:
        tick               : int
        final_revival_target: str or None
        revival_viability  : float
        revival_reason     : str
        gate_state         : str

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    VIABILITY_THRESH     = 0.50
    LOW_VIABILITY_THRESH = 0.20
    BIOLOGY_TOKENS       = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               dormant_milestone_reviver,
               milestone_dependency_graph,
               suppressed_thread_archive):

        dmr_rec = {}
        if dormant_milestone_reviver and hasattr(dormant_milestone_reviver, 'latest'):
            dmr_rec = dormant_milestone_reviver.latest() or {}
        revived = [
            r for r in dmr_rec.get('revived_milestones', [])
            if not self._is_biology(r.get('family_sig', ''))
        ]

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        dep_pressure = float(mdg_rec.get('dependency_pressure', 0.0))

        if not revived:
            record = {
                'tick':                 tick,
                'final_revival_target': None,
                'revival_viability':    0.0,
                'revival_reason':       'no_dormant_candidates',
                'gate_state':           'no_candidates',
            }
            self._history.append(record)
            return record

        # Single highest revival_priority candidate (uniqueness law)
        top = revived[0]
        fam              = top.get('family_sig', '')
        revival_priority = float(top.get('revival_priority', 0.5))

        revival_viability = self._clamp(
            revival_priority * 0.70
            + (1.0 - dep_pressure) * 0.30
        )

        if revival_viability >= self.VIABILITY_THRESH:
            gate_state     = 'viable'
            revival_reason = 'viable_revival_{}_priority={:.2f}'.format(
                fam, revival_priority
            )
        elif revival_viability >= self.LOW_VIABILITY_THRESH:
            gate_state     = 'low_viability'
            revival_reason = 'low_viability_{}_consider_prune'.format(fam)
        else:
            gate_state     = 'no_candidates'
            revival_reason = 'below_threshold_{}_prune_eligible'.format(fam)
            fam            = None

        record = {
            'tick':                 tick,
            'final_revival_target': fam,
            'revival_viability':    revival_viability,
            'revival_reason':       revival_reason,
            'gate_state':           gate_state,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class StaleNarrativePruner:
    """
    Mark dormant arcs as safe_to_prune using four-criterion hygiene rule
    (Rule 4 -- all criteria must hold simultaneously):
        1. no milestone contribution   : not in critical_milestone_path
        2. no critical dependency      : not in blocked_milestones
        3. suppression age >= 16       : starvation_duration >= STALE_THRESHOLD
        4. identity overlap < 0.40     : Jaccard vs all milestone family_sigs

    Biology family exclusion enforced unconditionally.

    prune_confidence: fraction of criteria met per candidate (mean),
                      producing a signal for downstream decisiveness.
    For safe_to_prune candidates, prune_confidence is always 1.0 per entry.

    Outputs per record:
        tick             : int
        prune_candidates : list[str]  -- safe_to_prune family_sigs
        prune_confidence : float      -- mean fraction of criteria met
        prune_reason     : str
        pruned_count     : int

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    STALE_THRESHOLD    = 16
    OVERLAP_CEILING    = 0.40
    BIOLOGY_TOKENS     = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    @staticmethod
    def _jaccard(a, b):
        import re as _re
        toks_a = set(_re.split(r'[_\-\s]+', a.lower())) - {''}
        toks_b = set(_re.split(r'[_\-\s]+', b.lower())) - {''}
        if not toks_a and not toks_b:
            return 1.0
        if not toks_a or not toks_b:
            return 0.0
        return len(toks_a & toks_b) / len(toks_a | toks_b)

    def _max_overlap_with_milestones(self, fam, milestone_fams):
        if not milestone_fams:
            return 0.0
        return max(self._jaccard(fam, m) for m in milestone_fams)

    def update(self, tick,
               suppressed_thread_archive,
               narrative_arc_merger,
               milestone_dependency_graph):

        archive = {}
        if suppressed_thread_archive and hasattr(suppressed_thread_archive, '_archive'):
            archive = suppressed_thread_archive._archive

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        critical_path      = set(mdg_rec.get('critical_milestone_path', []))
        blocked_milestones = set(mdg_rec.get('blocked_milestones', []))
        milestone_fams     = list(critical_path)

        prune_candidates  = []
        criteria_scores   = []

        for fam, entry in archive.items():
            if self._is_biology(fam):
                continue

            # Criterion 1: no milestone contribution
            c1 = fam not in critical_path

            # Criterion 2: no critical dependency
            c2 = fam not in blocked_milestones

            # Criterion 3: stale
            starvation = int(entry.get('starvation_duration', 0))
            c3 = starvation >= self.STALE_THRESHOLD

            # Criterion 4: low identity overlap with milestones
            overlap = self._max_overlap_with_milestones(fam, milestone_fams)
            c4 = overlap < self.OVERLAP_CEILING

            score = sum([c1, c2, c3, c4]) / 4.0
            criteria_scores.append(score)

            if c1 and c2 and c3 and c4:
                prune_candidates.append(fam)

        prune_confidence = (
            sum(criteria_scores) / len(criteria_scores)
            if criteria_scores else 0.0
        )

        if prune_candidates:
            prune_reason = 'stale_arcs_safe_to_prune_{}'.format(len(prune_candidates))
        elif criteria_scores:
            prune_reason = 'no_fully_eligible_arcs_partial={:.2f}'.format(prune_confidence)
        else:
            prune_reason = 'archive_empty_no_prune_needed'

        record = {
            'tick':             tick,
            'prune_candidates': prune_candidates,
            'prune_confidence': min(1.0, max(0.0, prune_confidence)),
            'prune_reason':     prune_reason,
            'pruned_count':     len(prune_candidates),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class WeekGapRestartSequence:
    """
    Construct the canonical 7-day return script -- the organism's first
    week-gap action playbook integrating all Phase B signals.

    restart_script schema:
        step_1_blocker           : str or None -- primary blocker family
        momentum_sequence        : list[dict]  -- from MomentumRecoveryPlanner
        final_revival_candidate  : str or None -- from DormantFinalRevivalGate
        first_safe_milestone     : str or None -- top non-blocked milestone
        first_narrative_followup : str         -- ASCII follow-up summary

    week_gap_confidence formula:
        recovery_confidence * 0.50
        + revival_viability * 0.20
        + restart_priority  * 0.30
    Clamped to [0, 1].

    Biology family exclusion enforced unconditionally.

    Outputs per record:
        tick                : int
        restart_script      : dict
        week_gap_confidence : float
        restart_rationale   : str -- ASCII

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.BIOLOGY_TOKENS)

    def update(self, tick,
               milestone_blocker_resolver,
               momentum_recovery_planner,
               dormant_final_revival_gate,
               milestone_memory_synthesizer,
               break_resumption_anchor):

        mbr_rec = {}
        if milestone_blocker_resolver and hasattr(milestone_blocker_resolver, 'latest'):
            mbr_rec = milestone_blocker_resolver.latest() or {}
        primary_blocker = mbr_rec.get('primary_blocker')

        mrp_rec = {}
        if momentum_recovery_planner and hasattr(momentum_recovery_planner, 'latest'):
            mrp_rec = momentum_recovery_planner.latest() or {}
        momentum_sequence   = mrp_rec.get('momentum_sequence', [])
        recovery_confidence = float(mrp_rec.get('recovery_confidence', 0.5))

        dfr_rec = {}
        if dormant_final_revival_gate and hasattr(dormant_final_revival_gate, 'latest'):
            dfr_rec = dormant_final_revival_gate.latest() or {}
        final_revival_candidate = dfr_rec.get('final_revival_target')
        revival_viability       = float(dfr_rec.get('revival_viability', 0.0))

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestones = mms_rec.get('milestone_memories', [])

        bra_rec = {}
        if break_resumption_anchor and hasattr(break_resumption_anchor, 'latest'):
            bra_rec = break_resumption_anchor.latest() or {}
        restart_priority = float(bra_rec.get('restart_priority', 0.5))
        break_anchor     = bra_rec.get('break_anchor', {}) or {}

        # First safe milestone (top salience, non-biology, non-blocker)
        blocker_set = {primary_blocker} if primary_blocker else set()
        first_safe_milestone = None
        for m in milestones:
            fam = m.get('family_sig', '')
            if not self._is_biology(fam) and fam not in blocker_set:
                first_safe_milestone = fam
                break

        # ASCII narrative follow-up
        primary_milestone = break_anchor.get('primary_milestone')
        if primary_milestone and not self._is_biology(primary_milestone):
            followup = (
                'After resolving blockers, synthesize new narrative '
                'evidence for [{}] and update milestone record.'.format(
                    primary_milestone
                )
            )
        elif first_safe_milestone:
            followup = (
                'Begin narrative reconnection at [{}] and '
                'verify milestone coherence.'.format(first_safe_milestone)
            )
        else:
            followup = 'Rebuild narrative from freshest identity thread available.'

        restart_script = {
            'step_1_blocker':           primary_blocker,
            'momentum_sequence':        momentum_sequence,
            'final_revival_candidate':  final_revival_candidate,
            'first_safe_milestone':     first_safe_milestone,
            'first_narrative_followup': followup,
        }

        week_gap_confidence = self._clamp(
            recovery_confidence * 0.50
            + revival_viability  * 0.20
            + restart_priority   * 0.30
        )

        # ASCII rationale
        if primary_blocker:
            rationale = (
                'Blocker [{}] resolved first. '
                'Then momentum via {} steps. '
                'Confidence={:.2f}.'.format(
                    primary_blocker, len(momentum_sequence), week_gap_confidence
                )
            )
        elif first_safe_milestone:
            rationale = (
                'No blocker. Warm-start at [{}]. '
                '{} momentum steps. '
                'Confidence={:.2f}.'.format(
                    first_safe_milestone, len(momentum_sequence), week_gap_confidence
                )
            )
        else:
            rationale = (
                'No clear target. Generic recovery. '
                'Confidence={:.2f}.'.format(week_gap_confidence)
            )

        record = {
            'tick':                tick,
            'restart_script':      restart_script,
            'week_gap_confidence': week_gap_confidence,
            'restart_rationale':   rationale,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


