class HypothesisPersistenceMemory:
    """
    Store unresolved scientific questions that must survive week-long silence
    as living curiosity vectors.

    HYPOTHESIS_CAP: 5 (Rule 1 -- no scientific clutter).
    EEIL_PRIORITY_BONUS: +0.15 (Rule 2) for hypotheses touching sparse law,
        horizon compression, continuity-before-localization, biology exclusion
        edge cases, or energy/performance tradeoffs.

    Hypothesis seeds are fixed templates. Each seed is scored per tick from
    organism state and the top-5 by salience are retained as active_hypotheses.

    salience formula per hypothesis:
        base_score * 0.40
        + identity_index * 0.30
        + week_gap_confidence * 0.30
        + eeil_priority_bonus (0.15 if eeil_tagged, else 0.0)
    Clamped to [0, 1].

    persistence_class values:
        'eeil_critical'    : eeil_tagged and salience >= 0.60
        'publication_risk' : linked to paper claim seed
        'dormant_risk'     : linked to dormant revival uncertainty
        'standard'         : all other

    Biology runtime token exclusion enforced.
    Conceptual biology hypotheses are permitted (Rule 5).

    Outputs per record:
        tick                : int
        active_hypotheses   : list[dict] -- max 5, each:
                                {hypothesis_id, question_text, salience,
                                 eeil_tagged, persistence_class}
        hypothesis_salience : float -- mean salience
        persistence_reason  : str

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    HYPOTHESIS_CAP      = 5
    EEIL_PRIORITY_BONUS = 0.15
    RUNTIME_BIO_TOKENS  = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    HYPOTHESIS_SEEDS = [
        {
            'id': 'eeil_sparse_law',
            'question': 'Does the EEIL sparse compute bound hold under '
                        'sustained narrative conflict pressure?',
            'eeil_tagged': True,
            'base_score': 0.80,
            'persistence_class_hint': 'eeil_critical',
        },
        {
            'id': 'continuity_before_localization',
            'question': 'Can milestone identity survive across session gaps '
                        'without region localization?',
            'eeil_tagged': True,
            'base_score': 0.75,
            'persistence_class_hint': 'eeil_critical',
        },
        {
            'id': 'horizon_compression_salience',
            'question': 'Does horizon compression degrade milestone salience '
                        'over extended dormancy?',
            'eeil_tagged': True,
            'base_score': 0.70,
            'persistence_class_hint': 'eeil_critical',
        },
        {
            'id': 'biology_exclusion_edge',
            'question': 'Are biology exclusion edges causing silent goal '
                        'arbitration gaps in multi-arc sessions?',
            'eeil_tagged': True,
            'base_score': 0.65,
            'persistence_class_hint': 'eeil_critical',
        },
        {
            'id': 'energy_performance_tradeoff',
            'question': 'What is the compute cost of maintaining six live '
                        'milestone memories under wake-sleep cycling?',
            'eeil_tagged': True,
            'base_score': 0.70,
            'persistence_class_hint': 'eeil_critical',
        },
        {
            'id': 'dormant_revival_fidelity',
            'question': 'Does dormant revival preserve thread identity '
                        'faithfully after eight or more suppression cycles?',
            'eeil_tagged': False,
            'base_score': 0.60,
            'persistence_class_hint': 'dormant_risk',
        },
        {
            'id': 'break_anchor_14day',
            'question': 'Is break anchor coherence sufficient for gaps '
                        'beyond seven days?',
            'eeil_tagged': False,
            'base_score': 0.65,
            'persistence_class_hint': 'publication_risk',
        },
        {
            'id': 'stale_prune_boundary',
            'question': 'What is the safe prune threshold for arcs meeting '
                        'only three of four stale criteria?',
            'eeil_tagged': False,
            'base_score': 0.55,
            'persistence_class_hint': 'standard',
        },
    ]

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               project_identity_continuity_index,
               week_gap_restart_sequence,
               break_resumption_anchor):

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))

        wgr_rec = {}
        if week_gap_restart_sequence and hasattr(week_gap_restart_sequence, 'latest'):
            wgr_rec = week_gap_restart_sequence.latest() or {}
        week_gap_confidence = float(wgr_rec.get('week_gap_confidence', 0.5))

        bra_rec = {}
        if break_resumption_anchor and hasattr(break_resumption_anchor, 'latest'):
            bra_rec = break_resumption_anchor.latest() or {}
        restart_priority = float(bra_rec.get('restart_priority', 0.5))

        scored = []
        for seed in self.HYPOTHESIS_SEEDS:
            base        = float(seed['base_score'])
            eeil_tagged = bool(seed['eeil_tagged'])
            bonus       = self.EEIL_PRIORITY_BONUS if eeil_tagged else 0.0

            salience = self._clamp(
                base              * 0.40
                + identity_index   * 0.30
                + week_gap_confidence * 0.30
                + bonus
            )

            hint = seed['persistence_class_hint']
            if eeil_tagged and salience >= 0.60:
                p_class = 'eeil_critical'
            elif hint == 'publication_risk':
                p_class = 'publication_risk'
            elif hint == 'dormant_risk':
                p_class = 'dormant_risk'
            else:
                p_class = 'standard'

            scored.append({
                'hypothesis_id':     seed['id'],
                'question_text':     seed['question'],
                'salience':          salience,
                'eeil_tagged':       eeil_tagged,
                'persistence_class': p_class,
            })

        scored.sort(key=lambda x: x['salience'], reverse=True)
        active_hypotheses = scored[:self.HYPOTHESIS_CAP]

        hypothesis_salience = self._clamp(
            sum(h['salience'] for h in active_hypotheses) / len(active_hypotheses)
        ) if active_hypotheses else 0.0

        eeil_count = sum(1 for h in active_hypotheses if h['eeil_tagged'])
        if eeil_count == self.HYPOTHESIS_CAP:
            persistence_reason = 'all_eeil_hypotheses_active'
        elif eeil_count > 0:
            persistence_reason = 'mixed_eeil_{}_of_{}'.format(
                eeil_count, self.HYPOTHESIS_CAP)
        else:
            persistence_reason = 'standard_hypotheses_only'

        record = {
            'tick':                tick,
            'active_hypotheses':   active_hypotheses,
            'hypothesis_salience': hypothesis_salience,
            'persistence_reason':  persistence_reason,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class OpenQuestionGraph:
    """
    Build dependency links between unresolved hypotheses and milestone
    blockers, continuity anomalies, and restart script gaps.

    Each active hypothesis is linked to milestone families whose token
    sets share at least one token with the hypothesis question text.
    A question with >= 2 milestone links is classified as a
    critical_unknown (high cross-linkage).

    resolution_dependencies: critical path families that co-occur
    with critical_unknowns' linked milestones.

    graph_density = link_count / max(1, node_count)
    Clamped to [0, 1].

    Biology runtime token exclusion enforced in milestone linking.

    Outputs per record:
        tick                   : int
        question_graph         : list[dict] -- each: {question_id,
                                     linked_milestones, dependency_type,
                                     link_count}
        critical_unknowns      : list[str]  -- question_ids with >= 2 links
        resolution_dependencies: list[str]  -- milestone families that block
                                              critical unknowns
        graph_density          : float

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    RUNTIME_BIO_TOKENS = frozenset({
        'neuron', 'synapse', 'homeostasis', 'hpa',
        'cortisol', 'adenosine', 'homeostatic',
        'cortisolsys', 'adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def _is_runtime_biology(self, fam):
        if not fam:
            return True
        key = str(fam).lower().replace('_', '').replace('-', '')
        return any(t in key for t in self.RUNTIME_BIO_TOKENS)

    @staticmethod
    def _question_tokens(text):
        import re as _re
        return set(_re.findall(r'[a-z]+', text.lower()))

    def update(self, tick,
               hypothesis_persistence_memory,
               milestone_dependency_graph,
               week_gap_restart_sequence):

        hpm_rec = {}
        if hypothesis_persistence_memory and hasattr(hypothesis_persistence_memory, 'latest'):
            hpm_rec = hypothesis_persistence_memory.latest() or {}
        active_hypotheses = hpm_rec.get('active_hypotheses', [])

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        critical_path      = [
            f for f in mdg_rec.get('critical_milestone_path', [])
            if not self._is_runtime_biology(f)
        ]
        blocked_milestones = set(
            f for f in mdg_rec.get('blocked_milestones', [])
            if not self._is_runtime_biology(f)
        )

        question_graph = []
        total_links    = 0

        for hyp in active_hypotheses:
            qid    = hyp.get('hypothesis_id', '')
            qtext  = hyp.get('question_text', '')
            qtoks  = self._question_tokens(qtext)
            linked = []
            for fam in critical_path:
                import re as _re
                fam_toks = set(_re.split(r'[_\-\s]+', fam.lower())) - {''}
                if qtoks & fam_toks:
                    linked.append(fam)

            dep_type = 'blocker_linked' if any(
                f in blocked_milestones for f in linked
            ) else 'path_linked' if linked else 'unlinked'

            total_links += len(linked)
            question_graph.append({
                'question_id':       qid,
                'linked_milestones': linked,
                'dependency_type':   dep_type,
                'link_count':        len(linked),
            })

        critical_unknowns = [
            g['question_id'] for g in question_graph if g['link_count'] >= 2
        ]

        resolution_deps = []
        critical_linked_fams = set()
        for g in question_graph:
            if g['question_id'] in critical_unknowns:
                for f in g['linked_milestones']:
                    critical_linked_fams.add(f)
        resolution_deps = [f for f in critical_path if f in critical_linked_fams]

        node_count    = max(1, len(active_hypotheses))
        graph_density = self._clamp(total_links / node_count)

        record = {
            'tick':                    tick,
            'question_graph':          question_graph,
            'critical_unknowns':       critical_unknowns,
            'resolution_dependencies': resolution_deps,
            'graph_density':           graph_density,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class EEILTensionTracker:
    """
    Track high-value unresolved EEIL tensions using a frozen three-axis
    tension score.

    Tension score formula (frozen):
        tension_score =
              energy_tradeoff   * 0.40
            + continuity_risk   * 0.30
            + publication_value * 0.30
    Clamped to [0, 1].

    Sources:
        energy_tradeoff   = 1.0 - resume_confidence
                            (from ResumptionPriorityEngine)
        continuity_risk   = 1.0 - identity_index
                            (from ProjectIdentityContinuityIndex)
        publication_value = milestone_salience
                            (from MilestoneMemorySynthesizer)

    Only hypotheses flagged eeil_tagged=True are evaluated.
    Each EEIL hypothesis receives its individual tension score.

    paper_relevance: mean publication_value across all EEIL tensions.
    tension_priority: maximum tension_score across all EEIL tensions.

    Biology runtime token exclusion enforced.

    Outputs per record:
        tick              : int
        eeil_tensions     : list[dict] -- each: {hypothesis_id, tension_score,
                               energy_tradeoff, continuity_risk,
                               publication_value, paper_relevant}
        tension_priority  : float -- max tension_score
        paper_relevance   : float -- mean publication_value of EEIL tensions

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               hypothesis_persistence_memory,
               project_identity_continuity_index,
               milestone_memory_synthesizer,
               resumption_priority_engine):

        hpm_rec = {}
        if hypothesis_persistence_memory and hasattr(hypothesis_persistence_memory, 'latest'):
            hpm_rec = hypothesis_persistence_memory.latest() or {}
        active_hyps = hpm_rec.get('active_hypotheses', [])

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))

        mms_rec = {}
        if milestone_memory_synthesizer and hasattr(milestone_memory_synthesizer, 'latest'):
            mms_rec = milestone_memory_synthesizer.latest() or {}
        milestone_salience = float(mms_rec.get('milestone_salience', 0.5))

        rpe_rec = {}
        if resumption_priority_engine and hasattr(resumption_priority_engine, 'latest'):
            rpe_rec = resumption_priority_engine.latest() or {}
        resume_confidence = float(rpe_rec.get('resume_confidence', 0.5))

        energy_tradeoff   = self._clamp(1.0 - resume_confidence)
        continuity_risk   = self._clamp(1.0 - identity_index)
        publication_value = self._clamp(milestone_salience)

        eeil_tensions = []
        for hyp in active_hyps:
            if not hyp.get('eeil_tagged', False):
                continue
            tension_score = self._clamp(
                energy_tradeoff   * 0.40
                + continuity_risk  * 0.30
                + publication_value * 0.30
            )
            paper_relevant = publication_value >= 0.50
            eeil_tensions.append({
                'hypothesis_id':    hyp['hypothesis_id'],
                'tension_score':    tension_score,
                'energy_tradeoff':  energy_tradeoff,
                'continuity_risk':  continuity_risk,
                'publication_value': publication_value,
                'paper_relevant':   paper_relevant,
            })

        eeil_tensions.sort(key=lambda x: x['tension_score'], reverse=True)

        tension_priority = eeil_tensions[0]['tension_score'] if eeil_tensions else 0.0
        paper_relevance  = (
            sum(t['publication_value'] for t in eeil_tensions) / len(eeil_tensions)
        ) if eeil_tensions else 0.0

        record = {
            'tick':             tick,
            'eeil_tensions':    eeil_tensions,
            'tension_priority': self._clamp(tension_priority),
            'paper_relevance':  self._clamp(paper_relevance),
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ExperimentGapAnalyzer:
    """
    Detect missing validation sweeps, dormant test gaps, and post-break
    experiment priorities.

    Experiment gap seeds are fixed templates scored per tick from organism
    state. Gaps with gap_confidence >= 0.70 (Rule 3) surface into
    research_catalyst rank 1.

    gap_confidence formula varies by gap_type:
        'validation_sweep' : week_gap_confidence * 0.70 + identity_index * 0.30
        'boundary_test'    : revival_priority * 0.60 + continuity_score * 0.40
        'drift_test'       : (1 - dep_pressure) * 0.70 + identity_index * 0.30
        'edge_case'        : hypothesis_salience * 0.60 + identity_index * 0.40
        'longitudinal'     : week_gap_confidence * 0.50 + identity_index * 0.50

    experiment_priority: gap_id of highest gap_confidence.

    Biology runtime token exclusion enforced.

    Outputs per record:
        tick                    : int
        critical_experiment_gaps: list[dict] -- max 5, each:
                                    {gap_id, description, gap_confidence,
                                     gap_type, experiment_priority_rank}
        gap_confidence          : float -- max gap_confidence
        experiment_priority     : str   -- top gap_id

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    GAP_SEEDS = [
        {
            'id': 'post_break_milestone_sweep',
            'description': (
                'Validate milestone synthesis stability at tick 0 post-break.'
            ),
            'gap_type': 'validation_sweep',
        },
        {
            'id': 'dormant_revival_boundary',
            'description': (
                'Test dormant revival at exactly suppression_count = 3 boundary.'
            ),
            'gap_type': 'boundary_test',
        },
        {
            'id': 'blocker_override_drift',
            'description': (
                'Verify blocker-first override stability at pressure = 0.69.'
            ),
            'gap_type': 'drift_test',
        },
        {
            'id': 'stale_prune_partial_criteria',
            'description': (
                'Characterize partial-criteria prune candidates across sessions.'
            ),
            'gap_type': 'edge_case',
        },
        {
            'id': 'break_anchor_extended',
            'description': (
                'Measure break anchor coherence degradation at 14-day intervals.'
            ),
            'gap_type': 'longitudinal',
        },
    ]

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               week_gap_restart_sequence,
               project_identity_continuity_index,
               dormant_final_revival_gate,
               milestone_dependency_graph,
               hypothesis_persistence_memory):

        wgr_rec = {}
        if week_gap_restart_sequence and hasattr(week_gap_restart_sequence, 'latest'):
            wgr_rec = week_gap_restart_sequence.latest() or {}
        week_gap_confidence = float(wgr_rec.get('week_gap_confidence', 0.5))

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))

        dfr_rec = {}
        if dormant_final_revival_gate and hasattr(dormant_final_revival_gate, 'latest'):
            dfr_rec = dormant_final_revival_gate.latest() or {}
        revival_viability = float(dfr_rec.get('revival_viability', 0.0))

        mdg_rec = {}
        if milestone_dependency_graph and hasattr(milestone_dependency_graph, 'latest'):
            mdg_rec = milestone_dependency_graph.latest() or {}
        dep_pressure = float(mdg_rec.get('dependency_pressure', 0.0))

        hpm_rec = {}
        if hypothesis_persistence_memory and hasattr(hypothesis_persistence_memory, 'latest'):
            hpm_rec = hypothesis_persistence_memory.latest() or {}
        hypothesis_salience = float(hpm_rec.get('hypothesis_salience', 0.5))

        # continuity_score proxy
        continuity_score = float(pici_rec.get('continuity_strength', 0.5))

        scored_gaps = []
        for seed in self.GAP_SEEDS:
            gt = seed['gap_type']
            if gt == 'validation_sweep':
                conf = self._clamp(
                    week_gap_confidence * 0.70 + identity_index * 0.30
                )
            elif gt == 'boundary_test':
                conf = self._clamp(
                    revival_viability * 0.60 + continuity_score * 0.40
                )
            elif gt == 'drift_test':
                conf = self._clamp(
                    (1.0 - dep_pressure) * 0.70 + identity_index * 0.30
                )
            elif gt == 'edge_case':
                conf = self._clamp(
                    hypothesis_salience * 0.60 + identity_index * 0.40
                )
            else:  # longitudinal
                conf = self._clamp(
                    week_gap_confidence * 0.50 + identity_index * 0.50
                )
            scored_gaps.append({
                'gap_id':      seed['id'],
                'description': seed['description'],
                'gap_confidence': conf,
                'gap_type':    gt,
            })

        scored_gaps.sort(key=lambda x: x['gap_confidence'], reverse=True)
        for rank, g in enumerate(scored_gaps):
            g['experiment_priority_rank'] = rank + 1

        critical_gaps  = scored_gaps[:5]
        max_confidence = critical_gaps[0]['gap_confidence'] if critical_gaps else 0.0
        top_gap_id     = critical_gaps[0]['gap_id'] if critical_gaps else 'none'

        record = {
            'tick':                     tick,
            'critical_experiment_gaps': critical_gaps,
            'gap_confidence':           max_confidence,
            'experiment_priority':      top_gap_id,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PaperClaimContinuityBridge:
    """
    Track future publication claims that must persist across the break.

    CLAIM_SEEDS: fixed templates representing monograph claims, EEIL paper
    arguments, Day 28 continuity milestone claims, and open proofs.

    Claim confidence is scored from organism state per tick.
    Claims with confidence < CONFIDENCE_FLOOR (0.30, Rule 4) are dropped.

    claim_confidence formula:
        identity_index * 0.35
        + hypothesis_salience * 0.35
        + week_gap_confidence * 0.30
    Clamped to [0, 1].

    claim_risk per claim: 1.0 - confidence
    publication_ready: confidence >= 0.60

    publication_next_step: ASCII summary of highest-confidence claim action.

    Biology runtime token exclusion enforced.

    Outputs per record:
        tick                 : int
        persistent_claims    : list[dict] -- each:
                                 {claim_id, claim_text, confidence, section,
                                  claim_risk, publication_ready}
        claim_risk           : float -- mean(1 - confidence) across claims
        publication_next_step: str   -- ASCII

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    CONFIDENCE_FLOOR = 0.30

    CLAIM_SEEDS = [
        {
            'id': 'eeil_milestone_synthesis',
            'claim': (
                'Milestone synthesis enables week-long autobiographical '
                'continuity in bounded neural organisms.'
            ),
            'section': 'EEIL_paper',
        },
        {
            'id': 'blocker_first_law',
            'claim': (
                'Blocker-first restart ordering reduces re-entry friction '
                'after episodic gaps.'
            ),
            'section': 'EEIL_paper',
        },
        {
            'id': 'dormant_revival_gate',
            'claim': (
                'Single-attempt dormant revival prevents meaningful memory '
                'loss before purge.'
            ),
            'section': 'monograph',
        },
        {
            'id': 'stale_prune_4criterion',
            'claim': (
                'Four-criterion stale prune prevents false memory retention '
                'while preserving meaningful arcs.'
            ),
            'section': 'monograph',
        },
        {
            'id': 'week_gap_catalyst',
            'claim': (
                'Post-break research catalyst ignition restores scientific '
                'momentum within the first resumed tick.'
            ),
            'section': 'Day28_continuity',
        },
    ]

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               project_identity_continuity_index,
               hypothesis_persistence_memory,
               week_gap_restart_sequence):

        pici_rec = {}
        if (project_identity_continuity_index and
                hasattr(project_identity_continuity_index, 'latest')):
            pici_rec = project_identity_continuity_index.latest() or {}
        identity_index = float(pici_rec.get('identity_index', 0.5))

        hpm_rec = {}
        if hypothesis_persistence_memory and hasattr(hypothesis_persistence_memory, 'latest'):
            hpm_rec = hypothesis_persistence_memory.latest() or {}
        hypothesis_salience = float(hpm_rec.get('hypothesis_salience', 0.5))

        wgr_rec = {}
        if week_gap_restart_sequence and hasattr(week_gap_restart_sequence, 'latest'):
            wgr_rec = week_gap_restart_sequence.latest() or {}
        week_gap_confidence = float(wgr_rec.get('week_gap_confidence', 0.5))

        claim_confidence = self._clamp(
            identity_index       * 0.35
            + hypothesis_salience * 0.35
            + week_gap_confidence * 0.30
        )

        persistent_claims = []
        for seed in self.CLAIM_SEEDS:
            if claim_confidence < self.CONFIDENCE_FLOOR:
                continue
            claim_risk         = self._clamp(1.0 - claim_confidence)
            publication_ready  = claim_confidence >= 0.60
            persistent_claims.append({
                'claim_id':          seed['id'],
                'claim_text':        seed['claim'],
                'confidence':        claim_confidence,
                'section':           seed['section'],
                'claim_risk':        claim_risk,
                'publication_ready': publication_ready,
            })

        mean_risk = (
            sum(c['claim_risk'] for c in persistent_claims) / len(persistent_claims)
        ) if persistent_claims else 1.0

        if persistent_claims:
            top = persistent_claims[0]
            if top['publication_ready']:
                next_step = (
                    'Write up claim [{}] for section [{}]. '
                    'Confidence={:.2f}.'.format(
                        top['claim_id'], top['section'], top['confidence']
                    )
                )
            else:
                next_step = (
                    'Strengthen evidence for claim [{}] before publication. '
                    'Confidence={:.2f}.'.format(
                        top['claim_id'], top['confidence']
                    )
                )
        else:
            next_step = 'No claims above confidence floor. Rebuild evidence first.'

        record = {
            'tick':                  tick,
            'persistent_claims':     persistent_claims,
            'claim_risk':            self._clamp(mean_risk),
            'publication_next_step': next_step,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PostBreakResearchCatalyst:
    """
    Select the single highest-value scientific unknown to pull the first
    resumed day back into active research (uniqueness law).

    Selection priority (Rule 3):
        1. Experiment gap with gap_confidence >= 0.70 -> rank_1 (forced)
        2. Top EEIL tension by tension_score
        3. Top hypothesis by salience

    catalyst_confidence formula:
        tension_priority   * 0.40
        + gap_confidence    * 0.30
        + hypothesis_salience * 0.30
    Clamped to [0, 1].

    research_catalyst schema:
        rank_1_question            : str  -- ASCII
        linked_experiment_gap      : str or None
        linked_milestone_blocker   : str or None
        publication_value          : float
        restart_scientific_rationale: str -- ASCII

    Biology runtime token exclusion enforced.

    Outputs per record:
        tick               : int
        research_catalyst  : dict
        catalyst_confidence: float
        curiosity_reason   : str  -- ASCII

    Advisory only. Zero survival contamination. Waking-only.
    deque(maxlen=96).
    """

    GAP_CONFIDENCE_THRESHOLD = 0.70

    def __init__(self, maxlen=96):
        self._history = deque(maxlen=maxlen)
        self._maxlen  = maxlen

    @staticmethod
    def _clamp(v):
        return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               eeil_tension_tracker,
               experiment_gap_analyzer,
               hypothesis_persistence_memory,
               paper_claim_continuity_bridge,
               week_gap_restart_sequence):

        ett_rec = {}
        if eeil_tension_tracker and hasattr(eeil_tension_tracker, 'latest'):
            ett_rec = eeil_tension_tracker.latest() or {}
        eeil_tensions    = ett_rec.get('eeil_tensions', [])
        tension_priority = float(ett_rec.get('tension_priority', 0.0))
        paper_relevance  = float(ett_rec.get('paper_relevance', 0.0))

        ega_rec = {}
        if experiment_gap_analyzer and hasattr(experiment_gap_analyzer, 'latest'):
            ega_rec = experiment_gap_analyzer.latest() or {}
        critical_gaps     = ega_rec.get('critical_experiment_gaps', [])
        gap_confidence    = float(ega_rec.get('gap_confidence', 0.0))
        experiment_prio   = ega_rec.get('experiment_priority', '')

        hpm_rec = {}
        if hypothesis_persistence_memory and hasattr(hypothesis_persistence_memory, 'latest'):
            hpm_rec = hypothesis_persistence_memory.latest() or {}
        active_hyps        = hpm_rec.get('active_hypotheses', [])
        hypothesis_salience = float(hpm_rec.get('hypothesis_salience', 0.0))

        pccb_rec = {}
        if paper_claim_continuity_bridge and hasattr(paper_claim_continuity_bridge, 'latest'):
            pccb_rec = paper_claim_continuity_bridge.latest() or {}
        persistent_claims = pccb_rec.get('persistent_claims', [])

        wgr_rec = {}
        if week_gap_restart_sequence and hasattr(week_gap_restart_sequence, 'latest'):
            wgr_rec = week_gap_restart_sequence.latest() or {}
        restart_script = wgr_rec.get('restart_script', {}) or {}
        milestone_blocker = restart_script.get('step_1_blocker')

        # Selection logic (Rule 3)
        rank_1_question      = None
        linked_experiment_gap = None
        curiosity_reason      = 'hypothesis_default'

        # Priority 1: experiment gap >= 0.70
        top_gap = critical_gaps[0] if critical_gaps else {}
        if gap_confidence >= self.GAP_CONFIDENCE_THRESHOLD:
            rank_1_question      = top_gap.get('description', '')
            linked_experiment_gap = top_gap.get('gap_id')
            curiosity_reason     = 'gap_confidence_override_{:.2f}'.format(gap_confidence)

        # Priority 2: top EEIL tension
        if rank_1_question is None and eeil_tensions:
            top_t = eeil_tensions[0]
            rank_1_question  = (
                'Resolve EEIL tension: {} (tension={:.2f})'.format(
                    top_t['hypothesis_id'], top_t['tension_score']
                )
            )
            linked_experiment_gap = experiment_prio if experiment_prio else None
            curiosity_reason      = 'eeil_tension_top'

        # Priority 3: top hypothesis
        if rank_1_question is None and active_hyps:
            top_h = active_hyps[0]
            rank_1_question  = top_h.get('question_text', '')
            linked_experiment_gap = experiment_prio if experiment_prio else None
            curiosity_reason      = 'hypothesis_salience_top'

        if rank_1_question is None:
            rank_1_question  = 'No scientific unknowns identified. Explore freely.'
            curiosity_reason = 'no_candidates'

        # publication_value from paper claims
        pub_value = (
            persistent_claims[0]['confidence'] if persistent_claims else paper_relevance
        )

        # ASCII restart scientific rationale
        if linked_experiment_gap:
            rationale = (
                'Run experiment [{}] first. '
                'Then address: {}. '
                'Publication value={:.2f}.'.format(
                    linked_experiment_gap,
                    rank_1_question[:60],
                    pub_value
                )
            )
        else:
            rationale = (
                'Address open question: {}. '
                'Publication value={:.2f}.'.format(
                    rank_1_question[:80], pub_value
                )
            )

        research_catalyst = {
            'rank_1_question':              rank_1_question,
            'linked_experiment_gap':        linked_experiment_gap,
            'linked_milestone_blocker':     milestone_blocker,
            'publication_value':            self._clamp(pub_value),
            'restart_scientific_rationale': rationale,
        }

        catalyst_confidence = self._clamp(
            tension_priority    * 0.40
            + gap_confidence     * 0.30
            + hypothesis_salience * 0.30
        )

        record = {
            'tick':                tick,
            'research_catalyst':   research_catalyst,
            'catalyst_confidence': catalyst_confidence,
            'curiosity_reason':    curiosity_reason,
        }
        self._history.append(record)
        return record

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        return list(self._history)[-n:]

    def summary(self):
        return {'maxlen': self._maxlen, 'count': len(self._history)}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


