# DAY 28 PHASE D: Autonomous Research Agenda Orchestration
# Pure advisory synthesis; waking-only; zero survival contamination.
# Friston 2010 (active inference); Schmidhuber 1991 (curiosity-driven learning)
# ===========================================================================

class ResearchAgendaComposer:
    """
    Ranks and composes the post-break research agenda from catalyst, claims,
    and experiment gaps. Enforces: AGENDA_CAP=5; catalyst forced rank_1
    (frozen law); PUBLICATION_BONUS=+0.10; at least one EEIL-tradeoff item.

    Scoring formula:
        item_score = base_score
                   + PUBLICATION_BONUS   * publication_flag    [+0.10]
                   + EEIL_TRADEOFF_BONUS * eeil_tradeoff_flag  [+0.05]

    Biology tokens excluded. deque(maxlen=96).
    """

    AGENDA_CAP          = 5
    PUBLICATION_BONUS   = 0.10
    EEIL_TRADEOFF_BONUS = 0.05
    BIOLOGY_TOKENS      = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _CANDIDATE_SEEDS = [
        {'id': 'eeil_sparse_validation',
         'base_score': 0.78, 'publication_flag': True,  'eeil_tradeoff_flag': True,
         'label': 'EEIL sparse law validation sweep'},
        {'id': 'continuity_localization',
         'base_score': 0.73, 'publication_flag': True,  'eeil_tradeoff_flag': False,
         'label': 'continuity before localization study'},
        {'id': 'tradeoff_sweep_depth',
         'base_score': 0.68, 'publication_flag': False, 'eeil_tradeoff_flag': True,
         'label': 'sweep depth vs sparse law tradeoff'},
        {'id': 'day28_proof_anchor',
         'base_score': 0.65, 'publication_flag': True,  'eeil_tradeoff_flag': False,
         'label': 'Day28 proof of continuity anchor'},
        {'id': 'biology_exclusion_bounds',
         'base_score': 0.60, 'publication_flag': False, 'eeil_tradeoff_flag': False,
         'label': 'biology exclusion boundary test'},
        {'id': 'monograph_claim_chain',
         'base_score': 0.72, 'publication_flag': True,  'eeil_tradeoff_flag': False,
         'label': 'monograph claim chain validation'},
        {'id': 'milestone_cap_tradeoff',
         'base_score': 0.58, 'publication_flag': False, 'eeil_tradeoff_flag': True,
         'label': 'milestone cap vs restart fidelity tradeoff'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.research_agenda   = []
        self.agenda_confidence = 0.0
        self.agenda_reason     = 'init'

    def _token_safe(self, text):
        return not bool(self.BIOLOGY_TOKENS & set(str(text).lower().split()))

    def update(self, tick, post_break_research_catalyst,
               paper_claim_continuity_bridge, experiment_gap_analyzer,
               milestone_blocker_resolver, eeil_tension_tracker):
        if _IKG.sleeping:
            return

        cat     = post_break_research_catalyst
        tension = eeil_tension_tracker

        scored = []
        for seed in self._CANDIDATE_SEEDS:
            if not self._token_safe(seed['label']):
                continue
            score = seed['base_score']
            if seed['publication_flag']:
                score += self.PUBLICATION_BONUS
            if seed['eeil_tradeoff_flag']:
                score += self.EEIL_TRADEOFF_BONUS
            scored.append({'id':                seed['id'],
                           'label':             seed['label'],
                           'score':             round(score, 4),
                           'publication_flag':  seed['publication_flag'],
                           'eeil_tradeoff_flag':seed['eeil_tradeoff_flag']})

        scored.sort(key=lambda x: x['score'], reverse=True)

        # Rule 2: force catalyst as rank_1 (frozen law)
        catalyst_label = getattr(cat, 'research_catalyst', '')
        if catalyst_label and self._token_safe(catalyst_label):
            catalyst_item = {
                'id':               'catalyst_forced',
                'label':            str(catalyst_label)[:80],
                'score':            1.00,
                'publication_flag': True,
                'eeil_tradeoff_flag': True,
            }
            scored.insert(0, catalyst_item)

        seen   = set()
        agenda = []
        for item in scored:
            if item['id'] not in seen:
                seen.add(item['id'])
                agenda.append(item)
            if len(agenda) >= self.AGENDA_CAP:
                break

        # Rule 5: ensure at least one eeil_tradeoff item
        has_tradeoff = any(i['eeil_tradeoff_flag'] for i in agenda)
        if not has_tradeoff:
            for seed in self._CANDIDATE_SEEDS:
                if seed['eeil_tradeoff_flag'] and seed['id'] not in seen:
                    s = round(seed['base_score'] + self.EEIL_TRADEOFF_BONUS, 4)
                    agenda.append({'id': seed['id'], 'label': seed['label'],
                                   'score': s, 'publication_flag': seed['publication_flag'],
                                   'eeil_tradeoff_flag': True})
                    if len(agenda) > self.AGENDA_CAP:
                        agenda = agenda[:self.AGENDA_CAP]
                    break

        self.research_agenda   = agenda
        tension_score          = getattr(tension, 'tension_score',       0.5)
        catalyst_conf          = getattr(cat,     'catalyst_confidence', 0.5)
        self.agenda_confidence = round(catalyst_conf * 0.60 + tension_score * 0.40, 4)
        top_label              = agenda[0]['label'] if agenda else 'none'
        self.agenda_reason     = 'catalyst_rank1_enforced agenda_cap=%d top=%s' % (
            len(agenda), top_label[:40])

        self._history.append({
            'tick':              tick,
            'research_agenda':   [i['id'] for i in agenda],
            'agenda_confidence': self.agenda_confidence,
            'agenda_reason':     self.agenda_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ExperimentPriorityScheduler:
    """
    Schedules the experiment queue from the ranked research agenda,
    experiment gaps, and blocker state. QUEUE_CAP=5.

    Priority formula:
        priority_score = agenda_rank_score * 0.50
                       + gap_confidence    * 0.30
                       + (1 - dep_pressure)* 0.20

    scheduler_confidence = agenda_confidence * 0.70 + gap_confidence * 0.30

    Biology tokens excluded. deque(maxlen=96).
    """

    QUEUE_CAP      = 5
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.experiment_queue     = []
        self.scheduler_confidence = 0.0
        self.priority_reason      = 'init'

    def update(self, tick, research_agenda_composer,
               experiment_gap_analyzer, milestone_blocker_resolver):
        if _IKG.sleeping:
            return

        agenda    = getattr(research_agenda_composer,   'research_agenda', [])
        gap_conf  = getattr(experiment_gap_analyzer,    'gap_confidence',  0.5)
        dep_press = getattr(milestone_blocker_resolver, 'dep_pressure',    0.0)

        queue = []
        for rank, item in enumerate(agenda):
            rank_score = item.get('score', 0.5)
            priority   = round(rank_score * 0.50 + gap_conf * 0.30 + (1.0 - dep_press) * 0.20, 4)
            exp_id     = 'exp_' + item['id'][:32]
            queue.append({'experiment_id': exp_id,
                          'agenda_label':  item['label'][:60],
                          'priority':      priority,
                          'rank':          rank + 1})
            if len(queue) >= self.QUEUE_CAP:
                break

        queue.sort(key=lambda x: x['priority'], reverse=True)
        self.experiment_queue     = queue
        agenda_conf               = getattr(research_agenda_composer, 'agenda_confidence', 0.5)
        self.scheduler_confidence = round(agenda_conf * 0.70 + gap_conf * 0.30, 4)
        top_exp                   = queue[0]['experiment_id'] if queue else 'none'
        self.priority_reason      = 'queue_len=%d top=%s' % (len(queue), top_exp[:40])

        self._history.append({
            'tick':                 tick,
            'experiment_queue':     [q['experiment_id'] for q in queue],
            'scheduler_confidence': self.scheduler_confidence,
            'priority_reason':      self.priority_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ValidationSweepForecaster:
    """
    Forecasts a bounded validation sweep (EEIL sparse discipline).
    SWEEP_DEPTH_CAP = 6 -- hard cap, never exceeded (Rule 3).

    forecast_base = agenda_confidence * 0.50
                  + tension_score     * 0.30
                  + hypothesis_salience * 0.20

    step_conf[i] = max(0, forecast_base * (1 - 0.08 * i))

    Biology tokens excluded. deque(maxlen=96).
    """

    SWEEP_DEPTH_CAP = 6
    BIOLOGY_TOKENS  = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _STEP_TEMPLATES = [
        'validate catalyst claim via controlled run',
        'measure EEIL tension delta pre vs post experiment',
        'compare hypothesis salience before and after sweep',
        'check agenda stability across 3 consecutive ticks',
        'verify blocker resolution under sweep conditions',
        'confirm paper claim confidence meets publication floor',
    ]

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.validation_sweep    = []
        self.forecast_confidence = 0.0
        self.sweep_reason        = 'init'

    def update(self, tick, research_agenda_composer,
               eeil_tension_tracker, hypothesis_persistence_memory):
        if _IKG.sleeping:
            return

        agenda_conf = getattr(research_agenda_composer,     'agenda_confidence', 0.5)
        tension_sc  = getattr(eeil_tension_tracker,          'tension_score',     0.5)
        hyp_sal     = getattr(hypothesis_persistence_memory, 'top_salience',      0.5)

        forecast_base = round(agenda_conf * 0.50 + tension_sc * 0.30 + hyp_sal * 0.20, 4)
        agenda        = getattr(research_agenda_composer, 'research_agenda', [])
        depth         = min(self.SWEEP_DEPTH_CAP, max(1, len(agenda)))

        steps = []
        for i in range(depth):
            tmpl      = self._STEP_TEMPLATES[i % len(self._STEP_TEMPLATES)]
            step_conf = round(max(0.0, forecast_base * (1.0 - 0.08 * i)), 4)
            agenda_ref = agenda[i]['id'] if i < len(agenda) else 'none'
            steps.append({'step':        i + 1,
                          'description': tmpl,
                          'agenda_ref':  agenda_ref,
                          'step_conf':   step_conf})

        self.validation_sweep    = steps
        self.forecast_confidence = round(forecast_base, 4)
        self.sweep_reason        = 'depth=%d cap=%d base=%.4f' % (
            depth, self.SWEEP_DEPTH_CAP, forecast_base)

        self._history.append({
            'tick':               tick,
            'sweep_depth':        depth,
            'forecast_confidence':self.forecast_confidence,
            'sweep_reason':       self.sweep_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PaperRoadmapSynthesizer:
    """
    Synthesizes publication roadmap sections from claims, agenda, hypotheses.

    section_score = claim_confidence * 0.40
                  + agenda_confidence * 0.35
                  + hypothesis_salience * 0.25

    next_claim_section: highest-scoring section with claim_confidence >= 0.30.
    Biology tokens excluded. deque(maxlen=96).
    """

    CONFIDENCE_FLOOR = 0.30
    BIOLOGY_TOKENS   = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _SECTION_SEEDS = [
        {'id': 'eeil_law_statement',  'label': 'EEIL Law Formal Statement',
         'claim_id': 'eeil_sparse_law_claim'},
        {'id': 'continuity_theory',   'label': 'Continuity Before Localization',
         'claim_id': 'continuity_localization_claim'},
        {'id': 'day28_proof_section', 'label': 'Day 28 Proof of Continuity',
         'claim_id': 'day28_continuity_claim'},
        {'id': 'monograph_synthesis', 'label': 'Monograph Integration Chapter',
         'claim_id': 'monograph_synthesis_claim'},
        {'id': 'tradeoff_analysis',   'label': 'EEIL Tradeoff Analysis',
         'claim_id': 'tradeoff_analysis_claim'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.paper_roadmap      = []
        self.next_claim_section = ''
        self.roadmap_reason     = 'init'

    def update(self, tick, paper_claim_continuity_bridge,
               research_agenda_composer, hypothesis_persistence_memory):
        if _IKG.sleeping:
            return

        claim_conf  = getattr(paper_claim_continuity_bridge, 'claim_confidence',  0.5)
        agenda_conf = getattr(research_agenda_composer,       'agenda_confidence', 0.5)
        hyp_sal     = getattr(hypothesis_persistence_memory,  'top_salience',      0.5)

        sections = []
        for seed in self._SECTION_SEEDS:
            score = round(claim_conf * 0.40 + agenda_conf * 0.35 + hyp_sal * 0.25, 4)
            sections.append({'id':            seed['id'],
                             'label':         seed['label'],
                             'claim_id':      seed['claim_id'],
                             'section_score': score,
                             'ready':         claim_conf >= self.CONFIDENCE_FLOOR})

        sections.sort(key=lambda x: x['section_score'], reverse=True)
        self.paper_roadmap      = sections
        ready_sections          = [s for s in sections if s['ready']]
        self.next_claim_section = ready_sections[0]['label'] if ready_sections else 'none'
        self.roadmap_reason     = 'sections=%d ready=%d next=%s' % (
            len(sections), len(ready_sections), self.next_claim_section[:40])

        self._history.append({
            'tick':               tick,
            'section_count':      len(sections),
            'ready_count':        len(ready_sections),
            'next_claim_section': self.next_claim_section,
            'roadmap_reason':     self.roadmap_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class EEILTradeoffWorkbench:
    """
    Executes explicit EEIL tradeoff studies. Mandatory -- always >= 1 active
    study (Rule 5 enforcement). Four fixed study axes:
        sweep_depth vs sparse_law
        milestone_cap vs restart_fidelity
        hypothesis_cap vs scientific_breadth
        continuity_robustness vs bounded_memory

    study_score = tension_score * 0.40
               + (1 - identity_index) * 0.30
               + milestone_salience   * 0.30

    eeil_gain_projection = mean(study_score) across all studies.
    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _STUDY_SEEDS = [
        {'id': 'sweep_depth_vs_sparse_law',
         'axis_a': 'sweep_depth',           'axis_b': 'sparse_law'},
        {'id': 'milestone_cap_vs_restart_fidelity',
         'axis_a': 'milestone_cap',          'axis_b': 'restart_fidelity'},
        {'id': 'hypothesis_cap_vs_scientific_breadth',
         'axis_a': 'hypothesis_cap',         'axis_b': 'scientific_breadth'},
        {'id': 'continuity_robustness_vs_bounded_memory',
         'axis_a': 'continuity_robustness',  'axis_b': 'bounded_memory'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.tradeoff_studies     = []
        self.eeil_gain_projection = 0.0
        self.tradeoff_reason      = 'init'

    def update(self, tick, eeil_tension_tracker,
               project_identity_continuity_index, milestone_memory_synthesizer):
        if _IKG.sleeping:
            return

        tension_sc   = getattr(eeil_tension_tracker,              'tension_score',    0.5)
        identity_idx = getattr(project_identity_continuity_index, 'identity_index',   0.5)
        ms_salience  = getattr(milestone_memory_synthesizer,       'top_salience',     0.5)

        studies = []
        for seed in self._STUDY_SEEDS:
            score = round(tension_sc * 0.40 + (1.0 - identity_idx) * 0.30 + ms_salience * 0.30, 4)
            studies.append({'id':          seed['id'],
                            'axis_a':      seed['axis_a'],
                            'axis_b':      seed['axis_b'],
                            'study_score': score})

        self.tradeoff_studies     = studies
        self.eeil_gain_projection = round(
            sum(s['study_score'] for s in studies) / max(1, len(studies)), 4)
        top_id = studies[0]['id'][:40] if studies else 'none'
        self.tradeoff_reason = 'studies=%d eeil_gain=%.4f top=%s' % (
            len(studies), self.eeil_gain_projection, top_id)

        self._history.append({
            'tick':                tick,
            'study_count':         len(studies),
            'eeil_gain_projection':self.eeil_gain_projection,
            'tradeoff_reason':     self.tradeoff_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PostBreakExperimentLaunchpad:
    """
    Selects the single highest-value post-break experiment (uniqueness law).
    Synthesizes agenda_rank_1 + sweep_plan + paper_implication + eeil_gain +
    milestone_dependency into one actionable launch_experiment dict.

    launch_confidence = agenda_confidence * 0.35
                      + forecast_confidence  * 0.25
                      + eeil_gain_projection * 0.25
                      + (1 - dep_pressure)   * 0.15

    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.launch_experiment = {}
        self.launch_confidence = 0.0
        self.launch_reason     = 'init'

    def update(self, tick, research_agenda_composer,
               validation_sweep_forecaster, paper_roadmap_synthesizer,
               eeil_tradeoff_workbench, milestone_dependency_graph):
        if _IKG.sleeping:
            return

        agenda       = getattr(research_agenda_composer,   'research_agenda',    [])
        agenda_conf  = getattr(research_agenda_composer,   'agenda_confidence',  0.5)
        sweep        = getattr(validation_sweep_forecaster, 'validation_sweep',   [])
        fore_conf    = getattr(validation_sweep_forecaster, 'forecast_confidence',0.5)
        next_section = getattr(paper_roadmap_synthesizer,   'next_claim_section', 'none')
        eeil_gain    = getattr(eeil_tradeoff_workbench,     'eeil_gain_projection',0.5)
        dep_press    = getattr(milestone_dependency_graph,  'dep_pressure',       0.0)
        graph_state  = getattr(milestone_dependency_graph,  'graph_state',        'clear')

        # Uniqueness law: single highest-value experiment = agenda rank_1
        rank1       = agenda[0] if agenda else {'id': 'none', 'label': 'post_break_default'}
        sweep_descs = [s['description'] for s in sweep[:3]]
        sweep_plan  = '; '.join(sweep_descs) if sweep_descs else 'run validation suite'

        self.launch_experiment = {
            'agenda_rank_1':        rank1.get('label', 'none')[:80],
            'sweep_plan':           sweep_plan[:120],
            'paper_implication':    str(next_section)[:60],
            'eeil_gain':            eeil_gain,
            'milestone_dependency': graph_state,
            'launch_rationale':     'highest_value_single_experiment uniqueness_law_enforced',
        }

        self.launch_confidence = round(
            agenda_conf * 0.35 + fore_conf * 0.25 + eeil_gain * 0.25 + (1.0 - dep_press) * 0.15,
            4)
        self.launch_reason = 'rank1=%s conf=%.4f' % (
            rank1.get('id', 'none')[:40], self.launch_confidence)

        self._history.append({
            'tick':              tick,
            'agenda_rank_1':     rank1.get('id', 'none'),
            'launch_confidence': self.launch_confidence,
            'launch_reason':     self.launch_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 28 PHASE E: Week-Break Counterfactual Incubation Forecast Suite
# Simulates 7-day silent incubation: milestone strengthening, hypothesis
# drift, agenda reorder, publication maturation, convergence forecasting.
# Schooler 2004 (incubation); Stickgold 2005 (offline consolidation);
# Oudeyer 2007 (intrinsic motivation / curiosity drift)
# ===========================================================================

class WeekBreakFutureSimulator:
    """
    Canonical 7-day silent incubation simulation. Projects how milestone
    memory, hypothesis salience, launch confidence, paper maturation, and
    blocker pressure will shift across the week-long hiatus before it occurs.

    SIMULATION_HORIZON = 7 (frozen, Rule 1)
    Milestone strengthening law (Rule 2): salience >= 0.70 -> +0.05
    Stale hypothesis decay (Rule 3): salience < 0.40, no pub coupling,
        no critical dep -> -0.10

    simulation_confidence = clamp(
        projected_milestone_salience * 0.35
        + projected_hypothesis_salience * 0.30
        + launch_confidence * 0.20
        + (1 - dep_pressure) * 0.15
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    SIMULATION_HORIZON    = 7
    STRENGTHEN_THRESHOLD  = 0.70
    STRENGTHEN_BONUS      = 0.05
    DECAY_THRESHOLD       = 0.40
    DECAY_PENALTY         = 0.10
    BIOLOGY_TOKENS        = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self.future_week_state     = {}
        self.simulation_confidence = 0.0
        self.incubation_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def _pub_coupled(self, hyp, claim_ids):
        return any(c in str(hyp.get('hypothesis_id', hyp.get('id', ''))).lower()
                   for c in claim_ids)

    def update(self, tick,
               milestone_memory_synthesizer,
               hypothesis_persistence_memory,
               post_break_experiment_launchpad,
               paper_claim_continuity_bridge,
               milestone_dependency_graph):
        if _IKG.sleeping:
            return

        ms_rec    = milestone_memory_synthesizer.latest() if milestone_memory_synthesizer else {}
        hyp_rec   = hypothesis_persistence_memory.latest() if hypothesis_persistence_memory else {}
        claim_rec = paper_claim_continuity_bridge.latest() if paper_claim_continuity_bridge else {}
        dep_rec   = milestone_dependency_graph.latest() if milestone_dependency_graph else {}

        milestones     = ms_rec.get('milestone_memories', [])
        hypotheses     = hyp_rec.get('active_hypotheses', [])
        claims         = claim_rec.get('persistent_claims', [])
        dep_pressure   = float(dep_rec.get('dependency_pressure', 0.0))
        launch_conf    = getattr(post_break_experiment_launchpad, 'launch_confidence', 0.5)

        claim_ids = {str(c.get('claim_id', c.get('id', ''))).lower() for c in claims}

        # Project milestones
        proj_milestones = []
        for m in milestones:
            sal = float(m.get('salience', 0.5))
            if sal >= self.STRENGTHEN_THRESHOLD:
                sal = self._clamp(sal + self.STRENGTHEN_BONUS)
            proj_milestones.append({'family_sig': m.get('family_sig', 'unknown'),
                                    'projected_salience': sal,
                                    'strengthened': sal > float(m.get('salience', 0.5))})

        proj_ms_sal = (sum(p['projected_salience'] for p in proj_milestones)
                       / max(1, len(proj_milestones))) if proj_milestones else 0.5

        # Project hypotheses
        proj_hypotheses = []
        for h in hypotheses:
            sal      = float(h.get('salience', 0.5))
            pub_coup = self._pub_coupled(h, claim_ids)
            if sal < self.DECAY_THRESHOLD and not pub_coup:
                sal = self._clamp(sal - self.DECAY_PENALTY)
                decayed = True
            else:
                decayed = False
            proj_hypotheses.append({'id':         h.get('hypothesis_id', h.get('id', 'unknown')),
                                    'proj_sal':   sal,
                                    'decayed':    decayed,
                                    'pub_coupled':pub_coup})

        proj_hyp_sal = (sum(p['proj_sal'] for p in proj_hypotheses)
                        / max(1, len(proj_hypotheses))) if proj_hypotheses else 0.5

        self.future_week_state = {
            'horizon_days':               self.SIMULATION_HORIZON,
            'projected_milestones':       proj_milestones,
            'projected_hypotheses':       proj_hypotheses,
            'projected_milestone_salience': round(proj_ms_sal, 4),
            'projected_hypothesis_salience':round(proj_hyp_sal, 4),
            'dep_pressure_projected':     round(dep_pressure * 0.90, 4),
            'launch_confidence_projected':round(self._clamp(launch_conf * 1.05), 4),
        }

        self.simulation_confidence = self._clamp(
            proj_ms_sal * 0.35 + proj_hyp_sal * 0.30
            + launch_conf * 0.20 + (1.0 - dep_pressure) * 0.15
        )
        self.simulation_confidence = round(self.simulation_confidence, 4)
        self.incubation_reason = 'horizon=%d ms_proj=%.4f hyp_proj=%.4f' % (
            self.SIMULATION_HORIZON, proj_ms_sal, proj_hyp_sal)

        self._history.append({
            'tick':                tick,
            'horizon_days':        self.SIMULATION_HORIZON,
            'proj_ms_sal':         round(proj_ms_sal, 4),
            'proj_hyp_sal':        round(proj_hyp_sal, 4),
            'simulation_confidence':self.simulation_confidence,
            'incubation_reason':   self.incubation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class HypothesisDriftForecaster:
    """
    Forecasts hypothesis salience shifts across the 7-day break:
    rising EEIL tensions strengthen EEIL-tagged hypotheses,
    publication-coupled hypotheses are resilient (no decay),
    stale hypotheses (salience < 0.40, no pub coupling) decay -0.10,
    dormant hypotheses (0.30 <= salience < 0.50) may resurface.

    drift_pressure = fraction of hypotheses that decay

    Biology tokens excluded. deque(maxlen=96).
    """

    DECAY_THRESHOLD  = 0.40
    DECAY_PENALTY    = 0.10
    DORMANT_LOW      = 0.30
    DORMANT_HIGH     = 0.50
    EEIL_LIFT        = 0.05
    BIOLOGY_TOKENS   = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.hypothesis_forecast = []
        self.drift_pressure      = 0.0
        self.drift_reason        = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               hypothesis_persistence_memory,
               eeil_tension_tracker,
               paper_claim_continuity_bridge,
               open_question_graph):
        if _IKG.sleeping:
            return

        hyp_rec   = hypothesis_persistence_memory.latest() if hypothesis_persistence_memory else {}
        claim_rec = paper_claim_continuity_bridge.latest() if paper_claim_continuity_bridge else {}
        oqg_rec   = open_question_graph.latest() if open_question_graph else {}

        hypotheses      = hyp_rec.get('active_hypotheses', [])
        persistent_ids  = {str(c.get('claim_id', c.get('id', ''))).lower()
                           for c in claim_rec.get('persistent_claims', [])}
        critical_unkn   = {str(u).lower() for u in oqg_rec.get('critical_unknowns', [])}

        forecast = []
        n_decay  = 0
        for h in hypotheses:
            hid      = str(h.get('hypothesis_id', h.get('id', 'unknown')))
            sal      = float(h.get('salience', 0.5))
            eeil_tag = bool(h.get('eeil_tagged', False))
            pub_coup = any(hid.lower() in pid for pid in persistent_ids) or \
                       any(pid in hid.lower() for pid in persistent_ids)
            crit_dep = any(hid.lower() in cu for cu in critical_unkn)

            proj_sal = sal
            status   = 'stable'
            if eeil_tag:
                proj_sal = self._clamp(proj_sal + self.EEIL_LIFT)
                status   = 'eeil_rising'
            if sal < self.DECAY_THRESHOLD and not pub_coup and not crit_dep:
                proj_sal = self._clamp(proj_sal - self.DECAY_PENALTY)
                status   = 'decaying'
                n_decay += 1
            elif not eeil_tag:
                if pub_coup:
                    status = 'pub_resilient'
                elif self.DORMANT_LOW <= sal < self.DORMANT_HIGH:
                    status = 'dormant_resurface_candidate'

            forecast.append({'id':           hid,
                              'base_salience':round(sal, 4),
                              'proj_salience': round(proj_sal, 4),
                              'status':       status,
                              'eeil_tagged':  eeil_tag,
                              'pub_coupled':  pub_coup})

        self.hypothesis_forecast = forecast
        self.drift_pressure      = round(n_decay / max(1, len(hypotheses)), 4)
        top_id = forecast[0]['id'][:40] if forecast else 'none'
        self.drift_reason = 'n=%d decaying=%d pressure=%.4f top=%s' % (
            len(forecast), n_decay, self.drift_pressure, top_id)

        self._history.append({
            'tick':               tick,
            'forecast_count':     len(forecast),
            'drift_pressure':     self.drift_pressure,
            'drift_reason':       self.drift_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MilestoneSalienceProjector:
    """
    Projects post-break milestone salience applying:
    - Strengthening law (Rule 2): salience >= 0.70 -> +0.05
    - Merge bonus: milestone in a merged arc -> +0.03
    - Break-anchor reinforcement: milestone in anchor families -> +0.02
    - Dormant arcs: unchanged unless above thresholds

    salience_delta = projected_mean - original_mean

    Biology tokens excluded. deque(maxlen=96).
    """

    STRENGTHEN_THRESHOLD = 0.70
    STRENGTHEN_BONUS     = 0.05
    MERGE_BONUS          = 0.03
    ANCHOR_BONUS         = 0.02
    BIOLOGY_TOKENS       = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.projected_milestones = []
        self.salience_delta      = 0.0
        self.projection_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               milestone_memory_synthesizer,
               narrative_arc_merger,
               dormant_milestone_reviver,
               break_resumption_anchor):
        if _IKG.sleeping:
            return

        ms_rec     = milestone_memory_synthesizer.latest() if milestone_memory_synthesizer else {}
        arc_rec    = narrative_arc_merger.latest() if narrative_arc_merger else {}
        anchor_rec = break_resumption_anchor.latest() if break_resumption_anchor else {}

        milestones  = ms_rec.get('milestone_memories', [])
        merged_arcs = arc_rec.get('merged_arcs', [])
        anchor_data = anchor_rec.get('break_anchor', {})

        merged_families = set()
        for arc in merged_arcs:
            merged_families.add(str(arc.get('primary_family', '')).lower())
            merged_families.add(str(arc.get('secondary_family', '')).lower())

        anchor_families = set()
        if isinstance(anchor_data, dict):
            for k, v in anchor_data.items():
                anchor_families.add(str(v).lower())
        elif isinstance(anchor_data, str):
            anchor_families.add(anchor_data.lower())

        projected = []
        orig_mean  = 0.0
        proj_mean  = 0.0

        for m in milestones:
            fam  = str(m.get('family_sig', '')).lower()
            sal  = float(m.get('salience', 0.5))
            p    = sal

            if sal >= self.STRENGTHEN_THRESHOLD:
                p = self._clamp(p + self.STRENGTHEN_BONUS)
            if any(fam in mf or mf in fam for mf in merged_families if mf):
                p = self._clamp(p + self.MERGE_BONUS)
            if any(fam in af or af in fam for af in anchor_families if af):
                p = self._clamp(p + self.ANCHOR_BONUS)

            orig_mean += sal
            proj_mean += p
            projected.append({'family_sig':         m.get('family_sig', 'unknown'),
                               'original_salience':  round(sal, 4),
                               'projected_salience': round(p, 4),
                               'delta':              round(p - sal, 4)})

        n = max(1, len(milestones))
        orig_mean  /= n
        proj_mean  /= n

        self.projected_milestones = projected
        self.salience_delta       = round(proj_mean - orig_mean, 4)
        n_strengthened = sum(1 for p in projected if p['delta'] > 0)
        self.projection_reason = 'n=%d strengthened=%d delta=%.4f' % (
            len(projected), n_strengthened, self.salience_delta)

        self._history.append({
            'tick':               tick,
            'milestone_count':    len(projected),
            'salience_delta':     self.salience_delta,
            'projection_reason':  self.projection_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class AgendaReorderPredictor:
    """
    Predicts post-break agenda reordering from EEIL promotion, blocker
    escalation, and catalyst replacement risk. Any item with predicted
    launch value delta >= 0.15 triggers a reorder (Rule 4).

    EEIL study promotion: eeil_tradeoff_flag -> +0.07
    Blocker escalation: blocked milestone -> -0.05
    Catalyst replacement risk: catalyst_confidence < 0.50 -> second item
        may displace rank_1

    reorder_delta = max absolute delta seen across all items.

    Biology tokens excluded. deque(maxlen=96).
    """

    REORDER_THRESHOLD  = 0.15
    EEIL_PROMO_DELTA   = 0.07
    BLOCKER_DEMOTION   = 0.05
    BIOLOGY_TOKENS     = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.forecast_agenda = []
        self.reorder_delta  = 0.0
        self.reorder_reason = 'init'

    def update(self, tick,
               research_agenda_composer,
               milestone_dependency_graph,
               eeil_tradeoff_workbench,
               post_break_research_catalyst):
        if _IKG.sleeping:
            return

        agenda      = list(getattr(research_agenda_composer, 'research_agenda', []))
        dep_rec     = milestone_dependency_graph.latest() if milestone_dependency_graph else {}
        blocked_ms  = {str(b).lower() for b in dep_rec.get('blocked_milestones', [])}
        eeil_gain   = getattr(eeil_tradeoff_workbench, 'eeil_gain_projection', 0.5)
        cat_rec     = post_break_research_catalyst.latest() if post_break_research_catalyst else {}
        cat_conf    = float(cat_rec.get('catalyst_confidence', 0.5))

        forecast = []
        max_delta = 0.0
        for item in agenda:
            base_score = float(item.get('score', 0.5))
            delta      = 0.0
            if item.get('eeil_tradeoff_flag'):
                delta += self.EEIL_PROMO_DELTA
            if any(str(item.get('id', '')).lower() in b or b in str(item.get('id', '')).lower()
                   for b in blocked_ms if b):
                delta -= self.BLOCKER_DEMOTION
            proj_score = max(0.0, min(1.0, base_score + delta))
            abs_delta  = abs(delta)
            if abs_delta > max_delta:
                max_delta = abs_delta
            forecast.append({'id':             item.get('id', 'unknown'),
                             'label':          item.get('label', '')[:60],
                             'base_score':     round(base_score, 4),
                             'proj_score':     round(proj_score, 4),
                             'launch_delta':   round(delta, 4),
                             'reordered':      abs_delta >= self.REORDER_THRESHOLD,
                             'eeil_tradeoff':  item.get('eeil_tradeoff_flag', False)})

        # Apply reorder: sort by proj_score descending if any delta >= threshold
        if any(f['reordered'] for f in forecast):
            forecast.sort(key=lambda x: x['proj_score'], reverse=True)

        # Catalyst replacement risk: if cat_conf < 0.50 and rank_1 is catalyst_forced,
        # flag it (don't actually demote -- frozen law -- but annotate risk)
        if forecast and forecast[0].get('id') == 'catalyst_forced' and cat_conf < 0.50:
            forecast[0]['replacement_risk'] = True
        else:
            for f in forecast:
                f.setdefault('replacement_risk', False)

        self.forecast_agenda = forecast
        self.reorder_delta   = round(max_delta, 4)
        n_reordered = sum(1 for f in forecast if f['reordered'])
        self.reorder_reason  = 'n=%d reordered=%d max_delta=%.4f' % (
            len(forecast), n_reordered, self.reorder_delta)

        self._history.append({
            'tick':           tick,
            'agenda_count':   len(forecast),
            'reorder_delta':  self.reorder_delta,
            'reorder_reason': self.reorder_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PaperClaimMaturationEstimator:
    """
    Estimates post-break claim maturation. For each persistent claim:

    maturation_projection = claim_confidence * 0.40
                          + agenda_confidence * 0.35
                          + forecast_confidence * 0.25

    If maturation_projection >= 0.60: flagged 'likely_publication_ready' (Rule 5).

    maturation_projection (class-level) = mean across all claims.
    Biology tokens excluded. deque(maxlen=96).
    """

    MATURATION_THRESHOLD = 0.60
    BIOLOGY_TOKENS       = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self.matured_claims        = []
        self.maturation_projection = 0.0
        self.claim_reason          = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               paper_claim_continuity_bridge,
               research_agenda_composer,
               hypothesis_persistence_memory,
               validation_sweep_forecaster):
        if _IKG.sleeping:
            return

        claim_rec   = paper_claim_continuity_bridge.latest() if paper_claim_continuity_bridge else {}
        agenda_conf = getattr(research_agenda_composer, 'agenda_confidence', 0.5)
        hyp_rec     = hypothesis_persistence_memory.latest() if hypothesis_persistence_memory else {}
        fore_conf   = getattr(validation_sweep_forecaster, 'forecast_confidence', 0.5)

        claims      = claim_rec.get('persistent_claims', [])
        hyp_sal_map = {h.get('hypothesis_id', h.get('id', '')): float(h.get('salience', 0.5))
                       for h in hyp_rec.get('active_hypotheses', [])}

        matured = []
        for c in claims:
            cid         = str(c.get('claim_id', c.get('id', 'unknown')))
            claim_conf  = float(c.get('confidence', c.get('claim_confidence', 0.5)))
            mat_proj    = self._clamp(
                claim_conf * 0.40 + agenda_conf * 0.35 + fore_conf * 0.25
            )
            pub_ready   = mat_proj >= self.MATURATION_THRESHOLD
            matured.append({'claim_id':             cid,
                            'claim_confidence':     round(claim_conf, 4),
                            'maturation_projection':round(mat_proj, 4),
                            'likely_publication_ready': pub_ready,
                            'status': 'likely_publication_ready' if pub_ready else 'maturing'})

        self.matured_claims = matured
        self.maturation_projection = round(
            sum(m['maturation_projection'] for m in matured) / max(1, len(matured)), 4
        ) if matured else 0.0

        n_ready = sum(1 for m in matured if m['likely_publication_ready'])
        top_id  = matured[0]['claim_id'][:40] if matured else 'none'
        self.claim_reason = 'n=%d ready=%d proj=%.4f top=%s' % (
            len(matured), n_ready, self.maturation_projection, top_id)

        self._history.append({
            'tick':                  tick,
            'claim_count':           len(matured),
            'ready_count':           n_ready,
            'maturation_projection': self.maturation_projection,
            'claim_reason':          self.claim_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PostHiatusValueConvergence:
    """
    Synthesizes the single most valuable projected post-break scientific state.
    Uniqueness law enforced: exactly one convergence record per tick.

    post_hiatus_value keys:
        top_matured_claim       : highest maturation_projection ready claim
        strongest_milestone     : highest projected salience milestone
        reordered_rank1_experiment : forecast_agenda[0] label
        strongest_hypothesis    : highest proj_salience in hypothesis_forecast
        projected_eeil_gain     : eeil_gain_projection

    convergence_confidence = maturation_projection * 0.30
                           + salience_delta_norm    * 0.20
                           + (1 - drift_pressure)   * 0.25
                           + eeil_gain_projection   * 0.25

    salience_delta_norm = clamp(salience_delta / 0.10)  (normalised to [0,1])

    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self.post_hiatus_value     = {}
        self.convergence_confidence= 0.0
        self.value_reason          = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               paper_claim_maturation_estimator,
               milestone_salience_projector,
               agenda_reorder_predictor,
               hypothesis_drift_forecaster,
               eeil_tradeoff_workbench):
        if _IKG.sleeping:
            return

        mat_claims  = getattr(paper_claim_maturation_estimator, 'matured_claims', [])
        mat_proj    = getattr(paper_claim_maturation_estimator, 'maturation_projection', 0.5)
        proj_ms     = getattr(milestone_salience_projector,     'projected_milestones', [])
        sal_delta   = getattr(milestone_salience_projector,     'salience_delta', 0.0)
        fc_agenda   = getattr(agenda_reorder_predictor,         'forecast_agenda', [])
        hyp_fore    = getattr(hypothesis_drift_forecaster,      'hypothesis_forecast', [])
        drift_press = getattr(hypothesis_drift_forecaster,      'drift_pressure', 0.0)
        eeil_gain   = getattr(eeil_tradeoff_workbench,          'eeil_gain_projection', 0.5)

        # Top matured claim (by maturation_projection, must be ready)
        ready_claims = [m for m in mat_claims if m.get('likely_publication_ready')]
        if ready_claims:
            top_claim = max(ready_claims, key=lambda x: x['maturation_projection'])
            top_claim_id = str(top_claim['claim_id'])[:60]
        else:
            top_claim_id = 'none_ready'

        # Strongest milestone by projected_salience
        if proj_ms:
            strongest_ms = max(proj_ms, key=lambda x: x['projected_salience'])
            strongest_ms_id = str(strongest_ms['family_sig'])[:60]
        else:
            strongest_ms_id = 'none'

        # Reordered rank 1 experiment
        rank1_exp = fc_agenda[0]['label'][:60] if fc_agenda else 'none'

        # Strongest surviving hypothesis
        if hyp_fore:
            strongest_hyp = max(hyp_fore, key=lambda x: x['proj_salience'])
            strongest_hyp_id = str(strongest_hyp['id'])[:60]
        else:
            strongest_hyp_id = 'none'

        self.post_hiatus_value = {
            'top_matured_claim':           top_claim_id,
            'strongest_milestone':         strongest_ms_id,
            'reordered_rank1_experiment':  rank1_exp,
            'strongest_hypothesis':        strongest_hyp_id,
            'projected_eeil_gain':         round(eeil_gain, 4),
        }

        sal_delta_norm = self._clamp(sal_delta / 0.10) if sal_delta >= 0 else 0.0
        self.convergence_confidence = round(self._clamp(
            mat_proj * 0.30
            + sal_delta_norm * 0.20
            + (1.0 - drift_press) * 0.25
            + eeil_gain * 0.25
        ), 4)

        top_claim_short = top_claim_id[:30]
        self.value_reason = 'top_claim=%s strongest_ms=%s rank1=%s eeil_gain=%.4f' % (
            top_claim_short, strongest_ms_id[:20], rank1_exp[:20], eeil_gain)

        self._history.append({
            'tick':                  tick,
            'top_matured_claim':     top_claim_id,
            'strongest_milestone':   strongest_ms_id,
            'convergence_confidence':self.convergence_confidence,
            'value_reason':          self.value_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


