class ForecastReliabilityAssessor:
    """
    Evaluates incubation forecast reliability along four axes:
    simulation_confidence, convergence_confidence, drift_pressure, maturation_projection.

    FRAGILE_CAP = 5 (Rule 1 -- no meta clutter)

    False confidence penalty (Rule 2): if simulation_confidence >= 0.80 AND
    fragility_score >= 0.60 -> reliability_score -= 0.15 (clamped).

    reliability formula:
        raw_reliability = simulation_confidence * 0.35
                        + convergence_confidence * 0.30
                        + (1 - drift_pressure)   * 0.20
                        + maturation_projection  * 0.15
        if sim_conf >= 0.80 and fragility_score >= 0.60:
            raw_reliability -= FALSE_CONFIDENCE_PENALTY (0.15)
        reliability = clamp(raw_reliability)

    Fragile forecasts: components whose individual contribution to
    forecast error exceeds their weight (i.e. value < 0.50).
    Capped at FRAGILE_CAP.

    Biology tokens excluded. deque(maxlen=96).
    """

    FRAGILE_CAP               = 5
    FALSE_CONFIDENCE_PENALTY  = 0.15
    FALSE_CONF_SIM_THRESHOLD  = 0.80
    FALSE_CONF_FRAG_THRESHOLD = 0.60
    BIOLOGY_TOKENS            = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.forecast_reliability = 0.0
        self.fragile_forecasts    = []
        self.reliability_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               week_break_future_simulator,
               post_hiatus_value_convergence,
               hypothesis_drift_forecaster,
               paper_claim_maturation_estimator):
        if _IKG.sleeping:
            return

        sim_conf  = getattr(week_break_future_simulator,     'simulation_confidence', 0.5)
        conv_conf = getattr(post_hiatus_value_convergence,   'convergence_confidence', 0.5)
        drift_p   = getattr(hypothesis_drift_forecaster,     'drift_pressure',         0.3)
        mat_proj  = getattr(paper_claim_maturation_estimator,'maturation_projection',  0.5)

        components = [
            ('simulation_confidence', sim_conf,        0.35),
            ('convergence_confidence',conv_conf,       0.30),
            ('drift_stability',       1.0 - drift_p,  0.20),
            ('maturation_certainty',  mat_proj,        0.15),
        ]

        raw_reliability = sum(val * w for _, val, w in components)

        fragile_forecasts = [
            {'component': name, 'value': round(val, 4), 'weight': w}
            for name, val, w in components
            if val < 0.50
        ][:self.FRAGILE_CAP]

        fragility_score = len(fragile_forecasts) / max(1, len(components))

        penalty_applied = False
        if sim_conf >= self.FALSE_CONF_SIM_THRESHOLD and fragility_score >= self.FALSE_CONF_FRAG_THRESHOLD:
            raw_reliability -= self.FALSE_CONFIDENCE_PENALTY
            penalty_applied = True

        self.forecast_reliability = self._clamp(raw_reliability)
        self.fragile_forecasts    = fragile_forecasts
        self.reliability_reason   = 'rel=%.4f fragile=%d penalty=%s' % (
            self.forecast_reliability, len(fragile_forecasts), str(penalty_applied))

        self._history.append({
            'tick':                 tick,
            'forecast_reliability': round(self.forecast_reliability, 4),
            'fragile_count':        len(fragile_forecasts),
            'fragility_score':      round(fragility_score, 4),
            'penalty_applied':      penalty_applied,
            'reliability_reason':   self.reliability_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class BreakStrategyMetaLearner:
    """
    Learns from the incubation simulation: which continuity layers mattered most,
    which phases over-predicted value, which milestone projections were stable,
    which hypothesis decays were too aggressive.

    meta_break_laws: fixed law templates scored by reliability and convergence.
        law_score = forecast_reliability * 0.50 + convergence_confidence * 0.30
                  + (1 - drift_pressure) * 0.20

    strategy_delta = law_score - previous_law_score (0 on first tick).
    Learning: top law = max(law_score).

    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _LAW_TEMPLATES = [
        {'id': 'high_salience_consolidation',
         'law': 'milestones above 0.70 consolidate during silence'},
        {'id': 'eeil_hypothesis_resilience',
         'law': 'EEIL-tagged hypotheses resist 7-day decay'},
        {'id': 'pub_coupled_stability',
         'law': 'publication-coupled claims mature without intervention'},
        {'id': 'catalyst_continuity',
         'law': 'catalyst rank_1 stability is the strongest post-break lever'},
        {'id': 'convergence_before_agenda',
         'law': 'convergence confidence must precede agenda reorder'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self._prev_law_score  = None
        self.meta_break_laws  = []
        self.strategy_delta   = 0.0
        self.learning_reason  = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               forecast_reliability_assessor,
               post_hiatus_value_convergence,
               hypothesis_drift_forecaster,
               milestone_salience_projector):
        if _IKG.sleeping:
            return

        rel       = getattr(forecast_reliability_assessor,  'forecast_reliability', 0.5)
        conv_conf = getattr(post_hiatus_value_convergence,  'convergence_confidence', 0.5)
        drift_p   = getattr(hypothesis_drift_forecaster,    'drift_pressure', 0.3)
        sal_delta = getattr(milestone_salience_projector,   'salience_delta', 0.0)

        law_score = self._clamp(rel * 0.50 + conv_conf * 0.30 + (1.0 - drift_p) * 0.20)

        laws = []
        for tmpl in self._LAW_TEMPLATES:
            laws.append({'id':      tmpl['id'],
                         'law':     tmpl['law'],
                         'score':   round(law_score, 4),
                         'stable':  sal_delta >= 0})

        if self._prev_law_score is None:
            self.strategy_delta = 0.0
        else:
            self.strategy_delta = round(law_score - self._prev_law_score, 4)
        self._prev_law_score = law_score

        self.meta_break_laws = laws
        top_law = laws[0]['id'][:40] if laws else 'none'
        self.learning_reason = 'law_score=%.4f delta=%.4f top=%s' % (
            law_score, self.strategy_delta, top_law)

        self._history.append({
            'tick':              tick,
            'law_score':         round(law_score, 4),
            'strategy_delta':    self.strategy_delta,
            'law_count':         len(laws),
            'learning_reason':   self.learning_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ContinuityFragilityMapper:
    """
    Maps fragile structural points: weak anchors, blocker overdependence,
    stale prune risks, catalyst overfitting, roadmap brittleness.

    FRAGILE_CAP = 5 (Rule 1 joint cap).

    fragility_score = clamp(
        (1 - restart_priority) * 0.25
        + dep_pressure         * 0.25
        + drift_pressure       * 0.20
        + (1 - agenda_conf)    * 0.15
        + (1 - reliability)    * 0.15
    )

    risk_reason: 'score=X fragile_count=Y'
    Biology tokens excluded. deque(maxlen=96).
    """

    FRAGILE_CAP    = 5
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _FRAGILITY_SEEDS = [
        {'id': 'weak_anchor',            'axis': 'restart_priority'},
        {'id': 'blocker_overdependence', 'axis': 'dep_pressure'},
        {'id': 'stale_prune_risk',       'axis': 'drift_pressure'},
        {'id': 'catalyst_overfit',       'axis': 'agenda_confidence'},
        {'id': 'roadmap_brittleness',    'axis': 'forecast_reliability'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.fragility_map  = []
        self.fragility_score= 0.0
        self.risk_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               break_resumption_anchor,
               milestone_dependency_graph,
               hypothesis_drift_forecaster,
               research_agenda_composer,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        anchor_rec  = break_resumption_anchor.latest() if break_resumption_anchor else {}
        dep_rec     = milestone_dependency_graph.latest() if milestone_dependency_graph else {}

        restart_pri = float(anchor_rec.get('restart_priority', 0.5))
        dep_press   = float(dep_rec.get('dependency_pressure', 0.2))
        drift_p     = getattr(hypothesis_drift_forecaster,    'drift_pressure',         0.3)
        agenda_conf = getattr(research_agenda_composer,       'agenda_confidence',       0.5)
        reliability = getattr(forecast_reliability_assessor,  'forecast_reliability',    0.5)

        raw_scores = {
            'weak_anchor':            1.0 - restart_pri,
            'blocker_overdependence': dep_press,
            'stale_prune_risk':       drift_p,
            'catalyst_overfit':       1.0 - agenda_conf,
            'roadmap_brittleness':    1.0 - reliability,
        }

        fmap = []
        for seed in self._FRAGILITY_SEEDS:
            score = self._clamp(raw_scores.get(seed['id'], 0.5))
            fmap.append({'id':     seed['id'],
                         'axis':   seed['axis'],
                         'score':  round(score, 4),
                         'fragile':score >= 0.50})
        fmap.sort(key=lambda x: x['score'], reverse=True)
        self.fragility_map = fmap[:self.FRAGILE_CAP]

        self.fragility_score = self._clamp(
            (1.0 - restart_pri)  * 0.25
            + dep_press          * 0.25
            + drift_p            * 0.20
            + (1.0 - agenda_conf)* 0.15
            + (1.0 - reliability)* 0.15
        )
        self.fragility_score = round(self.fragility_score, 4)
        n_fragile = sum(1 for f in self.fragility_map if f['fragile'])
        self.risk_reason = 'score=%.4f fragile_count=%d' % (self.fragility_score, n_fragile)

        self._history.append({
            'tick':           tick,
            'fragility_score':self.fragility_score,
            'fragile_count':  n_fragile,
            'risk_reason':    self.risk_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MilestoneStrengthCauseAnalyzer:
    """
    Explains why milestones strengthened. Causality may only be one of
    five frozen sources (Rule 3): merge_bonus, anchor_reinforcement,
    dormant_revival, publication_coupling, blocker_resolution_path.
    No arbitrary causal hallucination.

    cause_confidence = clamp(
        salience_delta / 0.10  * 0.50   (normalized delta)
        + reliability          * 0.30
        + (1 - fragility_score)* 0.20
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    CAUSAL_SOURCES = frozenset({
        'merge_bonus', 'anchor_reinforcement', 'dormant_revival',
        'publication_coupling', 'blocker_resolution_path',
    })
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.milestone_causes = []
        self.cause_confidence = 0.0
        self.causal_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               milestone_salience_projector,
               narrative_arc_merger,
               break_resumption_anchor,
               dormant_milestone_reviver,
               forecast_reliability_assessor,
               continuity_fragility_mapper):
        if _IKG.sleeping:
            return

        proj_ms    = getattr(milestone_salience_projector, 'projected_milestones', [])
        sal_delta  = getattr(milestone_salience_projector, 'salience_delta', 0.0)
        arc_rec    = narrative_arc_merger.latest() if narrative_arc_merger else {}
        anchor_rec = break_resumption_anchor.latest() if break_resumption_anchor else {}
        rev_rec    = dormant_milestone_reviver.latest() if dormant_milestone_reviver else {}
        reliability = getattr(forecast_reliability_assessor, 'forecast_reliability', 0.5)
        frag_score  = getattr(continuity_fragility_mapper,   'fragility_score',      0.3)

        merged_fams = {
            str(a.get('primary_family', '')).lower()
            for a in arc_rec.get('merged_arcs', [])
        } | {
            str(a.get('secondary_family', '')).lower()
            for a in arc_rec.get('merged_arcs', [])
        }
        anchor_fams = set()
        anchor_data = anchor_rec.get('break_anchor', {})
        if isinstance(anchor_data, dict):
            for v in anchor_data.values():
                anchor_fams.add(str(v).lower())
        revived_fams = {
            str(r.get('family_sig', '')).lower()
            for r in rev_rec.get('revived_milestones', [])
        }

        causes = []
        for m in proj_ms:
            if m.get('delta', 0.0) <= 0:
                continue
            fam   = str(m.get('family_sig', '')).lower()
            found = []
            if any(fam in mf or mf in fam for mf in merged_fams if mf):
                found.append('merge_bonus')
            if any(fam in af or af in fam for af in anchor_fams if af):
                found.append('anchor_reinforcement')
            if any(fam in rf or rf in fam for rf in revived_fams if rf):
                found.append('dormant_revival')
            # default: no other cause
            if not found:
                found = ['anchor_reinforcement']  # most conservative default

            # Validate: only CAUSAL_SOURCES allowed
            found = [c for c in found if c in self.CAUSAL_SOURCES]
            if not found:
                found = ['anchor_reinforcement']

            causes.append({'family_sig': m.get('family_sig', 'unknown'),
                           'delta':      round(m.get('delta', 0.0), 4),
                           'causes':     found})

        self.milestone_causes = causes
        delta_norm = self._clamp(sal_delta / 0.10) if sal_delta >= 0 else 0.0
        self.cause_confidence = self._clamp(
            delta_norm * 0.50 + reliability * 0.30 + (1.0 - frag_score) * 0.20
        )
        self.cause_confidence = round(self.cause_confidence, 4)
        self.causal_reason = 'n_causes=%d delta=%.4f conf=%.4f' % (
            len(causes), sal_delta, self.cause_confidence)

        # Validate all causes are in CAUSAL_SOURCES (freeze check)
        all_valid = all(c in self.CAUSAL_SOURCES
                        for ms in causes for c in ms['causes'])

        self._history.append({
            'tick':               tick,
            'cause_count':        len(causes),
            'cause_confidence':   self.cause_confidence,
            'all_causes_valid':   all_valid,
            'causal_reason':      self.causal_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class AgendaAssumptionAuditor:
    """
    Audits hidden dependency assumptions, sweep overconfidence, launchpad
    overfit, and weak EEIL tradeoff projections.

    DEPENDENCY_SENSITIVITY_THRESHOLD = 0.70 -> 'fragile_assumption' (Rule 4)

    dependency_sensitivity per item = proj_score * dep_press + (1 - agenda_conf)
    (clamped, measures how much the item depends on unresolved blockers)

    audit_confidence = forecast_reliability * 0.40
                     + agenda_confidence    * 0.35
                     + (1 - fragility_score)* 0.25

    assumption_risks: list of fragile assumption dicts (cap FRAGILE_CAP=5).

    Biology tokens excluded. deque(maxlen=96).
    """

    DEPENDENCY_SENSITIVITY_THRESHOLD = 0.70
    FRAGILE_CAP    = 5
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.assumption_risks = []
        self.audit_confidence = 0.0
        self.audit_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               agenda_reorder_predictor,
               validation_sweep_forecaster,
               post_break_experiment_launchpad,
               eeil_tradeoff_workbench,
               forecast_reliability_assessor,
               continuity_fragility_mapper):
        if _IKG.sleeping:
            return

        fc_agenda   = getattr(agenda_reorder_predictor,       'forecast_agenda',        [])
        dep_press   = getattr(agenda_reorder_predictor,       'reorder_delta',          0.1)
        fore_conf   = getattr(validation_sweep_forecaster,    'forecast_confidence',    0.5)
        launch_conf = getattr(post_break_experiment_launchpad,'launch_confidence',      0.5)
        eeil_gain   = getattr(eeil_tradeoff_workbench,        'eeil_gain_projection',   0.5)
        reliability = getattr(forecast_reliability_assessor,  'forecast_reliability',   0.5)
        agenda_conf = 0.5  # conservative default
        frag_score  = getattr(continuity_fragility_mapper,    'fragility_score',        0.3)

        risks = []

        # Per-item dependency sensitivity
        for item in fc_agenda:
            proj_score = float(item.get('proj_score', item.get('score', 0.5)))
            dep_sens   = self._clamp(proj_score * dep_press + (1.0 - fore_conf))
            if dep_sens >= self.DEPENDENCY_SENSITIVITY_THRESHOLD:
                risks.append({'id':                   item.get('id', 'unknown'),
                              'label':                item.get('label', '')[:50],
                              'dependency_sensitivity':round(dep_sens, 4),
                              'risk_class':            'fragile_assumption'})

        # Sweep overconfidence
        if fore_conf >= 0.85:
            risks.append({'id':         'sweep_overconfidence',
                          'label':      'validation sweep confidence too high',
                          'dependency_sensitivity': round(fore_conf, 4),
                          'risk_class': 'sweep_overconfidence'})

        # Launchpad overfit
        if launch_conf >= 0.90:
            risks.append({'id':         'launchpad_overfit',
                          'label':      'launch confidence may be overfit',
                          'dependency_sensitivity': round(launch_conf, 4),
                          'risk_class': 'launchpad_overfit'})

        # Weak EEIL tradeoff projection
        if eeil_gain < 0.40:
            risks.append({'id':         'weak_eeil_tradeoff',
                          'label':      'EEIL tradeoff gain below threshold',
                          'dependency_sensitivity': round(1.0 - eeil_gain, 4),
                          'risk_class': 'weak_eeil_tradeoff'})

        self.assumption_risks = risks[:self.FRAGILE_CAP]
        self.audit_confidence = self._clamp(
            reliability * 0.40 + fore_conf * 0.35 + (1.0 - frag_score) * 0.25
        )
        self.audit_confidence = round(self.audit_confidence, 4)
        n_fragile = sum(1 for r in self.assumption_risks
                        if r['risk_class'] == 'fragile_assumption')
        self.audit_reason = 'risks=%d fragile=%d conf=%.4f' % (
            len(self.assumption_risks), n_fragile, self.audit_confidence)

        self._history.append({
            'tick':             tick,
            'risk_count':       len(self.assumption_risks),
            'fragile_count':    n_fragile,
            'audit_confidence': self.audit_confidence,
            'audit_reason':     self.audit_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class FutureHiatusPolicyRefiner:
    """
    Chooses the single best refined strategy for the next long break
    (uniqueness law, Rule 5). Stores fragile assumptions, best continuity
    layer, safest agenda breadth, ideal milestone cap, optimal hypothesis
    retention, and policy rationale.

    policy_confidence = forecast_reliability * 0.30
                      + (1 - fragility_score) * 0.25
                      + cause_confidence      * 0.25
                      + audit_confidence      * 0.20

    next_hiatus_policy keys (fixed):
        fragile_assumptions      : list of top fragile assumption ids
        best_continuity_layer    : highest reliability source
        safest_agenda_breadth    : int (5 - fragile_count, min 1)
        ideal_milestone_cap      : int (6 if delta >= 0 else 5)
        optimal_hypothesis_cap   : int (5 if drift_pressure < 0.30 else 3)
        policy_rationale         : str

    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.next_hiatus_policy = {}
        self.policy_confidence  = 0.0
        self.policy_reason      = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               forecast_reliability_assessor,
               continuity_fragility_mapper,
               milestone_strength_cause_analyzer,
               agenda_assumption_auditor,
               hypothesis_drift_forecaster,
               milestone_salience_projector):
        if _IKG.sleeping:
            return

        reliability  = getattr(forecast_reliability_assessor,   'forecast_reliability', 0.5)
        frag_ff      = getattr(forecast_reliability_assessor,   'fragile_forecasts',    [])
        frag_score   = getattr(continuity_fragility_mapper,     'fragility_score',      0.3)
        frag_map     = getattr(continuity_fragility_mapper,     'fragility_map',        [])
        cause_conf   = getattr(milestone_strength_cause_analyzer,'cause_confidence',    0.5)
        audit_conf   = getattr(agenda_assumption_auditor,       'audit_confidence',     0.5)
        assumption_r = getattr(agenda_assumption_auditor,       'assumption_risks',     [])
        drift_p      = getattr(hypothesis_drift_forecaster,     'drift_pressure',       0.3)
        sal_delta    = getattr(milestone_salience_projector,    'salience_delta',       0.0)

        # Fragile assumptions (from both sources, capped at 5)
        all_fragile_ids = [f['component'] for f in frag_ff] + \
                          [r['id'] for r in assumption_r
                           if r.get('risk_class') == 'fragile_assumption']
        fragile_ids = list(dict.fromkeys(all_fragile_ids))[:5]

        # Best continuity layer: highest-scoring non-fragile from fragility map
        non_fragile = [f for f in frag_map if not f['fragile']]
        best_layer  = (max(non_fragile, key=lambda x: 1.0 - x['score'])['axis']
                       if non_fragile else 'catalyst_continuity')

        # Policy parameters
        fragile_count          = len(fragile_ids)
        safest_agenda_breadth  = max(1, 5 - fragile_count)
        ideal_milestone_cap    = 6 if sal_delta >= 0.0 else 5
        optimal_hypothesis_cap = 5 if drift_p < 0.30 else 3

        policy_rationale = (
            'fragile=%d breadth=%d ms_cap=%d hyp_cap=%d best_layer=%s' % (
                fragile_count, safest_agenda_breadth,
                ideal_milestone_cap, optimal_hypothesis_cap, best_layer[:30])
        )

        self.next_hiatus_policy = {
            'fragile_assumptions':   fragile_ids,
            'best_continuity_layer': best_layer[:60],
            'safest_agenda_breadth': safest_agenda_breadth,
            'ideal_milestone_cap':   ideal_milestone_cap,
            'optimal_hypothesis_cap':optimal_hypothesis_cap,
            'policy_rationale':      policy_rationale,
        }

        self.policy_confidence = round(self._clamp(
            reliability * 0.30
            + (1.0 - frag_score) * 0.25
            + cause_conf         * 0.25
            + audit_conf         * 0.20
        ), 4)

        self.policy_reason = 'conf=%.4f best_layer=%s fragile=%d' % (
            self.policy_confidence, best_layer[:30], fragile_count)

        self._history.append({
            'tick':               tick,
            'policy_confidence':  self.policy_confidence,
            'fragile_count':      fragile_count,
            'ideal_milestone_cap':ideal_milestone_cap,
            'policy_reason':      self.policy_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


