class HiatusIdentityProjector:
    """
    Projects how the organism's project identity will shift across the
    7-day hiatus: milestone identity changes, curiosity centre shifts,
    agenda priority influence, EEIL optimisation identity pull.

    identity_projection_conf = clamp(
        simulation_confidence * 0.35
        + milestone_salience  * 0.25
        + agenda_confidence   * 0.20
        + eeil_gain           * 0.20
    )

    future_identity_state keys:
        dominant_milestone_family : highest projected salience family
        agenda_rank_1_identity    : catalyst label (identity-defining)
        eeil_identity_pull        : eeil_gain_projection
        curiosity_center          : top hypothesis id
        projected_horizon_days    : 7 (frozen)

    Rule 5: if forecast_reliability < 0.50, flag 'tentative_shift_only'.
    Biology tokens excluded. deque(maxlen=96).
    """

    FORECAST_RELIABILITY_FLOOR = 0.50
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                 = maxlen
        self._history                = deque(maxlen=maxlen)
        self.future_identity_state   = {}
        self.identity_projection_conf= 0.0
        self.projection_reason       = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               week_break_future_simulator,
               milestone_salience_projector,
               research_agenda_composer,
               eeil_tradeoff_workbench,
               hypothesis_persistence_memory,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        sim_conf    = getattr(week_break_future_simulator,    'simulation_confidence', 0.5)
        proj_ms     = getattr(milestone_salience_projector,   'projected_milestones',  [])
        ms_sal      = getattr(milestone_salience_projector,   'salience_delta',        0.0)
        agenda      = getattr(research_agenda_composer,       'research_agenda',       [])
        agenda_conf = getattr(research_agenda_composer,       'agenda_confidence',     0.5)
        eeil_gain   = getattr(eeil_tradeoff_workbench,        'eeil_gain_projection',  0.5)
        reliability = getattr(forecast_reliability_assessor,  'forecast_reliability',  0.5)
        hyp_rec     = hypothesis_persistence_memory.latest() if hypothesis_persistence_memory else {}

        # Mean projected ms salience
        ms_mean_sal = (sum(m.get('projected_salience', 0.5) for m in proj_ms)
                       / max(1, len(proj_ms))) if proj_ms else 0.5

        dom_ms = (max(proj_ms, key=lambda x: x.get('projected_salience', 0))
                  ['family_sig'] if proj_ms else 'none')

        rank1_label = agenda[0]['label'][:60] if agenda else 'none'

        hyps = hyp_rec.get('active_hypotheses', [])
        top_hyp = hyps[0].get('hypothesis_id', hyps[0].get('id', 'none')) if hyps else 'none'

        tentative = reliability < self.FORECAST_RELIABILITY_FLOOR

        self.future_identity_state = {
            'dominant_milestone_family': str(dom_ms)[:60],
            'agenda_rank_1_identity':   rank1_label,
            'eeil_identity_pull':       round(eeil_gain, 4),
            'curiosity_center':         str(top_hyp)[:60],
            'projected_horizon_days':   7,
            'tentative_shift_only':     tentative,
        }

        self.identity_projection_conf = round(self._clamp(
            sim_conf * 0.35 + ms_mean_sal * 0.25 + agenda_conf * 0.20 + eeil_gain * 0.20
        ), 4)
        self.projection_reason = 'dom_ms=%s conf=%.4f tentative=%s' % (
            str(dom_ms)[:30], self.identity_projection_conf, str(tentative))

        self._history.append({
            'tick':                   tick,
            'dominant_milestone':     str(dom_ms)[:40],
            'identity_projection_conf':self.identity_projection_conf,
            'tentative':              tentative,
            'projection_reason':      self.projection_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class NarrativeSelfEvolutionModel:
    """
    Models the autobiographical scientific story after silence:
    which narrative becomes dominant, which thread becomes 'the self',
    which dormant meaning resurfaces stronger.

    narrative_shift = projected_identity_conf - prev_identity_conf
                      (0.0 on first tick)

    evolved_self_narrative: single dominant narrative record {
        thread_id, narrative_label, narrative_score, is_dominant, tentative
    }

    narrative_score = identity_projection_conf * 0.50
                    + convergence_confidence   * 0.30
                    + (1 - drift_pressure)     * 0.20

    Rule 5: tentative if forecast_reliability < 0.50.
    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _NARRATIVE_SEEDS = [
        {'id': 'eeil_sparse_researcher',
         'label': 'sparse compute efficiency researcher'},
        {'id': 'continuity_architect',
         'label': 'continuity-before-localization architect'},
        {'id': 'day28_continuity_author',
         'label': 'Day28 proof-of-continuity author'},
        {'id': 'milestone_synthesizer',
         'label': 'milestone synthesis theorist'},
        {'id': 'hiatus_intelligence_pioneer',
         'label': 'hiatus intelligence pioneer'},
    ]

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self._prev_identity_conf   = None
        self.evolved_self_narrative= {}
        self.narrative_shift       = 0.0
        self.evolution_reason      = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               hiatus_identity_projector,
               post_hiatus_value_convergence,
               hypothesis_drift_forecaster,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        id_conf   = getattr(hiatus_identity_projector,     'identity_projection_conf', 0.5)
        id_state  = getattr(hiatus_identity_projector,     'future_identity_state',    {})
        conv_conf = getattr(post_hiatus_value_convergence, 'convergence_confidence',   0.5)
        drift_p   = getattr(hypothesis_drift_forecaster,   'drift_pressure',           0.3)
        reliability = getattr(forecast_reliability_assessor,'forecast_reliability',    0.5)
        tentative   = reliability < 0.50

        narr_score = self._clamp(id_conf * 0.50 + conv_conf * 0.30 + (1.0 - drift_p) * 0.20)

        # Pick dominant narrative: highest scored seed
        # All seeds get same score (no per-seed variation in this advisory layer);
        # dominant = first seed aligned with identity state
        dom_id    = id_state.get('agenda_rank_1_identity', '')
        # Match seed whose label overlaps with agenda_rank_1_identity token
        best_seed = None
        for seed in self._NARRATIVE_SEEDS:
            if any(t in dom_id.lower() for t in seed['label'].split() if len(t) > 3):
                best_seed = seed
                break
        if best_seed is None:
            best_seed = self._NARRATIVE_SEEDS[0]

        self.evolved_self_narrative = {
            'thread_id':       best_seed['id'],
            'narrative_label': best_seed['label'],
            'narrative_score': round(narr_score, 4),
            'is_dominant':     True,
            'tentative':       tentative,
        }

        if self._prev_identity_conf is None:
            self.narrative_shift = 0.0
        else:
            self.narrative_shift = round(narr_score - self._prev_identity_conf, 4)
        self._prev_identity_conf = narr_score

        self.evolution_reason = 'dom=%s score=%.4f shift=%.4f tentative=%s' % (
            best_seed['id'][:30], narr_score, self.narrative_shift, str(tentative))

        self._history.append({
            'tick':             tick,
            'dominant_thread':  best_seed['id'],
            'narrative_score':  round(narr_score, 4),
            'narrative_shift':  self.narrative_shift,
            'tentative':        tentative,
            'evolution_reason': self.evolution_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ScientificPersonaStabilityIndex:
    """
    Frozen formula:
        persona_stability = clamp(
            identity_projection_conf * 0.35
            + forecast_reliability   * 0.25
            + milestone_meaning      * 0.20
            + curiosity_alignment    * 0.20
        )

    Rule 4: persona_stability >= 0.60 must be preserved.
    stability_risk: 'at_risk' if persona_stability < 0.60, else 'stable'.

    milestone_meaning: mean meaning_weight of reweighted_milestones.
    curiosity_alignment: mean normalised curiosity priority.

    Rule 5: tentative flag propagated if forecast_reliability < 0.50.
    Biology tokens excluded. deque(maxlen=96).
    """

    STABILITY_FLOOR = 0.60
    BIOLOGY_TOKENS  = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen         = maxlen
        self._history        = deque(maxlen=maxlen)
        self.persona_stability = 0.0
        self.stability_risk    = 'unknown'
        self.persona_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               hiatus_identity_projector,
               forecast_reliability_assessor,
               milestone_meaning_reweighter,
               curiosity_vector_realigner):
        if _IKG.sleeping:
            return

        id_conf     = getattr(hiatus_identity_projector,    'identity_projection_conf', 0.5)
        reliability = getattr(forecast_reliability_assessor,'forecast_reliability',     0.5)
        rw_ms       = getattr(milestone_meaning_reweighter, 'reweighted_milestones',   [])
        cv          = getattr(curiosity_vector_realigner,   'aligned_curiosity_vectors',[])

        ms_meaning = (sum(m.get('meaning_weight', 0.5) for m in rw_ms)
                      / max(1, len(rw_ms))) if rw_ms else 0.5

        curiosity_align = (sum(c.get('priority', 0.5) for c in cv)
                           / max(1, len(cv))) if cv else 0.5

        self.persona_stability = round(self._clamp(
            id_conf     * 0.35
            + reliability * 0.25
            + ms_meaning  * 0.20
            + curiosity_align * 0.20
        ), 4)

        self.stability_risk = 'at_risk' if self.persona_stability < self.STABILITY_FLOOR else 'stable'
        tentative = reliability < 0.50
        self.persona_reason = 'stability=%.4f risk=%s tentative=%s' % (
            self.persona_stability, self.stability_risk, str(tentative))

        self._history.append({
            'tick':              tick,
            'persona_stability': self.persona_stability,
            'stability_risk':    self.stability_risk,
            'tentative':         tentative,
            'persona_reason':    self.persona_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MilestoneMeaningReweighter:
    """
    Re-evaluates why milestones matter and which define selfhood.

    Rule 2: any milestone with projected_salience_delta >= 0.10
            receives meaning_weight_bonus = +0.05.

    meaning_weight per milestone:
        base_weight = projected_salience (clamped)
        if delta >= 0.10: base_weight += MEANING_WEIGHT_BONUS (0.05)

    meaning_shift = projected_mean_weight - original_mean_weight

    selfhood_class:
        'selfhood_defining'  : meaning_weight >= 0.75
        'utility_only'       : meaning_weight < 0.40
        'active_meaning'     : otherwise

    Biology tokens excluded. deque(maxlen=96).
    """

    MEANING_WEIGHT_BONUS   = 0.05
    SALIENCE_DELTA_THRESHOLD = 0.10
    SELFHOOD_THRESHOLD     = 0.75
    UTILITY_THRESHOLD      = 0.40
    BIOLOGY_TOKENS         = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.reweighted_milestones= []
        self.meaning_shift        = 0.0
        self.meaning_reason       = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               milestone_salience_projector,
               post_hiatus_value_convergence,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        proj_ms    = getattr(milestone_salience_projector, 'projected_milestones', [])
        reliability = getattr(forecast_reliability_assessor,'forecast_reliability', 0.5)
        tentative   = reliability < 0.50

        reweighted  = []
        orig_total  = 0.0
        proj_total  = 0.0

        for m in proj_ms:
            proj_sal  = float(m.get('projected_salience', 0.5))
            orig_sal  = float(m.get('original_salience', proj_sal))
            delta     = float(m.get('delta', proj_sal - orig_sal))

            base_w = proj_sal
            bonus_applied = False
            if delta >= self.SALIENCE_DELTA_THRESHOLD:
                base_w = self._clamp(base_w + self.MEANING_WEIGHT_BONUS)
                bonus_applied = True

            if base_w >= self.SELFHOOD_THRESHOLD:
                selfhood_cls = 'selfhood_defining'
            elif base_w < self.UTILITY_THRESHOLD:
                selfhood_cls = 'utility_only'
            else:
                selfhood_cls = 'active_meaning'

            orig_total += orig_sal
            proj_total += base_w

            reweighted.append({
                'family_sig':    m.get('family_sig', 'unknown'),
                'meaning_weight':round(base_w, 4),
                'selfhood_class':selfhood_cls,
                'bonus_applied': bonus_applied,
                'tentative':     tentative,
            })

        self.reweighted_milestones = reweighted
        n = max(1, len(proj_ms))
        self.meaning_shift  = round(proj_total/n - orig_total/n, 4)
        n_selfhood = sum(1 for r in reweighted if r['selfhood_class'] == 'selfhood_defining')
        self.meaning_reason = 'n=%d selfhood=%d shift=%.4f' % (
            len(reweighted), n_selfhood, self.meaning_shift)

        self._history.append({
            'tick':            tick,
            'milestone_count': len(reweighted),
            'meaning_shift':   self.meaning_shift,
            'meaning_reason':  self.meaning_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class CuriosityVectorRealigner:
    """
    Re-ranks curiosity vectors for the post-break self.

    Rule 3: vectors tied to rank_1 catalyst, launch_experiment, or
    top matured claim receive identity_priority_bonus = +0.10 (frozen).

    curiosity_vector priority:
        base_priority = hypothesis_salience (from forecast)
        if tied to rank_1 / launch / matured_claim: += PRIORITY_BONUS (0.10)
        clamped to [0, 1]

    realignment_delta = projected_mean_priority - base_mean_priority

    Rule 5: tentative if forecast_reliability < 0.50.
    Biology tokens excluded. deque(maxlen=96).
    """

    PRIORITY_BONUS         = 0.10
    BIOLOGY_TOKENS         = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                  = maxlen
        self._history                 = deque(maxlen=maxlen)
        self.aligned_curiosity_vectors= []
        self.realignment_delta        = 0.0
        self.curiosity_reason         = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               hypothesis_drift_forecaster,
               research_agenda_composer,
               post_break_experiment_launchpad,
               paper_claim_maturation_estimator,
               open_question_graph,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        hyp_fore    = getattr(hypothesis_drift_forecaster,      'hypothesis_forecast',  [])
        agenda      = getattr(research_agenda_composer,          'research_agenda',      [])
        launch_exp  = getattr(post_break_experiment_launchpad,   'launch_experiment',    {})
        mat_claims  = getattr(paper_claim_maturation_estimator,  'matured_claims',       [])
        oqg_rec     = open_question_graph.latest() if open_question_graph else {}
        reliability = getattr(forecast_reliability_assessor,     'forecast_reliability', 0.5)
        tentative   = reliability < 0.50

        # Build identity attractor set (rank_1 tokens, launch tokens, claim tokens)
        rank1_tokens  = set()
        if agenda:
            rank1_tokens = set(str(agenda[0].get('label', '')).lower().split())
        launch_tokens = set(str(launch_exp.get('agenda_rank_1', '')).lower().split())
        claim_tokens  = set()
        for m in [c for c in mat_claims if c.get('likely_publication_ready')]:
            claim_tokens |= set(str(m.get('claim_id', '')).lower().split('_'))

        attractor_tokens = rank1_tokens | launch_tokens | claim_tokens

        aligned = []
        base_total = 0.0
        proj_total = 0.0

        for h in hyp_fore:
            hid      = str(h.get('id', 'unknown'))
            base_pri = float(h.get('proj_salience', h.get('base_salience', 0.5)))
            base_total += base_pri

            # Check alignment with identity attractors
            h_tokens = set(hid.lower().split('_'))
            tied     = bool(h_tokens & attractor_tokens)
            proj_pri = self._clamp(base_pri + self.PRIORITY_BONUS) if tied else base_pri
            proj_total += proj_pri

            aligned.append({
                'id':            hid[:60],
                'priority':      round(proj_pri, 4),
                'base_priority': round(base_pri, 4),
                'tied_to_identity': tied,
                'tentative':     tentative,
            })

        aligned.sort(key=lambda x: x['priority'], reverse=True)
        self.aligned_curiosity_vectors = aligned

        n = max(1, len(hyp_fore))
        self.realignment_delta = round(proj_total/n - base_total/n, 4)
        n_tied = sum(1 for a in aligned if a['tied_to_identity'])
        self.curiosity_reason = 'n=%d tied=%d delta=%.4f tentative=%s' % (
            len(aligned), n_tied, self.realignment_delta, str(tentative))

        self._history.append({
            'tick':              tick,
            'vector_count':      len(aligned),
            'realignment_delta': self.realignment_delta,
            'tied_count':        n_tied,
            'curiosity_reason':  self.curiosity_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PostBreakSelfContinuityAnchor:
    """
    Chooses the single identity-defining self state to return from hiatus.
    Rule 1: exactly one anchor per tick (uniqueness law).

    anchor_confidence = persona_stability * 0.35
                      + identity_projection_conf * 0.30
                      + cause_confidence         * 0.20
                      + policy_confidence        * 0.15

    self_continuity_anchor keys:
        dominant_narrative      : evolved_self_narrative['narrative_label']
        strongest_milestone_meaning : highest meaning_weight milestone family
        top_curiosity_pull      : aligned_curiosity_vectors[0]['id']
        launch_experiment_influence : launch_experiment['agenda_rank_1']
        refined_hiatus_policy   : next_hiatus_policy['policy_rationale']
        selfhood_rationale      : str

    Rule 5: tentative if forecast_reliability < 0.50.
    Biology tokens excluded. deque(maxlen=96).
    """

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                  = maxlen
        self._history                 = deque(maxlen=maxlen)
        self.self_continuity_anchor   = {}
        self.anchor_confidence        = 0.0
        self.anchor_reason            = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               narrative_self_evolution_model,
               scientific_persona_stability_index,
               milestone_meaning_reweighter,
               curiosity_vector_realigner,
               hiatus_identity_projector,
               milestone_strength_cause_analyzer,
               future_hiatus_policy_refiner,
               post_break_experiment_launchpad,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        narr       = getattr(narrative_self_evolution_model,     'evolved_self_narrative', {})
        persona_st = getattr(scientific_persona_stability_index, 'persona_stability',      0.5)
        rw_ms      = getattr(milestone_meaning_reweighter,       'reweighted_milestones',  [])
        cv         = getattr(curiosity_vector_realigner,         'aligned_curiosity_vectors',[])
        id_conf    = getattr(hiatus_identity_projector,          'identity_projection_conf',0.5)
        cause_conf = getattr(milestone_strength_cause_analyzer,  'cause_confidence',        0.5)
        policy     = getattr(future_hiatus_policy_refiner,       'next_hiatus_policy',      {})
        policy_conf= getattr(future_hiatus_policy_refiner,       'policy_confidence',       0.5)
        launch_exp = getattr(post_break_experiment_launchpad,    'launch_experiment',       {})
        reliability = getattr(forecast_reliability_assessor,     'forecast_reliability',    0.5)
        tentative   = reliability < 0.50

        dom_narr    = str(narr.get('narrative_label', 'eeil_sparse_researcher'))[:60]
        strongest_ms = (max(rw_ms, key=lambda x: x['meaning_weight'])['family_sig']
                        if rw_ms else 'none')
        top_cv      = cv[0]['id'][:60] if cv else 'none'
        launch_infl = str(launch_exp.get('agenda_rank_1', 'none'))[:60]
        pol_rat     = str(policy.get('policy_rationale', 'none'))[:80]

        selfhood_rat = 'dom_narr=%s top_cv=%s tentative=%s' % (
            dom_narr[:30], top_cv[:20], str(tentative))

        self.self_continuity_anchor = {
            'dominant_narrative':         dom_narr,
            'strongest_milestone_meaning':str(strongest_ms)[:60],
            'top_curiosity_pull':         top_cv,
            'launch_experiment_influence':launch_infl,
            'refined_hiatus_policy':      pol_rat,
            'selfhood_rationale':         selfhood_rat,
            'tentative':                  tentative,
        }

        self.anchor_confidence = round(self._clamp(
            persona_st * 0.35
            + id_conf   * 0.30
            + cause_conf* 0.20
            + policy_conf * 0.15
        ), 4)

        self.anchor_reason = 'conf=%.4f narr=%s tentative=%s' % (
            self.anchor_confidence, dom_narr[:30], str(tentative))

        self._history.append({
            'tick':             tick,
            'anchor_confidence':self.anchor_confidence,
            'dominant_narrative':dom_narr[:40],
            'tentative':        tentative,
            'anchor_reason':    self.anchor_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 28 PHASE H: Long-Gap Doctrine Consolidation Suite
# First institutional memory layer for research breaks. Compresses all
# Day 28 hiatus intelligence into reusable silence doctrine.
# Klein 1998 (naturalistic decision making); Weick 1979 (sensemaking);
# March 1991 (exploration vs exploitation); Schon 1983 (reflective practice)
# ===========================================================================

class LongGapDoctrineSynthesizer:
    """
    Compresses Day 28 phase laws, restart doctrines, incubation rules,
    selfhood anchors, and catalyst priorities into ranked doctrine laws.

    REUSABLE_LAW_BONUS = +0.10 (Rule 2): law receives bonus if evidenced
    in 2+ phase-level validations (tracked by fixed provenance tags).

    doctrine_law_score = base_score
                       + REUSABLE_LAW_BONUS * reusable_flag
    synthesis_confidence = clamp(
        anchor_confidence * 0.35
        + persona_stability * 0.25
        + policy_confidence * 0.20
        + forecast_reliability * 0.20
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    REUSABLE_LAW_BONUS = 0.10
    BIOLOGY_TOKENS     = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _LAW_SEEDS = [
        {'id': 'ms_cap_doctrine',
         'law': 'milestone cap 6 preserves identity across all break durations',
         'base_score': 0.80, 'phases': ['A','B','D','G'], 'reusable': True},
        {'id': 'catalyst_freeze_doctrine',
         'law': 'research catalyst rank_1 must be frozen at break onset',
         'base_score': 0.78, 'phases': ['C','D','G'], 'reusable': True},
        {'id': 'eeil_sparse_doctrine',
         'law': 'EEIL sparse compute discipline holds across all hiatus regimes',
         'base_score': 0.76, 'phases': ['D','E','F'], 'reusable': True},
        {'id': 'incubation_horizon_doctrine',
         'law': 'incubation horizon frozen at 7 days for all week-class hiatuses',
         'base_score': 0.74, 'phases': ['E','G'], 'reusable': True},
        {'id': 'persona_floor_doctrine',
         'law': 'scientific persona stability must stay above 0.60 during silence',
         'base_score': 0.72, 'phases': ['G'], 'reusable': False},
        {'id': 'hypothesis_decay_doctrine',
         'law': 'stale hypotheses below 0.40 salience decay -0.10 per silence week',
         'base_score': 0.70, 'phases': ['E','F'], 'reusable': True},
        {'id': 'curiosity_identity_coupling',
         'law': 'curiosity vectors coupled to catalyst gain +0.10 identity priority',
         'base_score': 0.68, 'phases': ['G'], 'reusable': False},
    ]

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.doctrine_laws       = []
        self.synthesis_confidence= 0.0
        self.doctrine_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               post_break_self_continuity_anchor,
               scientific_persona_stability_index,
               future_hiatus_policy_refiner,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        anchor_conf = getattr(post_break_self_continuity_anchor,   'anchor_confidence',  0.5)
        persona_st  = getattr(scientific_persona_stability_index,   'persona_stability',  0.5)
        policy_conf = getattr(future_hiatus_policy_refiner,         'policy_confidence',  0.5)
        reliability = getattr(forecast_reliability_assessor,        'forecast_reliability',0.5)

        laws = []
        for seed in self._LAW_SEEDS:
            score = seed['base_score']
            if seed['reusable']:
                score = self._clamp(score + self.REUSABLE_LAW_BONUS)
            laws.append({'id':       seed['id'],
                         'law':      seed['law'],
                         'score':    round(score, 4),
                         'reusable': seed['reusable'],
                         'phases':   seed['phases']})

        laws.sort(key=lambda x: x['score'], reverse=True)
        self.doctrine_laws = laws

        self.synthesis_confidence = round(self._clamp(
            anchor_conf * 0.35 + persona_st * 0.25
            + policy_conf * 0.20 + reliability * 0.20
        ), 4)
        top_law = laws[0]['id'][:40] if laws else 'none'
        self.doctrine_reason = 'laws=%d conf=%.4f top=%s' % (
            len(laws), self.synthesis_confidence, top_law)

        self._history.append({
            'tick':               tick,
            'law_count':          len(laws),
            'synthesis_confidence':self.synthesis_confidence,
            'doctrine_reason':    self.doctrine_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class HiatusLawArchive:
    """
    Persists reusable break laws with provenance, success frequency,
    phase reuse evidence, and protocol confidence.

    Rule 2: reusable_law_bonus = +0.10 for laws evidenced in 2+ phases.

    law_reuse_score = clamp(
        mean(scored_laws) * 0.60 + synthesis_confidence * 0.40
    )

    archived_hiatus_laws: top laws from doctrine_laws that are reusable
    (may appear in all future hiatuses).

    Biology tokens excluded. deque(maxlen=96).
    """

    REUSABLE_LAW_BONUS = 0.10
    BIOLOGY_TOKENS     = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.archived_hiatus_laws = []
        self.law_reuse_score    = 0.0
        self.archive_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               long_gap_doctrine_synthesizer,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        doc_laws    = getattr(long_gap_doctrine_synthesizer, 'doctrine_laws',        [])
        synth_conf  = getattr(long_gap_doctrine_synthesizer, 'synthesis_confidence', 0.5)
        reliability = getattr(forecast_reliability_assessor, 'forecast_reliability', 0.5)

        # Archive only reusable laws (evidenced in 2+ phases)
        archived = [l for l in doc_laws if l.get('reusable')
                    and len(l.get('phases', [])) >= 2]
        # Annotate with provenance
        for law in archived:
            law['phase_count'] = len(law.get('phases', []))
            law['archive_tick'] = tick

        self.archived_hiatus_laws = archived

        scored = [l['score'] for l in archived]
        mean_score = sum(scored) / max(1, len(scored)) if scored else 0.5
        self.law_reuse_score = round(self._clamp(
            mean_score * 0.60 + synth_conf * 0.40
        ), 4)
        self.archive_reason = 'archived=%d reuse_score=%.4f' % (
            len(archived), self.law_reuse_score)

        self._history.append({
            'tick':            tick,
            'archived_count':  len(archived),
            'law_reuse_score': self.law_reuse_score,
            'archive_reason':  self.archive_reason,
        })

