class SilenceDurationClassifier:
    """
    Classifies the current silence duration into a canonical rung of the
    frozen duration ladder [1,3,7,14,30,90] and assigns a duration class
    label, duration confidence, and classification reason.

    Duration ladder (Rule 1 -- frozen):
        [1, 3, 7, 14, 30, 90]

    Class labels:
        1  -> micro_break
        3  -> short_gap
        7  -> week_gap
        14 -> long_gap
        30 -> semester_gap
        90 -> seasonal_hiatus

    duration_confidence = clamp(kernel_confidence * 0.60 + reliability * 0.40)

    Biology tokens excluded. deque(maxlen=96).
    """

    DURATION_LADDER   = [1, 3, 7, 14, 30, 90]
    DURATION_CLASS_MAP = {
        1:  'micro_break',
        3:  'short_gap',
        7:  'week_gap',
        14: 'long_gap',
        30: 'semester_gap',
        90: 'seasonal_hiatus',
    }
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self.duration_class        = 'week_gap'
        self.target_duration       = 7
        self.duration_confidence   = 0.0
        self.classification_reason = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _nearest_rung(d):
        ladder = [1, 3, 7, 14, 30, 90]
        return min(ladder, key=lambda x: abs(x - d))

    def update(self, tick,
               institutional_continuity_kernel,
               forecast_reliability_assessor):
        if _IKG.sleeping:
            return

        kernel      = getattr(institutional_continuity_kernel, 'continuity_kernel',    {})
        kernel_conf = getattr(institutional_continuity_kernel, 'kernel_confidence',    0.5)
        reliability = getattr(forecast_reliability_assessor,   'forecast_reliability', 0.5)

        raw_dur = int(kernel.get('forecast_horizon_doctrine', 7))
        rung    = self._nearest_rung(raw_dur)
        self.target_duration     = rung
        self.duration_class      = self.DURATION_CLASS_MAP.get(rung, 'week_gap')
        self.duration_confidence = round(self._clamp(
            kernel_conf * 0.60 + reliability * 0.40
        ), 4)
        self.classification_reason = 'dur=%d class=%s conf=%.4f' % (
            rung, self.duration_class, self.duration_confidence)

        self._history.append({
            'tick':                tick,
            'target_duration':     rung,
            'duration_class':      self.duration_class,
            'duration_confidence': self.duration_confidence,
            'classification_reason': self.classification_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class TemporalContinuityScaler:
    """
    Scales milestone caps, restart depth, hypothesis preservation, agenda
    breadth, and doctrine strictness according to the classified duration rung.

    Scaling table (all ms_cap = 6, milestone identity preserved):
        micro_break    : restart_depth=1, hyp_pres=0.95, breadth=5, strict=0.90
        short_gap      : restart_depth=2, hyp_pres=0.90, breadth=5, strict=0.85
        week_gap       : restart_depth=3, hyp_pres=0.80, breadth=4, strict=0.75
        long_gap       : restart_depth=4, hyp_pres=0.70, breadth=4, strict=0.65
        semester_gap   : restart_depth=5, hyp_pres=0.55, breadth=3, strict=0.55
        seasonal_hiatus: restart_depth=6, hyp_pres=0.40, breadth=3, strict=0.45

    scaling_delta = strictness - BASE_STRICTNESS (week_gap baseline = 0.75)

    Biology tokens excluded. deque(maxlen=96).
    """

    BASE_STRICTNESS = 0.75
    _SCALE_TABLE    = {
        'micro_break':    {'ms_cap': 6, 'restart_depth': 1, 'hyp_preservation': 0.95,
                           'agenda_breadth': 5, 'strictness': 0.90},
        'short_gap':      {'ms_cap': 6, 'restart_depth': 2, 'hyp_preservation': 0.90,
                           'agenda_breadth': 5, 'strictness': 0.85},
        'week_gap':       {'ms_cap': 6, 'restart_depth': 3, 'hyp_preservation': 0.80,
                           'agenda_breadth': 4, 'strictness': 0.75},
        'long_gap':       {'ms_cap': 6, 'restart_depth': 4, 'hyp_preservation': 0.70,
                           'agenda_breadth': 4, 'strictness': 0.65},
        'semester_gap':   {'ms_cap': 6, 'restart_depth': 5, 'hyp_preservation': 0.55,
                           'agenda_breadth': 3, 'strictness': 0.55},
        'seasonal_hiatus':{'ms_cap': 6, 'restart_depth': 6, 'hyp_preservation': 0.40,
                           'agenda_breadth': 3, 'strictness': 0.45},
    }
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                  = maxlen
        self._history                 = deque(maxlen=maxlen)
        self.scaled_continuity_profile= {}
        self.scaling_delta            = 0.0
        self.scaling_reason           = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               silence_duration_classifier,
               institutional_continuity_kernel):
        if _IKG.sleeping:
            return

        dur_class = getattr(silence_duration_classifier,      'duration_class',  'week_gap')
        profile   = dict(self._SCALE_TABLE.get(dur_class, self._SCALE_TABLE['week_gap']))

        self.scaled_continuity_profile = profile
        self.scaling_delta = round(profile['strictness'] - self.BASE_STRICTNESS, 4)
        self.scaling_reason = 'class=%s strict=%.2f delta=%.4f' % (
            dur_class, profile['strictness'], self.scaling_delta)

        self._history.append({
            'tick':          tick,
            'duration_class':dur_class,
            'scaling_delta': self.scaling_delta,
            'scaling_reason':self.scaling_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class AdaptiveRestartAggression:
    """
    Chooses the restart mode and aggression score from the classified
    duration rung. Rule 2 (frozen mapping):

        1-3   (gentle)    -> gentle_restart,           score=0.15/0.25
        7-14  (standard)  -> normal_restart,           score=0.50/0.60
        30-90 (aggressive)-> blocker_first_aggressive, score=0.80/0.90

    aggression_class: 'gentle' | 'standard' | 'aggressive'

    Biology tokens excluded. deque(maxlen=96).
    """

    # Rule 2 frozen mapping: (restart_mode, aggression_score)
    _AGGRESSION_MAP = {
        'micro_break':    ('gentle_restart',           0.15),
        'short_gap':      ('gentle_restart',           0.25),
        'week_gap':       ('normal_restart',           0.50),
        'long_gap':       ('normal_restart',           0.60),
        'semester_gap':   ('blocker_first_aggressive', 0.80),
        'seasonal_hiatus':('blocker_first_aggressive', 0.90),
    }
    _AGGRESSION_CLASS = {
        'micro_break':    'gentle',
        'short_gap':      'gentle',
        'week_gap':       'standard',
        'long_gap':       'standard',
        'semester_gap':   'aggressive',
        'seasonal_hiatus':'aggressive',
    }
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.restart_mode      = 'normal_restart'
        self.aggression_score  = 0.50
        self.aggression_class  = 'standard'
