        dur_conf    = getattr(silence_duration_classifier,       'duration_confidence',  0.5)
        profile     = getattr(temporal_continuity_scaler,        'scaled_continuity_profile', {})
        kernel_conf = getattr(institutional_continuity_kernel,   'kernel_confidence',    0.5)

        breadth = int(profile.get('agenda_breadth', 4))
        depth   = int(profile.get('restart_depth', 3))

        self.regulated_agenda = {
            'agenda_width':     breadth,
            'sweep_depth':      min(self.SWEEP_DEPTH_CAP, depth + 1),
            'experiment_queue': min(self.QUEUE_CAP, breadth),
            'roadmap_breadth':  min(self.QUEUE_CAP, breadth),
            'duration_class':   dur_class,
        }
        self.breadth_confidence = round(self._clamp(
            dur_conf * 0.60 + kernel_conf * 0.40
        ), 4)
        self.breadth_reason = 'class=%s width=%d depth=%d conf=%.4f' % (
            dur_class, breadth, depth, self.breadth_confidence)

        self._history.append({
            'tick':               tick,
            'duration_class':     dur_class,
            'breadth_confidence': self.breadth_confidence,
            'breadth_reason':     self.breadth_reason,
        })

