class ProjectPivotClassifier:
    """
    Classifies the type of project pivot from the frozen canonical ladder.

    Rule 1 (frozen pivot ladder):
        ["rename", "scope_expand", "scope_split", "domain_shift",
         "productization", "research_fork"]

    pivot_confidence = clamp(
        kernel_confidence * 0.55 + duration_confidence * 0.45
    )

    Pivot is inferred from doctrine kernel: if agenda_breadth_law < 3 -> scope_split;
    if conflict_class == 'conditional_only' -> domain_shift; default -> rename.

    Biology tokens excluded. deque(maxlen=96).
    """

    PIVOT_LADDER = ["rename", "scope_expand", "scope_split",
                    "domain_shift", "productization", "research_fork"]
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen         = maxlen
        self._history        = deque(maxlen=maxlen)
        self.pivot_type      = 'rename'
        self.pivot_confidence= 0.0
        self.pivot_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               universal_hiatus_policy_kernel,
               silence_duration_classifier):
        if _IKG.sleeping:
            return

        kernel      = getattr(universal_hiatus_policy_kernel, 'universal_hiatus_kernel', {})
        kernel_conf = getattr(universal_hiatus_policy_kernel, 'kernel_confidence',       0.5)
        dur_conf    = getattr(silence_duration_classifier,    'duration_confidence',     0.5)

        # Infer pivot type from kernel state
        breadth    = int(kernel.get('agenda_breadth_law', 4))
        agg_class  = str(kernel.get('current_aggression', 'standard'))
        conf_class = str(kernel.get('conflict_class', 'global'))

        if conf_class == 'conditional_only':
            pivot = 'domain_shift'
        elif agg_class == 'aggressive':
            pivot = 'research_fork'
        elif breadth <= 3:
            pivot = 'scope_split'
        elif breadth >= 5:
            pivot = 'scope_expand'
        else:
            pivot = 'rename'

        self.pivot_type       = pivot
        self.pivot_confidence = round(self._clamp(
            kernel_conf * 0.55 + dur_conf * 0.45
        ), 4)
        self.pivot_reason = 'pivot=%s conf=%.4f breadth=%d agg=%s' % (
            pivot, self.pivot_confidence, breadth, agg_class)

        self._history.append({
            'tick':             tick,
            'pivot_type':       self.pivot_type,
            'pivot_confidence': self.pivot_confidence,
            'pivot_reason':     self.pivot_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class DoctrineTransferMapper:
    """
    Maps silence doctrine, milestone caps, restart aggression, retention
    curves, and hypothesis half-life across a project pivot.

    Rule 2 (frozen floor): doctrine_transfer >= 0.60 always.

    transfer_confidence = clamp(
        pivot_confidence * 0.40
        + kernel_confidence * 0.35
        + (1 - conflict_penalty) * 0.25
    )
    conflict_penalty = 0.20 if pivot_type in {'domain_shift','research_fork'} else 0.05

    transferred_doctrine carries all universal_hiatus_kernel fields plus
    pivot_type and transfer_confidence.

    Biology tokens excluded. deque(maxlen=96).
    """

    DOCTRINE_TRANSFER_FLOOR = 0.60
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.transferred_doctrine= {}
        self.transfer_confidence = 0.0
        self.mapping_reason      = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               project_pivot_classifier,
               universal_hiatus_policy_kernel,
               institutional_continuity_kernel):
        if _IKG.sleeping:
            return

        pivot_type  = getattr(project_pivot_classifier,      'pivot_type',       'rename')
        pivot_conf  = getattr(project_pivot_classifier,      'pivot_confidence',  0.5)
        kernel      = getattr(universal_hiatus_policy_kernel,'universal_hiatus_kernel', {})
        kernel_conf = getattr(universal_hiatus_policy_kernel,'kernel_confidence',  0.5)

        conflict_penalty = 0.20 if pivot_type in ('domain_shift', 'research_fork') else 0.05
        raw_conf = self._clamp(
            pivot_conf * 0.40 + kernel_conf * 0.35 + (1.0 - conflict_penalty) * 0.25
        )
        # Rule 2: floor 0.60
        self.transfer_confidence = round(max(self.DOCTRINE_TRANSFER_FLOOR, raw_conf), 4)

        self.transferred_doctrine = dict(kernel)
        self.transferred_doctrine['pivot_type']          = pivot_type
        self.transferred_doctrine['transfer_confidence'] = self.transfer_confidence

        self.mapping_reason = 'pivot=%s conf=%.4f floor=%.2f' % (
            pivot_type, self.transfer_confidence, self.DOCTRINE_TRANSFER_FLOOR)

        self._history.append({
            'tick':               tick,
            'pivot_type':         pivot_type,
            'transfer_confidence':self.transfer_confidence,
            'mapping_reason':     self.mapping_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


