class MetaProjectContinuityKernel:
    """
    Synthesizes all Phase J outputs into a single cross-project continuity
    doctrine. Rule 5 (uniqueness): exactly one meta_project_kernel per tick.

    Stores: pivot_ladder (Rule 1 frozen), doctrine_transfer_floor (Rule 2),
    milestone_translation_priors (Rule 3), hypothesis_migration_law (Rule 4),
    lineage_preservation_chain, meta_project_rationale.

    kernel_confidence = clamp(
        lineage_strength * 0.30 + port_confidence * 0.25
        + transfer_confidence * 0.25 + translation_integrity * 0.20
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    # Rule 1 (frozen)
    PIVOT_LADDER            = ["rename", "scope_expand", "scope_split",
                               "domain_shift", "productization", "research_fork"]
    # Rule 2 (frozen)
    DOCTRINE_TRANSFER_FLOOR = 0.60
    # Rule 4 (frozen)
    MIGRATION_BONUS         = 0.15
    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.meta_project_kernel  = {}
        self.kernel_confidence    = 0.0
        self.kernel_reason        = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               research_lineage_preserver,
               identity_thread_porter,
               doctrine_transfer_mapper,
               cross_domain_milestone_translator,
               project_pivot_classifier,
               agenda_fork_resolver,
               hypothesis_migration_bridge):
        if _IKG.sleeping:
            return

        lineage_st  = getattr(research_lineage_preserver,        'lineage_strength',     0.5)
        port_conf   = getattr(identity_thread_porter,            'port_confidence',      0.5)
        transfer_c  = getattr(doctrine_transfer_mapper,          'transfer_confidence',  0.5)
        integrity   = getattr(cross_domain_milestone_translator, 'translation_integrity',0.5)
        pivot_type  = getattr(project_pivot_classifier,          'pivot_type',           'rename')
        fork_score  = getattr(agenda_fork_resolver,              'fork_conflict_score',  0.3)
        migration_p = getattr(hypothesis_migration_bridge,       'migration_pressure',   0.5)
        lineage_ch  = getattr(research_lineage_preserver,        'lineage_chain',        [])

        self.kernel_confidence = round(self._clamp(
            lineage_st * 0.30 + port_conf * 0.25
            + transfer_c * 0.25 + integrity * 0.20
        ), 4)

        self.meta_project_kernel = {
            # Rule 1: frozen pivot ladder
            'pivot_ladder':               self.PIVOT_LADDER,
            # Rule 2: doctrine transfer floor
            'doctrine_transfer_floor':    self.DOCTRINE_TRANSFER_FLOOR,
            # Rule 3: milestone translation priors
            'milestone_translation_priors': {
                'semantic_overlap_floor':     0.50,
                'tentative_flag':             'translation_tentative',
                'translation_integrity':      round(integrity, 4),
            },
            # Rule 4: hypothesis migration law
            'hypothesis_migration_law':   {
                'migration_bonus':            self.MIGRATION_BONUS,
                'tagged_criteria':            ['eeil_tag', 'pub_coup', 'crit_dep'],
                'migration_pressure':         round(migration_p, 4),
            },
            # Lineage preservation chain
            'lineage_preservation_chain': [l['id'] for l in lineage_ch],
            # Current pivot state
            'current_pivot':              pivot_type,
            'fork_conflict_score':        round(fork_score, 4),
            # Meta-project rationale
            'meta_project_rationale':     'cross_domain continuity doctrine v28J',
        }

        self.kernel_reason = 'conf=%.4f pivot=%s fork=%.4f lineage=%.4f' % (
            self.kernel_confidence, pivot_type, fork_score, lineage_st)

        self._history.append({
            'tick':              tick,
            'kernel_confidence': self.kernel_confidence,
            'pivot_type':        pivot_type,
            'fork_conflict':     fork_score,
            'lineage_strength':  lineage_st,
            'kernel_reason':     self.kernel_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

