class DeliberationWorkspace:
    """Newell & Simon 1972 (problem space); Baars 1988 (global workspace).
    Holds live premises, milestone facts, blockers, constraints, active
    hypotheses, and pivot implications for the deliberative reasoning layer.
    Biology tokens excluded. deque(maxlen=96)."""

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen             = maxlen
        self._history            = deque(maxlen=maxlen)
        self.workspace_state     = {}
        self.workspace_coherence = 0.0
        self.workspace_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               meta_project_continuity_kernel,
               universal_hiatus_policy_kernel,
               institutional_continuity_kernel):
        if _IKG.sleeping:
            return

        pivot_type  = getattr(meta_project_continuity_kernel, 'meta_project_kernel', {}).get('current_pivot', 'rename')
        lineage_st  = getattr(meta_project_continuity_kernel, 'kernel_confidence',   0.5)
        transfer_c  = lineage_st
        ret_floor   = getattr(universal_hiatus_policy_kernel, 'kernel_confidence',   0.5)
        dur_class   = 'week_gap'
        if getattr(universal_hiatus_policy_kernel, '_history', None):
            rec = list(universal_hiatus_policy_kernel._history)[-1]
            dur_class = rec.get('duration_class', 'week_gap')
        ick_conf    = getattr(institutional_continuity_kernel, 'kernel_confidence',  0.5)
        agenda_b    = getattr(institutional_continuity_kernel, 'continuity_kernel',  {}).get('agenda_sparse_prior', 4)
        n_blockers  = 1 if ick_conf < 0.50 else 0

        self.workspace_state = {
            'premises':           {'pivot_type': pivot_type, 'lineage_strength': lineage_st, 'transfer_confidence': transfer_c},
            'milestone_facts':    {'retention_floor': ret_floor, 'duration_class': dur_class},
            'blockers':           {'n_blockers': n_blockers, 'agenda_breadth': agenda_b},
            'constraints':        {'milestone_cap': 6, 'restart_cap': 5},
            'active_hypotheses':  {'count': 3, 'tagged': 1},
            'pivot_implications': {'pivot_type': pivot_type, 'transfer_confidence': transfer_c},
        }

        signal_mean = self._clamp((lineage_st + ret_floor + transfer_c) / 3.0)
        self.workspace_coherence = self._clamp(signal_mean * 0.60 + (1.0 - n_blockers * 0.10) * 0.40)
        self.workspace_reason    = 'coh=%.4f pivot=%s dur=%s' % (
            self.workspace_coherence, pivot_type, dur_class)

        self._history.append({
            'tick':               tick,
            'workspace_coherence': self.workspace_coherence,
            'pivot_type':          pivot_type,
            'duration_class':      dur_class,
            'workspace_reason':    self.workspace_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


