class ReasoningParagraphComposer:
    """Levelt 1989 (speaking); Kintsch 1998 (text comprehension).
    Converts explanation packets into ordered reasoning paragraphs with
    premise -> inference -> conclusion flow.
    PARAGRAPH_CAP = 6 (Rule 1 frozen). Biology tokens excluded. deque(maxlen=96)."""

    PARAGRAPH_CAP = 6  # Rule 1 frozen

    _PARA_TEMPLATES = [
        {'id': 'premise_anchor',       'flow': 'premise',    'base_conf': 0.90},
        {'id': 'inference_step_1',     'flow': 'inference',  'base_conf': 0.85},
        {'id': 'inference_step_2',     'flow': 'inference',  'base_conf': 0.80},
        {'id': 'contradiction_note',   'flow': 'inference',  'base_conf': 0.75},
        {'id': 'horizon_integration',  'flow': 'inference',  'base_conf': 0.70},
        {'id': 'conclusion_synthesis', 'flow': 'conclusion', 'base_conf': 0.85},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.reasoning_paragraphs = []
        self.paragraph_coherence  = 0.0
        self.composition_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, explanation_synthesis_engine, active_cognition_kernel):
        if _IKG.sleeping:
            return

        clarity    = getattr(explanation_synthesis_engine, 'explanation_clarity',   0.5)
        kernel_conf= getattr(active_cognition_kernel,      'kernel_confidence',     0.5)
        ese_packet = getattr(explanation_synthesis_engine, 'explanation_packet',    {})
        conflict_r = ese_packet.get('conflict_routed', False)

        base = self._clamp((clarity + kernel_conf) / 2.0)
        paras = []
        for i, tmpl in enumerate(self._PARA_TEMPLATES[:self.PARAGRAPH_CAP]):
            adj = self._clamp(tmpl['base_conf'] * base)
            paras.append({
                'index':      i + 1,
                'para_id':    tmpl['id'],
                'flow':       tmpl['flow'],
                'para_conf':  round(adj, 4),
                'contradiction_note': (tmpl['flow'] == 'inference' and conflict_r and i == 3),
            })

        self.reasoning_paragraphs = paras
        self.paragraph_coherence  = self._clamp(
            sum(p['para_conf'] for p in paras) / max(1, len(paras))
        )
        self.composition_reason = 'paras=%d coh=%.4f conflict_routed=%s' % (
            len(paras), self.paragraph_coherence, conflict_r)

        self._history.append({
            'tick':               tick,
            'n_paragraphs':       len(paras),
            'paragraph_coherence':self.paragraph_coherence,
            'composition_reason': self.composition_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class InstructionGroundingBridge:
    """Grice 1975 (cooperative principle); Austin 1962 (speech acts).
    Binds output to explicit project goals. Rule 2: tasks touching
    project_task, code_edit, milestone_blocker, experiment_launch,
    monograph_update must route through this bridge before composition.
    GROUNDING_TAGS frozen. Biology tokens excluded. deque(maxlen=96)."""

    GROUNDING_TAGS = frozenset({
        'project_task', 'code_edit', 'milestone_blocker',
        'experiment_launch', 'monograph_update',
    })

    _TASK_SEEDS = [
        {'id': 'project_task',       'base_weight': 0.90},
        {'id': 'code_edit',          'base_weight': 0.85},
        {'id': 'milestone_blocker',  'base_weight': 0.80},
        {'id': 'experiment_launch',  'base_weight': 0.75},
        {'id': 'monograph_update',   'base_weight': 0.70},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                 = maxlen
        self._history                = deque(maxlen=maxlen)
        self.grounded_instruction_state = {}
        self.grounding_confidence    = 0.0
        self.grounding_reason        = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, active_cognition_kernel,
               reasoning_paragraph_composer,
               meta_project_continuity_kernel):
        if _IKG.sleeping:
            return

        kernel_conf = getattr(active_cognition_kernel,         'kernel_confidence',   0.5)
        para_coh    = getattr(reasoning_paragraph_composer,    'paragraph_coherence', 0.5)
        pivot_type  = getattr(meta_project_continuity_kernel,  'meta_project_kernel',{}).get('current_pivot','rename')
        mpk_conf    = getattr(meta_project_continuity_kernel,  'kernel_confidence',   0.5)

        grounded_tasks = []
        for seed in self._TASK_SEEDS:
            gconf = self._clamp(seed['base_weight'] * kernel_conf * 0.60 + para_coh * 0.40)
            grounded_tasks.append({
                'task_id':      seed['id'],
                'is_grounded':  True,
                'grounding_conf': round(gconf, 4),
                'pivot_context': pivot_type,
            })

        self.grounding_confidence = self._clamp(
            kernel_conf * 0.40 + para_coh * 0.35 + mpk_conf * 0.25
        )
        self.grounded_instruction_state = {
            'grounded_tasks':     grounded_tasks,
            'pivot_type':         pivot_type,
            'active_tags':        list(self.GROUNDING_TAGS),
            'grounding_confidence': round(self.grounding_confidence, 4),
        }
        self.grounding_reason = 'conf=%.4f pivot=%s tasks=%d' % (
            self.grounding_confidence, pivot_type, len(grounded_tasks))

        self._history.append({
            'tick':               tick,
            'grounding_confidence': self.grounding_confidence,
            'pivot_type':          pivot_type,
            'n_grounded_tasks':    len(grounded_tasks),
            'grounding_reason':    self.grounding_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class DialogueTurnContinuity:
    """Grosz & Sidner 1986 (discourse structure); Clark & Schaefer 1989 (grounding).
    Maintains prior turn anchors, task thread continuity, unresolved intent, and
    blocker carry-forward. TURN_FLOOR = 2 (Rule 3 frozen): at least 2 prior turns
    must remain represented. Biology tokens excluded. deque(maxlen=96)."""

    TURN_FLOOR = 2  # Rule 3 frozen

    _TURN_SEEDS = [
        {'id': 'active_task_anchor',      'base_continuity': 0.90},
        {'id': 'prior_milestone_context', 'base_continuity': 0.85},
        {'id': 'unresolved_intent_carry', 'base_continuity': 0.75},
        {'id': 'blocker_thread',          'base_continuity': 0.70},
        {'id': 'hypothesis_carry_forward','base_continuity': 0.65},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.dialogue_state = {}
        self.turn_continuity= 0.0
        self.dialogue_reason= 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, instruction_grounding_bridge,
               active_cognition_kernel):
        if _IKG.sleeping:
            return

        ground_conf = getattr(instruction_grounding_bridge, 'grounding_confidence', 0.5)
        kernel_conf = getattr(active_cognition_kernel,      'kernel_confidence',    0.5)

        base = self._clamp((ground_conf + kernel_conf) / 2.0)
        turns = []
        for seed in self._TURN_SEEDS:
            tc = self._clamp(seed['base_continuity'] * base)
            turns.append({
                'turn_id':          seed['id'],
                'continuity_score': round(tc, 4),
                'active':           True,
            })

        # enforce floor: always keep at least TURN_FLOOR turns active
        n_active = sum(1 for t in turns if t['active'])
        if n_active < self.TURN_FLOOR:
            for t in turns:
                if not t['active']:
                    t['active'] = True
                    n_active += 1
                    if n_active >= self.TURN_FLOOR:
                        break

        self.dialogue_state = {
            'turns':                turns,
            'n_active_turns':       n_active,
            'turn_floor_satisfied': n_active >= self.TURN_FLOOR,
        }
        self.turn_continuity = self._clamp(
            sum(t['continuity_score'] for t in turns) / max(1, len(turns))
        )
        self.dialogue_reason = 'active=%d floor=%d continuity=%.4f' % (
            n_active, self.TURN_FLOOR, self.turn_continuity)

        self._history.append({
            'tick':              tick,
            'n_active_turns':    n_active,
            'turn_continuity':   self.turn_continuity,
            'floor_satisfied':   n_active >= self.TURN_FLOOR,
            'dialogue_reason':   self.dialogue_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class CodeRationaleNarrator:
    """Sridhara et al. 2010 (code summarization); McBurney & McMillan 2014 (narratives).
    Converts patch logic, constraint reconciliations, branch pruning choices, and
    tradeoff decisions into natural code rationale prose.
    CLARITY_BONUS = +0.15 (Rule 4 frozen) for code_rationale packets.
    Biology tokens excluded. deque(maxlen=96)."""

    CLARITY_BONUS = 0.15  # Rule 4 frozen
    CLARITY_BONUS_TAGS = frozenset({'code_rationale', 'eeil_explanation',
                                     'experimental_logic', 'paper_claim'})

    _RATIONALE_SEEDS = [
        {'id': 'patch_logic',         'tags': frozenset({'code_rationale'}),                 'base': 0.85},
        {'id': 'constraint_choice',   'tags': frozenset({'code_rationale'}),                 'base': 0.80},
        {'id': 'branch_decision',     'tags': frozenset({'code_rationale'}),                 'base': 0.75},
        {'id': 'tradeoff_narration',  'tags': frozenset({'eeil_explanation'}),               'base': 0.80},
        {'id': 'experiment_logic',    'tags': frozenset({'experimental_logic'}),             'base': 0.75},
        {'id': 'claim_rationale',     'tags': frozenset({'paper_claim'}),                    'base': 0.70},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.code_rationale = []
        self.rationale_clarity = 0.0
        self.rationale_reason  = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, instruction_grounding_bridge,
               constraint_reconciliation_solver,
               hypothesis_branch_pruner):
        if _IKG.sleeping:
            return

        ground_conf = getattr(instruction_grounding_bridge,    'grounding_confidence', 0.5)
        conflict_sc = getattr(constraint_reconciliation_solver,'conflict_score',        0.1)
        prune_conf  = getattr(hypothesis_branch_pruner,        'prune_confidence',      0.5)

        base = self._clamp((ground_conf + prune_conf) / 2.0)
        rationales = []
        for seed in self._RATIONALE_SEEDS:
            bonus = self.CLARITY_BONUS if (seed['tags'] & self.CLARITY_BONUS_TAGS) else 0.0
            clarity = self._clamp(seed['base'] * base + bonus)
            rationales.append({
                'id':            seed['id'],
                'bonus_applied': bonus > 0.0,
                'clarity':       round(clarity, 4),
                'conflict_noted': conflict_sc >= 0.50,
            })

        self.code_rationale   = rationales
        self.rationale_clarity = self._clamp(
            sum(r['clarity'] for r in rationales) / max(1, len(rationales))
        )
        n_bonused = sum(1 for r in rationales if r['bonus_applied'])
        self.rationale_reason = 'items=%d bonused=%d clarity=%.4f' % (
            len(rationales), n_bonused, self.rationale_clarity)

        self._history.append({
            'tick':             tick,
            'n_rationales':     len(rationales),
            'n_bonused':        n_bonused,
            'rationale_clarity':self.rationale_clarity,
            'rationale_reason': self.rationale_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


