class LongFormResponsePlanner:
    """Reiter & Dale 2000 (NLG pipeline); Mann & Thompson 1988 (RST).
    Constructs coherent long-form responses integrating prior turns, active
    cognition kernel, project milestones, code rationale, and scientific
    explanation. RESPONSE_PARA_CAP = 6 (Rule 1 frozen).
    Biology tokens excluded. deque(maxlen=96)."""

    RESPONSE_PARA_CAP = 6  # Rule 1 frozen
    TURN_FLOOR        = 2  # Rule 3 mirror

    _PLAN_SECTIONS = [
        {'id': 'task_grounding',       'weight': 0.20},
        {'id': 'prior_context',        'weight': 0.15},
        {'id': 'active_reasoning',     'weight': 0.20},
        {'id': 'code_rationale_block', 'weight': 0.15},
        {'id': 'scientific_block',     'weight': 0.15},
        {'id': 'conclusion_synthesis', 'weight': 0.15},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.response_plan  = {}
        self.plan_confidence= 0.0
        self.plan_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, dialogue_turn_continuity,
               active_cognition_kernel,
               code_rationale_narrator,
               scientific_explanation_formatter,
               instruction_grounding_bridge):
        if _IKG.sleeping:
            return

        turn_cont   = getattr(dialogue_turn_continuity,         'turn_continuity',     0.5)
        kernel_conf = getattr(active_cognition_kernel,          'kernel_confidence',   0.5)
        rat_clarity = getattr(code_rationale_narrator,          'rationale_clarity',   0.5)
        sci_clarity = getattr(scientific_explanation_formatter, 'scientific_clarity',  0.5)
        ground_conf = getattr(instruction_grounding_bridge,     'grounding_confidence',0.5)
        n_turns     = getattr(dialogue_turn_continuity,         'dialogue_state', {}).get('n_active_turns', 2)

        sections = []
        for sec in self._PLAN_SECTIONS[:self.RESPONSE_PARA_CAP]:
            sec_conf = self._clamp(
                kernel_conf * 0.30 + turn_cont * 0.20 +
                ground_conf * 0.20 + rat_clarity * 0.15 +
                sci_clarity * 0.15
            )
            sections.append({
                'section_id':   sec['id'],
                'weight':       sec['weight'],
                'section_conf': round(sec_conf, 4),
            })

        self.response_plan = {
            'sections':           sections,
            'n_sections':         len(sections),
            'prior_turns_repr':   max(self.TURN_FLOOR, n_turns),
            'para_cap':           self.RESPONSE_PARA_CAP,
            'turn_floor_held':    n_turns >= self.TURN_FLOOR,
        }
        self.plan_confidence = self._clamp(
            sum(s['section_conf'] * s['weight'] for s in sections)
        )
        self.plan_reason = 'sections=%d conf=%.4f turns=%d floor=%d' % (
            len(sections), self.plan_confidence, n_turns, self.TURN_FLOOR)

        self._history.append({
            'tick':            tick,
            'n_sections':      len(sections),
            'plan_confidence': self.plan_confidence,
            'n_turns':         n_turns,
            'plan_reason':     self.plan_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class NarrativeCoherenceRegulator:
    """Hobbs 1985 (coherence relations); Grosz & Sidner 1986 (attentional state).
    Ensures no paragraph contradictions, stable tone, coherent arc, preserved
    task grounding, and active kernel alignment.
    Biology tokens excluded. deque(maxlen=96)."""

    COHERENCE_FLOOR = 0.50

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.regulated_response = {}
        self.coherence_score    = 0.0
        self.regulation_reason  = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, long_form_response_planner,
               reasoning_paragraph_composer,
               instruction_grounding_bridge,
               active_cognition_kernel):
        if _IKG.sleeping:
            return

        plan_conf   = getattr(long_form_response_planner,   'plan_confidence',     0.5)
        para_coh    = getattr(reasoning_paragraph_composer, 'paragraph_coherence', 0.5)
        ground_conf = getattr(instruction_grounding_bridge, 'grounding_confidence',0.5)
        kernel_conf = getattr(active_cognition_kernel,      'kernel_confidence',   0.5)
        plan        = getattr(long_form_response_planner,   'response_plan',       {})

        self.coherence_score = self._clamp(
            plan_conf   * 0.30 +
            para_coh    * 0.25 +
            ground_conf * 0.25 +
            kernel_conf * 0.20
        )
        contradiction_free = self.coherence_score >= self.COHERENCE_FLOOR
        tone_stable        = para_coh >= 0.40
        arc_coherent       = plan_conf >= 0.40

        self.regulated_response = {
            'coherence_score':      round(self.coherence_score, 4),
            'contradiction_free':   contradiction_free,
            'tone_stable':          tone_stable,
            'arc_coherent':         arc_coherent,
            'task_grounded':        ground_conf >= 0.40,
            'kernel_aligned':       kernel_conf >= 0.40,
            'n_sections':           plan.get('n_sections', 6),
            'regulation_mode':      'pass' if contradiction_free else 'flag_contradiction',
        }
        self.regulation_reason = 'coh=%.4f mode=%s tone=%s arc=%s' % (
            self.coherence_score,
            self.regulated_response['regulation_mode'],
            tone_stable, arc_coherent)

        self._history.append({
            'tick':              tick,
            'coherence_score':   self.coherence_score,
            'regulation_mode':   self.regulated_response['regulation_mode'],
            'regulation_reason': self.regulation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class LanguageCognitionKernel:
    """Levelt 1989 (speaking); Dehaene 2014 (global workspace, language).
    Selects single dominant natural-language reasoning state per tick (Rule 5).
    Aggregates response plan, regulated narrative, grounded task, dialogue
    continuity, and active cognition into one language mind state.

    kernel_confidence = clamp(
        plan_confidence   * 0.25 + coherence_score   * 0.25
        + grounding_conf  * 0.20 + turn_continuity   * 0.15
        + kernel_conf_ack * 0.15
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    # Mandatory priors (all frozen)
    _PRIORS = {
        'paragraph_cap':     6,    # Rule 1
        'grounding_tags':    ('project_task','code_edit','milestone_blocker',
                              'experiment_launch','monograph_update'),  # Rule 2
        'turn_floor':        2,    # Rule 3
        'clarity_bonus':     0.15, # Rule 4
        'kernel_uniqueness': 'one_dominant_language_cognition_per_tick',  # Rule 5
    }

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                 = maxlen
        self._history                = deque(maxlen=maxlen)
        self.language_cognition_kernel = {}
        self.kernel_confidence       = 0.0
        self.kernel_reason           = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               long_form_response_planner,
               narrative_coherence_regulator,
               instruction_grounding_bridge,
               dialogue_turn_continuity,
               active_cognition_kernel,
               code_rationale_narrator,
               scientific_explanation_formatter):
        if _IKG.sleeping:
            return

        plan_conf   = getattr(long_form_response_planner,        'plan_confidence',     0.5)
        coh_score   = getattr(narrative_coherence_regulator,     'coherence_score',     0.5)
        ground_conf = getattr(instruction_grounding_bridge,      'grounding_confidence',0.5)
        turn_cont   = getattr(dialogue_turn_continuity,          'turn_continuity',     0.5)
        kernel_conf = getattr(active_cognition_kernel,           'kernel_confidence',   0.5)
        rat_clarity = getattr(code_rationale_narrator,           'rationale_clarity',   0.5)
        sci_clarity = getattr(scientific_explanation_formatter,  'scientific_clarity',  0.5)
        n_turns     = getattr(dialogue_turn_continuity, 'dialogue_state', {}).get('n_active_turns', 2)
        n_sections  = getattr(long_form_response_planner,'response_plan',{}).get('n_sections', 6)
        reg_mode    = getattr(narrative_coherence_regulator, 'regulated_response',{}).get('regulation_mode','pass')

        self.kernel_confidence = round(self._clamp(
            plan_conf   * 0.25 +
            coh_score   * 0.25 +
            ground_conf * 0.20 +
            turn_cont   * 0.15 +
            kernel_conf * 0.15
        ), 4)

        self.language_cognition_kernel = {
            # Rule 5 sentinel
            'kernel_uniqueness':       'one_dominant_language_cognition_per_tick',
            # live state
            'response_plan_sections':  n_sections,
            'regulated_narrative_mode':reg_mode,
            'grounded_task_conf':      round(ground_conf, 4),
            'prior_dialogue_turns':    n_turns,
            'active_cognition_conf':   round(kernel_conf,  4),
            'language_rationale':      self.kernel_reason,
            'code_rationale_clarity':  round(rat_clarity,  4),
            'scientific_clarity':      round(sci_clarity,  4),
            # mandatory priors
            'priors':                  self._PRIORS,
        }
        self.kernel_reason = 'conf=%.4f plan=%.4f coh=%.4f turns=%d mode=%s' % (
            self.kernel_confidence, plan_conf, coh_score, n_turns, reg_mode)
        self.language_cognition_kernel['language_rationale'] = self.kernel_reason

        self._history.append({
            'tick':              tick,
            'kernel_confidence': self.kernel_confidence,
            'n_sections':        n_sections,
            'n_turns':           n_turns,
            'regulation_mode':   reg_mode,
            'kernel_reason':     self.kernel_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 28 PHASE M: Interactive Conversational Agency Superphase
# Clark & Schaefer 1989 (grounding acts); Traum 1994 (dialogue moves);
# Schegloff 2007 (conversation analysis); Allen et al. 2001 (mixed initiative);
# Bohus & Rudnicky 2009 (RavenClaw); Grosz & Sidner 1986 (discourse structure)
# ===========================================================================

class IntentEvolutionTracker:
    """Clark & Schaefer 1989 (grounding); Traum 1994 (dialogue moves).
    Tracks original goal, revised goals, emergent task shifts, clarified
    blockers, and changed priorities across multi-turn interaction.
    Biology tokens excluded. deque(maxlen=96)."""

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _INTENT_SEEDS = [
        {'id': 'original_goal',      'base_stability': 0.90},
        {'id': 'revised_goal_1',     'base_stability': 0.80},
        {'id': 'emergent_task_shift','base_stability': 0.70},
        {'id': 'clarified_blocker',  'base_stability': 0.75},
        {'id': 'changed_priority',   'base_stability': 0.65},
    ]

    def __init__(self, maxlen=96):
        self._maxlen      = maxlen
        self._history     = deque(maxlen=maxlen)
        self.intent_state = {}
        self.intent_drift = 0.0
        self.intent_reason= 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, language_cognition_kernel, active_cognition_kernel):
        if _IKG.sleeping:
            return

        lang_conf   = getattr(language_cognition_kernel, 'kernel_confidence',       0.5)
        ack_conf    = getattr(active_cognition_kernel,   'kernel_confidence',       0.5)
        plan_pivot  = getattr(language_cognition_kernel, 'language_cognition_kernel',{}).get('regulated_narrative_mode','pass')

        base = self._clamp((lang_conf + ack_conf) / 2.0)
        intents = []
        for seed in self._INTENT_SEEDS:
            stab = self._clamp(seed['base_stability'] * base)
            intents.append({'id': seed['id'], 'stability': round(stab, 4), 'active': True})

        initial_stab = intents[0]['stability']
        latest_stab  = intents[-1]['stability']
        self.intent_drift = self._clamp(initial_stab - latest_stab)
        self.intent_state = {
            'intents':         intents,
            'n_active':        len(intents),
            'intent_drift':    round(self.intent_drift, 4),
            'narrative_mode':  plan_pivot,
        }
        self.intent_reason = 'drift=%.4f n=%d mode=%s' % (
            self.intent_drift, len(intents), plan_pivot)

        self._history.append({
            'tick':          tick,
            'intent_drift':  self.intent_drift,
            'n_active':      len(intents),
            'intent_reason': self.intent_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ClarificationQuestionPlanner:
    """Bohus & Rudnicky 2009 (clarification strategies); Purver 2004 (reprise).
    Generates bounded clarification questions. CLARIFICATION_CAP = 3 (Rule 1 frozen).
    Rule 2: ambiguity_score >= 0.50 must route through this planner before
    response finalization. Biology tokens excluded. deque(maxlen=96)."""

    CLARIFICATION_CAP  = 3   # Rule 1 frozen
    AMBIGUITY_THRESHOLD= 0.50 # Rule 2 frozen

    _QUESTION_SEEDS = [
        {'id': 'blocker_clarification',      'type': 'blocker',    'priority': 1},
        {'id': 'constraint_clarification',   'type': 'constraint', 'priority': 2},
        {'id': 'pivot_clarification',        'type': 'pivot',      'priority': 3},
        {'id': 'code_request_clarification', 'type': 'code',       'priority': 4},
        {'id': 'milestone_conflict_clarify', 'type': 'milestone',  'priority': 5},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                  = maxlen
        self._history                 = deque(maxlen=maxlen)
        self.clarification_questions  = []
        self.clarification_confidence = 0.0
        self.clarification_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, intent_evolution_tracker,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        intent_drift = getattr(intent_evolution_tracker,  'intent_drift',     0.1)
        lang_conf    = getattr(language_cognition_kernel, 'kernel_confidence', 0.5)

        # ambiguity_score derived from intent_drift and inverse language conf
        ambiguity_score = self._clamp(intent_drift * 0.60 + (1.0 - lang_conf) * 0.40)
        routed = ambiguity_score >= self.AMBIGUITY_THRESHOLD

        # produce at most CLARIFICATION_CAP questions
        questions = []
        for seed in sorted(self._QUESTION_SEEDS, key=lambda s: s['priority']):
            if len(questions) >= self.CLARIFICATION_CAP:
                break
            q_conf = self._clamp(lang_conf * 0.50 + (1.0 - intent_drift) * 0.50)
            questions.append({
                'question_id':    seed['id'],
                'type':           seed['type'],
                'q_conf':         round(q_conf, 4),
                'routed_via_ambiguity': routed,
            })

        self.clarification_questions  = questions
        self.clarification_confidence = self._clamp(
            sum(q['q_conf'] for q in questions) / max(1, len(questions))
        )
        self.clarification_reason = 'n=%d ambig=%.4f routed=%s cap=%d' % (
            len(questions), ambiguity_score, routed, self.CLARIFICATION_CAP)

        self._history.append({
            'tick':                   tick,
            'n_questions':            len(questions),
            'ambiguity_score':        ambiguity_score,
            'clarification_routed':   routed,
            'clarification_confidence': self.clarification_confidence,
            'clarification_reason':   self.clarification_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class CollaborativeRevisionLoop:
    """Schegloff 2007 (sequence organization); Clark & Wilkes-Gibbs 1986 (referential repair).
    Maintains prior revisions, accepted changes, rejected edits, evolving
    constraints, and latest working plan. REVISION_FLOOR = 2 (Rule 3 frozen):
    at least 2 prior revisions must remain represented.
    Biology tokens excluded. deque(maxlen=96)."""

    REVISION_FLOOR = 2  # Rule 3 frozen

    _REVISION_SEEDS = [
        {'id': 'baseline_plan',     'status': 'accepted', 'base_coh': 0.85},
        {'id': 'revision_1',        'status': 'accepted', 'base_coh': 0.80},
        {'id': 'revision_2',        'status': 'accepted', 'base_coh': 0.75},
        {'id': 'tentative_edit_1',  'status': 'pending',  'base_coh': 0.65},
        {'id': 'constraint_update', 'status': 'accepted', 'base_coh': 0.70},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.revision_state    = {}
        self.revision_coherence= 0.0
        self.revision_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, intent_evolution_tracker,
               clarification_question_planner,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        intent_drift = getattr(intent_evolution_tracker,      'intent_drift',             0.1)
        clar_conf    = getattr(clarification_question_planner,'clarification_confidence', 0.5)
        lang_conf    = getattr(language_cognition_kernel,     'kernel_confidence',        0.5)

        base = self._clamp((clar_conf + lang_conf) / 2.0)
        revisions = []
        for seed in self._REVISION_SEEDS:
            coh = self._clamp(seed['base_coh'] * base)
            revisions.append({
                'id':      seed['id'],
                'status':  seed['status'],
                'coh':     round(coh, 4),
            })

        n_accepted = sum(1 for r in revisions if r['status'] == 'accepted')
        # enforce revision floor
        if n_accepted < self.REVISION_FLOOR:
            for r in revisions:
                if r['status'] != 'accepted':
                    r['status'] = 'accepted'
                    n_accepted += 1
                    if n_accepted >= self.REVISION_FLOOR:
                        break

        self.revision_state = {
            'revisions':       revisions,
            'n_accepted':      n_accepted,
            'n_pending':       sum(1 for r in revisions if r['status'] == 'pending'),
            'floor_satisfied': n_accepted >= self.REVISION_FLOOR,
            'intent_drift':    round(intent_drift, 4),
        }
        self.revision_coherence = self._clamp(
            sum(r['coh'] for r in revisions) / max(1, len(revisions))
        )
        self.revision_reason = 'accepted=%d floor=%d coh=%.4f' % (
            n_accepted, self.REVISION_FLOOR, self.revision_coherence)

        self._history.append({
            'tick':               tick,
            'n_accepted':         n_accepted,
            'revision_coherence': self.revision_coherence,
            'floor_satisfied':    n_accepted >= self.REVISION_FLOOR,
            'revision_reason':    self.revision_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class GoalNegotiationEngine:
    """Allen et al. 2001 (mixed initiative); Grosz & Sidner 1986 (intention stack).
    Negotiates user goal vs milestone priority, short-term patch vs long-term
    doctrine, research vs product pivots, explanation vs execution.
    NEGOTIATION_BONUS = +0.15 (Rule 4 frozen) for milestone_blocker, code_patch,
    experiment_launch, paper_claim, project_pivot.
    Biology tokens excluded. deque(maxlen=96)."""

    NEGOTIATION_BONUS = 0.15  # Rule 4 frozen
    NEGOTIATION_BONUS_TAGS = frozenset({
        'milestone_blocker', 'code_patch', 'experiment_launch',
        'paper_claim', 'project_pivot',
    })

    _NEGOTIATION_AXES = [
        {'id': 'user_goal_vs_milestone',   'tags': frozenset({'milestone_blocker'}),   'base': 0.85},
        {'id': 'patch_vs_doctrine',        'tags': frozenset({'code_patch'}),           'base': 0.80},
        {'id': 'research_vs_product',      'tags': frozenset({'project_pivot'}),        'base': 0.75},
        {'id': 'experiment_vs_paper',      'tags': frozenset({'experiment_launch','paper_claim'}), 'base': 0.80},
        {'id': 'explanation_vs_execution', 'tags': frozenset({'milestone_blocker'}),   'base': 0.70},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen               = maxlen
        self._history              = deque(maxlen=maxlen)
        self.negotiated_goal       = {}
        self.negotiation_confidence= 0.0
        self.negotiation_reason    = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, intent_evolution_tracker,
               collaborative_revision_loop,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        intent_drift = getattr(intent_evolution_tracker,   'intent_drift',      0.1)
        rev_coh      = getattr(collaborative_revision_loop,'revision_coherence', 0.5)
        lang_conf    = getattr(language_cognition_kernel,  'kernel_confidence',  0.5)

        base = self._clamp((rev_coh + lang_conf) / 2.0)
        axes = []
        for ax in self._NEGOTIATION_AXES:
            bonus = self.NEGOTIATION_BONUS if (ax['tags'] & self.NEGOTIATION_BONUS_TAGS) else 0.0
            conf  = self._clamp(ax['base'] * base + bonus)
            axes.append({
                'id':             ax['id'],
                'bonus_applied':  bonus > 0.0,
                'negotiation_conf': round(conf, 4),
            })

        self.negotiation_confidence = self._clamp(
            sum(a['negotiation_conf'] for a in axes) / max(1, len(axes))
        )
        n_bonused = sum(1 for a in axes if a['bonus_applied'])
        dominant  = max(axes, key=lambda a: a['negotiation_conf'])
        self.negotiated_goal = {
            'axes':                  axes,
            'dominant_axis':         dominant['id'],
            'dominant_conf':         dominant['negotiation_conf'],
            'intent_drift':          round(intent_drift, 4),
            'n_bonused':             n_bonused,
        }
        self.negotiation_reason = 'conf=%.4f dom=%s bonused=%d' % (
            self.negotiation_confidence, dominant['id'], n_bonused)

        self._history.append({
            'tick':                  tick,
            'negotiation_confidence':self.negotiation_confidence,
            'dominant_axis':         dominant['id'],
            'n_bonused':             n_bonused,
            'negotiation_reason':    self.negotiation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class AmbiguityResolutionBridge:
    """Purver 2004 (query repairs); Ginzburg 2012 (inquisitive semantics).
    Resolves wording, scope, timeline, domain, and experimental ambiguity.
    AMBIGUITY_THRESHOLD = 0.50 (Rule 2 mirror): routes through
    ClarificationQuestionPlanner output when ambiguity_score >= 0.50.
    Biology tokens excluded. deque(maxlen=96)."""

    AMBIGUITY_THRESHOLD = 0.50  # Rule 2 mirror

    _AMBIGUITY_SEEDS = [
        {'id': 'wording_ambiguity',      'base_resolution': 0.85},
        {'id': 'scope_ambiguity',        'base_resolution': 0.80},
        {'id': 'timeline_ambiguity',     'base_resolution': 0.75},
        {'id': 'domain_ambiguity',       'base_resolution': 0.70},
        {'id': 'experimental_ambiguity', 'base_resolution': 0.75},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.resolved_ambiguity   = {}
        self.ambiguity_confidence = 0.0
        self.ambiguity_reason     = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, clarification_question_planner,
               intent_evolution_tracker,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        clar_conf    = getattr(clarification_question_planner,'clarification_confidence', 0.5)
        intent_drift = getattr(intent_evolution_tracker,      'intent_drift',             0.1)
        lang_conf    = getattr(language_cognition_kernel,     'kernel_confidence',        0.5)

        ambiguity_score = self._clamp(intent_drift * 0.60 + (1.0 - lang_conf) * 0.40)
        clar_routed = ambiguity_score >= self.AMBIGUITY_THRESHOLD
        base = self._clamp((clar_conf + lang_conf) / 2.0)

        resolutions = []
        for seed in self._AMBIGUITY_SEEDS:
            res_conf = self._clamp(seed['base_resolution'] * base)
            resolutions.append({
                'id':              seed['id'],
                'resolution_conf': round(res_conf, 4),
                'clar_assisted':   clar_routed,
            })

        self.ambiguity_confidence = self._clamp(
            sum(r['resolution_conf'] for r in resolutions) / max(1, len(resolutions))
        )
        self.resolved_ambiguity = {
            'resolutions':        resolutions,
            'ambiguity_score':    round(ambiguity_score, 4),
            'clar_routed':        clar_routed,
            'n_resolved':         len(resolutions),
        }
        self.ambiguity_reason = 'conf=%.4f score=%.4f routed=%s' % (
            self.ambiguity_confidence, ambiguity_score, clar_routed)

        self._history.append({
            'tick':                tick,
            'ambiguity_confidence':self.ambiguity_confidence,
            'ambiguity_score':     ambiguity_score,
            'clar_routed':         clar_routed,
            'ambiguity_reason':    self.ambiguity_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class TurnLevelMemoryBinder:
    """Grosz & Sidner 1986 (attentional state); Traum 1994 (grounding acts).
    Binds prior turn anchors, accepted clarifications, revision state, grounded
    goals, and dialogue continuity kernel into a unified turn memory state.
    Biology tokens excluded. deque(maxlen=96)."""

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _BINDING_SEEDS = [
        {'id': 'prior_turn_anchors',        'base_binding': 0.90},
        {'id': 'accepted_clarifications',   'base_binding': 0.85},
        {'id': 'revision_state_bind',       'base_binding': 0.80},
        {'id': 'grounded_goals_bind',       'base_binding': 0.85},
        {'id': 'dialogue_continuity_bind',  'base_binding': 0.80},
    ]

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.turn_memory_state    = {}
        self.memory_binding_conf  = 0.0
        self.binding_reason       = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, collaborative_revision_loop,
               ambiguity_resolution_bridge,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        rev_coh      = getattr(collaborative_revision_loop, 'revision_coherence',  0.5)
        amb_conf     = getattr(ambiguity_resolution_bridge, 'ambiguity_confidence', 0.5)
        lang_conf    = getattr(language_cognition_kernel,   'kernel_confidence',    0.5)
        n_accepted   = getattr(collaborative_revision_loop, 'revision_state',       {}).get('n_accepted', 2)
        n_turns      = getattr(language_cognition_kernel,   'language_cognition_kernel',{}).get('prior_dialogue_turns', 2)

        base = self._clamp((rev_coh + amb_conf + lang_conf) / 3.0)
        bindings = []
        for seed in self._BINDING_SEEDS:
            bconf = self._clamp(seed['base_binding'] * base)
            bindings.append({'id': seed['id'], 'binding_conf': round(bconf, 4)})

        self.memory_binding_conf = self._clamp(
            sum(b['binding_conf'] for b in bindings) / max(1, len(bindings))
        )
        self.turn_memory_state = {
            'bindings':           bindings,
            'n_bindings':         len(bindings),
            'n_accepted_revisions': n_accepted,
            'prior_turns':        n_turns,
            'binding_conf':       round(self.memory_binding_conf, 4),
        }
        self.binding_reason = 'conf=%.4f bindings=%d turns=%d revisions=%d' % (
            self.memory_binding_conf, len(bindings), n_turns, n_accepted)

        self._history.append({
            'tick':               tick,
            'memory_binding_conf':self.memory_binding_conf,
            'n_bindings':         len(bindings),
            'prior_turns':        n_turns,
            'binding_reason':     self.binding_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PartneredPlanningSynthesizer:
    """Allen et al. 2001 (collaborative planning); Grosz 1996 (shared plans).
    Constructs collaborative stepwise plans integrating negotiated goals,
    prior revisions, clarification outputs, milestone constraints, and the
    active language kernel. PLAN_STEP_CAP = 6. NEGOTIATION_BONUS = +0.15
    (Rule 4 mirror) for plans touching bonus-tagged axes.
    Biology tokens excluded. deque(maxlen=96)."""

    PLAN_STEP_CAP     = 6
    NEGOTIATION_BONUS = 0.15  # Rule 4 mirror
    NEGOTIATION_BONUS_TAGS = frozenset({
        'milestone_blocker', 'code_patch', 'experiment_launch',
        'paper_claim', 'project_pivot',
    })

    _PLAN_STEPS = [
        {'id': 'goal_alignment',       'tags': frozenset({'milestone_blocker'}),    'base': 0.85},
        {'id': 'blocker_resolution',   'tags': frozenset({'milestone_blocker'}),    'base': 0.80},
        {'id': 'code_plan_step',       'tags': frozenset({'code_patch'}),           'base': 0.80},
        {'id': 'experiment_step',      'tags': frozenset({'experiment_launch'}),    'base': 0.75},
        {'id': 'paper_step',           'tags': frozenset({'paper_claim'}),          'base': 0.75},
        {'id': 'pivot_resolution',     'tags': frozenset({'project_pivot'}),        'base': 0.70},
    ]

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.partnered_plan    = {}
        self.planning_confidence=0.0
        self.planning_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick, goal_negotiation_engine,
               collaborative_revision_loop,
               clarification_question_planner,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        neg_conf  = getattr(goal_negotiation_engine,         'negotiation_confidence',   0.5)
        rev_coh   = getattr(collaborative_revision_loop,     'revision_coherence',       0.5)
        clar_conf = getattr(clarification_question_planner,  'clarification_confidence', 0.5)
        lang_conf = getattr(language_cognition_kernel,       'kernel_confidence',        0.5)
        dom_axis  = getattr(goal_negotiation_engine, 'negotiated_goal',{}).get('dominant_axis','user_goal_vs_milestone')

        base = self._clamp((neg_conf + rev_coh + clar_conf + lang_conf) / 4.0)
        steps = []
        for step in self._PLAN_STEPS[:self.PLAN_STEP_CAP]:
            bonus = self.NEGOTIATION_BONUS if (step['tags'] & self.NEGOTIATION_BONUS_TAGS) else 0.0
            conf  = self._clamp(step['base'] * base + bonus)
            steps.append({
                'step_id':       step['id'],
                'bonus_applied': bonus > 0.0,
                'step_conf':     round(conf, 4),
            })

        self.planning_confidence = self._clamp(
            sum(s['step_conf'] for s in steps) / max(1, len(steps))
        )
        n_bonused = sum(1 for s in steps if s['bonus_applied'])
        self.partnered_plan = {
            'steps':             steps,
            'n_steps':           len(steps),
            'dominant_axis':     dom_axis,
            'n_bonused':         n_bonused,
            'plan_step_cap':     self.PLAN_STEP_CAP,
        }
        self.planning_reason = 'steps=%d conf=%.4f dom=%s bonused=%d' % (
            len(steps), self.planning_confidence, dom_axis, n_bonused)

        self._history.append({
            'tick':               tick,
            'n_steps':            len(steps),
            'planning_confidence':self.planning_confidence,
            'n_bonused':          n_bonused,
            'planning_reason':    self.planning_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ConversationalAgencyKernel:
    """Traum 1994 (dialogue moves); Clark & Schaefer 1989 (contribution model).
    Selects single dominant collaborative reasoning state per tick (Rule 5).
    Aggregates intent evolution, clarification planning, revision loop,
    goal negotiation, ambiguity resolution, turn memory, partnered plan,
    and active language kernel into one active conversational mind state.

    kernel_confidence = clamp(
        neg_conf  * 0.20 + plan_conf  * 0.20 + rev_coh   * 0.15
        + amb_conf * 0.15 + lang_conf  * 0.15 + bind_conf * 0.15
    )

    Biology tokens excluded. deque(maxlen=96).
    """

    # Mandatory priors (all frozen)
    _PRIORS = {
        'clarification_cap':   3,    # Rule 1
        'ambiguity_threshold': 0.50, # Rule 2
        'revision_floor':      2,    # Rule 3
        'negotiation_bonus':   0.15, # Rule 4
        'kernel_uniqueness':   'one_dominant_conversational_agency_per_tick',  # Rule 5
    }

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen                      = maxlen
        self._history                     = deque(maxlen=maxlen)
        self.conversational_agency_kernel = {}
        self.kernel_confidence            = 0.0
        self.kernel_reason                = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               intent_evolution_tracker,
               clarification_question_planner,
               collaborative_revision_loop,
               goal_negotiation_engine,
               ambiguity_resolution_bridge,
               turn_level_memory_binder,
               partnered_planning_synthesizer,
               language_cognition_kernel):
        if _IKG.sleeping:
            return

        intent_drift = getattr(intent_evolution_tracker,          'intent_drift',             0.1)
        clar_conf    = getattr(clarification_question_planner,    'clarification_confidence', 0.5)
        rev_coh      = getattr(collaborative_revision_loop,       'revision_coherence',       0.5)
        neg_conf     = getattr(goal_negotiation_engine,           'negotiation_confidence',   0.5)
        amb_conf     = getattr(ambiguity_resolution_bridge,       'ambiguity_confidence',     0.5)
        bind_conf    = getattr(turn_level_memory_binder,          'memory_binding_conf',      0.5)
        plan_conf    = getattr(partnered_planning_synthesizer,    'planning_confidence',      0.5)
        lang_conf    = getattr(language_cognition_kernel,         'kernel_confidence',        0.5)
        n_revisions  = getattr(collaborative_revision_loop,       'revision_state', {}).get('n_accepted', 2)
        n_questions  = len(getattr(clarification_question_planner,'clarification_questions',  []))
        dom_axis     = getattr(goal_negotiation_engine, 'negotiated_goal', {}).get('dominant_axis','user_goal_vs_milestone')
        reg_mode     = getattr(language_cognition_kernel,'language_cognition_kernel',{}).get('regulated_narrative_mode','pass')

        self.kernel_confidence = round(self._clamp(
            neg_conf  * 0.20 +
            plan_conf * 0.20 +
            rev_coh   * 0.15 +
            amb_conf  * 0.15 +
            lang_conf * 0.15 +
            bind_conf * 0.15
        ), 4)

        self.conversational_agency_kernel = {
            # Rule 5 sentinel
            'kernel_uniqueness':      'one_dominant_conversational_agency_per_tick',
            # live state
            'negotiated_goal_axis':   dom_axis,
            'clarification_path':     n_questions,
            'revision_loop_accepted': n_revisions,
            'partnered_plan_conf':    round(plan_conf,  4),
            'turn_memory_conf':       round(bind_conf,  4),
            'active_lang_kernel_conf':round(lang_conf,  4),
            'collaboration_rationale':self.kernel_reason,
            'regulated_narrative_mode': reg_mode,
            'intent_drift':           round(intent_drift, 4),
            # mandatory priors
            'priors':                 self._PRIORS,
        }
        self.kernel_reason = 'conf=%.4f dom=%s clar=%d rev=%d ambig=%.4f plan=%.4f' % (
            self.kernel_confidence, dom_axis, n_questions, n_revisions, amb_conf, plan_conf)
        self.conversational_agency_kernel['collaboration_rationale'] = self.kernel_reason

        self._history.append({
            'tick':              tick,
            'kernel_confidence': self.kernel_confidence,
            'dominant_axis':     dom_axis,
            'n_questions':       n_questions,
            'n_revisions':       n_revisions,
            'intent_drift':      intent_drift,
            'kernel_reason':     self.kernel_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# Day 29 Pack 1 -- Action Binding & Execution Gate
# Franklin & Graesser 1997 (single-agent action selection); Bratman 1987
# (intention, plans, practical reason); Friston 2010 (active inference:
# one executable action per cycle). This pack collapses advisory cognition
# into a single executable action per tick. Hard rules:
#   R1 Single-action law: exactly one selected_action per tick.
#   R2 Fallback dominance: if top_confidence < BINDING_THRESHOLD (0.60)
#      or execution invalid -> fallback to bg_sys.select_action().
#   R3 Reasoning accountability: every bound action cites source kernel.
#   R4 Execution validity: action_type must resolve to a known bridge.
#   R5 No multi-branch execution: candidate pool is scored, not enacted.
#   R6 Bounded memory: deque(maxlen=96). Biology tokens excluded.
# Insertion: waking-only, after conversational_agency_kernel.update(),
# before edit_intent_generator.generate(). Zero Day 28 drift.
# ===========================================================================

class ActionCandidateExtractor:
    """Extracts executable action candidates from upstream advisory kernels.
    Candidates follow the schema:
        {action_id, action_type, target, source, estimated_impact}
    Sources scanned: partnered_plan steps, conversational_agency_kernel
    dominant axis, active_cognition_kernel reasoning thrust, milestone
    blockers, experiment launch signals. Biology tokens excluded.
    deque(maxlen=96)."""

    CANDIDATE_CAP = 8

    # Map plan-step tags -> canonical action_type for execution bridging.
    _TAG_TO_ACTION = {
        'code_patch':        'edit_code',
        'experiment_launch': 'run_experiment',
        'paper_claim':       'update_memory',
        'milestone_blocker': 'edit_code',
        'project_pivot':     'update_memory',
    }

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    def __init__(self, maxlen=96):
        self._maxlen    = maxlen
        self._history   = deque(maxlen=maxlen)
        self.candidates = []
        self.extractor_reason = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def _safe_tag(self, tag):
        t = str(tag).lower()
        for bad in self.BIOLOGY_TOKENS:
            if bad in t:
                return False
        return True

    def update(self, tick,
               partnered_planning_synthesizer,
               conversational_agency_kernel,
               active_cognition_kernel,
               milestone_synthesizer=None,
               post_break_experiment_launchpad=None):
        if _IKG.sleeping:
            self.candidates = []
            return

        cands = []

        # Source 1: partnered plan steps (code, experiment, paper, blocker, pivot).
        plan = getattr(partnered_planning_synthesizer, 'partnered_plan', {}) or {}
        for step in (plan.get('steps', []) or [])[:self.CANDIDATE_CAP]:
            sid = str(step.get('step_id', 'step'))
            if not self._safe_tag(sid): continue
            # derive action_type by sid prefix match
            atype = 'idle_recover'
            if 'code' in sid or 'blocker' in sid:     atype = 'edit_code'
            elif 'experiment' in sid:                 atype = 'run_experiment'
            elif 'paper' in sid or 'pivot' in sid:    atype = 'update_memory'
            elif 'goal' in sid:                       atype = 'update_memory'
            cands.append({
                'action_id':        'plan_%s' % sid,
                'action_type':      atype,
                'target':           sid,
                'source':           'partnered_plan',
                'estimated_impact': float(step.get('step_conf', 0.5)),
            })

        # Source 2: conversational agency kernel dominant axis.
        cak_state = getattr(conversational_agency_kernel, 'conversational_agency_kernel', {}) or {}
        dom_axis = cak_state.get('negotiated_goal_axis', '')
        if dom_axis and self._safe_tag(dom_axis):
            cak_conf = float(getattr(conversational_agency_kernel, 'kernel_confidence', 0.5))
            atype = 'update_memory'
            if 'patch' in dom_axis or 'doctrine' in dom_axis: atype = 'edit_code'
            elif 'experiment' in dom_axis:                    atype = 'run_experiment'
            cands.append({
                'action_id':        'cak_%s' % dom_axis,
                'action_type':      atype,
                'target':           dom_axis,
                'source':           'conversational_agency_kernel',
                'estimated_impact': cak_conf,
            })

        # Source 3: active cognition kernel reasoning thrust.
        ack_conf = float(getattr(active_cognition_kernel, 'kernel_confidence', 0.0) or 0.0)
        if ack_conf >= 0.30:
            cands.append({
                'action_id':        'ack_reasoning_push',
                'action_type':      'edit_code',
                'target':           'active_reasoning',
                'source':           'active_cognition_kernel',
                'estimated_impact': ack_conf,
            })

        # Source 4: milestone blockers (optional).
        if milestone_synthesizer is not None:
            ms_latest = None
            try:
                ms_latest = milestone_synthesizer.latest() if hasattr(milestone_synthesizer, 'latest') else None
            except Exception:
                ms_latest = None
            if isinstance(ms_latest, dict) and ms_latest.get('blocker'):
                btxt = str(ms_latest.get('blocker', ''))[:32]
                if self._safe_tag(btxt):
                    cands.append({
                        'action_id':        'milestone_blocker',
                        'action_type':      'edit_code',
                        'target':           btxt or 'blocker',
                        'source':           'milestone_synthesizer',
                        'estimated_impact': float(ms_latest.get('anchor_confidence', 0.5)),
                    })

        # Source 5: post-break experiment launchpad signal (optional).
        if post_break_experiment_launchpad is not None:
            pbl_latest = None
            try:
                pbl_latest = post_break_experiment_launchpad.latest() if hasattr(post_break_experiment_launchpad, 'latest') else None
            except Exception:
                pbl_latest = None
            if isinstance(pbl_latest, dict):
                lc = float(pbl_latest.get('launch_confidence', 0.0) or 0.0)
                if lc >= 0.30:
                    cands.append({
                        'action_id':        'experiment_launch',
                        'action_type':      'run_experiment',
                        'target':           'launchpad',
                        'source':           'post_break_experiment_launchpad',
                        'estimated_impact': lc,
                    })

        # Cap candidate pool (R5: no unbounded branching).
        self.candidates = cands[:self.CANDIDATE_CAP]
        self.extractor_reason = 'n_cands=%d sources=%d' % (
            len(self.candidates),
            len({c['source'] for c in self.candidates})
        )

        self._history.append({
            'tick':             tick,
            'n_candidates':     len(self.candidates),
            'extractor_reason': self.extractor_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ActionConfidenceEvaluator:
    """Scores each candidate with the frozen four-factor formula:
        confidence = reasoning_confidence * 0.40
                   + goal_alignment       * 0.30
                   + feasibility          * 0.20
                   + horizon_relevance    * 0.10
    All four factors are clamped to [0,1]. Factors are derived from upstream
    kernel state so no separate learning signal is required. deque(maxlen=96).
    """

    W_REASONING  = 0.40
    W_ALIGN      = 0.30
    W_FEASIBLE   = 0.20
    W_HORIZON    = 0.10

    MAX_DAMPENING      = 0.15    # frozen D34P1-R1
    UNCERTAINTY_THRESH = 0.0008  # frozen D34P1-R2 -- calibration_delta threshold (empirical range 0.0009-0.0017)

    MAX_CANDIDATE_VARIANCE = 0.10  # frozen D34P2-R1
    MAX_CREDIT_EFFECT      = 0.05  # frozen D36P1-R1 (reinforcement, matching action)
    MAX_CREDIT_PENALTY     = 0.01  # frozen D36P1-R2 (penalty, non-matching actions)
    _ACTION_TYPE_BIAS = {
        'edit_code':      0.02,    # frozen D34P2-R2
        'run_experiment': 0.01,
        'update_memory': -0.01,
        'idle_recover':  -0.02,
    }

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self.scored        = []
        self.top_candidate = None
        self.top_confidence= 0.0
        self.eval_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               action_candidate_extractor,
               conversational_agency_kernel,
               active_cognition_kernel,
               language_cognition_kernel=None,
               confidence_calibrator=None):
        if _IKG.sleeping:
            self.scored = []
            self.top_candidate = None
            self.top_confidence= 0.0
            return

        cands = list(getattr(action_candidate_extractor, 'candidates', []) or [])
        cak_conf  = self._clamp(getattr(conversational_agency_kernel, 'kernel_confidence', 0.5))
        ack_conf  = self._clamp(getattr(active_cognition_kernel,      'kernel_confidence', 0.5))
        lang_conf = self._clamp(getattr(language_cognition_kernel,    'kernel_confidence', 0.5)) if language_cognition_kernel is not None else 0.5

        scored = []
        for c in cands:
            reasoning_conf = self._clamp(0.5 * ack_conf + 0.5 * lang_conf)
            goal_align     = self._clamp(cak_conf * 0.7 + float(c.get('estimated_impact', 0.5)) * 0.3)
            feasibility    = self._clamp(float(c.get('estimated_impact', 0.5)))
            # horizon relevance: plan/blocker/experiment score higher than generic memory updates.
            atype = c.get('action_type', 'idle_recover')
            horizon = {
                'edit_code':      0.85,
                'run_experiment': 0.75,
                'update_memory':  0.55,
                'idle_recover':   0.25,
            }.get(atype, 0.40)
            conf = self._clamp(
                reasoning_conf * self.W_REASONING +
                goal_align     * self.W_ALIGN     +
                feasibility    * self.W_FEASIBLE  +
                horizon        * self.W_HORIZON
            )
            scored.append({
                'action_id':         c.get('action_id','na'),
                'action_type':       atype,
                'target':            c.get('target','na'),
                'source':            c.get('source','na'),
                'confidence':        round(conf, 4),
                'reasoning_conf':    round(reasoning_conf, 4),
                'goal_alignment':    round(goal_align, 4),
                'feasibility':       round(feasibility, 4),
                'horizon_relevance': round(horizon, 4),
            })

        scored.sort(key=lambda x: x['confidence'], reverse=True)
        self.scored = scored

        # Day 34 Pack 2 -- Candidate-level Confidence Differentiation
        # Per-candidate modifier: action_type bias + impact deviation + depth/uncertainty signals.
        # Adjusts ranking so different action types compete on equal footing.
        if _IKG.enable_candidate_variance and scored:
            _cc2 = confidence_calibrator
            _cal2 = abs(float(getattr(_cc2, 'calibration_delta', 0.0))) if _cc2 is not None else 0.0
            _tdep_bonus = 0.01 * min(_IKG.temporal_depth / 10.0, 1.0) if _IKG.temporal_depth >= 3 else 0.0
            for s in scored:
                _mod = self._ACTION_TYPE_BIAS.get(s['action_type'], 0.0)
                _mod += (s['feasibility'] - 0.5) * 0.06  # candidate-specific: amplify impact deviation
                _mod += _tdep_bonus                        # temporal depth bonus (uniform)
                _mod -= _cal2 * 0.5                        # uncertainty penalty (uniform)
                _mod = max(-self.MAX_CANDIDATE_VARIANCE, min(self.MAX_CANDIDATE_VARIANCE, _mod))
                s['adjusted_confidence'] = max(0.0, min(1.0, s['confidence'] * (1.0 + _mod)))
            scored.sort(key=lambda x: x['adjusted_confidence'], reverse=True)
            self.scored = scored

        if scored:
            self.top_candidate  = scored[0]
            self.top_confidence = scored[0].get('adjusted_confidence', scored[0]['confidence'])
        else:
            self.top_candidate  = None
            self.top_confidence = 0.0

        # Day 34 Pack 1 -- Confidence Variance Injection
        # Uses calibration_delta (downstream uncertainty in decision space) as signal.
        # Dampening applies only within [0.4, 0.7] window; never increases confidence.
        if _IKG.enable_confidence_variance and confidence_calibrator is not None:
            _cal_delta = abs(float(getattr(confidence_calibrator, 'calibration_delta', 0.0)))
            if 0.4 <= self.top_confidence <= 0.7 and _cal_delta >= self.UNCERTAINTY_THRESH:
                _dampening = min(_cal_delta * 5.0, self.MAX_DAMPENING)
                self.top_confidence = max(0.0, min(1.0, self.top_confidence * (1.0 - _dampening)))

        # Day 35 Pack 2 -- Confidence Compression (near-threshold regime, default OFF)
        # Subtracts from top_confidence when PE is low and system is overly stable.
        # Pushes decisions from always-bind into near-threshold fallback territory.
        # MAX_COMPRESSION=0.05. Only reduces, never increases. No randomness.
        if _IKG.enable_confidence_compression and self.top_confidence > 0.55:
            _pp  = globals().get('pp')
            _pe  = float(getattr(_pp, 'error', 0.0)) if _pp is not None else 0.0
            if _pe < 0.05:
                _stability_factor = 1.0 - (_pe / 0.05)
                _compression      = 0.05 * _stability_factor
                # Floor at 0.55 keeps system in fallback_reasoning zone; prevents
                # over-compression into fallback_bg which zeroes binding_confidence.
                self.top_confidence = max(0.55, self.top_confidence - _compression)

        # Day 36 Pack 1 -- Credit-to-Decision Coupling (default OFF -- zero drift when disabled)
        # Action-conditioned differential: previous action reinforced, all others penalized.
        # Depth-gated: zero effect at depth 0, full at depth 10+.
        # Matching action: MAX_CREDIT_EFFECT=0.05. Non-matching: MAX_CREDIT_PENALTY=0.01.
        # Re-sorts scored so ranking shifts propagate to top_candidate. Never NaN or negative.
        if _IKG.enable_credit_coupling and scored:
            _cc_credit = float(getattr(_IKG, 'adjusted_credit_signal', 0.0))
            _cc_depth  = int(getattr(_IKG, 'temporal_depth', 0))
            _cc_credit = max(-1.0, min(1.0, _cc_credit))
            _cc_depth_factor = min(_cc_depth / 10.0, 1.0)
            _cc_prev = getattr(_IKG, 'last_action_type', None)
            for _s in scored:
                if _s['action_type'] == _cc_prev:
                    _cc_eff = _cc_credit * self.MAX_CREDIT_EFFECT * _cc_depth_factor
                else:
                    _cc_eff = -_cc_credit * self.MAX_CREDIT_PENALTY * _cc_depth_factor
                _s['confidence'] = max(0.0, min(1.0, _s['confidence'] * (1.0 + _cc_eff)))
                if 'adjusted_confidence' in _s:
                    _s['adjusted_confidence'] = max(0.0, min(1.0,
                        _s['adjusted_confidence'] * (1.0 + _cc_eff)))
            scored.sort(key=lambda x: x.get('adjusted_confidence', x['confidence']), reverse=True)
            self.top_candidate = scored[0]
            _cc_top_eff = (
                _cc_credit * self.MAX_CREDIT_EFFECT * _cc_depth_factor
                if scored[0]['action_type'] == _cc_prev
                else -_cc_credit * self.MAX_CREDIT_PENALTY * _cc_depth_factor
            )
            self.top_confidence = max(0.0, min(1.0, self.top_confidence * (1.0 + _cc_top_eff)))

        # Day 36 Pack 5 -- Credit-to-Candidate Coupling (default OFF -- zero drift when disabled)
        # Additive mean-preserving rank perturbation: shifts candidate ordering via credit
        # without raising the mean confidence level. top_confidence NEVER modified.
        # Global scaling forbidden -- multiplicative effects drift TC upward via feedback loop.
        # Method: add deltas per candidate, re-center to original mean, clamp, re-sort.
        if _IKG.enable_credit_selection and scored:
            _cs_credit = float(getattr(_IKG, 'adjusted_credit_signal', 0.0))
            _cs_depth  = int(getattr(_IKG, 'temporal_depth', 0))
            _cs_credit = max(-1.0, min(1.0, _cs_credit))
            _cs_credit_n = (_cs_credit + 1.0) / 2.0
            _cs_depth_factor = min(_cs_depth / 10.0, 1.0)
            _cs_prev = getattr(_IKG, 'last_action_type', None)
            _cs_key = 'adjusted_confidence' if 'adjusted_confidence' in scored[0] else 'confidence'
            # Capture mean before perturbation
            _cs_mean_before = sum(_s[_cs_key] for _s in scored) / len(scored)
            # Additive delta per candidate
            _CS_MAX_DELTA = 0.02
            for _s in scored:
                if _s['action_type'] == _cs_prev:
                    _cs_delta = _CS_MAX_DELTA * _cs_credit_n * _cs_depth_factor
                else:
                    _cs_delta = -_CS_MAX_DELTA * 0.25 * _cs_depth_factor
                _s[_cs_key] = _s[_cs_key] + _cs_delta
            # Re-center: shift all back so mean is unchanged
            _cs_mean_after = sum(_s[_cs_key] for _s in scored) / len(scored)
            _cs_shift = _cs_mean_before - _cs_mean_after
            for _s in scored:
                _s[_cs_key] = max(0.0, min(1.0, _s[_cs_key] + _cs_shift))
            scored.sort(key=lambda x: x[_cs_key], reverse=True)
            self.top_candidate = scored[0]
            # top_confidence intentionally NOT modified -- routing gate preserved

        self.eval_reason = 'n=%d top_conf=%.4f' % (len(scored), self.top_confidence)

        self._history.append({
            'tick':           tick,
            'n_scored':       len(scored),
            'top_confidence': self.top_confidence,
            'top_action':     self.top_candidate['action_id'] if self.top_candidate else None,
            'eval_reason':    self.eval_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ExecutionInterfaceBridge:
    """Maps action_type -> executable handler name (R4 validity).
    Frozen registry:
        edit_code      -> 'code_patch_executor'
        run_experiment -> 'experiment_trigger'
        update_memory  -> 'memory_write'
        idle_recover   -> 'homeostasis_call'
    Validity check ensures no action without a resolved bridge can be bound.
    deque(maxlen=96)."""

    _BRIDGE_REGISTRY = {
        'edit_code':      'code_patch_executor',
        'run_experiment': 'experiment_trigger',
        'update_memory':  'memory_write',
        'idle_recover':   'homeostasis_call',
    }

    def __init__(self, maxlen=96):
        self._maxlen      = maxlen
        self._history     = deque(maxlen=maxlen)
        self.resolved     = None     # dict: action + handler
        self.valid        = False
        self.bridge_reason= 'init'

    def resolve(self, action_record):
        if not isinstance(action_record, dict):
            return None, False
        atype = action_record.get('action_type', '')
        handler = self._BRIDGE_REGISTRY.get(atype)
        if handler is None:
            return None, False
        return handler, True

    def update(self, tick, action_confidence_evaluator):
        if _IKG.sleeping:
            self.resolved = None
            self.valid    = False
            return

        top = getattr(action_confidence_evaluator, 'top_candidate', None)
        handler, valid = self.resolve(top)
        if valid:
            self.resolved = {
                'action_id':   top.get('action_id'),
                'action_type': top.get('action_type'),
                'target':      top.get('target'),
                'source':      top.get('source'),
                'handler':     handler,
                'confidence':  top.get('confidence', 0.0),
            }
            self.valid = True
        else:
            self.resolved = None
            self.valid    = False
        self.bridge_reason = 'valid=%s handler=%s' % (
            self.valid,
            (self.resolved or {}).get('handler', 'none')
        )

        self._history.append({
            'tick':           tick,
            'valid':          self.valid,
            'handler':        (self.resolved or {}).get('handler', None),
            'action_id':      (self.resolved or {}).get('action_id', None),
            'bridge_reason':  self.bridge_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ActionBindingGate:
    """Core single-action collapse (Rules 1-6).
    Binds exactly one executable action per waking tick. Binding succeeds when:
        top_confidence >= BINDING_THRESHOLD (0.60) AND execution_valid.
    Otherwise falls back to bg_sys.select_action() record carried on the
    tick context. Output:
        self.bound_action = {
            'action_id','action_type','target','source','handler',
            'confidence','path'('bound'|'fallback_reasoning'|'fallback_bg'),
            'reasoning_citation'
        }
    deque(maxlen=96). Biology tokens excluded."""

    BINDING_THRESHOLD = 0.60   # R2 threshold (frozen)
    # Day 34 Pack 3 -- windowed reasoning fallback (frozen D34P3-R1)
    REASONING_FALLBACK_LOW  = 0.55
    REASONING_FALLBACK_HIGH = 0.60
    # Day 34 Pack 4 -- BG policy thresholds (frozen D34P4-R1 through R4)
    # Multi-signal: energy (L23 mean) + depth (temporal) + tc (confidence gap)
    BG_ENERGY_LOW  = 0.30   # l23 mean energy below this: depleted -> idle_recover
    BG_DEPTH_WAIT  = 5      # temporal depth at/above: wait
    BG_TC_EXPLORE  = 0.48   # top_conf below this: high uncertainty -> explore
    BG_TC_APPROACH = 0.53   # top_conf below this: moderate uncertainty -> approach
    _PATHS = frozenset({'bound', 'fallback_reasoning', 'fallback_bg'})

    BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys',
    })

    _PRIORS = {
        'binding_threshold':  0.60,      # R2
        'single_action_law':  'one_executable_action_per_waking_tick',  # R1
        'multi_branch_law':   'no_multi_branch_execution',              # R5
        'bounded_memory':     96,                                        # R6
    }

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.bound_action     = None
        self.binding_confidence = 0.0
        self.binding_path     = 'none'
        self.binding_reason   = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               action_confidence_evaluator,
               execution_interface_bridge,
               bg_fallback_action=None,
               active_cognition_kernel=None,
               conversational_agency_kernel=None):
        # R1: sleeping -> no action bound. Respect waking guard.
        if _IKG.sleeping:
            self.bound_action     = None
            self.binding_path     = 'none'
            self.binding_confidence = 0.0
            return

        top_conf = float(getattr(action_confidence_evaluator, 'top_confidence', 0.0) or 0.0)
        top_cand = getattr(action_confidence_evaluator, 'top_candidate', None)
        exec_valid = bool(getattr(execution_interface_bridge, 'valid', False))
        resolved   = getattr(execution_interface_bridge, 'resolved', None)

        ack_conf = float(getattr(active_cognition_kernel, 'kernel_confidence', 0.0) or 0.0)
        cak_conf = float(getattr(conversational_agency_kernel, 'kernel_confidence', 0.0) or 0.0)
        reasoning_citation = 'ack=%.3f cak=%.3f' % (ack_conf, cak_conf)

        if top_conf >= self.BINDING_THRESHOLD and exec_valid and resolved is not None:
            # R1 + R3 + R4 satisfied -> bind.
            self.bound_action = {
                'action_id':           resolved.get('action_id'),
                'action_type':         resolved.get('action_type'),
                'target':              resolved.get('target'),
                'source':              resolved.get('source'),
                'handler':             resolved.get('handler'),
                'confidence':          round(top_conf, 4),
                'path':                'bound',
                'reasoning_citation':  reasoning_citation,
            }
            self.binding_path       = 'bound'
            self.binding_confidence = self._clamp(top_conf)
            self.binding_reason = 'bound %s conf=%.4f' % (resolved.get('action_id'), top_conf)

        else:
            # R2 fallback dominance. Prefer top reasoning candidate if present
            # but sub-threshold; otherwise defer to bg_sys instinct.
            # Day 34 Pack 3: when routing correction enabled, restrict fallback_reasoning
            # to the [REASONING_FALLBACK_LOW, REASONING_FALLBACK_HIGH) window.
            # Below that window, route to fallback_bg (BG system) for true alternative path.
            _routing_ok = (
                not _IKG.enable_routing_correction or
                self.REASONING_FALLBACK_LOW <= top_conf < self.REASONING_FALLBACK_HIGH
            )
            if top_cand is not None and exec_valid and resolved is not None and _routing_ok:
                self.bound_action = {
                    'action_id':           resolved.get('action_id'),
                    'action_type':         resolved.get('action_type'),
                    'target':              resolved.get('target'),
                    'source':              resolved.get('source'),
                    'handler':             resolved.get('handler'),
                    'confidence':          round(top_conf, 4),
                    'path':                'fallback_reasoning',
                    'reasoning_citation':  reasoning_citation,
                }
                self.binding_path       = 'fallback_reasoning'
                self.binding_confidence = self._clamp(top_conf)
                self.binding_reason = 'fallback_reasoning below_thresh %.4f' % top_conf
            else:
                # Day 34 Pack 4 -- Background Policy Diversification
                # When enabled: select bg_name and atype based on energy/PE/depth signals.
                # When disabled: original behavior (bg_fallback_action string, atype='idle_recover').
                if _IKG.enable_bg_policy:
                    _energy = float(_IKG.bg_energy)   # l23 mean energy, injected per tick
                    _depth  = int(_IKG.temporal_depth)
                    # Three orthogonal axes: metabolic state, temporal context, confidence level
                    if _energy < self.BG_ENERGY_LOW:
                        bg_name = 'idle_recover'        # depleted: recover first
                    elif _depth >= self.BG_DEPTH_WAIT:
                        # Day 35 Pack 3 -- BG Policy Decomposition (default OFF -- zero drift)
                        # Depth gates this branch; PE + tc decide action when enabled.
                        if _IKG.enable_bg_decomposition:
                            _bg_pe = float(_IKG.bg_pe)
                            # Day 36 Pack 3 -- Score-Based BG Selection (default OFF -- zero drift)
                            # Replaces threshold logic with continuous score argmax + credit pressure.
                            # enable_bg_scoring=False preserves Pack 2 threshold logic exactly.
                            if _IKG.enable_bg_scoring:
                                _bg_cred = max(-1.0, min(1.0, float(
                                    getattr(_IKG, 'adjusted_credit_signal', 0.0))))
                                _credit_n = (_bg_cred + 1.0) / 2.0
                                _k = 0.3
                                # Day 36 Pack 4 -- Score Rebalancing (default OFF -- zero drift)
                                # Equalizes base scale so credit pressure can influence outcome.
                                if _IKG.enable_bg_rebalance:
                                    _sc_explore  = 0.45 + _k * (1.0 - _credit_n)
                                    _sc_approach = 0.45 + _k * _credit_n
                                    _sc_wait     = 0.45 + 0.05 * (0.5 - abs(_credit_n - 0.5))
                                else:
                                    _sc_explore  = (1.0 if _bg_pe > 0.05 else 0.2) + _k * (1.0 - _credit_n)
                                    _sc_approach = (1.0 if top_conf < self.BG_TC_APPROACH else 0.3) + _k * _credit_n
                                    _sc_wait     = (0.5 if _depth >= self.BG_DEPTH_WAIT else 0.2) + 0.05 * (0.5 - abs(_credit_n - 0.5))
                                # Day 36 Pack 6 -- PE Exploration Pressure (default OFF -- zero drift)
                                # High PE -> explore boost + approach suppression.
                                # Biologically: LC-NE uncertainty drives exploration over exploitation.
                                if _IKG.enable_pe_exploration:
                                    _pe_bg = max(0.0, min(1.0, float(getattr(_IKG, 'bg_pe', 0.0))))
                                    _K_PE = 0.18
                                    _sc_explore  += _K_PE * _pe_bg
                                    _sc_approach -= 0.6 * _K_PE * _pe_bg
                                    _sc_wait     += 0.04 * (0.5 - abs(_pe_bg - 0.5))
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 37 Pack 1 -- Novelty Pressure (default OFF -- zero drift)
                                # Coarse state visit counts: less-visited -> explore boost.
                                # Key uses behavior, not control vars; no randomness.
                                if _IKG.enable_novelty:
                                    _nov_key = (
                                        getattr(_IKG, 'last_action_type', None),
                                        int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                                        int(getattr(_IKG, 'bg_pe', 0.0) * 10),
                                    )
                                    _nov_count = _IKG.novelty_counts.get(_nov_key, 0)
                                    _nov_n = 1.0 / (1.0 + math.log(1.0 + _nov_count))
                                    _K_N = 0.20
                                    _sc_explore  += _K_N * _nov_n
                                    _sc_approach -= 0.3 * _K_N * _nov_n
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 37 Pack 3 -- Contextual Curiosity (default OFF -- zero drift)
                                # Explore only when novelty AND credit-vs-PE mismatch both high.
                                # Biologically: hippocampal novelty gates on prediction error.
                                if _IKG.enable_contextual_curiosity:
                                    _cc_pe      = max(0.0, min(1.0, float(getattr(_IKG, 'bg_pe', 0.0))))
                                    _cc_cred    = max(0.0, min(1.0, (float(getattr(_IKG, 'adjusted_credit_signal', 0.0)) + 1.0) / 2.0))
                                    _cc_pe_n     = min(1.0, _cc_pe / 0.10)
                                    _cc_mismatch = _cc_pe_n * (1.0 - _cc_cred)
                                    _cc_nov_key  = (
                                        getattr(_IKG, 'last_action_type', None),
                                        int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                                        int(getattr(_IKG, 'bg_pe', 0.0) * 10),
                                    )
                                    _cc_count   = _IKG.novelty_counts.get(_cc_nov_key, 0)
                                    _cc_n       = 1.0 / (1.0 + math.log(1.0 + _cc_count))
                                    _cc_curiosity = _cc_n * _cc_mismatch
                                    _K_CTX = 0.15
                                    _sc_explore  += _K_CTX * _cc_curiosity
                                    _sc_approach -= 0.25 * _K_CTX * _cc_curiosity
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 37 Pack 4 -- Curiosity Reinforcement (default OFF -- zero drift)
                                # Learned exploration value: states where exploring paid off get boosted.
                                # Updates only on explore actions; slow decay keeps memory adaptive.
                                if _IKG.enable_curiosity_reinforcement:
                                    _cr_key = (
                                        int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                                        int(getattr(_IKG, 'bg_pe', 0.0) * 10),
                                    )
                                    _cr_v   = _IKG.curiosity_value.get(_cr_key, 0.0)
                                    _K_CR   = 0.03
                                    _sc_explore  += _K_CR * _cr_v
                                    _sc_approach -= 0.2 * _K_CR * _cr_v
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 38 Pack 3 -- Error-Gated Modulation (default OFF -- zero drift).
                                # Transition prediction error nudges scoring; bounded, not a driver.
                                # Gates (three layers, all required):
                                #   1) predicted_next_state is not None -- system had expectation
                                #   2) last_action_type != 'run_experiment' -- decouple self-caused
                                #      error from external surprise (positive-feedback fix)
                                #   3) transition_error >= 0.8 -- magnitude gate; ignore small errors,
                                #      react only to real surprises (rare-event semantics)
                                # Result: "expected-stable behavior produced unexpected outcome" only.
                                # No routing/TC/ACE change; only score_explore / score_approach.
                                if (_IKG.enable_prediction_modulation
                                        and getattr(_IKG, 'predicted_next_state', None) is not None
                                        and getattr(_IKG, 'last_action_type', None) != 'run_experiment'
                                        and float(getattr(_IKG, 'transition_error', 0.0)) >= 0.8):
                                    _te_bg   = max(0.0, min(1.0, float(getattr(_IKG, 'transition_error', 0.0))))
                                    _K_PE_TE = 0.02
                                    _sc_explore  += _K_PE_TE * _te_bg
                                    _sc_approach -= 0.3 * _K_PE_TE * _te_bg
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 38 Pack 5 -- Confidence-Aware Surprise (default OFF -- zero drift).
                                # Secondary refinement: react more strongly to "sure and wrong".
                                # real_surprise = TE * PC. Same 3 gates as Pack 3 (TE gate mandatory
                                # per critical constraint -- no standalone confidence influence).
                                # K_CS=0.01 < K_PE=0.02 (refinement, not replacement).
                                if (_IKG.enable_confidence_surprise
                                        and getattr(_IKG, 'predicted_next_state', None) is not None
                                        and getattr(_IKG, 'last_action_type', None) != 'run_experiment'
                                        and float(getattr(_IKG, 'transition_error', 0.0)) >= 0.8):
                                    _te_cs = max(0.0, min(1.0, float(getattr(_IKG, 'transition_error', 0.0))))
                                    _pc_cs = max(0.0, min(1.0, float(getattr(_IKG, 'prediction_confidence', 0.0))))
                                    _real_surprise = _te_cs * _pc_cs
                                    _K_CS = 0.01
                                    _sc_explore  += _K_CS * _real_surprise
                                    _sc_approach -= 0.25 * _K_CS * _real_surprise
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                # Day 39 Pack 2 -- Concept-Conditioned Modulation (default OFF -- zero drift).
                                # Cluster-derived context as weak modifier. Strict hierarchy:
                                # K_CTX_CL=0.005 < K_CS=0.01 < K_PE=0.02 < K_N=0.20.
                                # Concepts guide, never drive. No routing/TC/ACE change.
                                if _IKG.enable_concept_modulation:
                                    _cm_key = (
                                        getattr(_IKG, 'last_action_type', None),
                                        int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                                        int(getattr(_IKG, 'bg_pe', 0.0) * 10),
                                    )
                                    _cm_cid = _IKG.state_clusters.get(_cm_key)
                                    if _cm_cid is not None:
                                        _cm_st = _IKG.cluster_stats.get(_cm_cid)
                                        if _cm_st is not None:
                                            _cm_te   = max(0.0, min(1.0, float(_cm_st.get('mean_te', 0.0))))
                                            _cm_pc   = max(0.0, min(1.0, float(_cm_st.get('mean_pc', 0.0))))
                                            _cm_size = min(1.0, float(_cm_st.get('sample_total', 0)) / 200.0)
                                            _K_CTX_CL = 0.005
                                            _sc_explore  += _K_CTX_CL * _cm_te * _cm_size
                                            _sc_approach += _K_CTX_CL * _cm_pc * _cm_size
                                            _sc_approach  = max(0.0, _sc_approach)
                                            _sc_explore   = max(0.0, _sc_explore)
                                            _sc_wait      = max(0.0, _sc_wait)
                                # Day 39 Pack 6 -- Conflict-Gated Attention (default OFF -- zero drift).
                                # Rare-event boost gated on macro-failure: signed<0 AND conflict>=0.6.
                                # K_CF=0.002 smallest in stack; cooldown 5 ticks prevents recursive
                                # activation. Reads previous tick's conflict (this tick computed later).
                                # No routing/TC/ACE change; only score_explore / score_approach.
                                if _IKG.enable_conflict_attention:
                                    _is_cf_event = (
                                        float(getattr(_IKG, 'cross_level_conflict', 0.0)) >= 0.6
                                        and float(getattr(_IKG, 'cross_level_signed', 0.0)) < 0.0
                                    )
                                    _cf_cooldown_ok = (tick - _IKG._conflict_last_tick) >= _IKG.conflict_cooldown_ticks
                                    if _is_cf_event and _cf_cooldown_ok:
                                        _K_CF = 0.002
                                        _sc_explore  += _K_CF
                                        _sc_approach -= 0.5 * _K_CF
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _sc_wait      = max(0.0, _sc_wait)
                                        _IKG._conflict_last_tick = tick
                                        # Day 39 Pack 7 activation -- triggered by Pack 6 fire only.
                                        if _IKG.enable_attention_persistence:
                                            _IKG.attention_timer    = 5
                                            _IKG.attention_strength = float(_IKG.cross_level_conflict)
                                # Day 39 Pack 7 -- Attention Persistence (default OFF -- zero drift).
                                # Sustains focus 3-5 ticks after macro failure event. Auto-decays.
                                # K_AP=0.001 < K_CF=0.002. No independent trigger.
                                if _IKG.enable_attention_persistence and _IKG.attention_timer > 0:
                                    _K_AP = 0.001
                                    _sc_explore  += _K_AP * _IKG.attention_strength
                                    _sc_approach -= 0.3 * _K_AP * _IKG.attention_strength
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _sc_wait      = max(0.0, _sc_wait)
                                    _IKG.attention_timer    -= 1
                                    _IKG.attention_strength *= 0.8
                                    if _IKG.attention_timer <= 0:
                                        _IKG.attention_strength = 0.0
                                # Day 39 Pack 8 -- Safe-Probing under Conflict (default OFF -- zero drift).
                                # Active only during attention window AND when energy >= safe margin.
                                # K_SP=0.0015 (between K_AP=0.001 and K_CF=0.002). Suppresses wait
                                # rather than approach, preserving exploit option for stable regimes.
                                if _IKG.enable_safe_probe:
                                    _is_safe_probe = (
                                        _IKG.attention_timer > 0
                                        and _energy > (self.BG_ENERGY_LOW + 0.05)
                                    )
                                    if _is_safe_probe:
                                        _K_SP = 0.0015
                                        _sc_explore += _K_SP * _IKG.attention_strength
                                        _sc_wait    -= 0.3 * _K_SP * _IKG.attention_strength
                                        _sc_approach = max(0.0, _sc_approach)
                                        _sc_explore  = max(0.0, _sc_explore)
                                        _sc_wait     = max(0.0, _sc_wait)
                                # Day 39 Pack 9 -- Targeted Exploration (default OFF -- zero drift).
                                # Bias exploration toward states the model contradicts.
                                # K_TE=0.0012 < K_SP=0.0015. Same gates as Pack 8 + target_signal > 0.3.
                                # target_signal = max(state_TE*state_PC, concept_TE*concept_PC).
                                if _IKG.enable_targeted_explore:
                                    _state_sig   = float(getattr(_IKG, 'transition_error', 0.0)) * float(getattr(_IKG, 'prediction_confidence', 0.0))
                                    _concept_sig = float(getattr(_IKG, 'cluster_transition_error', 0.0)) * float(getattr(_IKG, 'cluster_prediction_conf', 0.0))
                                    _target_sig  = min(1.0, max(_state_sig, _concept_sig))
                                    _is_target = (
                                        _IKG.attention_timer > 0
                                        and _energy > (self.BG_ENERGY_LOW + 0.05)
                                        and _target_sig > 0.3
                                    )
                                    if _is_target:
                                        _K_TE = 0.0012
                                        _sc_explore  += _K_TE * _target_sig
                                        _sc_approach -= 0.2 * _K_TE * _target_sig
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _sc_wait      = max(0.0, _sc_wait)
                                # Day 39 Pack 10 -- Selective Override (default OFF -- zero drift).
                                # Ultra-strict gate: target_signal > 0.7 AND attention AND energy safe.
                                # K_OV=0.0008 < K_TE=0.0012. Reduces approach/wait instead of boosting
                                # explore directly. No routing/TC change.
                                if _IKG.enable_selective_override:
                                    _state_sig_ov   = float(getattr(_IKG, 'transition_error', 0.0)) * float(getattr(_IKG, 'prediction_confidence', 0.0))
                                    _concept_sig_ov = float(getattr(_IKG, 'cluster_transition_error', 0.0)) * float(getattr(_IKG, 'cluster_prediction_conf', 0.0))
                                    _target_sig_ov  = min(1.0, max(_state_sig_ov, _concept_sig_ov))
                                    _is_override = (
                                        _IKG.attention_timer > 0
                                        and _energy > (self.BG_ENERGY_LOW + 0.05)
                                        and _target_sig_ov > 0.7
                                    )
                                    if _is_override:
                                        _K_OV = 0.0008
                                        _sc_approach -= _K_OV * _target_sig_ov
                                        _sc_wait     -= 0.5 * _K_OV * _target_sig_ov
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _sc_wait      = max(0.0, _sc_wait)
                                # Day 39 Pack 11 -- Micro-Strategy Persistence (default OFF -- zero drift).
                                # Brief 3-tick commitment to last action when attention high + target>0.6.
                                # K_MS=0.0006 (smallest behavioral K). No long-term lock.
                                if _IKG.enable_strategy_persistence:
                                    _state_sig_ms   = float(getattr(_IKG, 'transition_error', 0.0)) * float(getattr(_IKG, 'prediction_confidence', 0.0))
                                    _concept_sig_ms = float(getattr(_IKG, 'cluster_transition_error', 0.0)) * float(getattr(_IKG, 'cluster_prediction_conf', 0.0))
                                    _target_sig_ms  = min(1.0, max(_state_sig_ms, _concept_sig_ms))
                                    if (_IKG.strategy_timer == 0
                                            and _IKG.attention_timer > 0
                                            and _target_sig_ms > 0.6):
                                        _IKG.strategy_timer  = 3
                                        _IKG.strategy_action = getattr(_IKG, 'last_action_type', None)
                                    if _IKG.strategy_timer > 0 and _IKG.strategy_action is not None:
                                        _K_MS = 0.0006
                                        if _IKG.strategy_action == 'explore':
                                            _sc_explore += _K_MS
                                        elif _IKG.strategy_action == 'approach':
                                            _sc_approach += _K_MS
                                        elif _IKG.strategy_action == 'wait':
                                            _sc_wait += _K_MS
                                        _sc_approach = max(0.0, _sc_approach)
                                        _sc_explore  = max(0.0, _sc_explore)
                                        _sc_wait     = max(0.0, _sc_wait)
                                        _IKG.strategy_timer -= 1
                                        if _IKG.strategy_timer <= 0:
                                            _IKG.strategy_action = None
                                # Day 42 Pack 9: per-tick delta init (0 if S_real does not fire this tick).
                                _ot9_delta = 0.0
                                # Day 41 Pack 2 -- Real-Surprise Gated Modulation (default OFF).
                                # S_real flag set at prev-tick VSA hook (one-tick latency).
                                # K_RS=0.001 < K_CF=0.002; smallest explore nudge in stack.
                                if getattr(_IKG, 'enable_vsa_real_modulation', False) and getattr(_IKG, 'vsa_real_surprise', False):
                                    _IKG.vsa_real_trigger_count += 1
                                    _sc_explore  += _IKG.K_RS
                                    _sc_approach -= 0.5 * _IKG.K_RS
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _IKG.vsa_real_applied_count += 1
                                    # Day 41 Pack 3 FIX: window activation co-located with trigger.
                                    # Same gate + same clock as Pack 2 guarantees activations == trigger_count.
                                    if getattr(_IKG, 'enable_vsa_surprise_window', False):
                                        _IKG.vsa_sw_timer = _IKG.vsa_sw_duration
                                        _IKG.vsa_sw_activations += 1
                                    # Day 41 Pack 6 Step 1: update continuity buffer on S_real.
                                    if getattr(_IKG, 'enable_vsa_continuity', False):
                                        _ct_curr = _IKG.vsa_event
                                        _ct_sims = [_IKG.vsa_similarity(_ct_curr, _ep) for _ep in _IKG.vsa_ct_buffer]
                                        _IKG.vsa_ct_similarity = max(_ct_sims) if _ct_sims else 0.0
                                        _IKG.vsa_ct_buffer.append(_ct_curr)
                                        if len(_IKG.vsa_ct_buffer) > _IKG.vsa_ct_max:
                                            _IKG.vsa_ct_buffer.pop(0)
                                        _IKG.vsa_ct_events += 1
                                        if _IKG.vsa_ct_similarity > 0.7:
                                            _IKG.vsa_ct_matches += 1
                                    # Day 41 Pack 7 Step 1: compute repetition strength from similarity.
                                    if getattr(_IKG, 'enable_vsa_repetition_weighting', False):
                                        if _IKG.vsa_ct_similarity > 0.7:
                                            _IKG.vsa_rw_strength = min(1.0, (_IKG.vsa_ct_similarity - 0.7) / 0.3)
                                        else:
                                            _IKG.vsa_rw_strength = 0.0
                                    # Day 42 Pack 1 Step 1+2: direction accumulation at S_real.
                                    # Uses vsa_ct_similarity (context similarity to past S_real events)
                                    # rather than event-event similarity; the latter is always ~0.5 at
                                    # S_real time (structural change = near-random hamming sim).
                                    # vsa_ct_similarity is updated by Pack 6 Step 1 above; 0.0 if Pack 6 off.
                                    if getattr(_IKG, 'enable_vsa_trajectory', False):
                                        _tr_sim = _IKG.vsa_ct_similarity
                                        if _tr_sim < 0.3:
                                            _tr_d = 1
                                        elif _tr_sim > 0.7:
                                            _tr_d = -1
                                        else:
                                            _tr_d = 0
                                        _IKG.vsa_tr_buffer.append(_tr_d)
                                        if len(_IKG.vsa_tr_buffer) > _IKG.vsa_tr_max:
                                            _IKG.vsa_tr_buffer.pop(0)
                                        _IKG.vsa_tr_events += 1
                                        if _IKG.vsa_tr_buffer:
                                            _IKG.vsa_tr_score = sum(_IKG.vsa_tr_buffer) / len(_IKG.vsa_tr_buffer)
                                        else:
                                            _IKG.vsa_tr_score = 0.0
                                    # Day 42 Pack 3 Step 1: persist EMA update at S_real (event-level only).
                                    if getattr(_IKG, 'enable_vsa_tr_persist', False):
                                        _IKG.vsa_tr_persist = 0.8 * _IKG.vsa_tr_persist + 0.2 * _IKG.vsa_tr_score
                                    # Day 43 Pack 3 -- Outcome Diversity Guarantee.
                                    if getattr(_IKG, 'enable_env_outcome', False):
                                        _ot_te_raw = float(getattr(_IKG, 'transition_error', 0.0))
                                        _IKG.vsa_te_min = min(_IKG.vsa_te_min, _ot_te_raw)
                                        _IKG.vsa_te_max = max(_IKG.vsa_te_max, _ot_te_raw)

                                    # Day 42 Pack 8 Step 1: outcome trace update at S_real (event-level only).
                                    if getattr(_IKG, 'enable_vsa_outcome', False):
                                        _ot_te = float(getattr(_IKG, 'transition_error', 0.0))
                                        # Day 43 Pack 3 -- Outcome Diversity Guarantee.
                                        # When ON: update running TE range and normalize
                                        # so outcome is bidirectional around the organism's
                                        # own experience baseline.  TE unchanged; only the
                                        # outcome signal interpretation is relative.
                                        if getattr(_IKG, 'enable_env_outcome', False):
                                            if _IKG.vsa_te_max > _IKG.vsa_te_min:
                                                _te_norm = (_ot_te - _IKG.vsa_te_min) / (_IKG.vsa_te_max - _IKG.vsa_te_min)
                                            else:
                                                _te_norm = _ot_te
                                            _ot_signal = (1.0 - _te_norm) - 0.5
                                        else:
                                            # Pack 2 / original absolute formula (zero drift when OFF)
                                            _ot_signal = 0.5 - _ot_te
                                        _IKG.vsa_outcome = 0.7 * _IKG.vsa_outcome + 0.3 * _ot_signal
                                    # Day 42 Pack 9 Step 1: outcome delta at S_real (event-level only).
                                    if getattr(_IKG, 'enable_vsa_outcome_delta', False):
                                        _ot9_delta = _IKG.vsa_outcome - _IKG.vsa_outcome_prev
                                        _IKG.vsa_outcome_prev = _IKG.vsa_outcome
                                    # Day 43 Pack 5 Step 1: outcome sign counter at S_real (observation only).
                                    if getattr(_IKG, 'enable_env_shift', False):
                                        _IKG.env_shift_count += 1
                                        if _IKG.vsa_outcome > 0:
                                            _IKG.env_shift_pos += 1
                                        elif _IKG.vsa_outcome < 0:
                                            _IKG.env_shift_neg += 1
                                        if _IKG.env_shift_count > 0:
                                            _IKG.env_shift_rate = _IKG.env_shift_pos / _IKG.env_shift_count
                                            _IKG.env_shift_neg_rate = _IKG.env_shift_neg / _IKG.env_shift_count
                                        _IKG.env_shift_summary = _IKG.env_shift_corr
                                    # Day 43 Pack 8 Step 1: regime outcome profiling at S_real (observation only).
                                    if getattr(_IKG, 'enable_env_regime_profile', False):
                                        if getattr(_IKG, 'env_regime', 0) == 0:
                                            _IKG.env_regime0_count += 1
                                            _IKG.env_regime0_outcome_sum += _IKG.vsa_outcome
                                            _IKG.env_regime0_outcome_mean = _IKG.env_regime0_outcome_sum / max(1, _IKG.env_regime0_count)
                                        else:
                                            _IKG.env_regime1_count += 1
                                            _IKG.env_regime1_outcome_sum += _IKG.vsa_outcome
                                            _IKG.env_regime1_outcome_mean = _IKG.env_regime1_outcome_sum / max(1, _IKG.env_regime1_count)
                                        if _IKG.env_regime0_count > 0 and _IKG.env_regime1_count > 0:
                                            _IKG.env_regime_outcome_gap = _IKG.env_regime1_outcome_mean - _IKG.env_regime0_outcome_mean
                                        else:
                                            _IKG.env_regime_outcome_gap = 0.0
                                    # Day 43 Pack 12: regime trend detection at S_real (observation only).
                                    if getattr(_IKG, 'enable_env_regime_trend', False):
                                        if getattr(_IKG, 'env_regime', 0) == 0:
                                            _IKG.env_regime0_trend_ema = 0.95 * _IKG.env_regime0_trend_ema + 0.05 * _IKG.vsa_outcome
                                        else:
                                            _IKG.env_regime1_trend_ema = 0.95 * _IKG.env_regime1_trend_ema + 0.05 * _IKG.vsa_outcome
                                        _IKG.env_regime0_trend = _IKG.env_regime0_trend_ema
                                        _IKG.env_regime1_trend = _IKG.env_regime1_trend_ema
                                        _IKG.env_regime_trend_gap = _IKG.env_regime1_trend_ema - _IKG.env_regime0_trend_ema
                                # Day 41 Pack 3 -- Surprise Window modulation + tick decay.
                                # K_SW=0.0005 < K_RS=0.001; active for vsa_sw_duration ticks post S_real.
                                if getattr(_IKG, 'enable_vsa_surprise_window', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _sc_explore  += _IKG.K_SW
                                    _sc_approach -= 0.5 * _IKG.K_SW
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _IKG.vsa_sw_timer -= 1
                                    _IKG.vsa_sw_ticks += 1
                                    _IKG.vsa_sw_active_tick = True
                                # Day 41 Pack 4 -- Pattern-Guided Exploration (context-aware).
                                # Fires only when Pack 3 window is active (same clock, no drift).
                                # sim > 0.7 = stable regime -> exploit; sim < 0.3 = transition -> explore.
                                if getattr(_IKG, 'enable_vsa_pattern_guidance', False) and getattr(_IKG, 'vsa_sw_active_tick', False):
                                    _pg_sim = _IKG.vsa_similarity(_IKG.vsa_event, _IKG.vsa_prev_event)
                                    _IKG.vsa_pg_ticks += 1
                                    if _pg_sim > 0.7:
                                        _sc_approach += _IKG.K_PG
                                        _sc_explore  -= 0.5 * _IKG.K_PG
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _IKG.vsa_pg_high_ticks += 1
                                    elif _pg_sim < 0.3:
                                        _sc_explore  += _IKG.K_PG
                                        _sc_approach -= 0.5 * _IKG.K_PG
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _IKG.vsa_pg_low_ticks += 1
                                    _IKG.vsa_pg_applied += 1
                                # Day 41 Pack 5 -- Micro-Strategy Commitment.
                                # Short-lived hold (ms_duration ticks) strictly within surprise window.
                                # Step 5 (reset) runs first; activate only when sw_timer>0 and ms_timer==0.
                                if getattr(_IKG, 'enable_vsa_micro_strategy', False):
                                    if getattr(_IKG, 'vsa_sw_timer', 0) == 0:
                                        _IKG.vsa_ms_timer = 0
                                        _IKG.vsa_ms_action = None
                                    _ms_direction = None
                                    if getattr(_IKG, 'vsa_sw_active_tick', False):
                                        _ms_sim = _IKG.vsa_similarity(_IKG.vsa_event, _IKG.vsa_prev_event)
                                        if _ms_sim > 0.7:
                                            _ms_direction = 'approach'
                                        elif _ms_sim < 0.3:
                                            _ms_direction = 'explore'
                                    if (getattr(_IKG, 'vsa_sw_timer', 0) > 0 and
                                            _ms_direction is not None and
                                            _IKG.vsa_ms_timer == 0):
                                        _IKG.vsa_ms_timer = _IKG.vsa_ms_duration
                                        _IKG.vsa_ms_action = _ms_direction
                                        _IKG.vsa_ms_activations += 1
                                    if _IKG.vsa_ms_timer > 0:
                                        if _IKG.vsa_ms_action == 'explore':
                                            _sc_explore  += _IKG.K_MS
                                            _sc_approach -= 0.5 * _IKG.K_MS
                                            _sc_approach  = max(0.0, _sc_approach)
                                            _sc_explore   = max(0.0, _sc_explore)
                                        elif _IKG.vsa_ms_action == 'approach':
                                            _sc_approach += _IKG.K_MS
                                            _sc_explore  -= 0.5 * _IKG.K_MS
                                            _sc_approach  = max(0.0, _sc_approach)
                                            _sc_explore   = max(0.0, _sc_explore)
                                        _IKG.vsa_ms_timer -= 1
                                        _IKG.vsa_ms_ticks += 1
                                        _IKG.vsa_ms_active_tick = True
                                # Day 41 Pack 6 -- Cross-Window Continuity Signal (Step 3).
                                # K_CT nudge inside window: repeat context -> explore; new context -> approach.
                                if getattr(_IKG, 'enable_vsa_continuity', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _ct_cont = None
                                    if _IKG.vsa_ct_similarity > 0.7:
                                        _ct_cont = 'repeat'
                                    elif _IKG.vsa_ct_similarity < 0.3:
                                        _ct_cont = 'new'
                                    if _ct_cont == 'repeat':
                                        _sc_explore  += _IKG.K_CT
                                        _sc_approach -= 0.5 * _IKG.K_CT
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _IKG.vsa_ct_mod_ticks += 1
                                    elif _ct_cont == 'new':
                                        _sc_approach += _IKG.K_CT
                                        _sc_explore  -= 0.5 * _IKG.K_CT
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                        _IKG.vsa_ct_mod_ticks += 1
                                # Day 41 Pack 7 -- Repetition-Weighted Modulation (Step 2).
                                # Scales explore nudge by vsa_rw_strength; only in window + repeat context.
                                if (getattr(_IKG, 'enable_vsa_repetition_weighting', False) and
                                        getattr(_IKG, 'vsa_sw_timer', 0) > 0 and
                                        _IKG.vsa_ct_similarity > 0.7):
                                    _rw_delta = _IKG.K_RW * _IKG.vsa_rw_strength
                                    _sc_explore  += _rw_delta
                                    _sc_approach -= 0.5 * _rw_delta
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    _IKG.vsa_rw_ticks += 1
                                    _IKG.vsa_rw_applied += 1
                                # Day 42 Pack 1 Step 3: trajectory directional bias (window only).
                                # delta = K_TR * score; positive -> more explore; negative -> more approach.
                                if getattr(_IKG, 'enable_vsa_trajectory', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _tr_delta = _IKG.K_TR * _IKG.vsa_tr_score
                                    _sc_explore  += _tr_delta
                                    _sc_approach -= 0.5 * _tr_delta
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                    # Day 43 Pack 2: contextual trajectory gating.
                                    # low sim -> ctx_gain=1.5 (boost explore); high sim -> ctx_gain=0.5 (damp).
                                    if getattr(_IKG, 'enable_vsa_tr_context', False):
                                        _tr_sim_ctx = _IKG.vsa_ct_similarity
                                        if _tr_sim_ctx < 0.3:
                                            _tr_ctx_gain = 1.5
                                        elif _tr_sim_ctx > 0.7:
                                            _tr_ctx_gain = 0.5
                                        else:
                                            _tr_ctx_gain = 1.0
                                        _tr_ctx_delta = _IKG.K_TR_CTX * _IKG.vsa_tr_score * _tr_ctx_gain
                                        _sc_explore  += _tr_ctx_delta
                                        _sc_approach -= 0.5 * _tr_ctx_delta
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 3 Step 2: trajectory persistence apply (window only, weakest layer).
                                if getattr(_IKG, 'enable_vsa_tr_persist', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _tr_p_delta = _IKG.K_TR_PERSIST * _IKG.vsa_tr_persist
                                    _sc_explore  += _tr_p_delta
                                    _sc_approach -= 0.5 * _tr_p_delta
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 4 Step 1+2: conflict resolution layer.
                                # Trajectory applied only when top two action scores are close (uncertain state).
                                if getattr(_IKG, 'enable_vsa_tr_conflict', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _tr_c_scores = sorted([_sc_explore, _sc_approach, _sc_wait], reverse=True)
                                    _tr_c_top1 = _tr_c_scores[0]
                                    _tr_c_top2 = _tr_c_scores[1]
                                    _tr_c_conflict = abs(_tr_c_top1 - _tr_c_top2)
                                    _tr_c_is_conflict = _tr_c_conflict < 0.05
                                    if _tr_c_is_conflict:
                                        _tr_c_delta = _IKG.K_TR_CONFLICT * _IKG.vsa_tr_persist
                                        _sc_explore  += _tr_c_delta
                                        _sc_approach -= 0.5 * _tr_c_delta
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 5 Step 1+2: uncertainty-scaled trajectory amplification.
                                # Recomputes gap (same math as Pack 4) to stay independent of its enable flag.
                                # Scales K_TR_UNCERT by uncertainty = 1 - gap/0.2 (high uncertainty -> max scale).
                                if getattr(_IKG, 'enable_vsa_tr_uncertainty', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _tr_u_sorted = sorted([_sc_explore, _sc_approach, _sc_wait], reverse=True)
                                    _tr_u_gap = abs(_tr_u_sorted[0] - _tr_u_sorted[1])
                                    if _tr_u_gap < 0.05:
                                        _tr_uncertainty = min(1.0, max(0.0, 1.0 - (_tr_u_gap / 0.2)))
                                        _tr_u_delta = _IKG.K_TR_UNCERT * _IKG.vsa_tr_persist * _tr_uncertainty
                                        _sc_explore  += _tr_u_delta
                                        _sc_approach -= 0.5 * _tr_u_delta
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 6: Decision Margin Shaping.
                                # Multiplicative: top1 reduced, top2 lifted when scores are close (gap < 0.05).
                                if getattr(_IKG, 'enable_vsa_margin', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _tr_m_all = [('explore', _sc_explore), ('approach', _sc_approach), ('wait', _sc_wait)]
                                    _tr_m_sorted = sorted(_tr_m_all, key=lambda x: -x[1])
                                    _tr_m_top1_name, _tr_m_top1_val = _tr_m_sorted[0]
                                    _tr_m_top2_name, _tr_m_top2_val = _tr_m_sorted[1]
                                    _tr_m_gap = abs(_tr_m_top1_val - _tr_m_top2_val)
                                    if _tr_m_gap < 0.05:
                                        _tr_m_factor = min(1.0, max(0.0, 1.0 - (_tr_m_gap / 0.2)))
                                        _tr_m_top1_new = _tr_m_top1_val * (1.0 - _IKG.K_MARGIN * _tr_m_factor)
                                        _tr_m_top2_new = _tr_m_top2_val * (1.0 + 0.5 * _IKG.K_MARGIN * _tr_m_factor)
                                        if _tr_m_top1_name == 'explore':
                                            _sc_explore  = max(0.0, _tr_m_top1_new)
                                        elif _tr_m_top1_name == 'approach':
                                            _sc_approach = max(0.0, _tr_m_top1_new)
                                        elif _tr_m_top1_name == 'wait':
                                            _sc_wait     = max(0.0, _tr_m_top1_new)
                                        if _tr_m_top2_name == 'explore':
                                            _sc_explore  = max(0.0, _tr_m_top2_new)
                                        elif _tr_m_top2_name == 'approach':
                                            _sc_approach = max(0.0, _tr_m_top2_new)
                                        elif _tr_m_top2_name == 'wait':
                                            _sc_wait     = max(0.0, _tr_m_top2_new)
                                # Day 42 Pack 7 Step 1: consistency bias toward last BG direction.
                                if getattr(_IKG, 'enable_vsa_consistency', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0 and _IKG.vsa_last_action is not None:
                                    if _IKG.vsa_last_action == 'explore':
                                        _sc_explore  *= (1.0 + _IKG.K_CONSIST)
                                    elif _IKG.vsa_last_action == 'approach':
                                        _sc_approach *= (1.0 + _IKG.K_CONSIST)
                                    elif _IKG.vsa_last_action == 'wait':
                                        _sc_wait     *= (1.0 + _IKG.K_CONSIST)
                                # Day 42 Pack 8 Step 2: outcome trace score modulation (window only).
                                if getattr(_IKG, 'enable_vsa_outcome', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _ot_delta = _IKG.K_OUTCOME * _IKG.vsa_outcome
                                    _sc_explore  += _ot_delta
                                    _sc_approach -= 0.5 * _ot_delta
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 9 Step 2: outcome delta modulation (S_real tick + window gate).
                                if getattr(_IKG, 'enable_vsa_outcome_delta', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _ot9_d = _IKG.K_OUTCOME_DELTA * _ot9_delta
                                    _sc_explore  += _ot9_d
                                    _sc_approach -= 0.5 * _ot9_d
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_explore   = max(0.0, _sc_explore)
                                # Day 42 Pack 10: signal alignment boost (window gate).
                                if getattr(_IKG, 'enable_vsa_alignment', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _al_tr  = float(getattr(_IKG, 'vsa_tr_persist', 0.0))
                                    _al_out = float(getattr(_IKG, 'vsa_outcome', 0.0))
                                    _al_del = _ot9_delta
                                    _al_sign_tr  = 1 if _al_tr  > 0 else (-1 if _al_tr  < 0 else 0)
                                    _al_sign_out = 1 if _al_out > 0 else (-1 if _al_out < 0 else 0)
                                    _al_sign_del = 1 if _al_del > 0 else (-1 if _al_del < 0 else 0)
                                    _al_nz = [s for s in [_al_sign_tr, _al_sign_out, _al_sign_del] if s != 0]
                                    if len(_al_nz) >= 2:
                                        _al_pos = _al_nz.count(1)
                                        _al_neg = _al_nz.count(-1)
                                        if _al_pos > _al_neg:
                                            _al_align = 1
                                        elif _al_neg > _al_pos:
                                            _al_align = -1
                                        else:
                                            _al_align = 0
                                        if _al_align != 0:
                                            _al_delta = _IKG.K_ALIGN * _al_align
                                            _sc_explore  += _al_delta
                                            _sc_approach -= 0.5 * _al_delta
                                            _sc_approach  = max(0.0, _sc_approach)
                                            _sc_explore   = max(0.0, _sc_explore)
                                # Day 43 Pack 4: outcome-conditioned action bias (window gate).
                                if getattr(_IKG, 'enable_env_outcome_bias', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _ob_bias = _IKG.K_OUTCOME_BIAS * _IKG.vsa_outcome
                                    _sc_approach += 0.5 * _ob_bias
                                    _sc_wait     += 0.5 * _ob_bias
                                    _sc_explore  -= 0.5 * _ob_bias
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_wait      = max(0.0, _sc_wait)
                                    _sc_explore   = max(0.0, _sc_explore)
                                # Day 43 Pack 6: shift-gated outcome calibration (window gate).
                                if getattr(_IKG, 'enable_env_shift_cal', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    if getattr(_IKG, 'env_shift_count', 0) > 0:
                                        _p6_gap = abs(getattr(_IKG, 'env_shift_rate', 0.0) - getattr(_IKG, 'env_shift_neg_rate', 0.0))
                                        _p6_cal_sign = -1 if _IKG.env_shift_corr < 0 else 1
                                        _IKG.env_shift_cal = _IKG.K_SHIFT_CAL * _p6_cal_sign * (1.0 - min(1.0, _p6_gap))
                                        _sc_approach += 0.25 * _IKG.env_shift_cal
                                        _sc_wait     += 0.25 * _IKG.env_shift_cal
                                        _sc_explore  -= 0.25 * _IKG.env_shift_cal
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_wait      = max(0.0, _sc_wait)
                                        _sc_explore   = max(0.0, _sc_explore)
                                # Day 43 Pack 10: regime-conditioned outcome bias (tiny scale on Pack 4, window gate).
                                if getattr(_IKG, 'enable_env_regime_bias', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _p10_ob_bias = _IKG.K_REGIME_BIAS * _IKG.vsa_outcome * _IKG.env_regime_bias
                                    _sc_approach += 0.5 * _p10_ob_bias
                                    _sc_wait     += 0.5 * _p10_ob_bias
                                    _sc_explore  -= 0.5 * _p10_ob_bias
                                    _sc_approach  = max(0.0, _sc_approach)
                                    _sc_wait      = max(0.0, _sc_wait)
                                    _sc_explore   = max(0.0, _sc_explore)
                                # Day 45 Pack 1: task-to-neural feedback bridge.
                                # Reads previous-tick task acc; weak EMA signal biases action scores.
                                if getattr(_IKG, 'enable_task_feedback', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _p45_total = _IKG.task_correct + _IKG.task_incorrect
                                    if _p45_total > 0:
                                        _p45_acc = _IKG.task_correct / _p45_total
                                        _IKG.task_feedback_signal = _p45_acc - 0.5
                                        _IKG.task_feedback_ema = 0.9 * _IKG.task_feedback_ema + 0.1 * _IKG.task_feedback_signal
                                        _IKG.task_feedback_updates += 1
                                        if _IKG.task_feedback_ema > 0:
                                            _IKG.task_feedback_pos += 1
                                        elif _IKG.task_feedback_ema < 0:
                                            _IKG.task_feedback_neg += 1
                                        _p45_fb = _IKG.K_TASK_FB * _IKG.task_feedback_ema
                                        _sc_approach += 0.5 * _p45_fb
                                        _sc_wait     += 0.5 * _p45_fb
                                        _sc_explore  -= 0.5 * _p45_fb
                                        _sc_approach  = max(0.0, _sc_approach)
                                        _sc_wait      = max(0.0, _sc_wait)
                                        _sc_explore   = max(0.0, _sc_explore)
                                _bg_scores = {'explore': _sc_explore, 'approach': _sc_approach, 'wait': _sc_wait}
                                # Day 42 Pack 11: exploration perturbation under persistent negative outcome.
                                # Isolated RNG (_p11_rng) prevents main-loop random state contamination.
                                if getattr(_IKG, 'enable_vsa_perturb', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0 and getattr(_IKG, 'vsa_outcome', 0.0) < -0.2:
                                    if not hasattr(_IKG, '_p11_rng'):
                                        import random as _p11_rmod
                                        _IKG._p11_rng = _p11_rmod.Random(54321)
                                    if _IKG._p11_rng.random() < _IKG.P_PERTURB:
                                        for _p11_act in _bg_scores:
                                            _bg_scores[_p11_act] *= (1.0 + _IKG.K_PERTURB)
                                # Day 42 Pack 12: boundary-sensitive perturbation (window gate, near-boundary only).
                                # Isolated RNG (_p12_rng) prevents main-loop random state contamination.
                                if getattr(_IKG, 'enable_vsa_perturb2', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0 and getattr(_IKG, 'vsa_outcome', 0.0) < -0.2:
                                    _p12_sorted = sorted(_bg_scores.values(), reverse=True)
                                    _p12_gap = _p12_sorted[0] - _p12_sorted[1] if len(_p12_sorted) >= 2 else 1.0
                                    if _p12_gap < 0.03:
                                        if not hasattr(_IKG, '_p12_rng'):
                                            import random as _p12_rmod
                                            _IKG._p12_rng = _p12_rmod.Random(98765)
                                        if _IKG._p12_rng.random() < _IKG.P_PERTURB2:
                                            _p12_acts = sorted(_bg_scores, key=_bg_scores.get, reverse=True)
                                            _p12_top1 = _p12_acts[0]
                                            _p12_top2 = _p12_acts[1]
                                            _bg_scores[_p12_top1] *= (1.0 - _IKG.K_PERTURB2)
                                            _bg_scores[_p12_top2] *= (1.0 + 0.5 * _IKG.K_PERTURB2)
                                # Day 45 Pack 2: boundary-sensitive task feedback.
                                # Amplified feedback applied ONLY when winner margin < 0.03.
                                if getattr(_IKG, 'enable_task_feedback_boundary', False) and getattr(_IKG, 'enable_task_feedback', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _p2b_sorted = sorted(_bg_scores.values(), reverse=True)
                                    _p2b_gap = _p2b_sorted[0] - _p2b_sorted[1] if len(_p2b_sorted) >= 2 else 1.0
                                    if _p2b_gap < 0.03:
                                        _p2b_winner_pre = max(_bg_scores, key=_bg_scores.get)
                                        _IKG.task_fb_boundary_events += 1
                                        _IKG.task_fb_boundary_delta = _IKG.K_TASK_FB_BOUNDARY * _IKG.task_feedback_ema
                                        _p2b_fb = _IKG.task_fb_boundary_delta
                                        _bg_scores['approach'] = max(0.0, _bg_scores.get('approach', 0.0) + _p2b_fb)
                                        _bg_scores['explore']  = max(0.0, _bg_scores.get('explore', 0.0) - 0.5 * _p2b_fb)
                                        _p2b_winner_post = max(_bg_scores, key=_bg_scores.get)
                                        if _p2b_winner_post != _p2b_winner_pre:
                                            _IKG.task_fb_boundary_flips += 1
                                # Day 46 Pack 3 -- Token-State Behavioral Coupling: apply.
                                # 1-tick-lagged EMA from end-of-tick signal computation.
                                # +EMA (control-heavy) -> stability (approach/wait up, explore down).
                                # -EMA (math-heavy) -> exploration (explore up, approach/wait down).
                                if getattr(_IKG, 'enable_token_behavior', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _p3_delta = _IKG.K_TOKEN_BEHAVIOR * _IKG.token_behavior_ema
                                    _bg_scores['approach'] = max(0.0, _bg_scores.get('approach', 0.0) + 0.5 * _p3_delta)
                                    _bg_scores['wait']     = max(0.0, _bg_scores.get('wait', 0.0)     + 0.5 * _p3_delta)
                                    _bg_scores['explore']  = max(0.0, _bg_scores.get('explore', 0.0)  - 0.5 * _p3_delta)
                                # Day 46 Pack 4 -- Token-Task Feedback: apply.
                                # Extra = K_TOKEN_TASK_FB * task_fb_ema * tt_ema (product of two EMA values).
                                # Positive: ctrl context + good task perf -> stability reinforcement.
                                # Gate requires enable_task_feedback (D45P1 active) AND vsa_sw_timer > 0.
                                if getattr(_IKG, 'enable_token_task_feedback', False) and getattr(_IKG, 'enable_task_feedback', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    _p4_extra = (_IKG.K_TOKEN_TASK_FB * _IKG.task_feedback_ema *
                                                 _IKG.token_task_feedback_ema)
                                    _bg_scores['approach'] = max(0.0, _bg_scores.get('approach', 0.0) + 0.5 * _p4_extra)
                                    _bg_scores['wait']     = max(0.0, _bg_scores.get('wait', 0.0)     + 0.5 * _p4_extra)
                                    _bg_scores['explore']  = max(0.0, _bg_scores.get('explore', 0.0)  - 0.5 * _p4_extra)
                                bg_name = max(_bg_scores, key=_bg_scores.get)
                                if getattr(_IKG, 'enable_vsa_consistency', False):
                                    _IKG.vsa_last_action = bg_name
                                # Day 43 Pack 5 Step 2: action shift correlation (observation only).
                                if getattr(_IKG, 'enable_env_shift', False) and getattr(_IKG, 'vsa_sw_timer', 0) > 0:
                                    if bg_name in ('approach', 'wait'):
                                        _IKG.env_shift_corr += _IKG.vsa_outcome
                                    elif bg_name == 'explore':
                                        _IKG.env_shift_corr -= _IKG.vsa_outcome
                            else:
                                # Pack 2 threshold logic (preserved exactly)
                                if _bg_pe > 0.05:
                                    _bg_base = 'explore'
                                elif top_conf < self.BG_TC_APPROACH:
                                    _bg_base = 'approach'
                                else:
                                    _bg_base = 'wait'
                                if _IKG.enable_bg_credit:
                                    _bg_cred = max(-1.0, min(1.0, float(
                                        getattr(_IKG, 'adjusted_credit_signal', 0.0))))
                                    if _bg_cred < 0.2:
                                        bg_name = 'explore' if _bg_base == 'approach' else _bg_base
                                    else:
                                        bg_name = _bg_base
                                else:
                                    bg_name = _bg_base
                        else:
                            bg_name = 'wait'            # original: consolidate
                    elif top_conf < self.BG_TC_EXPLORE:
                        bg_name = 'explore'             # low confidence: high uncertainty, probe
                    elif top_conf < self.BG_TC_APPROACH:
                        bg_name = 'approach'            # moderate confidence: directed action
                    else:
                        bg_name = 'idle_recover'        # stable near-threshold: hold
                    atype = bg_name
                else:
                    bg_name = str(bg_fallback_action) if bg_fallback_action else 'idle_recover'
                    atype   = 'idle_recover'
                # map BG motor primitives to execution bridge's idle path.
                self.bound_action = {
                    'action_id':           'bg_%s' % bg_name,
                    'action_type':         atype,
                    'target':              bg_name,
                    'source':              'bg_sys',
                    'handler':             'homeostasis_call',
                    'confidence':          0.0,
                    'path':                'fallback_bg',
                    'reasoning_citation':  reasoning_citation,
                }
                self.binding_path       = 'fallback_bg'
                self.binding_confidence = 0.0
                self.binding_reason = 'fallback_bg bg=%s' % bg_name

        # R6 bounded memory history.
        self._history.append({
            'tick':              tick,
            'binding_path':      self.binding_path,
            'binding_confidence':self.binding_confidence,
            'action_id':         self.bound_action.get('action_id') if self.bound_action else None,
            'action_type':       self.bound_action.get('action_type') if self.bound_action else None,
            'handler':           self.bound_action.get('handler') if self.bound_action else None,
            'reasoning_citation':reasoning_citation,
            'binding_reason':    self.binding_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# Day 29 Pack 2 -- Metabolic Cost & Energy Coupling
# Attwell & Laughlin 2001 (brain metabolic budget); Raichle & Gusnard 2002
# (cognitive work is metabolically expensive); Niven & Laughlin 2008
# (energy-efficient neural computation). This pack enforces that reasoning
# justifies its energy cost: useful thinking is cheaper than useless
# thinking, via predicted-EES modulation of a base + chain-depth cost.
# Hard rules:
#   R1 base_cost = 0.02 on every waking tick with reasoning
#   R2 depth_cost = chain_depth * 0.01, chain_depth capped at 6
#   R3 effective_cost = (base_cost + depth_cost) * (1 - predicted_EES)
#   R4 fallback actions: effective_cost *= 0.5 (instinct is cheaper)
#   R5 minimum floor: effective_cost >= 0.005 (no free thinking)
#   R6 cost directly updates AdenosineSystem.level and l23.energy['cortex']
#   R7 bounded memory deque(maxlen=96). Biology tokens excluded from fields.
# Insertion: waking-only, after action_binding_gate.update(),
# before edit_intent_generator.generate().
# ===========================================================================

class PredictedValueEstimator:
    """Estimates predicted EES (expected efficiency of the bound action).
    Formula (frozen):
        predicted_EES = confidence * 0.40
                      + goal_alignment * 0.30
                      + horizon_relevance * 0.20
                      + policy_prior * 0.10
    All factors clamped to [0,1]. Policy prior is derived from the binding
    path ('bound'=0.9, 'fallback_reasoning'=0.5, 'fallback_bg'=0.2).
    deque(maxlen=96)."""

    W_CONF      = 0.40
    W_ALIGN     = 0.30
    W_HORIZON   = 0.20
    W_POLICY    = 0.10

    _POLICY_PRIOR = {
        'bound':              0.90,
        'fallback_reasoning': 0.50,
        'fallback_bg':        0.20,
        'none':               0.00,
    }

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self.predicted_EES = 0.0
        self.estimation_reason = 'init'

    @staticmethod
    def _clamp(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               action_binding_gate,
               action_confidence_evaluator):
        if _IKG.sleeping:
            self.predicted_EES = 0.0
            return

        top = getattr(action_confidence_evaluator, 'top_candidate', None) or {}
        confidence   = self._clamp(float(top.get('confidence',        0.0)))
        goal_align   = self._clamp(float(top.get('goal_alignment',    0.5)))
        horizon_rel  = self._clamp(float(top.get('horizon_relevance', 0.5)))
        path         = str(getattr(action_binding_gate, 'binding_path', 'none'))
        policy_prior = self._clamp(self._POLICY_PRIOR.get(path, 0.0))

        self.predicted_EES = self._clamp(
            confidence  * self.W_CONF    +
            goal_align  * self.W_ALIGN   +
            horizon_rel * self.W_HORIZON +
            policy_prior* self.W_POLICY
        )
        self.estimation_reason = 'EES=%.4f conf=%.3f align=%.3f hor=%.3f pol=%.3f' % (
            self.predicted_EES, confidence, goal_align, horizon_rel, policy_prior)

        self._history.append({
            'tick':              tick,
            'predicted_EES':     round(self.predicted_EES, 4),
            'binding_path':      path,
            'estimation_reason': self.estimation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ReasoningEnergyCostModel:
    """Computes metabolic cost of reasoning per waking tick.
        raw_cost       = BASE_COST + chain_depth * DEPTH_COST_PER_STEP
        effective_cost = raw_cost * (1 - predicted_EES)
        if fallback:     effective_cost *= FALLBACK_DISCOUNT
        effective_cost  = max(effective_cost, COST_FLOOR)
    Chain depth is read from ThoughtChainConstructor.thought_chain and
    capped at CHAIN_DEPTH_CAP = 6 (mirroring Rule 1 of that class).
    deque(maxlen=96)."""

    BASE_COST           = 0.02   # Rule 1 frozen
    DEPTH_COST_PER_STEP = 0.01   # Rule 2 frozen
    CHAIN_DEPTH_CAP     = 6      # mirror ThoughtChainConstructor.CHAIN_DEPTH_CAP
    FALLBACK_DISCOUNT   = 0.5    # Rule 4 frozen
    COST_FLOOR          = 0.005  # Rule 5 frozen

    _FALLBACK_PATHS = frozenset({'fallback_reasoning', 'fallback_bg'})

    def __init__(self, maxlen=96):
        self._maxlen         = maxlen
        self._history        = deque(maxlen=maxlen)
        self.raw_cost        = 0.0
        self.effective_cost  = 0.0
        self.cost_reason     = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               thought_chain_constructor,
               predicted_value_estimator,
               action_binding_gate):
        if _IKG.sleeping:
            self.raw_cost = 0.0
            self.effective_cost = 0.0
            return

        chain        = getattr(thought_chain_constructor, 'thought_chain', []) or []
        chain_depth  = min(len(chain), self.CHAIN_DEPTH_CAP)
        ees          = self._clamp01(getattr(predicted_value_estimator, 'predicted_EES', 0.0))
        path         = str(getattr(action_binding_gate, 'binding_path', 'none'))
        is_fallback  = path in self._FALLBACK_PATHS

        raw_cost       = self.BASE_COST + chain_depth * self.DEPTH_COST_PER_STEP
        effective_cost = raw_cost * (1.0 - ees)
        if is_fallback:
            effective_cost *= self.FALLBACK_DISCOUNT
        if effective_cost < self.COST_FLOOR:
            effective_cost = self.COST_FLOOR

        self.raw_cost       = round(raw_cost, 6)
        self.effective_cost = round(effective_cost, 6)
        self.cost_reason    = 'depth=%d EES=%.3f raw=%.4f eff=%.4f fb=%s' % (
            chain_depth, ees, raw_cost, effective_cost, is_fallback)

        self._history.append({
            'tick':           tick,
            'chain_depth':    chain_depth,
            'predicted_EES':  round(ees, 4),
            'raw_cost':       self.raw_cost,
            'effective_cost': self.effective_cost,
            'is_fallback':    is_fallback,
            'cost_reason':    self.cost_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class EnergyCouplingBridge:
    """Applies the computed reasoning cost to the biological substrate:
        - subtracts from l23.energy['cortex']        (cortical compartment)
        - increments AdenosineSystem.level            (fatigue signal)
        - tracks fatigue_delta as cumulative cortical cost per tick
    ENERGY_TO_ADO_SCALE and ENERGY_TO_COMPARTMENT_SCALE are frozen so the
    biological impact of reasoning is deterministic and auditable. Safe
    bounds: clamps energy to [0,1], adenosine to [0,1], never emits a
    negative delta. deque(maxlen=96)."""

    ENERGY_TO_COMPARTMENT_SCALE = 1.0   # 1:1 of effective_cost into cortex compartment
    ENERGY_TO_ADO_SCALE         = 0.5   # half of cost becomes adenosine rise

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self.energy_delta  = 0.0
        self.adenosine_delta = 0.0
        self.cortex_energy = 1.0
        self.adenosine_level = 0.0
        self.coupling_reason = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               reasoning_energy_cost_model,
               adenosine_system=None,
               cortical_energy_store=None):
        """
        adenosine_system: object with a .level attribute in [0,1].
        cortical_energy_store: dict-like with 'cortex' key in [0,1].
        Both are optional; when absent the deltas are recorded but no
        biological write occurs (useful for unit tests / no-organism runs).
        """
        if _IKG.sleeping:
            self.energy_delta    = 0.0
            self.adenosine_delta = 0.0
            return

        effective_cost = float(getattr(reasoning_energy_cost_model, 'effective_cost', 0.0) or 0.0)
        if effective_cost < 0.0:
            effective_cost = 0.0

        e_delta   = effective_cost * self.ENERGY_TO_COMPARTMENT_SCALE
        ado_delta = effective_cost * self.ENERGY_TO_ADO_SCALE

        # Apply to cortical compartment (clamp to [0,1], never negative).
        if cortical_energy_store is not None and isinstance(cortical_energy_store, dict):
            try:
                cur = float(cortical_energy_store.get('cortex', 1.0))
            except Exception:
                cur = 1.0
            new = self._clamp01(cur - e_delta)
            cortical_energy_store['cortex'] = new
            self.cortex_energy = new
        else:
            self.cortex_energy = self._clamp01(self.cortex_energy - e_delta)

        # Apply to adenosine (clamp to [0,1]).
        if adenosine_system is not None and hasattr(adenosine_system, 'level'):
            try:
                cur_ado = float(adenosine_system.level)
            except Exception:
                cur_ado = 0.0
            new_ado = self._clamp01(cur_ado + ado_delta)
            adenosine_system.level = new_ado
            self.adenosine_level = new_ado
        else:
            self.adenosine_level = self._clamp01(self.adenosine_level + ado_delta)

        self.energy_delta    = round(e_delta,   6)
        self.adenosine_delta = round(ado_delta, 6)
        self.coupling_reason = 'cost=%.4f de=%.4f dado=%.4f cx=%.4f ado=%.4f' % (
            effective_cost, e_delta, ado_delta,
            self.cortex_energy, self.adenosine_level)

        self._history.append({
            'tick':             tick,
            'effective_cost':   round(effective_cost, 6),
            'energy_delta':     self.energy_delta,
            'adenosine_delta':  self.adenosine_delta,
            'cortex_energy':    round(self.cortex_energy, 6),
            'adenosine_level':  round(self.adenosine_level, 6),
            'coupling_reason':  self.coupling_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class CognitiveMetabolicRegulator:
    """Tracks rolling cognitive metabolic state and emits a four-valued
    cognitive_state label based on strain_score. Strain score integrates
    recent cost (EMA) and efficiency ratio (reward over cost placeholder).
    States (strict ordering):
        efficient : strain_score <  0.25
        neutral   : strain_score <  0.50
        strained  : strain_score <  0.75
        overload  : strain_score >= 0.75
    Frozen thresholds. deque(maxlen=96)."""

    EMA_ALPHA        = 0.10
    EFFICIENT_MAX    = 0.25
    NEUTRAL_MAX      = 0.50
    STRAINED_MAX     = 0.75
    # Normalizer: COST_FLOOR..COST_CEIL maps to [0,1] in strain_score.
    COST_CEIL        = 0.12   # raw_cost max is ~0.08; allow headroom

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self.rolling_cost  = 0.0
        self.efficiency_ratio = 1.0
        self.strain_score  = 0.0
        self.cognitive_state = 'efficient'
        self.regulation_reason = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def _classify(self, strain):
        if strain < self.EFFICIENT_MAX: return 'efficient'
        if strain < self.NEUTRAL_MAX:   return 'neutral'
        if strain < self.STRAINED_MAX:  return 'strained'
        return 'overload'

    def update(self, tick,
               reasoning_energy_cost_model,
               predicted_value_estimator,
               energy_coupling_bridge):
        if _IKG.sleeping:
            return

        effective_cost = float(getattr(reasoning_energy_cost_model, 'effective_cost', 0.0) or 0.0)
        ees            = float(getattr(predicted_value_estimator,   'predicted_EES',   0.0) or 0.0)
        ado_level      = float(getattr(energy_coupling_bridge,      'adenosine_level', 0.0) or 0.0)

        # EMA of cost.
        self.rolling_cost = (1.0 - self.EMA_ALPHA) * self.rolling_cost + self.EMA_ALPHA * effective_cost

        # Efficiency ratio: predicted EES over normalised cost (placeholder reward).
        norm_cost = min(1.0, effective_cost / max(1e-9, self.COST_CEIL))
        self.efficiency_ratio = self._clamp01((ees + 0.1) / (norm_cost + 0.1))

        # Strain score: blends normalised rolling cost, adenosine, and inverse efficiency.
        norm_rolling = min(1.0, self.rolling_cost / max(1e-9, self.COST_CEIL))
        strain = (
            norm_rolling          * 0.40 +
            self._clamp01(ado_level) * 0.40 +
            (1.0 - self.efficiency_ratio) * 0.20
        )
        self.strain_score    = self._clamp01(strain)
        self.cognitive_state = self._classify(self.strain_score)
        self.regulation_reason = 'state=%s strain=%.4f roll=%.4f eff=%.4f' % (
            self.cognitive_state, self.strain_score, self.rolling_cost, self.efficiency_ratio)

        self._history.append({
            'tick':             tick,
            'rolling_cost':     round(self.rolling_cost,     6),
            'efficiency_ratio': round(self.efficiency_ratio, 4),
            'strain_score':     round(self.strain_score,     4),
            'cognitive_state':  self.cognitive_state,
            'regulation_reason':self.regulation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# Day 29 Pack 3 -- Outcome Credit & Reality-Based Pruning
# Sutton & Barto 1998 (reward prediction error, TD-learning); Rescorla &
# Wagner 1972 (prediction error drives associative updating); Kahneman &
# Tversky 1979 (outcome-based evaluation, not expectation). This pack
# replaces coherence-based branch survival with reality-based pruning:
# branches are reinforced or decayed strictly by prediction error and
# actual reward, not by reasoning quality or explanation depth.
# Hard rules:
#   R1 prediction_error = actual_reward - predicted_EES
#   R2 credit = prediction_error * 0.60 + actual_reward * 0.40, clamp[-1,1]
#   R3 new_weight = old_weight * (1 + K * prediction_error), K=0.5
#   R4 hard decay: if prediction_error <= -0.10 then new_weight *= 0.5
#   R5 survival threshold: branch inactive if new_weight < 0.20
#   R6 no logic override: branch survival depends ONLY on outcome signals
#   R7 bounded memory deque(maxlen=96). Biology tokens excluded from fields.
# Insertion: waking-only, after cognitive_metabolic_regulator.update(),
# before edit_intent_generator.generate().
# ===========================================================================

class OutcomeEvaluator:
    """Computes actual_reward from observable environmental signals.
    Formula (frozen):
        actual_reward = energy_gain    * 0.40
                      + goal_progress  * 0.30
                      + stability      * 0.20
                      - fatigue_increase * 0.10
    Clamped [0, 1].
    Inputs derived from upstream Pack 2 objects (no direct biology write).
    deque(maxlen=96)."""

    W_ENERGY    = 0.40
    W_GOAL      = 0.30
    W_STABILITY = 0.20
    W_FATIGUE   = 0.10

    # Normalisation constant: effective_cost up to ~0.12 maps to [0,1].
    ENERGY_COST_NORM = 0.12

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self.actual_reward = 0.0
        self.reward_reason = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               energy_coupling_bridge,
               action_binding_gate,
               cognitive_metabolic_regulator):
        if _IKG.sleeping:
            self.actual_reward = 0.0
            return

        # energy_gain: inverse of normalised energy cost
        # (spending little energy = high gain in this tick)
        e_delta   = float(getattr(energy_coupling_bridge, 'energy_delta', 0.0) or 0.0)
        energy_gain = self._clamp01(1.0 - e_delta / max(1e-9, self.ENERGY_COST_NORM))

        # goal_progress: binding confidence as proxy for how well the
        # organism committed to a purposeful action
        goal_progress = self._clamp01(
            float(getattr(action_binding_gate, 'binding_confidence', 0.0) or 0.0))

        # stability: efficiency ratio from metabolic regulator
        stability = self._clamp01(
            float(getattr(cognitive_metabolic_regulator, 'efficiency_ratio', 0.5) or 0.5))

        # fatigue_increase: adenosine delta (higher = more tired = worse)
        ado_delta    = float(getattr(energy_coupling_bridge, 'adenosine_delta', 0.0) or 0.0)
        fatigue_norm = self._clamp01(ado_delta / max(1e-9, self.ENERGY_COST_NORM * 0.5))

        self.actual_reward = self._clamp01(
            energy_gain    * self.W_ENERGY    +
            goal_progress  * self.W_GOAL      +
            stability      * self.W_STABILITY -
            fatigue_norm   * self.W_FATIGUE
        )
        self.reward_reason = 'rwd=%.4f eg=%.3f gp=%.3f stb=%.3f fat=%.3f' % (
            self.actual_reward, energy_gain, goal_progress, stability, fatigue_norm)

        self._history.append({
            'tick':          tick,
            'actual_reward': round(self.actual_reward, 4),
            'energy_gain':   round(energy_gain,    4),
            'goal_progress': round(goal_progress,  4),
            'stability':     round(stability,      4),
            'fatigue_norm':  round(fatigue_norm,   4),
            'reward_reason': self.reward_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class OutcomeCreditAssigner:
    """Assigns credit based on prediction error (R1) and actual reward (R2).
        prediction_error = actual_reward - predicted_EES   (R1)
        credit = prediction_error * 0.60 + actual_reward * 0.40  (R2)
    Credit is clamped to [-1, 1]. Positive credit signals the prediction
    was conservative (reward exceeded expectation). Negative credit signals
    overconfidence (reward fell short). deque(maxlen=96)."""

    W_PE     = 0.60   # Rule 2 frozen
    W_REWARD = 0.40   # Rule 2 frozen

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.prediction_error = 0.0
        self.credit           = 0.0
        self.credit_reason    = 'init'

    @staticmethod
    def _clamp11(v): return max(-1.0, min(1.0, float(v)))

    def update(self, state):
        """Unified interface (Day 32). Delegates to _update_internal()."""
        return self._update_internal(
            tick                      = state.tick,
            outcome_evaluator         = state.outcome_evaluator,
            predicted_value_estimator = state.predicted_value_estimator,
        )

    def _update_internal(self, tick,
                         outcome_evaluator,
                         predicted_value_estimator):
        if _IKG.sleeping:
            self.prediction_error = 0.0
            self.credit           = 0.0
            return

        actual_reward = float(getattr(outcome_evaluator,          'actual_reward', 0.0) or 0.0)
        predicted_EES = float(getattr(predicted_value_estimator,  'predicted_EES', 0.0) or 0.0)

        self.prediction_error = self._clamp11(actual_reward - predicted_EES)
        self.credit           = self._clamp11(
            self.prediction_error * self.W_PE +
            actual_reward         * self.W_REWARD
        )
        self.credit_reason = 'pe=%.4f credit=%.4f rwd=%.4f EES=%.4f' % (
            self.prediction_error, self.credit, actual_reward, predicted_EES)

        self._history.append({
            'tick':             tick,
            'prediction_error': round(self.prediction_error, 4),
            'credit':           round(self.credit,           4),
            'actual_reward':    round(actual_reward,         4),
            'predicted_EES':    round(predicted_EES,         4),
            'credit_reason':    self.credit_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# TEMPORAL CREDIT BRIDGE  (Day 33 Pack 1 -- Prince Siddhpara 2026)
# Read-only signal layer. Tracks short action sequences and computes a
# temporally-discounted credit signal for multi-step causal attribution.
#
# Activation: _IKG.enable_temporal_bridge (default False -- full bypass)
# Writes ONLY: _IKG.temporal_credit_signal, _IKG.temporal_depth
# Reads:  action_binding_gate.bound_action, predicted_value_estimator,
#         outcome_evaluator, _IKG.l23
# Rules:
#   R1  Sleeping guard -- skip entirely when _IKG.sleeping
#   R2  Bypass guard  -- skip entirely when not _IKG.enable_temporal_bridge
#   R3  Buffer maxlen = 10 (frozen)
#   R4  Decay base    = 0.85 per step distance from outcome (frozen)
#   R5  Zero side effects -- no writes to any existing system attribute
#   R6  deque(maxlen=10)
#   R7  to_dict / from_dict serialise _trace_buffer
# ===========================================================================

class TemporalCreditBridge:
    """
    Parallel temporal credit pathway for multi-step causal attribution.

    Maintains a rolling buffer of the last 10 waking ticks. When
    outcome_evaluator.actual_reward becomes available (non-zero), computes
    a decay-weighted temporal credit signal across buffered actions and
    writes it to _IKG.temporal_credit_signal / _IKG.temporal_depth.

    Does NOT modify any existing system. Read-only signal generation only.
    """

    BUFFER_MAXLEN  = 10    # frozen R3
    DECAY_BASE     = 0.85  # frozen R4

    def __init__(self):
        self._trace_buffer = deque(maxlen=self.BUFFER_MAXLEN)
        self.temporal_credit_signal = 0.0
        self.temporal_depth         = 0

    # ------------------------------------------------------------------
    # Public interface
    # ------------------------------------------------------------------

    def update(self, state: IkigaiState):
        """Unified interface (Day 33). Full bypass when bridge disabled."""
        if _IKG.sleeping:
            return
        if not _IKG.enable_temporal_bridge:
            return

        tick      = state.tick
        abg       = getattr(state, 'action_binding_gate', None)
        pve       = getattr(state, 'predicted_value_estimator', None)
        oe        = getattr(state, 'outcome_evaluator', None)

        bound_act    = getattr(abg, 'bound_action', None) or {}
        action_id    = str(bound_act.get('action_id',   'unknown'))
        action_type  = str(bound_act.get('action_type', 'unknown'))
        confidence   = float(bound_act.get('confidence', 0.0))
        pred_EES     = float(getattr(pve, 'predicted_EES', 0.0) or 0.0)

        l23          = _IKG.l23
        _raw_energy  = getattr(l23, 'energy', 0.0) if l23 is not None else 0.0
        if isinstance(_raw_energy, dict):
            _ev = list(_raw_energy.values())
            energy = float(sum(_ev) / len(_ev)) if _ev else 0.0
        else:
            energy = float(_raw_energy) if _raw_energy is not None else 0.0

        self._trace_buffer.append({
            'tick':          int(tick),
            'action_id':     action_id,
            'action_type':   action_type,
            'confidence':    float(round(confidence, 6)),
            'predicted_EES': float(round(pred_EES,  6)),
            'energy_before': float(round(energy,    6)),
        })

        actual_reward = float(getattr(oe, 'actual_reward', 0.0) or 0.0)
        if actual_reward != 0.0 and len(self._trace_buffer) > 0:
            self._compute_temporal_credit(actual_reward)

    # ------------------------------------------------------------------
    # Internal
    # ------------------------------------------------------------------

    def _compute_temporal_credit(self, actual_reward):
        buf   = list(self._trace_buffer)
        n     = len(buf)
        total = 0.0
        for i, _ in enumerate(buf):
            step_distance = n - 1 - i      # 0 = most recent, n-1 = oldest
            decay  = self.DECAY_BASE ** step_distance
            total += actual_reward * decay
        self.temporal_credit_signal      = float(round(total, 6))
        self.temporal_depth              = n
        _IKG.temporal_credit_signal      = self.temporal_credit_signal
        _IKG.temporal_depth              = self.temporal_depth

    # ------------------------------------------------------------------
    # Accessors
    # ------------------------------------------------------------------

    def latest_trace(self):
        return list(self._trace_buffer)

    def __len__(self):
        return len(self._trace_buffer)

    def to_dict(self):
        return {
            'temporal_credit_signal': self.temporal_credit_signal,
            'temporal_depth':         self.temporal_depth,
            'trace_buffer':           list(self._trace_buffer),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls()
        obj.temporal_credit_signal = float(d.get('temporal_credit_signal', 0.0))
        obj.temporal_depth         = int(d.get('temporal_depth', 0))
        for rec in d.get('trace_buffer', []):
            obj._trace_buffer.append(rec)
        return obj


# ===========================================================================
# TEMPORAL INTEGRATION LAYER  (Day 33 Pack 2 -- Prince Siddhpara 2026)
# Additive temporal credit correction at the OutcomeCreditAssigner output stage.
#
# Activation: _IKG.enable_temporal_integration (default False -- full bypass)
# Reads:  outcome_credit_assigner.credit, _IKG.temporal_credit_signal,
#         _IKG.temporal_depth
# Writes: _IKG.adjusted_credit_signal (read-only for downstream)
# Rules:
#   R1  Bypass guard  -- when disabled, adjusted_credit = base_credit exactly
#   R2  Sleeping guard -- when sleeping, adjusted_credit = base_credit exactly
#   R3  TEMPORAL_WEIGHT_MAX = 0.15 (frozen) -- absolute max temporal contribution
#   R4  depth_factor = min(temporal_depth / 10.0, 1.0) (frozen)
#   R5  adjustment = normalized_temporal * temporal_weight
#   R6  adjusted_credit = base_credit*(1-temporal_weight) + adjustment
#   R7  adjusted_credit clamped to [-1.0, 1.0]
#   R8  No modification of OutcomeCreditAssigner or any existing system
#   R9  deque(maxlen=64) for history
#   R10 to_dict / from_dict serialise history
# ===========================================================================

class TemporalIntegrationLayer:
    """
    Additive temporal credit correction layer.

    Reads OutcomeCreditAssigner.credit and the temporal credit signal from
    _IKG, then computes a bounded adjusted credit. The base credit is NEVER
    replaced; the adjustment is additive and bounded by TEMPORAL_WEIGHT_MAX.

    Does NOT write to OutcomeCreditAssigner or any other existing system.
    """

    TEMPORAL_WEIGHT_MAX = 0.15   # frozen R3 -- absolute max temporal contribution

    def __init__(self, maxlen=64):
        self.adjusted_credit  = 0.0
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)

    @staticmethod
    def _clamp(v, lo, hi):
        return lo if v < lo else (hi if v > hi else v)

    def update(self, state: IkigaiState):
        """Unified interface (Day 33). Full bypass when integration disabled."""
        oca        = getattr(state, 'outcome_credit_assigner', None)
        base_credit = float(getattr(oca, 'credit', 0.0) if oca is not None else 0.0)

        # R1 bypass -- disabled or sleeping -> pass through unchanged
        if _IKG.sleeping or not _IKG.enable_temporal_integration:
            self.adjusted_credit       = base_credit
            _IKG.adjusted_credit_signal = self.adjusted_credit
            return

        tick = state.tick

        # R4 depth factor
        depth_factor    = min(_IKG.temporal_depth / 10.0, 1.0)

        # R7 final temporal weight
        temporal_weight = self.TEMPORAL_WEIGHT_MAX * depth_factor

        # R5 normalise signal to [-1, 1] -- clamp preserves magnitude for
        # |signal| <= 1 and caps large values; small signals stay small.
        raw_signal      = _IKG.temporal_credit_signal
        normalized      = self._clamp(raw_signal, -1.0, 1.0)

        # R6 pure additive correction -- spec: "adding a small correction"
        # Net shift = normalized * temporal_weight (strictly bounded by w_max)
        adjustment      = normalized * temporal_weight
        blended         = base_credit + adjustment

        # R7 safety clamp
        self.adjusted_credit = self._clamp(blended, -1.0, 1.0)

        # Write to context -- downstream packs may read
        _IKG.adjusted_credit_signal = self.adjusted_credit

        self._history.append({
            'tick':           int(tick),
            'base_credit':    float(round(base_credit,        6)),
            'temporal_signal':float(round(raw_signal,         6)),
            'depth_factor':   float(round(depth_factor,       6)),
            'temporal_weight':float(round(temporal_weight,    6)),
            'adjusted_credit':float(round(self.adjusted_credit, 6)),
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def recent(self, n=10):
        buf = list(self._history)
        return buf[-n:] if n < len(buf) else buf

    def __len__(self):
        return len(self._history)

    def to_dict(self):
        return {
            'maxlen':          self._maxlen,
            'adjusted_credit': self.adjusted_credit,
            'history':         list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 64)))
        obj.adjusted_credit = float(d.get('adjusted_credit', 0.0))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# Day 33 Pack 3 -- Selective Ignition Layer
# Frozen constants:
#   R1  enable_selective_ignition=False  default OFF
#   R2  IGNITION_MAX_BIAS = 0.10         hard bound on bias magnitude
#   R3  temporal_depth >= 3              minimum trace depth gate
#   R4  0.3 <= base_confidence <= 0.8    mid-band confidence gate
#   R5  strain_score < 0.75              no ignition under overload
#   R6  energy > 0.3                     no ignition during energy deficit
#   R7  bias = signal * MAX_BIAS * depth_factor   pure additive
#   R8  ignited_confidence clamped [0.0, 1.0]
#   R9  no side effects on ConfidenceCalibrator or any existing system
#   R10 to_dict / from_dict serialisation
# ===========================================================================

class SelectiveIgnitionLayer:
    """
    Gated, additive temporal bias on calibrated confidence.

    Reads ConfidenceCalibrator.calibrated_confidence and adds a small
    temporal bias when ALL gate conditions are met. Base confidence is
    NEVER replaced; the adjustment is additive and bounded by IGNITION_MAX_BIAS.

    Does NOT write to ConfidenceCalibrator or any other existing system.
    Only writes to _IKG.ignited_confidence_signal.
    """

    IGNITION_MAX_BIAS = 0.10   # frozen R2 -- absolute max bias magnitude

    def __init__(self):
        self.ignited_confidence = 0.0

    @staticmethod
    def _clamp(v, lo, hi):
        return lo if v < lo else (hi if v > hi else v)

    @staticmethod
    def _mean_energy(l23):
        """Return scalar mean energy from l23 (handles dict or float)."""
        if l23 is None:
            return None
        e = getattr(l23, 'energy', None)
        if e is None:
            return None
        if isinstance(e, dict):
            return sum(e.values()) / max(len(e), 1)
        return float(e)

    def update(self, state: IkigaiState):
        """Unified interface (Day 33). Full bypass when ignition disabled."""
        cc  = getattr(state, 'confidence_calibrator', None)
        base_confidence = float(
            getattr(cc, 'calibrated_confidence', 0.60) if cc is not None else 0.60
        )

        # R1 bypass -- disabled or sleeping -> exact pass-through
        if _IKG.sleeping or not _IKG.enable_selective_ignition:
            self.ignited_confidence        = base_confidence
            _IKG.ignited_confidence_signal = self.ignited_confidence
            return

        # R5 overload check
        cmr = getattr(state, 'cognitive_metabolic_regulator', None)
        strain_score = float(getattr(cmr, 'strain_score', 0.0) if cmr is not None else 0.0)
        overload = strain_score >= 0.75

        # R6 energy check -- l23.energy may be dict {cortex,limbic,motor}; take mean
        energy = self._mean_energy(_IKG.l23)

        # All gates must pass
        allow_ignition = (
            _IKG.temporal_depth >= 3 and
            0.3 <= base_confidence <= 0.8 and
            not overload and
            energy is not None and energy > 0.3
        )

        if allow_ignition:
            # R7 -- pure additive bias
            signal       = self._clamp(_IKG.adjusted_credit_signal, -1.0, 1.0)
            depth_factor = min(_IKG.temporal_depth / 10.0, 1.0)
            bias         = signal * self.IGNITION_MAX_BIAS * depth_factor
            ignited      = base_confidence + bias
        else:
            ignited = base_confidence

        # R8 output clamp
        self.ignited_confidence        = self._clamp(ignited, 0.0, 1.0)
        _IKG.ignited_confidence_signal = self.ignited_confidence

    def to_dict(self):
        return {'ignited_confidence': self.ignited_confidence}

    @classmethod
    def from_dict(cls, d):
        obj = cls()
        obj.ignited_confidence = float(d.get('ignited_confidence', 0.0))
        return obj


# ===========================================================================
# Day 33 Pack 4 -- Decision Bridge Layer
# Frozen constants:
#   R1  enable_decision_bridge=False   default OFF
#   R2  DECISION_WINDOW_LOW  = 0.55    near-threshold band lower bound
#   R3  DECISION_WINDOW_HIGH = 0.65    near-threshold band upper bound
#   R4  IGNITION_THRESHOLD   = 0.05    minimum ignition_delta to allow override
#   R5  temporal_depth >= 3            minimum trace depth requirement
#   R6  strain_score < 0.75            no override under overload
#   R7  energy > 0.3                   no override during energy deficit
#   R8  override_bind = True ONLY when ALL conditions pass
#   R9  no modification to ActionBindingGate, ConfidenceCalibrator, or any
#       existing system internal logic
#   R10 to_dict / from_dict serialisation
# ===========================================================================

class DecisionBridgeLayer:
    """
    Gated, local influence of temporal ignition on action binding decisions.

    When ALL conditions are met, sets _IKG.override_bind_signal = True.
    The integration call site reads this flag and temporarily lifts
    action_confidence_evaluator.top_confidence to at least BINDING_THRESHOLD
    before passing to ActionBindingGate. ActionBindingGate is NOT modified.

    Influence is strictly local: only near-threshold confidence values in
    the band [DECISION_WINDOW_LOW, DECISION_WINDOW_HIGH] with sufficient
    ignition delta and trace depth can be affected.
    """

    DECISION_WINDOW_LOW  = 0.55   # frozen R2
    DECISION_WINDOW_HIGH = 0.65   # frozen R3
    IGNITION_THRESHOLD   = 0.05   # frozen R4

    def __init__(self):
        self.override_bind = False
        self._prev_depth   = 0

    @staticmethod
    def _clamp(v, lo, hi):
        return lo if v < lo else (hi if v > hi else v)

    @staticmethod
    def _mean_energy(l23):
        """Return scalar mean energy from l23 (handles dict or float)."""
        if l23 is None:
            return None
        e = getattr(l23, 'energy', None)
        if e is None:
            return None
        if isinstance(e, dict):
            return sum(e.values()) / max(len(e), 1)
        return float(e)

    def update(self, state: IkigaiState):
        """Evaluate override condition. Always resets to False first."""
        self.override_bind        = False
        _IKG.override_bind_signal = False

        # R1 bypass
        if not _IKG.enable_decision_bridge:
            return

        if _IKG.sleeping:
            return

        # R6 overload guard
        cmr = getattr(state, 'cognitive_metabolic_regulator', None)
        strain_score = float(getattr(cmr, 'strain_score', 0.0) if cmr is not None else 0.0)
        if strain_score >= 0.75:
            return

        # R7 energy guard -- l23.energy may be dict {cortex,limbic,motor}; take mean
        energy = self._mean_energy(_IKG.l23)
        if energy is None or energy <= 0.3:
            return

        # Read top_confidence from ActionConfidenceEvaluator
        ace = getattr(state, 'action_confidence_evaluator', None)
        top_confidence = float(
            getattr(ace, 'top_confidence', 0.0) if ace is not None else 0.0
        )

        # R2/R3 near-threshold band gate
        near_threshold  = (self.DECISION_WINDOW_LOW <= top_confidence <= self.DECISION_WINDOW_HIGH)

        # R4 event-detection gate (Pack 5 fix)
        # Gate on depth CHANGE not magnitude -- fires only when temporal context
        # deepens (new sequence step), not on every tick where signal merely persists.
        temporal_depth  = _IKG.temporal_depth
        depth_change    = temporal_depth - self._prev_depth
        event_strength  = max(depth_change, 0)
        ignition_strong = event_strength >= 1

        # R5 depth gate
        depth_ok = temporal_depth >= 3

        if near_threshold and ignition_strong and depth_ok:
            self.override_bind        = True
            _IKG.override_bind_signal = True

        self._prev_depth = temporal_depth

    def to_dict(self):
        return {'override_bind': self.override_bind, 'prev_depth': self._prev_depth}

    @classmethod
    def from_dict(cls, d):
        obj = cls()
        obj.override_bind = bool(d.get('override_bind', False))
        obj._prev_depth   = int(d.get('prev_depth', 0))
        return obj


class BranchWeightUpdater:
    """Updates branch weights using prediction error (Rules 3-4).
    Tracks five canonical branches (action types from Pack 1 bridge):
        edit_code, run_experiment, update_memory, idle_recover, bound_reasoning
    Update rule (R3):
        new_weight = old_weight * (1 + K * prediction_error),  K = 0.50
    Hard-decay (R4): if prediction_error <= HARD_DECAY_THRESHOLD (-0.10):
        new_weight *= HARD_DECAY_FACTOR (0.5)
    Weights are clamped to [0.01, 1.0] to prevent underflow while allowing
    near-extinction. The currently-bound action branch receives the update;
    all others remain unchanged this tick. deque(maxlen=96)."""

    K                   = 0.50   # Rule 3 frozen
    HARD_DECAY_THRESHOLD= -0.10  # Rule 4 frozen
    HARD_DECAY_FACTOR   = 0.50   # Rule 4 frozen
    WEIGHT_FLOOR        = 0.01   # clamp floor (not the pruning threshold)
    WEIGHT_CEIL         = 1.00

    _BRANCH_SEEDS = ('edit_code', 'run_experiment',
                     'update_memory', 'idle_recover', 'bound_reasoning')

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.weights        = {b: 0.50 for b in self._BRANCH_SEEDS}
        self.updated_weights= dict(self.weights)
        self.weight_reason  = 'init'

    @staticmethod
    def _clamp(v, lo, hi): return max(lo, min(hi, float(v)))

    def update(self, tick,
               outcome_credit_assigner,
               action_binding_gate):
        if _IKG.sleeping:
            return

        pe       = float(getattr(outcome_credit_assigner, 'prediction_error', 0.0) or 0.0)
        bound_act= getattr(action_binding_gate, 'bound_action', None) or {}
        atype    = str(bound_act.get('action_type', 'idle_recover'))
        path     = str(getattr(action_binding_gate, 'binding_path', 'none'))

        # Map bound action to a branch key.
        branch_key = atype if atype in self.weights else 'bound_reasoning'
        if path in ('bound',):
            branch_key = 'bound_reasoning'

        old_w  = self.weights.get(branch_key, 0.50)
        new_w  = old_w * (1.0 + self.K * pe)
        if pe <= self.HARD_DECAY_THRESHOLD:
            new_w *= self.HARD_DECAY_FACTOR
        new_w  = self._clamp(new_w, self.WEIGHT_FLOOR, self.WEIGHT_CEIL)

        self.weights[branch_key] = new_w
        self.updated_weights     = dict(self.weights)
        self.weight_reason = 'branch=%s old=%.4f pe=%.4f new=%.4f' % (
            branch_key, old_w, pe, new_w)

        self._history.append({
            'tick':           tick,
            'branch_key':     branch_key,
            'old_weight':     round(old_w, 4),
            'new_weight':     round(new_w, 4),
            'prediction_error': round(pe,  4),
            'hard_decay':     pe <= self.HARD_DECAY_THRESHOLD,
            'weight_reason':  self.weight_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class RealityDrivenPruner:
    """Deactivates branches whose weight falls below SURVIVAL_THRESHOLD (R5).
    Rule 6 (no logic override): survival depends exclusively on weight, which
    is updated only by prediction error / outcome credit -- never by coherence,
    depth, or explanation quality. Safety rule: at least 1 branch must remain
    active; if all weights are below threshold, the highest-weight branch is
    kept as the last survivor. deque(maxlen=96)."""

    SURVIVAL_THRESHOLD = 0.20   # Rule 5 frozen

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.active_branches = []
        self.pruned_branches = []
        self.prune_reason    = 'init'

    def update(self, tick, branch_weight_updater):
        if _IKG.sleeping:
            return

        weights = dict(getattr(branch_weight_updater, 'updated_weights', {}) or {})
        if not weights:
            return

        active  = [b for b, w in weights.items() if w >= self.SURVIVAL_THRESHOLD]
        pruned  = [b for b, w in weights.items() if w <  self.SURVIVAL_THRESHOLD]

        # Safety: guarantee at least one survivor (Rule 6 + safety).
        if not active:
            survivor = max(weights, key=lambda b: weights[b])
            active   = [survivor]
            pruned   = [b for b in weights if b != survivor]

        self.active_branches = active
        self.pruned_branches = pruned
        self.prune_reason    = 'active=%d pruned=%d branches=[%s]' % (
            len(active), len(pruned), ','.join(active[:4]))

        self._history.append({
            'tick':            tick,
            'n_active':        len(active),
            'n_pruned':        len(pruned),
            'active_branches': list(active),
            'pruned_branches': list(pruned),
            'prune_reason':    self.prune_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# Day 29 Pack 4 -- Memory-Guided Cognition & Neural Retrieval Layer
# Tulving 1983 (episodic memory); Hopfield 1982 (associative recall /
# content-addressable memory); Kahana 2012 (contextual retrieval and
# recency-weighted similarity). This pack closes the first true adaptive
# loop: action -> cost -> outcome -> memory -> improved action, by
# retrieving past episodes relevant to the current tick's context and
# modulating confidence according to their actual outcomes rather than
# predicted EES alone.
# Hard rules:
#   R1 MAX_RETRIEVAL = 5 (sparse retrieval only)
#   R2 RELEVANCE_MIN = 0.40 (sub-threshold memories discarded)
#   R3 recency weight = 1 / (1 + age * 0.05)
#   R4 outcome priority: |prediction_error| boosts retention
#   R5 adjusted_confidence = base*0.70 + memory_support*0.30
#   R6 indexer memory deque(maxlen=256); support classes deque(maxlen=96)
#   R7 biology tokens excluded from derived field values
# Insertion: waking-only, after reality_driven_pruner.update(),
# before edit_intent_generator.generate().
# ===========================================================================

class EpisodicMemoryIndexer:
    """Stores one episodic record per waking tick:
        {tick, action_type, action_id, target,
         predicted_EES, actual_reward, prediction_error,
         context_signature, outcome_class, credit}
    context_signature is a compact string built from (cognitive_state,
    action_type, binding_path) -- sufficient for context_similarity under
    the relevance scorer. outcome_class is a coarse label ('success',
    'failure', 'neutral') derived from credit sign. deque(maxlen=256)."""

    _INDEX_MAXLEN = 256

    def __init__(self, maxlen=256):
        self._maxlen   = maxlen
        self.records   = deque(maxlen=maxlen)
        self.index_reason = 'init'

    @staticmethod
    def _classify_outcome(credit):
        if credit >=  0.10: return 'success'
        if credit <= -0.10: return 'failure'
        return 'neutral'

    def update(self, tick,
               action_binding_gate,
               predicted_value_estimator,
               outcome_evaluator,
               outcome_credit_assigner,
               cognitive_metabolic_regulator):
        if _IKG.sleeping:
            return

        bound_act = getattr(action_binding_gate, 'bound_action', None) or {}
        action_type = str(bound_act.get('action_type', 'idle_recover'))
        action_id   = str(bound_act.get('action_id',   'none'))
        target      = str(bound_act.get('target',      'none'))
        path        = str(getattr(action_binding_gate, 'binding_path', 'none'))
        cog_state   = str(getattr(cognitive_metabolic_regulator, 'cognitive_state', 'efficient'))

        predicted_EES   = float(getattr(predicted_value_estimator,  'predicted_EES',   0.0) or 0.0)
        actual_reward   = float(getattr(outcome_evaluator,          'actual_reward',   0.0) or 0.0)
        prediction_error= float(getattr(outcome_credit_assigner,    'prediction_error',0.0) or 0.0)
        credit          = float(getattr(outcome_credit_assigner,    'credit',          0.0) or 0.0)

        context_signature = '%s|%s|%s' % (cog_state, action_type, path)
        outcome_class     = self._classify_outcome(credit)

        rec = {
            'tick':              tick,
            'action_type':       action_type,
            'action_id':         action_id,
            'target':            target,
            'predicted_EES':     round(predicted_EES, 4),
            'actual_reward':     round(actual_reward, 4),
            'prediction_error':  round(prediction_error, 4),
            'credit':            round(credit, 4),
            'context_signature': context_signature,
            'outcome_class':     outcome_class,
        }
        self.records.append(rec)
        self.index_reason = 'tick=%d act=%s out=%s pe=%.3f' % (
            tick, action_type, outcome_class, prediction_error)

    def latest(self):
        return self.records[-1] if self.records else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'records': list(self.records)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('records', []):
            obj.records.append(rec)
        return obj


class MemoryRelevanceScorer:
    """Scores each indexed memory against the current tick's context.
    Formula (frozen):
        relevance = context_similarity * 0.40
                  + outcome_magnitude  * 0.30
                  + recency            * 0.20
                  + action_match       * 0.10
    context_similarity: token-overlap over signature parts.
    outcome_magnitude : |prediction_error| (clamped).
    recency           : 1 / (1 + age * 0.05), Rule 3.
    action_match      : 1.0 if action_type matches current, else 0.0.
    deque(maxlen=96). Biology tokens excluded from fields."""

    W_CTX     = 0.40
    W_OUTCOME = 0.30
    W_RECENCY = 0.20
    W_ACTION  = 0.10
    RECENCY_DECAY = 0.05   # Rule 3 frozen

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.scored_memories= []
        self.scoring_reason = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _context_similarity(sig_a, sig_b):
        if not sig_a or not sig_b: return 0.0
        toks_a = set(str(sig_a).split('|'))
        toks_b = set(str(sig_b).split('|'))
        if not toks_a or not toks_b: return 0.0
        inter = toks_a & toks_b
        union = toks_a | toks_b
        return len(inter) / max(1, len(union))

    def update(self, tick,
               episodic_memory_indexer,
               action_binding_gate,
               cognitive_metabolic_regulator):
        if _IKG.sleeping:
            self.scored_memories = []
            return

        records = list(getattr(episodic_memory_indexer, 'records', []) or [])
        if not records:
            self.scored_memories = []
            return

        bound_act = getattr(action_binding_gate, 'bound_action', None) or {}
        cur_action = str(bound_act.get('action_type', 'idle_recover'))
        cur_path   = str(getattr(action_binding_gate, 'binding_path', 'none'))
        cur_state  = str(getattr(cognitive_metabolic_regulator, 'cognitive_state', 'efficient'))
        cur_sig    = '%s|%s|%s' % (cur_state, cur_action, cur_path)

        # Exclude current tick (just-written) record from retrieval.
        scored = []
        for rec in records:
            if rec.get('tick') == tick:
                continue
            age = max(0, tick - int(rec.get('tick', tick)))
            recency    = self._clamp01(1.0 / (1.0 + age * self.RECENCY_DECAY))
            ctx_sim    = self._clamp01(self._context_similarity(cur_sig, rec.get('context_signature','')))
            out_mag    = self._clamp01(abs(float(rec.get('prediction_error', 0.0))))
            act_match  = 1.0 if str(rec.get('action_type','')) == cur_action else 0.0

            relevance  = self._clamp01(
                ctx_sim   * self.W_CTX     +
                out_mag   * self.W_OUTCOME +
                recency   * self.W_RECENCY +
                act_match * self.W_ACTION
            )
            scored.append({
                'tick':      rec.get('tick'),
                'action_type': rec.get('action_type'),
                'actual_reward':    rec.get('actual_reward', 0.0),
                'prediction_error': rec.get('prediction_error', 0.0),
                'credit':           rec.get('credit', 0.0),
                'outcome_class':    rec.get('outcome_class','neutral'),
                'context_signature':rec.get('context_signature',''),
                'relevance':        round(relevance, 4),
                'age':              age,
            })

        self.scored_memories = scored
        self.scoring_reason  = 'n=%d cur_sig=%s' % (len(scored), cur_sig)

        self._history.append({
            'tick':       tick,
            'n_scored':   len(scored),
            'scoring_reason': self.scoring_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ContextualMemoryRetriever:
    """Retrieves top-MAX_RETRIEVAL memories with relevance >= RELEVANCE_MIN.
    Sorts by relevance descending. Emits retrieval_confidence as the mean
    relevance of the retained set (or 0.0 when empty). deque(maxlen=96)."""

    MAX_RETRIEVAL = 5     # Rule 1 frozen
    RELEVANCE_MIN = 0.40  # Rule 2 frozen

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.retrieved_memories= []
        self.retrieval_confidence = 0.0
        self.retrieval_reason  = 'init'

    def update(self, tick, memory_relevance_scorer):
        if _IKG.sleeping:
            self.retrieved_memories    = []
            self.retrieval_confidence  = 0.0
            return

        scored = list(getattr(memory_relevance_scorer, 'scored_memories', []) or [])
        filtered = [m for m in scored if m.get('relevance', 0.0) >= self.RELEVANCE_MIN]
        filtered.sort(key=lambda m: m.get('relevance', 0.0), reverse=True)
        top = filtered[:self.MAX_RETRIEVAL]

        if top:
            self.retrieval_confidence = round(
                sum(m.get('relevance', 0.0) for m in top) / len(top), 4)
        else:
            self.retrieval_confidence = 0.0
        self.retrieved_memories = top
        self.retrieval_reason = 'n_top=%d n_filtered=%d n_scored=%d conf=%.4f' % (
            len(top), len(filtered), len(scored), self.retrieval_confidence)

        self._history.append({
            'tick':                 tick,
            'n_retrieved':          len(top),
            'n_filtered':           len(filtered),
            'n_scored':             len(scored),
            'retrieval_confidence': self.retrieval_confidence,
            'retrieval_reason':     self.retrieval_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class AssociativeRecallEngine:
    """Clusters retrieved memories into recall patterns:
        'repeated_success' : >=2 retrieved records with outcome_class='success'
        'repeated_failure' : >=2 retrieved records with outcome_class='failure'
        'mixed'            : both success and failure present
        'sparse'           : fewer than 2 outcome records total
    pattern_strength is the fraction of retrieved records matching the
    dominant outcome class. deque(maxlen=96)."""

    REPEAT_FLOOR = 2   # Rule 4 mirror: need >=2 to call it a pattern

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self.recall_patterns= []
        self.pattern_strength = 0.0
        self.recall_reason  = 'init'

    def update(self, tick, contextual_memory_retriever):
        if _IKG.sleeping:
            self.recall_patterns   = []
            self.pattern_strength  = 0.0
            return

        retrieved = list(getattr(contextual_memory_retriever, 'retrieved_memories', []) or [])
        n = len(retrieved)

        n_succ = sum(1 for m in retrieved if m.get('outcome_class') == 'success')
        n_fail = sum(1 for m in retrieved if m.get('outcome_class') == 'failure')

        patterns = []
        if n_succ >= self.REPEAT_FLOOR:
            patterns.append('repeated_success')
        if n_fail >= self.REPEAT_FLOOR:
            patterns.append('repeated_failure')
        if n_succ >= 1 and n_fail >= 1:
            patterns.append('mixed')
        if n < self.REPEAT_FLOOR:
            patterns.append('sparse')

        # Strength = fraction of retrieved matching the dominant outcome class.
        if n > 0:
            dominant_count = max(n_succ, n_fail)
            self.pattern_strength = round(dominant_count / n, 4)
        else:
            self.pattern_strength = 0.0

        self.recall_patterns = patterns
        self.recall_reason = 'n=%d succ=%d fail=%d patterns=[%s]' % (
            n, n_succ, n_fail, ','.join(patterns))

        self._history.append({
            'tick':           tick,
            'n_retrieved':    n,
            'n_success':      n_succ,
            'n_failure':      n_fail,
            'patterns':       list(patterns),
            'pattern_strength': self.pattern_strength,
            'recall_reason':  self.recall_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MemoryConditionedCognition:
    """Modifies the organism's active confidence based on retrieved memories.
    memory_support (clamped to [-1,1]):
        avg_reward_of_similar_actions - avg_error_of_similar_actions
    Where 'similar' means retrieved memories that share action_type with the
    current bound action; absent such matches, the full retrieved set is
    used. Repeated-failure patterns subtract FAILURE_PENALTY (0.05);
    repeated-success patterns add SUCCESS_BONUS (0.05).
    Adjusted confidence (R5):
        adjusted = base * 0.70 + memory_support_normalised * 0.30
    Where memory_support_normalised maps [-1,1] to [0,1] via 0.5*(ms+1).
    deque(maxlen=96)."""

    W_BASE           = 0.70    # Rule 5 frozen
    W_MEMORY         = 0.30    # Rule 5 frozen
    FAILURE_PENALTY  = 0.05
    SUCCESS_BONUS    = 0.05

    def __init__(self, maxlen=96):
        self._maxlen                    = maxlen
        self._history                   = deque(maxlen=maxlen)
        self.memory_adjusted_confidence = 0.0
        self.memory_support             = 0.0
        self.cognition_reason           = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    @staticmethod
    def _clamp11(v): return max(-1.0, min(1.0, float(v)))

    def update(self, tick,
               action_binding_gate,
               contextual_memory_retriever,
               associative_recall_engine):
        if _IKG.sleeping:
            self.memory_adjusted_confidence = 0.0
            self.memory_support             = 0.0
            return

        base_conf = self._clamp01(
            float(getattr(action_binding_gate, 'binding_confidence', 0.0) or 0.0))
        bound_act = getattr(action_binding_gate, 'bound_action', None) or {}
        cur_action = str(bound_act.get('action_type', 'idle_recover'))

        retrieved = list(getattr(contextual_memory_retriever, 'retrieved_memories', []) or [])
        patterns  = list(getattr(associative_recall_engine,  'recall_patterns',    []) or [])

        # Choose similar subset: same action_type preferred.
        similar = [m for m in retrieved if str(m.get('action_type','')) == cur_action]
        if not similar:
            similar = retrieved

        if similar:
            avg_reward = sum(float(m.get('actual_reward', 0.0)) for m in similar) / len(similar)
            avg_error  = sum(abs(float(m.get('prediction_error', 0.0))) for m in similar) / len(similar)
            memory_support = self._clamp11(avg_reward - avg_error)
        else:
            memory_support = 0.0

        # Pattern-level adjustments.
        if 'repeated_failure' in patterns:
            memory_support -= self.FAILURE_PENALTY
        if 'repeated_success' in patterns:
            memory_support += self.SUCCESS_BONUS
        memory_support = self._clamp11(memory_support)
        self.memory_support = round(memory_support, 4)

        # Normalise [-1,1] -> [0,1] then blend per R5.
        memory_support_norm = (memory_support + 1.0) / 2.0
        adjusted = self._clamp01(
            base_conf * self.W_BASE + memory_support_norm * self.W_MEMORY
        )
        # When no memory at all, fall back to base (no bias).
        if not retrieved:
            adjusted = base_conf
            memory_support = 0.0
            self.memory_support = 0.0

        self.memory_adjusted_confidence = round(adjusted, 4)
        self.cognition_reason = 'base=%.4f ms=%.4f adj=%.4f patterns=[%s]' % (
            base_conf, memory_support, adjusted, ','.join(patterns))

        self._history.append({
            'tick':                       tick,
            'base_confidence':            round(base_conf, 4),
            'memory_support':             self.memory_support,
            'memory_adjusted_confidence': self.memory_adjusted_confidence,
            'patterns':                   list(patterns),
            'n_similar':                  len(similar) if retrieved else 0,
            'cognition_reason':           self.cognition_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 30 PACK 1 -- Stability & Truth Audit: Long-Horizon Validation of the
# Adaptive Cognition Loop.
# Sutton & Barto 1998 (TD convergence); Shannon 1948 (entropy);
# Pearson 1895 (linear regression); Ashby 1956 (requisite variety / stability).
# Observer-only -- Rule R1: zero mutation of any upstream state.
# Frozen rules:
#   R1  no intervention: read-only observation across all four classes
#   R2  HORIZONS = [50, 100, 200] tick windows (frozen)
#   R3  TREND_WINDOW = 50 ticks for slope and variance computation (frozen)
#   R4  ENERGY_FLOOR = 0.20; ENERGY_CEIL = 1.0 (frozen)
#   R5  convergence_score = dominant_frequency / max(entropy, 1e-6) (frozen)
#   R6  verdict = 'stable'|'unstable'|'inconclusive' (frozen logic)
#   R7  deque(maxlen=256) on all four classes
# Insertion: waking-only, after memory_conditioned_cognition.update(),
# before edit_intent_generator.generate().
# ===========================================================================

class LongHorizonSimulationRunner:
    """Collects per-tick metrics (read-only, Rule R1) and computes aggregated
    statistics over the frozen horizon windows [50, 100, 200] (Rule R2).
    Per-tick record schema:
      {tick, predicted_EES, actual_reward, prediction_error,
       energy, fallback_used, selected_action}
    horizon_results is a dict keyed by horizon size, populated once
    len(history) >= that horizon. Energy is read from l23.energy if the
    cortical-layer object is present in globals(), otherwise approximated
    from CognitiveMetabolicRegulator.efficiency_ratio. deque(maxlen=256)."""

    HORIZONS = [50, 100, 200]   # R2 frozen

    def __init__(self, maxlen=256):
        self._maxlen         = maxlen
        self._history        = deque(maxlen=maxlen)
        self.tick_log        = {}
        self.horizon_results = {}
        self.runner_reason   = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               predicted_value_estimator,
               outcome_evaluator,
               outcome_credit_assigner,
               cognitive_metabolic_regulator,
               action_binding_gate):
        if _IKG.sleeping:
            return

        # Rule R1: read-only extraction -- no upstream attribute writes.
        predicted_EES    = float(getattr(predicted_value_estimator, 'predicted_EES',   0.0) or 0.0)
        actual_reward    = float(getattr(outcome_evaluator,         'actual_reward',    0.0) or 0.0)
        prediction_error = float(getattr(outcome_credit_assigner,   'prediction_error', 0.0) or 0.0)
        bound_act        = getattr(action_binding_gate, 'bound_action', None) or {}
        selected_action  = str(bound_act.get('action_type', 'idle_recover'))
        binding_path     = str(getattr(action_binding_gate, 'binding_path', 'none'))
        fallback_used    = binding_path in ('fallback_bg', 'fallback_reasoning')

        # Energy: read cortical compartment mean if l23 is available.
        l23_obj = _IKG.l23
        if l23_obj is not None:
            e_dict = getattr(l23_obj, 'energy', {}) or {}
            vals   = [float(v) for v in e_dict.values() if v is not None]
            energy = sum(vals) / max(1, len(vals)) if vals else 0.5
        else:
            eff    = float(getattr(cognitive_metabolic_regulator,
                                   'efficiency_ratio', 1.0) or 1.0)
            energy = self._clamp01(eff / 2.0)

        rec = {
            'tick':             tick,
            'predicted_EES':    round(predicted_EES,     4),
            'actual_reward':    round(actual_reward,      4),
            'prediction_error': round(prediction_error,   4),
            'energy':           round(energy,             4),
            'fallback_used':    fallback_used,
            'selected_action':  selected_action,
        }
        self._history.append(rec)
        self.tick_log = rec

        # Compute windowed aggregates from accumulated history.
        h_results = {}
        records   = list(self._history)
        n         = len(records)
        for H in self.HORIZONS:
            if n < H:
                continue
            window    = records[-H:]
            abs_pes   = [abs(r['prediction_error']) for r in window]
            rewards   = [r['actual_reward']         for r in window]
            energies  = [r['energy']                for r in window]
            fallbacks = sum(1 for r in window if r['fallback_used'])
            h_results[H] = {
                'mean_abs_error': round(sum(abs_pes) / H, 4),
                'mean_reward':    round(sum(rewards) / H, 4),
                'mean_energy':    round(sum(energies) / H, 4),
                'fallback_rate':  round(fallbacks / H,    4),
                'n':              H,
            }
        self.horizon_results = h_results
        self.runner_reason   = 'tick=%d n=%d horizons=%s' % (
            tick, n, list(h_results.keys()))

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class PredictionErrorTracker:
    """Tracks |prediction_error| and actual_reward per waking tick. Over the
    last TREND_WINDOW=50 ticks (Rule R3) computes:
        mean_abs_error     : mean |pe|
        error_trend_slope  : least-squares slope of |pe| sequence;
                             negative value indicates improving calibration
        variance           : variance of |pe| over the window
        reward_trend_slope : least-squares slope of actual_reward sequence;
                             positive value indicates improving outcomes
    Rule R1: reads outcome_credit_assigner and outcome_evaluator only.
    deque(maxlen=256)."""

    TREND_WINDOW = 50   # R3 frozen

    def __init__(self, maxlen=256):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.mean_abs_error     = 0.0
        self.error_trend_slope  = 0.0
        self.variance           = 0.0
        self.reward_trend_slope = 0.0
        self.tracker_reason     = 'init'

    @staticmethod
    def _linear_slope(values):
        """Least-squares slope treating list index as x, value as y."""
        n = len(values)
        if n < 2:
            return 0.0
        x_mean = (n - 1) / 2.0
        y_mean = sum(values) / n
        num = sum((i - x_mean) * (values[i] - y_mean) for i in range(n))
        den = sum((i - x_mean) ** 2 for i in range(n))
        return num / den if den > 1e-12 else 0.0

    def update(self, tick, outcome_credit_assigner, outcome_evaluator):
        if _IKG.sleeping:
            return

        abs_pe = abs(float(getattr(outcome_credit_assigner, 'prediction_error', 0.0) or 0.0))
        reward = float(getattr(outcome_evaluator, 'actual_reward', 0.0) or 0.0)

        self._history.append({
            'tick':   tick,
            'abs_pe': round(abs_pe, 4),
            'reward': round(reward, 4),
        })

        records = list(self._history)
        window  = records[-self.TREND_WINDOW:]
        abs_pes = [r['abs_pe'] for r in window]
        rewards = [r['reward'] for r in window]
        n       = len(abs_pes)

        if n > 0:
            self.mean_abs_error = round(sum(abs_pes) / n, 4)
            self.variance       = round(
                sum((v - self.mean_abs_error) ** 2 for v in abs_pes) / max(1, n), 6)
        else:
            self.mean_abs_error = 0.0
            self.variance       = 0.0

        self.error_trend_slope  = round(self._linear_slope(abs_pes),  6)
        self.reward_trend_slope = round(self._linear_slope(rewards),  6)
        self.tracker_reason     = 'tick=%d n=%d mae=%.4f eslope=%.6f rslope=%.6f' % (
            tick, n, self.mean_abs_error,
            self.error_trend_slope, self.reward_trend_slope)

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class BehaviorConvergenceAnalyzer:
    """Tracks action-type distribution and memory influence to measure
    behavioral convergence over time (Rule R5):
        dominant_action    : action_type with highest cumulative frequency
        dominant_frequency : fraction of waking ticks choosing dominant_action
        entropy            : Shannon entropy (bits) over action distribution
        convergence_score  : dominant_frequency / max(entropy, 1e-6)
        memory_influence   : rolling mean of |memory_adjusted_confidence
                             - binding_confidence| (memory correction signal)
    Higher convergence_score indicates stronger behavioral commitment.
    Rule R1: reads action_binding_gate and memory_conditioned_cognition only.
    deque(maxlen=256). _action_counts preserved across to_dict/from_dict."""

    def __init__(self, maxlen=256):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self._action_counts     = {}
        self.dominant_action    = 'idle_recover'
        self.dominant_frequency = 0.0
        self.entropy            = 0.0
        self.convergence_score  = 0.0
        self.memory_influence   = 0.0
        self.convergence_reason = 'init'

    def update(self, tick, action_binding_gate, memory_conditioned_cognition):
        if _IKG.sleeping:
            return

        bound_act   = getattr(action_binding_gate, 'bound_action', None) or {}
        action_type = str(bound_act.get('action_type', 'idle_recover'))
        self._action_counts[action_type] = self._action_counts.get(action_type, 0) + 1

        total    = max(1, sum(self._action_counts.values()))
        dominant = max(self._action_counts, key=self._action_counts.get)
        dom_freq = self._action_counts[dominant] / total

        # Shannon entropy (bits) over action-type distribution.
        ent = 0.0
        for cnt in self._action_counts.values():
            p = cnt / total
            if p > 0.0:
                ent -= p * math.log2(p)

        conv_score = dom_freq / max(ent, 1e-6)

        # Memory influence: absolute confidence delta.
        mem_adj  = float(getattr(memory_conditioned_cognition,
                                 'memory_adjusted_confidence', 0.0) or 0.0)
        base_c   = float(getattr(action_binding_gate, 'binding_confidence', 0.0) or 0.0)
        mem_inf  = abs(mem_adj - base_c)

        self._history.append({
            'tick':               tick,
            'action_type':        action_type,
            'dominant_action':    dominant,
            'dominant_frequency': round(dom_freq,    4),
            'entropy':            round(ent,          4),
            'convergence_score':  round(conv_score,   4),
            'memory_influence':   round(mem_inf,      4),
        })

        self.dominant_action    = dominant
        self.dominant_frequency = round(dom_freq,    4)
        self.entropy            = round(ent,          4)
        self.convergence_score  = round(conv_score,   4)
        records = list(self._history)
        self.memory_influence   = round(
            sum(r['memory_influence'] for r in records) / max(1, len(records)), 4)
        self.convergence_reason = 'tick=%d dom=%s freq=%.4f ent=%.4f conv=%.4f' % (
            tick, dominant, dom_freq, ent, conv_score)

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen,
                'history': list(self._history),
                'action_counts': dict(self._action_counts)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._action_counts = dict(d.get('action_counts', {}))
        return obj


class SystemStabilityMonitor:
    """Aggregates all three prior Pack 1 observer classes to produce a final
    audit_result dict each waking tick:
      {error_trend, reward_trend, energy_stability, fallback_rate,
       convergence_score, verdict}
    Verdict logic (Rule R6, frozen):
        'stable'       : error_trend < 0 AND reward_trend > 0
                         AND energy_stability = True AND fallback_rate > 0
        'unstable'     : energy collapse (< ENERGY_FLOOR=0.20) OR
                         error_trend >= INSTABILITY_SLOPE_THRESHOLD
        'inconclusive' : n_records < 10 OR conditions not decisively met
    Rule R1: reads only from upstream observer classes and runner tick_log.
    deque(maxlen=256)."""

    ENERGY_FLOOR               = 0.20    # R4 frozen
    ENERGY_CEIL                = 1.0     # R4 frozen
    INSTABILITY_SLOPE_THRESHOLD= 0.002   # R6: positive PE slope this large = unstable
    MIN_RECORDS_FOR_VERDICT    = 10      # need at least 10 ticks for any verdict

    def __init__(self, maxlen=256):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.energy_stability = True
        self.fallback_rate    = 0.0
        self.audit_result     = {}
        self.monitor_reason   = 'init'

    def update(self, tick,
               long_horizon_simulation_runner,
               prediction_error_tracker,
               behavior_convergence_analyzer):
        if _IKG.sleeping:
            return

        # Energy stability from latest runner tick_log (Rule R1, read-only).
        tick_log   = getattr(long_horizon_simulation_runner, 'tick_log', {}) or {}
        energy     = float(tick_log.get('energy', 0.5))
        collapse   = (energy < self.ENERGY_FLOOR)
        runaway    = (energy > self.ENERGY_CEIL)
        energy_ok  = (not collapse) and (not runaway)

        # Fallback rate from longest available horizon, else raw history.
        h_results = getattr(long_horizon_simulation_runner, 'horizon_results', {}) or {}
        if h_results:
            largest_h    = max(h_results.keys())
            fallback_rate = float(h_results[largest_h].get('fallback_rate', 0.0))
        else:
            run_history   = list(getattr(long_horizon_simulation_runner,
                                         '_history', []) or [])
            n_run = max(1, len(run_history))
            fallback_rate = sum(1 for r in run_history if r.get('fallback_used', False)) / n_run

        # Trend signals from PredictionErrorTracker.
        error_trend  = float(getattr(prediction_error_tracker, 'error_trend_slope',  0.0) or 0.0)
        reward_trend = float(getattr(prediction_error_tracker, 'reward_trend_slope', 0.0) or 0.0)

        # Convergence score from BehaviorConvergenceAnalyzer.
        conv_score   = float(getattr(behavior_convergence_analyzer,
                                     'convergence_score', 0.0) or 0.0)

        # Number of waking records for verdict gating.
        n_records = len(list(getattr(long_horizon_simulation_runner,
                                     '_history', []) or []))

        # Verdict logic (Rule R6).
        if n_records < self.MIN_RECORDS_FOR_VERDICT:
            verdict = 'inconclusive'
        elif (not energy_ok) or (error_trend >= self.INSTABILITY_SLOPE_THRESHOLD):
            verdict = 'unstable'
        elif (error_trend < 0.0
              and reward_trend > 0.0
              and energy_ok
              and fallback_rate > 0.0):
            verdict = 'stable'
        else:
            verdict = 'inconclusive'

        self.energy_stability = energy_ok
        self.fallback_rate    = round(fallback_rate, 4)
        self.audit_result = {
            'error_trend':       round(error_trend,   6),
            'reward_trend':      round(reward_trend,  6),
            'energy_stability':  energy_ok,
            'fallback_rate':     round(fallback_rate, 4),
            'convergence_score': round(conv_score,    4),
            'verdict':           verdict,
        }
        self.monitor_reason = 'tick=%d verdict=%s e=%.4f fb=%.4f et=%.6f rt=%.6f' % (
            tick, verdict, energy, fallback_rate, error_trend, reward_trend)

        self._history.append({
            'tick':              tick,
            'energy':            round(energy,       4),
            'energy_stability':  energy_ok,
            'fallback_rate':     round(fallback_rate, 4),
            'error_trend':       round(error_trend,   6),
            'reward_trend':      round(reward_trend,  6),
            'convergence_score': round(conv_score,    4),
            'verdict':           verdict,
            'monitor_reason':    self.monitor_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 30 PACK 2 -- Overload Control & Reactive Efficiency Mode
# Kahneman 2011 (System 1/2 load switching); Posner & Snyder 1975 (automatic
# vs controlled processing); Yerkes-Dodson 1908 (performance-arousal curve);
# Selye 1950 (general adaptation syndrome -- alarm, resistance, exhaustion).
# Frozen rules:
#   R1  SOFT_THRESHOLD=0.60; OVERLOAD_THRESHOLD=0.75 (frozen)
#   R2  Soft degradation: chain_depth_cap=3, retrieval_cap=3, threshold+=0.05
#   R3  Overload: Reactive Efficiency Mode activated at strain >= 0.75
#   R4  Overload params: chain_depth=1, retrieval=2, threshold+=0.10, fallback=high
#   R5  Recovery: OVERLOAD_TICKS>=5 AND energy declining AND reward not improving
#   R6  deque(maxlen=96) all four classes
# Insertion: waking-only, after system_stability_monitor.update(),
# before edit_intent_generator.generate().
# ===========================================================================

class CognitiveLoadMonitor:
    """Monitors strain, energy trend, and reward trend each waking tick to
    classify the organism's current cognitive load state (Rule R1).
    strain_level is read from CognitiveMetabolicRegulator.strain_score.
    Energy trend is derived from the LongHorizonSimulationRunner history:
    recent-half mean vs early-half mean over the last 20 records. Reward
    trend is the sign of PredictionErrorTracker.reward_trend_slope.
    trend_state: 'healthy' | 'soft_strain' | 'overload'.
    overload_flag = strain_level >= OVERLOAD_THRESHOLD.
    deque(maxlen=96)."""

    SOFT_THRESHOLD     = 0.60   # R1 frozen
    OVERLOAD_THRESHOLD = 0.75   # R1 frozen
    ENERGY_TREND_WINDOW= 20     # ticks to use for energy trend comparison

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.strain_level     = 0.0
        self.overload_flag    = False
        self.trend_state      = 'healthy'
        self.energy_declining = False
        self.reward_improving = False
        self.load_reason      = 'init'

    @staticmethod
    def _clamp01(v): return max(0.0, min(1.0, float(v)))

    def update(self, tick,
               cognitive_metabolic_regulator,
               long_horizon_simulation_runner,
               prediction_error_tracker):
        if _IKG.sleeping:
            self.strain_level  = 0.0
            self.overload_flag = False
            self.trend_state   = 'healthy'
            return

        # Strain from CognitiveMetabolicRegulator (Rule R1).
        strain = self._clamp01(
            float(getattr(cognitive_metabolic_regulator, 'strain_score', 0.0) or 0.0))

        # Energy trend: compare recent vs early half of last ENERGY_TREND_WINDOW records.
        run_hist = list(getattr(long_horizon_simulation_runner, '_history', []) or [])
        energy_declining = False
        if len(run_hist) >= self.ENERGY_TREND_WINDOW:
            window   = run_hist[-self.ENERGY_TREND_WINDOW:]
            half     = len(window) // 2
            early_e  = sum(r.get('energy', 0.5) for r in window[:half]) / max(1, half)
            recent_e = sum(r.get('energy', 0.5) for r in window[half:]) / max(1, len(window) - half)
            energy_declining = (recent_e < early_e - 0.01)

        # Reward trend from PredictionErrorTracker.
        reward_slope   = float(getattr(prediction_error_tracker, 'reward_trend_slope', 0.0) or 0.0)
        reward_improving = (reward_slope > 0.0)

        # Classify trend_state.
        if strain >= self.OVERLOAD_THRESHOLD:
            trend_state = 'overload'
        elif strain >= self.SOFT_THRESHOLD:
            trend_state = 'soft_strain'
        else:
            trend_state = 'healthy'

        self.strain_level     = round(strain, 4)
        self.overload_flag    = (strain >= self.OVERLOAD_THRESHOLD)
        self.trend_state      = trend_state
        self.energy_declining = energy_declining
        self.reward_improving = reward_improving
        self.load_reason      = 'tick=%d strain=%.4f state=%s edecl=%s rimpr=%s' % (
            tick, strain, trend_state, energy_declining, reward_improving)

        self._history.append({
            'tick':             tick,
            'strain_level':     self.strain_level,
            'overload_flag':    self.overload_flag,
            'trend_state':      trend_state,
            'energy_declining': energy_declining,
            'reward_improving': reward_improving,
            'load_reason':      self.load_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class DynamicReasoningLimiter:
    """Adjusts effective chain depth and retrieval cap based on the current
    cognitive load state (Rules R2, R4). Limits are read-only advisory
    signals; enforcement requires downstream wiring. Frozen cap table:
        healthy    : chain_depth=6, retrieval_cap=5
        soft_strain: chain_depth=3, retrieval_cap=3 (R2)
        overload   : chain_depth=1, retrieval_cap=2 (R4)
    Additionally disables multi-hop inference, long-form reasoning, and
    negotiation loops under overload. deque(maxlen=96)."""

    # Frozen caps (R2, R4).
    NORMAL_CHAIN_DEPTH  = 6
    NORMAL_RETRIEVAL    = 5
    SOFT_CHAIN_DEPTH    = 3   # R2 frozen
    SOFT_RETRIEVAL      = 3   # R2 frozen
    OVERLOAD_CHAIN      = 1   # R4 frozen
    OVERLOAD_RETRIEVAL  = 2   # R4 frozen

    def __init__(self, maxlen=96):
        self._maxlen                = maxlen
        self._history               = deque(maxlen=maxlen)
        self.effective_chain_depth  = self.NORMAL_CHAIN_DEPTH
        self.effective_retrieval_cap= self.NORMAL_RETRIEVAL
        self.multi_hop_enabled      = True
        self.long_form_enabled      = True
        self.negotiation_enabled    = True
        self.limiter_reason         = 'init'

    def update(self, tick, cognitive_load_monitor):
        if _IKG.sleeping:
            self.effective_chain_depth   = self.NORMAL_CHAIN_DEPTH
            self.effective_retrieval_cap = self.NORMAL_RETRIEVAL
            return

        trend_state = str(getattr(cognitive_load_monitor, 'trend_state', 'healthy') or 'healthy')

        if trend_state == 'overload':
            chain   = self.OVERLOAD_CHAIN      # 1 (R4)
            retr    = self.OVERLOAD_RETRIEVAL  # 2 (R4)
            mh      = False
            lf      = False
            neg     = False
        elif trend_state == 'soft_strain':
            chain   = self.SOFT_CHAIN_DEPTH    # 3 (R2)
            retr    = self.SOFT_RETRIEVAL      # 3 (R2)
            mh      = True
            lf      = True
            neg     = False
        else:
            chain   = self.NORMAL_CHAIN_DEPTH  # 6
            retr    = self.NORMAL_RETRIEVAL    # 5
            mh      = True
            lf      = True
            neg     = True

        self.effective_chain_depth   = chain
        self.effective_retrieval_cap = retr
        self.multi_hop_enabled       = mh
        self.long_form_enabled       = lf
        self.negotiation_enabled     = neg
        self.limiter_reason          = 'tick=%d state=%s chain=%d retr=%d' % (
            tick, trend_state, chain, retr)

        self._history.append({
            'tick':                  tick,
            'trend_state':           trend_state,
            'effective_chain_depth': chain,
            'effective_retrieval_cap': retr,
            'multi_hop_enabled':     mh,
            'long_form_enabled':     lf,
            'negotiation_enabled':   neg,
            'limiter_reason':        self.limiter_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ReactiveEfficiencyController:
    """Adjusts binding confidence threshold and fallback bias based on
    cognitive load state (Rules R2, R4). All adjustments are advisory
    signals -- downstream classes read these without forcing upstream changes.
    Threshold schedule (frozen):
        healthy    : adjusted_threshold = BASE_THRESHOLD (0.60), bias = 'none'
        soft_strain: adjusted_threshold = 0.65 (+SOFT_BIAS=0.05),  bias = 'low'
        overload   : adjusted_threshold = 0.70 (+OVERLOAD_BIAS=0.10), bias = 'high'
    control_state: 'normal' | 'soft_degradation' | 'reactive_efficiency'.
    deque(maxlen=96)."""

    BASE_THRESHOLD  = 0.60   # mirrors ActionBindingGate.BINDING_THRESHOLD
    SOFT_BIAS       = 0.05   # R2 frozen
    OVERLOAD_BIAS   = 0.10   # R4 frozen

    def __init__(self, maxlen=96):
        self._maxlen            = maxlen
        self._history           = deque(maxlen=maxlen)
        self.adjusted_threshold = self.BASE_THRESHOLD
        self.fallback_bias      = 'none'
        self.control_state      = 'normal'
        self.disabled_features  = []
        self.controller_reason  = 'init'

    def update(self, tick, cognitive_load_monitor, dynamic_reasoning_limiter):
        if _IKG.sleeping:
            self.adjusted_threshold = self.BASE_THRESHOLD
            self.fallback_bias      = 'none'
            self.control_state      = 'normal'
            return

        trend_state = str(getattr(cognitive_load_monitor, 'trend_state', 'healthy') or 'healthy')

        if trend_state == 'overload':
            threshold     = round(self.BASE_THRESHOLD + self.OVERLOAD_BIAS, 4)  # 0.70
            bias          = 'high'
            ctrl          = 'reactive_efficiency'
            disabled      = ['multi_hop_inference', 'long_form_reasoning', 'negotiation_loops']
        elif trend_state == 'soft_strain':
            threshold     = round(self.BASE_THRESHOLD + self.SOFT_BIAS, 4)      # 0.65
            bias          = 'low'
            ctrl          = 'soft_degradation'
            disabled      = []
        else:
            threshold     = self.BASE_THRESHOLD                                  # 0.60
            bias          = 'none'
            ctrl          = 'normal'
            disabled      = []

        self.adjusted_threshold = threshold
        self.fallback_bias      = bias
        self.control_state      = ctrl
        self.disabled_features  = disabled
        self.controller_reason  = 'tick=%d state=%s thr=%.2f bias=%s' % (
            tick, trend_state, threshold, bias)

        self._history.append({
            'tick':               tick,
            'trend_state':        trend_state,
            'adjusted_threshold': threshold,
            'fallback_bias':      bias,
            'control_state':      ctrl,
            'disabled_features':  list(disabled),
            'controller_reason':  self.controller_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class RecoveryStateManager:
    """Tracks consecutive overload ticks and triggers recovery when Rule R5
    conditions are met:
        _consecutive_overload_ticks >= OVERLOAD_TICKS (5)
        AND energy_declining = True
        AND reward_improving = False
    recovery_triggered is a single-tick pulse: True only on the tick the
    condition is first met, then remains True until the organism leaves
    overload. recovery_active tracks whether recovery is currently engaged.
    Recovery is cleared when trend_state returns to 'healthy' or 'soft_strain'.
    deque(maxlen=96)."""

    OVERLOAD_TICKS = 5   # R5 frozen: consecutive overload ticks to trigger recovery

    def __init__(self, maxlen=96):
        self._maxlen                   = maxlen
        self._history                  = deque(maxlen=maxlen)
        self._consecutive_overload     = 0
        self.recovery_triggered        = False
        self.recovery_active           = False
        self.recovery_reason           = 'init'

    def update(self, tick, cognitive_load_monitor, prediction_error_tracker):
        if _IKG.sleeping:
            self._consecutive_overload = 0
            self.recovery_triggered    = False
            return

        overload_flag    = bool(getattr(cognitive_load_monitor, 'overload_flag',    False))
        energy_declining = bool(getattr(cognitive_load_monitor, 'energy_declining', False))
        reward_improving = bool(getattr(cognitive_load_monitor, 'reward_improving', False))
        trend_state      = str(getattr(cognitive_load_monitor,  'trend_state',      'healthy') or 'healthy')

        # Track consecutive overload ticks.
        if overload_flag:
            self._consecutive_overload += 1
        else:
            self._consecutive_overload = 0

        # Clear recovery when load normalises.
        if trend_state in ('healthy', 'soft_strain'):
            self.recovery_active = False

        # Rule R5: trigger recovery if threshold conditions all met.
        conditions_met = (
            self._consecutive_overload >= self.OVERLOAD_TICKS
            and energy_declining
            and not reward_improving
        )

        if conditions_met and not self.recovery_active:
            self.recovery_triggered = True
            self.recovery_active    = True
            self.recovery_reason    = (
                'tick=%d consecutive=%d edecl=%s rimpr=%s -> recovery' % (
                tick, self._consecutive_overload, energy_declining, reward_improving))
        else:
            self.recovery_triggered = False
            if not self.recovery_active:
                self.recovery_reason = 'tick=%d consecutive=%d state=%s' % (
                    tick, self._consecutive_overload, trend_state)

        self._history.append({
            'tick':                  tick,
            'consecutive_overload':  self._consecutive_overload,
            'overload_flag':         overload_flag,
            'energy_declining':      energy_declining,
            'reward_improving':      reward_improving,
            'recovery_triggered':    self.recovery_triggered,
            'recovery_active':       self.recovery_active,
            'recovery_reason':       self.recovery_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history),
                'consecutive_overload': self._consecutive_overload,
                'recovery_active': self.recovery_active}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj._consecutive_overload = int(d.get('consecutive_overload', 0))
        obj.recovery_active       = bool(d.get('recovery_active', False))
        return obj


# ===========================================================================
# DAY 30 PACK 3 -- Confidence Calibration & Uncertainty Correction
# Fischler & Firschein 1987 (uncertainty in reasoning);
# Lichtenstein & Fischhoff 1977 (calibration of subjective probability);
# Guo et al. 2017 (on calibration of modern neural networks);
# Venn 1888 (frequency interpretation of probability)
# ===========================================================================

class ConfidenceErrorTracker:
    """Tracks last ERROR_WINDOW (20) prediction errors from OutcomeCreditAssigner.
    Computes mean_error (mean of |pe|), error_variance, and error_trend (least-
    squares slope of |pe| sequence). Rule R1: window size frozen at 20.
    Rule R2: metric is mean(|prediction_error|). deque(maxlen=96) R7."""

    ERROR_WINDOW = 20   # R1 frozen
    CRA_STREAK   = 5    # CRA: consecutive improving ticks to trigger acceleration
    CRA_DECAY    = 0.85 # CRA: error memory multiplier per qualifying tick

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen       = maxlen
        self._history      = deque(maxlen=maxlen)
        self._pe_window    = deque(maxlen=self.ERROR_WINDOW)
        self.mean_error    = 0.0
        self.error_variance = 0.0
        self.error_trend   = 0.0
        self._cra_streak   = 0   # consecutive ticks where |pe| < previous |pe|
        self._last_abs_pe  = None

    @staticmethod
    def _slope(values):
        n = len(values)
        if n < 2:
            return 0.0
        x_mean = (n - 1) / 2.0
        y_mean = sum(values) / n
        num = sum((i - x_mean) * (values[i] - y_mean) for i in range(n))
        den = sum((i - x_mean) ** 2 for i in range(n))
        return num / den if den > 1e-12 else 0.0

    def update(self, tick, outcome_credit_assigner):
        if _IKG.sleeping:
            return

        pe     = float(getattr(outcome_credit_assigner, 'prediction_error', 0.0))
        abs_pe = abs(pe)
        self._pe_window.append(abs_pe)

        n    = len(self._pe_window)
        vals = list(self._pe_window)

        self.mean_error     = sum(vals) / n if n > 0 else 0.0
        mean_v              = self.mean_error
        self.error_variance = (sum((v - mean_v) ** 2 for v in vals) / n
                               if n > 1 else 0.0)
        self.error_trend    = self._slope(vals)

        # Confidence Recovery Acceleration (CRA):
        # Increment streak when incoming |pe| is below current rolling mean
        # (system performing better than its established error average).
        # After CRA_STREAK consecutive such ticks, apply CRA_DECAY multiplier
        # to mean_error and error_variance -- forgive past error memory faster.
        pre_mean = self.mean_error   # mean BEFORE CRA (raw window mean)
        if pre_mean > 1e-9 and abs_pe < pre_mean:
            self._cra_streak += 1
        else:
            self._cra_streak = 0
        self._last_abs_pe = abs_pe

        if self._cra_streak >= self.CRA_STREAK:
            # Decay window values directly so recomputed mean persists next tick.
            decayed = [v * self.CRA_DECAY for v in self._pe_window]
            self._pe_window.clear()
            for v in decayed:
                self._pe_window.append(v)
            vals                = list(self._pe_window)
            self.mean_error     = sum(vals) / len(vals) if vals else 0.0
            mean_v              = self.mean_error
            self.error_variance = (sum((v - mean_v) ** 2 for v in vals) / len(vals)
                                   if len(vals) > 1 else 0.0)
            # Floor: never believe performance better than current actual error.
            self.mean_error     = max(self.mean_error, abs_pe)
            # Reset streak after fire -- prevents cascade (unbounded streak -> runaway decay).
            self._cra_streak    = 0

        self._history.append({
            'tick':           tick,
            'mean_error':     self.mean_error,
            'error_variance': self.error_variance,
            'error_trend':    self.error_trend,
            'pe_raw':         pe,
            'cra_streak':     self._cra_streak,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {
            'maxlen':       self._maxlen,
            'history':      list(self._history),
            'pe_window':    list(self._pe_window),
            'cra_streak':   self._cra_streak,
            'last_abs_pe':  self._last_abs_pe,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        for v in d.get('pe_window', []):
            obj._pe_window.append(float(v))
        obj._cra_streak  = int(d.get('cra_streak', 0))
        obj._last_abs_pe = d.get('last_abs_pe', None)
        if obj._pe_window:
            vals        = list(obj._pe_window)
            n           = len(vals)
            obj.mean_error     = sum(vals) / n
            mean_v             = obj.mean_error
            obj.error_variance = (sum((v - mean_v) ** 2 for v in vals) / n
                                  if n > 1 else 0.0)
            obj.error_trend    = cls._slope(vals)
        return obj


class UncertaintyEstimator:
    """Computes uncertainty_score from ConfidenceErrorTracker.
    Rule R3 (frozen):
        uncertainty = mean_error * 0.60 + variance * 0.40
    Clamped [0, 1]. Emits uncertainty_reason as a short ASCII label.
    deque(maxlen=96) R7."""

    W_MEAN = 0.60   # R3 frozen
    W_VAR  = 0.40   # R3 frozen

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.uncertainty_score  = 0.0
        self.uncertainty_reason = 'init'

    def update(self, tick, confidence_error_tracker):
        if _IKG.sleeping:
            return

        mean_err = float(getattr(confidence_error_tracker, 'mean_error',     0.0))
        variance = float(getattr(confidence_error_tracker, 'error_variance', 0.0))

        raw = mean_err * self.W_MEAN + variance * self.W_VAR
        self.uncertainty_score = max(0.0, min(1.0, raw))

        if self.uncertainty_score < 0.25:
            self.uncertainty_reason = 'low_uncertainty'
        elif self.uncertainty_score < 0.50:
            self.uncertainty_reason = 'moderate_uncertainty'
        elif self.uncertainty_score < 0.75:
            self.uncertainty_reason = 'high_uncertainty'
        else:
            self.uncertainty_reason = 'critical_uncertainty'

        self._history.append({
            'tick':               tick,
            'uncertainty_score':  self.uncertainty_score,
            'uncertainty_reason': self.uncertainty_reason,
            'mean_error':         mean_err,
            'variance':           variance,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        if obj._history:
            last = obj._history[-1]
            obj.uncertainty_score  = float(last.get('uncertainty_score',  0.0))
            obj.uncertainty_reason = str(last.get('uncertainty_reason', 'init'))
        return obj


class ConfidenceCalibrator:
    """Applies Rule R4 (frozen):
        calibrated_confidence = base_confidence * (1 - uncertainty)
    Clamped to [confidence_floor=0.10, 1.0] (Rule R5 frozen).
    base_confidence sourced from ActionBindingGate.binding_confidence.
    calibration_delta = calibrated_confidence - base_confidence.
    deque(maxlen=96) R7."""

    CONFIDENCE_FLOOR = 0.10   # R5 frozen

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen              = maxlen
        self._history             = deque(maxlen=maxlen)
        self.calibrated_confidence = 0.60
        self.calibration_delta     = 0.0
        self.base_confidence       = 0.60

    def update(self, tick, action_binding_gate, uncertainty_estimator):
        if _IKG.sleeping:
            return

        base        = float(getattr(action_binding_gate,   'binding_confidence', 0.60))
        uncertainty = float(getattr(uncertainty_estimator, 'uncertainty_score',  0.0))

        raw = base * (1.0 - uncertainty)
        cal = max(self.CONFIDENCE_FLOOR, min(1.0, raw))

        self.base_confidence       = base
        self.calibrated_confidence = cal
        self.calibration_delta     = cal - base

        self._history.append({
            'tick':                  tick,
            'base_confidence':       base,
            'uncertainty':           uncertainty,
            'calibrated_confidence': cal,
            'calibration_delta':     self.calibration_delta,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        if obj._history:
            last = obj._history[-1]
            obj.calibrated_confidence = float(last.get('calibrated_confidence', 0.60))
            obj.calibration_delta     = float(last.get('calibration_delta',     0.0))
            obj.base_confidence       = float(last.get('base_confidence',       0.60))
        return obj


class FallbackDecisionController:
    """Monitors calibrated_confidence and adjusts fallback bias.
    Rule R6 (frozen): if calibrated_confidence < 0.60 -> force fallback bias increase.
    fallback_adjustment: additive bias added on top of base probability [0,1].
    decision_state: 'trust_reasoning' | 'mild_fallback' | 'strong_fallback'.
    deque(maxlen=96) R7."""

    FALLBACK_THRESHOLD     = 0.60   # R6 frozen
    MILD_FALLBACK_ADJ      = 0.10
    STRONG_FALLBACK_ADJ    = 0.25
    STRONG_FALLBACK_CAL    = 0.30   # below this -> strong

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen           = maxlen
        self._history          = deque(maxlen=maxlen)
        self.fallback_adjustment = 0.0
        self.decision_state      = 'trust_reasoning'

    def update(self, tick, confidence_calibrator, uncertainty_estimator):
        if _IKG.sleeping:
            return

        cal         = float(getattr(confidence_calibrator,  'calibrated_confidence', 0.60))
        uncertainty = float(getattr(uncertainty_estimator,  'uncertainty_score',     0.0))

        if cal >= self.FALLBACK_THRESHOLD:
            self.fallback_adjustment = 0.0
            self.decision_state      = 'trust_reasoning'
        elif cal >= self.STRONG_FALLBACK_CAL:
            self.fallback_adjustment = self.MILD_FALLBACK_ADJ
            self.decision_state      = 'mild_fallback'
        else:
            self.fallback_adjustment = self.STRONG_FALLBACK_ADJ
            self.decision_state      = 'strong_fallback'

        self._history.append({
            'tick':                tick,
            'calibrated_confidence': cal,
            'uncertainty':          uncertainty,
            'fallback_adjustment':   self.fallback_adjustment,
            'decision_state':        self.decision_state,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        if obj._history:
            last = obj._history[-1]
            obj.fallback_adjustment = float(last.get('fallback_adjustment', 0.0))
            obj.decision_state      = str(last.get('decision_state', 'trust_reasoning'))
        return obj


# ===========================================================================
# DAY 30 PACK 4 -- Dopamine-Coupled Policy Shaping (Stabilized)
# Schultz 1997 (dopamine prediction error);
# Rescorla & Wagner 1972 (associative learning via prediction error);
# Graybiel 2008 (habit formation and basal ganglia);
# Dayan & Niv 2008 (reinforcement learning in the brain)
# ===========================================================================

class DopamineSignalIntegrator:
    """Computes dopamine signal as TD-style prediction error over rewards.
    Rule R1 (frozen):
        dopamine = actual_reward - EMA_reward
        EMA_reward = old * 0.90 + new * 0.10
    dopamine clamped [-1, 1].
    dopamine_reason: ascii label for signal direction.
    deque(maxlen=96) R7."""

    EMA_ALPHA   = 0.10   # R1 frozen: EMA update weight for new reward
    EMA_DECAY   = 0.90   # R1 frozen: EMA decay

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen          = maxlen
        self._history         = deque(maxlen=maxlen)
        self.ema_reward       = 0.50   # neutral initialisation
        self.dopamine_signal  = 0.0
        self.dopamine_reason  = 'init'

    def update(self, tick, outcome_evaluator):
        if _IKG.sleeping:
            return

        actual = float(getattr(outcome_evaluator, 'actual_reward', 0.0))

        dopamine = actual - self.ema_reward
        dopamine = max(-1.0, min(1.0, dopamine))

        self.ema_reward      = self.EMA_DECAY * self.ema_reward + self.EMA_ALPHA * actual
        self.dopamine_signal = dopamine

        if dopamine > 0.10:
            self.dopamine_reason = 'positive_surprise'
        elif dopamine < -0.10:
            self.dopamine_reason = 'negative_surprise'
        else:
            self.dopamine_reason = 'expectation_met'

        self._history.append({
            'tick':            tick,
            'actual_reward':   actual,
            'ema_reward':      self.ema_reward,
            'dopamine_signal': self.dopamine_signal,
            'dopamine_reason': self.dopamine_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {
            'maxlen':    self._maxlen,
            'history':   list(self._history),
            'ema_reward': self.ema_reward,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj.ema_reward = float(d.get('ema_reward', 0.50))
        if obj._history:
            last = obj._history[-1]
            obj.dopamine_signal = float(last.get('dopamine_signal', 0.0))
            obj.dopamine_reason = str(last.get('dopamine_reason', 'init'))
        return obj


class PolicyBiasTable:
    """Maintains slow EMA bias per action_type.
    Rule R2 (frozen):
        bias_next = old_bias * 0.95 + dopamine * 0.05
    Three canonical action types: explore, approach, withdraw.
    bias_table: dict[str -> float], values clamped [-1, 1].
    deque(maxlen=96) R7."""

    BIAS_DECAY  = 0.95   # R2 frozen
    BIAS_LEARN  = 0.05   # R2 frozen
    ACTIONS     = ('explore', 'approach', 'withdraw')

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen    = maxlen
        self._history   = deque(maxlen=maxlen)
        self.bias_table = {a: 0.0 for a in self.ACTIONS}
        self.bias_reason = 'init'

    def update(self, tick, dopamine_signal_integrator, action_binding_gate):
        if _IKG.sleeping:
            return

        dopamine = float(getattr(dopamine_signal_integrator, 'dopamine_signal', 0.0))
        path     = str(getattr(action_binding_gate, 'binding_path', '') or '')

        # Identify current action type from binding path
        action_type = 'explore'
        for a in self.ACTIONS:
            if a in path.lower():
                action_type = a
                break

        # Update only the active action's bias (sparse credit assignment)
        for a in self.ACTIONS:
            if a == action_type:
                raw = self.bias_table[a] * self.BIAS_DECAY + dopamine * self.BIAS_LEARN
            else:
                raw = self.bias_table[a] * self.BIAS_DECAY
            self.bias_table[a] = max(-1.0, min(1.0, raw))

        dominant = max(self.bias_table, key=lambda k: abs(self.bias_table[k]))
        self.bias_reason = (
            'tick=%d action=%s da=%.3f bias_%s=%.4f' % (
            tick, action_type, dopamine, dominant, self.bias_table[dominant]))

        self._history.append({
            'tick':        tick,
            'action_type': action_type,
            'dopamine':    dopamine,
            'bias_table':  dict(self.bias_table),
            'bias_reason': self.bias_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {
            'maxlen':     self._maxlen,
            'history':    list(self._history),
            'bias_table': dict(self.bias_table),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        stored = d.get('bias_table', {})
        for a in cls.ACTIONS:
            obj.bias_table[a] = float(stored.get(a, 0.0))
        return obj


class HabitStabilityTracker:
    """Tracks consecutive positive / negative bias ticks per action type.
    Rule R5 (frozen): POSITIVE_THRESHOLD = +0.20, NEGATIVE_THRESHOLD = -0.20.
    Rule R6 (frozen): suppress when bias <= -0.20 for 3+ consecutive ticks.
    habit_state per action: 'emerging' | 'stable' | 'dominant' | 'suppressed'.
    habit_strength: abs(bias) for that action type.
    deque(maxlen=96) R7."""

    POSITIVE_THRESHOLD  = 0.20    # R5 frozen
    NEGATIVE_THRESHOLD  = -0.20   # R5 frozen
    SUPPRESS_STREAK     = 3       # R6 frozen: consecutive ticks for suppression

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen        = maxlen
        self._history       = deque(maxlen=maxlen)
        self._pos_streak    = {a: 0 for a in PolicyBiasTable.ACTIONS}
        self._neg_streak    = {a: 0 for a in PolicyBiasTable.ACTIONS}
        self.habit_state    = {a: 'emerging' for a in PolicyBiasTable.ACTIONS}
        self.habit_strength = {a: 0.0        for a in PolicyBiasTable.ACTIONS}
        self.habit_reason   = 'init'
        self.suppressed_actions = set()

    def update(self, tick, policy_bias_table):
        if _IKG.sleeping:
            return

        bias_tbl = getattr(policy_bias_table, 'bias_table', {})

        for a in PolicyBiasTable.ACTIONS:
            bias = float(bias_tbl.get(a, 0.0))
            self.habit_strength[a] = abs(bias)

            # Update streak counters
            if bias >= self.POSITIVE_THRESHOLD:
                self._pos_streak[a] += 1
                self._neg_streak[a]  = 0
            elif bias <= self.NEGATIVE_THRESHOLD:
                self._neg_streak[a] += 1
                self._pos_streak[a]  = 0
            else:
                self._pos_streak[a] = 0
                self._neg_streak[a] = 0

            # Determine state
            if self._neg_streak[a] >= self.SUPPRESS_STREAK:
                self.habit_state[a]  = 'suppressed'
                self.suppressed_actions.add(a)
            elif bias >= 0.50:
                self.habit_state[a]  = 'dominant'
                self.suppressed_actions.discard(a)
            elif bias >= self.POSITIVE_THRESHOLD:
                self.habit_state[a]  = 'stable'
                self.suppressed_actions.discard(a)
            else:
                if a in self.suppressed_actions and bias > self.NEGATIVE_THRESHOLD:
                    self.suppressed_actions.discard(a)
                self.habit_state[a]  = 'emerging'

        self.habit_reason = (
            'tick=%d states=%s suppressed=%s' % (
            tick,
            '|'.join('%s:%s' % (a, self.habit_state[a]) for a in PolicyBiasTable.ACTIONS),
            list(self.suppressed_actions)))

        self._history.append({
            'tick':               tick,
            'habit_state':        dict(self.habit_state),
            'habit_strength':     dict(self.habit_strength),
            'suppressed_actions': list(self.suppressed_actions),
            'habit_reason':       self.habit_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {
            'maxlen':           self._maxlen,
            'history':          list(self._history),
            'pos_streak':       dict(self._pos_streak),
            'neg_streak':       dict(self._neg_streak),
            'suppressed_actions': list(self.suppressed_actions),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        for a in PolicyBiasTable.ACTIONS:
            obj._pos_streak[a] = int(d.get('pos_streak', {}).get(a, 0))
            obj._neg_streak[a] = int(d.get('neg_streak', {}).get(a, 0))
        obj.suppressed_actions = set(d.get('suppressed_actions', []))
        if obj._history:
            last = obj._history[-1]
            for a in PolicyBiasTable.ACTIONS:
                obj.habit_state[a]    = str(last.get('habit_state', {}).get(a, 'emerging'))
                obj.habit_strength[a] = float(last.get('habit_strength', {}).get(a, 0.0))
        return obj


class BiasAdjustedDecisionModulator:
    """Applies bounded dopamine bias to calibrated confidence.
    Rule R3 (frozen):
        adjusted_confidence = calibrated_confidence + bias * MAX_BIAS_EFFECT
        MAX_BIAS_EFFECT = 0.10
    Clamped [0, 1]. Rule R4: never overrides fallback_decision_controller
    decision_state; fallback adjustment is additive on top and takes priority.
    deque(maxlen=96) R7."""

    MAX_BIAS_EFFECT = 0.10   # R3 frozen

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen                  = maxlen
        self._history                 = deque(maxlen=maxlen)
        self.bias_adjusted_confidence = 0.60
        self.modulation_reason        = 'init'

    def update(self, tick, confidence_calibrator, policy_bias_table,
               fallback_decision_controller, action_binding_gate):
        if _IKG.sleeping:
            return

        cal          = float(getattr(confidence_calibrator,       'calibrated_confidence', 0.60))
        path         = str(getattr(action_binding_gate,            'binding_path', '') or '')
        fdc_state    = str(getattr(fallback_decision_controller,   'decision_state', 'trust_reasoning'))
        fdc_adj      = float(getattr(fallback_decision_controller, 'fallback_adjustment', 0.0))
        bias_tbl     = getattr(policy_bias_table, 'bias_table', {})

        # Identify active action type
        action_type = 'explore'
        for a in PolicyBiasTable.ACTIONS:
            if a in path.lower():
                action_type = a
                break

        bias   = float(bias_tbl.get(action_type, 0.0))
        effect = bias * self.MAX_BIAS_EFFECT   # capped at ±0.10

        raw   = cal + effect
        final = max(0.0, min(1.0, raw))

        self.bias_adjusted_confidence = final
        self.modulation_reason = (
            'tick=%d act=%s cal=%.4f bias=%.4f eff=%.4f adj=%.4f fdc=%s' % (
            tick, action_type, cal, bias, effect, final, fdc_state))

        self._history.append({
            'tick':                      tick,
            'calibrated_confidence':     cal,
            'action_type':               action_type,
            'bias':                      bias,
            'effect':                    effect,
            'bias_adjusted_confidence':  final,
            'fdc_state':                 fdc_state,
            'fdc_adjustment':            fdc_adj,
            'modulation_reason':         self.modulation_reason,
        })

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        if obj._history:
            last = obj._history[-1]
            obj.bias_adjusted_confidence = float(last.get('bias_adjusted_confidence', 0.60))
            obj.modulation_reason        = str(last.get('modulation_reason', 'init'))
        return obj


