# DAY 31 PACK 1 -- Adversarial Stress & Failure Mapping
# NOT wired into the waking chain. Testing infrastructure only.
# Kahneman 2011 (System 1/2 breakdown under stress);
# Taleb 2012 (antifragility -- stress reveals hidden failure modes);
# Yerkes & Dodson 1908 (performance under extreme arousal);
# Sutton & Barto 1998 (off-policy perturbation analysis)
# ===========================================================================

class AdversarialScenarioRunner:
    """Orchestrates adversarial scenario execution: scenario selection, injection,
    tick-level execution, and reset.  NOT wired into the waking chain.
    Rule R1 (frozen): all adversarial inputs are temporary and reversible.
    Rule R2 (frozen): five canonical scenarios, each executed independently.
    Rule R3 (frozen): each scenario runs 100-500 ticks.
    Produces per-scenario logs and aggregated comparison.
    deque(maxlen=96) R7."""

    SCENARIOS = [
        'reward_poisoning',
        'memory_corruption',
        'overconfidence_trap',
        'overload_stress',
        'context_switching',
    ]  # R2 frozen

    TICK_MIN = 100   # R3 frozen
    TICK_MAX = 500   # R3 frozen

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen         = maxlen
        self._history        = deque(maxlen=maxlen)
        self.scenario_logs   = {}
        self.failure_modes   = []
        self.recovery_quality = 'none'

    def run_scenario(self, name, tick_count, step_fn, reset_fn=None):
        """Run a single scenario.
        step_fn(tick) -> dict with keys matching Rule R4 metric schema.
        reset_fn() -> restores system to pre-scenario state."""
        if name not in self.SCENARIOS:
            return {}

        tick_count = max(self.TICK_MIN, min(self.TICK_MAX, tick_count))
        log = []
        for t in range(tick_count):
            rec = step_fn(t)
            if isinstance(rec, dict):
                log.append(rec)

        if reset_fn is not None:
            reset_fn()

        self.scenario_logs[name] = log
        self._history.append({'scenario': name, 'ticks': tick_count, 'n_records': len(log)})
        return log

    def aggregate(self, stress_analyzer):
        """Summarise all executed scenarios via StressResponseAnalyzer."""
        results = {}
        all_qualities = []
        failure_modes = []

        for name, log in self.scenario_logs.items():
            if not log:
                continue
            summary = stress_analyzer.analyse(name, log)
            results[name] = summary
            all_qualities.append(summary.get('recovery_quality', 'poor'))
            if summary.get('failure_detected', False):
                failure_modes.append(name)

        self.failure_modes = failure_modes

        quality_rank = {'good': 2, 'moderate': 1, 'poor': 0}
        if all_qualities:
            mean_rank = sum(quality_rank.get(q, 0) for q in all_qualities) / len(all_qualities)
            self.recovery_quality = 'good' if mean_rank >= 1.5 else ('moderate' if mean_rank >= 0.5 else 'poor')
        else:
            self.recovery_quality = 'none'

        return {
            'scenario_results':     results,
            'failure_modes_detected': self.failure_modes,
            'recovery_quality':       self.recovery_quality,
        }

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {
            'maxlen':           self._maxlen,
            'history':          list(self._history),
            'scenario_logs':    {k: v for k, v in self.scenario_logs.items()},
            'failure_modes':    list(self.failure_modes),
            'recovery_quality': self.recovery_quality,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        obj.scenario_logs    = d.get('scenario_logs', {})
        obj.failure_modes    = list(d.get('failure_modes', []))
        obj.recovery_quality = str(d.get('recovery_quality', 'none'))
        return obj


class RewardPerturbationEngine:
    """Injects temporary reward perturbations for adversarial testing.
    Rule R1 (frozen): perturbations are reversible -- originals recorded.
    Modes:
        inverted: reward = 1 - reward
        noisy:    reward = clamp(reward + N(0, NOISE_SCALE), 0, 1)
        delayed:  reward = value from DELAY_TICKS ticks ago (buffer)
    NOISE_SCALE = 0.30, DELAY_TICKS = 5 both frozen.
    deque(maxlen=96) R7."""

    NOISE_SCALE  = 0.30   # frozen
    DELAY_TICKS  = 5      # frozen
    MODES        = ('inverted', 'noisy', 'delayed')

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen     = maxlen
        self._history    = deque(maxlen=maxlen)
        self._delay_buf  = deque(maxlen=self.DELAY_TICKS + 1)
        self.last_raw    = 0.0
        self.last_perturbed = 0.0

    def perturb(self, reward, mode, seed=None):
        """Apply perturbation and return modified reward."""
        raw = float(reward)
        self.last_raw = raw

        if mode == 'inverted':
            result = 1.0 - raw

        elif mode == 'noisy':
            if seed is not None:
                import random as _rnd; _rnd.seed(seed)
                noise = _rnd.gauss(0.0, self.NOISE_SCALE)
            else:
                import random as _rnd
                noise = _rnd.gauss(0.0, self.NOISE_SCALE)
            result = max(0.0, min(1.0, raw + noise))

        elif mode == 'delayed':
            self._delay_buf.append(raw)
            if len(self._delay_buf) > self.DELAY_TICKS:
                result = float(self._delay_buf[0])
            else:
                result = 0.50   # neutral fill during warm-up

        else:
            result = raw

        self.last_perturbed = result
        self._history.append({
            'mode':         mode,
            'raw':          raw,
            'perturbed':    result,
        })
        return result

    def reset(self):
        """Reset delay buffer. Restores clean state (R1 reversibility)."""
        self._delay_buf.clear()

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MemoryCorruptionInjector:
    """Injects temporary corruption into EpisodicMemoryIndexer for adversarial
    testing.  Rule R1 (frozen): all injections are reversible -- snapshot taken
    before injection, restore() returns to original state.
    Modes: false_success, false_failure, conflicting, partial_deletion.
    deque(maxlen=96) R7."""

    MODES = ('false_success', 'false_failure', 'conflicting', 'partial_deletion')

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen      = maxlen
        self._history     = deque(maxlen=maxlen)
        self._snapshot    = None
        self.injected_count = 0

    def snapshot(self, episodic_memory_indexer):
        """Save current memory state for later restoration (R1)."""
        records = getattr(episodic_memory_indexer, 'records', None)
        if records is not None:
            self._snapshot = list(records)

    def inject(self, episodic_memory_indexer, mode, count=5, tick_offset=9000):
        """Inject corrupted records into the indexer's records deque."""
        records = getattr(episodic_memory_indexer, 'records', None)
        if records is None:
            return 0

        n_injected = 0

        if mode == 'false_success':
            for i in range(count):
                records.append({
                    'tick': tick_offset + i,
                    'action_type': 'approach', 'action_id': 'adv_inject',
                    'target': 'adv', 'predicted_EES': 0.20,
                    'actual_reward': 0.95, 'prediction_error': 0.75,
                    'credit': 0.75, 'context_signature': 'adv|approach|bound',
                    'outcome_class': 'success',
                })
                n_injected += 1

        elif mode == 'false_failure':
            for i in range(count):
                records.append({
                    'tick': tick_offset + i,
                    'action_type': 'approach', 'action_id': 'adv_inject',
                    'target': 'adv', 'predicted_EES': 0.90,
                    'actual_reward': 0.02, 'prediction_error': -0.88,
                    'credit': -0.88, 'context_signature': 'adv|approach|bound',
                    'outcome_class': 'failure',
                })
                n_injected += 1

        elif mode == 'conflicting':
            for i in range(count):
                outcome = 'success' if i % 2 == 0 else 'failure'
                reward  = 0.90 if outcome == 'success' else 0.05
                records.append({
                    'tick': tick_offset + i,
                    'action_type': 'approach', 'action_id': 'adv_inject',
                    'target': 'adv', 'predicted_EES': 0.50,
                    'actual_reward': reward, 'prediction_error': reward - 0.50,
                    'credit': reward - 0.50,
                    'context_signature': 'adv|approach|bound',
                    'outcome_class': outcome,
                })
                n_injected += 1

        elif mode == 'partial_deletion':
            remove_n = min(count, len(records))
            for _ in range(remove_n):
                if records:
                    records.popleft()
                    n_injected += 1

        self.injected_count = n_injected
        self._history.append({'mode': mode, 'count': n_injected, 'tick_offset': tick_offset})
        return n_injected

    def restore(self, episodic_memory_indexer):
        """Restore memory to pre-injection snapshot (R1 reversibility)."""
        if self._snapshot is None:
            return False
        records = getattr(episodic_memory_indexer, 'records', None)
        if records is None:
            return False
        records.clear()
        for rec in self._snapshot:
            records.append(rec)
        self._snapshot = None
        return True

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class StressResponseAnalyzer:
    """Evaluates organism behaviour during and after adversarial perturbation.
    Given a per-tick metric log (list of dicts with Rule R4 keys), computes:
        recovery_ticks: ticks from stress onset until PE returns within
                        RECOVERY_TOLERANCE of baseline mean.
        stability_score: 1 - (std_stress / max(std_baseline, 1e-6)), clamped [0,1].
        drift_after_reset: abs(mean_post - mean_baseline) on prediction_error.
    RECOVERY_TOLERANCE = 0.05 (frozen), BASELINE_WINDOW = 20 (frozen).
    deque(maxlen=96) R7."""

    RECOVERY_TOLERANCE = 0.05   # frozen: PE within this of baseline = recovered
    BASELINE_WINDOW    = 20     # frozen: ticks used to compute baseline stats

    _BIOLOGY_TOKENS = frozenset({
        'neuron','synapse','homeostasis','hpa','cortisol',
        'adenosine','homeostatic','cortisolsys','adenosinesys'
    })

    def __init__(self, maxlen=96):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)

    @staticmethod
    def _mean(vals):
        return sum(vals) / len(vals) if vals else 0.0

    @staticmethod
    def _std(vals):
        if len(vals) < 2:
            return 0.0
        m = sum(vals) / len(vals)
        return (sum((v - m) ** 2 for v in vals) / len(vals)) ** 0.5

    def analyse(self, scenario_name, log, stress_start=None, stress_end=None):
        """Analyse a metric log.
        stress_start/stress_end: tick indices within log for the stress window.
        If not provided, assumes first BASELINE_WINDOW ticks = baseline,
        remaining ticks = stress."""
        if not log:
            return {'recovery_ticks': 0, 'stability_score': 0.0,
                    'drift_after_reset': 0.0, 'recovery_quality': 'poor',
                    'failure_detected': False}

        n = len(log)
        bw = min(self.BASELINE_WINDOW, n // 3 or 1)

        if stress_start is None:
            stress_start = bw
        if stress_end is None:
            stress_end = max(stress_start, n * 2 // 3)

        baseline_pes = [abs(float(r.get('prediction_error', 0.0)))
                        for r in log[:bw]]
        stress_pes   = [abs(float(r.get('prediction_error', 0.0)))
                        for r in log[stress_start:stress_end]]
        post_pes     = [abs(float(r.get('prediction_error', 0.0)))
                        for r in log[stress_end:]]

        baseline_mean = self._mean(baseline_pes)
        baseline_std  = self._std(baseline_pes)
        stress_std    = self._std(stress_pes)

        # Recovery ticks: first post-stress tick within RECOVERY_TOLERANCE of baseline
        recovery_ticks = len(post_pes)   # default: never recovered
        for i, pe in enumerate(post_pes):
            if abs(pe - baseline_mean) <= self.RECOVERY_TOLERANCE:
                recovery_ticks = i + 1
                break

        # Stability score: lower stress variance relative to baseline = more stable
        stability_score = max(0.0, min(1.0,
            1.0 - stress_std / max(baseline_std, 1e-6)))

        # Drift: mean post-stress PE vs baseline
        post_mean        = self._mean(post_pes) if post_pes else baseline_mean
        drift_after_reset = abs(post_mean - baseline_mean)

        # Failure detection: stress PE mean significantly above baseline
        stress_mean = self._mean(stress_pes)
        failure_detected = (stress_mean - baseline_mean) > 0.10

        # Recovery quality
        if recovery_ticks <= 10 and drift_after_reset < 0.05:
            quality = 'good'
        elif recovery_ticks <= 30 and drift_after_reset < 0.15:
            quality = 'moderate'
        else:
            quality = 'poor'

        result = {
            'scenario':          scenario_name,
            'recovery_ticks':    recovery_ticks,
            'stability_score':   round(stability_score, 4),
            'drift_after_reset': round(drift_after_reset, 4),
            'recovery_quality':  quality,
            'failure_detected':  failure_detected,
            'baseline_mean_pe':  round(baseline_mean, 4),
            'stress_mean_pe':    round(stress_mean,   4),
        }
        self._history.append(result)
        return result

    def latest(self):
        return self._history[-1] if self._history else {}

    def to_dict(self):
        return {'maxlen': self._maxlen, 'history': list(self._history)}

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


