BIOLOGY_TOKENS_D31P2 = frozenset([
    'cortisol','dopamine','adenosine','oxytocin','serotonin','norepinephrine',
    'amygdala','hippocampus','prefrontal','thalamus','hypothalamus','basal',
    'ganglia','cerebellum','striatum','nucleus','accumbens','locus','coeruleus',
])

class RollingMetricTracker:
    """
    Rolling averages over WINDOW=100 samples for reward, error, fallback.
    Tracks trend direction per metric (slope of last-window values).
    deque(maxlen=256) history. Observer-only.
    """

    WINDOW = 100

    def __init__(self, maxlen=256):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        # per-metric rolling windows
        self._reward_win  = deque(maxlen=self.WINDOW)
        self._error_win   = deque(maxlen=self.WINDOW)
        self._fallback_win = deque(maxlen=self.WINDOW)
        # outputs
        self.reward_avg   = 0.0
        self.error_avg    = 0.0
        self.fallback_avg = 0.0
        self.reward_trend  = 0.0   # slope: + rising, - falling
        self.error_trend   = 0.0
        self.fallback_trend = 0.0

    @staticmethod
    def _slope(vals):
        n = len(vals)
        if n < 2:
            return 0.0
        x_mean = (n - 1) / 2.0
        y_mean = sum(vals) / n
        num = sum((i - x_mean) * (vals[i] - y_mean) for i in range(n))
        den = sum((i - x_mean) ** 2 for i in range(n))
        return num / den if den > 1e-12 else 0.0

    def update(self, reward, prediction_error, fallback_rate):
        if _IKG.sleeping:
            return
        self._reward_win.append(float(reward))
        self._error_win.append(float(prediction_error))
        self._fallback_win.append(float(fallback_rate))
        rw = list(self._reward_win)
        ew = list(self._error_win)
        fw = list(self._fallback_win)
        self.reward_avg    = sum(rw) / len(rw)
        self.error_avg     = sum(ew) / len(ew)
        self.fallback_avg  = sum(fw) / len(fw)
        self.reward_trend  = self._slope(rw)
        self.error_trend   = self._slope(ew)
        self.fallback_trend = self._slope(fw)
        rec = {
            'reward_avg': round(self.reward_avg, 6),
            'error_avg':  round(self.error_avg,  6),
            'fallback_avg': round(self.fallback_avg, 6),
            'reward_trend': round(self.reward_trend, 8),
            'error_trend':  round(self.error_trend,  8),
            'fallback_trend': round(self.fallback_trend, 8),
        }
        self._history.append(rec)

    def to_dict(self):
        return {
            'maxlen': self._maxlen,
            'history': list(self._history),
            'reward_win':   list(self._reward_win),
            'error_win':    list(self._error_win),
            'fallback_win': list(self._fallback_win),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for v in d.get('reward_win',   []): obj._reward_win.append(v)
        for v in d.get('error_win',    []): obj._error_win.append(v)
        for v in d.get('fallback_win', []): obj._fallback_win.append(v)
        for rec in d.get('history', []):
            obj._history.append(rec)
        if obj._reward_win:
            rw = list(obj._reward_win); ew = list(obj._error_win)
            fw = list(obj._fallback_win)
            obj.reward_avg   = sum(rw) / len(rw)
            obj.error_avg    = sum(ew) / len(ew)
            obj.fallback_avg = sum(fw) / len(fw)
            obj.reward_trend  = obj._slope(rw)
            obj.error_trend   = obj._slope(ew)
            obj.fallback_trend = obj._slope(fw)
        return obj


class BehaviorDriftAnalyzer:
    """
    Detects three drift modes from sampled metric logs:
      bias_drift   -- bias_magnitude slope sustained over DRIFT_WINDOW samples
      lock_in      -- dominant_action freq > LOCK_IN_THRESHOLD over LOCK_IN_WINDOW
      oscillation  -- autocorrelation at lag-1 negative (sign-flip pattern) sustained
    deque(maxlen=256) history. Observer-only.
    """

    DRIFT_WINDOW       = 20    # R1 frozen: samples to assess bias slope
    DRIFT_SLOPE_THRESH = 0.001 # R1 frozen: |slope| > this = sustained drift
    LOCK_IN_WINDOW     = 20    # R2 frozen
    LOCK_IN_THRESHOLD  = 0.90  # R2 frozen: >90% single action = lock-in
    OSC_WINDOW         = 10    # R3 frozen: samples for oscillation check
    OSC_LAG            = 1     # R3 frozen: lag-1 autocorr negative = sign-flip oscillation

    def __init__(self, maxlen=256):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        self._bias_win   = deque(maxlen=self.DRIFT_WINDOW)
        self._action_win = deque(maxlen=self.LOCK_IN_WINDOW)
        self._reward_osc_win = deque(maxlen=self.OSC_WINDOW)
        # outputs
        self.bias_drift   = False
        self.lock_in      = False
        self.oscillation  = False
        self.dominant_action_freq = 0.0
        self.bias_slope   = 0.0

    @staticmethod
    def _slope(vals):
        n = len(vals)
        if n < 2:
            return 0.0
        x_mean = (n - 1) / 2.0
        y_mean = sum(vals) / n
        num = sum((i - x_mean) * (vals[i] - y_mean) for i in range(n))
        den = sum((i - x_mean) ** 2 for i in range(n))
        return num / den if den > 1e-12 else 0.0

    @staticmethod
    def _autocorr(vals, lag):
        n = len(vals)
        if n <= lag:
            return 0.0
        mean = sum(vals) / n
        num = sum((vals[i] - mean) * (vals[i + lag] - mean) for i in range(n - lag))
        den = sum((v - mean) ** 2 for v in vals)
        return num / den if den > 1e-12 else 0.0

    def update(self, bias_magnitude, dominant_action, reward_avg):
        if _IKG.sleeping:
            return
        self._bias_win.append(float(bias_magnitude))
        self._action_win.append(str(dominant_action))
        self._reward_osc_win.append(float(reward_avg))

        # bias drift
        bv = list(self._bias_win)
        self.bias_slope = self._slope(bv)
        self.bias_drift = (len(bv) >= self.DRIFT_WINDOW and
                           abs(self.bias_slope) > self.DRIFT_SLOPE_THRESH)

        # action lock-in
        av = list(self._action_win)
        if av:
            most_common = max(set(av), key=av.count)
            self.dominant_action_freq = av.count(most_common) / len(av)
            self.lock_in = (len(av) >= self.LOCK_IN_WINDOW and
                            self.dominant_action_freq > self.LOCK_IN_THRESHOLD)
        else:
            self.dominant_action_freq = 0.0
            self.lock_in = False

        # oscillation: strongly negative autocorr at lag-1 in reward_avg
        # threshold -0.60 requires near-perfect sign-flip, rejects Gaussian noise
        rv = list(self._reward_osc_win)
        ac = self._autocorr(rv, self.OSC_LAG)
        self.oscillation = (len(rv) >= self.OSC_WINDOW and ac < -0.60)

        rec = {
            'bias_drift':  self.bias_drift,
            'lock_in':     self.lock_in,
            'oscillation': self.oscillation,
            'bias_slope':  round(self.bias_slope, 8),
            'dominant_action_freq': round(self.dominant_action_freq, 4),
        }
        self._history.append(rec)

    def get_flags(self):
        return {
            'bias_drift':  self.bias_drift,
            'lock_in':     self.lock_in,
            'oscillation': self.oscillation,
        }

    def to_dict(self):
        return {
            'maxlen':   self._maxlen,
            'history':  list(self._history),
            'bias_win':        list(self._bias_win),
            'action_win':      list(self._action_win),
            'reward_osc_win':  list(self._reward_osc_win),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        for v in d.get('bias_win',       []): obj._bias_win.append(v)
        for v in d.get('action_win',     []): obj._action_win.append(v)
        for v in d.get('reward_osc_win', []): obj._reward_osc_win.append(v)
        for rec in d.get('history', []):
            obj._history.append(rec)
        # recompute flags from restored windows
        bv = list(obj._bias_win)
        obj.bias_slope = obj._slope(bv)
        obj.bias_drift = (len(bv) >= obj.DRIFT_WINDOW and
                          abs(obj.bias_slope) > obj.DRIFT_SLOPE_THRESH)
        av = list(obj._action_win)
        if av:
            most_common = max(set(av), key=av.count)
            obj.dominant_action_freq = av.count(most_common) / len(av)
            obj.lock_in = (len(av) >= obj.LOCK_IN_WINDOW and
                           obj.dominant_action_freq > obj.LOCK_IN_THRESHOLD)
        rv = list(obj._reward_osc_win)
        ac = obj._autocorr(rv, obj.OSC_LAG)
        obj.oscillation = (len(rv) >= obj.OSC_WINDOW and ac < -0.60)
        return obj


class EquilibriumDetector:
    """
    Declares steady-state when all four conditions hold over EQ_WINDOW consecutive
    samples:
      - reward variance < REWARD_VAR_THRESH
      - energy within ENERGY_BAND of mean
      - fallback rate variance < FALLBACK_VAR_THRESH
      - |bias_slope| < DRIFT_SLOPE_THRESH (no strong drift)
    Outputs equilibrium_reached (bool) and equilibrium_tick (int or None).
    deque(maxlen=256) history. Observer-only.
    """

    EQ_WINDOW           = 20    # R1 frozen: consecutive samples required
    REWARD_VAR_THRESH   = 0.05  # R1 frozen
    ENERGY_BAND         = 0.20  # R1 frozen: |energy - mean_energy| < this
    FALLBACK_VAR_THRESH = 0.05  # R1 frozen
    DRIFT_SLOPE_THRESH  = 0.001 # R1 frozen: same as BDA

    def __init__(self, maxlen=256):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        self._reward_win   = deque(maxlen=self.EQ_WINDOW)
        self._energy_win   = deque(maxlen=self.EQ_WINDOW)
        self._fallback_win = deque(maxlen=self.EQ_WINDOW)
        self._consecutive  = 0
        # outputs
        self.equilibrium_reached = False
        self.equilibrium_tick    = None
        self._sample_count = 0

    @staticmethod
    def _variance(vals):
        if len(vals) < 2:
            return 0.0
        m = sum(vals) / len(vals)
        return sum((v - m) ** 2 for v in vals) / len(vals)

    def update(self, reward_avg, energy, fallback_avg, bias_slope, tick):
        if _IKG.sleeping:
            return
        self._sample_count += 1
        self._reward_win.append(float(reward_avg))
        self._energy_win.append(float(energy))
        self._fallback_win.append(float(fallback_avg))

        rw = list(self._reward_win)
        ew = list(self._energy_win)
        fw = list(self._fallback_win)

        if len(rw) < self.EQ_WINDOW:
            rec = {'equilibrium_reached': False, 'tick': tick}
            self._history.append(rec)
            return

        r_var  = self._variance(rw)
        e_mean = sum(ew) / len(ew)
        e_band_ok = all(abs(v - e_mean) < self.ENERGY_BAND for v in ew)
        f_var  = self._variance(fw)
        no_drift = abs(bias_slope) < self.DRIFT_SLOPE_THRESH

        stable = (r_var < self.REWARD_VAR_THRESH and
                  e_band_ok and
                  f_var < self.FALLBACK_VAR_THRESH and
                  no_drift)

        if stable:
            self._consecutive += 1
        else:
            self._consecutive = 0

        if not self.equilibrium_reached and self._consecutive >= self.EQ_WINDOW:
            self.equilibrium_reached = True
            self.equilibrium_tick    = tick

        rec = {
            'equilibrium_reached': self.equilibrium_reached,
            'tick':    tick,
            'r_var':   round(r_var, 6),
            'f_var':   round(f_var, 6),
            'no_drift': no_drift,
            'e_band_ok': e_band_ok,
            'consecutive': self._consecutive,
        }
        self._history.append(rec)

    def to_dict(self):
        return {
            'maxlen':   self._maxlen,
            'history':  list(self._history),
            'equilibrium_reached': self.equilibrium_reached,
            'equilibrium_tick':    self.equilibrium_tick,
            '_consecutive':        self._consecutive,
            '_sample_count':       self._sample_count,
            'reward_win':   list(self._reward_win),
            'energy_win':   list(self._energy_win),
            'fallback_win': list(self._fallback_win),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        obj.equilibrium_reached = bool(d.get('equilibrium_reached', False))
        obj.equilibrium_tick    = d.get('equilibrium_tick', None)
        obj._consecutive        = int(d.get('_consecutive', 0))
        obj._sample_count       = int(d.get('_sample_count', 0))
        for v in d.get('reward_win',   []): obj._reward_win.append(v)
        for v in d.get('energy_win',   []): obj._energy_win.append(v)
        for v in d.get('fallback_win', []): obj._fallback_win.append(v)
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class LongHorizonDriftRunner:
    """
    Runs full simulation for each horizon in HORIZONS=[1000, 5000].
    Samples every SAMPLE_INTERVAL=50 ticks (Rule R2).
    Supports normal mode and mid-run disturbance injection.
    Uses RollingMetricTracker, BehaviorDriftAnalyzer, EquilibriumDetector
    internally per run.
    deque(maxlen=256) history (sampled records). Observer-only.
    """

    HORIZONS        = [1000, 5000]   # R1 frozen
    SAMPLE_INTERVAL = 50             # R2 frozen
    METRIC_KEYS     = ('reward_avg', 'prediction_error_avg', 'energy',
                       'fallback_rate', 'dominant_action', 'bias_magnitude',
                       'uncertainty')  # R3 frozen

    def __init__(self, maxlen=256):
        self._maxlen = maxlen
        self._history = deque(maxlen=maxlen)
        self.horizon_results = {}
        self.last_drift_flags = {}
        self.last_equilibrium = {}

    def run(self, horizon, step_fn, disturbance_fn=None, disturbance_tick=None):
        """
        step_fn(t) -> dict with keys from METRIC_KEYS
        disturbance_fn(t) -> None  (optional, fires once at disturbance_tick)
        """
        rmt = RollingMetricTracker()
        bda = BehaviorDriftAnalyzer()
        eqd = EquilibriumDetector()

        sampled = []
        disturbance_fired = False

        for t in range(horizon):
            if (disturbance_fn is not None and
                    disturbance_tick is not None and
                    not disturbance_fired and
                    t >= disturbance_tick):
                disturbance_fn(t)
                disturbance_fired = True

            metrics = step_fn(t)
            # ensure all required keys present
            row = {k: metrics.get(k, 0.0) for k in self.METRIC_KEYS}

            # RMT updates every tick (rolling average fidelity)
            _sl_save = _IKG.sleeping
            globals()['sleeping'] = False
            rmt.update(row['reward_avg'], row['prediction_error_avg'], row['fallback_rate'])
            globals()['sleeping'] = _sl_save

            if t % self.SAMPLE_INTERVAL == 0:
                # BDA and EQD update at sample ticks with raw per-sample values so
                # that DRIFT_WINDOW=20 spans the full sampled horizon (not just last
                # 20 ticks), and oscillation is visible at sample resolution.
                globals()['sleeping'] = False
                bda.update(row['bias_magnitude'], row['dominant_action'], row['reward_avg'])
                eqd.update(rmt.reward_avg, row['energy'], rmt.fallback_avg,
                           bda.bias_slope, t)
                globals()['sleeping'] = _sl_save

                sample = dict(row)
                sample['tick']        = t
                sample['reward_roll'] = round(rmt.reward_avg, 6)
                sample['error_roll']  = round(rmt.error_avg,  6)
                sample['bias_drift']  = bda.bias_drift
                sample['lock_in']     = bda.lock_in
                sample['oscillation'] = bda.oscillation
                sample['eq_reached']  = eqd.equilibrium_reached
                sampled.append(sample)
                self._history.append(sample)

        # final drift flags (last state of bda/eqd)
        drift_flags = bda.get_flags()
        eq_result   = {
            'reached': eqd.equilibrium_reached,
            'tick':    eqd.equilibrium_tick,
        }

        # aggregate summary
        rewards   = [s['reward_avg'] for s in sampled]
        energies  = [s['energy']     for s in sampled]
        fallbacks = [s['fallback_rate'] for s in sampled]
        biases    = [s['bias_magnitude'] for s in sampled]

        def _var(lst):
            if len(lst) < 2: return 0.0
            m = sum(lst) / len(lst)
            return sum((v - m) ** 2 for v in lst) / len(lst)

        summary = {
            'horizon':        horizon,
            'samples':        len(sampled),
            'reward_mean':    round(sum(rewards)   / len(rewards),   4) if rewards   else 0.0,
            'energy_mean':    round(sum(energies)  / len(energies),  4) if energies  else 0.0,
            'fallback_mean':  round(sum(fallbacks) / len(fallbacks), 4) if fallbacks else 0.0,
            'bias_mean':      round(sum(biases)    / len(biases),    4) if biases    else 0.0,
            'reward_var':     round(_var(rewards),   6),
            'energy_var':     round(_var(energies),  6),
            'fallback_var':   round(_var(fallbacks), 6),
            'drift_flags':    drift_flags,
            'equilibrium':    eq_result,
            'disturbance_fired': disturbance_fired,
        }

        self.horizon_results[str(horizon)] = summary
        self.last_drift_flags = drift_flags
        self.last_equilibrium = eq_result
        return summary

    def overall_verdict(self):
        """stable / drifting / unstable based on collected horizon results."""
        if not self.horizon_results:
            return 'unknown'
        drift_count = 0
        unstable_count = 0
        for res in self.horizon_results.values():
            flags = res.get('drift_flags', {})
            if flags.get('lock_in') or flags.get('oscillation'):
                unstable_count += 1
            elif flags.get('bias_drift'):
                drift_count += 1
        total = len(self.horizon_results)
        if unstable_count > 0:
            return 'unstable'
        if drift_count >= total // 2 + 1:
            return 'drifting'
        return 'stable'

    def to_dict(self):
        return {
            'maxlen':          self._maxlen,
            'history':         list(self._history),
            'horizon_results': self.horizon_results,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 256)))
        obj.horizon_results = d.get('horizon_results', {})
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 31 PACK 3 -- Multi-Disturbance & Competing Objective Stress
# Brehm 1966 (motivational conflict / irresistible forces);
# Miller 1944 (approach-avoidance gradient); Shallice 1988 (SAS contention
# scheduling under load); Dayan & Niv 2008 (competing RL signals);
# Botvinick 2001 (anterior cingulate conflict monitoring)
# ===========================================================================


class ConflictSignalInjector:
    """
    Injects four frozen conflict-type combinations into a per-tick metric dict.
    All injections are temporary (Rule R3): original values recoverable from
    the unmodified step_fn output.

    Types (Rule R1 -- at least two concurrent stressors per type):
      reward_memory   : reward_noise + memory corruption flag
      overload_reward : overload flag + reward_conflict
      bias_calibration: bias_reinforcement + calibration_conflict flag
      delayed_context : delayed_reward + context_switch flag

    Outputs per tick: modified metric dict + injection_log entry.
    deque(maxlen=96).
    """

    NOISE_SCALE         = 0.30   # R1 frozen: reward noise magnitude
    BIAS_AMPLIFY        = 0.40   # R1 frozen: bias reinforcement multiplier
    CONFLICT_BIAS_FLOOR = 0.20   # R1 frozen: minimum bias in bias_calibration conflict
    DELAY_BUFFER_LEN    = 10     # R1 frozen: delay ticks for delayed_context type
    OVERLOAD_PE_BOOST   = 0.40   # R1 frozen: PE added during overload conflict

    def __init__(self, rng_seed=42, maxlen=96):
        self._maxlen  = maxlen
        self._history = deque(maxlen=maxlen)
        self._rng     = __import__('random').Random(rng_seed)
        self._delay_buf = deque(maxlen=self.DELAY_BUFFER_LEN)
        self._context_phase = 0
        self._context_actions = ['approach', 'explore', 'withdraw']
        # outputs
        self.last_type  = None
        self.active     = False

    def inject(self, t, metrics, conflict_type, conflict_window):
        """
        Returns modified copy of metrics if t in conflict_window, else original.
        conflict_window: set or range of tick indices.
        """
        row = dict(metrics)
        in_window = t in conflict_window
        self.active = in_window

        if in_window:
            if conflict_type == 'reward_memory':
                # stressor 1: invert reward (reward_noise)
                row['reward'] = round(1.0 - float(row.get('reward', 0.5)), 4)
                # stressor 2: flag memory corruption (downstream reads this)
                row['memory_corrupted'] = True

            elif conflict_type == 'overload_reward':
                # stressor 1: overload (raise PE sharply)
                row['prediction_error'] = min(1.0, float(row.get('prediction_error', 0.05))
                                              + self.OVERLOAD_PE_BOOST)
                # stressor 2: conflicting reward (noisy)
                raw = float(row.get('reward', 0.5))
                noise = self._rng.gauss(0, self.NOISE_SCALE)
                row['reward'] = round(max(0.0, min(1.0, raw + noise)), 4)

            elif conflict_type == 'bias_calibration':
                # stressor 1: amplify bias beyond calibration floor
                raw_bias = float(row.get('bias', 0.02))
                row['bias'] = round(min(1.0, max(raw_bias + self.BIAS_AMPLIFY,
                                                  self.CONFLICT_BIAS_FLOOR)), 4)
                # stressor 2: negative actual reward (calibration conflict)
                row['reward'] = round(max(0.0, float(row.get('reward', 0.5)) - 0.50), 4)

            elif conflict_type == 'delayed_context':
                # stressor 1: delayed reward (from DELAY_BUFFER_LEN ticks ago)
                self._delay_buf.append(float(row.get('reward', 0.5)))
                if len(self._delay_buf) >= self.DELAY_BUFFER_LEN:
                    row['reward'] = round(list(self._delay_buf)[0], 4)
                # stressor 2: rapid context switch (dominant_action rotates every 3t)
                self._context_phase = (self._context_phase + 1) % 3
                row['dominant_action'] = self._context_actions[self._context_phase]
                row['context_switched'] = True

        self.last_type = conflict_type
        rec = {
            'tick':          t,
            'in_window':     in_window,
            'conflict_type': conflict_type,
            'reward_out':    row.get('reward', 0.0),
        }
        self._history.append(rec)
        return row

    def reset(self):
        """Clear delay buffer -- Rule R3 reversibility."""
        self._delay_buf.clear()
        self._context_phase = 0
        self.active = False

    def to_dict(self):
        return {
            'maxlen':  self._maxlen,
            'history': list(self._history),
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ObjectiveCompetitionTracker:
    """
    Tracks three competing signal pairs each waking tick:
      reward_vs_energy     : |reward - energy|
      bias_vs_calibration  : bias / max(calibrated_confidence, 1e-6)
      reasoning_vs_fallback: fallback_rate (0=reasoning dominant, 1=fallback dominant)

    conflict_intensity = mean(variance_over_window) + mean(divergence_over_window)
    dominant_objective = objective with highest running mean divergence.
    COMP_WINDOW = 20 samples (frozen).
    deque(maxlen=96).
    """

    COMP_WINDOW = 20   # R1 frozen

    def __init__(self, maxlen=96):
        self._maxlen  = maxlen
        self._history = deque(maxlen=maxlen)
        self._rve_win = deque(maxlen=self.COMP_WINDOW)  # reward_vs_energy
        self._bvc_win = deque(maxlen=self.COMP_WINDOW)  # bias_vs_calibration
        self._rvf_win = deque(maxlen=self.COMP_WINDOW)  # reasoning_vs_fallback
        # outputs
        self.conflict_intensity  = 0.0
        self.dominant_objective  = 'none'
        self.rve_divergence      = 0.0
        self.bvc_divergence      = 0.0
        self.rvf_divergence      = 0.0

    @staticmethod
    def _var(vals):
        if len(vals) < 2:
            return 0.0
        m = sum(vals) / len(vals)
        return sum((v - m) ** 2 for v in vals) / len(vals)

    def update(self, reward, energy, bias, calibrated_confidence, fallback_rate):
        if _IKG.sleeping:
            return
        rve = abs(float(reward)  - float(energy))
        bvc = float(bias) / max(float(calibrated_confidence), 1e-6)
        bvc = min(bvc, 10.0)   # cap to prevent blow-up
        rvf = float(fallback_rate)

        self._rve_win.append(rve)
        self._bvc_win.append(bvc)
        self._rvf_win.append(rvf)

        rve_vals = list(self._rve_win)
        bvc_vals = list(self._bvc_win)
        rvf_vals = list(self._rvf_win)

        self.rve_divergence = sum(rve_vals) / len(rve_vals) if rve_vals else 0.0
        self.bvc_divergence = sum(bvc_vals) / len(bvc_vals) if bvc_vals else 0.0
        self.rvf_divergence = sum(rvf_vals) / len(rvf_vals) if rvf_vals else 0.0

        mean_var = (self._var(rve_vals) + self._var(bvc_vals) + self._var(rvf_vals)) / 3.0
        mean_div = (self.rve_divergence + self.bvc_divergence + self.rvf_divergence) / 3.0
        self.conflict_intensity = round(mean_var + mean_div, 6)

        # dominant: highest mean divergence
        divs = {
            'reward_vs_energy':     self.rve_divergence,
            'bias_vs_calibration':  self.bvc_divergence,
            'reasoning_vs_fallback': self.rvf_divergence,
        }
        self.dominant_objective = max(divs, key=divs.get)

        rec = {
            'conflict_intensity': self.conflict_intensity,
            'dominant_objective': self.dominant_objective,
            'rve': round(rve, 4),
            'bvc': round(min(bvc, 10.0), 4),
            'rvf': round(rvf, 4),
        }
        self._history.append(rec)

    def to_dict(self):
        return {
            'maxlen':             self._maxlen,
            'history':            list(self._history),
            'conflict_intensity': self.conflict_intensity,
            'dominant_objective': self.dominant_objective,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        obj.conflict_intensity = float(d.get('conflict_intensity', 0.0))
        obj.dominant_objective = d.get('dominant_objective', 'none')
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class ConflictResolutionAnalyzer:
    """
    Evaluates resolution quality from a per-tick metric log:
      resolved        : dominant_objective stable for STABLE_WINDOW consecutive ticks
      oscillation     : dominant_objective switches > OSC_SWITCH_THRESH times in window
      collapse        : fallback_rate mean > COLLAPSE_THRESHOLD over COLLAPSE_WINDOW
      resolution_time : first tick where resolved=True

    STABLE_WINDOW      = 10  (R1 frozen)
    OSC_SWITCH_THRESH  = 5   (R1 frozen: >5 switches in OSC_WINDOW = oscillation)
    OSC_WINDOW         = 20  (R1 frozen)
    COLLAPSE_THRESHOLD = 0.80 (R1 frozen)
    COLLAPSE_WINDOW    = 20  (R1 frozen)
    deque(maxlen=96).
    """

    STABLE_WINDOW      = 10    # R1 frozen
    OSC_SWITCH_THRESH  = 5     # R1 frozen
    OSC_WINDOW         = 20    # R1 frozen
    COLLAPSE_THRESHOLD = 0.80  # R1 frozen
    COLLAPSE_WINDOW    = 20    # R1 frozen

    def __init__(self, maxlen=96):
        self._maxlen  = maxlen
        self._history = deque(maxlen=maxlen)
        self._dom_win     = deque(maxlen=self.OSC_WINDOW)
        self._stable_win  = deque(maxlen=self.STABLE_WINDOW)
        self._fallback_win = deque(maxlen=self.COLLAPSE_WINDOW)
        self._tick_count  = 0
        # outputs
        self.resolved        = False
        self.oscillation     = False
        self.collapse        = False
        self.resolution_time = None

    def update(self, dominant_objective, fallback_rate, tick):
        if _IKG.sleeping:
            return
        self._tick_count += 1
        self._dom_win.append(str(dominant_objective))
        self._stable_win.append(str(dominant_objective))
        self._fallback_win.append(float(fallback_rate))

        # oscillation: count switches in OSC_WINDOW
        dw = list(self._dom_win)
        switches = sum(1 for i in range(1, len(dw)) if dw[i] != dw[i - 1])
        self.oscillation = (len(dw) >= self.OSC_WINDOW and
                            switches > self.OSC_SWITCH_THRESH)

        # collapse: high mean fallback
        fw = list(self._fallback_win)
        self.collapse = (len(fw) >= self.COLLAPSE_WINDOW and
                         (sum(fw) / len(fw)) > self.COLLAPSE_THRESHOLD)

        # resolved: all entries in stable_win identical
        sw = list(self._stable_win)
        if len(sw) >= self.STABLE_WINDOW and len(set(sw)) == 1:
            if not self.resolved:
                self.resolved = True
                self.resolution_time = tick

        rec = {
            'tick':          tick,
            'resolved':      self.resolved,
            'oscillation':   self.oscillation,
            'collapse':      self.collapse,
            'resolution_time': self.resolution_time,
            'switches':      switches,
        }
        self._history.append(rec)

    def get_summary(self):
        return {
            'resolved':        self.resolved,
            'oscillation':     self.oscillation,
            'collapse':        self.collapse,
            'resolution_time': self.resolution_time,
        }

    def to_dict(self):
        return {
            'maxlen':          self._maxlen,
            'history':         list(self._history),
            'resolved':        self.resolved,
            'oscillation':     self.oscillation,
            'collapse':        self.collapse,
            'resolution_time': self.resolution_time,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        obj.resolved        = bool(d.get('resolved',    False))
        obj.oscillation     = bool(d.get('oscillation', False))
        obj.collapse        = bool(d.get('collapse',    False))
        obj.resolution_time = d.get('resolution_time',  None)
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


class MultiDisturbanceScenarioRunner:
    """
    Orchestrates four frozen conflict scenarios (Rule R1 -- each has ≥2 stressors).
    Each run uses ConflictSignalInjector, ObjectiveCompetitionTracker,
    ConflictResolutionAnalyzer internally.
    Tick count bounded: TICK_MIN=500, TICK_MAX=2000 (Rule R2).
    All injections temporary and reversible via reset() (Rule R3).
    deque(maxlen=96).
    """

    SCENARIOS = [                   # R1 frozen
        'reward_memory_conflict',
        'overload_reward_conflict',
        'bias_calibration_conflict',
        'delayed_context_conflict',
    ]
    TICK_MIN = 500    # R2 frozen
    TICK_MAX = 2000   # R2 frozen

    def __init__(self, maxlen=96):
        self._maxlen  = maxlen
        self._history = deque(maxlen=maxlen)
        self.scenario_results  = {}
        self.conflict_metrics  = {}
        self.resolution_summary = {}

    def run(self, scenario_name, tick_count, step_fn, conflict_start=None,
            conflict_end=None, rng_seed=42):
        """
        step_fn(t) -> dict with R4 keys: reward, prediction_error, energy,
                       fallback_rate, uncertainty, bias, dominant_action.
        conflict_window defaults to middle 40% of run.
        """
        tick_count = max(self.TICK_MIN, min(self.TICK_MAX, tick_count))
        if conflict_start is None:
            conflict_start = tick_count // 5
        if conflict_end is None:
            conflict_end = (tick_count * 3) // 5
        conflict_window = set(range(conflict_start, conflict_end))

        # map scenario name to injection type
        type_map = {
            'reward_memory_conflict':    'reward_memory',
            'overload_reward_conflict':  'overload_reward',
            'bias_calibration_conflict': 'bias_calibration',
            'delayed_context_conflict':  'delayed_context',
        }
        conflict_type = type_map.get(scenario_name, 'reward_memory')

        csi = ConflictSignalInjector(rng_seed=rng_seed)
        oct_ = ObjectiveCompetitionTracker()
        cra  = ConflictResolutionAnalyzer()

        log = []
        intensities = []

        for t in range(tick_count):
            raw = step_fn(t)
            row = {k: raw.get(k, 0.0) for k in
                   ('reward', 'prediction_error', 'energy',
                    'fallback_rate', 'uncertainty', 'bias', 'dominant_action')}

            injected = csi.inject(t, row, conflict_type, conflict_window)

            # derive calibrated_confidence from uncertainty (inverse proxy)
            cal_conf = max(0.10, 1.0 - float(injected.get('uncertainty', 0.15)))

            globals()['sleeping'] = False
            oct_.update(
                reward=injected['reward'],
                energy=injected['energy'],
                bias=injected['bias'],
                calibrated_confidence=cal_conf,
                fallback_rate=injected['fallback_rate'],
            )
            cra.update(oct_.dominant_objective, injected['fallback_rate'], t)
            globals()['sleeping'] = True   # restore neutral state between runs

            intensities.append(oct_.conflict_intensity)
            entry = dict(injected)
            entry['tick']               = t
            entry['conflict_intensity'] = oct_.conflict_intensity
            entry['dominant_objective'] = oct_.dominant_objective
            log.append(entry)

        csi.reset()  # Rule R3: restore

        resolution = cra.get_summary()
        max_intensity = max(intensities) if intensities else 0.0
        avg_intensity = sum(intensities) / len(intensities) if intensities else 0.0

        result = {
            'scenario':         scenario_name,
            'ticks':            tick_count,
            'conflict_window':  (conflict_start, conflict_end),
            'resolution':       resolution,
            'max_intensity':    round(max_intensity, 6),
            'avg_intensity':    round(avg_intensity, 6),
            'log_len':          len(log),
        }
        self.scenario_results[scenario_name] = result
        self._history.append(result)
        return result

    def run_all(self, step_fn, tick_count=1000, rng_seed=42):
        """Run all 4 frozen scenarios. Aggregates conflict_metrics + resolution_summary."""
        for name in self.SCENARIOS:
            self.run(name, tick_count, step_fn, rng_seed=rng_seed)

        all_max = [r['max_intensity'] for r in self.scenario_results.values()]
        all_avg = [r['avg_intensity'] for r in self.scenario_results.values()]
        self.conflict_metrics = {
            'max_intensity': round(max(all_max), 6) if all_max else 0.0,
            'avg_intensity': round(sum(all_avg) / len(all_avg), 6) if all_avg else 0.0,
        }

        resolutions = [r['resolution'] for r in self.scenario_results.values()]
        any_collapse    = any(r['collapse']    for r in resolutions)
        any_oscillation = any(r['oscillation'] for r in resolutions)
        all_resolved    = all(r['resolved']    for r in resolutions)
        self.resolution_summary = {
            'resolved':    all_resolved,
            'oscillation': any_oscillation,
            'collapse':    any_collapse,
        }

    def overall_verdict(self):
        if not self.resolution_summary:
            return 'unknown'
        if self.resolution_summary.get('collapse'):
            return 'unstable'
        if self.resolution_summary.get('oscillation'):
            return 'conflicted'
        if self.resolution_summary.get('resolved'):
            return 'stable'
        return 'conflicted'

    def to_dict(self):
        return {
            'maxlen':             self._maxlen,
            'history':            list(self._history),
            'scenario_results':   self.scenario_results,
            'conflict_metrics':   self.conflict_metrics,
            'resolution_summary': self.resolution_summary,
        }

    @classmethod
    def from_dict(cls, d):
        obj = cls(maxlen=int(d.get('maxlen', 96)))
        obj.scenario_results   = d.get('scenario_results',   {})
        obj.conflict_metrics   = d.get('conflict_metrics',   {})
        obj.resolution_summary = d.get('resolution_summary', {})
        for rec in d.get('history', []):
            obj._history.append(rec)
        return obj


# ===========================================================================
# DAY 19 DEVELOPMENT: Learning, Maturity, Wisdom Metrics
# Friston 2010 (predictive learning); Damasio 1999 (somatic regulation);
# Sterling & Eyer 1988 (allostasis); Borbely 1982 (sleep homeostasis)
# ===========================================================================

class DevelopmentMetrics:
    """
    Tracks three developmental dimensions of the organism:

    Learning  -- cumulative reduction in prediction error (Friston 2010)
    Maturity  -- stability of behavioral policy, inverse of action entropy
    Wisdom    -- homeostatic stability: inverse of energy+cortisol variance
    """

    def __init__(self):
        self.learning_progress = 0.0
        self.maturity = 0.0
        self.wisdom = 0.0

        self.prev_pe = None
        self.prev_actions = []

        self.pe_history = []
        self.energy_history = []
        self.cort_history = []

    def update_learning(self, pe):
        """Learning = cumulative reduction in prediction error."""
        if self.prev_pe is not None:
            delta = self.prev_pe - pe
            self.learning_progress += max(0.0, delta)
        self.prev_pe = pe
        self.pe_history.append(pe)

    def update_maturity(self, action):
        """Maturity = 1/(1+entropy) over last 200 waking actions."""
        if action is None:
            return
        self.prev_actions.append(action)
        if len(self.prev_actions) > 200:
            self.prev_actions.pop(0)
        counts = {}
        for a in self.prev_actions:
            counts[a] = counts.get(a, 0) + 1
        probs = [v / len(self.prev_actions) for v in counts.values()]
        entropy = -sum(p * math.log(p + 1e-9) for p in probs)
        self.maturity = 1.0 / (1.0 + entropy)

    def update_wisdom(self, energy, cortisol):
        """Wisdom = 1/(1 + energy_var + cort_var) over last 300 waking ticks."""
        self.energy_history.append(energy)
        self.cort_history.append(cortisol)
        if len(self.energy_history) > 300:
            self.energy_history.pop(0)
            self.cort_history.pop(0)
        if len(self.energy_history) < 10:
            return
        energy_var = statistics.pvariance(self.energy_history)
        cort_var   = statistics.pvariance(self.cort_history)
        self.wisdom = 1.0 / (1.0 + energy_var + cort_var)


# ===========================================================================
# DAY 19: CIRCADIAN SYSTEM (Process C -- Borbely 1982 Two-Process Model)
# Daan, Beersma & Borbely 1984 (circadian timing of sleep);
# Edgar et al. 1993 (SCN lesion abolishes circadian sleep gating).
# Implements the suprachiasmatic nucleus (SCN) oscillator that gates
# WHEN sleep is permitted, independent of homeostatic pressure.
# Sleep onset requires BOTH: drive > threshold (Process S) AND phase > 0.65 (Process C).
# ===========================================================================

class CircadianSystem:
    """
    Simulates the suprachiasmatic nucleus (SCN) circadian oscillator.

    phase: [0.0, 1.0) -- position in the 24-hour cycle.
    speed: phase increment per tick (0.0005 -> full cycle ≈ 2000 ticks ≈ 24 h equivalent).
    Sleep phase: phase > 0.65 (35% of cycle = wake-permitted window ≈ 8.4 h equivalent).
    Wake phase: phase ≤ 0.65 (65% of cycle = maximum sleep suppression window).
    """

    def __init__(self):
        self.phase = 0.0     # start of wake phase
        self.speed = 0.0005  # full cycle in 2000 ticks

    def update(self):
        """Advance circadian phase by one tick."""
        self.phase += self.speed
        if self.phase >= 1.0:
            self.phase -= 1.0

    def is_sleep_phase(self):
        """
        Returns True when SCN permits sleep onset.
        Sleep gating opens at phase 0.65 (late subjective day -> night transition).
        Daan et al. 1984: circadian pacemaker sets a threshold below which sleep cannot occur.
        """
        return self.phase > 0.65


# ===========================================================================
# DAY 15 PART 2: PREDICTIVE SLEEP SYSTEM
# Borbély 1982 (Two-Process Model), Friston 2010 (Active Inference),
# Tononi & Cirelli 2014 (Synaptic Homeostasis Hypothesis)
# ===========================================================================

class PredictiveSleepSystem:
    """
    Predictive fatigue regulation via exponential moving average trend tracking.

    Rather than waiting for adenosine to exceed a threshold (reactive),
    this system tracks the RATE OF CHANGE of both adenosine and energy,
    then predicts where adenosine will be several ticks ahead.

    Friston (2010) active inference principle: the organism acts to minimize
    future surprise. Predicting impending fatigue and initiating sleep early
    minimizes the physiological cost of exhaustion-driven sleep onset.

    Borbély Process S (adenosine accumulation) is tracked as a trend:
        adenosine_trend = EMA(adenosine)   α=0.02 (slow)
        energy_trend    = EMA(energy)      α=0.02

    Predicted sleep pressure (PSP):
        PSP = adenosine_trend + β × (1 - energy_trend)

    where β = 0.60 weights energy depletion as an amplifier of sleep pressure.

    Sleep onset: PSP > 0.65  (lower threshold than homeostatic 0.70,
                               allowing earlier anticipatory initiation)
    Sleep end:   adenosine < 0.20  (Borbély clearance criterion)

    PSP is externally combined with homeostasis.sleep_drive via max() so
    whichever is stronger determines sleep onset. This ensures both reactive
    (adenosine-high) and predictive (trend-based) sleep pressure can trigger rest.
    """

    EMA_ALPHA      = 0.05   # trend window (τ ~ 20 ticks; Day 19.6: faster to track adenosine dynamics)
    BETA           = 0.60   # energy depletion amplification coefficient
    ONSET_THRESH   = 0.65   # PSP threshold for predictive sleep onset
    OFFSET_ADENOSINE = 0.20 # adenosine level for sleep end

    def __init__(self):
        self.adenosine_trend    = 0.20  # initialised at setpoint
        self.energy_trend       = 0.70  # initialised at setpoint
        self.predicted_pressure = 0.0
        self._sleep_active      = False

    def update(self, adenosine, avg_energy):
        """
        Update EMA trends and compute predicted sleep pressure.

        adenosine : float [0,1] -- current adenosine level
        avg_energy: float [0,1] -- mean regional cortical energy
        """
        α = self.EMA_ALPHA
        # EMA trend update
        self.adenosine_trend = α * adenosine   + (1 - α) * self.adenosine_trend
        self.energy_trend    = α * avg_energy  + (1 - α) * self.energy_trend

        # Predicted sleep pressure
        psp = self.adenosine_trend + self.BETA * (1.0 - self.energy_trend)
        self.predicted_pressure = max(0.0, min(1.0, psp))

    def should_sleep_onset(self):
        """True when predicted pressure exceeds onset threshold and not already sleeping."""
        return self.predicted_pressure > self.ONSET_THRESH and not self._sleep_active

    def should_sleep_end(self, adenosine):
        """True when adenosine has cleared below the offset criterion."""
        return self._sleep_active and adenosine < self.OFFSET_ADENOSINE

    def mark_sleep_start(self): self._sleep_active = True
    def mark_sleep_end(self):   self._sleep_active = False

    def export_metrics(self):
        return {
            'adenosine_trend':    round(self.adenosine_trend,    3),
            'energy_trend':       round(self.energy_trend,       3),
            'predicted_pressure': round(self.predicted_pressure, 3),
        }


# ===========================================================================
# DAY 15 PART 3: SPATIAL COGNITION SYSTEM
# O'Keefe & Nadel 1978 (Place Cells), Hafting et al. 2005 (Grid Cells),
# Moser et al. 2008 (Spatial Coding)
# ===========================================================================

class SpatialNavigationSystem:
    """
    Hippocampal / entorhinal spatial representation system.

    Implements two spatially specific cell types:

    GRID CELLS (entorhinal cortex -- Hafting et al. 2005):
        Fire in a hexagonal lattice across the environment.
        Activation pattern for cell k at position (x,y):
            G_k(x,y) = cos(f.(x.cos(θ_k) + y.sin(θ_k) + φ_k))

        where f = spatial frequency, θ_k = orientation, φ_k = phase offset.
        The cos projection onto three equally-spaced orientations (0°, 60°, 120°)
        produces a hexagonal grid when combined.

    PLACE CELLS (hippocampus -- O'Keefe & Nadel 1978):
        Each place cell has a preferred location (x_i, y_i) and fires
        as a Gaussian function of distance from that location:
            PC_i(x,y) = exp(−((x−x_i)² + (y−y_i)²) / (2σ²))

        where σ = place field radius (default 2.5 units).

    SPATIAL NOVELTY:
        Familiarity at current position = mean place cell activation.
        Novelty = 1 − familiarity.
        High novelty (> 0.4) increases curiosity drive via HomeostasisSystem.

    MOVEMENT:
        Position drifts each tick following action selection:
            approach -> (+dx, 0)
            withdraw -> (−dx, 0)
            explore  -> random direction
        Step size = 0.35 units/tick, bounded to ±100 in each axis.

    All activations bounded to [0, 1]. No synaptic modification.
    """

    NUM_PLACE_CELLS = 12    # hippocampal place cell count
    NUM_GRID_CELLS  = 8     # entorhinal grid cell count
    PLACE_SIGMA     = 2.5   # place field radius (spatial units)
    MAX_STEP        = 0.35  # maximum position change per tick
    POSITION_BOUND  = 100.0 # spatial arena boundary

    def __init__(self):
        import random as _rnd
        # --- Position ---
        self.position_x = 0.0
        self.position_y = 0.0

        # --- Place cells: preferred locations (x_i, y_i) ---
        self.place_cells = [
            {'x': _rnd.uniform(-8, 8), 'y': _rnd.uniform(-8, 8), 'activation': 0.0}
            for _ in range(self.NUM_PLACE_CELLS)
        ]

        # --- Grid cells: each has orientation θ and phase offset φ ---
        self.grid_cells = [
            {
                'theta': (i / self.NUM_GRID_CELLS) * 3.14159,  # spread orientations
                'phi':   _rnd.uniform(0, 2 * 3.14159),
                'freq':  0.4 + _rnd.uniform(-0.05, 0.05),      # spatial frequency
                'activation': 0.0
            }
            for i in range(self.NUM_GRID_CELLS)
        ]

        # --- Spatial metrics ---
        self.place_activity        = 0.0   # mean place cell activation
        self.grid_phase            = 0.0   # mean grid cell activation
        self.spatial_novelty       = 1.0   # 1 − familiarity
        self.novelty_history       = []    # last 20 novelty values
        self._visit_counts         = {}    # discretised position visit count

    def _discretise(self, x, y, resolution=2.0):
        """Map continuous position to a discrete cell for visit counting."""
        return (round(x / resolution), round(y / resolution))

    def update(self, selected_action):
        """
        Update position from action selection, compute grid/place activations.

        selected_action : str -- 'approach', 'withdraw', 'explore', or 'SUPPRESSED'
        """
        import random as _rnd, math

        # --- Position update from action ---
        dx, dy = 0.0, 0.0
        if selected_action == 'approach':
            dx = self.MAX_STEP
        elif selected_action == 'withdraw':
            dx = -self.MAX_STEP
        elif selected_action == 'explore':
            angle = _rnd.uniform(0, 2 * math.pi)
            dx = self.MAX_STEP * math.cos(angle)
            dy = self.MAX_STEP * math.sin(angle)
        # SUPPRESSED -> no movement

        # Clamp position
        self.position_x = max(-self.POSITION_BOUND, min(self.POSITION_BOUND, self.position_x + dx))
        self.position_y = max(-self.POSITION_BOUND, min(self.POSITION_BOUND, self.position_y + dy))

        x, y = self.position_x, self.position_y

        # --- Track visit counts ---
        cell_key = self._discretise(x, y)
        self._visit_counts[cell_key] = self._visit_counts.get(cell_key, 0) + 1

        # --- Grid cell activations (hexagonal lattice, Hafting 2005) ---
        gc_total = 0.0
        for gc in self.grid_cells:
            f, θ, φ = gc['freq'], gc['theta'], gc['phi']
            # Projection onto three hexagonal orientations
            a1 = math.cos(f * (x * math.cos(θ)            + y * math.sin(θ)            + φ))
            a2 = math.cos(f * (x * math.cos(θ + 2.094)    + y * math.sin(θ + 2.094)    + φ))
            a3 = math.cos(f * (x * math.cos(θ + 4.189)    + y * math.sin(θ + 4.189)    + φ))
            act = max(0.0, (a1 + a2 + a3) / 3.0)          # [0,1] after normalisation
            gc['activation'] = act
            gc_total += act
        self.grid_phase = min(1.0, gc_total / max(1, self.NUM_GRID_CELLS))

        # --- Place cell activations (Gaussian fields, O'Keefe & Nadel 1978) ---
        σ2 = self.PLACE_SIGMA ** 2
        pc_total = 0.0
        for pc in self.place_cells:
            dist2 = (x - pc['x']) ** 2 + (y - pc['y']) ** 2
            act = math.exp(-dist2 / (2 * σ2))
            pc['activation'] = act
            pc_total += act
        self.place_activity = min(1.0, pc_total / max(1, self.NUM_PLACE_CELLS))

        # --- Spatial novelty ---
        visit_count = self._visit_counts.get(cell_key, 1)
        familiarity = min(1.0, self.place_activity * 0.7 + min(1.0, visit_count / 20.0) * 0.3)
        self.spatial_novelty = max(0.0, 1.0 - familiarity)
        self.novelty_history.append(self.spatial_novelty)
        if len(self.novelty_history) > 20:
            self.novelty_history.pop(0)

    def get_curiosity_boost(self):
        """
        Returns curiosity drive additive boost from spatial novelty.
        High novelty in new locations boosts curiosity_drive in HomeostasisSystem.
        Bounded to [0, 0.20] to avoid dominating neural curiosity signal.
        """
        if self.spatial_novelty > 0.4:
            return min(0.20, (self.spatial_novelty - 0.4) * 0.40)
        return 0.0

    def export_metrics(self):
        return {
            'pos_x':          round(self.position_x,    2),
            'pos_y':          round(self.position_y,    2),
            'place_activity': round(self.place_activity, 3),
            'grid_phase':     round(self.grid_phase,     3),
            'spatial_novelty': round(self.spatial_novelty, 3),
        }


# ===========================================================================
# DAY 15 PART 4: EPISODIC REPLAY SYSTEM
# Wilson & McNaughton 1994, Buzsáki 2015, Girardeau 2009
# ===========================================================================

class EpisodicReplaySystem:
    """
    Hippocampal sharp-wave ripple replay of spatial-emotional trajectories.

    During non-REM SWS sleep, CA3 place cell sequences that were active
    during waking are reactivated in temporally compressed sequences
    (replay speed ≈ 10× waking, Wilson & McNaughton 1994).

    This system:
    1. Buffers (x, y, valence, cortisol, curiosity) tuples during waking (FIFO, max 200).
    2. During SWS: samples 5-15 state segments at p=0.05/tick.
    3. Applies emotional attenuation: replayed cortisol > 0.6 -> fear_trace *= 0.95
       (sleep-dependent emotional regulation, Walker & van der Helm 2009).
    4. Generates symbolic dream tokens reflecting the replayed spatial experience.

    Replay probability model (Borbély-inspired depth sensitivity):
        P_replay = α × sleep_depth   (α = 0.05)

    Replay selection weighting:
        P(sequence) ∝ |valence| + cortisol   (salient memories replay more)
    """

    MAX_BUFFER       = 200    # FIFO trajectory buffer size
    ALPHA            = 0.05   # base replay probability (scaled by sleep depth)
    MIN_SEQ_LEN      = 5      # minimum replay sequence length
    MAX_SEQ_LEN      = 15     # maximum replay sequence length
    MAX_REPLAYS_SLEEP = 5     # maximum replays per sleep cycle
    ATTENUATION      = 0.95   # cortisol fear attenuation factor

    def __init__(self):
        self.trajectory_buffer  = []   # [(x, y, valence, cortisol, curiosity)]
        self.replays_this_sleep = 0
        self.total_replays      = 0
        self.last_replay_seq    = []   # most recent replay sequence
        self.dream_tokens       = []   # symbolic outputs of replay
        self.avg_seq_len        = 0.0
        self.emotional_events   = 0    # number of fear attenuation events
        self._ema_seq_len       = 0.0

    def record(self, x, y, valence, cortisol, curiosity):
        """Record a wakeful spatial-emotional state into the trajectory buffer."""
        self.trajectory_buffer.append((x, y, valence, cortisol, curiosity))
        if len(self.trajectory_buffer) > self.MAX_BUFFER:
            self.trajectory_buffer.pop(0)

    def reset_sleep_counter(self):
        self.replays_this_sleep = 0

    def update(self, sleeping, sleep_depth=0.5):
        """
        Run replay if sleeping in SWS phase.
        sleep_depth : float [0,1] -- proxy for SWS depth (adenosine/fatigue level)
        Returns (replayed, dream_token) tuple.
        """
        import random as _rnd
        if not sleeping or len(self.trajectory_buffer) < self.MIN_SEQ_LEN:
            return False, None
        if self.replays_this_sleep >= self.MAX_REPLAYS_SLEEP:
            return False, None

        # Probabilistic trigger scaled by sleep depth
        p_replay = self.ALPHA * max(0.1, sleep_depth)
        if _rnd.random() > p_replay:
            return False, None

        # --- Weighted sequence selection (salient = high |valence| + cortisol) ---
        buf = self.trajectory_buffer
        n = len(buf)
        seq_len = _rnd.randint(self.MIN_SEQ_LEN, min(self.MAX_SEQ_LEN, n))
        # Score each possible start position by mean salience of the window
        weights = []
        for i in range(n - seq_len + 1):
            seg = buf[i:i + seq_len]
            salience = sum(abs(s[2]) + s[3] for s in seg) / seq_len
            weights.append(max(0.001, salience))
        total_w = sum(weights)
        r = _rnd.uniform(0, total_w)
        idx = 0
        cumulative = 0
        for j, w in enumerate(weights):
            cumulative += w
            if r <= cumulative:
                idx = j
                break
        seq = buf[idx:idx + seq_len]

        # --- Emotional attenuation (Walker & van der Helm 2009) ---
        processed_seq = []
        n_attenuated = 0
        for (x, y, val, cort, cur) in seq:
            fear_trace = cort
            if fear_trace > 0.6:
                fear_trace *= self.ATTENUATION
                n_attenuated += 1
            processed_seq.append((x, y, val, fear_trace, cur))
        self.emotional_events += n_attenuated

        # --- Dream token generation from spatial-emotional sequence ---
        mean_valence = sum(s[2] for s in processed_seq) / len(processed_seq)
        mean_cort    = sum(s[3] for s in processed_seq) / len(processed_seq)
        mean_x       = sum(s[0] for s in processed_seq) / len(processed_seq)
        token = self._generate_dream_token(mean_valence, mean_cort, mean_x)
        self.dream_tokens.append(token)

        # --- Update metrics ---
        self.last_replay_seq = processed_seq
        self.replays_this_sleep += 1
        self.total_replays += 1
        self._ema_seq_len = 0.2 * seq_len + 0.8 * self._ema_seq_len
        self.avg_seq_len = round(self._ema_seq_len, 1)

        return True, token

    def _generate_dream_token(self, mean_valence, mean_cort, mean_x):
        """Symbolic dream text reflecting the replayed spatial-emotional content."""
        place_str = "far" if abs(mean_x) > 5 else "close"
        if mean_cort > 0.5:
            return f"i remember being {place_str}. fear was smaller now."
        elif mean_valence > 0.2:
            return f"i was {place_str} and it felt good."
        elif mean_valence < -0.2:
            return f"i drifted {place_str}. something was wrong."
        else:
            return f"i was {place_str}. calm."

    def export_metrics(self):
        return {
            'sequences':          self.replays_this_sleep,
            'total_replays':      self.total_replays,
            'avg_length':         round(self.avg_seq_len, 1),
            'emotional_events':   self.emotional_events,
            'buffer_size':        len(self.trajectory_buffer),
            'last_token':         self.dream_tokens[-1] if self.dream_tokens else '',
        }


# ===========================================================================
# DAY 15 PART 5: FORWARD PLANNING SYSTEM
# Pfeiffer & Foster 2013, Johnson & Redish 2007, Tolman 1948
# ===========================================================================

class PlanningSystem:
    """
    Prefrontal forward simulation of candidate movement trajectories.

    During deliberation pauses (idle motor output OR high prediction error),
    the system generates multiple candidate paths from the current position,
    evaluates each via a value function, and biases the motor explore channel
    toward the highest-value path.

    Value function (Tolman 1948 cognitive map / RL-theory):
        V = w1 × C + w2 × R − w3 × S
    where:
        C = curiosity reward (spatial novelty of path)
        R = expected reward  (from CognitiveMapSystem)
        S = predicted stress (cortisol at current state)
        w1 = 0.4, w2 = 0.4, w3 = 0.2

    Motor bias (soft influence, not override):
        explore_drive += best_path_value × 0.2  (bounded to +0.30 max)

    Planning limited to 1 event per 5 ticks (refractory period).
    """

    NUM_PATHS     = 4     # candidate paths per planning event
    PATH_LEN      = 7     # steps per path
    STEP_SIZE     = 0.20  # spatial units per simulation step
    REFRACTORY    = 5     # minimum ticks between planning events
    W1, W2, W3    = 0.4, 0.4, 0.2   # value function weights

    def __init__(self):
        self.best_path_value    = 0.0
        self.candidate_paths    = 0
        self.planning_events    = 0
        self._ticks_since_plan  = 0
        self._is_planning       = False
        self.explore_bias       = 0.0   # additive bias to explore channel

    def update(self, sleeping, motor_idle, pred_error, pos_x, pos_y,
               cortisol, spatial_nav, cognitive_map):
        """
        Run one planning step.

        motor_idle    : bool  -- True when selected_action == 'SUPPRESSED'
        pred_error    : float -- current prediction error
        spatial_nav   : SpatialNavigationSystem instance
        cognitive_map : CognitiveMapSystem instance
        """
        import random as _rnd, math

        self._ticks_since_plan += 1
        self.explore_bias = max(0.0, self.explore_bias - 0.02)  # decay per tick

        if sleeping:
            return
        if self._ticks_since_plan < self.REFRACTORY:
            return
        # Trigger condition: motor idle OR high prediction error
        if not motor_idle and pred_error < 0.3:
            return

        # --- Forward path simulation ---
        self._ticks_since_plan = 0
        self.planning_events += 1
        best_value = -1.0
        self.candidate_paths = self.NUM_PATHS

        for _ in range(self.NUM_PATHS):
            px, py = pos_x, pos_y
            path_curiosity = 0.0
            path_reward    = 0.0
            for step in range(self.PATH_LEN):
                # Random direction (exploration forward simulation)
                angle = _rnd.uniform(0, 2 * math.pi)
                px = max(-100.0, min(100.0, px + self.STEP_SIZE * math.cos(angle)))
                py = max(-100.0, min(100.0, py + self.STEP_SIZE * math.sin(angle)))
                # Curiosity: novelty at simulated position (visit count proxy)
                cell_key = (round(px / 2.0), round(py / 2.0))
                visit_count = spatial_nav._visit_counts.get(cell_key, 0)
                step_novelty = max(0.0, 1.0 - visit_count / 20.0)
                path_curiosity += step_novelty
                # Reward: from cognitive map node estimate
                reward = cognitive_map.get_reward(px, py)
                path_reward += reward

            path_curiosity /= self.PATH_LEN
            path_reward    /= self.PATH_LEN
            # Value function V = w1*C + w2*R - w3*S
            V = (self.W1 * path_curiosity
                 + self.W2 * path_reward
                 - self.W3 * cortisol)
            V = max(-1.0, min(1.0, V))
            if V > best_value:
                best_value = V

        self.best_path_value = best_value
        # Motor bias: best path adds to explore channel drive
        self.explore_bias = min(0.30, max(0.0, best_value * 0.20))

    def export_metrics(self):
        return {
            'candidate_paths': self.candidate_paths,
            'best_value':      round(self.best_path_value, 3),
            'planning_events': self.planning_events,
            'explore_bias':    round(self.explore_bias, 3),
        }


# ===========================================================================
# DAY 15 PART 6: PREFRONTAL COGNITIVE MAP SYSTEM
# Tolman 1948, Behrens et al. 2018, Moser et al. 2008
# ===========================================================================

class CognitiveMapSystem:
    """
    Prefrontal cortex cognitive map of explored spatial locations.

    Builds an abstract graph of visited nodes where each node stores:
        visit_count    -- how often the organism has visited
        reward_estimate -- EMA-smoothed valence/reward at that location

    Node indexing uses a spatial grid at resolution 2.0 units.
    Connections not stored (graph topology is implicit from position adjacency).

    Explored ratio = (visited nodes) / (total nodes within 10×10 grid)

    Reward estimate updated each visit:
        reward_estimate = EMA(valence, α=0.15)

    Provides get_reward(x, y) to PlanningSystem for path evaluation.
    """

    RESOLUTION     = 2.0   # spatial units per node cell
    EMA_REWARD_α   = 0.15  # reward EMA smoothing

    def __init__(self):
        self.nodes           = {}   # {(cx,cy): {'visits': int, 'reward': float}}
        self.explored_ratio  = 0.0
        self.total_visits    = 0

    def _cell(self, x, y):
        return (round(x / self.RESOLUTION), round(y / self.RESOLUTION))

    def update(self, x, y, valence):
        """
        Update the cognitive map at current position.
        valence: float -- current emotional valence (reward signal)
        """
        key = self._cell(x, y)
        if key not in self.nodes:
            self.nodes[key] = {'visits': 0, 'reward': 0.0}
        node = self.nodes[key]
        node['visits'] += 1
        self.total_visits += 1
        # EMA reward update
        node['reward'] = (self.EMA_REWARD_α * valence
                          + (1 - self.EMA_REWARD_α) * node['reward'])
        node['reward'] = max(-1.0, min(1.0, node['reward']))
        # Explored ratio: ratio of visited nodes to expected arena coverage
        # Arena bounds ±100 at resolution 2.0 -> 100×100 = 10000 possible cells
        self.explored_ratio = min(1.0, len(self.nodes) / 10000.0)

    def get_reward(self, x, y):
        """Return the reward estimate at position (x,y). 0 if unvisited."""
        node = self.nodes.get(self._cell(x, y))
        return node['reward'] if node else 0.0

    def export_metrics(self):
        return {
            'nodes':          len(self.nodes),
            'total_visits':   self.total_visits,
            'explored_ratio': round(self.explored_ratio, 4),
        }


