        conversational_agency_kernel.update(
            tick                            = tick,
            intent_evolution_tracker        = intent_evolution_tracker,
            clarification_question_planner  = clarification_question_planner,
            collaborative_revision_loop     = collaborative_revision_loop,
            goal_negotiation_engine         = goal_negotiation_engine,
            ambiguity_resolution_bridge     = ambiguity_resolution_bridge,
            turn_level_memory_binder        = turn_level_memory_binder,
            partnered_planning_synthesizer  = partnered_planning_synthesizer,
            language_cognition_kernel       = language_cognition_kernel,
        )

        # Day 29 Pack 1 -- Action Binding & Execution Gate.
        # Collapses advisory cognition into one executable action per waking tick.
        # Runs after conversational_agency_kernel.update(), before edit_intent_generator.generate().
        action_candidate_extractor.update(
            tick                            = tick,
            partnered_planning_synthesizer  = partnered_planning_synthesizer,
            conversational_agency_kernel    = conversational_agency_kernel,
            active_cognition_kernel         = active_cognition_kernel,
            milestone_synthesizer           = globals().get('milestone_synthesizer'),
            post_break_experiment_launchpad = globals().get('post_break_experiment_launchpad'),
        )
        action_confidence_evaluator.update(
            tick                            = tick,
            action_candidate_extractor      = action_candidate_extractor,
            conversational_agency_kernel    = conversational_agency_kernel,
            active_cognition_kernel         = active_cognition_kernel,
            language_cognition_kernel       = language_cognition_kernel,
            confidence_calibrator           = confidence_calibrator,
        )
        execution_interface_bridge.update(
            tick                            = tick,
            action_confidence_evaluator     = action_confidence_evaluator,
        )
        decision_bridge_layer.update(IkigaiState(
            tick                          = tick,
            action_confidence_evaluator   = action_confidence_evaluator,
            cognitive_metabolic_regulator = cognitive_metabolic_regulator,
        ))
        if _IKG.override_bind_signal:
            action_confidence_evaluator.top_confidence = max(
                action_confidence_evaluator.top_confidence,
                ActionBindingGate.BINDING_THRESHOLD,
            )
        action_binding_gate.update(
            tick                            = tick,
            action_confidence_evaluator     = action_confidence_evaluator,
            execution_interface_bridge      = execution_interface_bridge,
            bg_fallback_action              = locals().get('selected_action'),
            active_cognition_kernel         = active_cognition_kernel,
            conversational_agency_kernel    = conversational_agency_kernel,
        )
        # Day 36 Pack 1 -- Record selected action for credit coupling (always, zero cost).
        _IKG.last_action_type = (getattr(action_binding_gate, 'bound_action', None) or {}).get(
            'action_type', None)
        # Day 36 Pack 2 -- Execution Diversity (default OFF -- zero drift when disabled)
        # Maps BG action types to execution-layer types. Written to _IKG.exec_type.
        # Does NOT modify bound_action in place -- all internal systems see original types.
        if _IKG.enable_exec_diversity:
            _ed_atype = (getattr(action_binding_gate, 'bound_action', None) or {}).get(
                'action_type', '')
            _IKG.exec_type = {
                'approach':     'edit_code',
                'explore':      'run_experiment',
                'idle_recover': 'idle_recover',
                'wait':         'idle_recover',
            }.get(_ed_atype, _ed_atype)

        # Day 43 Pack 1 -- Controlled Environment Layer (default OFF).
        # Action advances the deterministic environment only when explicitly enabled.
        if getattr(_IKG, 'enable_env', False):
            _env_action_type = (
                getattr(_IKG, 'exec_type', None)
                if getattr(_IKG, 'enable_exec_diversity', False)
                else None
            )
            if _env_action_type is None:
                _env_action_type = getattr(_IKG, 'last_action_type', None)
            _IKG.env_step(_env_action_type)

        # Day 37 Pack 1 -- Novelty visit count update + decay (zero cost when disabled).
        # Runs after last_action_type is committed; updates count for current state.
        # Decay 0.995/tick: states never reach "fully known"; curiosity cycles over time.
        if _IKG.enable_novelty:
            _nov_upd_key = (
                getattr(_IKG, 'last_action_type', None),
                int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                int(getattr(_IKG, 'bg_pe', 0.0) * 10),
            )
            _IKG.novelty_counts[_nov_upd_key] = _IKG.novelty_counts.get(_nov_upd_key, 0) + 1
            for _nov_k in _IKG.novelty_counts:
                _IKG.novelty_counts[_nov_k] *= 0.995

        # Day 37 Pack 4 -- Curiosity Reinforcement update + decay (zero cost when disabled).
        # Updates curiosity_value only when explore was the committed action.
        # Slow decay (0.999/tick) keeps learned values relevant across timescales.
        if _IKG.enable_curiosity_reinforcement:
            _cr_upd_key = (
                int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                int(getattr(_IKG, 'bg_pe', 0.0) * 10),
            )
            if getattr(_IKG, 'last_action_type', None) == 'explore':
                _cr_reward = max(0.0, min(1.0, (float(getattr(_IKG, 'adjusted_credit_signal', 0.0)) + 1.0) / 2.0))
                _cr_alpha  = 0.05
                _cr_old    = _IKG.curiosity_value.get(_cr_upd_key, 0.0)
                _IKG.curiosity_value[_cr_upd_key] = (1.0 - _cr_alpha) * _cr_old + _cr_alpha * _cr_reward
            for _cr_k in _IKG.curiosity_value:
                _IKG.curiosity_value[_cr_k] *= 0.999

        # Day 37 V2 -- Proto-Representation: Transition Logging (always active, no flag).
        # Records how often state A is followed by state B using the novelty coarse key.
        # Pure observation: no decay, no score influence, no routing effect.
        if getattr(_IKG, 'enable_env', False):
            _tr_curr = (
                getattr(_IKG, 'last_action_type', None),
                int(getattr(_IKG, 'env_current', 0)),
                int(_IKG.env_branch_degree(getattr(_IKG, 'env_current', 0))),
            )
        else:
            _tr_curr = (
                getattr(_IKG, 'last_action_type', None),
                int(getattr(_IKG, 'bg_energy', 0.5) * 5),
                int(getattr(_IKG, 'bg_pe', 0.0) * 10),
            )
        # Day 38 Pack 2 -- Transition Prediction Error (signal only, no behavior).
        # error = 1 - P(actual_next | prev). 1.0 if prev not yet in transition_probs.
        # Computed BEFORE transition_counts update so judgment uses the model in force.
        if _IKG._prev_state_key is not None:
            _te_dist = _IKG.transition_probs.get(_IKG._prev_state_key)
            if not _te_dist:
                _IKG.transition_error = 1.0
                _IKG.predicted_next_state = None
            else:
                _te_prob = _te_dist.get(_tr_curr, 0.0)
                _IKG.transition_error = 1.0 - _te_prob
                _IKG.predicted_next_state = max(_te_dist.items(), key=lambda kv: kv[1])[0]
            _IKG.actual_next_state = _tr_curr
            _IKG._te_sum   += _IKG.transition_error
            _IKG._te_sumsq += _IKG.transition_error * _IKG.transition_error
            _IKG._te_count += 1
            # Day 39 P1 -- per-state TE running stats (for clustering features).
            _rt_key = _IKG._prev_state_key
            if _rt_key not in _IKG._state_runtime:
                _IKG._state_runtime[_rt_key] = {'te_sum': 0.0, 'te_count': 0}
            _IKG._state_runtime[_rt_key]['te_sum']   += _IKG.transition_error
            _IKG._state_runtime[_rt_key]['te_count'] += 1
        # Day 38 Pack 4 -- Prediction Confidence (signal only, no behavior).
        # confidence = max P(next | current_state). 0.0 if current state unknown.
        # Independent of accuracy: orthogonal to transition_error.
        _pc_dist = _IKG.transition_probs.get(_tr_curr)
        if not _pc_dist:
            _IKG.prediction_confidence = 0.0
        else:
            _IKG.prediction_confidence = max(_pc_dist.values())
        _IKG._pc_sum   += _IKG.prediction_confidence
        _IKG._pc_sumsq += _IKG.prediction_confidence * _IKG.prediction_confidence
        _IKG._pc_count += 1
        # Day 39 Pack 3 -- Concept Transition Logging (always active, no behavior).
        # Records (cid_prev -> cid_curr) per-tick using current state_clusters mapping.
        # Bounded by max_clusters^2 (<=256 entries). No scoring/routing influence.
        _ct_curr_cid = _IKG.state_clusters.get(_tr_curr)
        if _ct_curr_cid is not None:
            if _IKG._cluster_prev_id is not None:
                _ct_pair_k = (_IKG._cluster_prev_id, _ct_curr_cid)
                _IKG.cluster_transition_counts[_ct_pair_k] = _IKG.cluster_transition_counts.get(_ct_pair_k, 0) + 1
                # Day 39 Pack 4 -- Concept-Level Error & Confidence (signal only).
                # Computed BEFORE _cluster_prev_id update so prev_id reflects previous tick.
                _cce_dist = _IKG.cluster_transition_probs.get(_IKG._cluster_prev_id)
                if not _cce_dist:
                    _IKG.cluster_transition_error = 1.0
                    _IKG.cluster_prediction_conf  = 0.0
                else:
                    _cce_p = _cce_dist.get(_ct_curr_cid, 0.0)
                    _IKG.cluster_transition_error = max(0.0, min(1.0, 1.0 - _cce_p))
                    _IKG.cluster_prediction_conf  = max(0.0, min(1.0, max(_cce_dist.values())))
                _IKG._ce_sum   += _IKG.cluster_transition_error
                _IKG._ce_sumsq += _IKG.cluster_transition_error * _IKG.cluster_transition_error
                _IKG._ce_count += 1
                _IKG._cpc_sum   += _IKG.cluster_prediction_conf
                _IKG._cpc_sumsq += _IKG.cluster_prediction_conf * _IKG.cluster_prediction_conf
                _IKG._cpc_count += 1
                # Day 39 Pack 5 -- Cross-Level Conflict (meta-consistency, signal only).
                # conflict = |state_surprise - concept_surprise|; signed retains direction.
                # >0 = local chaos / global stable; <0 = global model failed.
                _state_surprise   = float(_IKG.transition_error) * float(_IKG.prediction_confidence)
                _concept_surprise = float(_IKG.cluster_transition_error) * float(_IKG.cluster_prediction_conf)
                _signed = _state_surprise - _concept_surprise
                _IKG.cross_level_signed   = max(-1.0, min(1.0, _signed))
                _IKG.cross_level_conflict = max(0.0, min(1.0, abs(_signed)))
                _IKG._cc_sum   += _IKG.cross_level_conflict
                _IKG._cc_sumsq += _IKG.cross_level_conflict * _IKG.cross_level_conflict
                _IKG._cc_count += 1
            # Day 40 Pack 2/3 -- Observational VSA encoding + semantic validation.
            # Snapshot _cluster_prev_id BEFORE overwrite so Pack 3 classification
            # sees the actual transition. Pure observation -- no scoring/TC influence.
            _vsa_prev_cid = _IKG._cluster_prev_id
            _IKG._cluster_prev_id = _ct_curr_cid
            if _IKG.enable_vsa:
                if not _IKG.vsa_items:
                    _IKG.vsa_init_items()
                _vsa_act = getattr(_IKG, 'last_action_type', None)
                _vsa_ev  = _IKG.vsa_encode_event(_ct_curr_cid, _vsa_act)
                if _vsa_ev is not None:
                    # Capture prev_event BEFORE record_event mutates it (Pack 4 chain).
                    _vsa_prev_for_chain = _IKG.vsa_event
                    _IKG.vsa_record_event(_vsa_ev,
                                          curr_cid=_ct_curr_cid,
                                          prev_cid=_vsa_prev_cid,
                                          curr_action=_vsa_act,
                                          prev_action=getattr(_IKG, 'vsa_prev_action', None))
                    # Day 40 Pack 4 -- decomposition + chain (signal only).
                    _vsa_cid_v = _IKG.vsa_items.get(f"CID_{_ct_curr_cid}")
                    _vsa_act_v = _IKG.vsa_items.get(f"ACT_{_vsa_act}") if _vsa_act else None
                    _IKG.vsa_test_recovery(_vsa_ev, _vsa_cid_v, _vsa_act_v)
                    _IKG.vsa_compose_chain(_vsa_ev, _vsa_prev_for_chain)
                    # Day 41 Pack 1 -- VSA-Prediction Diagnostic Link (signal only).
                    # Records TE/PC distribution at spike vs non-spike VSA ticks.
                    # Gated by enable_vsa_prediction_link; no behavior coupling.
                    if getattr(_IKG, 'enable_vsa_prediction_link', False):
                        _vp_te = getattr(_IKG, 'transition_error', 0.0)
                        _vp_pc = getattr(_IKG, 'prediction_confidence', 0.0)
                        if getattr(_IKG, 'vsa_last_spike', False):
                            _IKG.vsa_total_spikes += 1
                            if _vp_te >= _IKG.vsa_te_threshold:
                                _IKG.vsa_spike_te_high += 1
                            else:
                                _IKG.vsa_spike_te_low += 1
                            if _vp_pc >= _IKG.vsa_pc_threshold:
                                _IKG.vsa_spike_pc_high += 1
                            else:
                                _IKG.vsa_spike_pc_low += 1
                        else:
                            _IKG.non_spike_count += 1
                            if _vp_te >= _IKG.vsa_te_threshold:
                                _IKG.non_spike_te_high += 1
                            else:
                                _IKG.non_spike_te_low += 1
                    # Day 41 Pack 2 -- Real-Surprise flag (read by next-tick BG scoring).
                    # S_real = spike AND TE_high AND PC_high (all same tick, VSA side).
                    # One-tick latency is correct: surprise detected here, acted on next tick.
                    if getattr(_IKG, 'enable_vsa_real_modulation', False):
                        _rs2_te = getattr(_IKG, 'transition_error', 0.0)
