        cur_asm=cas.update(cort.level,ne.level,soma.mode,da.level,oxt.level,ach.level,nov,speech.active,narrative.self_model['resilience'],ht.level,tick)
        if cur_asm: bridge.trigger(nb1,nb2,tick)
