    print(f"EI_ratio:                         {mean_ei_ratio:.3f}")
    print(f"{'='*51}\n")

    # =========================================================================
    # FULL-SYSTEM OBSERVABILITY REPORT (Day 22-24 Cognition + Artifact Evolution)
    # Read-only. Discovers meaningful metrics from all active subsystems.
    # =========================================================================

    def _safe_lat(obj):
        """Read-only .latest() with None-guard. Never mutates."""
        try:
            r = obj.latest()
            return r if r is not None else {}
        except Exception:
            return {}

    def _safe_len(obj):
        """Read-only len() with fallback."""
        try:
            return len(obj)
        except Exception:
            return 0

    def _mean(vals):
        """Mean of a list, 0.0 if empty."""
        return sum(vals) / max(1, len(vals)) if vals else 0.0

    def _safe_mean_field(deque_obj, field, default=0.0):
        """Compute mean of a float field across all records in a deque."""
        try:
            vals = [r.get(field, default) for r in deque_obj if isinstance(r, dict)]
            return _mean(vals)
        except Exception:
            return default

    def _count_field_value(deque_obj, field, value):
        """Count records in a deque where field == value."""
        try:
            return sum(1 for r in deque_obj if isinstance(r, dict) and r.get(field) == value)
        except Exception:
            return 0

    _FT = max(1, fc)  # total completed ticks

    # -------------------------------------------------------------------------
    # METRIC DISCOVERY HEURISTIC
    # Scans the 'systems' dict for objects with __len__, .latest(), .recent()
    # and surfaces basic occupancy + most recent record fields automatically.
    # This ensures future packs become visible without manual report rewrites.
    # -------------------------------------------------------------------------
    _DISCOVERED = {}  # name -> {size, latest_keys}
    for _sname, _sobj in systems.items():
        _entry = {}
        try:
            _entry['size'] = len(_sobj)
        except Exception:
            pass
        try:
            _lr = _sobj.latest()
            if isinstance(_lr, dict):
                _entry['latest_keys'] = list(_lr.keys())
                _entry['latest'] = _lr
        except Exception:
            pass
        if _entry:
            _DISCOVERED[_sname] = _entry

    print(f"{'='*55}")
    print(f"DAY 22-24 COGNITION STACK REPORT")
    print(f"{'='*55}")

    # -- Memory Surfaces: size / growth --
