    print(f"  ConceptGraph:          {len(concept_graph.nodes)} nodes | {len(concept_graph.edges)} edges | density={len(concept_graph.edges)/max(1,len(concept_graph.nodes)):.2f} e/n")
    print(f"  ReportBus:             {_safe_len(report_bus)} reports")
    print(f"  LanguageReadout:       {_safe_len(language_readout)} propositions")
    print(f"  SentenceGenerator:     {_safe_len(sentence_generator)} sentences")
