    print(f"  FailureAtlas:          {_safe_len(failure_atlas)} atlas entries")

    _rot_deq = retry_outcome_tracker._trackers
    _improved_count  = _count_field_value(_rot_deq, 'outcome_status', 'improved')
    _unchanged_count = _count_field_value(_rot_deq, 'outcome_status', 'unchanged')
    _regressed_count = _count_field_value(_rot_deq, 'outcome_status', 'regressed')
    _mean_imp = _safe_mean_field(_rot_deq, 'improvement_score')
    print(f"  RetryOutcomes:         improved={_improved_count} unchanged={_unchanged_count} regressed={_regressed_count} | mean_imp={_mean_imp:.3f}")

    _mg_deq = mutation_guard._guards
    _stable_g   = _count_field_value(_mg_deq, 'guard_state', 'stable')
    _osc_g      = _count_field_value(_mg_deq, 'guard_state', 'oscillation_risk')
    _loop_g     = _count_field_value(_mg_deq, 'guard_state', 'loop_lock')
    print(f"  GuardStates:           stable={_stable_g} oscillation_risk={_osc_g} loop_lock={_loop_g}")

    _fa_final = _safe_lat(failure_atlas)
    if _fa_final:
        print(f"  LastAtlas:             conf={_fa_final.get('atlas_confidence',0.0):.3f} sig={_fa_final.get('atlas_signature','?')}")

    # -- Project cognition surfaces --
    print(f"\n  [PROJECT COGNITION SURFACES]")
    print(f"  AbstractTaskEngine:    {_safe_len(abstract_task_engine)} plans")
    print(f"  PlanGraphMemory:       {_safe_len(plan_graph_memory)} graph records")
