    print(f"  MeanEditConfidence:    {_mean_ei_conf:.3f}")

    print(f"\n  [PATCH EXECUTION LAYER]")
    print(f"  PatchExecutor:         {_safe_len(patch_executor)} executions")
    print(f"  VersionDiffTracker:    {_safe_len(version_diff_tracker)} diff records")
