    _unchanged_d = _count_field_value(_vdt_deq, 'diff_state', 'unchanged')
    _protected_d = _count_field_value(_vdt_deq, 'diff_state', 'protected')
    _unc_vdt     = _count_field_value(_vdt_deq, 'diff_state', 'uncertain')
    print(f"  DiffStates:            advanced={_advanced_d} unchanged={_unchanged_d} protected={_protected_d} uncertain={_unc_vdt}")

