    _mean_diff_score  = _safe_mean_field(_vdt_deq, 'diff_score')
    _mean_rb_score    = _safe_mean_field(_rc_deq,  'rollback_score')
    print(f"  MeanScores:            exec={_mean_exec_score:.3f} diff={_mean_diff_score:.3f} rollback={_mean_rb_score:.3f}")

    _vdt_final = _safe_lat(version_diff_tracker)
    if _vdt_final:
        _max_stag = max((r.get('stagnation_count', 0) for r in _vdt_deq if isinstance(r, dict)), default=0)
        print(f"  MaxStagnationDepth:    {_max_stag}")
