    print(f"{'='*55}")

    # Basic sleep accounting
    _sa_total_ticks     = _FT
    _sa_sleep_ratio     = _obs_sleep_ticks / max(1, _sa_total_ticks)
    _sa_wake_ticks      = _sa_total_ticks - _obs_sleep_ticks
    _sa_cycles          = _obs_sleep_cycles
    # If a sleep bout is still in progress at run end, include its length
    _sa_all_cycles      = _obs_cycle_lengths + ([_obs_cur_cycle_len] if _obs_cur_cycle_len > 0 else [])
    _sa_mean_cycle      = _mean(_sa_all_cycles) if _sa_all_cycles else 0.0
    _sa_max_cycle       = max(_sa_all_cycles) if _sa_all_cycles else 0
    _sa_min_cycle       = min(_sa_all_cycles) if _sa_all_cycles else 0
    _sa_frag_idx        = _sa_cycles / max(1, _obs_sleep_ticks)   # cycles per sleep tick
    _sa_consol_per_slp  = _obs_consolidation_calls / max(1, _obs_sleep_ticks)

    print(f"\n  [SLEEP ACCOUNTING]")
    print(f"  Total ticks:           {_sa_total_ticks}")
