    print(f"\n  [SLEEP CYCLE STRUCTURE]")
    print(f"  Completed cycles:      {_sa_cycles}")
    print(f"  Mean cycle length:     {_sa_mean_cycle:.1f} ticks")
    print(f"  Max cycle length:      {_sa_max_cycle} ticks")
    print(f"  Min cycle length:      {_sa_min_cycle} ticks")
    print(f"  Fragmentation index:   {_sa_frag_idx:.5f}  (cycles / sleep_ticks;  lower = fewer interruptions)")

    print(f"\n  [OFFLINE LEARNING EFFICIENCY]")
    print(f"  Consolidation calls:   {_obs_consolidation_calls}")
